def _optimize_transpose_hardswish_se_conv_hardsigmoid_mul_prepost_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove NCHW bridge transposes in activation + SE-conv + HardSigmoid gating blocks.

    Supported activation roots:
    - HARD_SWISH
    - RELU
    - RELU6
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            hsw_out_name: Optional[str] = None
            hsw_input_rewrites: List[Tuple[OperatorIR, int]] = []
            hsw_root_intermediate_names: List[str] = []

            # Pattern 1: direct activation root
            #   pre_output -> {HARD_SWISH|RELU|RELU6} -> hsw_out
            if len(pre_users) == 1:
                hsw_idx = int(pre_users[0])
                hsw_op = model_ir.operators[int(hsw_idx)]
                if (
                    str(hsw_op.op_type) in {"HARD_SWISH", "RELU", "RELU6"}
                    and len(hsw_op.inputs) == 1
                    and len(hsw_op.outputs) == 1
                    and str(hsw_op.inputs[0]) == pre_output_name
                ):
                    hsw_out_name = str(hsw_op.outputs[0])
                    hsw_input_rewrites.append((hsw_op, 0))
                    hsw_root_intermediate_names.append(str(hsw_out_name))

            # Pattern 2: decomposed hard-swish root
            #   pre_output --ADD(+const, fused=RELU6)--> a
            #              --MUL(a, const)-------------> b
            #              --MUL(pre_output, b)--------> hsw_out
            if hsw_out_name is None and len(pre_users) == 2:
                add_idx: Optional[int] = None
                mul_data_idx: Optional[int] = None
                add_data_input_index: Optional[int] = None
                mul_data_input_index: Optional[int] = None
                for user_idx in pre_users:
                    user_op = model_ir.operators[int(user_idx)]
                    user_type = str(user_op.op_type)
                    if user_type == "ADD" and len(user_op.inputs) == 2 and len(user_op.outputs) == 1:
                        add_inputs = [str(v) for v in list(user_op.inputs)]
                        if pre_output_name == add_inputs[0]:
                            side_name = add_inputs[1]
                            add_data_input_index = 0
                        elif pre_output_name == add_inputs[1]:
                            side_name = add_inputs[0]
                            add_data_input_index = 1
                        else:
                            continue
                        if not _is_singleton_constant_tensor(model_ir, side_name):
                            continue
                        fused_act = str(user_op.options.get("fusedActivationFunction", "NONE")).upper()
                        if fused_act != "RELU6":
                            continue
                        add_idx = int(user_idx)
                    elif user_type == "MUL" and len(user_op.inputs) == 2 and len(user_op.outputs) == 1:
                        mul_inputs = [str(v) for v in list(user_op.inputs)]
                        if pre_output_name == mul_inputs[0]:
                            mul_data_input_index = 0
                            mul_data_idx = int(user_idx)
                        elif pre_output_name == mul_inputs[1]:
                            mul_data_input_index = 1
                            mul_data_idx = int(user_idx)
                if (
                    add_idx is not None
                    and mul_data_idx is not None
                    and add_data_input_index is not None
                    and mul_data_input_index is not None
                ):
                    add_op = model_ir.operators[int(add_idx)]
                    mul_data_op = model_ir.operators[int(mul_data_idx)]
                    add_out_name = str(add_op.outputs[0])
                    add_users = [int(v) for v in consumers.get(add_out_name, [])]
                    if len(add_users) == 1:
                        mul_scale_idx = int(add_users[0])
                        mul_scale_op = model_ir.operators[int(mul_scale_idx)]
                        if str(mul_scale_op.op_type) == "MUL" and len(mul_scale_op.inputs) == 2 and len(mul_scale_op.outputs) == 1:
                            mul_scale_inputs = [str(v) for v in list(mul_scale_op.inputs)]
                            if add_out_name == mul_scale_inputs[0]:
                                mul_scale_side_name = mul_scale_inputs[1]
                            elif add_out_name == mul_scale_inputs[1]:
                                mul_scale_side_name = mul_scale_inputs[0]
                            else:
                                mul_scale_side_name = ""
                            if _is_singleton_constant_tensor(model_ir, mul_scale_side_name):
                                mul_scale_out_name = str(mul_scale_op.outputs[0])
                                mul_data_inputs = [str(v) for v in list(mul_data_op.inputs)]
                                if (
                                    (mul_data_inputs[0] == pre_output_name and mul_data_inputs[1] == mul_scale_out_name)
                                    or (mul_data_inputs[1] == pre_output_name and mul_data_inputs[0] == mul_scale_out_name)
                                ):
                                    hsw_out_name = str(mul_data_op.outputs[0])
                                    hsw_input_rewrites.append((add_op, int(add_data_input_index)))
                                    hsw_input_rewrites.append((mul_data_op, int(mul_data_input_index)))
                                    hsw_root_intermediate_names.extend(
                                        [str(add_out_name), str(mul_scale_out_name), str(hsw_out_name)]
                                    )

            if hsw_out_name is None:
                continue
            if hsw_out_name in model_outputs:
                continue

            hsw_users = [int(v) for v in consumers.get(hsw_out_name, [])]
            if len(hsw_users) != 2:
                continue

            mean_idx: Optional[int] = None
            residual_mul_idx: Optional[int] = None
            for user_idx in hsw_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "MEAN"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == hsw_out_name
                    and bool(user_op.options.get("keepDims", False))
                ):
                    mean_idx = int(user_idx)
                elif (
                    str(user_op.op_type) == "MUL"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and hsw_out_name in {str(v) for v in list(user_op.inputs)}
                ):
                    residual_mul_idx = int(user_idx)
            if mean_idx is None or residual_mul_idx is None:
                continue

            mean_op = model_ir.operators[int(mean_idx)]
            mean_axes_name = str(mean_op.inputs[1])
            mean_axes_tensor = model_ir.tensors.get(mean_axes_name, None)
            mean_axes_vals = _read_const_ints_from_tensor(mean_axes_tensor)
            if mean_axes_vals is None or len(mean_axes_vals) == 0:
                continue
            mean_out_name = str(mean_op.outputs[0])
            if mean_out_name in model_outputs:
                continue

            mean_users = [int(v) for v in consumers.get(mean_out_name, [])]
            if len(mean_users) != 1:
                continue
            post_mean_idx = int(mean_users[0])
            post_mean_op = model_ir.operators[int(post_mean_idx)]
            if (
                str(post_mean_op.op_type) != "TRANSPOSE"
                or len(post_mean_op.inputs) < 2
                or len(post_mean_op.outputs) != 1
                or str(post_mean_op.inputs[0]) != mean_out_name
                or _read_transpose_perm(model_ir, post_mean_op) != perm_nchw_to_nhwc
            ):
                continue
            post_mean_out_name = str(post_mean_op.outputs[0])
            if post_mean_out_name in model_outputs:
                continue

            post_mean_users = [int(v) for v in consumers.get(post_mean_out_name, [])]
            if len(post_mean_users) != 1:
                continue
            conv1_idx = int(post_mean_users[0])
            conv1_op = model_ir.operators[int(conv1_idx)]
            if (
                str(conv1_op.op_type) != "CONV_2D"
                or len(conv1_op.inputs) < 1
                or len(conv1_op.outputs) != 1
                or str(conv1_op.inputs[0]) != post_mean_out_name
            ):
                continue
            conv1_out_name = str(conv1_op.outputs[0])

            conv1_users = [int(v) for v in consumers.get(conv1_out_name, [])]
            if len(conv1_users) != 1:
                continue
            conv2_idx = int(conv1_users[0])
            conv2_op = model_ir.operators[int(conv2_idx)]
            if (
                str(conv2_op.op_type) != "CONV_2D"
                or len(conv2_op.inputs) < 1
                or len(conv2_op.outputs) != 1
                or str(conv2_op.inputs[0]) != conv1_out_name
            ):
                continue
            conv2_out_name = str(conv2_op.outputs[0])

            conv2_users = [int(v) for v in consumers.get(conv2_out_name, [])]
            if len(conv2_users) != 1:
                continue
            pre_gate_idx = int(conv2_users[0])
            pre_gate_op = model_ir.operators[int(pre_gate_idx)]
            if (
                str(pre_gate_op.op_type) != "TRANSPOSE"
                or len(pre_gate_op.inputs) < 2
                or len(pre_gate_op.outputs) != 1
                or str(pre_gate_op.inputs[0]) != conv2_out_name
                or _read_transpose_perm(model_ir, pre_gate_op) != perm_nhwc_to_nchw
            ):
                continue
            pre_gate_out_name = str(pre_gate_op.outputs[0])

            pre_gate_users = [int(v) for v in consumers.get(pre_gate_out_name, [])]
            if len(pre_gate_users) != 1:
                continue
            hs_entry_idx = int(pre_gate_users[0])
            hs_entry_op = model_ir.operators[int(hs_entry_idx)]
            hs_data_op = hs_entry_op
            hs_data_input_index: Optional[int] = None
            hs_out_name: Optional[str] = None
            hs_gate_intermediate_names: List[str] = []

            # Pattern A:
            #   MUL(alpha) -> ADD(beta) -> RELU_0_TO_1
            if str(hs_entry_op.op_type) == "MUL":
                if len(hs_entry_op.inputs) != 2 or len(hs_entry_op.outputs) != 1:
                    continue
                hs_mul_inputs = [str(v) for v in list(hs_entry_op.inputs)]
                if pre_gate_out_name == hs_mul_inputs[0]:
                    hs_data_input_index = 0
                    hs_mul_side_name = hs_mul_inputs[1]
                elif pre_gate_out_name == hs_mul_inputs[1]:
                    hs_data_input_index = 1
                    hs_mul_side_name = hs_mul_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_mul_side_name):
                    continue
                hs_mul_out_name = str(hs_entry_op.outputs[0])
                hs_gate_intermediate_names.append(str(hs_mul_out_name))

                hs_mul_users = [int(v) for v in consumers.get(hs_mul_out_name, [])]
                if len(hs_mul_users) != 1:
                    continue
                hs_add_idx = int(hs_mul_users[0])
                hs_add_op = model_ir.operators[int(hs_add_idx)]
                if str(hs_add_op.op_type) != "ADD" or len(hs_add_op.inputs) != 2 or len(hs_add_op.outputs) != 1:
                    continue
                hs_add_inputs = [str(v) for v in list(hs_add_op.inputs)]
                if hs_mul_out_name == hs_add_inputs[0]:
                    hs_add_side_name = hs_add_inputs[1]
                elif hs_mul_out_name == hs_add_inputs[1]:
                    hs_add_side_name = hs_add_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_add_side_name):
                    continue
                hs_add_out_name = str(hs_add_op.outputs[0])
                hs_gate_intermediate_names.append(str(hs_add_out_name))

                hs_add_users = [int(v) for v in consumers.get(hs_add_out_name, [])]
                if len(hs_add_users) != 1:
                    continue
                hs_relu_idx = int(hs_add_users[0])
                hs_relu_op = model_ir.operators[int(hs_relu_idx)]
                if (
                    str(hs_relu_op.op_type) != "RELU_0_TO_1"
                    or len(hs_relu_op.inputs) != 1
                    or len(hs_relu_op.outputs) != 1
                    or str(hs_relu_op.inputs[0]) != hs_add_out_name
                ):
                    continue
                hs_out_name = str(hs_relu_op.outputs[0])
                hs_gate_intermediate_names.append(str(hs_out_name))
            # Pattern B:
            #   ADD(beta, fusedActivation=RELU6) -> MUL(alpha)
            elif str(hs_entry_op.op_type) == "ADD":
                if len(hs_entry_op.inputs) != 2 or len(hs_entry_op.outputs) != 1:
                    continue
                hs_add_inputs = [str(v) for v in list(hs_entry_op.inputs)]
                if pre_gate_out_name == hs_add_inputs[0]:
                    hs_data_input_index = 0
                    hs_add_side_name = hs_add_inputs[1]
                elif pre_gate_out_name == hs_add_inputs[1]:
                    hs_data_input_index = 1
                    hs_add_side_name = hs_add_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_add_side_name):
                    continue
                fused_act = str(hs_entry_op.options.get("fusedActivationFunction", "NONE")).upper()
                if fused_act != "RELU6":
                    continue
                hs_add_out_name = str(hs_entry_op.outputs[0])
                hs_gate_intermediate_names.append(str(hs_add_out_name))

                hs_add_users = [int(v) for v in consumers.get(hs_add_out_name, [])]
                if len(hs_add_users) != 1:
                    continue
                hs_mul_idx = int(hs_add_users[0])
                hs_mul_op = model_ir.operators[int(hs_mul_idx)]
                if str(hs_mul_op.op_type) != "MUL" or len(hs_mul_op.inputs) != 2 or len(hs_mul_op.outputs) != 1:
                    continue
                hs_mul_inputs = [str(v) for v in list(hs_mul_op.inputs)]
                if hs_add_out_name == hs_mul_inputs[0]:
                    hs_mul_side_name = hs_mul_inputs[1]
                elif hs_add_out_name == hs_mul_inputs[1]:
                    hs_mul_side_name = hs_mul_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, hs_mul_side_name):
                    continue
                hs_out_name = str(hs_mul_op.outputs[0])
                hs_gate_intermediate_names.append(str(hs_out_name))
            else:
                continue

            if hs_data_input_index is None or hs_out_name is None:
                continue

            residual_mul_op = model_ir.operators[int(residual_mul_idx)]
            residual_inputs = [str(v) for v in list(residual_mul_op.inputs)]
            if not (
                (residual_inputs[0] == hsw_out_name and residual_inputs[1] == hs_out_name)
                or (residual_inputs[1] == hsw_out_name and residual_inputs[0] == hs_out_name)
            ):
                continue
            residual_out_name = str(residual_mul_op.outputs[0])
            if residual_out_name in model_outputs:
                continue

            residual_users = [int(v) for v in consumers.get(residual_out_name, [])]
            if len(residual_users) != 1:
                continue
            post_idx = int(residual_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != residual_out_name
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_output_name = str(post_op.outputs[0])

            mapped_axes: List[int] = []
            valid_axes = True
            for axis in mean_axes_vals:
                a = int(axis)
                if a < 0:
                    a += 4
                if a < 0 or a >= 4:
                    valid_axes = False
                    break
                mapped_axes.append(int(perm_nhwc_to_nchw[int(a)]))
            if not valid_axes:
                continue
            if mean_axes_tensor is None or not _write_const_ints_to_tensor(mean_axes_tensor, mapped_axes):
                continue

            for rewrite_op, rewrite_input_index in hsw_input_rewrites:
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=rewrite_op,
                    input_index=int(rewrite_input_index),
                    new_input_name=pre_input_name,
                )
            for root_name in hsw_root_intermediate_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(root_name), None),
                    perm_nchw_to_nhwc,
                )

            mean_inputs = [str(v) for v in list(mean_op.inputs)]
            mean_inputs[0] = hsw_out_name
            _set_operator_inputs(model_ir=model_ir, op=mean_op, new_inputs=mean_inputs)
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(mean_out_name, None),
                perm_nchw_to_nhwc,
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=mean_op,
                new_outputs=[post_mean_out_name],
            )
            old_mean_tensor = model_ir.tensors.get(mean_out_name, None)
            post_mean_tensor = model_ir.tensors.get(post_mean_out_name, None)
            if post_mean_tensor is not None and old_mean_tensor is not None:
                post_mean_tensor.dtype = str(old_mean_tensor.dtype)
                post_mean_tensor.quantization = _clone_quantization(old_mean_tensor.quantization)
                post_mean_tensor.shape = [int(v) for v in list(old_mean_tensor.shape)]
                post_mean_tensor.shape_signature = (
                    [int(v) for v in list(old_mean_tensor.shape_signature)]
                    if old_mean_tensor.shape_signature is not None
                    else [int(v) for v in list(old_mean_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post_mean_tensor,
                    perm_nchw_to_nhwc,
                )

            _replace_operator_input_at(
                model_ir=model_ir,
                op=hs_data_op,
                input_index=int(hs_data_input_index),
                new_input_name=conv2_out_name,
            )
            for name in hs_gate_intermediate_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(name, None),
                    perm_nchw_to_nhwc,
                )

            _set_operator_outputs(
                model_ir=model_ir,
                op=residual_mul_op,
                new_outputs=[post_output_name],
            )
            old_residual_tensor = model_ir.tensors.get(residual_out_name, None)
            post_output_tensor = model_ir.tensors.get(post_output_name, None)
            if post_output_tensor is not None and old_residual_tensor is not None:
                post_output_tensor.dtype = str(old_residual_tensor.dtype)
                post_output_tensor.quantization = _clone_quantization(old_residual_tensor.quantization)
                post_output_tensor.shape = [int(v) for v in list(old_residual_tensor.shape)]
                post_output_tensor.shape_signature = (
                    [int(v) for v in list(old_residual_tensor.shape_signature)]
                    if old_residual_tensor.shape_signature is not None
                    else [int(v) for v in list(old_residual_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post_output_tensor,
                    perm_nchw_to_nhwc,
                )

            remove_indices = sorted(
                list({int(pre_idx), int(post_mean_idx), int(pre_gate_idx), int(post_idx)}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_hardswish_se_conv_hardsigmoid_mul_prepost_nhwc_chains": int(rewritten)}


def _optimize_transpose_pad_prepost_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_pad_prepost_nhwc_chains_pass(model_ir)


def _optimize_transpose_unary_pad_prepost_to_single_adapter_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_unary_pad_prepost_to_single_adapter_nhwc_chains_pass(model_ir)


def _optimize_transpose_norm_subgraph_pad_prepost_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_norm_subgraph_pad_prepost_nhwc_chains_pass(model_ir)


def _optimize_swish_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around pseudo-op-expanded Swish chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --LOGISTIC--> s_t
      MUL(x_t, s_t) --> y_t
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --LOGISTIC--> s
      MUL(X, s) --> Y

    Safety:
    - Strict Swish topology (LOGISTIC + residual MUL input).
    - LOGISTIC output must be consumed only by the MUL.
    - Requires at least one inverse post-transpose consumer.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 2:
                continue

            log_idx = None
            mul_idx = None
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)
                if (
                    user_type == "LOGISTIC"
                    and len(user_op.inputs) == 1
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == pre_output_name
                ):
                    log_idx = int(user_idx)
                elif user_type == "MUL":
                    mul_idx = int(user_idx)
            if log_idx is None or mul_idx is None:
                continue

            log_op = model_ir.operators[int(log_idx)]
            log_out_name = str(log_op.outputs[0])
            log_users = [int(v) for v in consumers.get(log_out_name, [])]
            if len(log_users) != 1 or int(log_users[0]) != int(mul_idx):
                continue

            mul_op = model_ir.operators[int(mul_idx)]
            if len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_inputs = [str(v) for v in mul_op.inputs]
            if mul_inputs[0] == pre_output_name and mul_inputs[1] == log_out_name:
                mul_data_input_index = 0
            elif mul_inputs[1] == pre_output_name and mul_inputs[0] == log_out_name:
                mul_data_input_index = 1
            else:
                continue

            mul_out_name = str(mul_op.outputs[0])
            mul_users = [int(v) for v in consumers.get(mul_out_name, []) if int(v) != int(mul_idx)]
            if len(mul_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in mul_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == mul_out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or perm_post != perm_post_expected:
                        valid_users = False
                        break
                    post_output_name = str(user_op.outputs[0])
                    if post_output_name in model_outputs:
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue

            representative_output_name = str(post_output_names[0])

            _set_operator_inputs(
                model_ir=model_ir,
                op=log_op,
                new_inputs=[pre_input_name],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(mul_data_input_index),
                new_input_name=pre_input_name,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mul_op,
                new_outputs=[representative_output_name],
            )
            for alias_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_output_name, representative_output_name)

            # LOGISTIC is layout-agnostic; update metadata from transposed to source layout.
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(log_out_name, None),
                perm_post_expected,
            )

            old_mul_tensor = model_ir.tensors.get(mul_out_name, None)
            representative_tensor = model_ir.tensors.get(representative_output_name, None)
            if old_mul_tensor is not None and representative_tensor is not None:
                representative_tensor.dtype = str(old_mul_tensor.dtype)
                representative_tensor.quantization = _clone_quantization(old_mul_tensor.quantization)
                representative_tensor.shape = [int(v) for v in list(old_mul_tensor.shape)]
                representative_tensor.shape_signature = (
                    [int(v) for v in list(old_mul_tensor.shape_signature)]
                    if old_mul_tensor.shape_signature is not None
                    else [int(v) for v in list(old_mul_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    representative_tensor,
                    perm_post_expected,
                )

            preserve_nchw_adapter = len(legacy_users) > 0 or mul_out_name in model_outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[keep_post_idx]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[representative_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[mul_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(list({int(pre_idx), *post_remove_indices}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_swish_transpose_passthrough_chains": int(rewritten)}


def _optimize_gelu_tanh_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around tanh-approx GELU expansion chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      m2 = MUL(MUL(x_t, x_t), x_t)
      t0 = MUL(m2, c0)
      t1 = ADD(x_t, t0)
      t2 = MUL(t1, c1)
      t3 = TANH(t2)
      t4 = ADD(t3, c2)
      t5 = MUL(x_t, t4)
      y_t = MUL(t5, c3)
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      Same chain with x_t replaced by X and Y produced directly from final MUL.

    Safety:
    - Requires exact tanh-GELU topology with scalar-like constants c0..c3.
    - Final GELU output must be consumed by inverse post-transpose adapters only.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = sorted(list(set(int(v) for v in consumers.get(pre_output_name, []))))
            if len(pre_users) == 0:
                continue

            gelu_match_found = False
            for msq_idx in pre_users:
                msq_op = model_ir.operators[int(msq_idx)]
                if str(msq_op.op_type) != "MUL" or len(msq_op.inputs) != 2 or len(msq_op.outputs) != 1:
                    continue
                if not (str(msq_op.inputs[0]) == pre_output_name and str(msq_op.inputs[1]) == pre_output_name):
                    continue
                msq_out_name = str(msq_op.outputs[0])
                msq_users = [int(v) for v in consumers.get(msq_out_name, [])]
                if len(msq_users) != 1:
                    continue

                mcube_idx = int(msq_users[0])
                mcube_op = model_ir.operators[int(mcube_idx)]
                if str(mcube_op.op_type) != "MUL" or len(mcube_op.inputs) != 2 or len(mcube_op.outputs) != 1:
                    continue
                mcube_inputs = [str(v) for v in mcube_op.inputs]
                if pre_output_name == mcube_inputs[0] and msq_out_name == mcube_inputs[1]:
                    pass
                elif pre_output_name == mcube_inputs[1] and msq_out_name == mcube_inputs[0]:
                    pass
                else:
                    continue
                mcube_out_name = str(mcube_op.outputs[0])

                m1_users = [int(v) for v in consumers.get(mcube_out_name, [])]
                if len(m1_users) != 1:
                    continue
                m1_idx = int(m1_users[0])
                m1_op = model_ir.operators[int(m1_idx)]
                if str(m1_op.op_type) != "MUL" or len(m1_op.inputs) != 2 or len(m1_op.outputs) != 1:
                    continue
                m1_inputs = [str(v) for v in m1_op.inputs]
                if m1_inputs[0] == mcube_out_name:
                    m1_side_name = m1_inputs[1]
                elif m1_inputs[1] == mcube_out_name:
                    m1_side_name = m1_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, m1_side_name):
                    continue
                m1_out_name = str(m1_op.outputs[0])

                add1_users = [int(v) for v in consumers.get(m1_out_name, [])]
                if len(add1_users) != 1:
                    continue
                add1_idx = int(add1_users[0])
                add1_op = model_ir.operators[int(add1_idx)]
                if str(add1_op.op_type) != "ADD" or len(add1_op.inputs) != 2 or len(add1_op.outputs) != 1:
                    continue
                add1_inputs = [str(v) for v in add1_op.inputs]
                if pre_output_name == add1_inputs[0] and m1_out_name == add1_inputs[1]:
                    pass
                elif pre_output_name == add1_inputs[1] and m1_out_name == add1_inputs[0]:
                    pass
                else:
                    continue
                add1_out_name = str(add1_op.outputs[0])

                m2_users = [int(v) for v in consumers.get(add1_out_name, [])]
                if len(m2_users) != 1:
                    continue
                m2_idx = int(m2_users[0])
                m2_op = model_ir.operators[int(m2_idx)]
                if str(m2_op.op_type) != "MUL" or len(m2_op.inputs) != 2 or len(m2_op.outputs) != 1:
                    continue
                m2_inputs = [str(v) for v in m2_op.inputs]
                if m2_inputs[0] == add1_out_name:
                    m2_side_name = m2_inputs[1]
                elif m2_inputs[1] == add1_out_name:
                    m2_side_name = m2_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, m2_side_name):
                    continue
                m2_out_name = str(m2_op.outputs[0])

                tanh_users = [int(v) for v in consumers.get(m2_out_name, [])]
                if len(tanh_users) != 1:
                    continue
                tanh_idx = int(tanh_users[0])
                tanh_op = model_ir.operators[int(tanh_idx)]
                if (
                    str(tanh_op.op_type) != "TANH"
                    or len(tanh_op.inputs) != 1
                    or len(tanh_op.outputs) != 1
                    or str(tanh_op.inputs[0]) != m2_out_name
                ):
                    continue
                tanh_out_name = str(tanh_op.outputs[0])

                add2_users = [int(v) for v in consumers.get(tanh_out_name, [])]
                if len(add2_users) != 1:
                    continue
                add2_idx = int(add2_users[0])
                add2_op = model_ir.operators[int(add2_idx)]
                if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                    continue
                add2_inputs = [str(v) for v in add2_op.inputs]
                if add2_inputs[0] == tanh_out_name:
                    add2_side_name = add2_inputs[1]
                elif add2_inputs[1] == tanh_out_name:
                    add2_side_name = add2_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, add2_side_name):
                    continue
                add2_out_name = str(add2_op.outputs[0])

                m3_users = [int(v) for v in consumers.get(add2_out_name, [])]
                if len(m3_users) != 1:
                    continue
                m3_idx = int(m3_users[0])
                m3_op = model_ir.operators[int(m3_idx)]
                if str(m3_op.op_type) != "MUL" or len(m3_op.inputs) != 2 or len(m3_op.outputs) != 1:
                    continue
                m3_inputs = [str(v) for v in m3_op.inputs]
                if pre_output_name == m3_inputs[0] and add2_out_name == m3_inputs[1]:
                    pass
                elif pre_output_name == m3_inputs[1] and add2_out_name == m3_inputs[0]:
                    pass
                else:
                    continue
                m3_out_name = str(m3_op.outputs[0])

                m4_users = [int(v) for v in consumers.get(m3_out_name, [])]
                if len(m4_users) != 1:
                    continue
                m4_idx = int(m4_users[0])
                m4_op = model_ir.operators[int(m4_idx)]
                if str(m4_op.op_type) != "MUL" or len(m4_op.inputs) != 2 or len(m4_op.outputs) != 1:
                    continue
                m4_inputs = [str(v) for v in m4_op.inputs]
                if m4_inputs[0] == m3_out_name:
                    m4_side_name = m4_inputs[1]
                elif m4_inputs[1] == m3_out_name:
                    m4_side_name = m4_inputs[0]
                else:
                    continue
                if not _is_singleton_constant_tensor(model_ir, m4_side_name):
                    continue
                gelu_out_name = str(m4_op.outputs[0])

                gelu_users = [int(v) for v in consumers.get(gelu_out_name, []) if int(v) != int(m4_idx)]
                if len(gelu_users) == 0:
                    continue

                post_indices: List[int] = []
                post_output_names: List[str] = []
                valid_users = True
                for user_idx in gelu_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) != "TRANSPOSE"
                        or len(user_op.inputs) < 2
                        or len(user_op.outputs) != 1
                        or str(user_op.inputs[0]) != gelu_out_name
                    ):
                        valid_users = False
                        break
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or perm_post != perm_post_expected:
                        valid_users = False
                        break
                    post_output_name = str(user_op.outputs[0])
                    if post_output_name in model_outputs:
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                if not valid_users or len(post_indices) == 0:
                    continue

                representative_output_name = str(post_output_names[0])
                for op_idx in [int(msq_idx), int(mcube_idx), int(add1_idx), int(m3_idx)]:
                    op = model_ir.operators[int(op_idx)]
                    updated_inputs = [
                        pre_input_name if str(v) == pre_output_name else str(v)
                        for v in list(op.inputs)
                    ]
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=op,
                        new_inputs=updated_inputs,
                    )

                _set_operator_outputs(
                    model_ir=model_ir,
                    op=m4_op,
                    new_outputs=[representative_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, alias_name, representative_output_name)

                for tensor_name in [
                    msq_out_name,
                    mcube_out_name,
                    m1_out_name,
                    add1_out_name,
                    m2_out_name,
                    tanh_out_name,
                    add2_out_name,
                    m3_out_name,
                ]:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(tensor_name, None),
                        perm_post_expected,
                    )

                old_gelu_tensor = model_ir.tensors.get(gelu_out_name, None)
                representative_tensor = model_ir.tensors.get(representative_output_name, None)
                if old_gelu_tensor is not None and representative_tensor is not None:
                    representative_tensor.dtype = str(old_gelu_tensor.dtype)
                    representative_tensor.quantization = _clone_quantization(old_gelu_tensor.quantization)
                    representative_tensor.shape = [int(v) for v in list(old_gelu_tensor.shape)]
                    representative_tensor.shape_signature = (
                        [int(v) for v in list(old_gelu_tensor.shape_signature)]
                        if old_gelu_tensor.shape_signature is not None
                        else [int(v) for v in list(old_gelu_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        representative_tensor,
                        perm_post_expected,
                    )

                remove_indices = sorted(list({int(pre_idx), *post_indices}), reverse=True)
                for remove_idx in remove_indices:
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                gelu_match_found = True
                break

            if gelu_match_found:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_gelu_tanh_transpose_passthrough_chains": int(rewritten)}


def _optimize_center_size_offset_terminal_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove redundant NHWC->NCHW adapters in center/size/offset terminal heads.

    Typical target structure:
      center_nhwc --T(0,3,1,2)--> center_nchw --LOGISTIC->MAXIMUM->MINIMUM->RESHAPE([N,HW])
      size_nhwc   --T(0,3,1,2)--> size_nchw   --LOGISTIC->MAXIMUM->MINIMUM->RESHAPE([N,C,HW])->GATHER_ND
      offset_nhwc --T(0,3,1,2)--> offset_nchw --RESHAPE([N,C,HW])->GATHER_ND

    Rewrite:
      - Bypass the three transposes.
      - Keep branch math in NHWC.
      - Convert size/offset reshape shapes from [N,C,HW] to [N,HW,C].
      - Reorder GATHER_ND coords concat from [batch, channel, axis] to [batch, axis, channel].
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _single_consumer_op(
        tensor_name: str,
        consumers: Dict[str, List[int]],
        expected_type: str,
    ) -> Optional[int]:
        user_indices = [int(v) for v in consumers.get(str(tensor_name), [])]
        if len(user_indices) != 1:
            return None
        op_idx = int(user_indices[0])
        op = model_ir.operators[int(op_idx)]
        if str(op.op_type) != str(expected_type):
            return None
        return int(op_idx)

    def _next_unary_chain(
        start_tensor_name: str,
        consumers: Dict[str, List[int]],
        op_type: str,
    ) -> Optional[Tuple[int, str]]:
        op_idx = _single_consumer_op(start_tensor_name, consumers, op_type)
        if op_idx is None:
            return None
        op = model_ir.operators[int(op_idx)]
        if len(op.inputs) == 0 or len(op.outputs) != 1:
            return None
        if str(op.inputs[0]) != str(start_tensor_name):
            return None
        return int(op_idx), str(op.outputs[0])

    def _next_binary_const_chain(
        start_tensor_name: str,
        consumers: Dict[str, List[int]],
        op_type: str,
    ) -> Optional[Tuple[int, str]]:
        op_idx = _single_consumer_op(start_tensor_name, consumers, op_type)
        if op_idx is None:
            return None
        op = model_ir.operators[int(op_idx)]
        if len(op.inputs) != 2 or len(op.outputs) != 1:
            return None
        in0 = str(op.inputs[0])
        in1 = str(op.inputs[1])
        if in0 == str(start_tensor_name):
            side_name = str(in1)
        elif in1 == str(start_tensor_name):
            side_name = str(in0)
        else:
            return None
        if not _is_singleton_constant_tensor(model_ir, side_name):
            return None
        return int(op_idx), str(op.outputs[0])

    def _resolve_gather_coords_reorder_plan(
        *,
        gather_idx: int,
        producers: Dict[str, int],
    ) -> Optional[Tuple[int, List[str]]]:
        gather_op = model_ir.operators[int(gather_idx)]
        if str(gather_op.op_type) != "GATHER_ND" or len(gather_op.inputs) != 2:
            return None
        coords_name = str(gather_op.inputs[1])
        concat_idx = producers.get(coords_name, None)
        if concat_idx is None:
            return None
        concat_op = model_ir.operators[int(concat_idx)]
        if (
            str(concat_op.op_type) != "CONCATENATION"
            or len(concat_op.inputs) != 3
            or len(concat_op.outputs) != 1
            or str(concat_op.outputs[0]) != coords_name
            or int(concat_op.options.get("axis", -1)) != 3
        ):
            return None

        concat_inputs = [str(v) for v in list(concat_op.inputs)]
        axis_pos: Optional[int] = None
        for pos, input_name in enumerate(concat_inputs):
            prod_idx = producers.get(str(input_name), None)
            if prod_idx is None:
                continue
            prod_op = model_ir.operators[int(prod_idx)]
            if str(prod_op.op_type) != "RESHAPE":
                continue
            axis_tensor = model_ir.tensors.get(str(input_name), None)
            if axis_tensor is None or len(list(axis_tensor.shape)) != 4:
                continue
            if int(axis_tensor.shape[-1]) != 1:
                continue
            axis_pos = int(pos)
            break
        if axis_pos is None:
            return None

        other_positions = [int(v) for v in [0, 1, 2] if int(v) != int(axis_pos)]
        if len(other_positions) != 2:
            return None

        channel_pos: Optional[int] = None
        for pos in other_positions:
            tensor = model_ir.tensors.get(concat_inputs[int(pos)], None)
            if tensor is None or tensor.data is None:
                continue
            values = np.asarray(tensor.data).reshape(-1)
            if values.size == 0:
                continue
            unique_vals = sorted(list({int(v) for v in values.tolist()}))
            if len(unique_vals) > 1:
                channel_pos = int(pos)
                break
        if channel_pos is None:
            channel_pos = int(other_positions[-1])
        batch_pos = int(other_positions[0] if int(other_positions[0]) != int(channel_pos) else other_positions[1])

        reordered = [
            concat_inputs[int(batch_pos)],
            concat_inputs[int(axis_pos)],
            concat_inputs[int(channel_pos)],
        ]
        return int(concat_idx), [str(v) for v in reordered]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for center_pre_idx, center_pre_op in enumerate(model_ir.operators):
            if str(center_pre_op.op_type) != "TRANSPOSE" or len(center_pre_op.inputs) < 2 or len(center_pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, center_pre_op) != perm_nhwc_to_nchw:
                continue
            center_nhwc_name = str(center_pre_op.inputs[0])
            center_nchw_name = str(center_pre_op.outputs[0])
            if center_nhwc_name in model_outputs or center_nchw_name in model_outputs:
                continue

            center_log_idx = _single_consumer_op(center_nchw_name, consumers, "LOGISTIC")
            if center_log_idx is None:
                continue
            center_log_op = model_ir.operators[int(center_log_idx)]
            if len(center_log_op.inputs) != 1 or len(center_log_op.outputs) != 1:
                continue
            if str(center_log_op.inputs[0]) != center_nchw_name:
                continue
            center_log_out = str(center_log_op.outputs[0])

            center_max_info = _next_binary_const_chain(center_log_out, consumers, "MAXIMUM")
            if center_max_info is None:
                continue
            center_max_idx, center_max_out = center_max_info
            center_min_info = _next_binary_const_chain(center_max_out, consumers, "MINIMUM")
            if center_min_info is None:
                continue
            center_min_idx, center_min_out = center_min_info

            center_flat_idx = _single_consumer_op(center_min_out, consumers, "RESHAPE")
            if center_flat_idx is None:
                continue
            center_flat_op = model_ir.operators[int(center_flat_idx)]
            if len(center_flat_op.inputs) < 2 or len(center_flat_op.outputs) != 1:
                continue
            if str(center_flat_op.inputs[0]) != center_min_out:
                continue
            center_flat_shape_tensor = model_ir.tensors.get(str(center_flat_op.inputs[1]), None)
            center_flat_shape = _read_const_ints_from_tensor(center_flat_shape_tensor)
            if center_flat_shape is None or len(center_flat_shape) != 2:
                continue

            # Find paired size/offset pre-transposes in the same region.
            size_pre_idx: Optional[int] = None
            size_pre_op: Optional[OperatorIR] = None
            offset_pre_idx: Optional[int] = None
            offset_pre_op: Optional[OperatorIR] = None
            for candidate_idx in range(int(center_pre_idx) + 1, min(len(model_ir.operators), int(center_pre_idx) + 16)):
                candidate_op = model_ir.operators[int(candidate_idx)]
                if str(candidate_op.op_type) != "TRANSPOSE" or len(candidate_op.inputs) < 2 or len(candidate_op.outputs) != 1:
                    continue
                if _read_transpose_perm(model_ir, candidate_op) != perm_nhwc_to_nchw:
                    continue
                candidate_out = str(candidate_op.outputs[0])
                candidate_users = [int(v) for v in consumers.get(candidate_out, [])]
                if len(candidate_users) != 1:
                    continue
                user_op = model_ir.operators[int(candidate_users[0])]
                if str(user_op.op_type) == "LOGISTIC" and size_pre_idx is None:
                    size_pre_idx = int(candidate_idx)
                    size_pre_op = candidate_op
                    continue
                if str(user_op.op_type) == "RESHAPE" and offset_pre_idx is None:
                    offset_pre_idx = int(candidate_idx)
                    offset_pre_op = candidate_op
                    continue
            if size_pre_idx is None or size_pre_op is None or offset_pre_idx is None or offset_pre_op is None:
                continue

            size_nhwc_name = str(size_pre_op.inputs[0])
            size_nchw_name = str(size_pre_op.outputs[0])
            offset_nhwc_name = str(offset_pre_op.inputs[0])
            offset_nchw_name = str(offset_pre_op.outputs[0])
            if (
                size_nhwc_name in model_outputs
                or size_nchw_name in model_outputs
                or offset_nhwc_name in model_outputs
                or offset_nchw_name in model_outputs
            ):
                continue

            size_log_idx = _single_consumer_op(size_nchw_name, consumers, "LOGISTIC")
            if size_log_idx is None:
                continue
            size_log_op = model_ir.operators[int(size_log_idx)]
            if len(size_log_op.inputs) != 1 or len(size_log_op.outputs) != 1:
                continue
            if str(size_log_op.inputs[0]) != size_nchw_name:
                continue
            size_log_out = str(size_log_op.outputs[0])

            size_max_info = _next_binary_const_chain(size_log_out, consumers, "MAXIMUM")
            if size_max_info is None:
                continue
            size_max_idx, size_max_out = size_max_info
            size_min_info = _next_binary_const_chain(size_max_out, consumers, "MINIMUM")
            if size_min_info is None:
                continue
            size_min_idx, size_min_out = size_min_info

            size_reshape_idx = _single_consumer_op(size_min_out, consumers, "RESHAPE")
            if size_reshape_idx is None:
                continue
            size_reshape_op = model_ir.operators[int(size_reshape_idx)]
            if len(size_reshape_op.inputs) < 2 or len(size_reshape_op.outputs) != 1:
                continue
            if str(size_reshape_op.inputs[0]) != size_min_out:
                continue
            size_reshape_shape_tensor = model_ir.tensors.get(str(size_reshape_op.inputs[1]), None)
            size_reshape_shape = _read_const_ints_from_tensor(size_reshape_shape_tensor)
            if size_reshape_shape is None or len(size_reshape_shape) != 3:
                continue
            size_reshape_out = str(size_reshape_op.outputs[0])

            offset_reshape_idx = _single_consumer_op(offset_nchw_name, consumers, "RESHAPE")
            if offset_reshape_idx is None:
                continue
            offset_reshape_op = model_ir.operators[int(offset_reshape_idx)]
            if len(offset_reshape_op.inputs) < 2 or len(offset_reshape_op.outputs) != 1:
                continue
            if str(offset_reshape_op.inputs[0]) != offset_nchw_name:
                continue
            offset_reshape_shape_tensor = model_ir.tensors.get(str(offset_reshape_op.inputs[1]), None)
            offset_reshape_shape = _read_const_ints_from_tensor(offset_reshape_shape_tensor)
            if offset_reshape_shape is None or len(offset_reshape_shape) != 3:
                continue
            if [int(v) for v in offset_reshape_shape] != [int(v) for v in size_reshape_shape]:
                continue
            offset_reshape_out = str(offset_reshape_op.outputs[0])

            size_gather_idx = _single_consumer_op(size_reshape_out, consumers, "GATHER_ND")
            if size_gather_idx is None:
                continue
            offset_gather_idx = _single_consumer_op(offset_reshape_out, consumers, "GATHER_ND")
            if offset_gather_idx is None:
                continue

            size_concat_plan = _resolve_gather_coords_reorder_plan(
                gather_idx=int(size_gather_idx),
                producers=producers,
            )
            if size_concat_plan is None:
                continue
            offset_concat_plan = _resolve_gather_coords_reorder_plan(
                gather_idx=int(offset_gather_idx),
                producers=producers,
            )
            if offset_concat_plan is None:
                continue

            # Rewire to NHWC sources.
            _set_operator_inputs(
                model_ir=model_ir,
                op=center_log_op,
                new_inputs=[center_nhwc_name],
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=size_log_op,
                new_inputs=[size_nhwc_name],
            )
            offset_inputs = [str(v) for v in list(offset_reshape_op.inputs)]
            offset_inputs[0] = str(offset_nhwc_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=offset_reshape_op,
                new_inputs=offset_inputs,
            )

            for tensor_name in [
                center_log_out,
                center_max_out,
                center_min_out,
                size_log_out,
                size_max_out,
                size_min_out,
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(tensor_name, None),
                    perm_nchw_to_nhwc,
                )

            new_reshape_shape = [
                int(size_reshape_shape[0]),
                int(size_reshape_shape[2]),
                int(size_reshape_shape[1]),
            ]
            if not _write_const_ints_to_tensor(size_reshape_shape_tensor, [int(v) for v in new_reshape_shape]):
                continue
            if not _write_const_ints_to_tensor(offset_reshape_shape_tensor, [int(v) for v in new_reshape_shape]):
                continue

            size_opts = dict(size_reshape_op.options) if isinstance(size_reshape_op.options, dict) else {}
            if "newShape" in size_opts and isinstance(size_opts["newShape"], list):
                size_opts["newShape"] = [int(v) for v in list(new_reshape_shape)]
            if "onnxRawNewShape" in size_opts and isinstance(size_opts["onnxRawNewShape"], list) and len(size_opts["onnxRawNewShape"]) == 3:
                old_raw = [int(v) for v in list(size_opts["onnxRawNewShape"])]
                size_opts["onnxRawNewShape"] = [int(old_raw[0]), int(old_raw[2]), int(old_raw[1])]
            size_reshape_op.options = size_opts

            offset_opts = dict(offset_reshape_op.options) if isinstance(offset_reshape_op.options, dict) else {}
            if "newShape" in offset_opts and isinstance(offset_opts["newShape"], list):
                offset_opts["newShape"] = [int(v) for v in list(new_reshape_shape)]
            if "onnxRawNewShape" in offset_opts and isinstance(offset_opts["onnxRawNewShape"], list) and len(offset_opts["onnxRawNewShape"]) == 3:
                old_raw = [int(v) for v in list(offset_opts["onnxRawNewShape"])]
                offset_opts["onnxRawNewShape"] = [int(old_raw[0]), int(old_raw[2]), int(old_raw[1])]
            offset_reshape_op.options = offset_opts

            size_out_tensor = model_ir.tensors.get(size_reshape_out, None)
            if size_out_tensor is not None:
                size_out_tensor.shape = [int(v) for v in list(new_reshape_shape)]
                size_out_tensor.shape_signature = [int(v) for v in list(new_reshape_shape)]
            offset_out_tensor = model_ir.tensors.get(offset_reshape_out, None)
            if offset_out_tensor is not None:
                offset_out_tensor.shape = [int(v) for v in list(new_reshape_shape)]
                offset_out_tensor.shape_signature = [int(v) for v in list(new_reshape_shape)]

            size_concat_idx, size_concat_inputs = size_concat_plan
            _set_operator_inputs(
                model_ir=model_ir,
                op=model_ir.operators[int(size_concat_idx)],
                new_inputs=[str(v) for v in size_concat_inputs],
            )
            offset_concat_idx, offset_concat_inputs = offset_concat_plan
            _set_operator_inputs(
                model_ir=model_ir,
                op=model_ir.operators[int(offset_concat_idx)],
                new_inputs=[str(v) for v in offset_concat_inputs],
            )

            remove_indices = sorted(
                list({int(center_pre_idx), int(size_pre_idx), int(offset_pre_idx)}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_center_size_offset_terminal_transpose_chains": int(rewritten)}


def _optimize_leakyrelu_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around pseudo-op-expanded LeakyReLU chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --NEG--> n --RELU--> nr --MUL(alpha)--> m
      x_t --RELU--> p
      p --SUB(m)--> y_t
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --NEG--> n --RELU--> nr --MUL(alpha)--> m
      X --RELU--> p
      p --SUB(m)--> Y

    Safety:
    - Strict LeakyReLU topology (NEG/RELU fanout + RELU + MUL + SUB).
    - MUL side input must be singleton constant (alpha scalar-like).
    - Single-consumer chain on each branch and tail.
    """
    rewritten = 0

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE":
                continue
            if len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 2:
                continue

            neg_idx = None
            relu_pos_idx = None
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)
                if (
                    user_type == "NEG"
                    and len(user_op.inputs) == 1
                    and str(user_op.inputs[0]) == pre_output_name
                    and len(user_op.outputs) == 1
                ):
                    neg_idx = int(user_idx)
                elif (
                    user_type == "RELU"
                    and len(user_op.inputs) == 1
                    and str(user_op.inputs[0]) == pre_output_name
                    and len(user_op.outputs) == 1
                ):
                    relu_pos_idx = int(user_idx)
            if neg_idx is None or relu_pos_idx is None:
                continue

            neg_op = model_ir.operators[int(neg_idx)]
            neg_out_name = str(neg_op.outputs[0])
            neg_users = [int(v) for v in consumers.get(neg_out_name, [])]
            if len(neg_users) != 1:
                continue
            relu_neg_idx = int(neg_users[0])
            relu_neg_op = model_ir.operators[int(relu_neg_idx)]
            if (
                str(relu_neg_op.op_type) != "RELU"
                or len(relu_neg_op.inputs) != 1
                or len(relu_neg_op.outputs) != 1
                or str(relu_neg_op.inputs[0]) != neg_out_name
            ):
                continue
            relu_neg_out_name = str(relu_neg_op.outputs[0])

            relu_neg_users = [int(v) for v in consumers.get(relu_neg_out_name, [])]
            if len(relu_neg_users) != 1:
                continue
            mul_idx = int(relu_neg_users[0])
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_inputs = [str(v) for v in mul_op.inputs]
            if relu_neg_out_name == mul_inputs[0]:
                mul_side_input_name = mul_inputs[1]
            elif relu_neg_out_name == mul_inputs[1]:
                mul_side_input_name = mul_inputs[0]
            else:
                continue
            if not _is_singleton_constant_tensor(model_ir, mul_side_input_name):
                continue
            mul_out_name = str(mul_op.outputs[0])

            relu_pos_op = model_ir.operators[int(relu_pos_idx)]
            relu_pos_out_name = str(relu_pos_op.outputs[0])
            relu_pos_users = [int(v) for v in consumers.get(relu_pos_out_name, [])]
            if len(relu_pos_users) != 1:
                continue

            mul_users = [int(v) for v in consumers.get(mul_out_name, [])]
            if len(mul_users) != 1:
                continue
            sub_idx = int(mul_users[0])
            if relu_pos_users[0] != sub_idx:
                continue

            sub_op = model_ir.operators[int(sub_idx)]
            if str(sub_op.op_type) != "SUB" or len(sub_op.inputs) != 2 or len(sub_op.outputs) != 1:
                continue
            sub_inputs = [str(v) for v in sub_op.inputs]
            if sub_inputs != [relu_pos_out_name, mul_out_name]:
                continue
            sub_out_name = str(sub_op.outputs[0])

            sub_users = [int(v) for v in consumers.get(sub_out_name, []) if int(v) != int(sub_idx)]
            if len(sub_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in sub_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == sub_out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    if perm_post is None or perm_post != perm_post_expected:
                        valid_users = False
                        break
                    post_output_name = str(user_op.outputs[0])
                    if post_output_name in model_outputs:
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue
            post_output_name = str(post_output_names[0])

            # Rewire the pseudo-LeakyReLU chain to consume source layout directly.
            _set_operator_inputs(
                model_ir=model_ir,
                op=neg_op,
                new_inputs=[pre_input_name],
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=relu_pos_op,
                new_inputs=[pre_input_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=sub_op,
                new_outputs=[post_output_name],
            )
            for alias_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_output_name, post_output_name)

            # Update intermediate metadata from transposed layout to source layout.
            for intermediate_name in [neg_out_name, relu_pos_out_name, relu_neg_out_name, mul_out_name]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(intermediate_name, None),
                    perm_post_expected,
                )

            # Keep final tensor metadata stable on the post-transpose name.
            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            old_sub_tensor = model_ir.tensors.get(sub_out_name, None)
            post_output_tensor = model_ir.tensors.get(post_output_name, None)
            if post_output_tensor is not None:
                if pre_input_tensor is not None:
                    post_output_tensor.shape = [int(v) for v in list(pre_input_tensor.shape)]
                    post_output_tensor.shape_signature = (
                        [int(v) for v in list(pre_input_tensor.shape_signature)]
                        if pre_input_tensor.shape_signature is not None
                        else [int(v) for v in list(pre_input_tensor.shape)]
                    )
                if old_sub_tensor is not None:
                    post_output_tensor.dtype = str(old_sub_tensor.dtype)
                    post_output_tensor.quantization = _clone_quantization(old_sub_tensor.quantization)

            preserve_nchw_adapter = len(legacy_users) > 0 or sub_out_name in model_outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[keep_post_idx]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[sub_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(list({int(pre_idx), *post_remove_indices}), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    fuse_stats = _optimize_fuse_pseudo_leakyrelu_chains(model_ir)
    _prune_unused_tensors(model_ir)
    return {
        "rewritten_leakyrelu_transpose_passthrough_chains": int(rewritten),
        "fused_pseudo_leakyrelu_chains": int(
            fuse_stats.get("fused_pseudo_leakyrelu_chains", 0)
        ),
    }


def _optimize_prelu_transpose_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold transpose wrappers around PRELU chains.

    Target:
      X --TRANSPOSE(P)--> x_t
      x_t --PRELU(alpha)--> y_t
      y_t --TRANSPOSE(inv(P))--> Y

    Rewrite:
      X --PRELU(alpha')--> Y

    Safety:
    - PRELU alpha must be constant.
    - Requires at least one inverse post-transpose consumer.
    - Keeps one adapter transpose when legacy NCHW consumers remain.
    """
    rewritten = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            perm_pre = _read_transpose_perm(model_ir, pre_op)
            if perm_pre is None:
                continue
            perm_post_expected = _invert_perm(perm_pre)
            if perm_post_expected is None:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue

            prelu_candidates: List[int] = []
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "PRELU"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == pre_output_name
                ):
                    prelu_candidates.append(int(user_idx))
            if len(prelu_candidates) != 1:
                continue

            prelu_idx = int(prelu_candidates[0])
            prelu_op = model_ir.operators[int(prelu_idx)]
            prelu_out_name = str(prelu_op.outputs[0])
            if prelu_out_name in model_outputs:
                continue

            prelu_users = [int(v) for v in consumers.get(prelu_out_name, [])]
            if len(prelu_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in prelu_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == prelu_out_name
                ):
                    perm_post = _read_transpose_perm(model_ir, user_op)
                    post_output_name = str(user_op.outputs[0])
                    if (
                        perm_post is None
                        or perm_post != perm_post_expected
                        or post_output_name in model_outputs
                    ):
                        valid_users = False
                        break
                    post_indices.append(int(user_idx))
                    post_output_names.append(post_output_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue

            alpha_name = str(prelu_op.inputs[1])
            alpha_tensor = model_ir.tensors.get(alpha_name, None)
            if alpha_tensor is None or not isinstance(alpha_tensor.data, np.ndarray):
                continue

            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            target_shape = (
                [int(v) for v in list(pre_input_tensor.shape)]
                if pre_input_tensor is not None and pre_input_tensor.shape is not None
                else None
            )

            alpha_data = np.asarray(alpha_tensor.data)
            alpha_candidates: List[np.ndarray] = []
            if int(alpha_data.ndim) == int(len(perm_post_expected)):
                # Prefer layout-remapped alpha first. For ambiguous static shapes
                # (e.g. [1,64,64,64]), both original/transposed alpha can be
                # broadcastable; original-first selection can silently keep
                # NCHW alpha on NHWC PRELU after transpose passthrough rewrite.
                alpha_candidates.append(
                    np.transpose(alpha_data, axes=perm_post_expected).astype(alpha_data.dtype, copy=False)
                )
            alpha_candidates.append(np.asarray(alpha_data))
            if perm_pre == [0, 3, 1, 2] and perm_post_expected == [0, 2, 3, 1] and int(alpha_data.ndim) == 3:
                alpha_candidates.append(
                    np.transpose(alpha_data, axes=[1, 2, 0]).astype(alpha_data.dtype, copy=False)
                )

            def _broadcastable_to_target(candidate: np.ndarray) -> bool:
                if target_shape is None:
                    return True
                return (
                    _broadcast_static_shapes(
                        [int(v) for v in list(target_shape)],
                        [int(v) for v in list(candidate.shape)],
                    )
                    is not None
                )

            selected_alpha: Optional[np.ndarray] = None
            for candidate in alpha_candidates:
                if _broadcastable_to_target(candidate):
                    selected_alpha = np.asarray(candidate)
                    break
            if selected_alpha is None:
                continue

            selected_alpha_name = str(alpha_name)
            alpha_users = [int(v) for v in consumers.get(alpha_name, [])]
            alpha_needs_rewrite = (
                selected_alpha.shape != alpha_data.shape
                or not np.array_equal(selected_alpha, alpha_data)
            )
            if alpha_needs_rewrite:
                if len(alpha_users) == 1 and int(alpha_users[0]) == int(prelu_idx):
                    shape, signature = normalize_onnx_shape(list(selected_alpha.shape))
                    alpha_tensor.data = np.asarray(selected_alpha)
                    alpha_tensor.shape = [int(v) for v in list(shape)]
                    alpha_tensor.shape_signature = [int(v) for v in list(signature)]
                else:
                    selected_alpha_name = _unique_tensor_name(f"{alpha_name}_nhwc")
                    shape, signature = normalize_onnx_shape(list(selected_alpha.shape))
                    model_ir.tensors[selected_alpha_name] = TensorIR(
                        name=selected_alpha_name,
                        dtype=str(alpha_tensor.dtype),
                        shape=[int(v) for v in list(shape)],
                        shape_signature=[int(v) for v in list(signature)],
                        data=np.asarray(selected_alpha),
                        is_variable=False,
                        quantization=_clone_quantization(alpha_tensor.quantization),
                    )

            representative_output_name = str(post_output_names[0])
            _set_operator_inputs(
                model_ir=model_ir,
                op=prelu_op,
                new_inputs=[pre_input_name, selected_alpha_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[representative_output_name],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_name, representative_output_name)

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(prelu_out_name, None),
                perm_post_expected,
            )

            old_prelu_tensor = model_ir.tensors.get(prelu_out_name, None)
            representative_tensor = model_ir.tensors.get(representative_output_name, None)
            if old_prelu_tensor is not None and representative_tensor is not None:
                representative_tensor.dtype = str(old_prelu_tensor.dtype)
                representative_tensor.quantization = _clone_quantization(old_prelu_tensor.quantization)
                representative_tensor.shape = [int(v) for v in list(old_prelu_tensor.shape)]
                representative_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu_tensor.shape_signature)]
                    if old_prelu_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    representative_tensor,
                    perm_post_expected,
                )

            preserve_nchw_adapter = len(legacy_users) > 0 or prelu_out_name in model_outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[keep_post_idx]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_pre, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[representative_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[prelu_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = set(int(v) for v in post_remove_indices)
            pre_remaining_users = [int(v) for v in pre_users if int(v) != int(prelu_idx)]
            if len(pre_remaining_users) == 0:
                remove_indices.add(int(pre_idx))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"rewritten_prelu_transpose_passthrough_chains": int(rewritten)}


def _optimize_transpose_elementwise_concat_conv_nhwc_groups(model_ir: ModelIR) -> Dict[str, int]:
    """
    Lift NCHW elementwise/concat groups back to NHWC when they are terminated by
    CONCAT(axis=1) -> TRANSPOSE(0,2,3,1) adapters into Conv inputs.

    This pass rewrites a whole connected concat group at once (not per-node),
    so shared upstream elementwise producers are converted consistently.
    """
    optimized_groups = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw_const_name = "__nhwc_to_nchw_perm_rank4__"
    unary_ops = {"RELU", "RELU6", "LEAKY_RELU", "LOGISTIC", "TANH", "NEG", "EXP", "ABS", "SQRT", "GELU", "ELU"}
    binary_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM"}
    legacy_consumer_safe_ops = set(unary_ops) | set(binary_ops)

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    if perm_nhwc_to_nchw_const_name not in model_ir.tensors:
        model_ir.tensors[perm_nhwc_to_nchw_const_name] = TensorIR(
            name=perm_nhwc_to_nchw_const_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
            is_variable=False,
            quantization=None,
        )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        candidate_concats: List[int] = []
        post_by_concat: Dict[int, List[int]] = {}
        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            axis_old = int(concat_op.options.get("axis", 1))
            if axis_old < 0:
                axis_old += 4
            if axis_old != 1:
                continue
            concat_out = str(concat_op.outputs[0])
            concat_users = [int(v) for v in consumers.get(concat_out, [])]
            if len(concat_users) == 0:
                continue
            post_indices: List[int] = []
            valid_users = True
            for user_idx in concat_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) != "TRANSPOSE"
                    or len(user_op.inputs) < 2
                    or len(user_op.outputs) != 1
                    or str(user_op.inputs[0]) != concat_out
                    or _read_transpose_perm(model_ir, user_op) != perm_nchw_to_nhwc
                    or str(user_op.outputs[0]) in model_outputs
                ):
                    valid_users = False
                    break
                post_indices.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue
            candidate_concats.append(int(concat_idx))
            post_by_concat[int(concat_idx)] = [int(v) for v in post_indices]

        if len(candidate_concats) == 0:
            break

        for seed_concat_idx in candidate_concats:
            target_concats: set[int] = {int(seed_concat_idx)}
            closure_ops: set[int] = set()
            boundary_transpose_by_tensor: Dict[str, Tuple[str, int]] = {}
            const_tensor_names_to_permute: set[str] = set()

            def _trace_tensor_to_nhwc(
                tensor_name: str,
                visiting: set[int],
            ) -> bool:
                if str(tensor_name) in boundary_transpose_by_tensor:
                    return True
                producer_idx = producers.get(str(tensor_name), None)
                if producer_idx is None:
                    tensor = model_ir.tensors.get(str(tensor_name), None)
                    if (
                        str(tensor_name) in set(str(v) for v in model_ir.inputs)
                        and tensor is not None
                        and len(list(tensor.shape)) == 4
                    ):
                        boundary_transpose_by_tensor[str(tensor_name)] = (str(tensor_name), -1)
                        return True
                    return False
                producer_op = model_ir.operators[int(producer_idx)]
                producer_type = str(producer_op.op_type)

                if (
                    producer_type == "TRANSPOSE"
                    and len(producer_op.inputs) >= 2
                    and len(producer_op.outputs) == 1
                    and str(producer_op.outputs[0]) == str(tensor_name)
                    and _read_transpose_perm(model_ir, producer_op) == perm_nhwc_to_nchw
                ):
                    boundary_transpose_by_tensor[str(tensor_name)] = (
                        str(producer_op.inputs[0]),
                        int(producer_idx),
                    )
                    return True

                # Also accept an existing forward NCHW->NHWC adapter produced
                # from this tensor by a consumer TRANSPOSE.
                for consumer_idx in [int(v) for v in consumers.get(str(tensor_name), [])]:
                    consumer_op = model_ir.operators[int(consumer_idx)]
                    if (
                        str(consumer_op.op_type) == "TRANSPOSE"
                        and len(consumer_op.inputs) >= 2
                        and len(consumer_op.outputs) == 1
                        and str(consumer_op.inputs[0]) == str(tensor_name)
                        and _read_transpose_perm(model_ir, consumer_op) == perm_nchw_to_nhwc
                        and str(consumer_op.outputs[0]) not in model_outputs
                    ):
                        boundary_transpose_by_tensor[str(tensor_name)] = (
                            str(consumer_op.outputs[0]),
                            -1,
                        )
                        return True

                if int(producer_idx) in closure_ops:
                    return True
                if int(producer_idx) in visiting:
                    return False
                if str(tensor_name) in model_outputs:
                    return False

                if producer_type in unary_ops:
                    if len(producer_op.inputs) != 1 or len(producer_op.outputs) != 1:
                        return False
                    visiting.add(int(producer_idx))
                    closure_ops.add(int(producer_idx))
                    ok = _trace_tensor_to_nhwc(str(producer_op.inputs[0]), visiting)
                    visiting.remove(int(producer_idx))
                    return bool(ok)

                if producer_type in binary_ops:
                    if len(producer_op.inputs) != 2 or len(producer_op.outputs) != 1:
                        return False
                    visiting.add(int(producer_idx))
                    closure_ops.add(int(producer_idx))
                    ok = True
                    for input_name in [str(v) for v in list(producer_op.inputs)]:
                        input_tensor = model_ir.tensors.get(str(input_name), None)
                        if input_tensor is not None and input_tensor.data is not None:
                            try:
                                const_arr = np.asarray(input_tensor.data)
                            except Exception:
                                const_arr = None
                            if const_arr is not None and const_arr.ndim == 4 and int(const_arr.size) > 1:
                                const_tensor_names_to_permute.add(str(input_name))
                            continue
                        if not _trace_tensor_to_nhwc(str(input_name), visiting):
                            ok = False
                            break
                    visiting.remove(int(producer_idx))
                    return bool(ok)

                return False

            analysis_ok = True
            while True:
                closure_ops.clear()
                boundary_transpose_by_tensor.clear()
                const_tensor_names_to_permute.clear()

                for concat_idx in sorted(list(target_concats)):
                    concat_op = model_ir.operators[int(concat_idx)]
                    if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.inputs) == 0:
                        analysis_ok = False
                        break
                    for concat_input_name in [str(v) for v in list(concat_op.inputs)]:
                        if not _trace_tensor_to_nhwc(concat_input_name, set()):
                            analysis_ok = False
                            break
                    if not analysis_ok:
                        break
                if not analysis_ok:
                    break

                expanded = False
                for candidate_concat_idx in candidate_concats:
                    if int(candidate_concat_idx) in target_concats:
                        continue
                    candidate_concat_op = model_ir.operators[int(candidate_concat_idx)]
                    for candidate_input_name in [str(v) for v in list(candidate_concat_op.inputs)]:
                        candidate_input_prod = producers.get(str(candidate_input_name), None)
                        if candidate_input_prod is not None and int(candidate_input_prod) in closure_ops:
                            target_concats.add(int(candidate_concat_idx))
                            expanded = True
                            break
                if not expanded:
                    break

            if not analysis_ok:
                continue

            target_post_indices: set[int] = set()
            for concat_idx in target_concats:
                target_post_indices.update(set(int(v) for v in post_by_concat.get(int(concat_idx), [])))
            allowed_consumer_indices = set(int(v) for v in closure_ops) | set(int(v) for v in target_concats) | set(
                int(v) for v in target_post_indices
            )

            valid_group = True
            legacy_consumer_slots_by_output: Dict[str, List[Tuple[int, int]]] = {}
            for op_idx in sorted(list(closure_ops)):
                op = model_ir.operators[int(op_idx)]
                if any(str(output_name) in model_outputs for output_name in op.outputs):
                    valid_group = False
                    break
                for output_name in [str(v) for v in list(op.outputs)]:
                    external_slots: List[Tuple[int, int]] = []
                    for user_idx in [int(v) for v in consumers.get(str(output_name), [])]:
                        if int(user_idx) in allowed_consumer_indices:
                            continue
                        user_op = model_ir.operators[int(user_idx)]
                        if str(user_op.op_type) not in legacy_consumer_safe_ops:
                            valid_group = False
                            break
                        input_indices = [
                            int(input_idx)
                            for input_idx, input_name in enumerate(list(user_op.inputs))
                            if str(input_name) == str(output_name)
                        ]
                        if len(input_indices) == 0:
                            valid_group = False
                            break
                        for input_idx in input_indices:
                            external_slots.append((int(id(user_op)), int(input_idx)))
                    if not valid_group:
                        break
                    if len(external_slots) > 0:
                        legacy_consumer_slots_by_output[str(output_name)] = list(external_slots)
                if not valid_group:
                    break

            if not valid_group:
                continue

            for const_name in sorted(list(const_tensor_names_to_permute)):
                const_users = [int(v) for v in consumers.get(str(const_name), [])]
                if any(int(user_idx) not in closure_ops for user_idx in const_users):
                    valid_group = False
                    break
            if not valid_group:
                continue

            for concat_idx in sorted(list(target_concats)):
                concat_op = model_ir.operators[int(concat_idx)]
                concat_out_name = str(concat_op.outputs[0])
                concat_users = set(int(v) for v in consumers.get(str(concat_out_name), []))
                expected_users = set(int(v) for v in post_by_concat.get(int(concat_idx), []))
                if concat_users != expected_users:
                    valid_group = False
                    break
            if not valid_group:
                continue

            remove_indices: set[int] = set()
            legacy_nchw_tensor_meta_by_output: Dict[str, Tuple[str, Optional[Any], List[int], List[int]]] = {}
            for const_name in sorted(list(const_tensor_names_to_permute)):
                const_tensor = model_ir.tensors.get(str(const_name), None)
                if const_tensor is None or const_tensor.data is None:
                    continue
                const_arr = np.asarray(const_tensor.data)
                if const_arr.ndim != 4 or int(const_arr.size) <= 1:
                    continue
                transposed = np.transpose(const_arr, axes=perm_nchw_to_nhwc)
                const_tensor.data = np.asarray(transposed)
                const_tensor.shape = [int(v) for v in list(transposed.shape)]
                const_tensor.shape_signature = [int(v) for v in list(transposed.shape)]

            for op_idx in sorted(list(closure_ops)):
                op = model_ir.operators[int(op_idx)]
                old_inputs = [str(v) for v in list(op.inputs)]
                new_inputs: List[str] = []
                for input_name in old_inputs:
                    boundary = boundary_transpose_by_tensor.get(str(input_name), None)
                    if boundary is not None:
                        new_inputs.append(str(boundary[0]))
                        remove_indices.add(int(boundary[1]))
                    else:
                        new_inputs.append(str(input_name))
                if new_inputs != old_inputs:
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=op,
                        new_inputs=[str(v) for v in list(new_inputs)],
                    )
                for output_name in [str(v) for v in list(op.outputs)]:
                    if str(output_name) in legacy_consumer_slots_by_output:
                        output_tensor = model_ir.tensors.get(str(output_name), None)
                        if output_tensor is not None and len(list(output_tensor.shape)) == 4:
                            legacy_nchw_tensor_meta_by_output[str(output_name)] = (
                                str(output_tensor.dtype),
                                _clone_quantization(output_tensor.quantization),
                                [int(v) for v in list(output_tensor.shape)],
                                (
                                    [int(v) for v in list(output_tensor.shape_signature)]
                                    if output_tensor.shape_signature is not None
                                    else [int(v) for v in list(output_tensor.shape)]
                                ),
                            )
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(output_name), None),
                        perm_nchw_to_nhwc,
                    )

            post_indices_to_remove: set[int] = set()
            for concat_idx in sorted(list(target_concats)):
                concat_op = model_ir.operators[int(concat_idx)]
                old_concat_out_name = str(concat_op.outputs[0])
                old_concat_tensor = model_ir.tensors.get(old_concat_out_name, None)
                old_inputs = [str(v) for v in list(concat_op.inputs)]
                new_inputs: List[str] = []
                for input_name in old_inputs:
                    boundary = boundary_transpose_by_tensor.get(str(input_name), None)
                    if boundary is not None:
                        new_inputs.append(str(boundary[0]))
                        remove_indices.add(int(boundary[1]))
                    else:
                        new_inputs.append(str(input_name))
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=concat_op,
                    new_inputs=[str(v) for v in list(new_inputs)],
                )
                concat_op.options["axis"] = 3
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(old_concat_out_name, None),
                    perm_nchw_to_nhwc,
                )

                post_indices = sorted([int(v) for v in post_by_concat.get(int(concat_idx), [])])
                if len(post_indices) == 0:
                    valid_group = False
                    break
                canonical_post_idx = int(post_indices[0])
                canonical_post_op = model_ir.operators[int(canonical_post_idx)]
                canonical_post_out_name = str(canonical_post_op.outputs[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=concat_op,
                    new_outputs=[canonical_post_out_name],
                )
                for alias_post_idx in post_indices[1:]:
                    alias_post_op = model_ir.operators[int(alias_post_idx)]
                    alias_output_name = str(alias_post_op.outputs[0])
                    _replace_tensor_inputs(model_ir, alias_output_name, canonical_post_out_name)
                canonical_post_tensor = model_ir.tensors.get(canonical_post_out_name, None)
                if old_concat_tensor is not None and canonical_post_tensor is not None:
                    canonical_post_tensor.dtype = str(old_concat_tensor.dtype)
                    canonical_post_tensor.quantization = _clone_quantization(old_concat_tensor.quantization)
                    canonical_post_tensor.shape = [int(v) for v in list(old_concat_tensor.shape)]
                    canonical_post_tensor.shape_signature = (
                        [int(v) for v in list(old_concat_tensor.shape_signature)]
                        if old_concat_tensor.shape_signature is not None
                        else [int(v) for v in list(old_concat_tensor.shape)]
                    )
                for post_idx in post_indices:
                    post_indices_to_remove.add(int(post_idx))

            if not valid_group:
                continue

            for post_idx in post_indices_to_remove:
                remove_indices.add(int(post_idx))

            consumers_after = _build_tensor_consumer_map(model_ir)
            final_remove_indices: set[int] = set()
            for remove_idx in sorted(list(remove_indices)):
                if int(remove_idx) < 0 or int(remove_idx) >= len(model_ir.operators):
                    continue
                if int(remove_idx) in post_indices_to_remove:
                    final_remove_indices.add(int(remove_idx))
                    continue
                remove_op = model_ir.operators[int(remove_idx)]
                if str(remove_op.op_type) != "TRANSPOSE" or len(remove_op.outputs) != 1:
                    continue
                remove_out_name = str(remove_op.outputs[0])
                if remove_out_name in model_outputs:
                    continue
                if len(consumers_after.get(remove_out_name, [])) == 0:
                    final_remove_indices.add(int(remove_idx))

            for remove_idx in sorted(list(final_remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            adapter_insertions: List[Tuple[int, OperatorIR]] = []
            op_index_by_id = {int(id(op)): int(op_idx) for op_idx, op in enumerate(model_ir.operators)}
            for output_name, legacy_slots in legacy_consumer_slots_by_output.items():
                output_tensor = model_ir.tensors.get(str(output_name), None)
                if output_tensor is None or len(list(output_tensor.shape)) != 4:
                    continue
                slot_targets: List[Tuple[int, int]] = []
                for consumer_op_id, input_index in legacy_slots:
                    consumer_index = op_index_by_id.get(int(consumer_op_id), None)
                    if consumer_index is None:
                        continue
                    if int(consumer_index) < 0 or int(consumer_index) >= len(model_ir.operators):
                        continue
                    consumer_op = model_ir.operators[int(consumer_index)]
                    if int(input_index) < 0 or int(input_index) >= len(consumer_op.inputs):
                        continue
                    if str(consumer_op.inputs[int(input_index)]) != str(output_name):
                        continue
                    slot_targets.append((int(consumer_index), int(input_index)))
                if len(slot_targets) == 0:
                    continue

                adapter_name = _unique_tensor_name(f"{output_name}_nchw_adapter")
                legacy_meta = legacy_nchw_tensor_meta_by_output.get(str(output_name), None)
                if legacy_meta is not None:
                    adapter_dtype, adapter_quant, adapter_shape, adapter_shape_signature = legacy_meta
                else:
                    adapter_dtype = str(output_tensor.dtype)
                    adapter_quant = _clone_quantization(output_tensor.quantization)
                    adapter_shape = [int(v) for v in list(output_tensor.shape)]
                    adapter_shape_signature = (
                        [int(v) for v in list(output_tensor.shape_signature)]
                        if output_tensor.shape_signature is not None
                        else [int(v) for v in list(output_tensor.shape)]
                    )
                model_ir.tensors[adapter_name] = TensorIR(
                    name=adapter_name,
                    dtype=str(adapter_dtype),
                    shape=[int(v) for v in list(adapter_shape)],
                    shape_signature=[int(v) for v in list(adapter_shape_signature)],
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(adapter_quant),
                )
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(output_name), perm_nhwc_to_nchw_const_name],
                    outputs=[adapter_name],
                )
                for consumer_index, input_index in slot_targets:
                    consumer_op = model_ir.operators[int(consumer_index)]
                    new_inputs = [str(v) for v in list(consumer_op.inputs)]
                    new_inputs[int(input_index)] = str(adapter_name)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=consumer_op,
                        new_inputs=new_inputs,
                    )
                insert_index = min(int(v[0]) for v in slot_targets)
                adapter_insertions.append((int(insert_index), adapter_op))

            if len(adapter_insertions) > 0:
                inserted = 0
                for insert_idx, adapter_op in sorted(adapter_insertions, key=lambda v: int(v[0])):
                    model_ir.operators.insert(int(insert_idx + inserted), adapter_op)
                    inserted += 1

            optimized_groups += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_elementwise_concat_conv_nhwc_groups": int(optimized_groups)}


def _optimize_transpose_pre_concat_nhwc_chains_legacy(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Convert NCHW concat blocks back to NHWC when they are wrapped by transpose adapters.

    Target:
      ... -> t_i_nchw (some inputs may be pseudo-LeakyRelu outputs from transpose-wrapped NHWC)
      CONCAT(axis=1, [t_0_nchw, ...]) -> y_nchw
      y_nchw -> TRANSPOSE(0,2,3,1) -> y_nhwc

    Rewrite:
      ... -> t_i_nhwc
      CONCAT(axis=3, [t_0_nhwc, ...]) -> y_nhwc
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    # NHWC <-> NHCW (self-inverse). Used to keep SOFTMAX "last-axis" semantics
    # while lifting pre-concat chains to NHWC.
    perm_nhwc_to_nhcw = [0, 1, 3, 2]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _find_or_create_perm_tensor(
        *,
        base_name: str,
        perm: List[int],
    ) -> str:
        perm_arr = np.asarray([int(v) for v in list(perm)], dtype=np.int32)
        for tensor_name, tensor in model_ir.tensors.items():
            if tensor is None or tensor.data is None:
                continue
            try:
                data = np.asarray(tensor.data)
            except Exception:
                continue
            if data.dtype != np.int32 or int(data.size) != int(len(perm)):
                continue
            if np.array_equal(data.reshape(-1), perm_arr):
                return str(tensor_name)
        new_name = _unique_tensor_name(str(base_name))
        model_ir.tensors[new_name] = TensorIR(
            name=new_name,
            dtype="INT32",
            shape=[int(len(perm))],
            shape_signature=[int(len(perm))],
            data=np.asarray(perm_arr),
            is_variable=False,
            quantization=None,
        )
        return str(new_name)

    def _select_prelu_alpha_for_nhwc(
        *,
        alpha_data: np.ndarray,
        target_nhwc_shape: Optional[List[int]],
    ) -> Optional[np.ndarray]:
        alpha_candidates: List[np.ndarray] = []
        if int(alpha_data.ndim) == int(len(perm_nchw_to_nhwc)):
            alpha_candidates.append(
                np.transpose(alpha_data, axes=perm_nchw_to_nhwc).astype(alpha_data.dtype, copy=False)
            )
        alpha_candidates.append(np.asarray(alpha_data))
        if int(alpha_data.ndim) == 3:
            alpha_candidates.append(
                np.transpose(alpha_data, axes=[1, 2, 0]).astype(alpha_data.dtype, copy=False)
            )

        def _broadcastable(candidate: np.ndarray) -> bool:
            if target_nhwc_shape is None or not _is_fully_known_positive_shape(target_nhwc_shape):
                return True
            return (
                _broadcast_static_shapes(
                    [int(v) for v in list(target_nhwc_shape)],
                    [int(v) for v in list(candidate.shape)],
                )
                is not None
            )

        for candidate in alpha_candidates:
            if _broadcastable(candidate):
                return np.asarray(candidate)
        return None

    def _analyze_swish_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
        allow_consumer_fanout_to_slice: bool = False,
    ) -> Optional[Dict[str, Any]]:
        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        input_users = set(int(v) for v in consumers.get(str(input_name), []))
        if not allow_consumer_fanout_to_slice:
            if input_users != {int(consumer_idx)}:
                return None
        else:
            if int(consumer_idx) not in input_users or len(input_users) <= 0:
                return None
            for user_idx in sorted(list(input_users)):
                user_op = model_ir.operators[int(user_idx)]
                if str(user_op.op_type) != "SLICE" or len(user_op.inputs) < 3 or len(user_op.outputs) != 1:
                    return None
                if str(user_op.inputs[0]) != str(input_name):
                    return None
                begin_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(user_op.inputs[1]), None))
                size_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(user_op.inputs[2]), None))
                if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
                    return None
                if int(size_vals[1]) <= 0:
                    return None
                if int(begin_vals[2]) != 0 or int(begin_vals[3]) != 0:
                    return None

        in0_name = str(mul_op.inputs[0])
        in1_name = str(mul_op.inputs[1])
        in0_prod_idx = producers.get(in0_name, None)
        in1_prod_idx = producers.get(in1_name, None)

        log_idx: Optional[int] = None
        log_out_name: Optional[str] = None
        pre_nchw_name: Optional[str] = None
        mul_data_input_index: Optional[int] = None

        if in0_prod_idx is not None:
            in0_prod_op = model_ir.operators[int(in0_prod_idx)]
            if (
                str(in0_prod_op.op_type) == "LOGISTIC"
                and len(in0_prod_op.inputs) == 1
                and len(in0_prod_op.outputs) == 1
                and str(in0_prod_op.outputs[0]) == in0_name
            ):
                log_idx = int(in0_prod_idx)
                log_out_name = in0_name
                pre_nchw_name = str(in0_prod_op.inputs[0])
                mul_data_input_index = 1

        if log_idx is None and in1_prod_idx is not None:
            in1_prod_op = model_ir.operators[int(in1_prod_idx)]
            if (
                str(in1_prod_op.op_type) == "LOGISTIC"
                and len(in1_prod_op.inputs) == 1
                and len(in1_prod_op.outputs) == 1
                and str(in1_prod_op.outputs[0]) == in1_name
            ):
                log_idx = int(in1_prod_idx)
                log_out_name = in1_name
                pre_nchw_name = str(in1_prod_op.inputs[0])
                mul_data_input_index = 0

        if log_idx is None or log_out_name is None or pre_nchw_name is None or mul_data_input_index is None:
            return None

        if str(mul_op.inputs[int(mul_data_input_index)]) != str(pre_nchw_name):
            return None

        pre_idx = producers.get(str(pre_nchw_name), None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != str(pre_nchw_name):
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None

        if set(int(v) for v in consumers.get(str(pre_nchw_name), [])) != {int(log_idx), int(mul_idx)}:
            return None
        if set(int(v) for v in consumers.get(str(log_out_name), [])) != {int(mul_idx)}:
            return None

        return {
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "log_idx": int(log_idx),
            "mul_idx": int(mul_idx),
            "mul_data_input_index": int(mul_data_input_index),
            "log_out_name": str(log_out_name),
            "mul_out_name": str(input_name),
        }

    def _apply_swish_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        log_idx = int(plan["log_idx"])
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        log_out_name = str(plan["log_out_name"])
        mul_out_name = str(plan["mul_out_name"])

        mul_op = model_ir.operators[int(mul_idx)]
        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(log_idx)],
            new_inputs=[pre_input_name],
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=mul_op,
            input_index=int(mul_data_input_index),
            new_input_name=pre_input_name,
        )

        for tensor_name in [log_out_name, mul_out_name]:
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(tensor_name, None),
                perm_nchw_to_nhwc,
            )
        return [int(pre_idx)]

    def _try_rewrite_swish_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        return _analyze_swish_input_to_nhwc(
            input_name=input_name,
            consumer_idx=consumer_idx,
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )

    def _try_rewrite_leaky_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        sub_idx = producers.get(str(input_name), None)
        if sub_idx is None:
            return None
        sub_op = model_ir.operators[int(sub_idx)]
        if str(sub_op.op_type) != "SUB" or len(sub_op.inputs) != 2 or len(sub_op.outputs) != 1:
            return None
        if str(sub_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        input_users = [int(v) for v in consumers.get(str(input_name), [])]
        if set(input_users) != {int(concat_idx)}:
            return None

        relu_pos_out_name = str(sub_op.inputs[0])
        mul_out_name = str(sub_op.inputs[1])

        relu_pos_idx = producers.get(relu_pos_out_name, None)
        mul_idx = producers.get(mul_out_name, None)
        if relu_pos_idx is None or mul_idx is None:
            return None
        relu_pos_op = model_ir.operators[int(relu_pos_idx)]
        mul_op = model_ir.operators[int(mul_idx)]
        if str(relu_pos_op.op_type) != "RELU" or len(relu_pos_op.inputs) != 1 or len(relu_pos_op.outputs) != 1:
            return None
        if str(relu_pos_op.outputs[0]) != relu_pos_out_name:
            return None
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != mul_out_name:
            return None
        if not _is_singleton_constant_tensor(model_ir, str(mul_op.inputs[0])) and not _is_singleton_constant_tensor(
            model_ir, str(mul_op.inputs[1])
        ):
            return None

        relu_pos_in_name = str(relu_pos_op.inputs[0])
        mul_in0 = str(mul_op.inputs[0])
        mul_in1 = str(mul_op.inputs[1])
        relu_neg_out_name = mul_in0 if mul_in0 != relu_pos_in_name else mul_in1
        if relu_neg_out_name == relu_pos_in_name:
            relu_neg_out_name = mul_in1 if mul_in0 == relu_pos_in_name else mul_in0
        relu_neg_idx = producers.get(relu_neg_out_name, None)
        if relu_neg_idx is None:
            return None
        relu_neg_op = model_ir.operators[int(relu_neg_idx)]
        if str(relu_neg_op.op_type) != "RELU" or len(relu_neg_op.inputs) != 1 or len(relu_neg_op.outputs) != 1:
            return None
        if str(relu_neg_op.outputs[0]) != relu_neg_out_name:
            return None

        neg_out_name = str(relu_neg_op.inputs[0])
        neg_idx = producers.get(neg_out_name, None)
        if neg_idx is None:
            return None
        neg_op = model_ir.operators[int(neg_idx)]
        if str(neg_op.op_type) != "NEG" or len(neg_op.inputs) != 1 or len(neg_op.outputs) != 1:
            return None
        if str(neg_op.outputs[0]) != neg_out_name:
            return None

        pre_nchw_name = str(neg_op.inputs[0])
        if relu_pos_in_name != pre_nchw_name:
            return None
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None
        pre_users = [int(v) for v in consumers.get(pre_nchw_name, [])]
        if set(pre_users) != {int(neg_idx), int(relu_pos_idx)}:
            return None

        if set(int(v) for v in consumers.get(neg_out_name, [])) != {int(relu_neg_idx)}:
            return None
        if set(int(v) for v in consumers.get(relu_neg_out_name, [])) != {int(mul_idx)}:
            return None
        if set(int(v) for v in consumers.get(relu_pos_out_name, [])) != {int(sub_idx)}:
            return None
        if set(int(v) for v in consumers.get(mul_out_name, [])) != {int(sub_idx)}:
            return None

        return {
            "input_name": str(input_name),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "neg_idx": int(neg_idx),
            "relu_pos_idx": int(relu_pos_idx),
            "tensors_to_permute": [
                str(neg_out_name),
                str(relu_pos_out_name),
                str(relu_neg_out_name),
                str(mul_out_name),
                str(input_name),
            ],
        }

    def _apply_leaky_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        neg_idx = int(plan["neg_idx"])
        relu_pos_idx = int(plan["relu_pos_idx"])
        tensors_to_permute = [str(v) for v in list(plan.get("tensors_to_permute", []))]

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(neg_idx)],
            new_inputs=[pre_input_name],
        )
        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(relu_pos_idx)],
            new_inputs=[pre_input_name],
        )
        for tensor_name in tensors_to_permute:
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(tensor_name), None),
                perm_nchw_to_nhwc,
            )
        return [int(pre_idx)]

    def _try_rewrite_split_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        split_idx = producers.get(str(input_name), None)
        if split_idx is None:
            return None
        split_op = model_ir.operators[int(split_idx)]
        if str(split_op.op_type) != "SPLIT" or len(split_op.inputs) < 2 or len(split_op.outputs) < 2:
            return None
        if str(input_name) not in set(str(v) for v in list(split_op.outputs)):
            return None
        if str(input_name) in model_outputs:
            return None

        split_axis_tensor_name = str(split_op.inputs[0])
        split_axis_vals = _read_const_ints_from_tensor(model_ir.tensors.get(split_axis_tensor_name, None))
        if split_axis_vals is None or len(split_axis_vals) != 1:
            return None

        split_input_name = str(split_op.inputs[1])
        split_input_tensor = model_ir.tensors.get(split_input_name, None)
        split_rank = int(len(list(split_input_tensor.shape))) if split_input_tensor is not None else 4
        if split_rank != 4:
            return None

        split_axis = int(split_axis_vals[0])
        if split_axis < 0:
            split_axis += int(split_rank)
        if split_axis != 1:
            return None

        source_plan: Dict[str, Any]
        swish_plan = _analyze_swish_input_to_nhwc(
            input_name=split_input_name,
            consumer_idx=int(split_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if swish_plan is not None:
            source_plan = {
                "kind": "swish",
                "plan": dict(swish_plan),
            }
        else:
            pre_idx = producers.get(split_input_name, None)
            if pre_idx is None:
                return None
            pre_op = model_ir.operators[int(pre_idx)]
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or str(pre_op.outputs[0]) != str(split_input_name)
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                or str(split_input_name) in model_outputs
            ):
                return None
            pre_users = set(int(v) for v in consumers.get(str(split_input_name), []))
            source_plan = {
                "kind": "direct",
                "pre_idx": int(pre_idx),
                "pre_input_name": str(pre_op.inputs[0]),
                "remove_pre": bool(pre_users == {int(split_idx)}),
            }

        post_transpose_indices: List[int] = []
        for split_out_name in [str(v) for v in list(split_op.outputs)]:
            if split_out_name in model_outputs:
                return None
            out_users = [int(v) for v in consumers.get(split_out_name, [])]
            for user_idx in out_users:
                if int(user_idx) in {int(concat_idx), int(consumer_idx)}:
                    continue
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)

                if user_type == "ADD":
                    if (
                        len(user_op.inputs) != 2
                        or len(user_op.outputs) != 1
                        or str(user_op.outputs[0]) in model_outputs
                    ):
                        return None
                    add_users = set(int(v) for v in consumers.get(str(user_op.outputs[0]), []))
                    if int(concat_idx) not in add_users:
                        return None
                    for add_user_idx in sorted(list(add_users)):
                        if int(add_user_idx) == int(concat_idx):
                            continue
                        add_user_op = model_ir.operators[int(add_user_idx)]
                        if (
                            str(add_user_op.op_type) == "TRANSPOSE"
                            and len(add_user_op.inputs) >= 2
                            and len(add_user_op.outputs) == 1
                            and str(add_user_op.inputs[0]) == str(user_op.outputs[0])
                            and _read_transpose_perm(model_ir, add_user_op) == perm_nchw_to_nhwc
                            and str(add_user_op.outputs[0]) not in model_outputs
                        ):
                            continue
                        if (
                            str(add_user_op.op_type) == "ADD"
                            and len(add_user_op.outputs) == 1
                            and str(add_user_op.outputs[0]) not in model_outputs
                            and int(concat_idx)
                            in set(
                                int(v)
                                for v in consumers.get(str(add_user_op.outputs[0]), [])
                            )
                        ):
                            continue
                        return None
                    continue

                if (
                    user_type == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == str(split_out_name)
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_transpose_indices.append(int(user_idx))
                    continue

                return None

        return {
            "input_name": str(input_name),
            "split_idx": int(split_idx),
            "source_plan": dict(source_plan),
            "post_transpose_indices": [int(v) for v in list(sorted(set(post_transpose_indices)))],
        }

    def _apply_split_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        split_idx = int(plan["split_idx"])
        if int(split_idx) < 0 or int(split_idx) >= len(model_ir.operators):
            return []
        split_op = model_ir.operators[int(split_idx)]
        if str(split_op.op_type) != "SPLIT" or len(split_op.inputs) < 2:
            return []

        remove_indices: List[int] = []
        source_plan = dict(plan.get("source_plan", {}))
        source_kind = str(source_plan.get("kind", ""))
        if source_kind == "swish":
            swish_plan = source_plan.get("plan", None)
            if swish_plan is not None:
                remove_indices.extend([int(v) for v in list(_apply_swish_nhwc_plan(plan=dict(swish_plan)))])
        elif source_kind == "direct":
            _replace_operator_input_at(
                model_ir=model_ir,
                op=split_op,
                input_index=1,
                new_input_name=str(source_plan["pre_input_name"]),
            )
            if bool(source_plan.get("remove_pre", False)):
                remove_indices.append(int(source_plan["pre_idx"]))
        else:
            return []

        axis_input_name = str(split_op.inputs[0])
        axis_tensor = model_ir.tensors.get(axis_input_name, None)
        axis_users = set(int(v) for v in _build_tensor_consumer_map(model_ir).get(axis_input_name, []))
        if axis_tensor is not None and axis_users == {int(split_idx)}:
            _write_const_ints_to_tensor(axis_tensor, [3])
        else:
            axis_name_new = _unique_tensor_name(f"{axis_input_name}_nhwc")
            model_ir.tensors[axis_name_new] = TensorIR(
                name=axis_name_new,
                dtype="INT32",
                shape=[1],
                shape_signature=[1],
                data=np.asarray([3], dtype=np.int32),
                is_variable=False,
                quantization=None,
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=split_op,
                input_index=0,
                new_input_name=str(axis_name_new),
            )

        for split_out_name in [str(v) for v in list(split_op.outputs)]:
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(split_out_name), None),
                perm_nchw_to_nhwc,
            )

        for post_idx in [int(v) for v in list(plan.get("post_transpose_indices", []))]:
            if int(post_idx) < 0 or int(post_idx) >= len(model_ir.operators):
                continue
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                or str(post_op.outputs[0]) in set(str(v) for v in model_ir.outputs)
            ):
                continue
            _replace_tensor_inputs(
                model_ir=model_ir,
                src_name=str(post_op.outputs[0]),
                dst_name=str(post_op.inputs[0]),
            )
            remove_indices.append(int(post_idx))

        return [int(v) for v in list(remove_indices)]

    def _try_rewrite_slice_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        slice_idx = producers.get(str(input_name), None)
        if slice_idx is None:
            return None
        slice_op = model_ir.operators[int(slice_idx)]
        if str(slice_op.op_type) != "SLICE" or len(slice_op.inputs) < 3 or len(slice_op.outputs) != 1:
            return None
        if str(slice_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None

        begin_tensor = model_ir.tensors.get(str(slice_op.inputs[1]), None)
        size_tensor = model_ir.tensors.get(str(slice_op.inputs[2]), None)
        begin_vals = _read_const_ints_from_tensor(begin_tensor)
        size_vals = _read_const_ints_from_tensor(size_tensor)
        if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
            return None
        if int(size_vals[1]) <= 0:
            return None
        if int(begin_vals[2]) != 0 or int(begin_vals[3]) != 0:
            return None

        slice_input_name = str(slice_op.inputs[0])
        slice_input_tensor = model_ir.tensors.get(slice_input_name, None)
        if slice_input_tensor is None or len(list(slice_input_tensor.shape)) != 4:
            return None

        source_plan: Dict[str, Any]
        slice_group_indices: List[int]
        swish_plan = _analyze_swish_input_to_nhwc(
            input_name=slice_input_name,
            consumer_idx=int(slice_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
            allow_consumer_fanout_to_slice=True,
        )
        if swish_plan is not None:
            source_plan = {
                "kind": "swish",
                "plan": dict(swish_plan),
            }
            slice_group_indices = sorted(
                set(int(v) for v in consumers.get(str(slice_input_name), []))
            )
        else:
            pre_idx = producers.get(slice_input_name, None)
            if pre_idx is None:
                return None
            pre_op = model_ir.operators[int(pre_idx)]
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or str(pre_op.outputs[0]) != str(slice_input_name)
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                or str(slice_input_name) in model_outputs
            ):
                return None
            pre_users = set(int(v) for v in consumers.get(str(slice_input_name), []))
            source_plan = {
                "kind": "direct",
                "pre_idx": int(pre_idx),
                "pre_input_name": str(pre_op.inputs[0]),
                "remove_pre": bool(pre_users == {int(slice_idx)}),
            }
            slice_group_indices = [int(slice_idx)]

        post_transpose_indices: set[int] = set()
        for target_slice_idx in [int(v) for v in list(slice_group_indices)]:
            if int(target_slice_idx) < 0 or int(target_slice_idx) >= len(model_ir.operators):
                return None
            target_slice_op = model_ir.operators[int(target_slice_idx)]
            if (
                str(target_slice_op.op_type) != "SLICE"
                or len(target_slice_op.inputs) < 3
                or len(target_slice_op.outputs) != 1
                or str(target_slice_op.inputs[0]) != str(slice_input_name)
            ):
                return None
            target_out_name = str(target_slice_op.outputs[0])
            if target_out_name in model_outputs:
                return None
            for user_idx in [int(v) for v in consumers.get(target_out_name, [])]:
                if int(user_idx) == int(concat_idx):
                    continue
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == target_out_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_transpose_indices.add(int(user_idx))
                    continue
                return None

        return {
            "input_name": str(input_name),
            "slice_idx": int(slice_idx),
            "concat_idx": int(concat_idx),
            "slice_group_key": (
                str(slice_input_name)
                if str(source_plan.get("kind", "")) == "swish" and len(slice_group_indices) > 1
                else ""
            ),
            "slice_group_indices": [int(v) for v in list(slice_group_indices)],
            "source_plan": dict(source_plan),
            "post_transpose_indices": [int(v) for v in sorted(post_transpose_indices)],
        }

    def _apply_slice_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        slice_idx = int(plan["slice_idx"])
        if int(slice_idx) < 0 or int(slice_idx) >= len(model_ir.operators):
            return []
        slice_op = model_ir.operators[int(slice_idx)]
        if str(slice_op.op_type) != "SLICE" or len(slice_op.inputs) < 3 or len(slice_op.outputs) != 1:
            return []

        remove_indices: List[int] = []
        source_plan = dict(plan.get("source_plan", {}))
        source_kind = str(source_plan.get("kind", ""))
        if source_kind == "swish":
            swish_plan = source_plan.get("plan", None)
            if swish_plan is not None:
                remove_indices.extend([int(v) for v in list(_apply_swish_nhwc_plan(plan=dict(swish_plan)))])
        elif source_kind == "direct":
            _replace_operator_input_at(
                model_ir=model_ir,
                op=slice_op,
                input_index=0,
                new_input_name=str(source_plan["pre_input_name"]),
            )
            if bool(source_plan.get("remove_pre", False)):
                remove_indices.append(int(source_plan["pre_idx"]))
        else:
            return []

        target_slice_indices = [
            int(v) for v in list(plan.get("slice_group_indices", [int(slice_idx)]))
        ]
        for target_slice_idx in target_slice_indices:
            if int(target_slice_idx) < 0 or int(target_slice_idx) >= len(model_ir.operators):
                return []
            target_slice_op = model_ir.operators[int(target_slice_idx)]
            if (
                str(target_slice_op.op_type) != "SLICE"
                or len(target_slice_op.inputs) < 3
                or len(target_slice_op.outputs) != 1
            ):
                return []
            begin_tensor = model_ir.tensors.get(str(target_slice_op.inputs[1]), None)
            size_tensor = model_ir.tensors.get(str(target_slice_op.inputs[2]), None)
            begin_vals = _read_const_ints_from_tensor(begin_tensor)
            size_vals = _read_const_ints_from_tensor(size_tensor)
            if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
                return []
            _write_const_ints_to_tensor(
                begin_tensor,
                [int(begin_vals[0]), int(begin_vals[2]), int(begin_vals[3]), int(begin_vals[1])],
            )
            _write_const_ints_to_tensor(
                size_tensor,
                [int(size_vals[0]), int(size_vals[2]), int(size_vals[3]), int(size_vals[1])],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(target_slice_op.outputs[0]), None),
                perm_nchw_to_nhwc,
            )

        for post_idx in [int(v) for v in list(plan.get("post_transpose_indices", []))]:
            if int(post_idx) < 0 or int(post_idx) >= len(model_ir.operators):
                continue
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                or str(post_op.outputs[0]) in set(str(v) for v in model_ir.outputs)
            ):
                continue
            _replace_tensor_inputs(
                model_ir=model_ir,
                src_name=str(post_op.outputs[0]),
                dst_name=str(post_op.inputs[0]),
            )
            remove_indices.append(int(post_idx))

        return [int(v) for v in list(remove_indices)]

    def _is_indexed_direct_slice_plan(plan: Dict[str, Any]) -> bool:
        source_plan = dict(plan.get("source_plan", {}))
        source_name = str(source_plan.get("pre_input_name", ""))
        source_tensor = model_ir.tensors.get(source_name, None)
        slice_idx = int(plan.get("slice_idx", -1))
        slice_group_indices = [
            int(value)
            for value in list(plan.get("slice_group_indices", []))
        ]
        return (
            str(source_plan.get("kind", "")) == "direct"
            and slice_group_indices == [slice_idx]
            and source_tensor is not None
            and len(list(source_tensor.shape)) == 4
        )

    def _is_indexed_direct_split_plan(
        plan: Dict[str, Any],
        *,
        concat_idx: int,
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> bool:
        source_plan = dict(plan.get("source_plan", {}))
        source_name = str(source_plan.get("pre_input_name", ""))
        source_tensor = model_ir.tensors.get(source_name, None)
        split_idx = int(plan.get("split_idx", -1))
        post_transpose_indices = {
            int(value)
            for value in list(plan.get("post_transpose_indices", []))
        }
        if (
            str(source_plan.get("kind", "")) != "direct"
            or source_tensor is None
            or len(list(source_tensor.shape)) != 4
            or split_idx < 0
            or split_idx >= len(model_ir.operators)
        ):
            return False
        split_op = model_ir.operators[split_idx]
        if (
            str(split_op.op_type) != "SPLIT"
            or len(split_op.inputs) < 2
            or len(split_op.outputs) < 2
        ):
            return False
        for output_name in [str(name) for name in split_op.outputs]:
            output_tensor = model_ir.tensors.get(output_name, None)
            if (
                output_name in model_outputs
                or output_tensor is None
                or len(list(output_tensor.shape)) != 4
                or not set(
                    int(value) for value in consumers.get(output_name, [])
                ).issubset(
                    {int(concat_idx), *post_transpose_indices}
                )
            ):
                return False
        return True

    def _is_indexed_direct_add_plan(
        plan: Dict[str, Any],
        *,
        concat_idx: int,
        consumers: Dict[str, List[int]],
    ) -> bool:
        add_idx = int(plan.get("add_idx", -1))
        actions = [dict(action) for action in plan.get("actions", [])]
        input_name = str(plan.get("input_name", ""))
        post_transpose_indices = {
            int(value)
            for value in list(
                plan.get("removable_post_transpose_indices", [])
            )
        }
        return (
            add_idx >= 0
            and add_idx < len(model_ir.operators)
            and str(model_ir.operators[add_idx].op_type) == "ADD"
            and len(model_ir.operators[add_idx].inputs) == 2
            and len(model_ir.operators[add_idx].outputs) == 1
            and len(actions) == 2
            and all(
                str(action.get("kind", "")) == "direct"
                and len(list(action.get("remove_indices", []))) >= 1
                for action in actions
            )
            and len(list(plan.get("new_add_inputs", []))) == 2
            and set(
                int(value) for value in consumers.get(input_name, [])
            )
            == {int(concat_idx), *post_transpose_indices}
        )

    def _try_rewrite_add_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        root_concat_idx: Optional[int] = None,
        visited_add_outputs: Optional[set[str]] = None,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        if root_concat_idx is None:
            root_concat_idx = int(concat_idx)
        if visited_add_outputs is None:
            visited_add_outputs = set()
        if str(input_name) in visited_add_outputs:
            return None

        add_idx = producers.get(str(input_name), None)
        if add_idx is None:
            return None
        add_op = model_ir.operators[int(add_idx)]
        if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
            return None
        if str(add_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        input_users = set(int(v) for v in consumers.get(str(input_name), []))
        if int(concat_idx) not in input_users:
            return None

        removable_post_transpose_indices: List[int] = []
        for user_idx in sorted(list(input_users)):
            if int(user_idx) == int(concat_idx):
                continue
            if int(user_idx) == int(root_concat_idx):
                continue
            user_op = model_ir.operators[int(user_idx)]
            if (
                str(user_op.op_type) == "TRANSPOSE"
                and len(user_op.inputs) >= 2
                and len(user_op.outputs) == 1
                and str(user_op.inputs[0]) == str(input_name)
                and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                and str(user_op.outputs[0]) not in model_outputs
            ):
                removable_post_transpose_indices.append(int(user_idx))
                continue
            if (
                str(user_op.op_type) == "ADD"
                and len(user_op.outputs) == 1
                and str(user_op.outputs[0]) not in model_outputs
                and int(root_concat_idx) in set(int(v) for v in consumers.get(str(user_op.outputs[0]), []))
            ):
                continue
            return None

        actions: List[Dict[str, Any]] = []
        next_visited = set(str(v) for v in visited_add_outputs)
        next_visited.add(str(input_name))
        for add_input_name in [str(v) for v in list(add_op.inputs)]:
            input_producer_idx = producers.get(add_input_name, None)
            if input_producer_idx is not None:
                input_producer_op = model_ir.operators[int(input_producer_idx)]
                input_users = set(int(v) for v in consumers.get(add_input_name, []))
                if (
                    str(input_producer_op.op_type) == "TRANSPOSE"
                    and len(input_producer_op.inputs) >= 2
                    and len(input_producer_op.outputs) == 1
                    and str(input_producer_op.outputs[0]) == add_input_name
                    and _read_transpose_perm(model_ir, input_producer_op) == perm_nhwc_to_nchw
                    and int(add_idx) in input_users
                ):
                    extra_users = {int(v) for v in input_users if int(v) != int(add_idx)}
                    if extra_users.difference({int(root_concat_idx)}):
                        return None
                    actions.append(
                        {
                            "kind": "direct",
                            "new_input_name": str(input_producer_op.inputs[0]),
                            "remove_indices": (
                                [int(input_producer_idx)] if len(extra_users) == 0 else []
                            ),
                        }
                    )
                    continue

            unary_plan = _try_rewrite_unary_input_to_nhwc(
                input_name=add_input_name,
                concat_idx=int(add_idx),
                producers=producers,
                consumers=consumers,
                model_outputs=model_outputs,
            )
            if unary_plan is not None:
                actions.append(
                    {
                        "kind": "unary",
                        "new_input_name": str(add_input_name),
                        "plan": unary_plan,
                    }
                )
                continue

            swish_plan = _analyze_swish_input_to_nhwc(
                input_name=add_input_name,
                consumer_idx=int(add_idx),
                producers=producers,
                consumers=consumers,
                model_outputs=model_outputs,
            )
            if swish_plan is not None:
                actions.append(
                    {
                        "kind": "swish",
                        "new_input_name": str(add_input_name),
                        "plan": swish_plan,
                    }
                )
                continue

            split_plan = _try_rewrite_split_input_to_nhwc(
                input_name=add_input_name,
                consumer_idx=int(add_idx),
                concat_idx=int(root_concat_idx),
                producers=producers,
                consumers=consumers,
                model_outputs=model_outputs,
            )
            if split_plan is not None:
                actions.append(
                    {
                        "kind": "split",
                        "new_input_name": str(add_input_name),
                        "plan": split_plan,
                    }
                )
                continue

            nested_add_plan = _try_rewrite_add_input_to_nhwc(
                input_name=add_input_name,
                concat_idx=int(add_idx),
                root_concat_idx=int(root_concat_idx),
                visited_add_outputs=set(next_visited),
                producers=producers,
                consumers=consumers,
                model_outputs=model_outputs,
            )
            if nested_add_plan is not None:
                actions.append(
                    {
                        "kind": "add_chain",
                        "new_input_name": str(add_input_name),
                        "plan": dict(nested_add_plan),
                    }
                )
                continue

            return None

        new_add_inputs: List[str] = []
        remove_indices: List[int] = []
        for action in actions:
            action_kind = str(action.get("kind", ""))
            if action_kind == "direct":
                new_add_inputs.append(str(action["new_input_name"]))
                remove_indices.extend([int(v) for v in list(action.get("remove_indices", []))])
                continue
            if action_kind == "swish":
                new_add_inputs.append(str(action["new_input_name"]))
                remove_indices.extend([])
                continue
            if action_kind == "unary":
                new_add_inputs.append(str(action["new_input_name"]))
                remove_indices.extend([])
                continue
            if action_kind == "split":
                new_add_inputs.append(str(action["new_input_name"]))
                remove_indices.extend([])
                continue
            if action_kind == "add_chain":
                new_add_inputs.append(str(action["new_input_name"]))
                remove_indices.extend([])
                continue
            return None

        return {
            "input_name": str(input_name),
            "add_idx": int(add_idx),
            "root_concat_idx": int(root_concat_idx),
            "new_add_inputs": [str(v) for v in new_add_inputs],
            "remove_indices": [int(v) for v in remove_indices],
            "removable_post_transpose_indices": [int(v) for v in list(sorted(set(removable_post_transpose_indices)))],
            "actions": [dict(v) for v in actions],
        }

    def _apply_add_nhwc_plan(
        *,
        plan: Dict[str, Any],
        applied_split_indices: Optional[set[int]] = None,
        applied_add_indices: Optional[set[int]] = None,
    ) -> List[int]:
        input_name = str(plan["input_name"])
        add_idx = int(plan["add_idx"])
        new_add_inputs = [str(v) for v in list(plan.get("new_add_inputs", []))]
        remove_indices = [int(v) for v in list(plan.get("remove_indices", []))]
        removable_post_transpose_indices = [
            int(v) for v in list(plan.get("removable_post_transpose_indices", []))
        ]
        actions = [dict(v) for v in list(plan.get("actions", []))]
        if applied_split_indices is None:
            applied_split_indices = set()
        if applied_add_indices is None:
            applied_add_indices = set()
        if int(add_idx) in applied_add_indices:
            return []

        for action in actions:
            action_kind = str(action.get("kind", ""))
            if action_kind == "swish":
                swish_plan = action.get("plan", None)
                if swish_plan is None:
                    continue
                swish_pre_remove = _apply_swish_nhwc_plan(plan=dict(swish_plan))
                remove_indices.extend([int(v) for v in swish_pre_remove])
                continue
            if action_kind == "unary":
                unary_plan = action.get("plan", None)
                if unary_plan is None:
                    continue
                unary_pre_remove = _apply_unary_nhwc_plan(plan=dict(unary_plan))
                remove_indices.extend([int(v) for v in unary_pre_remove])
                continue
            if action_kind == "split":
                split_plan = action.get("plan", None)
                if split_plan is None:
                    continue
                split_idx = int(split_plan.get("split_idx", -1))
                if int(split_idx) in applied_split_indices:
                    continue
                split_pre_remove = _apply_split_nhwc_plan(plan=dict(split_plan))
                remove_indices.extend([int(v) for v in list(split_pre_remove)])
                applied_split_indices.add(int(split_idx))
                continue
            if action_kind == "add_chain":
                nested_plan = action.get("plan", None)
                if nested_plan is None:
                    continue
                nested_pre_remove = _apply_add_nhwc_plan(
                    plan=dict(nested_plan),
                    applied_split_indices=applied_split_indices,
                    applied_add_indices=applied_add_indices,
                )
                remove_indices.extend([int(v) for v in list(nested_pre_remove)])
                continue

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(add_idx)],
            new_inputs=[str(v) for v in list(new_add_inputs)],
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        for post_idx in removable_post_transpose_indices:
            if int(post_idx) < 0 or int(post_idx) >= len(model_ir.operators):
                continue
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                or str(post_op.outputs[0]) in set(str(v) for v in model_ir.outputs)
            ):
                continue
            _replace_tensor_inputs(
                model_ir=model_ir,
                src_name=str(post_op.outputs[0]),
                dst_name=str(post_op.inputs[0]),
            )
            remove_indices.append(int(post_idx))
        applied_add_indices.add(int(add_idx))
        return [int(v) for v in remove_indices]

    def _try_rewrite_pad_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        pad_idx = producers.get(str(input_name), None)
        if pad_idx is None:
            return None
        pad_op = model_ir.operators[int(pad_idx)]
        if str(pad_op.op_type) != "PAD" or len(pad_op.inputs) < 2 or len(pad_op.outputs) != 1:
            return None
        if str(pad_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(concat_idx)}:
            return None

        pad_input_name = str(pad_op.inputs[0])
        pre_idx = producers.get(pad_input_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pad_input_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pad_input_name) in model_outputs:
            return None

        pads_tensor_name = str(pad_op.inputs[1])
        pads_tensor = model_ir.tensors.get(pads_tensor_name, None)
        if pads_tensor is None or pads_tensor.data is None:
            return None
        try:
            pads_array = np.asarray(pads_tensor.data)
            pads_pairs = pads_array.reshape(4, 2)
        except Exception:
            return None
        if int(pads_pairs.size) != 8:
            return None

        pre_users = set(int(v) for v in consumers.get(pad_input_name, []))
        remove_pre = pre_users == {int(pad_idx)}

        return {
            "input_name": str(input_name),
            "pad_idx": int(pad_idx),
            "pad_input_name": str(pad_input_name),
            "pad_input_rewritten_name": str(pre_op.inputs[0]),
            "pads_tensor_name": str(pads_tensor_name),
            "pre_idx": int(pre_idx),
            "remove_pre": bool(remove_pre),
        }

    def _apply_pad_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        input_name = str(plan["input_name"])
        pad_idx = int(plan["pad_idx"])
        pre_idx = int(plan["pre_idx"])
        remove_pre = bool(plan["remove_pre"])
        pad_rewritten_input_name = str(plan["pad_input_rewritten_name"])
        pads_tensor_name = str(plan["pads_tensor_name"])

        pad_op = model_ir.operators[int(pad_idx)]
        _set_operator_inputs(
            model_ir=model_ir,
            op=pad_op,
            new_inputs=[pad_rewritten_input_name, str(pad_op.inputs[1])],
        )

        pads_tensor = model_ir.tensors.get(pads_tensor_name, None)
        if pads_tensor is not None and pads_tensor.data is not None:
            pads_array = np.asarray(pads_tensor.data)
            pads_pairs = pads_array.reshape(4, 2)
            # NCHW [N,C,H,W] -> NHWC [N,H,W,C]
            pads_pairs = np.asarray(
                [pads_pairs[0], pads_pairs[2], pads_pairs[3], pads_pairs[1]],
                dtype=pads_array.dtype,
            )
            pads_tensor.data = pads_pairs
            pads_tensor.shape = [4, 2]
            pads_tensor.shape_signature = [4, 2]

        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )

        return [int(pre_idx)] if remove_pre else []

    def _try_rewrite_unary_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        unary_idx = producers.get(str(input_name), None)
        if unary_idx is None:
            return None
        unary_op = model_ir.operators[int(unary_idx)]
        if str(unary_op.op_type) not in {"RELU", "RELU6", "LOGISTIC", "TANH", "GELU"}:
            return None
        if len(unary_op.inputs) != 1 or len(unary_op.outputs) != 1:
            return None
        if str(unary_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(concat_idx)}:
            return None

        pre_nchw_name = str(unary_op.inputs[0])
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(pre_nchw_name, [])) != {int(unary_idx)}:
            return None

        return {
            "input_name": str(input_name),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "unary_idx": int(unary_idx),
        }

    def _try_rewrite_softmax_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        softmax_idx = producers.get(str(input_name), None)
        if softmax_idx is None:
            return None
        softmax_op = model_ir.operators[int(softmax_idx)]
        if str(softmax_op.op_type) != "SOFTMAX":
            return None
        if len(softmax_op.inputs) != 1 or len(softmax_op.outputs) != 1:
            return None
        if str(softmax_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(concat_idx)}:
            return None

        pre_nchw_name = str(softmax_op.inputs[0])
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None
        # Keep strict: the removed pre-transpose output must only feed SOFTMAX.
        if set(int(v) for v in consumers.get(pre_nchw_name, [])) != {int(softmax_idx)}:
            return None

        pre_input_tensor = model_ir.tensors.get(str(pre_op.inputs[0]), None)
        softmax_output_tensor = model_ir.tensors.get(str(input_name), None)
        if (
            pre_input_tensor is None
            or softmax_output_tensor is None
            or len(list(pre_input_tensor.shape)) != 4
            or len(list(softmax_output_tensor.shape)) != 4
        ):
            return None

        return {
            "input_name": str(input_name),
            "softmax_idx": int(softmax_idx),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "softmax_input_name": str(pre_nchw_name),
        }

    def _try_rewrite_dequant_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        dq_idx = producers.get(str(input_name), None)
        if dq_idx is None:
            return None
        dq_op = model_ir.operators[int(dq_idx)]
        if str(dq_op.op_type) != "DEQUANTIZE" or len(dq_op.inputs) != 1 or len(dq_op.outputs) != 1:
            return None
        if str(dq_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(concat_idx)}:
            return None

        pre_nchw_name = str(dq_op.inputs[0])
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None

        pre_users = set(int(v) for v in consumers.get(pre_nchw_name, []))
        remove_pre = pre_users == {int(dq_idx)}
        return {
            "input_name": str(input_name),
            "dq_idx": int(dq_idx),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "remove_pre": bool(remove_pre),
        }

    def _apply_dequant_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        input_name = str(plan["input_name"])
        dq_idx = int(plan["dq_idx"])
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        remove_pre = bool(plan["remove_pre"])

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(dq_idx)],
            new_inputs=[pre_input_name],
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)] if remove_pre else []

    def _try_rewrite_prelu_input_to_nhwc(
        *,
        input_name: str,
        concat_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        prelu_idx = producers.get(str(input_name), None)
        if prelu_idx is None:
            return None
        prelu_op = model_ir.operators[int(prelu_idx)]
        if str(prelu_op.op_type) != "PRELU" or len(prelu_op.inputs) != 2 or len(prelu_op.outputs) != 1:
            return None
        if str(prelu_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(concat_idx)}:
            return None

        pre_nchw_name = str(prelu_op.inputs[0])
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(pre_nchw_name, [])) != {int(prelu_idx)}:
            return None

        alpha_name = str(prelu_op.inputs[1])
        alpha_tensor = model_ir.tensors.get(alpha_name, None)
        if alpha_tensor is None or alpha_tensor.data is None:
            return None
        pre_input_tensor = model_ir.tensors.get(str(pre_op.inputs[0]), None)
        target_nhwc_shape = (
            [int(v) for v in list(pre_input_tensor.shape)]
            if pre_input_tensor is not None and pre_input_tensor.shape is not None
            else None
        )
        alpha_data = np.asarray(alpha_tensor.data)
        if _select_prelu_alpha_for_nhwc(
            alpha_data=alpha_data,
            target_nhwc_shape=target_nhwc_shape,
        ) is None:
            return None

        return {
            "input_name": str(input_name),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "prelu_idx": int(prelu_idx),
            "target_nhwc_shape": (
                [int(v) for v in list(target_nhwc_shape)]
                if target_nhwc_shape is not None
                else None
            ),
        }

    def _apply_unary_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        input_name = str(plan["input_name"])
        unary_idx = int(plan["unary_idx"])
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(unary_idx)],
            new_inputs=[pre_input_name],
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)]

    def _apply_softmax_nhwc_plan(*, plan: Dict[str, Any]) -> Optional[List[int]]:
        input_name = str(plan["input_name"])
        softmax_idx = int(plan["softmax_idx"])
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        old_softmax_input_name = str(plan["softmax_input_name"])

        if softmax_idx < 0 or softmax_idx >= len(model_ir.operators):
            return None
        softmax_op = model_ir.operators[int(softmax_idx)]
        if str(softmax_op.op_type) != "SOFTMAX" or len(softmax_op.inputs) != 1 or len(softmax_op.outputs) != 1:
            return None
        if str(softmax_op.outputs[0]) != input_name:
            return None

        pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
        old_softmax_input_tensor = model_ir.tensors.get(old_softmax_input_name, None)
        softmax_output_tensor = model_ir.tensors.get(input_name, None)
        if (
            pre_input_tensor is None
            or old_softmax_input_tensor is None
            or softmax_output_tensor is None
            or len(list(pre_input_tensor.shape)) != 4
            or len(list(old_softmax_input_tensor.shape)) != 4
            or len(list(softmax_output_tensor.shape)) != 4
        ):
            return None

        pre_input_shape = [int(v) for v in list(pre_input_tensor.shape)]
        pre_input_signature = (
            [int(v) for v in list(pre_input_tensor.shape_signature)]
            if pre_input_tensor.shape_signature is not None
            else [int(v) for v in list(pre_input_tensor.shape)]
        )
        axis_last_shape = _permute_shape(pre_input_shape, perm_nhwc_to_nhcw)
        axis_last_signature = _permute_shape(pre_input_signature, perm_nhwc_to_nhcw)
        if axis_last_shape is None or axis_last_signature is None:
            return None

        axis_last_input_name = _unique_tensor_name(f"{old_softmax_input_name}_axis_last")
        axis_last_output_name = _unique_tensor_name(f"{input_name}_axis_last")
        perm_tensor_name = _find_or_create_perm_tensor(
            base_name=f"{input_name}_nhwc_to_nhcw_perm",
            perm=perm_nhwc_to_nhcw,
        )

        model_ir.tensors[axis_last_input_name] = TensorIR(
            name=axis_last_input_name,
            dtype=str(old_softmax_input_tensor.dtype),
            shape=[int(v) for v in list(axis_last_shape)],
            shape_signature=[int(v) for v in list(axis_last_signature)],
            data=None,
            is_variable=False,
            quantization=_clone_quantization(old_softmax_input_tensor.quantization),
        )
        model_ir.tensors[axis_last_output_name] = TensorIR(
            name=axis_last_output_name,
            dtype=str(softmax_output_tensor.dtype),
            shape=[int(v) for v in list(axis_last_shape)],
            shape_signature=[int(v) for v in list(axis_last_signature)],
            data=None,
            is_variable=False,
            quantization=_clone_quantization(softmax_output_tensor.quantization),
        )

        # Keep SOFTMAX last-axis semantics by locally rotating NHWC -> NHCW -> SOFTMAX -> NHWC.
        _set_operator_inputs(
            model_ir=model_ir,
            op=softmax_op,
            new_inputs=[axis_last_input_name],
        )
        _set_operator_outputs(
            model_ir=model_ir,
            op=softmax_op,
            new_outputs=[axis_last_output_name],
        )

        model_ir.operators.insert(
            int(softmax_idx),
            OperatorIR(
                op_type="TRANSPOSE",
                inputs=[pre_input_name, perm_tensor_name],
                outputs=[axis_last_input_name],
                options={},
            ),
        )
        model_ir.operators.insert(
            int(softmax_idx) + 2,
            OperatorIR(
                op_type="TRANSPOSE",
                inputs=[axis_last_output_name, perm_tensor_name],
                outputs=[input_name],
                options={},
            ),
        )

        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)]

    def _apply_prelu_nhwc_plan(*, plan: Dict[str, Any]) -> Optional[List[int]]:
        input_name = str(plan["input_name"])
        prelu_idx = int(plan["prelu_idx"])
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        target_nhwc_shape = (
            [int(v) for v in list(plan.get("target_nhwc_shape", []))]
            if plan.get("target_nhwc_shape", None) is not None
            else None
        )

        prelu_op = model_ir.operators[int(prelu_idx)]
        alpha_name = str(prelu_op.inputs[1])
        alpha_tensor = model_ir.tensors.get(alpha_name, None)
        if alpha_tensor is None or alpha_tensor.data is None:
            return None
        alpha_data = np.asarray(alpha_tensor.data)
        selected_alpha = _select_prelu_alpha_for_nhwc(
            alpha_data=alpha_data,
            target_nhwc_shape=target_nhwc_shape,
        )
        if selected_alpha is None:
            return None

        selected_alpha_name = str(alpha_name)
        alpha_users = [int(v) for v in _build_tensor_consumer_map(model_ir).get(alpha_name, [])]
        alpha_needs_rewrite = (
            selected_alpha.shape != alpha_data.shape
            or not np.array_equal(selected_alpha, alpha_data)
        )
        if alpha_needs_rewrite:
            shape, signature = normalize_onnx_shape(list(selected_alpha.shape))
            if len(alpha_users) == 1 and int(alpha_users[0]) == int(prelu_idx):
                alpha_tensor.data = np.asarray(selected_alpha)
                alpha_tensor.shape = [int(v) for v in list(shape)]
                alpha_tensor.shape_signature = [int(v) for v in list(signature)]
            else:
                selected_alpha_name = _unique_tensor_name(f"{alpha_name}_nhwc")
                model_ir.tensors[selected_alpha_name] = TensorIR(
                    name=selected_alpha_name,
                    dtype=str(alpha_tensor.dtype),
                    shape=[int(v) for v in list(shape)],
                    shape_signature=[int(v) for v in list(signature)],
                    data=np.asarray(selected_alpha),
                    is_variable=False,
                    quantization=_clone_quantization(alpha_tensor.quantization),
                )

        _set_operator_inputs(
            model_ir=model_ir,
            op=prelu_op,
            new_inputs=[pre_input_name, str(selected_alpha_name)],
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)]

    def _project_shape_after_nchw_to_nhwc(tensor_name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None:
            return None
        shape = [int(v) for v in list(tensor.shape)]
        if len(shape) != 4:
            return None
        return [int(shape[0]), int(shape[2]), int(shape[3]), int(shape[1])]

    indexed_quantized_simple_family_contracts = (
        (frozenset({"direct", "unary"}), frozenset({"unary"})),
        (frozenset({"direct", "pad"}), frozenset({"direct", "pad"})),
        (
            frozenset({"direct", "unary", "pad"}),
            frozenset({"unary", "pad"}),
        ),
        (
            frozenset({"direct", "unary", "swish"}),
            frozenset({"swish"}),
        ),
        (
            frozenset({"direct", "dequantize"}),
            frozenset({"dequantize"}),
        ),
        (frozenset({"direct", "prelu"}), frozenset({"prelu"})),
        (
            frozenset({"direct", "unary", "leaky"}),
            frozenset({"leaky"}),
        ),
    )
    indexed_float_simple_family_contracts = (
        (frozenset({"direct", "unary"}), frozenset({"unary"})),
        (frozenset({"direct", "pad"}), frozenset({"direct", "pad"})),
        (
            frozenset({"direct", "dequantize"}),
            frozenset({"dequantize"}),
        ),
        (frozenset({"direct", "prelu"}), frozenset({"prelu"})),
        (
            frozenset({"direct", "softmax"}),
            frozenset({"direct", "softmax"}),
        ),
        (
            frozenset({"direct", "unary", "swish"}),
            frozenset({"swish"}),
        ),
        (
            frozenset({"direct", "unary", "leaky"}),
            frozenset({"leaky"}),
        ),
    )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            concat_out_name = str(concat_op.outputs[0])
            concat_out_tensor = model_ir.tensors.get(concat_out_name, None)
            if concat_out_tensor is None or len(list(concat_out_tensor.shape)) != 4:
                continue

            concat_axis_old = int(concat_op.options.get("axis", 1))
            if concat_axis_old < 0:
                concat_axis_old += 4
            if concat_axis_old != 1:
                continue

            concat_users = [int(v) for v in consumers.get(concat_out_name, [])]
            if len(concat_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            post_quantize_idx: Optional[int] = None
            post_quantize_out_name: Optional[str] = None
            valid_post_only = True
            for user_idx in concat_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == concat_out_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                elif (
                    len(concat_users) == 1
                    and str(user_op.op_type) == "QUANTIZE"
                    and len(user_op.inputs) == 1
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == concat_out_name
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    q_out_name = str(user_op.outputs[0])
                    q_users = [int(v) for v in consumers.get(q_out_name, [])]
                    if len(q_users) == 0:
                        valid_post_only = False
                        break
                    valid_q_post = True
                    for q_user_idx in q_users:
                        q_user_op = model_ir.operators[int(q_user_idx)]
                        if (
                            str(q_user_op.op_type) == "TRANSPOSE"
                            and len(q_user_op.inputs) >= 2
                            and len(q_user_op.outputs) == 1
                            and str(q_user_op.inputs[0]) == q_out_name
                            and _read_transpose_perm(model_ir, q_user_op) == perm_nchw_to_nhwc
                            and str(q_user_op.outputs[0]) not in model_outputs
                        ):
                            post_indices.append(int(q_user_idx))
                            post_output_names.append(str(q_user_op.outputs[0]))
                        else:
                            valid_q_post = False
                            break
                    if not valid_q_post:
                        valid_post_only = False
                        break
                    post_quantize_idx = int(user_idx)
                    post_quantize_out_name = str(q_out_name)
                else:
                    valid_post_only = False
                    break
            if not valid_post_only or len(post_indices) == 0:
                continue
            post_op_ids: List[int] = [
                int(id(model_ir.operators[int(post_idx)]))
                for post_idx in post_indices
                if int(post_idx) >= 0 and int(post_idx) < len(model_ir.operators)
            ]

            concat_input_actions: List[Dict[str, Any]] = []
            rewritable = True
            for input_name in [str(v) for v in list(concat_op.inputs)]:
                input_producer_idx = producers.get(input_name, None)
                if input_producer_idx is not None:
                    input_producer_op = model_ir.operators[int(input_producer_idx)]
                    if (
                        str(input_producer_op.op_type) == "TRANSPOSE"
                        and len(input_producer_op.inputs) >= 2
                        and len(input_producer_op.outputs) == 1
                        and str(input_producer_op.outputs[0]) == input_name
                        and _read_transpose_perm(model_ir, input_producer_op) == perm_nhwc_to_nchw
                        and int(concat_idx) in set(int(v) for v in consumers.get(input_name, []))
                    ):
                        input_users = set(int(v) for v in consumers.get(input_name, []))
                        remove_indices = (
                            [int(input_producer_idx)]
                            if input_users == {int(concat_idx)}
                            else []
                        )
                        concat_input_actions.append(
                            {
                                "kind": "direct",
                                "input_name": str(input_name),
                                "new_input_name": str(input_producer_op.inputs[0]),
                                "remove_indices": remove_indices,
                            }
                        )
                        continue

                pad_plan = _try_rewrite_pad_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if pad_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "pad",
                            "input_name": str(input_name),
                            "plan": dict(pad_plan),
                        }
                    )
                    continue

                leaky_plan = _try_rewrite_leaky_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if leaky_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "leaky",
                            "input_name": str(input_name),
                            "plan": dict(leaky_plan),
                        }
                    )
                    continue

                dequant_plan = _try_rewrite_dequant_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if dequant_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "dequantize",
                            "input_name": str(input_name),
                            "plan": dict(dequant_plan),
                        }
                    )
                    continue

                unary_plan = _try_rewrite_unary_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if unary_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "unary",
                            "input_name": str(input_name),
                            "plan": dict(unary_plan),
                        }
                    )
                    continue

                softmax_plan = _try_rewrite_softmax_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if softmax_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "softmax",
                            "input_name": str(input_name),
                            "plan": dict(softmax_plan),
                        }
                    )
                    continue

                prelu_plan = _try_rewrite_prelu_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if prelu_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "prelu",
                            "input_name": str(input_name),
                            "plan": dict(prelu_plan),
                        }
                    )
                    continue

                swish_plan = _try_rewrite_swish_input_to_nhwc(
                    input_name=input_name,
                    consumer_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if swish_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "swish",
                            "input_name": str(input_name),
                            "plan": dict(swish_plan),
                        }
                    )
                    continue

                add_plan = _try_rewrite_add_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    root_concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if add_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "add",
                            "input_name": str(input_name),
                            "plan": dict(add_plan),
                        }
                    )
                    continue

                split_plan = _try_rewrite_split_input_to_nhwc(
                    input_name=input_name,
                    consumer_idx=int(concat_idx),
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if split_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "split",
                            "input_name": str(input_name),
                            "plan": dict(split_plan),
                        }
                    )
                    continue

                slice_plan = _try_rewrite_slice_input_to_nhwc(
                    input_name=input_name,
                    concat_idx=int(concat_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if slice_plan is not None:
                    concat_input_actions.append(
                        {
                            "kind": "slice",
                            "input_name": str(input_name),
                            "plan": dict(slice_plan),
                        }
                    )
                    continue

                rewritable = False
                break

            if not rewritable:
                continue

            action_kind_counts: Dict[str, int] = {}
            for action in concat_input_actions:
                action_kind = str(action.get("kind", ""))
                action_kind_counts[action_kind] = (
                    action_kind_counts.get(action_kind, 0) + 1
                )
            action_kinds = set(action_kind_counts)
            softmax_action_count = int(
                action_kind_counts.get("softmax", 0)
            )
            if softmax_action_count > 0:
                # Safety + benefit gate:
                # - support only float-path concat-post-transpose rewrite
                # - require at least one non-softmax input so total transpose count decreases
                if post_quantize_idx is not None:
                    continue
                if softmax_action_count != 1:
                    continue
                if int(len(concat_input_actions) - softmax_action_count) <= 0:
                    continue

            all_direct_input_actions = (
                not action_kinds or action_kinds == {"direct"}
            )
            # Both strict direct-adapter families are owned by indexed
            # transactional passes, with or without post Quantize.
            if all_direct_input_actions:
                continue

            indexed_quantized_simple_family = (
                post_quantize_idx is not None
                and (
                    any(
                        required_kinds.issubset(action_kinds)
                        and action_kinds.issubset(allowed_kinds)
                        for allowed_kinds, required_kinds
                        in indexed_quantized_simple_family_contracts
                    )
                    or (
                        len(concat_input_actions) >= 2
                        and action_kinds == {"pad"}
                    )
                )
            )
            if indexed_quantized_simple_family:
                continue
            quantized_slice_actions = [
                action
                for action in concat_input_actions
                if str(action.get("kind", "")) == "slice"
            ]
            indexed_quantized_slice_family = (
                post_quantize_idx is not None
                and len(quantized_slice_actions) >= 1
                and all(
                    str(action.get("kind", "")) in {"direct", "slice"}
                    for action in concat_input_actions
                )
                and all(
                    _is_indexed_direct_slice_plan(
                        dict(action.get("plan", {}))
                    )
                    and not list(
                        dict(action.get("plan", {})).get(
                            "post_transpose_indices",
                            [],
                        )
                    )
                    for action in quantized_slice_actions
                )
            )
            if indexed_quantized_slice_family:
                continue
            quantized_split_actions = [
                action
                for action in concat_input_actions
                if str(action.get("kind", "")) == "split"
            ]
            indexed_quantized_split_family = (
                post_quantize_idx is not None
                and len(quantized_split_actions) >= 1
                and all(
                    str(action.get("kind", "")) in {"direct", "split"}
                    for action in concat_input_actions
                )
                and all(
                    _is_indexed_direct_split_plan(
                        dict(action.get("plan", {})),
                        concat_idx=int(concat_idx),
                        consumers=consumers,
                        model_outputs=model_outputs,
                    )
                    and not list(
                        dict(action.get("plan", {})).get(
                            "post_transpose_indices",
                            [],
                        )
                    )
                    for action in quantized_split_actions
                )
            )
            if indexed_quantized_split_family:
                continue
            quantized_add_actions = [
                action
                for action in concat_input_actions
                if str(action.get("kind", "")) == "add"
            ]
            indexed_quantized_add_family = (
                post_quantize_idx is not None
                and len(quantized_add_actions) >= 1
                and all(
                    str(action.get("kind", ""))
                    in {"direct", "unary", "add"}
                    for action in concat_input_actions
                )
                and all(
                    _is_indexed_direct_add_plan(
                        dict(action.get("plan", {})),
                        concat_idx=int(concat_idx),
                        consumers=consumers,
                    )
                    for action in quantized_add_actions
                )
            )
            if indexed_quantized_add_family:
                continue
            indexed_float_simple_family = (
                post_quantize_idx is None
                and any(
                    required_kinds.issubset(action_kinds)
                    and action_kinds.issubset(allowed_kinds)
                    for allowed_kinds, required_kinds
                    in indexed_float_simple_family_contracts
                )
            )
            if indexed_float_simple_family:
                continue
            slice_actions = [
                action
                for action in concat_input_actions
                if str(action.get("kind", "")) == "slice"
            ]
            indexed_slice_family = (
                post_quantize_idx is None
                and len(slice_actions) >= 1
                and all(
                    str(action.get("kind", "")) in {"direct", "slice"}
                    for action in concat_input_actions
                )
                and len(
                    {
                        str(action.get("input_name", ""))
                        for action in slice_actions
                    }
                )
                == len(slice_actions)
                and all(
                    _is_indexed_direct_slice_plan(
                        dict(action.get("plan", {}))
                    )
                    for action in slice_actions
                )
            )
            if indexed_slice_family:
                continue
            split_actions = [
                action
                for action in concat_input_actions
                if str(action.get("kind", "")) == "split"
            ]
            indexed_split_family = (
                post_quantize_idx is None
                and len(split_actions) >= 1
                and all(
                    str(action.get("kind", "")) in {"direct", "split"}
                    for action in concat_input_actions
                )
                and all(
                    _is_indexed_direct_split_plan(
                        dict(action.get("plan", {})),
                        concat_idx=int(concat_idx),
                        consumers=consumers,
                        model_outputs=model_outputs,
                    )
                    for action in split_actions
                )
            )
            if indexed_split_family:
                continue
            add_actions = [
                action
                for action in concat_input_actions
                if str(action.get("kind", "")) == "add"
            ]
            indexed_add_family = (
                post_quantize_idx is None
                and len(add_actions) >= 1
                and all(
                    str(action.get("kind", "")) in {"direct", "add"}
                    for action in concat_input_actions
                )
                and all(
                    _is_indexed_direct_add_plan(
                        dict(action.get("plan", {})),
                        concat_idx=int(concat_idx),
                        consumers=consumers,
                    )
                    for action in add_actions
                )
            )
            if indexed_add_family:
                continue
            nhwc_inputs_ok = True
            nhwc_ref_shape: Optional[List[int]] = None
            for action in concat_input_actions:
                action_kind = str(action.get("kind", ""))
                if action_kind == "direct":
                    projected_input_name = str(action["new_input_name"])
                    input_tensor = model_ir.tensors.get(projected_input_name, None)
                    if input_tensor is None or len(list(input_tensor.shape)) != 4:
                        nhwc_inputs_ok = False
                        break
                    shape = [int(v) for v in list(input_tensor.shape)]
                elif action_kind in {"swish", "leaky", "add", "unary", "pad", "prelu", "dequantize", "softmax", "split", "slice"}:
                    projected_input_name = str(action["input_name"])
                    projected_shape = _project_shape_after_nchw_to_nhwc(projected_input_name)
                    if projected_shape is None:
                        nhwc_inputs_ok = False
                        break
                    shape = [int(v) for v in list(projected_shape)]
                else:
                    nhwc_inputs_ok = False
                    break
                if nhwc_ref_shape is None:
                    nhwc_ref_shape = list(shape)
                else:
                    for dim_idx in [0, 1, 2]:
                        if int(shape[dim_idx]) != int(nhwc_ref_shape[dim_idx]):
                            nhwc_inputs_ok = False
                            break
                if not nhwc_inputs_ok:
                    break
            if not nhwc_inputs_ok or nhwc_ref_shape is None:
                # Some paths keep stale rank-4 metadata even though runtime concat
                # is valid (e.g. resize branches). For strict direct transpose
                # wrappers, the algebraic rewrite is still safe.
                if not all_direct_input_actions:
                    continue

            new_concat_inputs: List[str] = []
            pre_remove_indices: List[int] = []
            applied_split_indices: set[int] = set()
            applied_add_indices: set[int] = set()
            applied_slice_group_keys: set[str] = set()
            for action in concat_input_actions:
                action_kind = str(action.get("kind", ""))
                if action_kind == "direct":
                    new_concat_inputs.append(str(action["new_input_name"]))
                    pre_remove_indices.extend([int(v) for v in list(action.get("remove_indices", []))])
                    continue
                if action_kind == "pad":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_pad_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "swish":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_swish_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "leaky":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_leaky_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "dequantize":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_dequant_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "add":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_add_nhwc_plan(
                            plan=dict(action["plan"]),
                            applied_split_indices=applied_split_indices,
                            applied_add_indices=applied_add_indices,
                        )
                    )
                    continue
                if action_kind == "split":
                    new_concat_inputs.append(str(action["input_name"]))
                    split_plan = dict(action["plan"])
                    split_idx = int(split_plan.get("split_idx", -1))
                    if int(split_idx) not in applied_split_indices:
                        pre_remove_indices.extend(
                            _apply_split_nhwc_plan(plan=split_plan)
                        )
                        applied_split_indices.add(int(split_idx))
                    continue
                if action_kind == "slice":
                    new_concat_inputs.append(str(action["input_name"]))
                    slice_plan = dict(action["plan"])
                    slice_group_key = str(slice_plan.get("slice_group_key", ""))
                    if slice_group_key != "" and slice_group_key in applied_slice_group_keys:
                        continue
                    pre_remove_indices.extend(_apply_slice_nhwc_plan(plan=slice_plan))
                    if slice_group_key != "":
                        applied_slice_group_keys.add(slice_group_key)
                    continue
                if action_kind == "unary":
                    new_concat_inputs.append(str(action["input_name"]))
                    pre_remove_indices.extend(
                        _apply_unary_nhwc_plan(plan=dict(action["plan"]))
                    )
                    continue
                if action_kind == "softmax":
                    new_concat_inputs.append(str(action["input_name"]))
                    softmax_remove = _apply_softmax_nhwc_plan(plan=dict(action["plan"]))
                    if softmax_remove is None:
                        rewritable = False
                        break
                    pre_remove_indices.extend([int(v) for v in list(softmax_remove)])
                    continue
                if action_kind == "prelu":
                    new_concat_inputs.append(str(action["input_name"]))
                    prelu_remove = _apply_prelu_nhwc_plan(plan=dict(action["plan"]))
                    if prelu_remove is None:
                        rewritable = False
                        break
                    pre_remove_indices.extend([int(v) for v in list(prelu_remove)])
                    continue
                rewritable = False
                break
            if not rewritable:
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat_op.options["axis"] = 3
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(concat_out_name, None),
                perm_nchw_to_nhwc,
            )

            canonical_post_output_name = str(post_output_names[0])
            if post_quantize_idx is None:
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=concat_op,
                    new_outputs=[canonical_post_output_name],
                )
            else:
                post_quantize_op = model_ir.operators[int(post_quantize_idx)]
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=post_quantize_op,
                    new_outputs=[canonical_post_output_name],
                )
            for alias_post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_post_output_name, canonical_post_output_name)

            old_concat_tensor = model_ir.tensors.get(concat_out_name, None)
            canonical_post_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if canonical_post_tensor is not None:
                if post_quantize_idx is None:
                    if old_concat_tensor is not None:
                        canonical_post_tensor.dtype = str(old_concat_tensor.dtype)
                        canonical_post_tensor.quantization = _clone_quantization(old_concat_tensor.quantization)
                else:
                    old_q_out_tensor = (
                        model_ir.tensors.get(str(post_quantize_out_name), None)
                        if post_quantize_out_name is not None
                        else None
                    )
                    if old_q_out_tensor is not None:
                        canonical_post_tensor.dtype = str(old_q_out_tensor.dtype)
                        canonical_post_tensor.quantization = _clone_quantization(old_q_out_tensor.quantization)
                    if old_concat_tensor is not None:
                        canonical_post_tensor.shape = [int(v) for v in list(old_concat_tensor.shape)]
                        canonical_post_tensor.shape_signature = (
                            [int(v) for v in list(old_concat_tensor.shape_signature)]
                            if old_concat_tensor.shape_signature is not None
                            else [int(v) for v in list(old_concat_tensor.shape)]
                        )

            remove_op_ids: set[int] = set(int(v) for v in list(post_op_ids))
            for remove_idx in pre_remove_indices:
                if int(remove_idx) < 0 or int(remove_idx) >= len(model_ir.operators):
                    continue
                remove_op_ids.add(int(id(model_ir.operators[int(remove_idx)])))
            remove_indices = sorted(
                [
                    int(op_idx)
                    for op_idx, op in enumerate(model_ir.operators)
                    if int(id(op)) in remove_op_ids
                ],
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_concat_nhwc_chains": int(optimized)}


def _optimize_transpose_pre_concat_nhwc_chains(
    model_ir: ModelIR,
    *,
    layout_state: Any = None,
    diagnostics: Optional[List[Dict[str, Any]]] = None,
) -> Dict[str, int]:
    """Run indexed bounded families before the remaining legacy families."""

    indexed_stats = run_nhwc_concat_layout_cleanup(
        model_ir,
        layout_state=layout_state,
        diagnostics=diagnostics,
    )
    quantized_indexed_stats = run_nhwc_concat_quantized_layout_cleanup(
        model_ir,
        layout_state=layout_state,
        diagnostics=diagnostics,
    )
    legacy_stats = _optimize_transpose_pre_concat_nhwc_chains_legacy(model_ir)
    indexed_stats_keys = (
        "optimized_transpose_pre_concat_nhwc_direct_chains",
        "optimized_transpose_pre_concat_nhwc_unary_chains",
        "optimized_transpose_pre_concat_nhwc_pad_chains",
        "optimized_transpose_pre_concat_nhwc_dequantize_chains",
        "optimized_transpose_pre_concat_nhwc_prelu_chains",
        "optimized_transpose_pre_concat_nhwc_softmax_chains",
        "optimized_transpose_pre_concat_nhwc_swish_chains",
        "optimized_transpose_pre_concat_nhwc_slice_chains",
        "optimized_transpose_pre_concat_nhwc_split_chains",
        "optimized_transpose_pre_concat_nhwc_add_chains",
        "optimized_transpose_pre_concat_nhwc_leaky_chains",
    )
    quantized_indexed_stats_keys = (
        "optimized_transpose_pre_concat_nhwc_quantized_direct_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_unary_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_pad_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_unary_pad_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_all_pad_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_swish_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_dequantize_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_prelu_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_softmax_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_leaky_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_slice_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_split_chains",
        "optimized_transpose_pre_concat_nhwc_quantized_add_chains",
    )
    optimized = sum(
        int(indexed_stats.get(stats_key, 0))
        for stats_key in indexed_stats_keys
    )
    optimized += sum(
        int(quantized_indexed_stats.get(stats_key, 0))
        for stats_key in quantized_indexed_stats_keys
    )
    optimized += int(
        legacy_stats.get("optimized_transpose_pre_concat_nhwc_chains", 0)
    )
    return {
        "optimized_transpose_pre_concat_nhwc_chains": int(optimized)
    }


def _optimize_transpose_pre_dequant_concat_quantize_post_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_pre_dequant_concat_quantize_post_nhwc_chains_pass(
        model_ir
    )


def _optimize_transpose_concat_unary_fanout_conv_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_concat_unary_fanout_conv_nhwc_chains_pass(
        model_ir
    )


def _optimize_transpose_resize_add_concat_affine_conv_spp_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_resize_add_concat_affine_conv_spp_nhwc_chains_pass(
        model_ir
    )


def _optimize_transpose_pre_concat_ndhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    return _optimize_transpose_pre_concat_ndhwc_chains_pass(model_ir)


def _optimize_transpose_slice_prepost_nhwc_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate strict NHWC<->NCHW transpose wrappers around rank-4 SLICE.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --SLICE(begin,size)--> y_nchw
      y_nchw --TRANSPOSE(0,2,3,1)--> z_nhwc

    Rewrite:
      x_nhwc --SLICE(begin',size')--> z_nhwc

    Safety:
    - Rank-4 only.
    - SLICE begin/size must be constant tensors.
    - Intermediate transpose/slice tensors must be strict single-consumer links.
    - begin/size tensors must be used only by the target SLICE.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc:
                continue

            slice_out_name = str(post_op.inputs[0])
            post_out_name = str(post_op.outputs[0])
            if slice_out_name in model_outputs:
                continue

            slice_idx = producers.get(slice_out_name, None)
            if slice_idx is None:
                continue
            slice_op = model_ir.operators[int(slice_idx)]
            if str(slice_op.op_type) != "SLICE" or len(slice_op.inputs) < 3 or len(slice_op.outputs) != 1:
                continue
            if str(slice_op.outputs[0]) != slice_out_name:
                continue
            if set(int(v) for v in consumers.get(slice_out_name, [])) != {int(post_idx)}:
                continue

            begin_name = str(slice_op.inputs[1])
            size_name = str(slice_op.inputs[2])
            begin_vals = _read_const_ints_from_tensor(model_ir.tensors.get(begin_name, None))
            size_vals = _read_const_ints_from_tensor(model_ir.tensors.get(size_name, None))
            if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
                continue
            if set(int(v) for v in consumers.get(begin_name, [])) != {int(slice_idx)}:
                continue
            if set(int(v) for v in consumers.get(size_name, [])) != {int(slice_idx)}:
                continue

            pre_out_name = str(slice_op.inputs[0])
            if pre_out_name in model_outputs:
                continue
            pre_idx = producers.get(pre_out_name, None)
            if pre_idx is None:
                continue
            pre_op = model_ir.operators[int(pre_idx)]
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or str(pre_op.outputs[0]) != pre_out_name
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue
            if set(int(v) for v in consumers.get(pre_out_name, [])) != {int(slice_idx)}:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            post_out_tensor = model_ir.tensors.get(post_out_name, None)
            if (
                pre_input_tensor is None
                or post_out_tensor is None
                or len(list(pre_input_tensor.shape)) != 4
                or len(list(post_out_tensor.shape)) != 4
            ):
                continue

            pre_input_shape = [int(v) for v in list(pre_input_tensor.shape)]
            post_out_shape = [int(v) for v in list(post_out_tensor.shape)]
            begin_vals_i = [int(v) for v in list(begin_vals)]
            size_vals_i = [int(v) for v in list(size_vals)]

            # Select remapped params only when they reproduce the expected NHWC post shape.
            # This prevents double-remap corruption when constants were already converted.
            as_is_shape, _, _ = _infer_slice_output_shape_and_resolved_params(
                input_shape=pre_input_shape,
                begin_vals=begin_vals_i,
                size_vals=size_vals_i,
            )
            remapped_begin = [int(begin_vals_i[int(axis)]) for axis in perm_nchw_to_nhwc]
            remapped_size = [int(size_vals_i[int(axis)]) for axis in perm_nchw_to_nhwc]
            remapped_shape, _, _ = _infer_slice_output_shape_and_resolved_params(
                input_shape=pre_input_shape,
                begin_vals=remapped_begin,
                size_vals=remapped_size,
            )

            selected_begin: Optional[List[int]] = None
            selected_size: Optional[List[int]] = None
            if as_is_shape is not None and [int(v) for v in list(as_is_shape)] == post_out_shape:
                selected_begin = begin_vals_i
                selected_size = size_vals_i
            elif remapped_shape is not None and [int(v) for v in list(remapped_shape)] == post_out_shape:
                selected_begin = remapped_begin
                selected_size = remapped_size
            else:
                continue

            _write_const_ints_to_tensor(model_ir.tensors.get(begin_name, None), selected_begin)
            _write_const_ints_to_tensor(model_ir.tensors.get(size_name, None), selected_size)
            _replace_operator_input_at(
                model_ir=model_ir,
                op=slice_op,
                input_index=0,
                new_input_name=pre_input_name,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=slice_op,
                new_outputs=[post_out_name],
            )

            for remove_idx in sorted([int(post_idx), int(pre_idx)], reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    if optimized > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_slice_prepost_nhwc_passthrough_chains": int(optimized)}


def _optimize_transpose_shape_extract_nhwc_to_nchw_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove NHWC->NCHW transposes used only for SHAPE extraction.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw --SHAPE--> s_nchw
      s_nchw --GATHER/SLICE(...)--> ...

    Rewrite:
      x_nhwc --SHAPE--> s_nchw'
      - Remap GATHER indices by transpose permutation.
      - For SLICE on rank-1 shape vectors, remap selected indices.
        If remapped indices are non-contiguous, convert SLICE to GATHER.
      - Remove the now-redundant TRANSPOSE.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]

    def _unique_tensor_name(base: str) -> str:
        if base not in model_ir.tensors:
            return base
        suffix = 1
        while f"{base}_{suffix}" in model_ir.tensors:
            suffix += 1
        return f"{base}_{suffix}"

    def _materialize_const_tensor(
        *,
        base_name: str,
        template_tensor: Optional[TensorIR],
        values: List[int],
    ) -> str:
        new_name = _unique_tensor_name(base_name)
        np_dtype = np.int32
        dtype_name = "INT32"
        quant = None
        if template_tensor is not None:
            dtype_name = str(template_tensor.dtype)
            quant = _clone_quantization(template_tensor.quantization)
            if template_tensor.data is not None:
                try:
                    np_dtype = np.asarray(template_tensor.data).dtype
                except Exception:
                    np_dtype = np.int32
        const_values = [int(v) for v in list(values)]
        model_ir.tensors[new_name] = TensorIR(
            name=new_name,
            dtype=dtype_name,
            shape=[int(len(const_values))],
            shape_signature=[int(len(const_values))],
            data=np.asarray(const_values, dtype=np_dtype),
            is_variable=False,
            quantization=quant,
        )
        return new_name

    def _assign_const_input(
        *,
        op_idx: int,
        input_index: int,
        values: List[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        op = model_ir.operators[int(op_idx)]
        if int(input_index) < 0 or int(input_index) >= len(op.inputs):
            return False
        input_name = str(op.inputs[int(input_index)])
        input_tensor = model_ir.tensors.get(input_name, None)
        if input_tensor is None:
            return False
        user_set = set(int(v) for v in consumers.get(input_name, []))
        if user_set == {int(op_idx)}:
            return _write_const_ints_to_tensor(input_tensor, [int(v) for v in list(values)])
        cloned_name = _materialize_const_tensor(
            base_name=f"{input_name}_shape_remap",
            template_tensor=input_tensor,
            values=[int(v) for v in list(values)],
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=op,
            input_index=int(input_index),
            new_input_name=cloned_name,
        )
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for transpose_idx, transpose_op in enumerate(model_ir.operators):
            if (
                str(transpose_op.op_type) != "TRANSPOSE"
                or len(transpose_op.inputs) < 2
                or len(transpose_op.outputs) != 1
            ):
                continue
            perm = _read_transpose_perm(model_ir, transpose_op)
            if perm != perm_nhwc_to_nchw:
                continue

            transpose_input_name = str(transpose_op.inputs[0])
            transpose_output_name = str(transpose_op.outputs[0])
            if transpose_output_name in model_outputs:
                continue

            transpose_users = [int(v) for v in consumers.get(transpose_output_name, [])]
            if len(transpose_users) != 1:
                continue
            shape_idx = int(transpose_users[0])
            shape_op = model_ir.operators[int(shape_idx)]
            if (
                str(shape_op.op_type) != "SHAPE"
                or len(shape_op.inputs) != 1
                or len(shape_op.outputs) != 1
                or str(shape_op.inputs[0]) != transpose_output_name
            ):
                continue

            shape_output_name = str(shape_op.outputs[0])
            if shape_output_name in model_outputs:
                continue
            shape_users = [int(v) for v in consumers.get(shape_output_name, [])]
            if len(shape_users) == 0:
                continue

            gather_rewrites: List[Tuple[int, List[int]]] = []
            slice_contiguous_rewrites: List[Tuple[int, List[int], List[int]]] = []
            slice_to_gather_rewrites: List[Tuple[int, List[int]]] = []
            rewrite_supported = True
            rank = int(len(perm))

            for user_idx in shape_users:
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)
                if user_type == "GATHER":
                    if (
                        len(user_op.inputs) < 2
                        or len(user_op.outputs) != 1
                        or str(user_op.inputs[0]) != shape_output_name
                    ):
                        rewrite_supported = False
                        break
                    axis = int(user_op.options.get("axis", 0))
                    if axis < 0:
                        axis += 1
                    if axis != 0:
                        rewrite_supported = False
                        break
                    indices_tensor = model_ir.tensors.get(str(user_op.inputs[1]), None)
                    indices_vals = _read_const_ints_from_tensor(indices_tensor)
                    if indices_vals is None or len(indices_vals) == 0:
                        rewrite_supported = False
                        break
                    remapped_indices: List[int] = []
                    for index_value in indices_vals:
                        index = int(index_value)
                        if index < 0:
                            index += int(rank)
                        if index < 0 or index >= int(rank):
                            rewrite_supported = False
                            break
                        remapped_indices.append(int(perm[int(index)]))
                    if not rewrite_supported:
                        break
                    gather_rewrites.append((int(user_idx), remapped_indices))
                    continue

                if user_type == "SLICE":
                    if (
                        len(user_op.inputs) < 3
                        or len(user_op.outputs) != 1
                        or str(user_op.inputs[0]) != shape_output_name
                    ):
                        rewrite_supported = False
                        break
                    begin_tensor = model_ir.tensors.get(str(user_op.inputs[1]), None)
                    size_tensor = model_ir.tensors.get(str(user_op.inputs[2]), None)
                    begin_vals = _read_const_ints_from_tensor(begin_tensor)
                    size_vals = _read_const_ints_from_tensor(size_tensor)
                    if begin_vals is None or size_vals is None:
                        rewrite_supported = False
                        break
                    if len(begin_vals) != 1 or len(size_vals) != 1:
                        rewrite_supported = False
                        break
                    begin = int(begin_vals[0])
                    size = int(size_vals[0])
                    if begin < 0:
                        begin += int(rank)
                    begin = max(0, min(int(begin), int(rank)))
                    if size == -1:
                        end = int(rank)
                    elif size < -1:
                        rewrite_supported = False
                        break
                    else:
                        end = min(int(rank), int(begin + size))
                    if int(end) <= int(begin):
                        rewrite_supported = False
                        break
                    selected = [int(v) for v in range(int(begin), int(end))]
                    remapped_selected = [int(perm[int(v)]) for v in selected]
                    is_contiguous = all(
                        int(remapped_selected[int(i)]) == int(remapped_selected[0] + i)
                        for i in range(len(remapped_selected))
                    )
                    if is_contiguous:
                        new_begin = [int(remapped_selected[0])]
                        new_size = [int(len(remapped_selected))]
                        slice_contiguous_rewrites.append((int(user_idx), new_begin, new_size))
                    else:
                        slice_to_gather_rewrites.append((int(user_idx), remapped_selected))
                    continue

                rewrite_supported = False
                break

            if not rewrite_supported:
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=shape_op,
                input_index=0,
                new_input_name=transpose_input_name,
            )

            for gather_idx, remapped_indices in gather_rewrites:
                _assign_const_input(
                    op_idx=int(gather_idx),
                    input_index=1,
                    values=[int(v) for v in remapped_indices],
                    consumers=consumers,
                )

            for slice_idx, new_begin, new_size in slice_contiguous_rewrites:
                _assign_const_input(
                    op_idx=int(slice_idx),
                    input_index=1,
                    values=[int(v) for v in list(new_begin)],
                    consumers=consumers,
                )
                _assign_const_input(
                    op_idx=int(slice_idx),
                    input_index=2,
                    values=[int(v) for v in list(new_size)],
                    consumers=consumers,
                )

            for slice_idx, remapped_indices in slice_to_gather_rewrites:
                slice_op = model_ir.operators[int(slice_idx)]
                begin_input_name = str(slice_op.inputs[1])
                begin_tensor = model_ir.tensors.get(begin_input_name, None)
                gather_indices_name = _materialize_const_tensor(
                    base_name=f"{begin_input_name}_gather",
                    template_tensor=begin_tensor,
                    values=[int(v) for v in remapped_indices],
                )
                slice_op.op_type = "GATHER"
                slice_op.version = 1
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=slice_op,
                    new_inputs=[shape_output_name, gather_indices_name],
                )
                slice_op.options = {"axis": 0, "batchDims": 0}
                slice_out_name = str(slice_op.outputs[0])
                slice_out_tensor = model_ir.tensors.get(slice_out_name, None)
                if slice_out_tensor is not None:
                    slice_out_tensor.shape = [int(len(remapped_indices))]
                    slice_out_tensor.shape_signature = [int(len(remapped_indices))]

            del model_ir.operators[int(transpose_idx)]
            optimized += 1
            changed = True
            break

        if not changed:
            break

    if optimized > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_shape_extract_nhwc_to_nchw_chains": int(optimized)}


def _optimize_transpose_stridedslice_pre_concat_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around stride-slice fan-in concat blocks.

    Target:
      X_nhwc --TRANSPOSE(0,3,1,2)--> X_nchw
      X_nchw --STRIDED_SLICE(...)--> s_i_nchw   (all consumed by one CONCAT axis=1)
      CONCAT(axis=1, [s_i_nchw...]) --> y_nchw
      y_nchw --TRANSPOSE(0,2,3,1)--> y_nhwc

    Rewrite:
      X_nhwc --STRIDED_SLICE'(NHWC params)--> s_i_nhwc
      CONCAT(axis=3, [s_i_nhwc...]) --> y_nhwc

    If legacy NCHW consumers of `y_nchw` exist, keep one adapter:
      y_nhwc --TRANSPOSE(0,3,1,2)--> y_nchw
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _is_supported_stridedslice(op: OperatorIR) -> bool:
        if str(op.op_type) != "STRIDED_SLICE":
            return False
        if len(op.inputs) != 4 or len(op.outputs) != 1:
            return False
        opts = op.options if isinstance(op.options, dict) else {}
        if int(opts.get("beginMask", 0)) != 0:
            return False
        if int(opts.get("endMask", 0)) != 0:
            return False
        if int(opts.get("ellipsisMask", 0)) != 0:
            return False
        if int(opts.get("newAxisMask", 0)) != 0:
            return False
        if int(opts.get("shrinkAxisMask", 0)) != 0:
            return False
        if bool(opts.get("offset", False)):
            return False
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) < 2:
                continue

            slice_indices: List[int] = []
            slice_output_names: List[str] = []
            stridedslice_consts: List[Tuple[str, str, str]] = []
            valid_slices = True
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                if not _is_supported_stridedslice(user_op):
                    valid_slices = False
                    break
                if str(user_op.inputs[0]) != pre_output_name:
                    valid_slices = False
                    break
                out_name = str(user_op.outputs[0])
                if out_name in model_outputs:
                    valid_slices = False
                    break

                begin_name = str(user_op.inputs[1])
                end_name = str(user_op.inputs[2])
                strides_name = str(user_op.inputs[3])
                begin_tensor = model_ir.tensors.get(begin_name, None)
                end_tensor = model_ir.tensors.get(end_name, None)
                strides_tensor = model_ir.tensors.get(strides_name, None)
                begin_vals = _read_const_ints_from_tensor(begin_tensor)
                end_vals = _read_const_ints_from_tensor(end_tensor)
                strides_vals = _read_const_ints_from_tensor(strides_tensor)
                if begin_vals is None or end_vals is None or strides_vals is None:
                    valid_slices = False
                    break
                if len(begin_vals) != 4 or len(end_vals) != 4 or len(strides_vals) != 4:
                    valid_slices = False
                    break
                if any(int(v) == 0 for v in strides_vals):
                    valid_slices = False
                    break
                # Avoid mutating shared constants.
                if set(int(v) for v in consumers.get(begin_name, [])) != {int(user_idx)}:
                    valid_slices = False
                    break
                if set(int(v) for v in consumers.get(end_name, [])) != {int(user_idx)}:
                    valid_slices = False
                    break
                if set(int(v) for v in consumers.get(strides_name, [])) != {int(user_idx)}:
                    valid_slices = False
                    break

                slice_indices.append(int(user_idx))
                slice_output_names.append(out_name)
                stridedslice_consts.append((begin_name, end_name, strides_name))

            if not valid_slices:
                continue

            concat_idx: Optional[int] = None
            for slice_out_name in slice_output_names:
                users = [int(v) for v in consumers.get(slice_out_name, [])]
                if len(users) != 1:
                    concat_idx = None
                    break
                if concat_idx is None:
                    concat_idx = int(users[0])
                elif int(concat_idx) != int(users[0]):
                    concat_idx = None
                    break
            if concat_idx is None:
                continue

            concat_op = model_ir.operators[int(concat_idx)]
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue
            concat_axis_old = int(concat_op.options.get("axis", 1))
            if concat_axis_old < 0:
                concat_axis_old += 4
            if concat_axis_old != 1:
                continue

            concat_inputs = [str(v) for v in list(concat_op.inputs)]
            if len(concat_inputs) != len(slice_output_names):
                continue
            if set(concat_inputs) != set(slice_output_names):
                continue

            concat_out_name = str(concat_op.outputs[0])
            concat_users = [int(v) for v in consumers.get(concat_out_name, []) if int(v) != int(concat_idx)]
            if len(concat_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_posts = True
            for user_idx in concat_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == concat_out_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    legacy_users.append(int(user_idx))
            if not valid_posts or len(post_indices) == 0:
                continue

            # Rewrite all STRIDED_SLICE params/layout from NCHW to NHWC.
            rewrite_ok = True
            for slice_idx, (begin_name, end_name, strides_name), slice_out_name in zip(
                slice_indices,
                stridedslice_consts,
                slice_output_names,
            ):
                slice_op = model_ir.operators[int(slice_idx)]
                begin_tensor = model_ir.tensors.get(begin_name, None)
                end_tensor = model_ir.tensors.get(end_name, None)
                strides_tensor = model_ir.tensors.get(strides_name, None)
                begin_vals = _read_const_ints_from_tensor(begin_tensor)
                end_vals = _read_const_ints_from_tensor(end_tensor)
                strides_vals = _read_const_ints_from_tensor(strides_tensor)
                if begin_vals is None or end_vals is None or strides_vals is None:
                    rewrite_ok = False
                    break
                begin_nhwc = _permute_shape(begin_vals, perm_nchw_to_nhwc)
                end_nhwc = _permute_shape(end_vals, perm_nchw_to_nhwc)
                strides_nhwc = _permute_shape(strides_vals, perm_nchw_to_nhwc)
                if begin_nhwc is None or end_nhwc is None or strides_nhwc is None:
                    rewrite_ok = False
                    break
                _write_const_ints_to_tensor(begin_tensor, [int(v) for v in begin_nhwc])
                _write_const_ints_to_tensor(end_tensor, [int(v) for v in end_nhwc])
                _write_const_ints_to_tensor(strides_tensor, [int(v) for v in strides_nhwc])
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=slice_op,
                    input_index=0,
                    new_input_name=pre_input_name,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(slice_out_name, None),
                    perm_nchw_to_nhwc,
                )

            if not rewrite_ok:
                continue

            concat_op.options["axis"] = 3
            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat_op,
                new_outputs=[canonical_post_output_name],
            )
            for alias_post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_post_output_name, canonical_post_output_name)

            old_concat_tensor = model_ir.tensors.get(concat_out_name, None)
            canonical_post_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_concat_tensor is not None and canonical_post_tensor is not None:
                canonical_post_tensor.dtype = str(old_concat_tensor.dtype)
                canonical_post_tensor.quantization = _clone_quantization(old_concat_tensor.quantization)
                canonical_post_tensor.shape = [int(v) for v in list(old_concat_tensor.shape)]
                canonical_post_tensor.shape_signature = (
                    [int(v) for v in list(old_concat_tensor.shape_signature)]
                    if old_concat_tensor.shape_signature is not None
                    else [int(v) for v in list(old_concat_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_post_tensor,
                    perm_nchw_to_nhwc,
                )

            preserve_nchw_adapter = len(legacy_users) > 0 or concat_out_name in model_outputs
            if preserve_nchw_adapter:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[int(keep_post_idx)]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[canonical_post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[concat_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(
                list({int(pre_idx), *post_remove_indices}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_stridedslice_pre_concat_nhwc_chains": int(optimized)}


def _optimize_transpose_input_chains_pre_concat_to_single_post_adapter(model_ir: ModelIR) -> Dict[str, int]:
    """
    Collapse per-input NHWC->NCHW adapters before CONCAT into a single post-CONCAT adapter.

    Target:
      x0_nhwc --TRANSPOSE(0,3,1,2)--> x0_nchw --(optional unary)--> i0_nchw
      x1_nhwc --TRANSPOSE(0,3,1,2)--> x1_nchw --(optional unary)--> i1_nchw
      ...
      CONCAT(axis=1, [i0_nchw, i1_nchw, ...]) -> y_nchw
      y_nchw -> downstream (e.g. RESHAPE)

    Rewrite:
      x0_nhwc --(optional unary)--> i0_nhwc
      x1_nhwc --(optional unary)--> i1_nhwc
      ...
      CONCAT(axis=3, [i0_nhwc, i1_nhwc, ...]) -> y_nhwc
      y_nhwc --TRANSPOSE(0,3,1,2)--> y_nchw

    This keeps downstream NCHW semantics unchanged while reducing redundant pre-concat
    transpose chains.

    Supported layout adapters:
      - TRANSPOSE(0,3,1,2)
      - RESHAPE [N,H,W,1] -> [N,1,H,W] (singleton-channel layout adapter)
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {
        "LOGISTIC",
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "ELU",
        "LEAKY_RELU",
        "TANH",
        "GELU",
        "HARD_SWISH",
        "ABS",
        "EXP",
        "NEG",
        "SQRT",
    }

    def _unique_tensor_name(base: str) -> str:
        if base not in model_ir.tensors:
            return base
        suffix = 1
        while True:
            candidate = f"{base}_{suffix}"
            if candidate not in model_ir.tensors:
                return candidate
            suffix += 1

    def _is_singleton_channel_nhwc_to_nchw_reshape(
        *,
        input_name: str,
        output_name: str,
    ) -> bool:
        in_tensor = model_ir.tensors.get(str(input_name), None)
        out_tensor = model_ir.tensors.get(str(output_name), None)
        if in_tensor is None or out_tensor is None:
            return False
        in_shape = [int(v) for v in list(in_tensor.shape)]
        out_shape = [int(v) for v in list(out_tensor.shape)]
        if len(in_shape) != 4 or len(out_shape) != 4:
            return False
        return (
            int(in_shape[0]) == int(out_shape[0])
            and int(in_shape[1]) == int(out_shape[2])
            and int(in_shape[2]) == int(out_shape[3])
            and int(in_shape[3]) == 1
            and int(out_shape[1]) == 1
        )

    def _find_or_create_nhwc_to_nchw_perm_tensor() -> str:
        target = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
        for tensor_name, tensor in model_ir.tensors.items():
            if tensor is None or tensor.data is None:
                continue
            data = np.asarray(tensor.data)
            if data.dtype != np.int32 or data.size != 4:
                continue
            if np.array_equal(data.reshape(-1), target):
                return str(tensor_name)
        perm_name = _unique_tensor_name("transpose_input_chains_nhwc_to_nchw_perm")
        model_ir.tensors[perm_name] = TensorIR(
            name=perm_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=target,
            is_variable=False,
        )
        return perm_name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue

            concat_axis_old = int(concat_op.options.get("axis", 1))
            if concat_axis_old < 0:
                concat_axis_old += 4
            if concat_axis_old != 1:
                continue

            concat_out_name = str(concat_op.outputs[0])
            concat_out_tensor = model_ir.tensors.get(concat_out_name, None)
            if concat_out_tensor is None or len(list(concat_out_tensor.shape)) != 4:
                continue

            new_concat_inputs: List[str] = []
            pre_remove_indices: List[int] = []
            unary_input_rewrites: Dict[int, str] = {}
            unary_output_names_to_permute: List[str] = []
            adapter_perm_tensor_name: Optional[str] = None
            rewritable = True

            for input_name in [str(v) for v in list(concat_op.inputs)]:
                input_producer_idx = producers.get(str(input_name), None)
                if input_producer_idx is None:
                    rewritable = False
                    break
                input_producer = model_ir.operators[int(input_producer_idx)]

                if (
                    str(input_producer.op_type) == "TRANSPOSE"
                    and len(input_producer.inputs) >= 2
                    and len(input_producer.outputs) == 1
                    and str(input_producer.outputs[0]) == str(input_name)
                    and _read_transpose_perm(model_ir, input_producer) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(input_name), [])) == {int(concat_idx)}
                    and str(input_name) not in model_outputs
                ):
                    new_concat_inputs.append(str(input_producer.inputs[0]))
                    pre_remove_indices.append(int(input_producer_idx))
                    if adapter_perm_tensor_name is None:
                        adapter_perm_tensor_name = str(input_producer.inputs[1])
                    continue

                if (
                    str(input_producer.op_type) in unary_ops
                    and len(input_producer.inputs) == 1
                    and len(input_producer.outputs) == 1
                    and str(input_producer.outputs[0]) == str(input_name)
                    and set(int(v) for v in consumers.get(str(input_name), [])) == {int(concat_idx)}
                    and str(input_name) not in model_outputs
                ):
                    unary_in_name = str(input_producer.inputs[0])
                    pre_idx = producers.get(unary_in_name, None)
                    if pre_idx is None:
                        rewritable = False
                        break
                    pre_op = model_ir.operators[int(pre_idx)]
                    if (
                        set(int(v) for v in consumers.get(unary_in_name, [])) != {int(input_producer_idx)}
                        or unary_in_name in model_outputs
                    ):
                        rewritable = False
                        break
                    if str(pre_op.op_type) == "TRANSPOSE":
                        if (
                            len(pre_op.inputs) < 2
                            or len(pre_op.outputs) != 1
                            or str(pre_op.outputs[0]) != unary_in_name
                            or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                        ):
                            rewritable = False
                            break
                        if adapter_perm_tensor_name is None:
                            adapter_perm_tensor_name = str(pre_op.inputs[1])
                    elif str(pre_op.op_type) == "RESHAPE":
                        if (
                            len(pre_op.inputs) < 1
                            or len(pre_op.outputs) != 1
                            or str(pre_op.outputs[0]) != unary_in_name
                            or not _is_singleton_channel_nhwc_to_nchw_reshape(
                                input_name=str(pre_op.inputs[0]),
                                output_name=unary_in_name,
                            )
                        ):
                            rewritable = False
                            break
                    else:
                        rewritable = False
                        break
                    unary_input_rewrites[int(input_producer_idx)] = str(pre_op.inputs[0])
                    unary_output_names_to_permute.append(str(input_name))
                    new_concat_inputs.append(str(input_name))
                    pre_remove_indices.append(int(pre_idx))
                    continue

                rewritable = False
                break

            if not rewritable:
                continue
            if adapter_perm_tensor_name is None:
                adapter_perm_tensor_name = _find_or_create_nhwc_to_nchw_perm_tensor()

            unary_outputs_to_permute = {str(v) for v in unary_output_names_to_permute}
            nhwc_inputs_ok = True
            nhwc_ref_shape: Optional[List[int]] = None
            for input_name in new_concat_inputs:
                input_tensor = model_ir.tensors.get(str(input_name), None)
                if input_tensor is None or len(list(input_tensor.shape)) != 4:
                    nhwc_inputs_ok = False
                    break
                shape = [int(v) for v in list(input_tensor.shape)]
                if str(input_name) in unary_outputs_to_permute:
                    permuted_shape = _permute_shape(shape, perm_nchw_to_nhwc)
                    if permuted_shape is None:
                        nhwc_inputs_ok = False
                        break
                    shape = [int(v) for v in list(permuted_shape)]
                if nhwc_ref_shape is None:
                    nhwc_ref_shape = list(shape)
                else:
                    for dim_idx in [0, 1, 2]:
                        if int(shape[dim_idx]) != int(nhwc_ref_shape[dim_idx]):
                            nhwc_inputs_ok = False
                            break
                if not nhwc_inputs_ok:
                    break
            if not nhwc_inputs_ok:
                continue

            new_concat_shape = _permute_shape(list(concat_out_tensor.shape), perm_nchw_to_nhwc)
            concat_sig_source = (
                list(concat_out_tensor.shape_signature)
                if concat_out_tensor.shape_signature is not None
                else list(concat_out_tensor.shape)
            )
            new_concat_signature = _permute_shape(concat_sig_source, perm_nchw_to_nhwc)
            if new_concat_shape is None or new_concat_signature is None:
                continue

            for unary_idx, rewrite_input_name in unary_input_rewrites.items():
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=model_ir.operators[int(unary_idx)],
                    new_inputs=[str(rewrite_input_name)],
                )
            for tensor_name in unary_output_names_to_permute:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(tensor_name), None),
                    perm_nchw_to_nhwc,
                )

            new_concat_out_name = _unique_tensor_name(f"{concat_out_name}_nhwc")
            model_ir.tensors[new_concat_out_name] = TensorIR(
                name=new_concat_out_name,
                dtype=str(concat_out_tensor.dtype),
                shape=[int(v) for v in list(new_concat_shape)],
                data=None,
                quantization=_clone_quantization(concat_out_tensor.quantization),
                shape_signature=[int(v) for v in list(new_concat_signature)],
            )

            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat_op.options["axis"] = 3
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat_op,
                new_outputs=[str(new_concat_out_name)],
            )

            adapter_op = OperatorIR(
                op_type="TRANSPOSE",
                inputs=[str(new_concat_out_name), str(adapter_perm_tensor_name)],
                outputs=[str(concat_out_name)],
                options={},
            )
            model_ir.operators.insert(int(concat_idx) + 1, adapter_op)

            remove_indices = sorted(list({int(v) for v in pre_remove_indices}), reverse=True)
            for remove_idx in remove_indices:
                if int(remove_idx) == int(concat_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_input_chains_pre_concat_to_single_post_adapter": int(optimized)}


def _optimize_transpose_split_mixed_pre_concat_to_single_post_adapter_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Collapse mixed pre-CONCAT NCHW adapters with SPLIT branches into NHWC + single post adapter.

    Target:
      split_in_nchw --SPLIT(axis=1)--> s0_nchw, s1_nchw, ...
      s1_nchw --TRANSPOSE(0,2,3,1)--> s1_nhwc --...
      b0_nhwc --TRANSPOSE(0,3,1,2)--> b0_nchw
      b1_nhwc --TRANSPOSE(0,3,1,2)--> b1_nchw
      CONCAT(axis=1, [s0_nchw, b0_nchw, b1_nchw, ...]) -> cat_nchw

    Rewrite:
      split_in_nchw --TRANSPOSE(0,2,3,1)--> split_in_nhwc
      split_in_nhwc --SPLIT(axis=3)--> s0_nhwc, s1_nhwc, ...
      bypass/remove s_i_nchw -> TRANSPOSE(0,2,3,1)
      CONCAT(axis=3, [s0_nhwc, b0_nhwc, b1_nhwc, ...]) -> cat_nhwc
      cat_nhwc --TRANSPOSE(0,3,1,2)--> cat_nchw

    This keeps downstream NCHW semantics unchanged while reducing redundant local
    transpose chains around split/concat bridges.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        candidate = str(base)
        suffix = 1
        while candidate in model_ir.tensors:
            candidate = f"{base}_{suffix}"
            suffix += 1
        return candidate

    def _find_op_index_by_id(op_id: int) -> Optional[int]:
        for idx, op in enumerate(model_ir.operators):
            if int(id(op)) == int(op_id):
                return int(idx)
        return None

    def _find_or_create_perm_tensor(
        *,
        base_name: str,
        perm: List[int],
    ) -> str:
        target = np.asarray([int(v) for v in list(perm)], dtype=np.int32)
        for tensor_name, tensor in model_ir.tensors.items():
            if tensor is None or tensor.data is None:
                continue
            try:
                data = np.asarray(tensor.data)
            except Exception:
                continue
            if data.dtype != np.int32 or int(data.size) != int(len(perm)):
                continue
            if np.array_equal(data.reshape(-1), target):
                return str(tensor_name)
        perm_name = _unique_tensor_name(str(base_name))
        model_ir.tensors[perm_name] = TensorIR(
            name=perm_name,
            dtype="INT32",
            shape=[int(len(perm))],
            shape_signature=[int(len(perm))],
            data=np.asarray(target, dtype=np.int32),
            is_variable=False,
        )
        return perm_name

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or len(concat_op.outputs) != 1:
                continue

            concat_axis_old = int(concat_op.options.get("axis", 1))
            if concat_axis_old < 0:
                concat_axis_old += 4
            if concat_axis_old != 1:
                continue

            concat_out_name = str(concat_op.outputs[0])
            concat_out_tensor = model_ir.tensors.get(concat_out_name, None)
            if concat_out_tensor is None or len(list(concat_out_tensor.shape)) != 4:
                continue
            if concat_out_name in model_outputs:
                continue

            concat_input_names = [str(v) for v in list(concat_op.inputs)]
            if len(concat_input_names) < 2:
                continue

            remove_op_ids: set[int] = set()
            new_concat_inputs: List[str] = []
            split_plans: Dict[int, Dict[str, Any]] = {}
            adapter_perm_tensor_name: Optional[str] = None
            nhwc_ref_shape: Optional[List[int]] = None
            rewritable = True

            for input_name in concat_input_names:
                input_producer_idx = producers.get(str(input_name), None)
                if input_producer_idx is None:
                    rewritable = False
                    break
                input_producer = model_ir.operators[int(input_producer_idx)]

                if (
                    str(input_producer.op_type) == "TRANSPOSE"
                    and len(input_producer.inputs) >= 2
                    and len(input_producer.outputs) == 1
                    and str(input_producer.outputs[0]) == str(input_name)
                    and _read_transpose_perm(model_ir, input_producer) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(input_name), [])) == {int(concat_idx)}
                    and str(input_name) not in model_outputs
                ):
                    source_name = str(input_producer.inputs[0])
                    source_tensor = model_ir.tensors.get(source_name, None)
                    if source_tensor is None or len(list(source_tensor.shape)) != 4:
                        rewritable = False
                        break
                    source_shape = [int(v) for v in list(source_tensor.shape)]
                    if nhwc_ref_shape is None:
                        nhwc_ref_shape = list(source_shape)
                    else:
                        for dim_idx in [0, 1, 2]:
                            if int(source_shape[dim_idx]) != int(nhwc_ref_shape[dim_idx]):
                                rewritable = False
                                break
                        if not rewritable:
                            break
                    new_concat_inputs.append(str(source_name))
                    remove_op_ids.add(int(id(input_producer)))
                    if adapter_perm_tensor_name is None:
                        adapter_perm_tensor_name = str(input_producer.inputs[1])
                    continue

                if str(input_producer.op_type) != "SPLIT" or len(input_producer.inputs) < 2:
                    rewritable = False
                    break
                split_idx = int(input_producer_idx)
                split_op_id = int(id(input_producer))

                split_plan = split_plans.get(split_idx, None)
                if split_plan is None:
                    split_axis_name = str(input_producer.inputs[0])
                    split_axis_tensor = model_ir.tensors.get(split_axis_name, None)
                    split_axis_vals = _read_const_ints_from_tensor(split_axis_tensor)
                    if split_axis_vals is None or len(split_axis_vals) != 1:
                        rewritable = False
                        break
                    split_axis = int(split_axis_vals[0])
                    if split_axis < 0:
                        split_axis += 4
                    if split_axis != 1:
                        rewritable = False
                        break

                    split_input_name = str(input_producer.inputs[1])
                    split_input_tensor = model_ir.tensors.get(split_input_name, None)
                    if split_input_tensor is None or len(list(split_input_tensor.shape)) != 4:
                        rewritable = False
                        break

                    split_output_names = [str(v) for v in list(input_producer.outputs)]
                    if str(input_name) not in set(split_output_names):
                        rewritable = False
                        break

                    split_output_shapes_nhwc: Dict[str, List[int]] = {}
                    split_post_rewires: List[Tuple[str, str]] = []
                    split_post_remove_ids: set[int] = set()
                    valid_split = True
                    for split_output_name in split_output_names:
                        split_output_tensor = model_ir.tensors.get(str(split_output_name), None)
                        if split_output_tensor is None or len(list(split_output_tensor.shape)) != 4:
                            valid_split = False
                            break
                        projected_shape = _permute_shape(
                            [int(v) for v in list(split_output_tensor.shape)],
                            perm_nchw_to_nhwc,
                        )
                        if projected_shape is None:
                            valid_split = False
                            break
                        split_output_shapes_nhwc[str(split_output_name)] = [int(v) for v in list(projected_shape)]

                        output_users = [int(v) for v in consumers.get(str(split_output_name), [])]
                        for user_idx in output_users:
                            if int(user_idx) == int(concat_idx):
                                continue
                            user_op = model_ir.operators[int(user_idx)]
                            if (
                                str(user_op.op_type) == "TRANSPOSE"
                                and len(user_op.inputs) >= 2
                                and len(user_op.outputs) == 1
                                and str(user_op.inputs[0]) == str(split_output_name)
                                and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                                and str(user_op.outputs[0]) not in model_outputs
                            ):
                                split_post_rewires.append((str(user_op.outputs[0]), str(split_output_name)))
                                split_post_remove_ids.add(int(id(user_op)))
                                continue
                            valid_split = False
                            break
                        if not valid_split:
                            break

                    if not valid_split:
                        rewritable = False
                        break

                    split_plan = {
                        "split_idx": int(split_idx),
                        "split_op_id": int(split_op_id),
                        "split_axis_name": str(split_axis_name),
                        "split_input_name": str(split_input_name),
                        "split_output_names": [str(v) for v in split_output_names],
                        "split_output_shapes_nhwc": dict(split_output_shapes_nhwc),
                        "split_post_rewires": list(split_post_rewires),
                        "split_post_remove_ids": set(int(v) for v in split_post_remove_ids),
                    }
                    split_plans[int(split_idx)] = dict(split_plan)

                projected_input_shape = split_plan["split_output_shapes_nhwc"].get(str(input_name), None)
                if projected_input_shape is None:
                    rewritable = False
                    break
                if nhwc_ref_shape is None:
                    nhwc_ref_shape = [int(v) for v in list(projected_input_shape)]
                else:
                    for dim_idx in [0, 1, 2]:
                        if int(projected_input_shape[dim_idx]) != int(nhwc_ref_shape[dim_idx]):
                            rewritable = False
                            break
                    if not rewritable:
                        break
                new_concat_inputs.append(str(input_name))

            if not rewritable or nhwc_ref_shape is None:
                continue
            if len(split_plans) == 0:
                continue

            if adapter_perm_tensor_name is None:
                adapter_perm_tensor_name = _find_or_create_perm_tensor(
                    base_name="mixed_pre_concat_nhwc_to_nchw_perm",
                    perm=perm_nhwc_to_nchw,
                )
            split_adapter_perm_name = _find_or_create_perm_tensor(
                base_name="mixed_pre_concat_nchw_to_nhwc_perm",
                perm=perm_nchw_to_nhwc,
            )

            pre_split_insertions: List[Tuple[int, OperatorIR]] = []
            for split_plan in split_plans.values():
                split_op_idx = _find_op_index_by_id(int(split_plan["split_op_id"]))
                if split_op_idx is None:
                    rewritable = False
                    break
                split_op = model_ir.operators[int(split_op_idx)]

                split_axis_name = str(split_plan["split_axis_name"])
                split_axis_tensor = model_ir.tensors.get(split_axis_name, None)
                if split_axis_tensor is None:
                    rewritable = False
                    break
                split_axis_users = [int(v) for v in consumers.get(split_axis_name, [])]
                if set(split_axis_users) == {int(split_op_idx)}:
                    _write_const_ints_to_tensor(split_axis_tensor, [3])
                else:
                    axis_dtype = np.int32
                    try:
                        if split_axis_tensor.data is not None:
                            axis_dtype = np.asarray(split_axis_tensor.data).dtype
                    except Exception:
                        axis_dtype = np.int32
                    split_axis_nhwc_name = _unique_tensor_name(f"{split_axis_name}_nhwc")
                    model_ir.tensors[split_axis_nhwc_name] = TensorIR(
                        name=split_axis_nhwc_name,
                        dtype=str(split_axis_tensor.dtype),
                        shape=[1],
                        shape_signature=[1],
                        data=np.asarray([3], dtype=axis_dtype),
                        is_variable=False,
                        quantization=_clone_quantization(split_axis_tensor.quantization),
                    )
                    split_inputs = [str(v) for v in list(split_op.inputs)]
                    split_inputs[0] = str(split_axis_nhwc_name)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=split_op,
                        new_inputs=split_inputs,
                    )

                split_input_name = str(split_plan["split_input_name"])
                split_input_tensor = model_ir.tensors.get(split_input_name, None)
                if split_input_tensor is None or len(list(split_input_tensor.shape)) != 4:
                    rewritable = False
                    break
                split_input_shape_nhwc = _permute_shape(
                    [int(v) for v in list(split_input_tensor.shape)],
                    perm_nchw_to_nhwc,
                )
                split_input_sig = (
                    [int(v) for v in list(split_input_tensor.shape_signature)]
                    if split_input_tensor.shape_signature is not None
                    else [int(v) for v in list(split_input_tensor.shape)]
                )
                split_input_sig_nhwc = _permute_shape(split_input_sig, perm_nchw_to_nhwc)
                if split_input_shape_nhwc is None or split_input_sig_nhwc is None:
                    rewritable = False
                    break
                split_input_nhwc_name = _unique_tensor_name(f"{split_input_name}_nhwc")
                model_ir.tensors[split_input_nhwc_name] = TensorIR(
                    name=split_input_nhwc_name,
                    dtype=str(split_input_tensor.dtype),
                    shape=[int(v) for v in list(split_input_shape_nhwc)],
                    shape_signature=[int(v) for v in list(split_input_sig_nhwc)],
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(split_input_tensor.quantization),
                )
                split_inputs = [str(v) for v in list(split_op.inputs)]
                split_inputs[1] = str(split_input_nhwc_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=split_op,
                    new_inputs=split_inputs,
                )
                pre_split_insertions.append(
                    (
                        int(split_op_idx),
                        OperatorIR(
                            op_type="TRANSPOSE",
                            inputs=[str(split_input_name), str(split_adapter_perm_name)],
                            outputs=[str(split_input_nhwc_name)],
                            options={},
                        ),
                    )
                )

                for split_output_name in [str(v) for v in list(split_plan["split_output_names"])]:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(split_output_name), None),
                        perm_nchw_to_nhwc,
                    )

                for post_output_name, replacement_name in list(split_plan["split_post_rewires"]):
                    _replace_tensor_inputs(model_ir, str(post_output_name), str(replacement_name))
                remove_op_ids.update(set(int(v) for v in list(split_plan["split_post_remove_ids"])))

            if not rewritable:
                continue

            new_concat_shape = _permute_shape(list(concat_out_tensor.shape), perm_nchw_to_nhwc)
            concat_sig_src = (
                list(concat_out_tensor.shape_signature)
                if concat_out_tensor.shape_signature is not None
                else list(concat_out_tensor.shape)
            )
            new_concat_sig = _permute_shape(concat_sig_src, perm_nchw_to_nhwc)
            if new_concat_shape is None or new_concat_sig is None:
                continue

            new_concat_out_name = _unique_tensor_name(f"{concat_out_name}_nhwc")
            model_ir.tensors[new_concat_out_name] = TensorIR(
                name=new_concat_out_name,
                dtype=str(concat_out_tensor.dtype),
                shape=[int(v) for v in list(new_concat_shape)],
                shape_signature=[int(v) for v in list(new_concat_sig)],
                data=None,
                is_variable=False,
                quantization=_clone_quantization(concat_out_tensor.quantization),
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[str(v) for v in list(new_concat_inputs)],
            )
            concat_op.options["axis"] = 3
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat_op,
                new_outputs=[str(new_concat_out_name)],
            )

            concat_op_idx = _find_op_index_by_id(int(id(concat_op)))
            if concat_op_idx is None:
                continue
            model_ir.operators.insert(
                int(concat_op_idx) + 1,
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(new_concat_out_name), str(adapter_perm_tensor_name)],
                    outputs=[str(concat_out_name)],
                    options={},
                ),
            )

            inserted = 0
            for split_op_idx, split_adapter_op in sorted(pre_split_insertions, key=lambda v: int(v[0])):
                split_plan_target_idx = int(split_op_idx) + int(inserted)
                model_ir.operators.insert(int(split_plan_target_idx), split_adapter_op)
                inserted += 1

            remove_indices = sorted(
                [
                    int(op_idx)
                    for op_idx, op in enumerate(model_ir.operators)
                    if int(id(op)) in remove_op_ids
                ],
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    if optimized > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_split_mixed_pre_concat_to_single_post_adapter_nhwc_chains": int(optimized)}


def _optimize_transpose_slice_logistic_concat_reshape_tail_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Collapse repeated NCHW adapters in detection heads into a single 3D post-CONCAT transpose.

    Target (per branch):
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --SLICE--> a_nchw --(optional LOGISTIC)--> a'_nchw
      x_nchw --SLICE--> b_nchw
      CONCAT(axis=1, [a'_nchw, b_nchw]) -> c_nchw
      RESHAPE([N,C,S]) -> r_nchw

    Tail:
      CONCAT(axis=2, [r0_nchw, r1_nchw, ...]) -> y_nchw

    Rewrite:
      - Per branch: keep everything in NHWC
          x_nhwc --SLICE--> a_nhwc --(optional LOGISTIC)--> a'_nhwc
          x_nhwc --SLICE--> b_nhwc
          CONCAT(axis=3) -> c_nhwc
          RESHAPE([N,S,C]) -> r_nhwc
      - Tail:
          CONCAT(axis=1, [r0_nhwc, r1_nhwc, ...]) -> y_nhwc
          y_nhwc --TRANSPOSE(0,2,1)--> y_nchw
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_3d_nchw_to_nhwc = [0, 2, 1]
    unary_ops = {"LOGISTIC"}

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _op_index(op_ref: OperatorIR) -> Optional[int]:
        for idx, op in enumerate(model_ir.operators):
            if int(id(op)) == int(id(op_ref)):
                return int(idx)
        return None

    def _find_or_create_perm_3d_nhwc_to_nchw() -> str:
        target = np.asarray(perm_3d_nchw_to_nhwc, dtype=np.int32)
        for tensor_name, tensor in model_ir.tensors.items():
            if tensor is None or tensor.data is None:
                continue
            data = np.asarray(tensor.data)
            if data.dtype != np.int32 or int(data.size) != 3:
                continue
            if np.array_equal(data.reshape(-1), target):
                return str(tensor_name)
        perm_name = _unique_tensor_name("transpose_tail_3d_nhwc_to_nchw_perm")
        model_ir.tensors[perm_name] = TensorIR(
            name=perm_name,
            dtype="INT32",
            shape=[3],
            shape_signature=[3],
            data=np.asarray(target, dtype=np.int32),
            is_variable=False,
        )
        return perm_name

    def _swap_reshape_shape_tensor(
        *,
        reshape_op: OperatorIR,
        reshape_idx: int,
        consumers: Dict[str, List[int]],
    ) -> bool:
        if len(reshape_op.inputs) < 2:
            return False
        shape_name = str(reshape_op.inputs[1])
        shape_tensor = model_ir.tensors.get(shape_name, None)
        shape_vals = _read_const_ints_from_tensor(shape_tensor)
        if shape_vals is None or len(shape_vals) != 3:
            return False
        swapped = [int(shape_vals[0]), int(shape_vals[2]), int(shape_vals[1])]
        shape_consumers = [int(v) for v in consumers.get(shape_name, [])]
        if any(int(v) != int(reshape_idx) for v in shape_consumers):
            if shape_tensor is None:
                return False
            cloned_name = _unique_tensor_name(f"{shape_name}_nhwc")
            data_dtype = np.int32
            if shape_tensor.data is not None:
                try:
                    data_dtype = np.asarray(shape_tensor.data).dtype
                except Exception:
                    data_dtype = np.int32
            swapped_arr = np.asarray(swapped, dtype=data_dtype)
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(shape_tensor.dtype),
                shape=[int(v) for v in list(swapped_arr.shape)],
                shape_signature=[int(v) for v in list(swapped_arr.shape)],
                data=np.asarray(swapped_arr),
                is_variable=False,
                quantization=_clone_quantization(shape_tensor.quantization),
            )
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[1] = str(cloned_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
            return True
        _write_const_ints_to_tensor(shape_tensor, swapped)
        return True

    def _swap_reshape_option_shape(reshape_op: OperatorIR) -> None:
        if not isinstance(reshape_op.options, dict):
            return
        opts = dict(reshape_op.options)
        changed = False
        for key in ["newShape", "onnxRawNewShape"]:
            value = opts.get(key, None)
            if not isinstance(value, list) or len(value) != 3:
                continue
            swapped = [int(value[0]), int(value[2]), int(value[1])]
            if swapped != [int(v) for v in value]:
                opts[key] = swapped
                changed = True
        if changed:
            reshape_op.options = opts

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for tail_concat_idx, tail_concat_op in enumerate(model_ir.operators):
            if str(tail_concat_op.op_type) != "CONCATENATION" or len(tail_concat_op.outputs) != 1:
                continue
            tail_axis = int(tail_concat_op.options.get("axis", 2))
            if tail_axis < 0:
                tail_axis += 3
            if tail_axis != 2:
                continue

            tail_out_name = str(tail_concat_op.outputs[0])
            tail_out_tensor = model_ir.tensors.get(tail_out_name, None)
            if tail_out_tensor is None or len(list(tail_out_tensor.shape)) != 3:
                continue

            tail_inputs = [str(v) for v in list(tail_concat_op.inputs)]
            if len(tail_inputs) < 2:
                continue

            branch_plans: List[Dict[str, Any]] = []
            removable_pre_transpose_ids: set[int] = set()
            rewritable = True

            for reshape_out_name in tail_inputs:
                reshape_idx = producers.get(str(reshape_out_name), None)
                if reshape_idx is None:
                    rewritable = False
                    break
                reshape_op = model_ir.operators[int(reshape_idx)]
                if (
                    str(reshape_op.op_type) != "RESHAPE"
                    or len(reshape_op.inputs) < 2
                    or len(reshape_op.outputs) != 1
                    or str(reshape_op.outputs[0]) != str(reshape_out_name)
                ):
                    rewritable = False
                    break
                if set(int(v) for v in consumers.get(str(reshape_out_name), [])) != {int(tail_concat_idx)}:
                    rewritable = False
                    break

                branch_concat_out_name = str(reshape_op.inputs[0])
                branch_concat_idx = producers.get(branch_concat_out_name, None)
                if branch_concat_idx is None:
                    rewritable = False
                    break
                branch_concat_op = model_ir.operators[int(branch_concat_idx)]
                if str(branch_concat_op.op_type) != "CONCATENATION" or len(branch_concat_op.outputs) != 1:
                    rewritable = False
                    break
                branch_axis = int(branch_concat_op.options.get("axis", 1))
                if branch_axis < 0:
                    branch_axis += 4
                if branch_axis != 1:
                    rewritable = False
                    break
                if set(int(v) for v in consumers.get(branch_concat_out_name, [])) != {int(reshape_idx)}:
                    rewritable = False
                    break

                branch_concat_inputs = [str(v) for v in list(branch_concat_op.inputs)]
                if len(branch_concat_inputs) != 2:
                    rewritable = False
                    break

                pre_transpose_idx: Optional[int] = None
                unary_indices: List[int] = []
                slice_plans: List[Dict[str, Any]] = []
                expected_pre_users: set[int] = set()

                for branch_input_name in branch_concat_inputs:
                    slice_out_name = str(branch_input_name)
                    unary_idx: Optional[int] = None

                    maybe_unary_idx = producers.get(slice_out_name, None)
                    if maybe_unary_idx is not None:
                        maybe_unary_op = model_ir.operators[int(maybe_unary_idx)]
                        if (
                            str(maybe_unary_op.op_type) in unary_ops
                            and len(maybe_unary_op.inputs) == 1
                            and len(maybe_unary_op.outputs) == 1
                            and str(maybe_unary_op.outputs[0]) == slice_out_name
                            and set(int(v) for v in consumers.get(slice_out_name, [])) == {int(branch_concat_idx)}
                            and slice_out_name not in model_outputs
                        ):
                            unary_idx = int(maybe_unary_idx)
                            unary_indices.append(int(maybe_unary_idx))
                            slice_out_name = str(maybe_unary_op.inputs[0])

                    slice_idx = producers.get(slice_out_name, None)
                    if slice_idx is None:
                        rewritable = False
                        break
                    slice_op = model_ir.operators[int(slice_idx)]
                    if (
                        str(slice_op.op_type) != "SLICE"
                        or len(slice_op.inputs) < 3
                        or len(slice_op.outputs) != 1
                        or str(slice_op.outputs[0]) != slice_out_name
                    ):
                        rewritable = False
                        break
                    expected_slice_users = {int(unary_idx)} if unary_idx is not None else {int(branch_concat_idx)}
                    if set(int(v) for v in consumers.get(slice_out_name, [])) != expected_slice_users:
                        rewritable = False
                        break

                    begin_name = str(slice_op.inputs[1])
                    size_name = str(slice_op.inputs[2])
                    begin_vals = _read_const_ints_from_tensor(model_ir.tensors.get(begin_name, None))
                    size_vals = _read_const_ints_from_tensor(model_ir.tensors.get(size_name, None))
                    if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
                        rewritable = False
                        break
                    if int(begin_vals[0]) != 0 or int(begin_vals[2]) != 0 or int(begin_vals[3]) != 0:
                        rewritable = False
                        break
                    if int(begin_vals[1]) < 0 or int(size_vals[1]) <= 0:
                        rewritable = False
                        break

                    pre_idx = producers.get(str(slice_op.inputs[0]), None)
                    if pre_idx is None:
                        rewritable = False
                        break
                    pre_op = model_ir.operators[int(pre_idx)]
                    if (
                        str(pre_op.op_type) != "TRANSPOSE"
                        or len(pre_op.inputs) < 2
                        or len(pre_op.outputs) != 1
                        or str(pre_op.outputs[0]) != str(slice_op.inputs[0])
                        or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                        or str(pre_op.outputs[0]) in model_outputs
                    ):
                        rewritable = False
                        break
                    if pre_transpose_idx is None:
                        pre_transpose_idx = int(pre_idx)
                    elif int(pre_transpose_idx) != int(pre_idx):
                        rewritable = False
                        break

                    expected_pre_users.add(int(slice_idx))
                    slice_plans.append(
                        {
                            "slice_idx": int(slice_idx),
                            "slice_out_name": str(slice_out_name),
                            "begin_name": str(begin_name),
                            "size_name": str(size_name),
                        }
                    )

                if not rewritable or pre_transpose_idx is None:
                    rewritable = False
                    break

                pre_op = model_ir.operators[int(pre_transpose_idx)]
                pre_out_name = str(pre_op.outputs[0])
                if set(int(v) for v in consumers.get(pre_out_name, [])) != set(expected_pre_users):
                    rewritable = False
                    break

                pre_input_name = str(pre_op.inputs[0])
                pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
                pre_out_tensor = model_ir.tensors.get(pre_out_name, None)
                if (
                    pre_input_tensor is None
                    or pre_out_tensor is None
                    or len(list(pre_input_tensor.shape)) != 4
                    or len(list(pre_out_tensor.shape)) != 4
                ):
                    rewritable = False
                    break

                branch_plans.append(
                    {
                        "reshape_idx": int(reshape_idx),
                        "reshape_out_name": str(reshape_out_name),
                        "branch_concat_idx": int(branch_concat_idx),
                        "branch_concat_out_name": str(branch_concat_out_name),
                        "pre_transpose_idx": int(pre_transpose_idx),
                        "pre_input_name": str(pre_input_name),
                        "unary_indices": [int(v) for v in unary_indices],
                        "slice_plans": list(slice_plans),
                    }
                )
                removable_pre_transpose_ids.add(int(id(pre_op)))

            if not rewritable or len(branch_plans) < 2:
                continue

            # Keep this rewrite strict: all branch reshapes must share the same channel dimension.
            channel_dim: Optional[int] = None
            for plan in branch_plans:
                reshape_tensor = model_ir.tensors.get(str(plan["reshape_out_name"]), None)
                if reshape_tensor is None or len(list(reshape_tensor.shape)) != 3:
                    rewritable = False
                    break
                cdim = int(reshape_tensor.shape[1]) if len(list(reshape_tensor.shape)) > 1 else -1
                if cdim <= 0:
                    rewritable = False
                    break
                if channel_dim is None:
                    channel_dim = int(cdim)
                elif int(channel_dim) != int(cdim):
                    rewritable = False
                    break
            if not rewritable:
                continue

            apply_ok = True
            for plan in branch_plans:
                pre_input_name = str(plan["pre_input_name"])

                for slice_plan in list(plan["slice_plans"]):
                    slice_idx = int(slice_plan["slice_idx"])
                    begin_name = str(slice_plan["begin_name"])
                    size_name = str(slice_plan["size_name"])
                    if set(int(v) for v in consumers.get(begin_name, [])) != {int(slice_idx)}:
                        apply_ok = False
                        break
                    if set(int(v) for v in consumers.get(size_name, [])) != {int(slice_idx)}:
                        apply_ok = False
                        break

                    slice_op = model_ir.operators[int(slice_idx)]
                    begin_tensor = model_ir.tensors.get(begin_name, None)
                    size_tensor = model_ir.tensors.get(size_name, None)
                    begin_vals = _read_const_ints_from_tensor(begin_tensor)
                    size_vals = _read_const_ints_from_tensor(size_tensor)
                    if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
                        apply_ok = False
                        break

                    new_begin = [int(begin_vals[0]), int(begin_vals[2]), int(begin_vals[3]), int(begin_vals[1])]
                    new_size = [int(size_vals[0]), int(size_vals[2]), int(size_vals[3]), int(size_vals[1])]
                    _write_const_ints_to_tensor(begin_tensor, new_begin)
                    _write_const_ints_to_tensor(size_tensor, new_size)
                    _replace_operator_input_at(
                        model_ir=model_ir,
                        op=slice_op,
                        input_index=0,
                        new_input_name=pre_input_name,
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(slice_plan["slice_out_name"]), None),
                        perm_nchw_to_nhwc,
                    )

                if not apply_ok:
                    break

                for unary_idx in list(plan["unary_indices"]):
                    unary_out_name = str(model_ir.operators[int(unary_idx)].outputs[0])
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(unary_out_name, None),
                        perm_nchw_to_nhwc,
                    )

                branch_concat_op = model_ir.operators[int(plan["branch_concat_idx"])]
                branch_concat_op.options["axis"] = 3
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(plan["branch_concat_out_name"]), None),
                    perm_nchw_to_nhwc,
                )

                reshape_op = model_ir.operators[int(plan["reshape_idx"])]
                if not _swap_reshape_shape_tensor(
                    reshape_op=reshape_op,
                    reshape_idx=int(plan["reshape_idx"]),
                    consumers=consumers,
                ):
                    apply_ok = False
                    break
                _swap_reshape_option_shape(reshape_op)
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(plan["reshape_out_name"]), None),
                    perm_3d_nchw_to_nhwc,
                )

            if not apply_ok:
                continue

            tail_shape = [int(v) for v in list(tail_out_tensor.shape)]
            tail_signature = (
                [int(v) for v in list(tail_out_tensor.shape_signature)]
                if tail_out_tensor.shape_signature is not None
                else [int(v) for v in list(tail_out_tensor.shape)]
            )
            tail_nhwc_shape = _permute_shape(tail_shape, perm_3d_nchw_to_nhwc)
            tail_nhwc_signature = _permute_shape(tail_signature, perm_3d_nchw_to_nhwc)
            if tail_nhwc_shape is None or tail_nhwc_signature is None:
                continue

            tail_concat_nhwc_name = _unique_tensor_name(f"{tail_out_name}_nhwc")
            model_ir.tensors[tail_concat_nhwc_name] = TensorIR(
                name=tail_concat_nhwc_name,
                dtype=str(tail_out_tensor.dtype),
                shape=[int(v) for v in list(tail_nhwc_shape)],
                shape_signature=[int(v) for v in list(tail_nhwc_signature)],
                data=None,
                is_variable=False,
                quantization=_clone_quantization(tail_out_tensor.quantization),
            )
            tail_concat_op.options["axis"] = 1
            _set_operator_outputs(
                model_ir=model_ir,
                op=tail_concat_op,
                new_outputs=[tail_concat_nhwc_name],
            )

            perm_3d_name = _find_or_create_perm_3d_nhwc_to_nchw()
            tail_concat_current_idx = _op_index(tail_concat_op)
            if tail_concat_current_idx is None:
                continue
            model_ir.operators.insert(
                int(tail_concat_current_idx) + 1,
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[tail_concat_nhwc_name, perm_3d_name],
                    outputs=[tail_out_name],
                    options={},
                ),
            )

            remove_indices = [
                int(op_idx)
                for op_idx, op in enumerate(model_ir.operators)
                if int(id(op)) in removable_pre_transpose_ids
            ]
            for remove_idx in sorted(list(set(remove_indices)), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_slice_logistic_concat_reshape_tail_nhwc_chains": int(optimized)}


