def _repair_nchw_concat_transpose_conv_axes(model_ir: ModelIR) -> Dict[str, int]:
    """Restore axis=1 for NCHW concat feeding an NHWC Conv adapter.

    Quantized Conv lowering can place PAD/CAST/SUB after the layout transpose
    and QUANTIZE before it. Those operators preserve the relevant layout, so
    trace through them instead of requiring CONCAT->TRANSPOSE->CONV to be
    adjacent.
    """

    repaired = 0
    producers = _build_tensor_producer_map(model_ir)
    for conv_op in model_ir.operators:
        conv_type = str(conv_op.op_type)
        if (
            conv_type not in {"CONV_2D", "TRANSPOSE_CONV"}
            or len(conv_op.inputs) < (3 if conv_type == "TRANSPOSE_CONV" else 2)
            or len(conv_op.outputs) != 1
        ):
            continue
        data_input_index = 2 if conv_type == "TRANSPOSE_CONV" else 0
        filter_input_index = 1
        conv_data_name = str(conv_op.inputs[data_input_index])
        transpose_output_name = str(conv_data_name)
        post_transpose_output_names: List[str] = []
        transpose_op: Optional[OperatorIR] = None
        while True:
            transpose_idx = producers.get(transpose_output_name, None)
            if transpose_idx is None:
                break
            candidate_op = model_ir.operators[int(transpose_idx)]
            if (
                str(candidate_op.op_type) == "TRANSPOSE"
                and len(candidate_op.inputs) >= 2
                and len(candidate_op.outputs) == 1
                and _read_transpose_perm(model_ir, candidate_op)
                == [0, 2, 3, 1]
            ):
                transpose_op = candidate_op
                break
            if (
                str(candidate_op.op_type) not in {"PAD", "CAST", "SUB"}
                or len(candidate_op.inputs) < 1
                or len(candidate_op.outputs) != 1
                or str(candidate_op.outputs[0]) != transpose_output_name
            ):
                break
            post_transpose_output_names.append(transpose_output_name)
            transpose_output_name = str(candidate_op.inputs[0])
        if transpose_op is None:
            continue
        concat_output_name = str(transpose_op.inputs[0])
        shape_passthrough_output_names: List[str] = []
        concat_idx = producers.get(concat_output_name, None)
        while concat_idx is not None:
            candidate_op = model_ir.operators[int(concat_idx)]
            if (
                str(candidate_op.op_type)
                not in {"RELU", "RELU6", "QUANTIZE", "DEQUANTIZE", "CAST"}
                or len(candidate_op.inputs) != 1
                or len(candidate_op.outputs) != 1
                or str(candidate_op.outputs[0]) != concat_output_name
            ):
                break
            shape_passthrough_output_names.append(concat_output_name)
            concat_output_name = str(candidate_op.inputs[0])
            concat_idx = producers.get(concat_output_name, None)
        if concat_idx is None:
            continue
        concat_op = model_ir.operators[int(concat_idx)]
        if (
            str(concat_op.op_type) != "CONCATENATION"
            or len(concat_op.inputs) < 2
            or len(concat_op.outputs) != 1
            or int(concat_op.options.get("axis", 1)) == 1
        ):
            continue
        filter_tensor = model_ir.tensors.get(
            str(conv_op.inputs[filter_input_index]),
            None,
        )
        transpose_tensor = model_ir.tensors.get(transpose_output_name, None)
        conv_output_tensor = model_ir.tensors.get(str(conv_op.outputs[0]), None)
        input_tensors = [model_ir.tensors.get(str(name), None) for name in concat_op.inputs]
        if (
            filter_tensor is None
            or transpose_tensor is None
            or conv_output_tensor is None
            or any(tensor is None for tensor in input_tensors)
        ):
            continue
        filter_shape = [int(v) for v in list(filter_tensor.shape)]
        input_shapes = [[int(v) for v in list(tensor.shape)] for tensor in input_tensors if tensor is not None]
        if len(filter_shape) != 4 or not input_shapes or any(len(shape) != 4 for shape in input_shapes):
            continue
        reference = input_shapes[0]
        if any(
            any(int(shape[axis]) != int(reference[axis]) for axis in [0, 2, 3])
            for shape in input_shapes[1:]
        ):
            continue
        expected_channels = int(sum(int(shape[1]) for shape in input_shapes))
        if expected_channels <= 0 or expected_channels != int(filter_shape[3]):
            continue
        if int(transpose_tensor.shape[3]) == expected_channels:
            continue

        concat_op.options["axis"] = 1
        concat_shape = [int(v) for v in reference]
        concat_shape[1] = int(expected_channels)
        concat_tensor = model_ir.tensors.get(concat_output_name, None)
        if concat_tensor is not None:
            concat_tensor.shape = list(concat_shape)
            concat_tensor.shape_signature = list(concat_shape)
        for passthrough_output_name in shape_passthrough_output_names:
            passthrough_tensor = model_ir.tensors.get(
                passthrough_output_name,
                None,
            )
            if passthrough_tensor is None:
                continue
            passthrough_tensor.shape = list(concat_shape)
            passthrough_tensor.shape_signature = list(concat_shape)
        nhwc_shape = [
            int(concat_shape[0]),
            int(concat_shape[2]),
            int(concat_shape[3]),
            int(concat_shape[1]),
        ]
        transpose_tensor.shape = list(nhwc_shape)
        transpose_tensor.shape_signature = list(nhwc_shape)
        if conv_type == "CONV_2D" and len(post_transpose_output_names) == 0:
            conv_output_tensor.shape = [
                int(nhwc_shape[0]),
                int(nhwc_shape[1]),
                int(nhwc_shape[2]),
                int(filter_shape[0]),
            ]
            conv_output_tensor.shape_signature = list(conv_output_tensor.shape)
        repaired += 1
    return {"repaired_nchw_concat_transpose_conv_axes": int(repaired)}


def _repair_nchw_concat_global_pool_conv_axes(model_ir: ModelIR) -> Dict[str, int]:
    """Restore an NCHW concat channel axis before global-pool attention Conv."""

    repaired = 0
    producers = _build_tensor_producer_map(model_ir)
    for conv_op in model_ir.operators:
        if (
            str(conv_op.op_type) != "CONV_2D"
            or len(conv_op.inputs) < 2
            or len(conv_op.outputs) != 1
        ):
            continue
        reshape_output_name = str(conv_op.inputs[0])
        reshape_idx = producers.get(reshape_output_name, None)
        if reshape_idx is None:
            continue
        reshape_op = model_ir.operators[int(reshape_idx)]
        if (
            str(reshape_op.op_type) != "RESHAPE"
            or len(reshape_op.inputs) < 1
            or len(reshape_op.outputs) != 1
        ):
            continue
        pool_output_name = str(reshape_op.inputs[0])
        pool_idx = producers.get(pool_output_name, None)
        if pool_idx is None:
            continue
        pool_op = model_ir.operators[int(pool_idx)]
        if (
            str(pool_op.op_type) != "MEAN"
            or len(pool_op.inputs) < 1
            or len(pool_op.outputs) != 1
            or not bool(pool_op.options.get("keepDims", True))
        ):
            continue
        concat_output_name = str(pool_op.inputs[0])
        concat_idx = producers.get(concat_output_name, None)
        if concat_idx is None:
            continue
        concat_op = model_ir.operators[int(concat_idx)]
        if (
            str(concat_op.op_type) != "CONCATENATION"
            or len(concat_op.inputs) < 2
            or len(concat_op.outputs) != 1
            or int(concat_op.options.get("axis", 1)) == 1
        ):
            continue

        filter_tensor = model_ir.tensors.get(str(conv_op.inputs[1]), None)
        concat_tensor = model_ir.tensors.get(concat_output_name, None)
        pool_tensor = model_ir.tensors.get(pool_output_name, None)
        reshape_tensor = model_ir.tensors.get(reshape_output_name, None)
        input_tensors = [
            model_ir.tensors.get(str(name), None) for name in concat_op.inputs
        ]
        if (
            filter_tensor is None
            or concat_tensor is None
            or pool_tensor is None
            or reshape_tensor is None
            or any(tensor is None for tensor in input_tensors)
        ):
            continue
        filter_shape = [int(v) for v in list(filter_tensor.shape)]
        input_shapes = [
            [int(v) for v in list(tensor.shape)]
            for tensor in input_tensors
            if tensor is not None
        ]
        if (
            len(filter_shape) != 4
            or not input_shapes
            or any(len(shape) != 4 for shape in input_shapes)
        ):
            continue
        reference = input_shapes[0]
        if any(
            any(
                int(shape[axis]) != int(reference[axis])
                for axis in (0, 2, 3)
            )
            for shape in input_shapes[1:]
        ):
            continue
        expected_channels = int(sum(int(shape[1]) for shape in input_shapes))
        if (
            expected_channels <= 0
            or int(filter_shape[3]) != expected_channels
            or [int(v) for v in list(reshape_tensor.shape)]
            == [int(reference[0]), 1, 1, expected_channels]
        ):
            continue

        concat_op.options["axis"] = 1
        concat_shape = [int(v) for v in reference]
        concat_shape[1] = expected_channels
        concat_tensor.shape = list(concat_shape)
        concat_tensor.shape_signature = list(concat_shape)
        pool_shape = [int(reference[0]), expected_channels, 1, 1]
        pool_tensor.shape = list(pool_shape)
        pool_tensor.shape_signature = list(pool_shape)
        reshape_shape = [int(reference[0]), 1, 1, expected_channels]
        reshape_tensor.shape = list(reshape_shape)
        reshape_tensor.shape_signature = list(reshape_shape)
        if len(reshape_op.inputs) >= 2:
            reshape_shape_tensor = model_ir.tensors.get(
                str(reshape_op.inputs[1]),
                None,
            )
            if (
                reshape_shape_tensor is not None
                and reshape_shape_tensor.data is not None
                and int(np.asarray(reshape_shape_tensor.data).size) == 4
            ):
                reshape_shape_tensor.data = np.asarray(
                    reshape_shape,
                    dtype=np.asarray(reshape_shape_tensor.data).dtype,
                )
                reshape_op.options["newShape"] = list(reshape_shape)
        repaired += 1

    return {"repaired_nchw_concat_global_pool_conv_axes": int(repaired)}


def _optimize_transpose_gather_transpose_axis_remap_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    return _optimize_transpose_gather_transpose_axis_remap_nhwc_chains_pass(model_ir)


def _optimize_transpose_pre_add_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Convert NCHW Add blocks back to NHWC when wrapped by transpose adapters.

    Target:
      a_nhwc -> (optional swish-wrapped NCHW adapters) -> a_nchw
      b_nhwc -> (optional swish-wrapped NCHW adapters) -> b_nchw
      ADD(a_nchw, b_nchw) -> y_nchw
      (optional unary RELU/RELU6/LOGISTIC/TANH) -> y2_nchw
      y_or_y2_nchw -> TRANSPOSE(0,2,3,1) -> y_nhwc

    Rewrite:
      ADD(a_nhwc, b_nhwc) -> y_nhwc
      (if unary exists, keep unary and bridge its output instead of ADD output directly)

    Notes:
    - If y_nchw has legacy consumers, keep one adapter TRANSPOSE(0,3,1,2): y_nhwc -> y_nchw.
    - Swish-wrapped NCHW inputs are recognized as:
        pre_nhwc --T(0,3,1,2)--> x_nchw --LOGISTIC--> s --MUL(x_nchw,s)--> x_swish_nchw
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_passthrough_ops = {"RELU", "RELU6", "LOGISTIC", "TANH", "GELU", "HARD_SWISH", "LEAKY_RELU"}
    skip_add_activation_fuse_marker = "__skip_add_activation_fuse__"
    optimized_add_marker = "__transpose_pre_add_nhwc_optimized__"

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_prelu_alpha_to_nhwc(
        *,
        prelu_idx: int,
        prelu_op: OperatorIR,
        target_nhwc_shape: Optional[List[int]],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        alpha_name = str(prelu_op.inputs[1]) if len(prelu_op.inputs) >= 2 else ""
        alpha_tensor = model_ir.tensors.get(alpha_name, None)
        if alpha_tensor is None or alpha_tensor.data is None:
            return None

        alpha_data = np.asarray(alpha_tensor.data)
        alpha_candidates: List[np.ndarray] = []
        if int(alpha_data.ndim) == int(len(perm_nchw_to_nhwc)):
            # Prefer layout-remapped alpha first when both can broadcast.
            alpha_candidates.append(
                np.transpose(alpha_data, axes=perm_nchw_to_nhwc).astype(alpha_data.dtype, copy=False)
            )
        alpha_candidates.append(np.asarray(alpha_data))
        if int(alpha_data.ndim) == 3:
            alpha_candidates.append(
                np.transpose(alpha_data, axes=[1, 2, 0]).astype(alpha_data.dtype, copy=False)
            )

        def _broadcastable_to_target(candidate: np.ndarray) -> bool:
            if target_nhwc_shape is None or not _is_fully_known_positive_shape(target_nhwc_shape):
                return True
            return (
                _broadcast_static_shapes(
                    [int(v) for v in list(target_nhwc_shape)],
                    [int(v) for v in list(candidate.shape)],
                )
                is not None
            )

        selected_alpha: Optional[np.ndarray] = None
        for candidate in alpha_candidates:
            if _broadcastable_to_target(candidate):
                selected_alpha = np.asarray(candidate)
                break
        if selected_alpha is None:
            return None

        selected_alpha_name = str(alpha_name)
        alpha_users = [int(v) for v in consumers.get(alpha_name, [])]
        alpha_needs_rewrite = (
            selected_alpha.shape != alpha_data.shape
            or not np.array_equal(selected_alpha, alpha_data)
        )
        if alpha_needs_rewrite:
            shape, signature = normalize_onnx_shape(list(selected_alpha.shape))
            if len(alpha_users) == 1 and int(alpha_users[0]) == int(prelu_idx):
                alpha_tensor.data = np.asarray(selected_alpha)
                alpha_tensor.shape = [int(v) for v in list(shape)]
                alpha_tensor.shape_signature = [int(v) for v in list(signature)]
            else:
                selected_alpha_name = _unique_tensor_name(f"{alpha_name}_nhwc")
                model_ir.tensors[selected_alpha_name] = TensorIR(
                    name=selected_alpha_name,
                    dtype=str(alpha_tensor.dtype),
                    shape=[int(v) for v in list(shape)],
                    shape_signature=[int(v) for v in list(signature)],
                    data=np.asarray(selected_alpha),
                    is_variable=False,
                    quantization=_clone_quantization(alpha_tensor.quantization),
                )
        return str(selected_alpha_name)

    def _analyze_swish_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        in0_name = str(mul_op.inputs[0])
        in1_name = str(mul_op.inputs[1])
        in0_prod_idx = producers.get(in0_name, None)
        in1_prod_idx = producers.get(in1_name, None)

        log_idx: Optional[int] = None
        log_out_name: Optional[str] = None
        pre_nchw_name: Optional[str] = None
        mul_data_input_index: Optional[int] = None

        if in0_prod_idx is not None:
            in0_prod_op = model_ir.operators[int(in0_prod_idx)]
            if (
                str(in0_prod_op.op_type) == "LOGISTIC"
                and len(in0_prod_op.inputs) == 1
                and len(in0_prod_op.outputs) == 1
                and str(in0_prod_op.outputs[0]) == in0_name
            ):
                log_idx = int(in0_prod_idx)
                log_out_name = in0_name
                pre_nchw_name = str(in0_prod_op.inputs[0])
                mul_data_input_index = 1

        if log_idx is None and in1_prod_idx is not None:
            in1_prod_op = model_ir.operators[int(in1_prod_idx)]
            if (
                str(in1_prod_op.op_type) == "LOGISTIC"
                and len(in1_prod_op.inputs) == 1
                and len(in1_prod_op.outputs) == 1
                and str(in1_prod_op.outputs[0]) == in1_name
            ):
                log_idx = int(in1_prod_idx)
                log_out_name = in1_name
                pre_nchw_name = str(in1_prod_op.inputs[0])
                mul_data_input_index = 0

        if log_idx is None or log_out_name is None or pre_nchw_name is None or mul_data_input_index is None:
            return None
        if str(mul_op.inputs[int(mul_data_input_index)]) != str(pre_nchw_name):
            return None

        pre_idx = producers.get(str(pre_nchw_name), None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != str(pre_nchw_name):
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None

        if set(int(v) for v in consumers.get(str(pre_nchw_name), [])) != {int(log_idx), int(mul_idx)}:
            return None
        if set(int(v) for v in consumers.get(str(log_out_name), [])) != {int(mul_idx)}:
            return None

        return {
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "log_idx": int(log_idx),
            "mul_idx": int(mul_idx),
            "mul_data_input_index": int(mul_data_input_index),
            "log_out_name": str(log_out_name),
            "mul_out_name": str(input_name),
        }

    def _apply_swish_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        log_idx = int(plan["log_idx"])
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        log_out_name = str(plan["log_out_name"])
        mul_out_name = str(plan["mul_out_name"])

        mul_op = model_ir.operators[int(mul_idx)]
        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(log_idx)],
            new_inputs=[pre_input_name],
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=mul_op,
            input_index=int(mul_data_input_index),
            new_input_name=pre_input_name,
        )

        for tensor_name in [log_out_name, mul_out_name]:
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(tensor_name, None),
                perm_nchw_to_nhwc,
            )
        return [int(pre_idx)]

    def _analyze_unary_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        unary_idx = producers.get(str(input_name), None)
        if unary_idx is None:
            return None
        unary_op = model_ir.operators[int(unary_idx)]
        if str(unary_op.op_type) not in unary_passthrough_ops:
            return None
        if len(unary_op.inputs) != 1 or len(unary_op.outputs) != 1:
            return None
        if str(unary_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        pre_nchw_name = str(unary_op.inputs[0])
        pre_idx = producers.get(pre_nchw_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
            return None
        if str(pre_op.outputs[0]) != pre_nchw_name:
            return None
        if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
            return None
        if str(pre_nchw_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(pre_nchw_name), [])) != {int(unary_idx)}:
            return None

        return {
            "input_name": str(input_name),
            "unary_idx": int(unary_idx),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
        }

    def _apply_unary_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        input_name = str(plan["input_name"])
        unary_idx = int(plan["unary_idx"])
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])

        _set_operator_inputs(
            model_ir=model_ir,
            op=model_ir.operators[int(unary_idx)],
            new_inputs=[pre_input_name],
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(input_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)]

    def _analyze_mul_const_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        data_input_index: Optional[int] = None
        side_input_index: Optional[int] = None
        side_input_name: Optional[str] = None
        pre_idx: Optional[int] = None
        pre_input_name: Optional[str] = None
        pre_output_name: Optional[str] = None

        for candidate_data_index, candidate_side_index in [(0, 1), (1, 0)]:
            data_name = str(mul_op.inputs[int(candidate_data_index)])
            side_name = str(mul_op.inputs[int(candidate_side_index)])
            side_tensor = model_ir.tensors.get(side_name, None)
            if side_tensor is None or side_tensor.data is None:
                continue

            data_prod_idx = producers.get(data_name, None)
            if data_prod_idx is None:
                continue
            data_prod_op = model_ir.operators[int(data_prod_idx)]
            if (
                str(data_prod_op.op_type) != "TRANSPOSE"
                or len(data_prod_op.inputs) < 2
                or len(data_prod_op.outputs) != 1
                or str(data_prod_op.outputs[0]) != data_name
                or _read_transpose_perm(model_ir, data_prod_op) != perm_nhwc_to_nchw
                or str(data_name) in model_outputs
            ):
                continue
            data_users = set(int(v) for v in consumers.get(data_name, []))
            if int(mul_idx) not in data_users:
                continue

            data_tensor = model_ir.tensors.get(data_name, None)
            pre_in_name = str(data_prod_op.inputs[0])
            pre_in_tensor = model_ir.tensors.get(pre_in_name, None)
            if data_tensor is None or pre_in_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(list(data_tensor.shape))
                or not _is_fully_known_positive_shape(list(pre_in_tensor.shape))
                or len(list(data_tensor.shape)) != 4
                or len(list(pre_in_tensor.shape)) != 4
            ):
                continue

            side_data = np.asarray(side_tensor.data)
            if int(side_data.size) != 1 and side_data.ndim not in {3, 4}:
                continue
            if int(side_data.size) != 1:
                if _broadcast_static_shapes(list(data_tensor.shape), [int(v) for v in list(side_data.shape)]) is None:
                    continue

            data_input_index = int(candidate_data_index)
            side_input_index = int(candidate_side_index)
            side_input_name = str(side_name)
            pre_idx = int(data_prod_idx)
            pre_input_name = pre_in_name
            pre_output_name = data_name
            break

        if (
            data_input_index is None
            or side_input_index is None
            or side_input_name is None
            or pre_idx is None
            or pre_input_name is None
            or pre_output_name is None
        ):
            return None

        side_tensor = model_ir.tensors.get(side_input_name, None)
        if side_tensor is None or side_tensor.data is None:
            return None
        side_data = np.asarray(side_tensor.data)
        nhwc_side_data: Optional[np.ndarray] = None
        side_needs_update = False
        if int(side_data.size) != 1:
            target_nhwc_shape = [int(v) for v in list(model_ir.tensors[str(pre_input_name)].shape)]
            side_shape = [int(v) for v in list(side_data.shape)]
            # Prefer semantic channel remap for NCHW channel-wise constants even
            # when static shapes are broadcast-ambiguous (e.g. [1,64,64,64]).
            is_nchw_channelwise = (
                int(side_data.ndim) == 4
                and len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 0
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            )
            if is_nchw_channelwise:
                rotated = np.transpose(side_data, axes=perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_nhwc_shape, rotated_shape) is None:
                    return None
                nhwc_side_data = np.asarray(rotated)
                side_needs_update = not np.array_equal(nhwc_side_data, side_data)
            elif _broadcast_static_shapes(target_nhwc_shape, side_shape) is not None:
                nhwc_side_data = np.asarray(side_data)
                side_needs_update = False
            else:
                rotated = np.asarray(side_data)
                found = False
                transpose_perm = (
                    perm_nchw_to_nhwc
                    if int(rotated.ndim) == 4
                    else [1, 2, 0]
                )
                max_rotate = 3 if int(rotated.ndim) == 3 else 1
                for _ in range(int(max_rotate)):
                    rotated = np.transpose(rotated, transpose_perm).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_nhwc_shape, rotated_shape) is not None:
                        nhwc_side_data = np.asarray(rotated)
                        side_needs_update = True
                        found = True
                        break
                if not found:
                    return None

        shared_outside_mul = any(
            int(v) != int(mul_idx)
            for v in consumers.get(str(side_input_name), [])
        )

        return {
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_input_name),
            "mul_idx": int(mul_idx),
            "mul_data_input_index": int(data_input_index),
            "mul_side_input_index": int(side_input_index),
            "mul_side_input_name": str(side_input_name),
            "mul_out_name": str(input_name),
            "pre_removable": bool(
                set(int(v) for v in consumers.get(str(pre_output_name), [])) == {int(mul_idx)}
            ),
            "side_needs_update": bool(side_needs_update),
            "side_shared_outside_mul": bool(shared_outside_mul),
            "side_nhwc_data": (None if nhwc_side_data is None else np.asarray(nhwc_side_data)),
        }

    def _apply_mul_const_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        pre_idx = int(plan["pre_idx"])
        pre_input_name = str(plan["pre_input_name"])
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        mul_side_input_index = int(plan["mul_side_input_index"])
        mul_side_input_name = str(plan["mul_side_input_name"])
        mul_out_name = str(plan["mul_out_name"])

        side_input_name_for_mul = str(mul_side_input_name)
        if bool(plan.get("side_needs_update", False)):
            nhwc_data = np.asarray(plan.get("side_nhwc_data"))
            side_tensor = model_ir.tensors.get(str(mul_side_input_name), None)
            if side_tensor is None:
                return []
            if bool(plan.get("side_shared_outside_mul", False)):
                side_input_name_for_mul = _unique_tensor_name(f"{mul_side_input_name}_nhwc")
                model_ir.tensors[side_input_name_for_mul] = TensorIR(
                    name=side_input_name_for_mul,
                    dtype=str(side_tensor.dtype),
                    shape=[int(v) for v in list(nhwc_data.shape)],
                    shape_signature=[int(v) for v in list(nhwc_data.shape)],
                    data=np.asarray(nhwc_data),
                    is_variable=False,
                    quantization=_clone_quantization(side_tensor.quantization),
                )
            else:
                side_tensor.data = np.asarray(nhwc_data)
                side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
                side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        mul_op = model_ir.operators[int(mul_idx)]
        mul_inputs = [str(v) for v in list(mul_op.inputs)]
        if int(mul_data_input_index) < 0 or int(mul_data_input_index) >= len(mul_inputs):
            return []
        if int(mul_side_input_index) < 0 or int(mul_side_input_index) >= len(mul_inputs):
            return []
        mul_inputs[int(mul_data_input_index)] = str(pre_input_name)
        mul_inputs[int(mul_side_input_index)] = str(side_input_name_for_mul)
        _set_operator_inputs(
            model_ir=model_ir,
            op=mul_op,
            new_inputs=mul_inputs,
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(mul_out_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(pre_idx)] if bool(plan.get("pre_removable", False)) else []

    def _analyze_gather_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        gather_idx = producers.get(str(input_name), None)
        if gather_idx is None:
            return None
        gather_op = model_ir.operators[int(gather_idx)]
        if str(gather_op.op_type) != "GATHER" or len(gather_op.inputs) < 2 or len(gather_op.outputs) != 1:
            return None
        if str(gather_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        gather_options = dict(gather_op.options) if isinstance(gather_op.options, dict) else {}
        if int(gather_options.get("batchDims", 0)) != 0:
            return None

        gather_data_name = str(gather_op.inputs[0])
        pre_idx = producers.get(gather_data_name, None)
        if pre_idx is None:
            return None
        pre_op = model_ir.operators[int(pre_idx)]
        if (
            str(pre_op.op_type) != "TRANSPOSE"
            or len(pre_op.inputs) < 2
            or len(pre_op.outputs) != 1
            or str(pre_op.outputs[0]) != gather_data_name
            or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            or str(gather_data_name) in model_outputs
        ):
            return None

        gather_data_tensor = model_ir.tensors.get(gather_data_name, None)
        if gather_data_tensor is None or len(list(gather_data_tensor.shape)) != 4:
            return None
        axis = int(gather_options.get("axis", 0))
        if axis < 0:
            axis += 4
        if axis < 0 or axis >= 4:
            return None
        remapped_axis = int(perm_nhwc_to_nchw[axis])

        pre_users = set(int(v) for v in consumers.get(gather_data_name, []))
        return {
            "gather_idx": int(gather_idx),
            "gather_in_name": str(gather_data_name),
            "gather_out_name": str(input_name),
            "pre_idx": int(pre_idx),
            "pre_input_name": str(pre_op.inputs[0]),
            "remapped_axis": int(remapped_axis),
            "pre_removable": bool(pre_users == {int(gather_idx)}),
        }

    def _apply_gather_input_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        gather_idx = int(plan["gather_idx"])
        gather_op = model_ir.operators[int(gather_idx)]
        gather_inputs = [str(v) for v in list(gather_op.inputs)]
        if len(gather_inputs) < 2:
            return []
        gather_inputs[0] = str(plan["pre_input_name"])
        _set_operator_inputs(
            model_ir=model_ir,
            op=gather_op,
            new_inputs=gather_inputs,
        )
        gather_options = dict(gather_op.options) if isinstance(gather_op.options, dict) else {}
        gather_options["axis"] = int(plan["remapped_axis"])
        gather_options["batchDims"] = 0
        gather_op.options = gather_options
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(str(plan["gather_out_name"]), None),
            perm_nchw_to_nhwc,
        )
        return [int(plan["pre_idx"])] if bool(plan.get("pre_removable", False)) else []

    def _analyze_mul_sub_const_input_to_nhwc(
        *,
        input_name: str,
        consumer_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        if set(int(v) for v in consumers.get(str(input_name), [])) != {int(consumer_idx)}:
            return None

        mul_data_input_index: Optional[int] = None
        mul_side_input_index: Optional[int] = None
        mul_side_input_name: Optional[str] = None
        sub_idx: Optional[int] = None
        sub_out_name: Optional[str] = None
        sub_input_rewrites: List[Dict[str, Any]] = []
        removable_pre_indices: List[int] = []
        target_nhwc_shape: Optional[List[int]] = None

        for candidate_data_index, candidate_side_index in [(0, 1), (1, 0)]:
            data_name = str(mul_op.inputs[int(candidate_data_index)])
            side_name = str(mul_op.inputs[int(candidate_side_index)])
            side_tensor = model_ir.tensors.get(side_name, None)
            if side_tensor is None or side_tensor.data is None:
                continue

            candidate_sub_idx = producers.get(data_name, None)
            if candidate_sub_idx is None:
                continue
            candidate_sub_op = model_ir.operators[int(candidate_sub_idx)]
            if (
                str(candidate_sub_op.op_type) != "SUB"
                or len(candidate_sub_op.inputs) != 2
                or len(candidate_sub_op.outputs) != 1
                or str(candidate_sub_op.outputs[0]) != data_name
                or str(data_name) in model_outputs
            ):
                continue
            if set(int(v) for v in consumers.get(data_name, [])) != {int(mul_idx)}:
                continue

            candidate_rewrites: List[Dict[str, Any]] = []
            candidate_removable: List[int] = []
            candidate_target_shape: Optional[List[int]] = None
            valid_sub_inputs = True
            for sub_input_index, sub_input_name in enumerate([str(v) for v in list(candidate_sub_op.inputs)]):
                sub_pre_idx = producers.get(str(sub_input_name), None)
                if sub_pre_idx is None:
                    valid_sub_inputs = False
                    break
                sub_pre_op = model_ir.operators[int(sub_pre_idx)]
                if (
                    str(sub_pre_op.op_type) != "TRANSPOSE"
                    or len(sub_pre_op.inputs) < 2
                    or len(sub_pre_op.outputs) != 1
                    or str(sub_pre_op.outputs[0]) != str(sub_input_name)
                    or _read_transpose_perm(model_ir, sub_pre_op) != perm_nhwc_to_nchw
                    or str(sub_input_name) in model_outputs
                ):
                    valid_sub_inputs = False
                    break
                sub_input_users = set(int(v) for v in consumers.get(str(sub_input_name), []))
                if not sub_input_users.issubset({int(candidate_sub_idx), int(consumer_idx)}):
                    valid_sub_inputs = False
                    break
                nhwc_name = str(sub_pre_op.inputs[0])
                candidate_rewrites.append(
                    {
                        "sub_input_index": int(sub_input_index),
                        "nhwc_name": nhwc_name,
                        "pre_idx": int(sub_pre_idx),
                    }
                )
                candidate_removable.append(int(sub_pre_idx))
                nhwc_tensor = model_ir.tensors.get(nhwc_name, None)
                if (
                    candidate_target_shape is None
                    and nhwc_tensor is not None
                    and _is_fully_known_positive_shape(list(nhwc_tensor.shape))
                ):
                    candidate_target_shape = [int(v) for v in list(nhwc_tensor.shape)]

            if not valid_sub_inputs or len(candidate_rewrites) != 2:
                continue

            mul_data_input_index = int(candidate_data_index)
            mul_side_input_index = int(candidate_side_index)
            mul_side_input_name = str(side_name)
            sub_idx = int(candidate_sub_idx)
            sub_out_name = str(data_name)
            sub_input_rewrites = [dict(v) for v in candidate_rewrites]
            removable_pre_indices = [int(v) for v in candidate_removable]
            target_nhwc_shape = (
                [int(v) for v in list(candidate_target_shape)]
                if candidate_target_shape is not None
                else None
            )
            break

        if (
            mul_data_input_index is None
            or mul_side_input_index is None
            or mul_side_input_name is None
            or sub_idx is None
            or sub_out_name is None
            or len(sub_input_rewrites) != 2
        ):
            return None

        side_tensor = model_ir.tensors.get(str(mul_side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return None

        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) != 1 and side_data.ndim not in {1, 3, 4}:
            return None

        nhwc_side_data: Optional[np.ndarray] = None
        side_needs_update = False
        if int(side_data.size) != 1 and side_data.ndim in {3, 4}:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                target_nhwc_shape is not None
                and _broadcast_static_shapes(target_nhwc_shape, side_shape) is not None
            ):
                nhwc_side_data = np.asarray(side_data)
            else:
                rotated = np.asarray(side_data)
                transpose_perm = perm_nchw_to_nhwc if int(rotated.ndim) == 4 else [1, 2, 0]
                max_rotate = 1 if int(rotated.ndim) == 4 else 3
                found = False
                for _ in range(int(max_rotate)):
                    rotated = np.transpose(rotated, transpose_perm).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if (
                        target_nhwc_shape is None
                        or _broadcast_static_shapes(target_nhwc_shape, rotated_shape) is not None
                    ):
                        nhwc_side_data = np.asarray(rotated)
                        side_needs_update = True
                        found = True
                        break
                if not found:
                    return None

        side_shared_outside_mul = any(
            int(v) != int(mul_idx)
            for v in consumers.get(str(mul_side_input_name), [])
        )

        return {
            "sub_idx": int(sub_idx),
            "sub_input_rewrites": [dict(v) for v in sub_input_rewrites],
            "sub_out_name": str(sub_out_name),
            "mul_idx": int(mul_idx),
            "mul_data_input_index": int(mul_data_input_index),
            "mul_side_input_index": int(mul_side_input_index),
            "mul_side_input_name": str(mul_side_input_name),
            "mul_out_name": str(input_name),
            "removable_pre_indices": sorted(list({int(v) for v in removable_pre_indices})),
            "side_needs_update": bool(side_needs_update),
            "side_shared_outside_mul": bool(side_shared_outside_mul),
            "side_nhwc_data": (None if nhwc_side_data is None else np.asarray(nhwc_side_data)),
        }

    def _apply_mul_sub_const_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
        sub_idx = int(plan["sub_idx"])
        sub_input_rewrites = [dict(v) for v in list(plan["sub_input_rewrites"])]
        sub_out_name = str(plan["sub_out_name"])
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        mul_side_input_index = int(plan["mul_side_input_index"])
        mul_side_input_name = str(plan["mul_side_input_name"])
        mul_out_name = str(plan["mul_out_name"])
        removable_pre_indices = [int(v) for v in list(plan.get("removable_pre_indices", []))]

        side_input_name_for_mul = str(mul_side_input_name)
        if bool(plan.get("side_needs_update", False)):
            nhwc_data = np.asarray(plan.get("side_nhwc_data"))
            side_tensor = model_ir.tensors.get(str(mul_side_input_name), None)
            if side_tensor is None:
                return []
            if bool(plan.get("side_shared_outside_mul", False)):
                side_input_name_for_mul = _unique_tensor_name(f"{mul_side_input_name}_nhwc")
                model_ir.tensors[side_input_name_for_mul] = TensorIR(
                    name=side_input_name_for_mul,
                    dtype=str(side_tensor.dtype),
                    shape=[int(v) for v in list(nhwc_data.shape)],
                    shape_signature=[int(v) for v in list(nhwc_data.shape)],
                    data=np.asarray(nhwc_data),
                    is_variable=False,
                    quantization=_clone_quantization(side_tensor.quantization),
                )
            else:
                side_tensor.data = np.asarray(nhwc_data)
                side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
                side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        sub_op = model_ir.operators[int(sub_idx)]
        sub_inputs = [str(v) for v in list(sub_op.inputs)]
        for rewrite in sub_input_rewrites:
            input_index = int(rewrite["sub_input_index"])
            if int(input_index) < 0 or int(input_index) >= len(sub_inputs):
                return []
            sub_inputs[int(input_index)] = str(rewrite["nhwc_name"])
        _set_operator_inputs(
            model_ir=model_ir,
            op=sub_op,
            new_inputs=sub_inputs,
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(sub_out_name, None),
            perm_nchw_to_nhwc,
        )

        mul_op = model_ir.operators[int(mul_idx)]
        mul_inputs = [str(v) for v in list(mul_op.inputs)]
        if int(mul_data_input_index) < 0 or int(mul_data_input_index) >= len(mul_inputs):
            return []
        if int(mul_side_input_index) < 0 or int(mul_side_input_index) >= len(mul_inputs):
            return []
        mul_inputs[int(mul_data_input_index)] = str(sub_out_name)
        mul_inputs[int(mul_side_input_index)] = str(side_input_name_for_mul)
        _set_operator_inputs(
            model_ir=model_ir,
            op=mul_op,
            new_inputs=mul_inputs,
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(mul_out_name, None),
            perm_nchw_to_nhwc,
        )

        return [int(v) for v in list(removable_pre_indices)]

    def _analyze_const_add_input_to_nhwc(
        *,
        input_name: str,
        add_idx: int,
        consumers: Dict[str, List[int]],
    ) -> Optional[Dict[str, Any]]:
        const_tensor = model_ir.tensors.get(str(input_name), None)
        if const_tensor is None or const_tensor.data is None:
            return None

        add_op = model_ir.operators[int(add_idx)]
        if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
            return None

        const_data = np.asarray(const_tensor.data)
        const_shape = [int(v) for v in list(const_data.shape)]
        target_nhwc_shape: Optional[List[int]] = None
        add_out_tensor = model_ir.tensors.get(str(add_op.outputs[0]), None)
        if (
            add_out_tensor is not None
            and _is_fully_known_positive_shape(list(add_out_tensor.shape))
            and len(list(add_out_tensor.shape)) == 4
        ):
            target_nhwc_shape = _permute_shape(list(add_out_tensor.shape), perm_nchw_to_nhwc)

        nhwc_data: Optional[np.ndarray] = None
        const_needs_update = False
        if int(const_data.size) == 1:
            pass
        elif const_data.ndim == 4:
            is_nchw_channelwise = (
                len(const_shape) == 4
                and int(const_shape[0]) == 1
                and int(const_shape[1]) > 0
                and int(const_shape[2]) == 1
                and int(const_shape[3]) == 1
            )
            if is_nchw_channelwise:
                rotated = np.transpose(const_data, perm_nchw_to_nhwc).astype(const_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if target_nhwc_shape is not None and _broadcast_static_shapes(target_nhwc_shape, rotated_shape) is None:
                    return None
                nhwc_data = np.asarray(rotated)
                const_needs_update = not np.array_equal(nhwc_data, const_data)
            elif target_nhwc_shape is not None and _broadcast_static_shapes(target_nhwc_shape, const_shape) is not None:
                pass
            else:
                rotated: Optional[np.ndarray] = None
                candidate = np.asarray(const_data)
                for _ in range(3):
                    candidate = np.transpose(candidate, perm_nchw_to_nhwc).astype(const_data.dtype, copy=False)
                    candidate_shape = [int(v) for v in list(candidate.shape)]
                    if target_nhwc_shape is None or _broadcast_static_shapes(target_nhwc_shape, candidate_shape) is not None:
                        rotated = np.asarray(candidate)
                        break
                if rotated is None:
                    return None
                nhwc_data = np.asarray(rotated)
                const_needs_update = True
        elif const_data.ndim == 3:
            if target_nhwc_shape is not None and _broadcast_static_shapes(target_nhwc_shape, const_shape) is not None:
                pass
            else:
                candidate = np.asarray(const_data)
                rotated: Optional[np.ndarray] = None
                for _ in range(3):
                    candidate = np.transpose(candidate, [1, 2, 0]).astype(const_data.dtype, copy=False)
                    candidate_shape = [int(v) for v in list(candidate.shape)]
                    if target_nhwc_shape is None or _broadcast_static_shapes(target_nhwc_shape, candidate_shape) is not None:
                        rotated = np.asarray(candidate)
                        break
                if rotated is None:
                    return None
                nhwc_data = np.asarray(rotated)
                const_needs_update = True
        else:
            if target_nhwc_shape is not None and _broadcast_static_shapes(target_nhwc_shape, const_shape) is None:
                return None

        shared_outside_add = any(
            int(v) != int(add_idx)
            for v in consumers.get(str(input_name), [])
        )
        return {
            "const_input_name": str(input_name),
            "const_needs_update": bool(const_needs_update),
            "const_shared_outside_add": bool(shared_outside_add),
            "const_nhwc_data": (None if nhwc_data is None else np.asarray(nhwc_data)),
        }

    def _apply_const_add_input_nhwc_plan(*, plan: Dict[str, Any]) -> str:
        const_input_name = str(plan["const_input_name"])
        const_input_name_for_add = str(const_input_name)
        if not bool(plan.get("const_needs_update", False)):
            return const_input_name_for_add

        nhwc_data = np.asarray(plan.get("const_nhwc_data"))
        const_tensor = model_ir.tensors.get(const_input_name, None)
        if const_tensor is None:
            return const_input_name_for_add
        if bool(plan.get("const_shared_outside_add", False)):
            const_input_name_for_add = _unique_tensor_name(f"{const_input_name}_nhwc")
            model_ir.tensors[const_input_name_for_add] = TensorIR(
                name=const_input_name_for_add,
                dtype=str(const_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(const_tensor.quantization),
            )
        else:
            const_tensor.data = np.asarray(nhwc_data)
            const_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            const_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(const_input_name_for_add)

    def _build_direct_nchw_fallback_plan(
        *,
        input_name: str,
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        if str(input_name) in model_outputs:
            return None
        input_tensor = model_ir.tensors.get(str(input_name), None)
        if input_tensor is None:
            return None
        # Restrict fallback to dynamic rank-4 tensors. Constants are handled by
        # const-specific remap logic; scalar/rank!=4 paths are left unchanged.
        if input_tensor.data is not None:
            return None
        input_shape = [int(v) for v in list(input_tensor.shape)]
        if len(input_shape) != 4:
            return None

        bridge_name = _unique_tensor_name(f"{input_name}_nhwc_bridge")
        return {
            "nhwc_input_name": str(bridge_name),
            "pre_remove_indices": [],
            "direct_nchw_plan": {
                "input_name": str(input_name),
                "bridge_name": str(bridge_name),
            },
        }

    def _materialize_direct_nchw_bridge(
        *,
        plan: Dict[str, Any],
    ) -> Optional[Dict[str, str]]:
        input_name = str(plan.get("input_name", ""))
        bridge_name = str(plan.get("bridge_name", ""))
        if input_name == "" or bridge_name == "":
            return None
        input_tensor = model_ir.tensors.get(input_name, None)
        if input_tensor is None:
            return None
        if len(list(input_tensor.shape)) != 4:
            return None

        perm_arr = np.asarray([0, 2, 3, 1], dtype=np.int32)
        # Keep per-bridge dedicated perm tensor to avoid cross-rewrite mutation.
        perm_const_name = _unique_tensor_name(f"{bridge_name}_perm")
        model_ir.tensors[perm_const_name] = TensorIR(
            name=perm_const_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=perm_arr,
            is_variable=False,
            quantization=None,
        )

        bridge_shape = _permute_shape(
            [int(v) for v in list(input_tensor.shape)],
            [0, 2, 3, 1],
        )
        bridge_signature_src = (
            [int(v) for v in list(input_tensor.shape_signature)]
            if input_tensor.shape_signature is not None
            else [int(v) for v in list(input_tensor.shape)]
        )
        bridge_signature = _permute_shape(bridge_signature_src, [0, 2, 3, 1])
        if bridge_shape is None or bridge_signature is None:
            return None

        if bridge_name not in model_ir.tensors:
            model_ir.tensors[bridge_name] = TensorIR(
                name=bridge_name,
                dtype=str(input_tensor.dtype),
                shape=[int(v) for v in list(bridge_shape)],
                shape_signature=[int(v) for v in list(bridge_signature)],
                data=None,
                is_variable=False,
                quantization=_clone_quantization(input_tensor.quantization),
            )

        return {
            "input_name": str(input_name),
            "bridge_name": str(bridge_name),
            "perm_name": str(perm_const_name),
        }

    def _resolve_add_input_to_nhwc(
        *,
        input_name: str,
        add_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
        allow_nested_add: bool = True,
    ) -> Optional[Dict[str, Any]]:
        input_producer_idx = producers.get(str(input_name), None)
        if input_producer_idx is not None:
            input_producer_op = model_ir.operators[int(input_producer_idx)]
            input_users = set(int(v) for v in consumers.get(str(input_name), []))

            if (
                str(input_producer_op.op_type) == "TRANSPOSE"
                and len(input_producer_op.inputs) >= 2
                and len(input_producer_op.outputs) == 1
                and str(input_producer_op.outputs[0]) == str(input_name)
                and _read_transpose_perm(model_ir, input_producer_op) == perm_nhwc_to_nchw
                and int(add_idx) in input_users
                and str(input_name) not in model_outputs
            ):
                extra_user_indices = [int(v) for v in sorted(input_users) if int(v) != int(add_idx)]
                return {
                    "nhwc_input_name": str(input_producer_op.inputs[0]),
                    "pre_remove_indices": (
                        [int(input_producer_idx)] if len(extra_user_indices) == 0 else []
                    ),
                    "swish_plan": None,
                    "unary_plan": None,
                    "mul_const_plan": None,
                    "nested_add_plan": None,
                }

        swish_plan = _analyze_swish_input_to_nhwc(
            input_name=input_name,
            consumer_idx=int(add_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if swish_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": swish_plan,
                "unary_plan": None,
                "mul_const_plan": None,
                "mul_sub_const_plan": None,
                "gather_plan": None,
                "nested_add_plan": None,
            }

        unary_plan = _analyze_unary_input_to_nhwc(
            input_name=input_name,
            consumer_idx=int(add_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if unary_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": None,
                "unary_plan": unary_plan,
                "mul_const_plan": None,
                "mul_sub_const_plan": None,
                "gather_plan": None,
                "nested_add_plan": None,
            }

        mul_const_plan = _analyze_mul_const_input_to_nhwc(
            input_name=input_name,
            consumer_idx=int(add_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if mul_const_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": None,
                "unary_plan": None,
                "mul_const_plan": mul_const_plan,
                "mul_sub_const_plan": None,
                "gather_plan": None,
                "nested_add_plan": None,
            }

        mul_sub_const_plan = _analyze_mul_sub_const_input_to_nhwc(
            input_name=input_name,
            consumer_idx=int(add_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if mul_sub_const_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": None,
                "unary_plan": None,
                "mul_const_plan": None,
                "mul_sub_const_plan": mul_sub_const_plan,
                "gather_plan": None,
                "nested_add_plan": None,
            }

        gather_plan = _analyze_gather_input_to_nhwc(
            input_name=input_name,
            consumer_idx=int(add_idx),
            producers=producers,
            consumers=consumers,
            model_outputs=model_outputs,
        )
        if gather_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": None,
                "unary_plan": None,
                "mul_const_plan": None,
                "mul_sub_const_plan": None,
                "gather_plan": gather_plan,
                "nested_add_plan": None,
            }

        const_add_plan = _analyze_const_add_input_to_nhwc(
            input_name=input_name,
            add_idx=int(add_idx),
            consumers=consumers,
        )
        if const_add_plan is not None:
            return {
                "nhwc_input_name": str(input_name),
                "pre_remove_indices": [],
                "swish_plan": None,
                "unary_plan": None,
                "mul_const_plan": None,
                "mul_sub_const_plan": None,
                "gather_plan": None,
                "nested_add_plan": None,
                "const_add_plan": const_add_plan,
            }

        if input_producer_idx is not None and allow_nested_add:
            input_producer_op = model_ir.operators[int(input_producer_idx)]
            if (
                str(input_producer_op.op_type) == "ADD"
                and len(input_producer_op.inputs) == 2
                and len(input_producer_op.outputs) == 1
                and str(input_producer_op.outputs[0]) == str(input_name)
                and str(input_name) not in model_outputs
            ):
                input_users = set(int(v) for v in consumers.get(str(input_name), []))
                if input_users == {int(add_idx)}:
                    nested_input_plans: List[Dict[str, Any]] = []
                    nested_rewritable = True
                    for nested_input_name in [str(v) for v in list(input_producer_op.inputs)]:
                        nested_plan = _resolve_add_input_to_nhwc(
                            input_name=str(nested_input_name),
                            add_idx=int(input_producer_idx),
                            producers=producers,
                            consumers=consumers,
                            model_outputs=model_outputs,
                            allow_nested_add=False,
                        )
                        if nested_plan is None:
                            nested_rewritable = False
                            break
                        nested_input_plans.append(dict(nested_plan))
                    if nested_rewritable:
                        return {
                            "nhwc_input_name": str(input_name),
                            "pre_remove_indices": [],
                            "swish_plan": None,
                            "unary_plan": None,
                            "mul_const_plan": None,
                            "mul_sub_const_plan": None,
                            "gather_plan": None,
                            "nested_add_plan": {
                                "input_name": str(input_name),
                                "add_idx": int(input_producer_idx),
                                "input_plans": [dict(v) for v in nested_input_plans],
                            },
                        }

        if input_producer_idx is not None:
            input_producer_op = model_ir.operators[int(input_producer_idx)]
            if (
                str(input_producer_op.op_type) == "ADD"
                and len(input_producer_op.outputs) == 1
                and str(input_producer_op.outputs[0]) == str(input_name)
            ):
                input_users = [int(v) for v in consumers.get(str(input_name), []) if int(v) != int(input_producer_idx)]
                post_candidates: List[str] = []
                for user_idx in input_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == str(input_name)
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        post_candidates.append(str(user_op.outputs[0]))
                if len(post_candidates) > 0:
                    return {
                        "nhwc_input_name": str(post_candidates[0]),
                        "pre_remove_indices": [],
                        "swish_plan": None,
                        "unary_plan": None,
                        "mul_const_plan": None,
                        "mul_sub_const_plan": None,
                        "gather_plan": None,
                        "nested_add_plan": None,
                    }

        return None

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            if bool(add_op.options.get(optimized_add_marker, False)):
                continue
            add_out_name = str(add_op.outputs[0])

            bridge_output_name = add_out_name
            bridge_output_producer_idx = int(add_idx)
            bridge_output_producer_op = add_op
            bridge_prelu_idx: Optional[int] = None

            # Also support: ADD -> unary -> post-transpose fanout.
            add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_out_users) == 1:
                unary_idx = int(add_out_users[0])
                unary_op = model_ir.operators[int(unary_idx)]
                if (
                    str(unary_op.op_type) in unary_passthrough_ops
                    and len(unary_op.inputs) == 1
                    and len(unary_op.outputs) == 1
                    and str(unary_op.inputs[0]) == add_out_name
                ):
                    unary_out_name = str(unary_op.outputs[0])
                    if add_out_name not in model_outputs and unary_out_name not in model_outputs:
                        bridge_output_name = unary_out_name
                        bridge_output_producer_idx = int(unary_idx)
                        bridge_output_producer_op = unary_op
                elif (
                    str(unary_op.op_type) == "PRELU"
                    and len(unary_op.inputs) == 2
                    and len(unary_op.outputs) == 1
                    and str(unary_op.inputs[0]) == add_out_name
                ):
                    prelu_out_name = str(unary_op.outputs[0])
                    if add_out_name not in model_outputs and prelu_out_name not in model_outputs:
                        bridge_output_name = prelu_out_name
                        bridge_output_producer_idx = int(unary_idx)
                        bridge_output_producer_op = unary_op
                        bridge_prelu_idx = int(unary_idx)

            out_users = [
                int(v)
                for v in consumers.get(bridge_output_name, [])
                if int(v) != int(bridge_output_producer_idx)
            ]
            if len(out_users) == 0:
                continue

            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in out_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == bridge_output_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or len(post_indices) == 0:
                continue

            input_plans: List[Dict[str, Any]] = []
            rewritable = True
            for input_name in [str(v) for v in list(add_op.inputs)]:
                resolved = _resolve_add_input_to_nhwc(
                    input_name=input_name,
                    add_idx=int(add_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if resolved is None:
                    resolved = _build_direct_nchw_fallback_plan(
                        input_name=str(input_name),
                        model_outputs=model_outputs,
                    )
                    if resolved is None:
                        rewritable = False
                        break
                input_plans.append(dict(resolved))
            if not rewritable:
                continue

            planned_direct_bridge_count = int(
                sum(1 for plan in input_plans if plan.get("direct_nchw_plan", None) is not None)
            )
            if planned_direct_bridge_count > 0:
                planned_pre_remove_count = int(
                    sum(
                        len([int(v) for v in list(plan.get("pre_remove_indices", []))])
                        for plan in input_plans
                    )
                )
                planned_post_remove_count = int(len(post_indices) - 1) if len(legacy_users) > 0 else int(len(post_indices))
                # Require strict local transpose reduction before introducing
                # direct NCHW->NHWC bridge inserts.
                if int(planned_post_remove_count + planned_pre_remove_count) <= int(planned_direct_bridge_count):
                    if int(planned_post_remove_count + planned_pre_remove_count) < int(planned_direct_bridge_count):
                        continue

            def _apply_nested_add_nhwc_plan(*, plan: Dict[str, Any]) -> List[int]:
                nested_input_name = str(plan["input_name"])
                nested_add_idx = int(plan["add_idx"])
                nested_input_plans = [dict(v) for v in list(plan.get("input_plans", []))]

                nested_remove_indices: List[int] = []
                nested_new_inputs: List[str] = []
                for nested_input_plan in nested_input_plans:
                    nested_nhwc_input_name = str(nested_input_plan["nhwc_input_name"])
                    nested_swish_plan = nested_input_plan.get("swish_plan", None)
                    if nested_swish_plan is not None:
                        nested_remove_indices.extend(_apply_swish_nhwc_plan(plan=dict(nested_swish_plan)))
                    nested_unary_plan = nested_input_plan.get("unary_plan", None)
                    if nested_unary_plan is not None:
                        nested_remove_indices.extend(_apply_unary_nhwc_plan(plan=dict(nested_unary_plan)))
                    nested_mul_const_plan = nested_input_plan.get("mul_const_plan", None)
                    if nested_mul_const_plan is not None:
                        nested_remove_indices.extend(_apply_mul_const_nhwc_plan(plan=dict(nested_mul_const_plan)))
                    nested_mul_sub_const_plan = nested_input_plan.get("mul_sub_const_plan", None)
                    if nested_mul_sub_const_plan is not None:
                        nested_remove_indices.extend(
                            _apply_mul_sub_const_nhwc_plan(plan=dict(nested_mul_sub_const_plan))
                        )
                    nested_gather_plan = nested_input_plan.get("gather_plan", None)
                    if nested_gather_plan is not None:
                        nested_remove_indices.extend(
                            _apply_gather_input_nhwc_plan(plan=dict(nested_gather_plan))
                        )
                    nested_nested_add_plan = nested_input_plan.get("nested_add_plan", None)
                    if nested_nested_add_plan is not None:
                        nested_remove_indices.extend(
                            _apply_nested_add_nhwc_plan(plan=dict(nested_nested_add_plan))
                        )
                    nested_const_add_plan = nested_input_plan.get("const_add_plan", None)
                    if nested_const_add_plan is not None:
                        nested_nhwc_input_name = _apply_const_add_input_nhwc_plan(
                            plan=dict(nested_const_add_plan)
                        )
                    nested_new_inputs.append(str(nested_nhwc_input_name))
                    nested_remove_indices.extend(
                        [int(v) for v in list(nested_input_plan.get("pre_remove_indices", []))]
                    )

                nested_add_op = model_ir.operators[int(nested_add_idx)]
                if (
                    str(nested_add_op.op_type) != "ADD"
                    or len(nested_add_op.inputs) != 2
                    or len(nested_add_op.outputs) != 1
                ):
                    return nested_remove_indices
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=nested_add_op,
                    new_inputs=[str(v) for v in list(nested_new_inputs)],
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(nested_input_name, None),
                    perm_nchw_to_nhwc,
                )
                return nested_remove_indices

            new_add_inputs: List[str] = []
            pre_remove_indices: List[int] = []
            direct_bridge_specs: List[Dict[str, str]] = []
            for plan in input_plans:
                nhwc_input_name = str(plan["nhwc_input_name"])
                swish_plan = plan.get("swish_plan", None)
                if swish_plan is not None:
                    pre_remove_indices.extend(_apply_swish_nhwc_plan(plan=dict(swish_plan)))
                unary_plan = plan.get("unary_plan", None)
                if unary_plan is not None:
                    pre_remove_indices.extend(_apply_unary_nhwc_plan(plan=dict(unary_plan)))
                mul_const_plan = plan.get("mul_const_plan", None)
                if mul_const_plan is not None:
                    pre_remove_indices.extend(_apply_mul_const_nhwc_plan(plan=dict(mul_const_plan)))
                mul_sub_const_plan = plan.get("mul_sub_const_plan", None)
                if mul_sub_const_plan is not None:
                    pre_remove_indices.extend(_apply_mul_sub_const_nhwc_plan(plan=dict(mul_sub_const_plan)))
                gather_plan = plan.get("gather_plan", None)
                if gather_plan is not None:
                    pre_remove_indices.extend(_apply_gather_input_nhwc_plan(plan=dict(gather_plan)))
                nested_add_plan = plan.get("nested_add_plan", None)
                if nested_add_plan is not None:
                    pre_remove_indices.extend(_apply_nested_add_nhwc_plan(plan=dict(nested_add_plan)))
                const_add_plan = plan.get("const_add_plan", None)
                if const_add_plan is not None:
                    nhwc_input_name = _apply_const_add_input_nhwc_plan(plan=dict(const_add_plan))
                direct_nchw_plan = plan.get("direct_nchw_plan", None)
                if direct_nchw_plan is not None:
                    bridge_spec = _materialize_direct_nchw_bridge(plan=dict(direct_nchw_plan))
                    if bridge_spec is None:
                        rewritable = False
                        break
                    nhwc_input_name = str(bridge_spec["bridge_name"])
                    direct_bridge_specs.append(dict(bridge_spec))
                new_add_inputs.append(str(nhwc_input_name))
                pre_remove_indices.extend([int(v) for v in list(plan.get("pre_remove_indices", []))])
            if not rewritable:
                continue

            if bridge_prelu_idx is not None:
                target_nhwc_shape: Optional[List[int]] = None
                if len(new_add_inputs) > 0:
                    target_tensor = model_ir.tensors.get(str(new_add_inputs[0]), None)
                    if target_tensor is not None and target_tensor.shape is not None:
                        target_nhwc_shape = [int(v) for v in list(target_tensor.shape)]
                bridge_prelu_op = model_ir.operators[int(bridge_prelu_idx)]
                selected_alpha_name = _rewrite_prelu_alpha_to_nhwc(
                    prelu_idx=int(bridge_prelu_idx),
                    prelu_op=bridge_prelu_op,
                    target_nhwc_shape=target_nhwc_shape,
                    consumers=consumers,
                )
                if selected_alpha_name is None:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=bridge_prelu_op,
                    new_inputs=[add_out_name, str(selected_alpha_name)],
                )

            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=[str(v) for v in new_add_inputs],
            )

            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=bridge_output_producer_op,
                new_outputs=[canonical_post_output_name],
            )
            for alias_post_output_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, alias_post_output_name, canonical_post_output_name)

            old_bridge_tensor = model_ir.tensors.get(bridge_output_name, None)
            canonical_post_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_bridge_tensor is not None and canonical_post_tensor is not None:
                canonical_post_tensor.dtype = str(old_bridge_tensor.dtype)
                canonical_post_tensor.quantization = _clone_quantization(old_bridge_tensor.quantization)
                canonical_post_tensor.shape = [int(v) for v in list(old_bridge_tensor.shape)]
                canonical_post_tensor.shape_signature = (
                    [int(v) for v in list(old_bridge_tensor.shape_signature)]
                    if old_bridge_tensor.shape_signature is not None
                    else [int(v) for v in list(old_bridge_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_post_tensor,
                    perm_nchw_to_nhwc,
                )

            if len(legacy_users) > 0:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[int(keep_post_idx)]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[canonical_post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[bridge_output_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = sorted(
                list({int(v) for v in pre_remove_indices + post_remove_indices}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                if int(remove_idx) == int(add_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            if len(direct_bridge_specs) > 0:
                try:
                    add_current_idx = int(model_ir.operators.index(add_op))
                except ValueError:
                    add_current_idx = int(max(0, min(add_idx, len(model_ir.operators))))
                insert_offset = 0
                for bridge_spec in direct_bridge_specs:
                    model_ir.operators.insert(
                        int(add_current_idx + insert_offset),
                        OperatorIR(
                            op_type="TRANSPOSE",
                            inputs=[str(bridge_spec["input_name"]), str(bridge_spec["perm_name"])],
                            outputs=[str(bridge_spec["bridge_name"])],
                        ),
                    )
                    insert_offset += 1

            # Keep explicit unary ops after transpose-bridge rewrites for stability.
            add_opts = dict(add_op.options) if isinstance(add_op.options, dict) else {}
            add_opts[skip_add_activation_fuse_marker] = True
            add_opts[optimized_add_marker] = True
            add_op.options = add_opts

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_add_nhwc_chains": int(optimized)}


def _optimize_transpose_dual_pre_add_to_single_post_adapter_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Reduce dual NHWC->NCHW adapters feeding one ADD into a single post-ADD adapter.

    Target:
      a_nhwc --T(0,3,1,2)--> a_nchw
      b_nhwc --T(0,3,1,2)--> b_nchw
      ADD(a_nchw, b_nchw) -> y_nchw

    Rewrite:
      ADD(a_nhwc, b_nhwc) -> y_nhwc
      y_nhwc --T(0,3,1,2)--> y_nchw

    Safety:
    - Both pre-transpose outputs are consumed only by the target ADD.
    - ADD output is rank-4 and is not a graph output.
    - Skip when ADD already fans out to NCHW->NHWC post-transpose consumers.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_const_name = "__nhwc_to_nchw_perm_rank4__"

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _op_index(op_ref: OperatorIR) -> Optional[int]:
        for idx, op in enumerate(model_ir.operators):
            if id(op) == id(op_ref):
                return int(idx)
        return None

    if perm_const_name not in model_ir.tensors:
        model_ir.tensors[perm_const_name] = TensorIR(
            name=perm_const_name,
            dtype="INT32",
            shape=[4],
            shape_signature=[4],
            data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
            is_variable=False,
            quantization=None,
        )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if any(
                str(model_ir.operators[int(user_idx)].op_type) == "TRANSPOSE"
                and _read_transpose_perm(model_ir, model_ir.operators[int(user_idx)]) == perm_nchw_to_nhwc
                for user_idx in add_out_users
            ):
                continue

            pre_indices: List[int] = []
            new_add_inputs: List[str] = []
            rewritable = True
            for add_input_name in [str(v) for v in list(add_op.inputs)]:
                pre_idx = producers.get(add_input_name, None)
                if pre_idx is None:
                    rewritable = False
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != add_input_name
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                    or str(add_input_name) in model_outputs
                ):
                    rewritable = False
                    break
                if set(int(v) for v in consumers.get(add_input_name, [])) != {int(add_idx)}:
                    rewritable = False
                    break
                pre_input_name = str(pre_op.inputs[0])
                pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
                if pre_input_tensor is None or len(list(pre_input_tensor.shape)) != 4:
                    rewritable = False
                    break
                pre_indices.append(int(pre_idx))
                new_add_inputs.append(pre_input_name)
            if not rewritable:
                continue

            add_out_tensor = model_ir.tensors.get(add_out_name, None)
            if add_out_tensor is None or len(list(add_out_tensor.shape)) != 4:
                continue
            add_out_shape = [int(v) for v in list(add_out_tensor.shape)]
            add_out_signature = (
                [int(v) for v in list(add_out_tensor.shape_signature)]
                if add_out_tensor.shape_signature is not None
                else [int(v) for v in list(add_out_tensor.shape)]
            )
            add_out_nhwc_shape = _permute_shape(add_out_shape, perm_nchw_to_nhwc)
            add_out_nhwc_signature = _permute_shape(add_out_signature, perm_nchw_to_nhwc)
            if add_out_nhwc_shape is None or add_out_nhwc_signature is None:
                continue

            add_out_nhwc_name = _unique_tensor_name(f"{add_out_name}_nhwc")
            model_ir.tensors[add_out_nhwc_name] = TensorIR(
                name=add_out_nhwc_name,
                dtype=str(add_out_tensor.dtype),
                shape=[int(v) for v in list(add_out_nhwc_shape)],
                shape_signature=[int(v) for v in list(add_out_nhwc_signature)],
                data=None,
                is_variable=False,
                quantization=_clone_quantization(add_out_tensor.quantization),
            )

            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=[str(v) for v in list(new_add_inputs)],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_op,
                new_outputs=[str(add_out_nhwc_name)],
            )

            for remove_idx in sorted(list(set(int(v) for v in pre_indices)), reverse=True):
                del model_ir.operators[int(remove_idx)]

            add_new_idx = _op_index(add_op)
            if add_new_idx is None:
                changed = False
                break
            model_ir.operators.insert(
                int(add_new_idx) + 1,
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(add_out_nhwc_name), str(perm_const_name)],
                    outputs=[str(add_out_name)],
                    options={},
                ),
            )

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_dual_pre_add_to_single_post_adapter_nhwc_chains": int(optimized)}


def _optimize_terminal_transpose_mul_add_reshape_fc_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove terminal NHWC->NCHW transpose before MUL/ADD/RESHAPE/FULLY_CONNECTED.

    Target:
      x_nhwc --T(0,3,1,2)--> x_nchw
      x_nchw --MUL(c1)--> m_nchw
      m_nchw --ADD(c2)--> y_nchw
      y_nchw --RESHAPE([N,-1]|[N,K])--> r
      r --FULLY_CONNECTED(W,b)--> o

    Rewrite:
      x_nhwc --MUL(c1_nhwc)--> m_nhwc
      m_nhwc --ADD(c2_nhwc)--> y_nhwc
      y_nhwc --RESHAPE([N,-1]|[N,K])--> r
      r --FULLY_CONNECTED(W',b)--> o

    where W' is input-axis permuted for NHWC flatten ordering.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _materialize_nhwc_const(
        *,
        tensor_name: str,
        target_nhwc_shape: List[int],
        consumers: Dict[str, List[int]],
        chain_indices: set[int],
    ) -> Optional[str]:
        side_tensor = model_ir.tensors.get(str(tensor_name), None)
        if side_tensor is None or side_tensor.data is None:
            return None
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return str(tensor_name)

        if side_data.ndim != 4:
            return None
        side_shape = [int(v) for v in list(side_data.shape)]
        if _broadcast_static_shapes(target_nhwc_shape, side_shape) is not None:
            return str(tensor_name)

        rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
        rotated_shape = [int(v) for v in list(rotated.shape)]
        if _broadcast_static_shapes(target_nhwc_shape, rotated_shape) is None:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_indices for u in side_users)
        if shared_outside_chain:
            replacement_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[replacement_name] = TensorIR(
                name=replacement_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(rotated_shape)],
                shape_signature=[int(v) for v in list(rotated_shape)],
                data=np.asarray(rotated),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
            return str(replacement_name)

        side_tensor.data = np.asarray(rotated)
        side_tensor.shape = [int(v) for v in list(rotated_shape)]
        side_tensor.shape_signature = [int(v) for v in list(rotated_shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue

            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            if pre_out_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_out_name, [])]
            if len(pre_users) != 1:
                continue
            mul_idx = int(pre_users[0])
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue

            mul_side_index: Optional[int] = None
            mul_side_name: Optional[str] = None
            if str(mul_op.inputs[0]) == pre_out_name:
                mul_side_index = 1
                mul_side_name = str(mul_op.inputs[1])
            elif str(mul_op.inputs[1]) == pre_out_name:
                mul_side_index = 0
                mul_side_name = str(mul_op.inputs[0])
            if mul_side_index is None or mul_side_name is None:
                continue

            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name in model_outputs:
                continue
            mul_users = [int(v) for v in consumers.get(mul_out_name, [])]
            if len(mul_users) != 1:
                continue
            add_idx = int(mul_users[0])
            add_op = model_ir.operators[int(add_idx)]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_side_index: Optional[int] = None
            add_side_name: Optional[str] = None
            if str(add_op.inputs[0]) == mul_out_name:
                add_side_index = 1
                add_side_name = str(add_op.inputs[1])
            elif str(add_op.inputs[1]) == mul_out_name:
                add_side_index = 0
                add_side_name = str(add_op.inputs[0])
            if add_side_index is None or add_side_name is None:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue
            add_users = [int(v) for v in consumers.get(add_out_name, [])]
            if len(add_users) != 1:
                continue
            reshape_idx = int(add_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 2
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != add_out_name
            ):
                continue

            reshape_out_name = str(reshape_op.outputs[0])
            if reshape_out_name in model_outputs:
                continue
            reshape_users = [int(v) for v in consumers.get(reshape_out_name, [])]
            if len(reshape_users) != 1:
                continue
            fc_idx = int(reshape_users[0])
            fc_op = model_ir.operators[int(fc_idx)]
            if (
                str(fc_op.op_type) != "FULLY_CONNECTED"
                or len(fc_op.inputs) < 2
                or len(fc_op.outputs) != 1
                or str(fc_op.inputs[0]) != reshape_out_name
            ):
                continue

            pre_out_tensor = model_ir.tensors.get(pre_out_name, None)
            pre_in_tensor = model_ir.tensors.get(pre_in_name, None)
            add_out_tensor = model_ir.tensors.get(add_out_name, None)
            if (
                pre_out_tensor is None
                or pre_in_tensor is None
                or add_out_tensor is None
                or len(list(pre_out_tensor.shape)) != 4
                or len(list(pre_in_tensor.shape)) != 4
                or len(list(add_out_tensor.shape)) != 4
            ):
                continue

            nchw_shape = [int(v) for v in list(pre_out_tensor.shape)]
            nhwc_shape = [int(v) for v in list(pre_in_tensor.shape)]
            if _permute_shape(nchw_shape, perm_nchw_to_nhwc) != nhwc_shape:
                continue
            if not _is_fully_known_positive_shape(nchw_shape):
                continue

            n, c, h, w = [int(v) for v in nchw_shape]
            input_size = int(c * h * w)

            weight_name = str(fc_op.inputs[1])
            weight_tensor = model_ir.tensors.get(weight_name, None)
            if weight_tensor is None or weight_tensor.data is None:
                continue
            weight_data = np.asarray(weight_tensor.data)
            if weight_data.ndim != 2:
                continue

            perm_index = np.transpose(
                np.arange(input_size, dtype=np.int64).reshape(c, h, w),
                (1, 2, 0),
            ).reshape(-1)
            if weight_data.shape[1] == input_size:
                weight_nhwc = np.asarray(weight_data[:, perm_index])
            elif weight_data.shape[0] == input_size:
                weight_nhwc = np.asarray(weight_data[perm_index, :])
            else:
                continue

            chain_indices = {int(pre_idx), int(mul_idx), int(add_idx), int(reshape_idx), int(fc_idx)}
            mul_side_replacement = _materialize_nhwc_const(
                tensor_name=str(mul_side_name),
                target_nhwc_shape=[int(v) for v in list(nhwc_shape)],
                consumers=consumers,
                chain_indices=chain_indices,
            )
            if mul_side_replacement is None:
                continue
            add_side_replacement = _materialize_nhwc_const(
                tensor_name=str(add_side_name),
                target_nhwc_shape=[int(v) for v in list(nhwc_shape)],
                consumers=consumers,
                chain_indices=chain_indices,
            )
            if add_side_replacement is None:
                continue

            weight_users = [int(v) for v in consumers.get(weight_name, [])]
            selected_weight_name = str(weight_name)
            if len(weight_users) == 1 and int(weight_users[0]) == int(fc_idx):
                weight_tensor.data = np.asarray(weight_nhwc)
                weight_tensor.shape = [int(v) for v in list(weight_nhwc.shape)]
                weight_tensor.shape_signature = [int(v) for v in list(weight_nhwc.shape)]
            else:
                selected_weight_name = _unique_tensor_name(f"{weight_name}_nhwc")
                model_ir.tensors[selected_weight_name] = TensorIR(
                    name=selected_weight_name,
                    dtype=str(weight_tensor.dtype),
                    shape=[int(v) for v in list(weight_nhwc.shape)],
                    shape_signature=[int(v) for v in list(weight_nhwc.shape)],
                    data=np.asarray(weight_nhwc),
                    is_variable=False,
                    quantization=_clone_quantization(weight_tensor.quantization),
                )

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=0 if int(mul_side_index) == 1 else 1,
                new_input_name=str(pre_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(mul_side_index),
                new_input_name=str(mul_side_replacement),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add_op,
                input_index=int(add_side_index),
                new_input_name=str(add_side_replacement),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=fc_op,
                input_index=1,
                new_input_name=str(selected_weight_name),
            )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(mul_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_out_name, None),
                perm_nchw_to_nhwc,
            )

            del model_ir.operators[int(pre_idx)]
            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_terminal_transpose_mul_add_reshape_fc_nhwc_chains": int(optimized)}


def _optimize_terminal_transpose_prelu_reshape_batchmatmul_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove terminal NHWC->NCHW transpose before PRELU/RESHAPE/BATCH_MATMUL.

    Target:
      x_nhwc --T(0,3,1,2)--> x_nchw
      x_nchw --PRELU(alpha_nchw)--> p_nchw
      p_nchw --RESHAPE([N,-1]|[N,K])--> r
      r --BATCH_MATMUL(W)--> o

    Rewrite:
      x_nhwc --PRELU(alpha_nhwc)--> p_nhwc
      p_nhwc --RESHAPE([N,-1]|[N,K])--> r
      r --BATCH_MATMUL(W')--> o

    where W' is input-axis permuted for NHWC flatten ordering.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _materialize_prelu_alpha_nhwc(
        *,
        alpha_name: str,
        channel_dim: int,
        consumers: Dict[str, List[int]],
        chain_indices: set[int],
    ) -> Optional[str]:
        alpha_tensor = model_ir.tensors.get(str(alpha_name), None)
        if alpha_tensor is None or alpha_tensor.data is None:
            return None
        alpha_data = np.asarray(alpha_tensor.data)
        if int(alpha_data.size) == 1:
            return str(alpha_name)

        alpha_nhwc: Optional[np.ndarray] = None
        alpha_shape = [int(v) for v in list(alpha_data.shape)]
        if alpha_data.ndim == 4:
            if (
                int(alpha_shape[0]) == 1
                and int(alpha_shape[1]) == int(channel_dim)
                and int(alpha_shape[2]) == 1
                and int(alpha_shape[3]) == 1
            ):
                alpha_nhwc = np.transpose(alpha_data, perm_nchw_to_nhwc).astype(alpha_data.dtype, copy=False)
            elif (
                int(alpha_shape[0]) == 1
                and int(alpha_shape[1]) == 1
                and int(alpha_shape[2]) == 1
                and int(alpha_shape[3]) == int(channel_dim)
            ):
                return str(alpha_name)
        elif alpha_data.ndim == 3:
            if (
                int(alpha_shape[0]) == int(channel_dim)
                and int(alpha_shape[1]) == 1
                and int(alpha_shape[2]) == 1
            ):
                alpha_nhwc = np.transpose(alpha_data, (1, 2, 0)).astype(alpha_data.dtype, copy=False)
        elif alpha_data.ndim == 1:
            # 1D slope is ambiguous for rank-4 layout in this converter; keep strict.
            return None

        if alpha_nhwc is None:
            return None

        alpha_users = [int(v) for v in consumers.get(str(alpha_name), [])]
        shared_outside_chain = any(int(u) not in chain_indices for u in alpha_users)
        if shared_outside_chain:
            replacement_name = _unique_tensor_name(f"{alpha_name}_nhwc")
            replacement_shape = [int(v) for v in list(alpha_nhwc.shape)]
            model_ir.tensors[replacement_name] = TensorIR(
                name=replacement_name,
                dtype=str(alpha_tensor.dtype),
                shape=replacement_shape,
                shape_signature=replacement_shape,
                data=np.asarray(alpha_nhwc),
                is_variable=False,
                quantization=_clone_quantization(alpha_tensor.quantization),
            )
            return str(replacement_name)

        alpha_tensor.data = np.asarray(alpha_nhwc)
        alpha_tensor.shape = [int(v) for v in list(alpha_nhwc.shape)]
        alpha_tensor.shape_signature = [int(v) for v in list(alpha_nhwc.shape)]
        return str(alpha_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue

            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            if pre_out_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_out_name, [])]
            if len(pre_users) != 1:
                continue
            prelu_idx = int(pre_users[0])
            prelu_op = model_ir.operators[int(prelu_idx)]
            if (
                str(prelu_op.op_type) != "PRELU"
                or len(prelu_op.inputs) != 2
                or len(prelu_op.outputs) != 1
                or str(prelu_op.inputs[0]) != pre_out_name
            ):
                continue
            prelu_out_name = str(prelu_op.outputs[0])
            if prelu_out_name in model_outputs:
                continue

            prelu_users = [int(v) for v in consumers.get(prelu_out_name, [])]
            if len(prelu_users) != 1:
                continue
            reshape_idx = int(prelu_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 2
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != prelu_out_name
            ):
                continue
            reshape_out_name = str(reshape_op.outputs[0])
            if reshape_out_name in model_outputs:
                continue

            reshape_users = [int(v) for v in consumers.get(reshape_out_name, [])]
            if len(reshape_users) != 1:
                continue
            bmm_idx = int(reshape_users[0])
            bmm_op = model_ir.operators[int(bmm_idx)]
            if (
                str(bmm_op.op_type) != "BATCH_MATMUL"
                or len(bmm_op.inputs) != 2
                or len(bmm_op.outputs) != 1
                or str(bmm_op.inputs[0]) != reshape_out_name
            ):
                continue
            bmm_opts = dict(bmm_op.options) if isinstance(bmm_op.options, dict) else {}
            if bool(bmm_opts.get("adjX", False)) or bool(bmm_opts.get("adjY", False)):
                continue

            pre_out_tensor = model_ir.tensors.get(pre_out_name, None)
            pre_in_tensor = model_ir.tensors.get(pre_in_name, None)
            prelu_out_tensor = model_ir.tensors.get(prelu_out_name, None)
            if (
                pre_out_tensor is None
                or pre_in_tensor is None
                or prelu_out_tensor is None
                or len(list(pre_out_tensor.shape)) != 4
                or len(list(pre_in_tensor.shape)) != 4
                or len(list(prelu_out_tensor.shape)) != 4
            ):
                continue
            nchw_shape = [int(v) for v in list(pre_out_tensor.shape)]
            nhwc_shape = [int(v) for v in list(pre_in_tensor.shape)]
            if not _is_fully_known_positive_shape(nchw_shape):
                continue
            if _permute_shape(nchw_shape, perm_nchw_to_nhwc) != nhwc_shape:
                continue
            _, c, h, w = [int(v) for v in nchw_shape]
            input_size = int(c * h * w)

            rhs_name = str(bmm_op.inputs[1])
            rhs_tensor = model_ir.tensors.get(rhs_name, None)
            if rhs_tensor is None or rhs_tensor.data is None:
                continue
            rhs_data = np.asarray(rhs_tensor.data)
            if rhs_data.ndim != 2 or int(rhs_data.shape[0]) != int(input_size):
                continue

            perm_index = np.transpose(
                np.arange(input_size, dtype=np.int64).reshape(c, h, w),
                (1, 2, 0),
            ).reshape(-1)
            rhs_nhwc = np.asarray(rhs_data[perm_index, :])

            chain_indices = {int(pre_idx), int(prelu_idx), int(reshape_idx), int(bmm_idx)}
            alpha_name = str(prelu_op.inputs[1])
            alpha_replacement = _materialize_prelu_alpha_nhwc(
                alpha_name=str(alpha_name),
                channel_dim=int(c),
                consumers=consumers,
                chain_indices=chain_indices,
            )
            if alpha_replacement is None:
                continue

            rhs_users = [int(v) for v in consumers.get(rhs_name, [])]
            selected_rhs_name = str(rhs_name)
            if len(rhs_users) == 1 and int(rhs_users[0]) == int(bmm_idx):
                rhs_tensor.data = np.asarray(rhs_nhwc)
                rhs_tensor.shape = [int(v) for v in list(rhs_nhwc.shape)]
                rhs_tensor.shape_signature = [int(v) for v in list(rhs_nhwc.shape)]
            else:
                selected_rhs_name = _unique_tensor_name(f"{rhs_name}_nhwc")
                model_ir.tensors[selected_rhs_name] = TensorIR(
                    name=selected_rhs_name,
                    dtype=str(rhs_tensor.dtype),
                    shape=[int(v) for v in list(rhs_nhwc.shape)],
                    shape_signature=[int(v) for v in list(rhs_nhwc.shape)],
                    data=np.asarray(rhs_nhwc),
                    is_variable=False,
                    quantization=_clone_quantization(rhs_tensor.quantization),
                )

            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu_op,
                input_index=0,
                new_input_name=str(pre_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu_op,
                input_index=1,
                new_input_name=str(alpha_replacement),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=bmm_op,
                input_index=1,
                new_input_name=str(selected_rhs_name),
            )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(prelu_out_name, None),
                perm_nchw_to_nhwc,
            )

            del model_ir.operators[int(pre_idx)]
            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_terminal_transpose_prelu_reshape_batchmatmul_nhwc_chains": int(optimized)}


def _optimize_transpose_pre_add_mul_add_prelu_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Lift NCHW residual blocks back to NHWC when they follow:
      ADD -> MUL(const) -> ADD(const) -> PRELU -> TRANSPOSE(0,2,3,1)

    Inputs to the first ADD must be wrapped by TRANSPOSE(0,3,1,2) adapters.
    If PRELU keeps legacy NCHW consumers, preserve one adapter transpose.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_binary_const_to_nhwc(
        *,
        op_idx: int,
        side_input_index: int,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False

        nhwc_data: Optional[np.ndarray] = None
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is not None:
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                return True
            # NCHW per-channel const [1,C,1,1] is mapped once to NHWC [1,1,1,C].
            # Avoid multi-step rotations, which can accidentally produce [1,1,C,1]
            # when target metadata is stale/non-canonical.
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 0
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                    nhwc_data = np.asarray(rotated)
            else:
                rotated = np.asarray(side_data)
                for _ in range(3):
                    rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                        nhwc_data = np.asarray(rotated)
                        break
            if nhwc_data is None:
                return False
        else:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 1
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                nhwc_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            else:
                # Unknown target rank-4 shape: avoid speculative re-rotation to keep
                # repeated optimization sweeps idempotent.
                return True

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        target_name = str(side_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{side_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
        else:
            side_tensor.data = np.asarray(nhwc_data)
            side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        _replace_operator_input_at(
            model_ir=model_ir,
            op=model_ir.operators[int(op_idx)],
            input_index=int(side_input_index),
            new_input_name=str(target_name),
        )
        return True

    def _can_rewrite_binary_const_to_nhwc(
        *,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is None:
            return True
        side_shape = [int(v) for v in list(side_data.shape)]
        if _broadcast_static_shapes(target_shape, side_shape) is not None:
            return True
        if (
            len(side_shape) == 4
            and int(side_shape[0]) == 1
            and int(side_shape[1]) > 0
            and int(side_shape[2]) == 1
            and int(side_shape[3]) == 1
        ):
            rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            return _broadcast_static_shapes(target_shape, rotated_shape) is not None
        rotated = np.asarray(side_data)
        for _ in range(3):
            rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue
            add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_out_users) != 1:
                continue
            mul_idx = int(add_out_users[0])
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_in0 = str(mul_op.inputs[0])
            mul_in1 = str(mul_op.inputs[1])
            if mul_in0 == add_out_name:
                mul_side_input_index = 1
                mul_side_name = mul_in1
            elif mul_in1 == add_out_name:
                mul_side_input_index = 0
                mul_side_name = mul_in0
            else:
                continue

            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name in model_outputs:
                continue
            mul_out_users = [int(v) for v in consumers.get(mul_out_name, []) if int(v) != int(mul_idx)]
            if len(mul_out_users) != 1:
                continue
            add2_idx = int(mul_out_users[0])
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == mul_out_name:
                add2_side_input_index = 1
                add2_side_name = add2_in1
            elif add2_in1 == mul_out_name:
                add2_side_input_index = 0
                add2_side_name = add2_in0
            else:
                continue

            add2_out_name = str(add2_op.outputs[0])
            if add2_out_name in model_outputs:
                continue
            add2_out_users = [int(v) for v in consumers.get(add2_out_name, []) if int(v) != int(add2_idx)]
            if len(add2_out_users) != 1:
                continue
            prelu_idx = int(add2_out_users[0])
            prelu_op = model_ir.operators[int(prelu_idx)]
            if (
                str(prelu_op.op_type) != "PRELU"
                or len(prelu_op.inputs) != 2
                or len(prelu_op.outputs) != 1
                or str(prelu_op.inputs[0]) != add2_out_name
            ):
                continue
            prelu_side_input_index = 1
            prelu_side_name = str(prelu_op.inputs[1])
            prelu_out_name = str(prelu_op.outputs[0])
            if prelu_out_name in model_outputs:
                continue

            prelu_users = [int(v) for v in consumers.get(prelu_out_name, []) if int(v) != int(prelu_idx)]
            if len(prelu_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            for user_idx in prelu_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == prelu_out_name
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(user_idx))
                    post_output_names.append(str(user_op.outputs[0]))
                else:
                    legacy_users.append(int(user_idx))
            if len(post_indices) == 0:
                continue

            input_plans: List[Dict[str, Any]] = []
            rewritable_inputs = True
            for add_input_name in [str(v) for v in list(add_op.inputs)]:
                pre_idx = producers.get(str(add_input_name), None)
                if pre_idx is None:
                    rewritable_inputs = False
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != str(add_input_name)
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                    or str(add_input_name) in model_outputs
                ):
                    rewritable_inputs = False
                    break
                users = [int(v) for v in consumers.get(str(add_input_name), [])]
                if int(add_idx) not in users:
                    rewritable_inputs = False
                    break
                input_plans.append(
                    {
                        "nhwc_input_name": str(pre_op.inputs[0]),
                        "pre_remove_indices": [int(pre_idx)] if set(users) == {int(add_idx)} else [],
                    }
                )
            if not rewritable_inputs or len(input_plans) != 2:
                continue

            target_nhwc_shape = (
                list(model_ir.tensors[str(input_plans[0]["nhwc_input_name"])].shape)
                if str(input_plans[0]["nhwc_input_name"]) in model_ir.tensors
                else None
            )
            chain_index_set = {int(mul_idx), int(add2_idx), int(prelu_idx)}
            if not _can_rewrite_binary_const_to_nhwc(
                side_input_name=str(mul_side_name),
                target_broadcast_shape=target_nhwc_shape,
            ):
                continue
            if not _can_rewrite_binary_const_to_nhwc(
                side_input_name=str(add2_side_name),
                target_broadcast_shape=target_nhwc_shape,
            ):
                continue
            if not _can_rewrite_binary_const_to_nhwc(
                side_input_name=str(prelu_side_name),
                target_broadcast_shape=target_nhwc_shape,
            ):
                continue
            if not _rewrite_binary_const_to_nhwc(
                op_idx=int(mul_idx),
                side_input_index=int(mul_side_input_index),
                side_input_name=str(mul_side_name),
                target_broadcast_shape=target_nhwc_shape,
                chain_index_set=chain_index_set,
                consumers=consumers,
            ):
                continue
            if not _rewrite_binary_const_to_nhwc(
                op_idx=int(add2_idx),
                side_input_index=int(add2_side_input_index),
                side_input_name=str(add2_side_name),
                target_broadcast_shape=target_nhwc_shape,
                chain_index_set=chain_index_set,
                consumers=consumers,
            ):
                continue
            if not _rewrite_binary_const_to_nhwc(
                op_idx=int(prelu_idx),
                side_input_index=int(prelu_side_input_index),
                side_input_name=str(prelu_side_name),
                target_broadcast_shape=target_nhwc_shape,
                chain_index_set=chain_index_set,
                consumers=consumers,
            ):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=[str(plan["nhwc_input_name"]) for plan in input_plans],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(mul_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add2_out_name, None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(prelu_out_name, None),
                perm_nchw_to_nhwc,
            )

            canonical_post_output_name = str(post_output_names[0])
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[canonical_post_output_name],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

            old_prelu_out_tensor = model_ir.tensors.get(prelu_out_name, None)
            canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
            if old_prelu_out_tensor is not None and canonical_tensor is not None:
                canonical_tensor.dtype = str(old_prelu_out_tensor.dtype)
                canonical_tensor.quantization = _clone_quantization(old_prelu_out_tensor.quantization)
                canonical_tensor.shape = [int(v) for v in list(old_prelu_out_tensor.shape)]
                canonical_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu_out_tensor.shape_signature)]
                    if old_prelu_out_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu_out_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_tensor,
                    perm_nchw_to_nhwc,
                )

            if len(legacy_users) > 0:
                keep_post_idx = int(post_indices[0])
                keep_post_op = model_ir.operators[int(keep_post_idx)]
                keep_perm_name = str(keep_post_op.inputs[1])
                keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                if keep_perm_tensor is not None:
                    keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_inputs=[canonical_post_output_name, keep_perm_name],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=keep_post_op,
                    new_outputs=[prelu_out_name],
                )
                post_remove_indices = [int(v) for v in post_indices[1:]]
            else:
                post_remove_indices = [int(v) for v in post_indices]

            remove_indices = set(int(v) for v in post_remove_indices)
            for plan in input_plans:
                for pre_remove_idx in list(plan.get("pre_remove_indices", [])):
                    remove_indices.add(int(pre_remove_idx))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_add_mul_add_prelu_nhwc_chains": int(optimized)}


def _optimize_transpose_pre_add_mul_add_transpose_fanout_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Lift NCHW residual add fanouts back to NHWC when they follow:
      [x_nhwc --T(0,3,1,2)--> x_nchw] + [y_nhwc --T(0,3,1,2)--> y_nchw]
      ADD(x_nchw, y_nchw) -> a_nchw
      branch_i: a_nchw -> MUL(const) -> ADD(const) -> T(0,2,3,1) -> out_i_nhwc

    The ADD output may also keep legacy NCHW consumers. In that case, keep one
    adapter transpose: a_nhwc --T(0,3,1,2)--> a_nchw(legacy).
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_binary_const_to_nhwc(
        *,
        op_idx: int,
        side_input_index: int,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False

        nhwc_data: Optional[np.ndarray] = None
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is not None:
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                return True
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 0
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                    nhwc_data = np.asarray(rotated)
            else:
                rotated = np.asarray(side_data)
                for _ in range(3):
                    rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                        nhwc_data = np.asarray(rotated)
                        break
            if nhwc_data is None:
                return False
        else:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 1
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                nhwc_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            else:
                return True

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        target_name = str(side_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{side_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
        else:
            side_tensor.data = np.asarray(nhwc_data)
            side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        _replace_operator_input_at(
            model_ir=model_ir,
            op=model_ir.operators[int(op_idx)],
            input_index=int(side_input_index),
            new_input_name=str(target_name),
        )
        return True

    def _can_rewrite_binary_const_to_nhwc(
        *,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is None:
            return True
        side_shape = [int(v) for v in list(side_data.shape)]
        if _broadcast_static_shapes(target_shape, side_shape) is not None:
            return True
        if (
            len(side_shape) == 4
            and int(side_shape[0]) == 1
            and int(side_shape[1]) > 0
            and int(side_shape[2]) == 1
            and int(side_shape[3]) == 1
        ):
            rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            return _broadcast_static_shapes(target_shape, rotated_shape) is not None
        rotated = np.asarray(side_data)
        for _ in range(3):
            rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            input_plans: List[Dict[str, Any]] = []
            rewritable_inputs = True
            for add_input_name in [str(v) for v in list(add_op.inputs)]:
                pre_idx = producers.get(str(add_input_name), None)
                if pre_idx is None:
                    rewritable_inputs = False
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != str(add_input_name)
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                    or str(add_input_name) in model_outputs
                ):
                    rewritable_inputs = False
                    break
                input_users = [int(v) for v in consumers.get(str(add_input_name), [])]
                if int(add_idx) not in input_users:
                    rewritable_inputs = False
                    break
                input_plans.append(
                    {
                        "nhwc_input_name": str(pre_op.inputs[0]),
                        "pre_remove_indices": [int(pre_idx)] if set(input_users) == {int(add_idx)} else [],
                    }
                )
            if not rewritable_inputs or len(input_plans) != 2:
                continue

            add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_out_users) == 0:
                continue

            branch_plans: List[Dict[str, Any]] = []
            legacy_users: List[int] = []
            for user_idx in add_out_users:
                mul_op = model_ir.operators[int(user_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    legacy_users.append(int(user_idx))
                    continue
                mul_in0 = str(mul_op.inputs[0])
                mul_in1 = str(mul_op.inputs[1])
                if mul_in0 == add_out_name:
                    mul_data_input_index = 0
                    mul_side_input_index = 1
                    mul_side_name = mul_in1
                elif mul_in1 == add_out_name:
                    mul_data_input_index = 1
                    mul_side_input_index = 0
                    mul_side_name = mul_in0
                else:
                    legacy_users.append(int(user_idx))
                    continue

                mul_out_name = str(mul_op.outputs[0])
                if mul_out_name in model_outputs:
                    legacy_users.append(int(user_idx))
                    continue
                mul_out_users = [int(v) for v in consumers.get(mul_out_name, []) if int(v) != int(user_idx)]
                if len(mul_out_users) != 1:
                    legacy_users.append(int(user_idx))
                    continue
                add2_idx = int(mul_out_users[0])
                add2_op = model_ir.operators[int(add2_idx)]
                if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                    legacy_users.append(int(user_idx))
                    continue
                add2_in0 = str(add2_op.inputs[0])
                add2_in1 = str(add2_op.inputs[1])
                if add2_in0 == mul_out_name:
                    add2_side_input_index = 1
                    add2_side_name = add2_in1
                elif add2_in1 == mul_out_name:
                    add2_side_input_index = 0
                    add2_side_name = add2_in0
                else:
                    legacy_users.append(int(user_idx))
                    continue

                add2_out_name = str(add2_op.outputs[0])
                if add2_out_name in model_outputs:
                    legacy_users.append(int(user_idx))
                    continue
                add2_out_users = [int(v) for v in consumers.get(add2_out_name, []) if int(v) != int(add2_idx)]
                if len(add2_out_users) != 1:
                    legacy_users.append(int(user_idx))
                    continue
                post_idx = int(add2_out_users[0])
                post_op = model_ir.operators[int(post_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or str(post_op.inputs[0]) != add2_out_name
                    or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                    or str(post_op.outputs[0]) in model_outputs
                ):
                    legacy_users.append(int(user_idx))
                    continue

                branch_plans.append(
                    {
                        "mul_idx": int(user_idx),
                        "mul_data_input_index": int(mul_data_input_index),
                        "mul_side_input_index": int(mul_side_input_index),
                        "mul_side_name": str(mul_side_name),
                        "mul_out_name": str(mul_out_name),
                        "add2_idx": int(add2_idx),
                        "add2_side_input_index": int(add2_side_input_index),
                        "add2_side_name": str(add2_side_name),
                        "add2_out_name": str(add2_out_name),
                        "post_idx": int(post_idx),
                        "post_output_name": str(post_op.outputs[0]),
                    }
                )

            if len(branch_plans) == 0:
                continue

            planned_pre_remove_count = int(
                sum(len([int(v) for v in list(plan.get("pre_remove_indices", []))]) for plan in input_plans)
            )
            planned_post_remove_count = int(len(branch_plans))
            planned_adapter_count = int(1 if len(legacy_users) > 0 else 0)
            if int(planned_pre_remove_count + planned_post_remove_count) <= int(planned_adapter_count):
                continue

            target_nhwc_shape = (
                list(model_ir.tensors[str(input_plans[0]["nhwc_input_name"])].shape)
                if str(input_plans[0]["nhwc_input_name"]) in model_ir.tensors
                else None
            )
            chain_index_set: set[int] = set()
            for branch in branch_plans:
                chain_index_set.add(int(branch["mul_idx"]))
                chain_index_set.add(int(branch["add2_idx"]))
            constants_rewritable = True
            for branch in branch_plans:
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(branch["mul_side_name"]),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    constants_rewritable = False
                    break
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(branch["add2_side_name"]),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    constants_rewritable = False
                    break
            if not constants_rewritable:
                continue
            constants_applied = True
            for branch in branch_plans:
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(branch["mul_idx"]),
                    side_input_index=int(branch["mul_side_input_index"]),
                    side_input_name=str(branch["mul_side_name"]),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    constants_applied = False
                    break
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(branch["add2_idx"]),
                    side_input_index=int(branch["add2_side_input_index"]),
                    side_input_name=str(branch["add2_side_name"]),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    constants_applied = False
                    break
            if not constants_applied:
                continue

            add_nhwc_name = (
                _unique_tensor_name(f"{add_out_name}_nhwc")
                if len(legacy_users) > 0
                else str(add_out_name)
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=[str(plan["nhwc_input_name"]) for plan in input_plans],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_op,
                new_outputs=[str(add_nhwc_name)],
            )

            old_add_tensor = model_ir.tensors.get(add_out_name, None)
            if add_nhwc_name != add_out_name and old_add_tensor is not None and add_nhwc_name not in model_ir.tensors:
                model_ir.tensors[add_nhwc_name] = TensorIR(
                    name=add_nhwc_name,
                    dtype=str(old_add_tensor.dtype),
                    shape=[int(v) for v in list(old_add_tensor.shape)],
                    shape_signature=(
                        [int(v) for v in list(old_add_tensor.shape_signature)]
                        if old_add_tensor.shape_signature is not None
                        else [int(v) for v in list(old_add_tensor.shape)]
                    ),
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(old_add_tensor.quantization),
                )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_nhwc_name, None),
                perm_nchw_to_nhwc,
            )

            for branch in branch_plans:
                mul_op = model_ir.operators[int(branch["mul_idx"])]
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                data_input_index = int(branch["mul_data_input_index"])
                if int(data_input_index) >= len(mul_inputs):
                    constants_applied = False
                    break
                if str(mul_inputs[int(data_input_index)]) != add_out_name:
                    constants_applied = False
                    break
                mul_inputs[int(data_input_index)] = str(add_nhwc_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )

                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(branch["mul_out_name"]), None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(branch["add2_out_name"]), None),
                    perm_nchw_to_nhwc,
                )

                add2_op = model_ir.operators[int(branch["add2_idx"])]
                canonical_post_output_name = str(branch["post_output_name"])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=add2_op,
                    new_outputs=[canonical_post_output_name],
                )

                old_add2_out_tensor = model_ir.tensors.get(str(branch["add2_out_name"]), None)
                canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
                if old_add2_out_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_add2_out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_add2_out_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_add2_out_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_add2_out_tensor.shape_signature)]
                        if old_add2_out_tensor.shape_signature is not None
                        else [int(v) for v in list(old_add2_out_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )
            if not constants_applied:
                continue

            remove_indices: set[int] = set()
            for plan in input_plans:
                for pre_remove_idx in list(plan.get("pre_remove_indices", [])):
                    remove_indices.add(int(pre_remove_idx))
            for branch in branch_plans:
                remove_indices.add(int(branch["post_idx"]))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                if int(remove_idx) == int(add_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            if len(legacy_users) > 0:
                adapter_perm_name = _unique_tensor_name(f"{add_out_name}_adapter_perm")
                model_ir.tensors[adapter_perm_name] = TensorIR(
                    name=adapter_perm_name,
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
                try:
                    add_current_idx = int(model_ir.operators.index(add_op))
                except ValueError:
                    add_current_idx = int(max(0, min(add_idx, len(model_ir.operators))))
                model_ir.operators.insert(
                    int(add_current_idx + 1),
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(add_nhwc_name), str(adapter_perm_name)],
                        outputs=[str(add_out_name)],
                    ),
                )

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_add_mul_add_transpose_fanout_nhwc_chains": int(optimized)}


def _optimize_transpose_pre_unary_mul_add_transpose_fanout_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Lift strict fanout chains:
      x_nhwc --T(0,3,1,2)--> x_nchw --UNARY-->
      branch_i: MUL(const)->ADD(const)->T(0,2,3,1)

    into NHWC without adapter transposes.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {"RELU", "RELU6", "LOGISTIC", "TANH", "HARD_SWISH", "LEAKY_RELU", "GELU"}

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_binary_const_to_nhwc(
        *,
        op_idx: int,
        side_input_index: int,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False

        nhwc_data: Optional[np.ndarray] = None
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is not None:
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                return True
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 0
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                    nhwc_data = np.asarray(rotated)
            else:
                rotated = np.asarray(side_data)
                for _ in range(3):
                    rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                        nhwc_data = np.asarray(rotated)
                        break
            if nhwc_data is None:
                return False
        else:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 1
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                nhwc_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            else:
                return True

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        target_name = str(side_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{side_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
        else:
            side_tensor.data = np.asarray(nhwc_data)
            side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        _replace_operator_input_at(
            model_ir=model_ir,
            op=model_ir.operators[int(op_idx)],
            input_index=int(side_input_index),
            new_input_name=str(target_name),
        )
        return True

    def _can_rewrite_binary_const_to_nhwc(
        *,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is None:
            return True
        side_shape = [int(v) for v in list(side_data.shape)]
        if _broadcast_static_shapes(target_shape, side_shape) is not None:
            return True
        if (
            len(side_shape) == 4
            and int(side_shape[0]) == 1
            and int(side_shape[1]) > 0
            and int(side_shape[2]) == 1
            and int(side_shape[3]) == 1
        ):
            rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            return _broadcast_static_shapes(target_shape, rotated_shape) is not None
        rotated = np.asarray(side_data)
        for _ in range(3):
            rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue
            unary_idx = int(pre_users[0])
            unary_op = model_ir.operators[int(unary_idx)]
            if (
                str(unary_op.op_type) not in unary_ops
                or len(unary_op.inputs) != 1
                or len(unary_op.outputs) != 1
                or str(unary_op.inputs[0]) != pre_output_name
            ):
                continue

            unary_out_name = str(unary_op.outputs[0])
            if unary_out_name in model_outputs:
                continue
            unary_users = [int(v) for v in consumers.get(unary_out_name, []) if int(v) != int(unary_idx)]
            if len(unary_users) == 0:
                continue

            branch_plans: List[Dict[str, Any]] = []
            valid = True
            for user_idx in unary_users:
                mul_op = model_ir.operators[int(user_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    valid = False
                    break
                mul_in0 = str(mul_op.inputs[0])
                mul_in1 = str(mul_op.inputs[1])
                if mul_in0 == unary_out_name:
                    mul_data_input_index = 0
                    mul_side_input_index = 1
                    mul_side_name = mul_in1
                elif mul_in1 == unary_out_name:
                    mul_data_input_index = 1
                    mul_side_input_index = 0
                    mul_side_name = mul_in0
                else:
                    valid = False
                    break

                mul_out_name = str(mul_op.outputs[0])
                if mul_out_name in model_outputs:
                    valid = False
                    break
                mul_out_users = [int(v) for v in consumers.get(mul_out_name, []) if int(v) != int(user_idx)]
                if len(mul_out_users) != 1:
                    valid = False
                    break
                add_idx = int(mul_out_users[0])
                add_op = model_ir.operators[int(add_idx)]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    valid = False
                    break
                add_in0 = str(add_op.inputs[0])
                add_in1 = str(add_op.inputs[1])
                if add_in0 == mul_out_name:
                    add_side_input_index = 1
                    add_side_name = add_in1
                elif add_in1 == mul_out_name:
                    add_side_input_index = 0
                    add_side_name = add_in0
                else:
                    valid = False
                    break

                add_out_name = str(add_op.outputs[0])
                if add_out_name in model_outputs:
                    valid = False
                    break
                add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
                if len(add_out_users) != 1:
                    valid = False
                    break
                post_idx = int(add_out_users[0])
                post_op = model_ir.operators[int(post_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or str(post_op.inputs[0]) != add_out_name
                    or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                    or str(post_op.outputs[0]) in model_outputs
                ):
                    valid = False
                    break

                branch_plans.append(
                    {
                        "mul_idx": int(user_idx),
                        "mul_data_input_index": int(mul_data_input_index),
                        "mul_side_input_index": int(mul_side_input_index),
                        "mul_side_name": str(mul_side_name),
                        "mul_out_name": str(mul_out_name),
                        "add_idx": int(add_idx),
                        "add_side_input_index": int(add_side_input_index),
                        "add_side_name": str(add_side_name),
                        "add_out_name": str(add_out_name),
                        "post_idx": int(post_idx),
                        "post_output_name": str(post_op.outputs[0]),
                    }
                )
            if not valid or len(branch_plans) == 0:
                continue

            target_nhwc_shape = (
                [int(v) for v in list(model_ir.tensors[pre_input_name].shape)]
                if pre_input_name in model_ir.tensors
                else None
            )
            chain_index_set: set[int] = {int(unary_idx)}
            for branch in branch_plans:
                chain_index_set.add(int(branch["mul_idx"]))
                chain_index_set.add(int(branch["add_idx"]))

            constants_rewritable = True
            for branch in branch_plans:
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(branch["mul_side_name"]),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    constants_rewritable = False
                    break
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(branch["add_side_name"]),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    constants_rewritable = False
                    break
            if not constants_rewritable:
                continue

            constants_applied = True
            for branch in branch_plans:
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(branch["mul_idx"]),
                    side_input_index=int(branch["mul_side_input_index"]),
                    side_input_name=str(branch["mul_side_name"]),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    constants_applied = False
                    break
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(branch["add_idx"]),
                    side_input_index=int(branch["add_side_input_index"]),
                    side_input_name=str(branch["add_side_name"]),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    constants_applied = False
                    break
            if not constants_applied:
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=unary_op,
                new_inputs=[str(pre_input_name)],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(unary_out_name, None),
                perm_nchw_to_nhwc,
            )

            for branch in branch_plans:
                mul_op = model_ir.operators[int(branch["mul_idx"])]
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                data_input_index = int(branch["mul_data_input_index"])
                if int(data_input_index) >= len(mul_inputs):
                    constants_applied = False
                    break
                if str(mul_inputs[int(data_input_index)]) != unary_out_name:
                    constants_applied = False
                    break
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )

                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(branch["mul_out_name"]), None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(branch["add_out_name"]), None),
                    perm_nchw_to_nhwc,
                )

                add_op = model_ir.operators[int(branch["add_idx"])]
                canonical_post_output_name = str(branch["post_output_name"])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=add_op,
                    new_outputs=[canonical_post_output_name],
                )

                old_add_out_tensor = model_ir.tensors.get(str(branch["add_out_name"]), None)
                canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
                if old_add_out_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_add_out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_add_out_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_add_out_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_add_out_tensor.shape_signature)]
                        if old_add_out_tensor.shape_signature is not None
                        else [int(v) for v in list(old_add_out_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )
            if not constants_applied:
                continue

            remove_indices: set[int] = {int(pre_idx)}
            for branch in branch_plans:
                remove_indices.add(int(branch["post_idx"]))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_unary_mul_add_transpose_fanout_nhwc_chains": int(optimized)}


def _optimize_transpose_pre_add_reshape_transpose_suffix_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW add bridges that immediately feed [N,C,HW] reshape + [0,2,1] transpose.

    Target:
      a_nhwc --TRANSPOSE(0,3,1,2)--> a_nchw
      b_nhwc --TRANSPOSE(0,3,1,2)--> b_nchw
      ADD(a_nchw, b_nchw) -> y_nchw
      y_nchw --RESHAPE([N,C,HW])--> r
      r --TRANSPOSE([0,2,1])--> z
      (optional legacy users consume y_nchw)

    Rewrite:
      ADD(a_nhwc, b_nhwc) -> y_nhwc
      y_nhwc --RESHAPE([N,HW,C])--> z
      (if legacy users exist, keep one adapter TRANSPOSE(0,3,1,2): y_nhwc -> y_nchw)
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_3d_nchw_to_nhwc = [0, 2, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _maybe_swap_reshape_shape_tensor(
        *,
        reshape_op: OperatorIR,
        reshape_idx: int,
        consumers: Dict[str, List[int]],
    ) -> None:
        if len(reshape_op.inputs) < 2:
            return
        shape_name = str(reshape_op.inputs[1])
        shape_tensor = model_ir.tensors.get(shape_name, None)
        if shape_tensor is None or shape_tensor.data is None:
            return
        shape_data = np.asarray(shape_tensor.data)
        if int(shape_data.size) != 3:
            return
        flat = shape_data.reshape(-1).copy()
        flat[[1, 2]] = flat[[2, 1]]
        swapped = flat.reshape(shape_data.shape).astype(shape_data.dtype, copy=False)

        shape_consumers = [int(v) for v in consumers.get(shape_name, [])]
        if any(int(v) != int(reshape_idx) for v in shape_consumers):
            cloned_name = _unique_tensor_name(f"{shape_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(shape_tensor.dtype),
                shape=[int(v) for v in list(swapped.shape)],
                shape_signature=[int(v) for v in list(swapped.shape)],
                data=np.asarray(swapped),
                is_variable=False,
                quantization=_clone_quantization(shape_tensor.quantization),
            )
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[1] = str(cloned_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
        else:
            shape_tensor.data = np.asarray(swapped)
            shape_tensor.shape = [int(v) for v in list(swapped.shape)]
            shape_tensor.shape_signature = [int(v) for v in list(swapped.shape)]

    def _maybe_swap_reshape_option_shape(reshape_op: OperatorIR) -> None:
        if not isinstance(reshape_op.options, dict):
            return
        opts = dict(reshape_op.options)
        changed = False
        for key in ["newShape", "onnxRawNewShape"]:
            value = opts.get(key, None)
            if not isinstance(value, list) or len(value) != 3:
                continue
            swapped = [value[0], value[2], value[1]]
            if swapped != value:
                opts[key] = [int(v) for v in swapped]
                changed = True
        if changed:
            reshape_op.options = opts

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            add_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_users) == 0:
                continue

            suffix_reshape_idx: Optional[int] = None
            suffix_transpose_idx: Optional[int] = None
            suffix_output_name: Optional[str] = None
            legacy_users: List[int] = []

            valid = True
            for user_idx in add_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "RESHAPE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == add_out_name
                ):
                    reshape_out_name = str(user_op.outputs[0])
                    reshape_users = [
                        int(v)
                        for v in consumers.get(reshape_out_name, [])
                        if int(v) != int(user_idx)
                    ]
                    if len(reshape_users) != 1:
                        legacy_users.append(int(user_idx))
                        continue
                    post_idx = int(reshape_users[0])
                    post_op = model_ir.operators[int(post_idx)]
                    if (
                        str(post_op.op_type) != "TRANSPOSE"
                        or len(post_op.inputs) < 2
                        or len(post_op.outputs) != 1
                        or str(post_op.inputs[0]) != reshape_out_name
                        or _read_transpose_perm(model_ir, post_op) != perm_3d_nchw_to_nhwc
                    ):
                        legacy_users.append(int(user_idx))
                        continue
                    post_out_name = str(post_op.outputs[0])
                    if post_out_name in model_outputs:
                        valid = False
                        break
                    if suffix_reshape_idx is not None:
                        valid = False
                        break
                    suffix_reshape_idx = int(user_idx)
                    suffix_transpose_idx = int(post_idx)
                    suffix_output_name = post_out_name
                else:
                    legacy_users.append(int(user_idx))
            if not valid or suffix_reshape_idx is None or suffix_transpose_idx is None or suffix_output_name is None:
                continue

            input_plans: List[Dict[str, Any]] = []
            can_rewrite_inputs = True
            for input_name in [str(v) for v in list(add_op.inputs)]:
                pre_idx = producers.get(input_name, None)
                if pre_idx is None:
                    can_rewrite_inputs = False
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != input_name
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                    or input_name in model_outputs
                ):
                    can_rewrite_inputs = False
                    break

                input_users = [int(v) for v in consumers.get(input_name, [])]
                if int(add_idx) not in input_users:
                    can_rewrite_inputs = False
                    break
                pre_remove = [int(pre_idx)] if set(input_users) == {int(add_idx)} else []
                input_plans.append(
                    {
                        "nhwc_input_name": str(pre_op.inputs[0]),
                        "pre_remove_indices": pre_remove,
                    }
                )
            if not can_rewrite_inputs:
                continue

            add_nhwc_name = (
                _unique_tensor_name(f"{add_out_name}_nhwc")
                if len(legacy_users) > 0
                else str(add_out_name)
            )
            new_add_inputs = [str(plan["nhwc_input_name"]) for plan in input_plans]
            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=new_add_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_op,
                new_outputs=[add_nhwc_name],
            )

            old_add_tensor = model_ir.tensors.get(add_out_name, None)
            if add_nhwc_name != add_out_name:
                if old_add_tensor is not None and add_nhwc_name not in model_ir.tensors:
                    model_ir.tensors[add_nhwc_name] = TensorIR(
                        name=add_nhwc_name,
                        dtype=str(old_add_tensor.dtype),
                        shape=[int(v) for v in list(old_add_tensor.shape)],
                        shape_signature=(
                            [int(v) for v in list(old_add_tensor.shape_signature)]
                            if old_add_tensor.shape_signature is not None
                            else [int(v) for v in list(old_add_tensor.shape)]
                        ),
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(old_add_tensor.quantization),
                    )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_nhwc_name, None),
                perm_nchw_to_nhwc,
            )

            reshape_op = model_ir.operators[int(suffix_reshape_idx)]
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[0] = add_nhwc_name
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=reshape_op,
                new_outputs=[str(suffix_output_name)],
            )
            _maybe_swap_reshape_shape_tensor(
                reshape_op=reshape_op,
                reshape_idx=int(suffix_reshape_idx),
                consumers=consumers,
            )
            _maybe_swap_reshape_option_shape(reshape_op)

            remove_indices = [int(suffix_transpose_idx)]
            for plan in input_plans:
                remove_indices.extend([int(v) for v in list(plan.get("pre_remove_indices", []))])
            remove_indices = sorted(list(set(remove_indices)), reverse=True)
            removed_before_add = sum(1 for idx in remove_indices if int(idx) < int(add_idx))
            new_add_idx = int(add_idx) - int(removed_before_add)
            for remove_idx in remove_indices:
                if int(remove_idx) == int(add_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            if len(legacy_users) > 0:
                adapter_perm_name = _unique_tensor_name(f"{add_out_name}_adapter_perm")
                model_ir.tensors[adapter_perm_name] = TensorIR(
                    name=adapter_perm_name,
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[add_nhwc_name, adapter_perm_name],
                    outputs=[add_out_name],
                    options={},
                )
                model_ir.operators.insert(int(new_add_idx) + 1, adapter_op)

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_add_reshape_transpose_suffix_nhwc_chains": int(rewritten)}


def _optimize_transpose_pre_add_mulconst_reshape_transpose_suffix_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW add bridges with mul-const inputs that feed [N,C,HW] reshape + [0,2,1] transpose.

    Target:
      a_nhwc --TRANSPOSE(0,3,1,2)--> a_nchw
      b_nhwc --TRANSPOSE(0,3,1,2)--> b_nchw --MUL(const)--> b_scaled_nchw
      ADD(a_nchw, b_scaled_nchw) -> y_nchw
      y_nchw --RESHAPE([N,C,HW])--> r --TRANSPOSE([0,2,1])--> z
      (optional legacy users consume y_nchw)

    Rewrite:
      ADD(a_nhwc, b_scaled_nhwc) -> y_nhwc
      y_nhwc --RESHAPE([N,HW,C])--> z
      (if legacy users exist, keep one adapter TRANSPOSE(0,3,1,2): y_nhwc -> y_nchw)
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_3d_nchw_to_nhwc = [0, 2, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _maybe_swap_reshape_shape_tensor(
        *,
        reshape_op: OperatorIR,
        reshape_idx: int,
        consumers: Dict[str, List[int]],
    ) -> None:
        if len(reshape_op.inputs) < 2:
            return
        shape_name = str(reshape_op.inputs[1])
        shape_tensor = model_ir.tensors.get(shape_name, None)
        if shape_tensor is None or shape_tensor.data is None:
            return
        shape_data = np.asarray(shape_tensor.data)
        if int(shape_data.size) != 3:
            return
        flat = shape_data.reshape(-1).copy()
        flat[[1, 2]] = flat[[2, 1]]
        swapped = flat.reshape(shape_data.shape).astype(shape_data.dtype, copy=False)

        shape_consumers = [int(v) for v in consumers.get(shape_name, [])]
        if any(int(v) != int(reshape_idx) for v in shape_consumers):
            cloned_name = _unique_tensor_name(f"{shape_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(shape_tensor.dtype),
                shape=[int(v) for v in list(swapped.shape)],
                shape_signature=[int(v) for v in list(swapped.shape)],
                data=np.asarray(swapped),
                is_variable=False,
                quantization=_clone_quantization(shape_tensor.quantization),
            )
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[1] = str(cloned_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
        else:
            shape_tensor.data = np.asarray(swapped)
            shape_tensor.shape = [int(v) for v in list(swapped.shape)]
            shape_tensor.shape_signature = [int(v) for v in list(swapped.shape)]

    def _maybe_swap_reshape_option_shape(reshape_op: OperatorIR) -> None:
        if not isinstance(reshape_op.options, dict):
            return
        opts = dict(reshape_op.options)
        changed = False
        for key in ["newShape", "onnxRawNewShape"]:
            value = opts.get(key, None)
            if not isinstance(value, list) or len(value) != 3:
                continue
            swapped = [value[0], value[2], value[1]]
            if swapped != value:
                opts[key] = [int(v) for v in swapped]
                changed = True
        if changed:
            reshape_op.options = opts

    def _analyze_input_plan(
        *,
        input_name: str,
        add_idx: int,
        producers: Dict[str, int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        pre_idx = producers.get(str(input_name), None)
        if pre_idx is not None:
            pre_op = model_ir.operators[int(pre_idx)]
            if (
                str(pre_op.op_type) == "TRANSPOSE"
                and len(pre_op.inputs) >= 2
                and len(pre_op.outputs) == 1
                and str(pre_op.outputs[0]) == str(input_name)
                and _read_transpose_perm(model_ir, pre_op) == perm_nhwc_to_nchw
                and str(input_name) not in model_outputs
            ):
                users = [int(v) for v in consumers.get(str(input_name), [])]
                if int(add_idx) in users:
                    return {
                        "nhwc_input_name": str(pre_op.inputs[0]),
                        "pre_remove_indices": [int(pre_idx)] if set(users) == {int(add_idx)} else [],
                        "mul_plan": None,
                    }

        mul_idx = producers.get(str(input_name), None)
        if mul_idx is None:
            return None
        mul_op = model_ir.operators[int(mul_idx)]
        if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
            return None
        if str(mul_op.outputs[0]) != str(input_name):
            return None
        if str(input_name) in model_outputs:
            return None
        input_users = [int(v) for v in consumers.get(str(input_name), [])]
        if int(add_idx) not in input_users:
            return None

        data_input_index: Optional[int] = None
        side_input_index: Optional[int] = None
        side_input_name: Optional[str] = None
        data_pre_idx: Optional[int] = None
        data_pre_input_name: Optional[str] = None

        for cand_data_idx, cand_side_idx in [(0, 1), (1, 0)]:
            data_name = str(mul_op.inputs[int(cand_data_idx)])
            side_name = str(mul_op.inputs[int(cand_side_idx)])
            side_tensor = model_ir.tensors.get(side_name, None)
            if side_tensor is None or side_tensor.data is None:
                continue
            side_data = np.asarray(side_tensor.data)
            if int(side_data.size) != 1 and side_data.ndim not in {3, 4}:
                continue

            data_prod_idx = producers.get(data_name, None)
            if data_prod_idx is None:
                continue
            data_prod_op = model_ir.operators[int(data_prod_idx)]
            if (
                str(data_prod_op.op_type) != "TRANSPOSE"
                or len(data_prod_op.inputs) < 2
                or len(data_prod_op.outputs) != 1
                or str(data_prod_op.outputs[0]) != data_name
                or _read_transpose_perm(model_ir, data_prod_op) != perm_nhwc_to_nchw
                or str(data_name) in model_outputs
            ):
                continue
            if set(int(v) for v in consumers.get(data_name, [])) != {int(mul_idx)}:
                continue

            data_tensor = model_ir.tensors.get(data_name, None)
            pre_input_name = str(data_prod_op.inputs[0])
            pre_input_tensor = model_ir.tensors.get(pre_input_name, None)
            if data_tensor is None or pre_input_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(list(data_tensor.shape))
                or not _is_fully_known_positive_shape(list(pre_input_tensor.shape))
                or len(list(data_tensor.shape)) != 4
                or len(list(pre_input_tensor.shape)) != 4
            ):
                continue

            if int(side_data.size) != 1:
                if _broadcast_static_shapes(list(data_tensor.shape), [int(v) for v in list(side_data.shape)]) is None:
                    continue

            data_input_index = int(cand_data_idx)
            side_input_index = int(cand_side_idx)
            side_input_name = str(side_name)
            data_pre_idx = int(data_prod_idx)
            data_pre_input_name = str(pre_input_name)
            break

        if (
            data_input_index is None
            or side_input_index is None
            or side_input_name is None
            or data_pre_idx is None
            or data_pre_input_name is None
        ):
            return None

        side_tensor = model_ir.tensors.get(side_input_name, None)
        if side_tensor is None or side_tensor.data is None:
            return None
        side_data = np.asarray(side_tensor.data)
        nhwc_side_data: Optional[np.ndarray] = None
        side_needs_update = False
        if int(side_data.size) != 1:
            target_shape = [int(v) for v in list(model_ir.tensors[str(data_pre_input_name)].shape)]
            side_shape = [int(v) for v in list(side_data.shape)]
            is_nchw_channelwise = (
                int(side_data.ndim) == 4
                and len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 0
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            )
            if is_nchw_channelwise:
                rotated = np.transpose(side_data, axes=perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is None:
                    return None
                nhwc_side_data = np.asarray(rotated)
                side_needs_update = not np.array_equal(nhwc_side_data, side_data)
            elif _broadcast_static_shapes(target_shape, side_shape) is not None:
                nhwc_side_data = np.asarray(side_data)
            else:
                rotated = np.asarray(side_data)
                found = False
                transpose_perm = perm_nchw_to_nhwc if int(rotated.ndim) == 4 else [1, 2, 0]
                max_rotate = 1 if int(rotated.ndim) == 4 else 3
                for _ in range(int(max_rotate)):
                    rotated = np.transpose(rotated, transpose_perm).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                        nhwc_side_data = np.asarray(rotated)
                        side_needs_update = True
                        found = True
                        break
                if not found:
                    return None

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        side_shared_outside_mul = any(int(v) != int(mul_idx) for v in side_users)

        return {
            "nhwc_input_name": str(input_name),
            "pre_remove_indices": [],
            "mul_plan": {
                "mul_idx": int(mul_idx),
                "mul_data_input_index": int(data_input_index),
                "mul_side_input_index": int(side_input_index),
                "mul_side_input_name": str(side_input_name),
                "mul_out_name": str(input_name),
                "data_pre_idx": int(data_pre_idx),
                "data_pre_input_name": str(data_pre_input_name),
                "side_needs_update": bool(side_needs_update),
                "side_shared_outside_mul": bool(side_shared_outside_mul),
                "side_nhwc_data": (None if nhwc_side_data is None else np.asarray(nhwc_side_data)),
            },
        }

    def _apply_mul_plan(*, plan: Dict[str, Any]) -> List[int]:
        mul_idx = int(plan["mul_idx"])
        mul_data_input_index = int(plan["mul_data_input_index"])
        mul_side_input_index = int(plan["mul_side_input_index"])
        mul_side_input_name = str(plan["mul_side_input_name"])
        mul_out_name = str(plan["mul_out_name"])
        data_pre_idx = int(plan["data_pre_idx"])
        data_pre_input_name = str(plan["data_pre_input_name"])

        side_input_name_for_mul = str(mul_side_input_name)
        if bool(plan.get("side_needs_update", False)):
            nhwc_data = np.asarray(plan.get("side_nhwc_data"))
            side_tensor = model_ir.tensors.get(str(mul_side_input_name), None)
            if side_tensor is None:
                return []
            if bool(plan.get("side_shared_outside_mul", False)):
                side_input_name_for_mul = _unique_tensor_name(f"{mul_side_input_name}_nhwc")
                model_ir.tensors[side_input_name_for_mul] = TensorIR(
                    name=side_input_name_for_mul,
                    dtype=str(side_tensor.dtype),
                    shape=[int(v) for v in list(nhwc_data.shape)],
                    shape_signature=[int(v) for v in list(nhwc_data.shape)],
                    data=np.asarray(nhwc_data),
                    is_variable=False,
                    quantization=_clone_quantization(side_tensor.quantization),
                )
            else:
                side_tensor.data = np.asarray(nhwc_data)
                side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
                side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        mul_op = model_ir.operators[int(mul_idx)]
        mul_inputs = [str(v) for v in list(mul_op.inputs)]
        if int(mul_data_input_index) < 0 or int(mul_data_input_index) >= len(mul_inputs):
            return []
        if int(mul_side_input_index) < 0 or int(mul_side_input_index) >= len(mul_inputs):
            return []
        mul_inputs[int(mul_data_input_index)] = str(data_pre_input_name)
        mul_inputs[int(mul_side_input_index)] = str(side_input_name_for_mul)
        _set_operator_inputs(
            model_ir=model_ir,
            op=mul_op,
            new_inputs=mul_inputs,
        )
        _permute_tensor_metadata_if_rank_matches(
            model_ir.tensors.get(mul_out_name, None),
            perm_nchw_to_nhwc,
        )
        return [int(data_pre_idx)]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for add_idx, add_op in enumerate(model_ir.operators):
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue

            add_out_name = str(add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            add_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
            if len(add_users) == 0:
                continue

            suffix_reshape_idx: Optional[int] = None
            suffix_transpose_idx: Optional[int] = None
            suffix_output_name: Optional[str] = None
            legacy_users: List[int] = []
            valid_users = True
            for user_idx in add_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "RESHAPE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == add_out_name
                ):
                    reshape_out_name = str(user_op.outputs[0])
                    reshape_users = [
                        int(v)
                        for v in consumers.get(reshape_out_name, [])
                        if int(v) != int(user_idx)
                    ]
                    if len(reshape_users) != 1:
                        legacy_users.append(int(user_idx))
                        continue
                    post_idx = int(reshape_users[0])
                    post_op = model_ir.operators[int(post_idx)]
                    if (
                        str(post_op.op_type) != "TRANSPOSE"
                        or len(post_op.inputs) < 2
                        or len(post_op.outputs) != 1
                        or str(post_op.inputs[0]) != reshape_out_name
                        or _read_transpose_perm(model_ir, post_op) != perm_3d_nchw_to_nhwc
                    ):
                        legacy_users.append(int(user_idx))
                        continue
                    post_out_name = str(post_op.outputs[0])
                    if post_out_name in model_outputs:
                        valid_users = False
                        break
                    if suffix_reshape_idx is not None:
                        valid_users = False
                        break
                    suffix_reshape_idx = int(user_idx)
                    suffix_transpose_idx = int(post_idx)
                    suffix_output_name = str(post_out_name)
                else:
                    legacy_users.append(int(user_idx))
            if not valid_users or suffix_reshape_idx is None or suffix_transpose_idx is None or suffix_output_name is None:
                continue

            input_plans: List[Dict[str, Any]] = []
            rewritable = True
            for input_name in [str(v) for v in list(add_op.inputs)]:
                plan = _analyze_input_plan(
                    input_name=input_name,
                    add_idx=int(add_idx),
                    producers=producers,
                    consumers=consumers,
                    model_outputs=model_outputs,
                )
                if plan is None:
                    rewritable = False
                    break
                input_plans.append(dict(plan))
            if not rewritable:
                continue

            pre_remove_indices: List[int] = []
            for plan in input_plans:
                mul_plan = plan.get("mul_plan", None)
                if mul_plan is not None:
                    pre_remove_indices.extend(_apply_mul_plan(plan=dict(mul_plan)))
                pre_remove_indices.extend([int(v) for v in list(plan.get("pre_remove_indices", []))])

            add_nhwc_name = (
                _unique_tensor_name(f"{add_out_name}_nhwc")
                if len(legacy_users) > 0
                else str(add_out_name)
            )
            new_add_inputs = [str(plan["nhwc_input_name"]) for plan in input_plans]
            _set_operator_inputs(
                model_ir=model_ir,
                op=add_op,
                new_inputs=new_add_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_op,
                new_outputs=[add_nhwc_name],
            )

            old_add_tensor = model_ir.tensors.get(add_out_name, None)
            if add_nhwc_name != add_out_name:
                if old_add_tensor is not None and add_nhwc_name not in model_ir.tensors:
                    model_ir.tensors[add_nhwc_name] = TensorIR(
                        name=add_nhwc_name,
                        dtype=str(old_add_tensor.dtype),
                        shape=[int(v) for v in list(old_add_tensor.shape)],
                        shape_signature=(
                            [int(v) for v in list(old_add_tensor.shape_signature)]
                            if old_add_tensor.shape_signature is not None
                            else [int(v) for v in list(old_add_tensor.shape)]
                        ),
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(old_add_tensor.quantization),
                    )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(add_nhwc_name, None),
                perm_nchw_to_nhwc,
            )

            reshape_op = model_ir.operators[int(suffix_reshape_idx)]
            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[0] = add_nhwc_name
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=reshape_op,
                new_outputs=[str(suffix_output_name)],
            )
            _maybe_swap_reshape_shape_tensor(
                reshape_op=reshape_op,
                reshape_idx=int(suffix_reshape_idx),
                consumers=consumers,
            )
            _maybe_swap_reshape_option_shape(reshape_op)

            remove_indices = [int(suffix_transpose_idx)]
            remove_indices.extend([int(v) for v in pre_remove_indices])
            remove_indices = sorted(list(set(remove_indices)), reverse=True)
            removed_before_add = sum(1 for idx in remove_indices if int(idx) < int(add_idx))
            new_add_idx = int(add_idx) - int(removed_before_add)
            for remove_idx in remove_indices:
                if int(remove_idx) == int(add_idx):
                    continue
                del model_ir.operators[int(remove_idx)]

            if len(legacy_users) > 0:
                adapter_perm_name = _unique_tensor_name(f"{add_out_name}_adapter_perm")
                model_ir.tensors[adapter_perm_name] = TensorIR(
                    name=adapter_perm_name,
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[add_nhwc_name, adapter_perm_name],
                    outputs=[add_out_name],
                    options={},
                )
                model_ir.operators.insert(int(new_add_idx) + 1, adapter_op)

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_pre_add_mulconst_reshape_transpose_suffix_nhwc_chains": int(rewritten)
    }


def _optimize_transpose_pre_unary_reshape_transpose_suffix_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NHWC->NCHW unary wrappers that immediately feed
    [N,C,HW] reshape + [0,2,1] transpose suffixes.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --UNARY(1-input)-> u_nchw
      u_nchw --RESHAPE([N,C,HW])--> r
      r --TRANSPOSE([0,2,1])--> z

    Rewrite:
      x_nhwc --UNARY(1-input)-> u_nhwc
      u_nhwc --RESHAPE([N,HW,C])--> z

    Extended (pseudo-unary Swish):
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      s_nchw = LOGISTIC(x_nchw)
      y_nchw = MUL(x_nchw, s_nchw)
      y_nchw --RESHAPE([N,C,HW])--> r
      r --TRANSPOSE([0,2,1])--> z

    Rewrite:
      s_nhwc = LOGISTIC(x_nhwc)
      y_nhwc = MUL(x_nhwc, s_nhwc)
      y_nhwc --RESHAPE([N,HW,C])--> z
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_3d_nchw_to_nhwc = [0, 2, 1]
    unary_ops = {
        "RELU",
        "RELU6",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "CAST",
        "FLOOR",
        "CEIL",
        "ROUND",
    }

    def _swap_reshape_shape_tensor(reshape_op: OperatorIR) -> bool:
        if len(reshape_op.inputs) < 2:
            return False
        shape_name = str(reshape_op.inputs[1])
        shape_tensor = model_ir.tensors.get(shape_name, None)
        shape_vals = _read_const_ints_from_tensor(shape_tensor)
        if shape_vals is None or len(shape_vals) != 3:
            return False
        swapped = [int(shape_vals[0]), int(shape_vals[2]), int(shape_vals[1])]
        return _write_const_ints_to_tensor(shape_tensor, swapped)

    def _swap_reshape_option_shape(reshape_op: OperatorIR) -> bool:
        if not isinstance(reshape_op.options, dict):
            return False
        opts = dict(reshape_op.options)
        changed = False
        for key in ["newShape", "onnxRawNewShape"]:
            value = opts.get(key, None)
            if not isinstance(value, list) or len(value) != 3:
                continue
            swapped = [int(value[0]), int(value[2]), int(value[1])]
            if swapped != [int(v) for v in value]:
                opts[key] = swapped
                changed = True
        if changed:
            reshape_op.options = opts
        return changed

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for reshape_idx, reshape_op in enumerate(model_ir.operators):
            if str(reshape_op.op_type) != "RESHAPE" or len(reshape_op.inputs) < 1 or len(reshape_op.outputs) != 1:
                continue

            reshape_in_name = str(reshape_op.inputs[0])
            reshape_out_name = str(reshape_op.outputs[0])
            if reshape_in_name in model_outputs:
                continue

            reshape_users = [int(v) for v in consumers.get(reshape_out_name, [])]
            if len(reshape_users) != 1:
                continue
            post_idx = int(reshape_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != reshape_out_name
                or _read_transpose_perm(model_ir, post_op) != perm_3d_nchw_to_nhwc
            ):
                continue
            post_out_name = str(post_op.outputs[0])
            if reshape_out_name in model_outputs:
                continue

            unary_idx = producers.get(reshape_in_name, None)
            if unary_idx is None:
                continue
            unary_op = model_ir.operators[int(unary_idx)]
            rewrite_kind = ""
            swish_log_idx: Optional[int] = None
            swish_log_op: Optional[OperatorIR] = None
            swish_log_out_name = ""
            swish_mul_data_input_index: Optional[int] = None

            if (
                str(unary_op.op_type) in unary_ops
                and len(unary_op.inputs) == 1
                and len(unary_op.outputs) == 1
                and str(unary_op.outputs[0]) == reshape_in_name
            ):
                rewrite_kind = "unary"
                pre_out_name = str(unary_op.inputs[0])
            elif (
                str(unary_op.op_type) == "MUL"
                and len(unary_op.inputs) == 2
                and len(unary_op.outputs) == 1
                and str(unary_op.outputs[0]) == reshape_in_name
            ):
                mul_inputs = [str(v) for v in unary_op.inputs]
                for log_input_index in [0, 1]:
                    data_input_index = 1 - int(log_input_index)
                    candidate_log_out_name = str(mul_inputs[log_input_index])
                    candidate_pre_out_name = str(mul_inputs[data_input_index])
                    candidate_log_idx = producers.get(candidate_log_out_name, None)
                    if candidate_log_idx is None:
                        continue
                    candidate_log_op = model_ir.operators[int(candidate_log_idx)]
                    if (
                        str(candidate_log_op.op_type) != "LOGISTIC"
                        or len(candidate_log_op.inputs) != 1
                        or len(candidate_log_op.outputs) != 1
                        or str(candidate_log_op.outputs[0]) != candidate_log_out_name
                        or str(candidate_log_op.inputs[0]) != candidate_pre_out_name
                    ):
                        continue
                    candidate_log_users = [int(v) for v in consumers.get(candidate_log_out_name, [])]
                    if set(candidate_log_users) != {int(unary_idx)}:
                        continue
                    rewrite_kind = "swish"
                    pre_out_name = candidate_pre_out_name
                    swish_log_idx = int(candidate_log_idx)
                    swish_log_op = candidate_log_op
                    swish_log_out_name = candidate_log_out_name
                    swish_mul_data_input_index = int(data_input_index)
                    break
            else:
                continue

            if rewrite_kind == "":
                continue

            pre_idx = producers.get(pre_out_name, None)
            if pre_idx is None:
                continue
            pre_op = model_ir.operators[int(pre_idx)]
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or str(pre_op.outputs[0]) != pre_out_name
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue
            pre_in_name = str(pre_op.inputs[0])

            if (
                pre_in_name in model_outputs
                or pre_out_name in model_outputs
                or reshape_in_name in model_outputs
            ):
                continue

            if rewrite_kind == "unary":
                if set(int(v) for v in consumers.get(pre_out_name, [])) != {int(unary_idx)}:
                    continue
            elif rewrite_kind == "swish":
                expected_pre_users = {int(unary_idx), int(swish_log_idx)} if swish_log_idx is not None else {int(unary_idx)}
                if set(int(v) for v in consumers.get(pre_out_name, [])) != expected_pre_users:
                    continue
                if swish_log_out_name == "":
                    continue
                if set(int(v) for v in consumers.get(swish_log_out_name, [])) != {int(unary_idx)}:
                    continue
            else:
                continue
            if set(int(v) for v in consumers.get(reshape_in_name, [])) != {int(reshape_idx)}:
                continue

            shape_changed = _swap_reshape_shape_tensor(reshape_op)
            opts_changed = _swap_reshape_option_shape(reshape_op)
            if not shape_changed and not opts_changed:
                continue

            if rewrite_kind == "unary":
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=unary_op,
                    new_inputs=[pre_in_name],
                )
            else:
                if swish_log_op is None or swish_mul_data_input_index is None:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=swish_log_op,
                    new_inputs=[pre_in_name],
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=unary_op,
                    input_index=int(swish_mul_data_input_index),
                    new_input_name=pre_in_name,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(swish_log_out_name, None),
                    perm_nchw_to_nhwc,
                )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(reshape_in_name, None),
                perm_nchw_to_nhwc,
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=reshape_op,
                new_outputs=[post_out_name],
            )

            old_reshape_out_tensor = model_ir.tensors.get(reshape_out_name, None)
            canonical_tensor = model_ir.tensors.get(post_out_name, None)
            if old_reshape_out_tensor is not None and canonical_tensor is not None:
                canonical_tensor.dtype = str(old_reshape_out_tensor.dtype)
                canonical_tensor.quantization = _clone_quantization(old_reshape_out_tensor.quantization)
                canonical_tensor.shape = [int(v) for v in list(old_reshape_out_tensor.shape)]
                canonical_tensor.shape_signature = (
                    [int(v) for v in list(old_reshape_out_tensor.shape_signature)]
                    if old_reshape_out_tensor.shape_signature is not None
                    else [int(v) for v in list(old_reshape_out_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_tensor,
                    perm_3d_nchw_to_nhwc,
                )

            remove_indices: List[int] = []
            pre_remove_idx = next((idx for idx, op in enumerate(model_ir.operators) if op is pre_op), None)
            if pre_remove_idx is not None:
                remove_indices.append(int(pre_remove_idx))
            post_remove_idx = next((idx for idx, op in enumerate(model_ir.operators) if op is post_op), None)
            if post_remove_idx is not None:
                remove_indices.append(int(post_remove_idx))
            for remove_idx in sorted(set(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_unary_reshape_transpose_suffix_nhwc_chains": int(rewritten)}


def _optimize_transpose_pre_unary_squeeze_transpose_suffix_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NHWC->NCHW unary/Swish wrappers that feed SQUEEZE + [0,2,1] transpose suffix.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --(UNARY | Swish(LOGISTIC+MUL))-> y_nchw
      y_nchw --SQUEEZE(axis in {2,3})--> s
      s --TRANSPOSE([0,2,1])--> z

    Rewrite:
      x_nhwc --(same UNARY/Swish)-> y_nhwc
      y_nhwc --SQUEEZE(mapped axis)-> z
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_3d_nchw_to_nhwc = [0, 2, 1]
    unary_ops = {
        "RELU",
        "RELU6",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "CAST",
        "FLOOR",
        "CEIL",
        "ROUND",
    }

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for squeeze_idx, squeeze_op in enumerate(model_ir.operators):
            if str(squeeze_op.op_type) != "SQUEEZE" or len(squeeze_op.inputs) != 1 or len(squeeze_op.outputs) != 1:
                continue

            squeeze_in_name = str(squeeze_op.inputs[0])
            squeeze_out_name = str(squeeze_op.outputs[0])
            if squeeze_in_name in model_outputs or squeeze_out_name in model_outputs:
                continue

            squeeze_users = [int(v) for v in consumers.get(squeeze_out_name, [])]
            if len(squeeze_users) != 1:
                continue
            post_idx = int(squeeze_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != squeeze_out_name
                or _read_transpose_perm(model_ir, post_op) != perm_3d_nchw_to_nhwc
            ):
                continue
            post_out_name = str(post_op.outputs[0])

            unary_idx = producers.get(squeeze_in_name, None)
            if unary_idx is None:
                continue
            unary_op = model_ir.operators[int(unary_idx)]

            rewrite_kind = ""
            swish_log_idx: Optional[int] = None
            swish_log_op: Optional[OperatorIR] = None
            swish_log_out_name = ""
            swish_mul_data_input_index: Optional[int] = None

            if (
                str(unary_op.op_type) in unary_ops
                and len(unary_op.inputs) == 1
                and len(unary_op.outputs) == 1
                and str(unary_op.outputs[0]) == squeeze_in_name
            ):
                rewrite_kind = "unary"
                pre_out_name = str(unary_op.inputs[0])
            elif (
                str(unary_op.op_type) == "MUL"
                and len(unary_op.inputs) == 2
                and len(unary_op.outputs) == 1
                and str(unary_op.outputs[0]) == squeeze_in_name
            ):
                mul_inputs = [str(v) for v in unary_op.inputs]
                for log_input_index in [0, 1]:
                    data_input_index = 1 - int(log_input_index)
                    candidate_log_out_name = str(mul_inputs[log_input_index])
                    candidate_pre_out_name = str(mul_inputs[data_input_index])
                    candidate_log_idx = producers.get(candidate_log_out_name, None)
                    if candidate_log_idx is None:
                        continue
                    candidate_log_op = model_ir.operators[int(candidate_log_idx)]
                    if (
                        str(candidate_log_op.op_type) != "LOGISTIC"
                        or len(candidate_log_op.inputs) != 1
                        or len(candidate_log_op.outputs) != 1
                        or str(candidate_log_op.outputs[0]) != candidate_log_out_name
                        or str(candidate_log_op.inputs[0]) != candidate_pre_out_name
                    ):
                        continue
                    if set(int(v) for v in consumers.get(candidate_log_out_name, [])) != {int(unary_idx)}:
                        continue
                    rewrite_kind = "swish"
                    pre_out_name = candidate_pre_out_name
                    swish_log_idx = int(candidate_log_idx)
                    swish_log_op = candidate_log_op
                    swish_log_out_name = candidate_log_out_name
                    swish_mul_data_input_index = int(data_input_index)
                    break
            else:
                continue

            if rewrite_kind == "":
                continue

            pre_idx = producers.get(pre_out_name, None)
            if pre_idx is None:
                continue
            pre_op = model_ir.operators[int(pre_idx)]
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or str(pre_op.outputs[0]) != pre_out_name
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue
            pre_in_name = str(pre_op.inputs[0])
            if pre_in_name in model_outputs or pre_out_name in model_outputs:
                continue

            if rewrite_kind == "unary":
                if set(int(v) for v in consumers.get(pre_out_name, [])) != {int(unary_idx)}:
                    continue
            elif rewrite_kind == "swish":
                expected_pre_users = {int(unary_idx), int(swish_log_idx)} if swish_log_idx is not None else {int(unary_idx)}
                if set(int(v) for v in consumers.get(pre_out_name, [])) != expected_pre_users:
                    continue
                if swish_log_out_name == "":
                    continue
                if set(int(v) for v in consumers.get(swish_log_out_name, [])) != {int(unary_idx)}:
                    continue
            else:
                continue

            if set(int(v) for v in consumers.get(squeeze_in_name, [])) != {int(squeeze_idx)}:
                continue
            if set(int(v) for v in consumers.get(squeeze_out_name, [])) != {int(post_idx)}:
                continue

            squeeze_in_tensor = model_ir.tensors.get(squeeze_in_name, None)
            squeeze_out_tensor = model_ir.tensors.get(squeeze_out_name, None)
            if (
                squeeze_in_tensor is None
                or squeeze_out_tensor is None
                or not _is_fully_known_positive_shape(squeeze_in_tensor.shape)
                or not _is_fully_known_positive_shape(squeeze_out_tensor.shape)
            ):
                continue
            squeeze_in_shape = [int(v) for v in list(squeeze_in_tensor.shape)]
            squeeze_out_shape = [int(v) for v in list(squeeze_out_tensor.shape)]
            if len(squeeze_in_shape) != 4 or len(squeeze_out_shape) != 3:
                continue

            squeeze_axis_candidates: List[int] = []
            for axis in range(4):
                if int(squeeze_in_shape[axis]) != 1:
                    continue
                candidate_out_shape = [int(v) for i, v in enumerate(squeeze_in_shape) if int(i) != int(axis)]
                if candidate_out_shape == squeeze_out_shape:
                    squeeze_axis_candidates.append(int(axis))
            if len(squeeze_axis_candidates) != 1:
                continue

            squeeze_axis_nchw = int(squeeze_axis_candidates[0])
            if squeeze_axis_nchw == 2:
                squeeze_axis_nhwc = 1
            elif squeeze_axis_nchw == 3:
                squeeze_axis_nhwc = 2
            else:
                continue

            squeeze_in_shape_nhwc = _permute_shape(squeeze_in_shape, perm_nchw_to_nhwc)
            if (
                squeeze_in_shape_nhwc is None
                or len(squeeze_in_shape_nhwc) != 4
                or int(squeeze_in_shape_nhwc[squeeze_axis_nhwc]) != 1
            ):
                continue

            if rewrite_kind == "unary":
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=unary_op,
                    new_inputs=[pre_in_name],
                )
            else:
                if swish_log_op is None or swish_mul_data_input_index is None:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=swish_log_op,
                    new_inputs=[pre_in_name],
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=unary_op,
                    input_index=int(swish_mul_data_input_index),
                    new_input_name=pre_in_name,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(swish_log_out_name, None),
                    perm_nchw_to_nhwc,
                )

            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(squeeze_in_name, None),
                perm_nchw_to_nhwc,
            )

            squeeze_options = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
            squeeze_options["squeezeDims"] = [int(squeeze_axis_nhwc)]
            squeeze_op.options = squeeze_options

            _set_operator_outputs(
                model_ir=model_ir,
                op=squeeze_op,
                new_outputs=[post_out_name],
            )

            old_squeeze_out_tensor = model_ir.tensors.get(squeeze_out_name, None)
            canonical_tensor = model_ir.tensors.get(post_out_name, None)
            if old_squeeze_out_tensor is not None and canonical_tensor is not None:
                canonical_tensor.dtype = str(old_squeeze_out_tensor.dtype)
                canonical_tensor.quantization = _clone_quantization(old_squeeze_out_tensor.quantization)
                canonical_tensor.shape = [int(v) for v in list(old_squeeze_out_tensor.shape)]
                canonical_tensor.shape_signature = (
                    [int(v) for v in list(old_squeeze_out_tensor.shape_signature)]
                    if old_squeeze_out_tensor.shape_signature is not None
                    else [int(v) for v in list(old_squeeze_out_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_tensor,
                    perm_3d_nchw_to_nhwc,
                )

            remove_indices: List[int] = []
            pre_remove_idx = next((idx for idx, op in enumerate(model_ir.operators) if op is pre_op), None)
            if pre_remove_idx is not None:
                remove_indices.append(int(pre_remove_idx))
            post_remove_idx = next((idx for idx, op in enumerate(model_ir.operators) if op is post_op), None)
            if post_remove_idx is not None:
                remove_indices.append(int(post_remove_idx))
            for remove_idx in sorted(set(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_pre_unary_squeeze_transpose_suffix_nhwc_chains": int(rewritten)}


def _optimize_transpose_reshape_transpose_to_expanddims_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Collapse NHWC->NCHW->RESHAPE->N?HWC wrappers into a single RESHAPE.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --RESHAPE([N,1,C,H,W])--> r
      r      --TRANSPOSE(0,1,3,4,2)--> y

    Rewrite:
      x_nhwc --RESHAPE([N,1,H,W,C])--> y

    This pattern appears in some YOLO heads where layout wrappers are only used
    to insert a singleton anchor axis before 5D decode operations.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_n1chw_to_n1hwc = [0, 1, 3, 4, 2]
    perm_nchw1_to_nhwc1 = [0, 2, 3, 1, 4]
    perm_nhwab_to_nahwb = [0, 3, 1, 2, 4]

    def _dims_compatible(a: int, b: int) -> bool:
        if int(a) < 0 or int(b) < 0:
            return True
        return int(a) == int(b)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            pre_users = [int(v) for v in consumers.get(pre_out_name, [])]
            if len(pre_users) != 1:
                continue
            reshape_idx = int(pre_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 1
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != pre_out_name
            ):
                continue

            reshape_out_name = str(reshape_op.outputs[0])
            reshape_users = [int(v) for v in consumers.get(reshape_out_name, [])]
            if len(reshape_users) != 1:
                continue
            post_idx = int(reshape_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != reshape_out_name
            ):
                continue
            post_perm = _read_transpose_perm(model_ir, post_op)
            if post_perm not in [perm_n1chw_to_n1hwc, perm_nchw1_to_nhwc1]:
                continue

            post_out_name = str(post_op.outputs[0])
            if pre_out_name in model_outputs or reshape_out_name in model_outputs:
                continue
            input_tensor = model_ir.tensors.get(pre_in_name, None)
            pre_out_tensor = model_ir.tensors.get(pre_out_name, None)
            reshape_out_tensor = model_ir.tensors.get(reshape_out_name, None)
            post_out_tensor = model_ir.tensors.get(post_out_name, None)
            if (
                input_tensor is None
                or pre_out_tensor is None
                or reshape_out_tensor is None
                or post_out_tensor is None
            ):
                continue

            in_shape = [int(v) for v in list(input_tensor.shape)]
            pre_out_shape = [int(v) for v in list(pre_out_tensor.shape)]
            reshape_out_shape = [int(v) for v in list(reshape_out_tensor.shape)]
            post_out_shape = [int(v) for v in list(post_out_tensor.shape)]
            if len(in_shape) != 4 or len(pre_out_shape) != 4 or len(reshape_out_shape) != 5 or len(post_out_shape) != 5:
                continue

            n, h, w, c = in_shape
            expected_pre_out = [n, c, h, w]
            if not _shapes_match_if_known(pre_out_shape, expected_pre_out):
                continue
            if post_perm == perm_n1chw_to_n1hwc:
                expected_reshape_out = [n, 1, c, h, w]
                expected_post_out = [n, 1, h, w, c]
                reshape_singleton_axis = 1
                post_singleton_axis = 1
            elif post_perm == perm_nchw1_to_nhwc1:
                expected_reshape_out = [n, c, h, w, 1]
                expected_post_out = [n, h, w, c, 1]
                reshape_singleton_axis = 4
                post_singleton_axis = 4
            else:
                continue

            # Case A:
            #   NHWC -> NCHW -> RESHAPE(insert singleton) -> transpose back
            #   => NHWC -> RESHAPE(insert singleton in NHWC order)
            if (
                _shapes_match_if_known(reshape_out_shape, expected_reshape_out)
                and _shapes_match_if_known(post_out_shape, expected_post_out)
                and _dims_compatible(int(reshape_out_shape[int(reshape_singleton_axis)]), 1)
                and _dims_compatible(int(post_out_shape[int(post_singleton_axis)]), 1)
            ):
                target_shape = [int(v) for v in list(post_out_shape)]
                if len(reshape_op.inputs) >= 2:
                    shape_tensor = model_ir.tensors.get(str(reshape_op.inputs[1]), None)
                    if _read_const_ints_from_tensor(shape_tensor) is None:
                        continue
                    if not _write_const_ints_to_tensor(shape_tensor, target_shape):
                        continue
                if isinstance(reshape_op.options, dict):
                    reshape_opts = dict(reshape_op.options)
                    for key in ["newShape", "onnxRawNewShape"]:
                        if isinstance(reshape_opts.get(key, None), list):
                            reshape_opts[key] = [int(v) for v in target_shape]
                    reshape_op.options = reshape_opts

                _set_operator_inputs(
                    model_ir=model_ir,
                    op=reshape_op,
                    new_inputs=[pre_in_name] + [str(v) for v in list(reshape_op.inputs[1:])],
                )
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=reshape_op,
                    new_outputs=[post_out_name],
                )

                for remove_idx in sorted([int(post_idx), int(pre_idx)], reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            # Case B (YOLO decode style):
            #   NHWC -> NCHW -> RESHAPE([N,A,B,H,W]) -> TRANSPOSE([0,1,3,4,2]) -> [N,A,H,W,B]
            #   => NHWC -> RESHAPE([N,H,W,A,B]) -> TRANSPOSE([0,3,1,2,4]) -> [N,A,H,W,B]
            if post_perm == perm_n1chw_to_n1hwc:
                a = int(reshape_out_shape[1])
                b = int(reshape_out_shape[2])
                rh = int(reshape_out_shape[3])
                rw = int(reshape_out_shape[4])
                expected_post_out_factorized = [n, a, h, w, b]
                if not _shapes_match_if_known(post_out_shape, expected_post_out_factorized):
                    continue
                if not _dims_compatible(rh, h) or not _dims_compatible(rw, w):
                    continue
                if int(c) > 0 and int(a) > 0 and int(b) > 0 and int(c) != int(a) * int(b):
                    continue

                target_reshape_shape = [int(n), int(h), int(w), int(a), int(b)]
                if len(reshape_op.inputs) < 2:
                    continue
                reshape_shape_tensor = model_ir.tensors.get(str(reshape_op.inputs[1]), None)
                if _read_const_ints_from_tensor(reshape_shape_tensor) is None:
                    continue
                if not _write_const_ints_to_tensor(reshape_shape_tensor, target_reshape_shape):
                    continue

                if isinstance(reshape_op.options, dict):
                    reshape_opts = dict(reshape_op.options)
                    for key in ["newShape", "onnxRawNewShape"]:
                        if isinstance(reshape_opts.get(key, None), list):
                            reshape_opts[key] = [int(v) for v in target_reshape_shape]
                    reshape_op.options = reshape_opts

                if len(post_op.inputs) < 2:
                    continue
                post_perm_tensor = model_ir.tensors.get(str(post_op.inputs[1]), None)
                if _read_const_ints_from_tensor(post_perm_tensor) is None:
                    continue
                if not _write_const_ints_to_tensor(post_perm_tensor, perm_nhwab_to_nahwb):
                    continue

                reshape_shape_norm, reshape_signature_norm = normalize_onnx_shape(target_reshape_shape)
                reshape_out_tensor.shape = [int(v) for v in reshape_shape_norm]
                reshape_out_tensor.shape_signature = [int(v) for v in reshape_signature_norm]

                _set_operator_inputs(
                    model_ir=model_ir,
                    op=reshape_op,
                    new_inputs=[pre_in_name] + [str(v) for v in list(reshape_op.inputs[1:])],
                )
                del model_ir.operators[int(pre_idx)]

                rewritten += 1
                changed = True
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_reshape_transpose_to_expanddims_nhwc_chains": int(rewritten)
    }


def _optimize_transpose_reshape_transpose_to_flatten_hw_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Collapse NHWC->NCHW->RESHAPE->TRANSPOSE flatten wrappers into one RESHAPE.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --RESHAPE([N,C,H*W])--> r
      r      --TRANSPOSE(0,2,1)--> y  (shape [N,H*W,C])

    Rewrite:
      x_nhwc --RESHAPE([N,H*W,C])--> y
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_ncw_to_nwc = [0, 2, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            pre_users = [int(v) for v in consumers.get(pre_out_name, [])]
            if len(pre_users) != 1:
                continue
            reshape_idx = int(pre_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 2
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != pre_out_name
            ):
                continue

            reshape_out_name = str(reshape_op.outputs[0])
            reshape_users = [int(v) for v in consumers.get(reshape_out_name, [])]
            if len(reshape_users) != 1:
                continue
            post_idx = int(reshape_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != reshape_out_name
            ):
                continue
            if _read_transpose_perm(model_ir, post_op) != perm_ncw_to_nwc:
                continue

            post_out_name = str(post_op.outputs[0])
            if pre_out_name in model_outputs or reshape_out_name in model_outputs:
                continue

            in_tensor = model_ir.tensors.get(pre_in_name, None)
            pre_out_tensor = model_ir.tensors.get(pre_out_name, None)
            reshape_out_tensor = model_ir.tensors.get(reshape_out_name, None)
            post_out_tensor = model_ir.tensors.get(post_out_name, None)
            if (
                in_tensor is None
                or pre_out_tensor is None
                or reshape_out_tensor is None
                or post_out_tensor is None
            ):
                continue

            if (
                not _is_fully_known_positive_shape(in_tensor.shape)
                or not _is_fully_known_positive_shape(pre_out_tensor.shape)
                or not _is_fully_known_positive_shape(reshape_out_tensor.shape)
                or not _is_fully_known_positive_shape(post_out_tensor.shape)
            ):
                continue

            in_shape = [int(v) for v in list(in_tensor.shape)]
            pre_out_shape = [int(v) for v in list(pre_out_tensor.shape)]
            reshape_out_shape = [int(v) for v in list(reshape_out_tensor.shape)]
            post_out_shape = [int(v) for v in list(post_out_tensor.shape)]
            if len(in_shape) != 4 or len(pre_out_shape) != 4 or len(reshape_out_shape) != 3 or len(post_out_shape) != 3:
                continue

            n, h, w, c = in_shape
            if pre_out_shape != [n, c, h, w]:
                continue
            hw = int(h) * int(w)
            if reshape_out_shape != [n, c, hw]:
                continue
            if post_out_shape != [n, hw, c]:
                continue

            shape_tensor = model_ir.tensors.get(str(reshape_op.inputs[1]), None)
            if _read_const_ints_from_tensor(shape_tensor) is None:
                continue
            target_shape = [int(n), int(hw), int(c)]
            if not _write_const_ints_to_tensor(shape_tensor, target_shape):
                continue

            if isinstance(reshape_op.options, dict):
                reshape_opts = dict(reshape_op.options)
                for key in ["newShape", "onnxRawNewShape"]:
                    if isinstance(reshape_opts.get(key, None), list):
                        reshape_opts[key] = [int(v) for v in target_shape]
                reshape_op.options = reshape_opts

            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=[pre_in_name] + [str(v) for v in list(reshape_op.inputs[1:])],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=reshape_op,
                new_outputs=[post_out_name],
            )

            for remove_idx in sorted([int(post_idx), int(pre_idx)], reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_reshape_transpose_to_flatten_hw_nhwc_chains": int(rewritten)
    }


def _optimize_reshape_transpose_reshape_transpose_to_nhwc_reshape_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Collapse rank-3 -> rank-4 layout shims into a single NHWC reshape.

    Target:
      x --RESHAPE([N,S,C,1])--> r1
        --TRANSPOSE([0,3,2,1])--> t1
        --RESHAPE([N,C,H,W])--> r2
        --TRANSPOSE([0,2,3,1])--> y

    Rewrite:
      x --RESHAPE([N,H,W,C])--> y

    with S == H * W.
    """
    rewritten = 0
    perm_nsc1_to_n1cs = [0, 3, 2, 1]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        serial = 1
        while name in model_ir.tensors:
            name = f"{base}_{serial}"
            serial += 1
        return name

    def _set_reshape_shape_input(
        *,
        reshape_op: OperatorIR,
        reshape_idx: int,
        consumers: Dict[str, List[int]],
        target_shape: List[int],
    ) -> bool:
        if len(reshape_op.inputs) < 2:
            return False
        shape_name = str(reshape_op.inputs[1])
        shape_tensor = model_ir.tensors.get(shape_name, None)
        if shape_tensor is None:
            return False
        shape_users = set(int(v) for v in consumers.get(shape_name, []))
        target = [int(v) for v in list(target_shape)]
        if shape_users == {int(reshape_idx)}:
            return _write_const_ints_to_tensor(shape_tensor, target)

        np_dtype = np.int32
        dtype_name = str(shape_tensor.dtype)
        if shape_tensor.data is not None:
            try:
                np_dtype = np.asarray(shape_tensor.data).dtype
            except Exception:
                np_dtype = np.int32
        new_shape_name = _unique_tensor_name(f"{shape_name}_nhwc")
        model_ir.tensors[new_shape_name] = TensorIR(
            name=new_shape_name,
            dtype=dtype_name,
            shape=[int(len(target))],
            shape_signature=[int(len(target))],
            data=np.asarray(target, dtype=np_dtype),
            is_variable=False,
            quantization=_clone_quantization(shape_tensor.quantization),
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=reshape_op,
            input_index=1,
            new_input_name=new_shape_name,
        )
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for reshape1_idx, reshape1_op in enumerate(model_ir.operators):
            if str(reshape1_op.op_type) != "RESHAPE" or len(reshape1_op.inputs) < 2 or len(reshape1_op.outputs) != 1:
                continue

            input_name = str(reshape1_op.inputs[0])
            reshape1_out_name = str(reshape1_op.outputs[0])
            if reshape1_out_name in model_outputs:
                continue

            reshape1_users = [int(v) for v in consumers.get(reshape1_out_name, [])]
            if len(reshape1_users) != 1:
                continue
            transpose1_idx = int(reshape1_users[0])
            transpose1_op = model_ir.operators[int(transpose1_idx)]
            if (
                str(transpose1_op.op_type) != "TRANSPOSE"
                or len(transpose1_op.inputs) < 2
                or len(transpose1_op.outputs) != 1
                or str(transpose1_op.inputs[0]) != reshape1_out_name
                or _read_transpose_perm(model_ir, transpose1_op) != perm_nsc1_to_n1cs
            ):
                continue

            transpose1_out_name = str(transpose1_op.outputs[0])
            if transpose1_out_name in model_outputs:
                continue
            transpose1_users = [int(v) for v in consumers.get(transpose1_out_name, [])]
            if len(transpose1_users) != 1:
                continue
            reshape2_idx = int(transpose1_users[0])
            reshape2_op = model_ir.operators[int(reshape2_idx)]
            if (
                str(reshape2_op.op_type) != "RESHAPE"
                or len(reshape2_op.inputs) < 2
                or len(reshape2_op.outputs) != 1
                or str(reshape2_op.inputs[0]) != transpose1_out_name
            ):
                continue

            reshape2_out_name = str(reshape2_op.outputs[0])
            if reshape2_out_name in model_outputs:
                continue
            reshape2_users = [int(v) for v in consumers.get(reshape2_out_name, [])]
            if len(reshape2_users) != 1:
                continue
            transpose2_idx = int(reshape2_users[0])
            transpose2_op = model_ir.operators[int(transpose2_idx)]
            if (
                str(transpose2_op.op_type) != "TRANSPOSE"
                or len(transpose2_op.inputs) < 2
                or len(transpose2_op.outputs) != 1
                or str(transpose2_op.inputs[0]) != reshape2_out_name
                or _read_transpose_perm(model_ir, transpose2_op) != perm_nchw_to_nhwc
            ):
                continue

            output_name = str(transpose2_op.outputs[0])
            in_tensor = model_ir.tensors.get(input_name, None)
            reshape1_out_tensor = model_ir.tensors.get(reshape1_out_name, None)
            transpose1_out_tensor = model_ir.tensors.get(transpose1_out_name, None)
            reshape2_out_tensor = model_ir.tensors.get(reshape2_out_name, None)
            output_tensor = model_ir.tensors.get(output_name, None)
            if (
                in_tensor is None
                or reshape1_out_tensor is None
                or transpose1_out_tensor is None
                or reshape2_out_tensor is None
                or output_tensor is None
            ):
                continue
            if (
                not _is_fully_known_positive_shape(in_tensor.shape)
                or not _is_fully_known_positive_shape(reshape1_out_tensor.shape)
                or not _is_fully_known_positive_shape(transpose1_out_tensor.shape)
                or not _is_fully_known_positive_shape(reshape2_out_tensor.shape)
                or not _is_fully_known_positive_shape(output_tensor.shape)
            ):
                continue

            in_shape = [int(v) for v in list(in_tensor.shape)]
            reshape1_shape = [int(v) for v in list(reshape1_out_tensor.shape)]
            transpose1_shape = [int(v) for v in list(transpose1_out_tensor.shape)]
            reshape2_shape = [int(v) for v in list(reshape2_out_tensor.shape)]
            output_shape = [int(v) for v in list(output_tensor.shape)]
            if (
                len(in_shape) != 3
                or len(reshape1_shape) != 4
                or len(transpose1_shape) != 4
                or len(reshape2_shape) != 4
                or len(output_shape) != 4
            ):
                continue

            n, s, c = [int(v) for v in list(in_shape)]
            if reshape1_shape != [int(n), int(s), int(c), 1]:
                continue
            if transpose1_shape != [int(n), 1, int(c), int(s)]:
                continue

            n2, c2, h, w = [int(v) for v in list(reshape2_shape)]
            if n2 != n or c2 != c:
                continue
            if int(h) <= 0 or int(w) <= 0 or int(s) != int(h) * int(w):
                continue
            if output_shape != [int(n), int(h), int(w), int(c)]:
                continue

            target_shape = [int(n), int(h), int(w), int(c)]
            if not _set_reshape_shape_input(
                reshape_op=reshape1_op,
                reshape_idx=int(reshape1_idx),
                consumers=consumers,
                target_shape=target_shape,
            ):
                continue

            if isinstance(reshape1_op.options, dict):
                reshape_opts = dict(reshape1_op.options)
                for key in ["newShape", "onnxRawNewShape"]:
                    if isinstance(reshape_opts.get(key, None), list):
                        reshape_opts[key] = [int(v) for v in list(target_shape)]
                reshape1_op.options = reshape_opts

            _set_operator_outputs(
                model_ir=model_ir,
                op=reshape1_op,
                new_outputs=[str(output_name)],
            )

            for remove_idx in sorted([int(transpose2_idx), int(reshape2_idx), int(transpose1_idx)], reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_reshape_transpose_reshape_transpose_to_nhwc_reshape_chains": int(rewritten)}


def _optimize_attention_qkv_reshape_transpose_reshape_to_reshape_transpose_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Reduce QKV-style `RESHAPE -> TRANSPOSE -> RESHAPE` rank adapters.

    Target:
      x[A,1,C] --RESHAPE([A,H,D])--> r
               --TRANSPOSE([1,0,2])--> t
               --RESHAPE([1,H,A,D])--> y
    or
      x[A,1,C] --RESHAPE([A,H,D])--> r
               --TRANSPOSE([1,2,0])--> t
               --RESHAPE([1,H,D,A])--> y

    Rewrite:
      x[A,1,C] --RESHAPE([1,A,H,D])--> r'
               --TRANSPOSE([0,2,1,3] or [0,2,3,1])--> y
    """
    rewritten = 0
    rank3_perm_had = [1, 0, 2]
    rank3_perm_hda = [1, 2, 0]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        serial = 1
        while name in model_ir.tensors:
            name = f"{base}_{serial}"
            serial += 1
        return name

    def _set_const_input(
        *,
        op: OperatorIR,
        op_idx: int,
        input_index: int,
        consumers: Dict[str, List[int]],
        values: List[int],
        base_suffix: str,
    ) -> bool:
        if int(input_index) >= len(op.inputs):
            return False
        input_name = str(op.inputs[int(input_index)])
        input_tensor = model_ir.tensors.get(input_name, None)
        if input_tensor is None:
            return False
        target_vals = [int(v) for v in list(values)]
        input_users = set(int(v) for v in consumers.get(input_name, []))
        if input_users == {int(op_idx)}:
            return _write_const_ints_to_tensor(input_tensor, target_vals)

        np_dtype = np.int32
        if input_tensor.data is not None:
            try:
                np_dtype = np.asarray(input_tensor.data).dtype
            except Exception:
                np_dtype = np.int32
        cloned_name = _unique_tensor_name(f"{input_name}_{base_suffix}")
        model_ir.tensors[cloned_name] = TensorIR(
            name=cloned_name,
            dtype=str(input_tensor.dtype),
            shape=[int(len(target_vals))],
            shape_signature=[int(len(target_vals))],
            data=np.asarray(target_vals, dtype=np_dtype),
            is_variable=False,
            quantization=_clone_quantization(input_tensor.quantization),
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=op,
            input_index=int(input_index),
            new_input_name=cloned_name,
        )
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for reshape1_idx, reshape1_op in enumerate(model_ir.operators):
            if str(reshape1_op.op_type) != "RESHAPE" or len(reshape1_op.inputs) < 2 or len(reshape1_op.outputs) != 1:
                continue

            reshape1_in_name = str(reshape1_op.inputs[0])
            reshape1_out_name = str(reshape1_op.outputs[0])
            if reshape1_out_name in model_outputs:
                continue

            reshape1_users = [int(v) for v in consumers.get(reshape1_out_name, [])]
            if len(reshape1_users) != 1:
                continue
            transpose_idx = int(reshape1_users[0])
            transpose_op = model_ir.operators[int(transpose_idx)]
            if (
                str(transpose_op.op_type) != "TRANSPOSE"
                or len(transpose_op.inputs) < 2
                or len(transpose_op.outputs) != 1
                or str(transpose_op.inputs[0]) != str(reshape1_out_name)
            ):
                continue

            transpose_perm = _read_transpose_perm(model_ir, transpose_op)
            if transpose_perm not in [rank3_perm_had, rank3_perm_hda]:
                continue

            transpose_out_name = str(transpose_op.outputs[0])
            if transpose_out_name in model_outputs:
                continue
            transpose_users = [int(v) for v in consumers.get(transpose_out_name, [])]
            if len(transpose_users) != 1:
                continue
            reshape2_idx = int(transpose_users[0])
            reshape2_op = model_ir.operators[int(reshape2_idx)]
            if (
                str(reshape2_op.op_type) != "RESHAPE"
                or len(reshape2_op.inputs) < 2
                or len(reshape2_op.outputs) != 1
                or str(reshape2_op.inputs[0]) != str(transpose_out_name)
            ):
                continue

            reshape2_out_name = str(reshape2_op.outputs[0])

            reshape1_in_tensor = model_ir.tensors.get(reshape1_in_name, None)
            reshape1_out_tensor = model_ir.tensors.get(reshape1_out_name, None)
            transpose_out_tensor = model_ir.tensors.get(transpose_out_name, None)
            reshape2_out_tensor = model_ir.tensors.get(reshape2_out_name, None)
            if (
                reshape1_in_tensor is None
                or reshape1_out_tensor is None
                or transpose_out_tensor is None
                or reshape2_out_tensor is None
            ):
                continue
            if (
                not _is_fully_known_positive_shape(reshape1_in_tensor.shape)
                or not _is_fully_known_positive_shape(reshape1_out_tensor.shape)
                or not _is_fully_known_positive_shape(transpose_out_tensor.shape)
                or not _is_fully_known_positive_shape(reshape2_out_tensor.shape)
            ):
                continue

            in_shape = [int(v) for v in list(reshape1_in_tensor.shape)]
            reshape1_shape = [int(v) for v in list(reshape1_out_tensor.shape)]
            transpose_shape = [int(v) for v in list(transpose_out_tensor.shape)]
            reshape2_shape = [int(v) for v in list(reshape2_out_tensor.shape)]
            if len(in_shape) != 3 or len(reshape1_shape) != 3 or len(transpose_shape) != 3 or len(reshape2_shape) != 4:
                continue

            a, b, c = [int(v) for v in list(in_shape)]
            if int(b) != 1:
                continue
            if int(reshape1_shape[0]) != int(a):
                continue
            h = int(reshape1_shape[1])
            d = int(reshape1_shape[2])
            if int(h) <= 0 or int(d) <= 0:
                continue
            if int(h) * int(d) != int(c):
                continue

            if transpose_perm == rank3_perm_had:
                if transpose_shape != [int(h), int(a), int(d)]:
                    continue
                if reshape2_shape != [1, int(h), int(a), int(d)]:
                    continue
                new_transpose_perm = [0, 2, 1, 3]
            else:
                if transpose_shape != [int(h), int(d), int(a)]:
                    continue
                if reshape2_shape != [1, int(h), int(d), int(a)]:
                    continue
                new_transpose_perm = [0, 2, 3, 1]

            new_reshape_shape = [1, int(a), int(h), int(d)]
            if not _set_const_input(
                op=reshape1_op,
                op_idx=int(reshape1_idx),
                input_index=1,
                consumers=consumers,
                values=new_reshape_shape,
                base_suffix="qkv_shape",
            ):
                continue
            if not _set_const_input(
                op=transpose_op,
                op_idx=int(transpose_idx),
                input_index=1,
                consumers=consumers,
                values=new_transpose_perm,
                base_suffix="qkv_perm",
            ):
                continue

            if isinstance(reshape1_op.options, dict):
                reshape_opts = dict(reshape1_op.options)
                for key in ["newShape", "onnxRawNewShape"]:
                    if isinstance(reshape_opts.get(key, None), list):
                        reshape_opts[key] = [int(v) for v in list(new_reshape_shape)]
                reshape1_op.options = reshape_opts

            _set_operator_outputs(
                model_ir=model_ir,
                op=transpose_op,
                new_outputs=[str(reshape2_out_name)],
            )

            reshape1_out_tensor.shape = [int(v) for v in list(new_reshape_shape)]
            reshape1_out_tensor.shape_signature = [int(v) for v in list(new_reshape_shape)]
            reshape2_out_tensor.shape = [int(v) for v in list(reshape2_shape)]
            reshape2_out_tensor.shape_signature = [int(v) for v in list(reshape2_shape)]

            del model_ir.operators[int(reshape2_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_attention_qkv_reshape_transpose_reshape_to_reshape_transpose_chains": int(rewritten)}


def _optimize_attention_gather_transpose_reshape_cleanup_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Simplify redundant attention tail chains around Gather/Transpose/Reshape.

    Pattern A:
      x[1,H,T,D] --GATHER(axis=0,index=0)--> [H,T,D]
               --TRANSPOSE([1,0,2])--> [T,H,D]
               --RESHAPE([1,1,T,H*D])--> y
      =>
      x --TRANSPOSE([0,2,1,3])--> [1,T,H,D] --RESHAPE([1,1,T,H*D])--> y

    Pattern B:
      x[1,1,T,C] --GATHER(axis=0,index=0)--> [1,T,C]
                --GATHER(axis=0,index=0)--> [T,C]
                --RESHAPE([1,1,T,C])--> y
      =>
      identity (replace y with x)
    """
    rewritten_pattern_a = 0
    rewritten_pattern_b = 0

    def _normalize_axis(axis: int, rank: int) -> int:
        axis_i = int(axis)
        if axis_i < 0:
            axis_i += int(rank)
        return int(axis_i)

    def _is_zero_index_tensor(tensor: Optional[TensorIR]) -> bool:
        vals = _read_const_ints_from_tensor(tensor)
        if vals is None or len(vals) <= 0:
            return False
        return all(int(v) == 0 for v in list(vals))

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        serial = 1
        while name in model_ir.tensors:
            name = f"{base}_{serial}"
            serial += 1
        return name

    def _set_const_input_with_clone(
        *,
        op: OperatorIR,
        op_idx: int,
        input_index: int,
        consumers: Dict[str, List[int]],
        values: List[int],
        suffix: str,
    ) -> bool:
        if int(input_index) >= len(op.inputs):
            return False
        input_name = str(op.inputs[int(input_index)])
        input_tensor = model_ir.tensors.get(input_name, None)
        if input_tensor is None:
            return False

        target_values = [int(v) for v in list(values)]
        users = set(int(v) for v in consumers.get(input_name, []))
        if users == {int(op_idx)}:
            return _write_const_ints_to_tensor(input_tensor, target_values)

        np_dtype = np.int32
        if input_tensor.data is not None:
            try:
                np_dtype = np.asarray(input_tensor.data).dtype
            except Exception:
                np_dtype = np.int32
        cloned_name = _unique_tensor_name(f"{input_name}_{suffix}")
        model_ir.tensors[cloned_name] = TensorIR(
            name=cloned_name,
            dtype=str(input_tensor.dtype),
            shape=[int(len(target_values))],
            shape_signature=[int(len(target_values))],
            data=np.asarray(target_values, dtype=np_dtype),
            is_variable=False,
            quantization=_clone_quantization(input_tensor.quantization),
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=op,
            input_index=int(input_index),
            new_input_name=cloned_name,
        )
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        # Pattern B: double-gather + reshape back to original shape => identity.
        for gather0_idx, gather0_op in enumerate(model_ir.operators):
            if str(gather0_op.op_type) != "GATHER" or len(gather0_op.inputs) < 2 or len(gather0_op.outputs) != 1:
                continue
            gather0_in_name = str(gather0_op.inputs[0])
            gather0_out_name = str(gather0_op.outputs[0])
            if gather0_out_name in model_outputs:
                continue

            gather0_in_tensor = model_ir.tensors.get(gather0_in_name, None)
            gather0_out_tensor = model_ir.tensors.get(gather0_out_name, None)
            if gather0_in_tensor is None or gather0_out_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(gather0_in_tensor.shape)
                or not _is_fully_known_positive_shape(gather0_out_tensor.shape)
            ):
                continue
            in0_shape = [int(v) for v in list(gather0_in_tensor.shape)]
            out0_shape = [int(v) for v in list(gather0_out_tensor.shape)]
            if len(in0_shape) < 2 or len(out0_shape) != len(in0_shape) - 1:
                continue
            axis0 = _normalize_axis(int(gather0_op.options.get("axis", 0)), len(in0_shape))
            if axis0 != 0 or int(in0_shape[0]) != 1:
                continue
            if not _is_zero_index_tensor(model_ir.tensors.get(str(gather0_op.inputs[1]), None)):
                continue

            gather0_users = [int(v) for v in consumers.get(gather0_out_name, [])]
            if len(gather0_users) != 1:
                continue
            gather1_idx = int(gather0_users[0])
            gather1_op = model_ir.operators[int(gather1_idx)]
            if (
                str(gather1_op.op_type) != "GATHER"
                or len(gather1_op.inputs) < 2
                or len(gather1_op.outputs) != 1
                or str(gather1_op.inputs[0]) != gather0_out_name
            ):
                continue
            gather1_out_name = str(gather1_op.outputs[0])
            if gather1_out_name in model_outputs:
                continue
            gather1_out_tensor = model_ir.tensors.get(gather1_out_name, None)
            if gather1_out_tensor is None or not _is_fully_known_positive_shape(gather1_out_tensor.shape):
                continue
            out1_shape = [int(v) for v in list(gather1_out_tensor.shape)]
            if len(out1_shape) != len(out0_shape) - 1:
                continue
            axis1 = _normalize_axis(int(gather1_op.options.get("axis", 0)), len(out0_shape))
            if axis1 != 0 or int(out0_shape[0]) != 1:
                continue
            if not _is_zero_index_tensor(model_ir.tensors.get(str(gather1_op.inputs[1]), None)):
                continue

            gather1_users = [int(v) for v in consumers.get(gather1_out_name, [])]
            if len(gather1_users) != 1:
                continue
            reshape_idx = int(gather1_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 2
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != gather1_out_name
            ):
                continue
            reshape_out_name = str(reshape_op.outputs[0])
            if reshape_out_name in model_outputs:
                continue

            target_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(reshape_op.inputs[1]), None))
            if target_vals is None or len(target_vals) != len(in0_shape):
                continue
            target_shape = [int(v) for v in list(target_vals)]
            if target_shape != [int(v) for v in list(in0_shape)]:
                continue

            _replace_tensor_inputs(model_ir, str(reshape_out_name), str(gather0_in_name))
            for remove_idx in sorted([int(reshape_idx), int(gather1_idx), int(gather0_idx)], reverse=True):
                del model_ir.operators[int(remove_idx)]
            rewritten_pattern_b += 1
            changed = True
            break

        if changed:
            continue

        # Pattern A: gather(strip axis-0 singleton) + transpose + reshape -> transpose(rank4) + reshape
        for gather_idx, gather_op in enumerate(model_ir.operators):
            if str(gather_op.op_type) != "GATHER" or len(gather_op.inputs) < 2 or len(gather_op.outputs) != 1:
                continue
            gather_in_name = str(gather_op.inputs[0])
            gather_out_name = str(gather_op.outputs[0])
            if gather_out_name in model_outputs:
                continue

            gather_in_tensor = model_ir.tensors.get(gather_in_name, None)
            gather_out_tensor = model_ir.tensors.get(gather_out_name, None)
            if gather_in_tensor is None or gather_out_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(gather_in_tensor.shape)
                or not _is_fully_known_positive_shape(gather_out_tensor.shape)
            ):
                continue
            in_shape = [int(v) for v in list(gather_in_tensor.shape)]
            out_shape = [int(v) for v in list(gather_out_tensor.shape)]
            if len(in_shape) != 4 or len(out_shape) != 3:
                continue
            axis = _normalize_axis(int(gather_op.options.get("axis", 0)), len(in_shape))
            if axis != 0 or int(in_shape[0]) != 1:
                continue
            if not _is_zero_index_tensor(model_ir.tensors.get(str(gather_op.inputs[1]), None)):
                continue
            if out_shape != [int(in_shape[1]), int(in_shape[2]), int(in_shape[3])]:
                continue

            gather_users = [int(v) for v in consumers.get(gather_out_name, [])]
            if len(gather_users) != 1:
                continue
            transpose_idx = int(gather_users[0])
            transpose_op = model_ir.operators[int(transpose_idx)]
            if (
                str(transpose_op.op_type) != "TRANSPOSE"
                or len(transpose_op.inputs) < 2
                or len(transpose_op.outputs) != 1
                or str(transpose_op.inputs[0]) != gather_out_name
                or _read_transpose_perm(model_ir, transpose_op) != [1, 0, 2]
            ):
                continue

            transpose_out_name = str(transpose_op.outputs[0])
            if transpose_out_name in model_outputs:
                continue
            transpose_out_tensor = model_ir.tensors.get(transpose_out_name, None)
            if transpose_out_tensor is None or not _is_fully_known_positive_shape(transpose_out_tensor.shape):
                continue
            if [int(v) for v in list(transpose_out_tensor.shape)] != [int(in_shape[2]), int(in_shape[1]), int(in_shape[3])]:
                continue

            transpose_users = [int(v) for v in consumers.get(transpose_out_name, [])]
            if len(transpose_users) != 1:
                continue
            reshape_idx = int(transpose_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 2
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != transpose_out_name
            ):
                continue

            reshape_shape_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(reshape_op.inputs[1]), None))
            if reshape_shape_vals is None or len(reshape_shape_vals) != 4:
                continue
            expected_last = int(in_shape[1]) * int(in_shape[3])
            expected_shape = [1, 1, int(in_shape[2]), int(expected_last)]
            if [int(v) for v in list(reshape_shape_vals)] != [int(v) for v in list(expected_shape)]:
                continue

            if not _set_const_input_with_clone(
                op=transpose_op,
                op_idx=int(transpose_idx),
                input_index=1,
                consumers=consumers,
                values=[0, 2, 1, 3],
                suffix="qkv_perm4",
            ):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=transpose_op,
                new_inputs=[str(gather_in_name), str(transpose_op.inputs[1])],
            )

            transpose_out_tensor.shape = [1, int(in_shape[2]), int(in_shape[1]), int(in_shape[3])]
            transpose_out_tensor.shape_signature = [1, int(in_shape[2]), int(in_shape[1]), int(in_shape[3])]
            if isinstance(transpose_op.options, dict):
                opts = dict(transpose_op.options)
                for key in ["perm", "onnxPerm"]:
                    if isinstance(opts.get(key, None), list):
                        opts[key] = [0, 2, 1, 3]
                transpose_op.options = opts

            del model_ir.operators[int(gather_idx)]
            rewritten_pattern_a += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_attention_gather_transpose_reshape_cleanup_pattern_a": int(rewritten_pattern_a),
        "optimized_attention_gather_transpose_reshape_cleanup_pattern_b": int(rewritten_pattern_b),
    }


def _optimize_gather_axis0_singleton_to_reshape_input_chains(
    model_ir: ModelIR,
    *,
    layout_state: Optional[LayoutState] = None,
) -> Dict[str, int]:
    return _optimize_gather_axis0_singleton_to_reshape_input_chains_pass(
        model_ir,
        layout_state=layout_state,
    )


def _optimize_attention_preproj_reshape_to_batchmatmul_ranklift_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Lift pre-projection RESHAPE rank before attention Q/K projections.

    Target:
      x[1,1,T,C] --RESHAPE([T,1,C])--> r
      r --BATCH_MATMUL(W_i[C,K_i])--> y_i[T,1,K_i]
      y_i --(ADD/SUB/MUL/DIV + bias)--> z_i[T,1,K_i]
      z_i --RESHAPE([1,T,H,D])--> ...

    Rewrite:
      x --BATCH_MATMUL(W_i)--> y_i'[1,1,T,K_i]
      (same binary op, same tail reshape)
    and remove the leading RESHAPE.
    """
    rewritten = 0
    binary_ops = {"ADD", "SUB", "MUL", "DIV"}

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for reshape_idx, reshape_op in enumerate(model_ir.operators):
            if str(reshape_op.op_type) != "RESHAPE" or len(reshape_op.inputs) < 2 or len(reshape_op.outputs) != 1:
                continue
            reshape_in_name = str(reshape_op.inputs[0])
            reshape_out_name = str(reshape_op.outputs[0])
            if reshape_out_name in model_outputs:
                continue

            reshape_in_tensor = model_ir.tensors.get(reshape_in_name, None)
            reshape_out_tensor = model_ir.tensors.get(reshape_out_name, None)
            if reshape_in_tensor is None or reshape_out_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(reshape_in_tensor.shape)
                or not _is_fully_known_positive_shape(reshape_out_tensor.shape)
            ):
                continue
            in_shape = [int(v) for v in list(reshape_in_tensor.shape)]
            out_shape = [int(v) for v in list(reshape_out_tensor.shape)]
            if len(in_shape) != 4 or len(out_shape) != 3:
                continue
            if int(in_shape[0]) != 1 or int(in_shape[1]) != 1:
                continue

            t_dim = int(in_shape[2])
            c_dim = int(in_shape[3])
            if out_shape != [int(t_dim), 1, int(c_dim)]:
                continue
            target_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(reshape_op.inputs[1]), None))
            if target_vals is None or [int(v) for v in list(target_vals)] != [int(t_dim), 1, int(c_dim)]:
                continue

            bmm_indices = [int(v) for v in consumers.get(reshape_out_name, [])]
            if len(bmm_indices) <= 0:
                continue

            branch_specs: List[Tuple[int, int, int]] = []
            valid = True
            for bmm_idx in bmm_indices:
                bmm_op = model_ir.operators[int(bmm_idx)]
                if (
                    str(bmm_op.op_type) != "BATCH_MATMUL"
                    or len(bmm_op.inputs) < 2
                    or len(bmm_op.outputs) != 1
                    or str(bmm_op.inputs[0]) != str(reshape_out_name)
                ):
                    valid = False
                    break
                bmm_out_name = str(bmm_op.outputs[0])
                if bmm_out_name in model_outputs:
                    valid = False
                    break
                bmm_out_tensor = model_ir.tensors.get(bmm_out_name, None)
                rhs_tensor = model_ir.tensors.get(str(bmm_op.inputs[1]), None)
                if (
                    bmm_out_tensor is None
                    or rhs_tensor is None
                    or not _is_fully_known_positive_shape(bmm_out_tensor.shape)
                    or not _is_fully_known_positive_shape(rhs_tensor.shape)
                ):
                    valid = False
                    break
                rhs_shape = [int(v) for v in list(rhs_tensor.shape)]
                bmm_out_shape = [int(v) for v in list(bmm_out_tensor.shape)]
                if len(rhs_shape) != 2 or int(rhs_shape[0]) != int(c_dim):
                    valid = False
                    break
                k_dim = int(rhs_shape[1])
                if bmm_out_shape != [int(t_dim), 1, int(k_dim)]:
                    valid = False
                    break

                bmm_users = [int(v) for v in consumers.get(bmm_out_name, [])]
                if len(bmm_users) != 1:
                    valid = False
                    break
                binary_idx = int(bmm_users[0])
                binary_op = model_ir.operators[int(binary_idx)]
                if (
                    str(binary_op.op_type) not in binary_ops
                    or len(binary_op.inputs) < 2
                    or len(binary_op.outputs) != 1
                ):
                    valid = False
                    break
                if bmm_out_name not in [str(binary_op.inputs[0]), str(binary_op.inputs[1])]:
                    valid = False
                    break
                binary_out_name = str(binary_op.outputs[0])
                if binary_out_name in model_outputs:
                    valid = False
                    break
                binary_out_tensor = model_ir.tensors.get(binary_out_name, None)
                if (
                    binary_out_tensor is None
                    or not _is_fully_known_positive_shape(binary_out_tensor.shape)
                    or [int(v) for v in list(binary_out_tensor.shape)] != [int(t_dim), 1, int(k_dim)]
                ):
                    valid = False
                    break

                binary_users = [int(v) for v in consumers.get(binary_out_name, [])]
                if len(binary_users) != 1:
                    valid = False
                    break
                tail_reshape_idx = int(binary_users[0])
                tail_reshape_op = model_ir.operators[int(tail_reshape_idx)]
                if (
                    str(tail_reshape_op.op_type) != "RESHAPE"
                    or len(tail_reshape_op.inputs) < 2
                    or len(tail_reshape_op.outputs) != 1
                    or str(tail_reshape_op.inputs[0]) != str(binary_out_name)
                ):
                    valid = False
                    break
                tail_target_vals = _read_const_ints_from_tensor(
                    model_ir.tensors.get(str(tail_reshape_op.inputs[1]), None)
                )
                if tail_target_vals is None or len(tail_target_vals) != 4:
                    valid = False
                    break
                tail_target = [int(v) for v in list(tail_target_vals)]
                if tail_target[0] != 1 or tail_target[1] != int(t_dim):
                    valid = False
                    break
                if int(tail_target[2]) * int(tail_target[3]) != int(k_dim):
                    valid = False
                    break

                branch_specs.append((int(bmm_idx), int(binary_idx), int(k_dim)))

            if not valid or len(branch_specs) <= 0:
                continue

            # Rewrite all BATCH_MATMUL inputs and rank metadata.
            for bmm_idx, binary_idx, k_dim in branch_specs:
                bmm_op = model_ir.operators[int(bmm_idx)]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=bmm_op,
                    new_inputs=[str(reshape_in_name), str(bmm_op.inputs[1])],
                )
                bmm_out_name = str(bmm_op.outputs[0])
                bmm_out_tensor = model_ir.tensors.get(bmm_out_name, None)
                if bmm_out_tensor is not None:
                    bmm_out_tensor.shape = [1, 1, int(t_dim), int(k_dim)]
                    bmm_out_tensor.shape_signature = [1, 1, int(t_dim), int(k_dim)]

                binary_op = model_ir.operators[int(binary_idx)]
                binary_out_name = str(binary_op.outputs[0])
                binary_out_tensor = model_ir.tensors.get(binary_out_name, None)
                if binary_out_tensor is not None:
                    binary_out_tensor.shape = [1, 1, int(t_dim), int(k_dim)]
                    binary_out_tensor.shape_signature = [1, 1, int(t_dim), int(k_dim)]

            del model_ir.operators[int(reshape_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_attention_preproj_reshape_to_batchmatmul_ranklift_chains": int(rewritten)}


def _optimize_window_partition_reshape_transpose_to_space_to_depth_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Replace Swin-like window-partition wrappers with SPACE_TO_DEPTH.

    Target:
      x[N,H,W,C]
        --RESHAPE([N,OH,BS,OW,BS,C])--> r1
        --TRANSPOSE([0,1,3,2,4,5])--> t1
        --RESHAPE([N*OH*OW, BS*BS, C])--> y

    Rewrite:
      x --SPACE_TO_DEPTH(blockSize=BS)--> s2d [N,OH,OW,BS*BS*C]
      s2d --RESHAPE([N*OH*OW, BS*BS, C])--> y
    """
    rewritten = 0
    target_perm = [0, 1, 3, 2, 4, 5]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for reshape1_idx, reshape1_op in enumerate(model_ir.operators):
            if str(reshape1_op.op_type) != "RESHAPE" or len(reshape1_op.inputs) < 2 or len(reshape1_op.outputs) != 1:
                continue

            input_name = str(reshape1_op.inputs[0])
            reshape1_out_name = str(reshape1_op.outputs[0])
            if reshape1_out_name in model_outputs:
                continue

            input_tensor = model_ir.tensors.get(input_name, None)
            reshape1_out_tensor = model_ir.tensors.get(reshape1_out_name, None)
            if input_tensor is None or reshape1_out_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(input_tensor.shape)
                or not _is_fully_known_positive_shape(reshape1_out_tensor.shape)
            ):
                continue

            in_shape = [int(v) for v in list(input_tensor.shape)]
            r1_shape = [int(v) for v in list(reshape1_out_tensor.shape)]
            if len(in_shape) != 4 or len(r1_shape) != 6:
                continue

            n, h, w, c = [int(v) for v in list(in_shape)]
            n1, oh, bs_h, ow, bs_w, c1 = [int(v) for v in list(r1_shape)]
            if int(n1) != int(n) or int(c1) != int(c):
                continue
            if int(bs_h) <= 1 or int(bs_w) <= 1 or int(bs_h) != int(bs_w):
                continue
            bs = int(bs_h)
            if int(oh) * int(bs) != int(h) or int(ow) * int(bs) != int(w):
                continue

            reshape1_target = _read_const_ints_from_tensor(model_ir.tensors.get(str(reshape1_op.inputs[1]), None))
            if reshape1_target is None or [int(v) for v in list(reshape1_target)] != [int(v) for v in list(r1_shape)]:
                continue

            reshape1_users = [int(v) for v in consumers.get(reshape1_out_name, [])]
            if len(reshape1_users) != 1:
                continue
            transpose_idx = int(reshape1_users[0])
            transpose_op = model_ir.operators[int(transpose_idx)]
            if (
                str(transpose_op.op_type) != "TRANSPOSE"
                or len(transpose_op.inputs) < 2
                or len(transpose_op.outputs) != 1
                or str(transpose_op.inputs[0]) != str(reshape1_out_name)
                or _read_transpose_perm(model_ir, transpose_op) != target_perm
            ):
                continue

            transpose_out_name = str(transpose_op.outputs[0])
            if transpose_out_name in model_outputs:
                continue
            transpose_out_tensor = model_ir.tensors.get(transpose_out_name, None)
            if transpose_out_tensor is None or not _is_fully_known_positive_shape(transpose_out_tensor.shape):
                continue
            transpose_shape = [int(v) for v in list(transpose_out_tensor.shape)]
            expected_transpose_shape = [int(n), int(oh), int(ow), int(bs), int(bs), int(c)]
            if transpose_shape != expected_transpose_shape:
                continue

            transpose_users = [int(v) for v in consumers.get(transpose_out_name, [])]
            if len(transpose_users) != 1:
                continue
            reshape2_idx = int(transpose_users[0])
            reshape2_op = model_ir.operators[int(reshape2_idx)]
            if (
                str(reshape2_op.op_type) != "RESHAPE"
                or len(reshape2_op.inputs) < 2
                or len(reshape2_op.outputs) != 1
                or str(reshape2_op.inputs[0]) != str(transpose_out_name)
            ):
                continue

            reshape2_target = _read_const_ints_from_tensor(model_ir.tensors.get(str(reshape2_op.inputs[1]), None))
            expected_reshape2 = [int(n) * int(oh) * int(ow), int(bs) * int(bs), int(c)]
            if reshape2_target is None or [int(v) for v in list(reshape2_target)] != expected_reshape2:
                continue

            # Convert TRANSPOSE op in-place to SPACE_TO_DEPTH and bypass first RESHAPE.
            transpose_op.op_type = "SPACE_TO_DEPTH"
            _set_operator_inputs(
                model_ir=model_ir,
                op=transpose_op,
                new_inputs=[str(input_name)],
            )
            transpose_op.options = {"blockSize": int(bs)}

            s2d_shape = [int(n), int(oh), int(ow), int(bs) * int(bs) * int(c)]
            transpose_out_tensor.shape = [int(v) for v in list(s2d_shape)]
            transpose_out_tensor.shape_signature = [int(v) for v in list(s2d_shape)]

            del model_ir.operators[int(reshape1_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_window_partition_reshape_transpose_to_space_to_depth_chains": int(rewritten)}


def _optimize_window_reverse_reshape_transpose_to_depth_to_space_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Replace Swin-like window-reverse wrappers with DEPTH_TO_SPACE.

    Target:
      x[NW, BS*BS, C]
        --RESHAPE([N,OH,OW,BS,BS,C])--> r1
        --TRANSPOSE([0,1,3,2,4,5])--> t1
        --RESHAPE([N,OH*BS,OW*BS,C])--> y

    Rewrite:
      x --RESHAPE([N,OH,OW,BS*BS*C])--> r1'
      r1' --DEPTH_TO_SPACE(blockSize=BS)--> y
    """
    rewritten = 0
    target_perm = [0, 1, 3, 2, 4, 5]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        serial = 1
        while name in model_ir.tensors:
            name = f"{base}_{serial}"
            serial += 1
        return name

    def _set_const_input_with_clone(
        *,
        op: OperatorIR,
        op_idx: int,
        input_index: int,
        consumers: Dict[str, List[int]],
        values: List[int],
        suffix: str,
    ) -> bool:
        if int(input_index) >= len(op.inputs):
            return False
        input_name = str(op.inputs[int(input_index)])
        input_tensor = model_ir.tensors.get(input_name, None)
        if input_tensor is None:
            return False

        target_values = [int(v) for v in list(values)]
        users = set(int(v) for v in consumers.get(input_name, []))
        if users == {int(op_idx)}:
            return _write_const_ints_to_tensor(input_tensor, target_values)

        np_dtype = np.int32
        if input_tensor.data is not None:
            try:
                np_dtype = np.asarray(input_tensor.data).dtype
            except Exception:
                np_dtype = np.int32
        cloned_name = _unique_tensor_name(f"{input_name}_{suffix}")
        model_ir.tensors[cloned_name] = TensorIR(
            name=cloned_name,
            dtype=str(input_tensor.dtype),
            shape=[int(len(target_values))],
            shape_signature=[int(len(target_values))],
            data=np.asarray(target_values, dtype=np_dtype),
            is_variable=False,
            quantization=_clone_quantization(input_tensor.quantization),
        )
        _replace_operator_input_at(
            model_ir=model_ir,
            op=op,
            input_index=int(input_index),
            new_input_name=cloned_name,
        )
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for reshape1_idx, reshape1_op in enumerate(model_ir.operators):
            if str(reshape1_op.op_type) != "RESHAPE" or len(reshape1_op.inputs) < 2 or len(reshape1_op.outputs) != 1:
                continue

            input_name = str(reshape1_op.inputs[0])
            reshape1_out_name = str(reshape1_op.outputs[0])
            if reshape1_out_name in model_outputs:
                continue

            input_tensor = model_ir.tensors.get(input_name, None)
            reshape1_out_tensor = model_ir.tensors.get(reshape1_out_name, None)
            if input_tensor is None or reshape1_out_tensor is None:
                continue
            if (
                not _is_fully_known_positive_shape(input_tensor.shape)
                or not _is_fully_known_positive_shape(reshape1_out_tensor.shape)
            ):
                continue

            in_shape = [int(v) for v in list(input_tensor.shape)]
            r1_shape = [int(v) for v in list(reshape1_out_tensor.shape)]
            if len(in_shape) != 3 or len(r1_shape) != 6:
                continue

            nw, ws2, c = [int(v) for v in list(in_shape)]
            n, oh, ow, bs_h, bs_w, c1 = [int(v) for v in list(r1_shape)]
            if int(c1) != int(c):
                continue
            if int(bs_h) <= 1 or int(bs_w) <= 1 or int(bs_h) != int(bs_w):
                continue
            bs = int(bs_h)
            if int(ws2) != int(bs) * int(bs):
                continue
            if int(nw) != int(n) * int(oh) * int(ow):
                continue

            reshape1_target = _read_const_ints_from_tensor(model_ir.tensors.get(str(reshape1_op.inputs[1]), None))
            if reshape1_target is None or [int(v) for v in list(reshape1_target)] != [int(v) for v in list(r1_shape)]:
                continue

            reshape1_users = [int(v) for v in consumers.get(reshape1_out_name, [])]
            if len(reshape1_users) != 1:
                continue
            transpose_idx = int(reshape1_users[0])
            transpose_op = model_ir.operators[int(transpose_idx)]
            if (
                str(transpose_op.op_type) != "TRANSPOSE"
                or len(transpose_op.inputs) < 2
                or len(transpose_op.outputs) != 1
                or str(transpose_op.inputs[0]) != str(reshape1_out_name)
                or _read_transpose_perm(model_ir, transpose_op) != target_perm
            ):
                continue

            transpose_out_name = str(transpose_op.outputs[0])
            if transpose_out_name in model_outputs:
                continue
            transpose_out_tensor = model_ir.tensors.get(transpose_out_name, None)
            if transpose_out_tensor is None or not _is_fully_known_positive_shape(transpose_out_tensor.shape):
                continue
            transpose_shape = [int(v) for v in list(transpose_out_tensor.shape)]
            expected_transpose_shape = [int(n), int(oh), int(bs), int(ow), int(bs), int(c)]
            if transpose_shape != expected_transpose_shape:
                continue

            transpose_users = [int(v) for v in consumers.get(transpose_out_name, [])]
            if len(transpose_users) != 1:
                continue
            reshape2_idx = int(transpose_users[0])
            reshape2_op = model_ir.operators[int(reshape2_idx)]
            if (
                str(reshape2_op.op_type) != "RESHAPE"
                or len(reshape2_op.inputs) < 2
                or len(reshape2_op.outputs) != 1
                or str(reshape2_op.inputs[0]) != str(transpose_out_name)
            ):
                continue

            reshape2_out_name = str(reshape2_op.outputs[0])
            reshape2_target = _read_const_ints_from_tensor(model_ir.tensors.get(str(reshape2_op.inputs[1]), None))
            expected_h = int(oh) * int(bs)
            expected_w = int(ow) * int(bs)
            expected_reshape2 = [int(n), int(expected_h), int(expected_w), int(c)]
            if reshape2_target is None or [int(v) for v in list(reshape2_target)] != expected_reshape2:
                continue

            reshape2_out_tensor = model_ir.tensors.get(reshape2_out_name, None)
            if (
                reshape2_out_tensor is None
                or not _is_fully_known_positive_shape(reshape2_out_tensor.shape)
                or [int(v) for v in list(reshape2_out_tensor.shape)] != expected_reshape2
            ):
                continue

            new_reshape1_shape = [int(n), int(oh), int(ow), int(bs) * int(bs) * int(c)]
            if not _set_const_input_with_clone(
                op=reshape1_op,
                op_idx=int(reshape1_idx),
                input_index=1,
                consumers=consumers,
                values=new_reshape1_shape,
                suffix="d2s_shape",
            ):
                continue

            if isinstance(reshape1_op.options, dict):
                reshape_opts = dict(reshape1_op.options)
                for key in ["newShape", "onnxRawNewShape"]:
                    if isinstance(reshape_opts.get(key, None), list):
                        reshape_opts[key] = [int(v) for v in list(new_reshape1_shape)]
                reshape1_op.options = reshape_opts

            reshape1_out_tensor.shape = [int(v) for v in list(new_reshape1_shape)]
            reshape1_out_tensor.shape_signature = [int(v) for v in list(new_reshape1_shape)]

            transpose_op.op_type = "DEPTH_TO_SPACE"
            _set_operator_inputs(
                model_ir=model_ir,
                op=transpose_op,
                new_inputs=[str(reshape1_out_name)],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=transpose_op,
                new_outputs=[str(reshape2_out_name)],
            )
            transpose_op.options = {"blockSize": int(bs)}

            del model_ir.operators[int(reshape2_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_window_reverse_reshape_transpose_to_depth_to_space_chains": int(rewritten)}


def _optimize_transpose_squeeze_unary_expanddims_transpose_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Collapse Conv1D-shim transpose wrappers around unary activations.

    Target:
      x_nhwc --T(0,3,1,2)--> x_nchw
             --SQUEEZE(axis=k)--> s
             --UNARY--> u
             --EXPAND_DIMS(axis=k)--> e
             --T(0,2,3,1)--> y_nhwc

    Rewrite:
      x_nhwc --UNARY--> y_nhwc

    Safety:
    - Strict linear chain (single consumer on every intermediate).
    - Canonical NHWC<->NCHW transpose pair only.
    - SQUEEZE and EXPAND_DIMS axes must match and round-trip rank-4 shape.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "GELU",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "CAST",
        "FLOOR",
        "CEIL",
        "ROUND",
        "HARD_SWISH",
    }

    def _shape_list(name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or tensor.shape is None:
            return None
        return [int(v) for v in list(tensor.shape)]

    def _dims_compatible(a: int, b: int) -> bool:
        if int(a) < 0 or int(b) < 0:
            return True
        return int(a) == int(b)

    def _shape_compatible(a: List[int], b: List[int]) -> bool:
        if len(a) != len(b):
            return False
        return all(_dims_compatible(int(x), int(y)) for x, y in zip(a, b))

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue
            squeeze_idx = int(pre_users[0])
            squeeze_op = model_ir.operators[int(squeeze_idx)]
            if (
                str(squeeze_op.op_type) != "SQUEEZE"
                or len(squeeze_op.inputs) != 1
                or len(squeeze_op.outputs) != 1
                or str(squeeze_op.inputs[0]) != pre_output_name
            ):
                continue
            squeeze_out_name = str(squeeze_op.outputs[0])
            if squeeze_out_name in model_outputs:
                continue

            squeeze_users = [int(v) for v in consumers.get(squeeze_out_name, [])]
            if len(squeeze_users) != 1:
                continue
            unary_idx = int(squeeze_users[0])
            unary_op = model_ir.operators[int(unary_idx)]
            if (
                str(unary_op.op_type) not in unary_ops
                or len(unary_op.inputs) != 1
                or len(unary_op.outputs) != 1
                or str(unary_op.inputs[0]) != squeeze_out_name
            ):
                continue
            unary_out_name = str(unary_op.outputs[0])
            if unary_out_name in model_outputs:
                continue

            unary_users = [int(v) for v in consumers.get(unary_out_name, [])]
            if len(unary_users) != 1:
                continue
            expand_idx = int(unary_users[0])
            expand_op = model_ir.operators[int(expand_idx)]
            if (
                str(expand_op.op_type) != "EXPAND_DIMS"
                or len(expand_op.inputs) < 2
                or len(expand_op.outputs) != 1
                or str(expand_op.inputs[0]) != unary_out_name
            ):
                continue
            expand_out_name = str(expand_op.outputs[0])
            if expand_out_name in model_outputs:
                continue

            expand_users = [int(v) for v in consumers.get(expand_out_name, [])]
            if len(expand_users) != 1:
                continue
            post_idx = int(expand_users[0])
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != expand_out_name
            ):
                continue
            if _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc:
                continue
            post_output_name = str(post_op.outputs[0])

            pre_input_shape = _shape_list(pre_input_name)
            pre_output_shape = _shape_list(pre_output_name)
            squeeze_out_shape = _shape_list(squeeze_out_name)
            unary_out_shape = _shape_list(unary_out_name)
            expand_out_shape = _shape_list(expand_out_name)
            post_output_shape = _shape_list(post_output_name)
            if (
                pre_input_shape is None
                or pre_output_shape is None
                or squeeze_out_shape is None
                or unary_out_shape is None
                or expand_out_shape is None
                or post_output_shape is None
            ):
                continue
            if (
                len(pre_input_shape) != 4
                or len(pre_output_shape) != 4
                or len(squeeze_out_shape) != 3
                or len(unary_out_shape) != 3
                or len(expand_out_shape) != 4
                or len(post_output_shape) != 4
            ):
                continue
            if not _shape_compatible(squeeze_out_shape, unary_out_shape):
                continue
            if not _shape_compatible(pre_output_shape, expand_out_shape):
                continue
            if not _shape_compatible(pre_input_shape, post_output_shape):
                continue

            squeeze_axis: Optional[int] = None
            squeeze_options = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
            if "squeezeDims" in squeeze_options:
                raw_axes = np.asarray(squeeze_options.get("squeezeDims", []), dtype=np.int64).reshape(-1)
                normalized_axes = _normalize_squeeze_axes_for_rank(
                    [int(v) for v in raw_axes.tolist()],
                    4,
                )
                if normalized_axes is None or len(normalized_axes) != 1:
                    continue
                candidate_axis = int(normalized_axes[0])
                if int(pre_output_shape[candidate_axis]) != 1:
                    continue
                candidate_squeezed = [
                    int(pre_output_shape[idx])
                    for idx in range(4)
                    if int(idx) != int(candidate_axis)
                ]
                if not _shape_compatible(candidate_squeezed, squeeze_out_shape):
                    continue
                squeeze_axis = int(candidate_axis)
            else:
                candidate_axes: List[int] = []
                for axis in range(4):
                    if int(pre_output_shape[axis]) != 1:
                        continue
                    candidate_squeezed = [
                        int(pre_output_shape[idx])
                        for idx in range(4)
                        if int(idx) != int(axis)
                    ]
                    if _shape_compatible(candidate_squeezed, squeeze_out_shape):
                        candidate_axes.append(int(axis))
                if len(candidate_axes) != 1:
                    continue
                squeeze_axis = int(candidate_axes[0])

            expand_axis_values = _read_const_ints_from_tensor(
                model_ir.tensors.get(str(expand_op.inputs[1]), None)
            )
            if expand_axis_values is None or len(expand_axis_values) != 1:
                continue
            expand_axis = int(expand_axis_values[0])
            if expand_axis < 0:
                expand_axis += 4
            if expand_axis < 0 or expand_axis >= 4:
                continue
            if int(expand_axis) != int(squeeze_axis):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=unary_op,
                new_inputs=[pre_input_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=unary_op,
                new_outputs=[post_output_name],
            )

            old_unary_tensor = model_ir.tensors.get(unary_out_name, None)
            post_output_tensor = model_ir.tensors.get(post_output_name, None)
            if old_unary_tensor is not None and post_output_tensor is not None:
                post_output_tensor.dtype = str(old_unary_tensor.dtype)
                post_output_tensor.quantization = _clone_quantization(old_unary_tensor.quantization)

            remove_indices = sorted(
                list({int(pre_idx), int(squeeze_idx), int(expand_idx), int(post_idx)}),
                reverse=True,
            )
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_squeeze_unary_expanddims_transpose_nhwc_chains": int(rewritten)
    }


def _optimize_transpose_unary_transpose_reshape_expanddims_transpose_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Collapse unary Conv1D-shim wrappers with an intermediate rank-4 transpose.

    Target:
      x_nhwc --T(0,3,1,2)--> x_nchw
             --UNARY--> u_nchw
             --T(0,2,1,3)--> t
             --RESHAPE([H,C,W])--> r3
             --EXPAND_DIMS(axis=2)--> e4
             --T(0,2,3,1)--> y

    Rewrite:
      x_nhwc --UNARY--> u_nhwc
             --RESHAPE([H,W,C])--> r3'
             --EXPAND_DIMS(axis=1)--> y
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nhcw_from_nchw = [0, 2, 1, 3]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_hcw_to_hwc = [0, 2, 1]
    unary_ops = {
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "GELU",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "CAST",
        "FLOOR",
        "CEIL",
        "ROUND",
        "HARD_SWISH",
    }

    def _shape_list(name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or tensor.shape is None:
            return None
        return [int(v) for v in list(tensor.shape)]

    def _dims_compatible(a: int, b: int) -> bool:
        if int(a) < 0 or int(b) < 0:
            return True
        return int(a) == int(b)

    def _shape_compatible(a: List[int], b: List[int]) -> bool:
        if len(a) != len(b):
            return False
        return all(_dims_compatible(int(x), int(y)) for x, y in zip(a, b))

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _swap_rank3_shape_in_reshape(reshape_op: OperatorIR) -> bool:
        changed = False
        if len(reshape_op.inputs) >= 2:
            shape_tensor = model_ir.tensors.get(str(reshape_op.inputs[1]), None)
            shape_vals = _read_const_ints_from_tensor(shape_tensor)
            if shape_vals is not None and len(shape_vals) == 3:
                swapped = [int(shape_vals[0]), int(shape_vals[2]), int(shape_vals[1])]
                if swapped != [int(v) for v in list(shape_vals)]:
                    changed = _write_const_ints_to_tensor(shape_tensor, swapped) or changed
        if isinstance(reshape_op.options, dict):
            opts = dict(reshape_op.options)
            opts_changed = False
            for key in ["newShape", "onnxRawNewShape"]:
                value = opts.get(key, None)
                if not isinstance(value, list) or len(value) != 3:
                    continue
                swapped = [int(value[0]), int(value[2]), int(value[1])]
                if swapped != [int(v) for v in list(value)]:
                    opts[key] = swapped
                    opts_changed = True
            if opts_changed:
                reshape_op.options = opts
                changed = True
        return bool(changed)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue

            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            if pre_out_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_out_name, [])]
            if len(pre_users) != 1:
                continue
            unary_idx = int(pre_users[0])
            unary_op = model_ir.operators[int(unary_idx)]
            if (
                str(unary_op.op_type) not in unary_ops
                or len(unary_op.inputs) != 1
                or len(unary_op.outputs) != 1
                or str(unary_op.inputs[0]) != pre_out_name
            ):
                continue
            unary_out_name = str(unary_op.outputs[0])
            if unary_out_name in model_outputs:
                continue

            unary_users = [int(v) for v in consumers.get(unary_out_name, [])]
            if len(unary_users) != 1:
                continue
            mid_idx = int(unary_users[0])
            mid_op = model_ir.operators[int(mid_idx)]
            if (
                str(mid_op.op_type) != "TRANSPOSE"
                or len(mid_op.inputs) < 2
                or len(mid_op.outputs) != 1
                or str(mid_op.inputs[0]) != unary_out_name
                or _read_transpose_perm(model_ir, mid_op) != perm_nhcw_from_nchw
            ):
                continue
            mid_out_name = str(mid_op.outputs[0])
            if mid_out_name in model_outputs:
                continue

            mid_users = [int(v) for v in consumers.get(mid_out_name, [])]
            if len(mid_users) != 1:
                continue
            reshape_idx = int(mid_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 1
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != mid_out_name
            ):
                continue
            reshape_out_name = str(reshape_op.outputs[0])
            if reshape_out_name in model_outputs:
                continue

            reshape_users = [int(v) for v in consumers.get(reshape_out_name, [])]
            if len(reshape_users) < 1:
                continue
            expand_idx: Optional[int] = None
            post_idx: Optional[int] = None
            expand_op: Optional[OperatorIR] = None
            post_op: Optional[OperatorIR] = None
            expand_out_name = ""
            post_out_name = ""
            for candidate_expand_idx in reshape_users:
                candidate_expand_op = model_ir.operators[int(candidate_expand_idx)]
                if (
                    str(candidate_expand_op.op_type) != "EXPAND_DIMS"
                    or len(candidate_expand_op.inputs) < 2
                    or len(candidate_expand_op.outputs) != 1
                    or str(candidate_expand_op.inputs[0]) != reshape_out_name
                ):
                    continue
                candidate_expand_axis_values = _read_const_ints_from_tensor(
                    model_ir.tensors.get(str(candidate_expand_op.inputs[1]), None)
                )
                if candidate_expand_axis_values is None or len(candidate_expand_axis_values) != 1:
                    continue
                candidate_expand_axis = int(candidate_expand_axis_values[0])
                if candidate_expand_axis < 0:
                    candidate_expand_axis += 4
                if int(candidate_expand_axis) != 2:
                    continue
                candidate_expand_out_name = str(candidate_expand_op.outputs[0])
                if candidate_expand_out_name in model_outputs:
                    continue
                candidate_expand_users = [int(v) for v in consumers.get(candidate_expand_out_name, [])]
                if len(candidate_expand_users) != 1:
                    continue
                candidate_post_idx = int(candidate_expand_users[0])
                candidate_post_op = model_ir.operators[int(candidate_post_idx)]
                if (
                    str(candidate_post_op.op_type) != "TRANSPOSE"
                    or len(candidate_post_op.inputs) < 2
                    or len(candidate_post_op.outputs) != 1
                    or str(candidate_post_op.inputs[0]) != candidate_expand_out_name
                    or _read_transpose_perm(model_ir, candidate_post_op) != perm_nchw_to_nhwc
                ):
                    continue
                expand_idx = int(candidate_expand_idx)
                expand_op = candidate_expand_op
                post_idx = int(candidate_post_idx)
                post_op = candidate_post_op
                expand_out_name = str(candidate_expand_out_name)
                post_out_name = str(candidate_post_op.outputs[0])
                break
            if expand_idx is None or post_idx is None or expand_op is None or post_op is None:
                continue
            non_expand_users = [int(v) for v in reshape_users if int(v) != int(expand_idx)]

            pre_in_shape = _shape_list(pre_in_name)
            pre_out_shape = _shape_list(pre_out_name)
            unary_out_shape = _shape_list(unary_out_name)
            mid_out_shape = _shape_list(mid_out_name)
            reshape_out_shape = _shape_list(reshape_out_name)
            expand_out_shape = _shape_list(expand_out_name)
            post_out_shape = _shape_list(post_out_name)
            if (
                pre_in_shape is None
                or pre_out_shape is None
                or unary_out_shape is None
                or mid_out_shape is None
                or reshape_out_shape is None
                or expand_out_shape is None
                or post_out_shape is None
            ):
                continue
            if (
                len(pre_in_shape) != 4
                or len(pre_out_shape) != 4
                or len(unary_out_shape) != 4
                or len(mid_out_shape) != 4
                or len(reshape_out_shape) != 3
                or len(expand_out_shape) != 4
                or len(post_out_shape) != 4
            ):
                continue

            n, h, w, c = [int(v) for v in list(pre_in_shape)]
            expected_pre_out = [n, c, h, w]
            expected_mid_out = [n, h, c, w]
            expected_reshape_out = [h, c, w]
            expected_expand_out = [h, c, 1, w]
            expected_post_out = [h, 1, w, c]
            if not _shape_compatible(pre_out_shape, expected_pre_out):
                continue
            if not _shape_compatible(unary_out_shape, expected_pre_out):
                continue
            if not _shape_compatible(mid_out_shape, expected_mid_out):
                continue
            if not _shape_compatible(reshape_out_shape, expected_reshape_out):
                continue
            if not _shape_compatible(expand_out_shape, expected_expand_out):
                continue
            if not _shape_compatible(post_out_shape, expected_post_out):
                continue
            if not _dims_compatible(n, 1):
                continue

            reshape_out_legacy_shape = [int(v) for v in list(reshape_out_shape)]
            if not _swap_rank3_shape_in_reshape(reshape_op):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=unary_op,
                new_inputs=[pre_in_name],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(unary_out_name, None),
                perm_nchw_to_nhwc,
            )

            reshape_inputs = [str(v) for v in list(reshape_op.inputs)]
            reshape_inputs[0] = str(unary_out_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=reshape_op,
                new_inputs=reshape_inputs,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(reshape_out_name, None),
                perm_hcw_to_hwc,
            )
            if len(non_expand_users) > 0:
                bridge_perm_name = _unique_tensor_name(f"{reshape_out_name}_legacy_hcw_perm")
                bridge_out_name = _unique_tensor_name(f"{reshape_out_name}_legacy_hcw")
                model_ir.tensors[bridge_perm_name] = TensorIR(
                    name=bridge_perm_name,
                    dtype="INT32",
                    shape=[3],
                    shape_signature=[3],
                    data=np.asarray([0, 2, 1], dtype=np.int32),
                    is_variable=False,
                )
                reshape_tensor = model_ir.tensors.get(reshape_out_name, None)
                model_ir.tensors[bridge_out_name] = TensorIR(
                    name=bridge_out_name,
                    dtype=str(reshape_tensor.dtype if reshape_tensor is not None else "FLOAT32"),
                    shape=[int(v) for v in list(reshape_out_legacy_shape)],
                    shape_signature=[int(v) for v in list(reshape_out_legacy_shape)],
                )
                for non_expand_user_idx in non_expand_users:
                    non_expand_user_op = model_ir.operators[int(non_expand_user_idx)]
                    for input_idx, input_name in enumerate(list(non_expand_user_op.inputs)):
                        if str(input_name) == str(reshape_out_name):
                            _replace_operator_input_at(
                                model_ir=model_ir,
                                op=non_expand_user_op,
                                input_index=int(input_idx),
                                new_input_name=str(bridge_out_name),
                            )
                model_ir.operators.append(
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(reshape_out_name), str(bridge_perm_name)],
                        outputs=[str(bridge_out_name)],
                        options={},
                    )
                )

            _write_const_ints_to_tensor(
                model_ir.tensors.get(str(expand_op.inputs[1]), None),
                [1],
            )
            if model_ir.tensors.get(expand_out_name, None) is not None and model_ir.tensors.get(post_out_name, None) is not None:
                post_tensor = model_ir.tensors.get(post_out_name)
                expand_tensor = model_ir.tensors.get(expand_out_name)
                if post_tensor is not None and expand_tensor is not None:
                    expand_tensor.shape = [int(v) for v in list(post_tensor.shape)]
                    expand_tensor.shape_signature = (
                        [int(v) for v in list(post_tensor.shape_signature)]
                        if post_tensor.shape_signature is not None
                        else [int(v) for v in list(post_tensor.shape)]
                    )
                    expand_tensor.dtype = str(post_tensor.dtype)
                    expand_tensor.quantization = _clone_quantization(post_tensor.quantization)

            _replace_tensor_inputs(model_ir, post_out_name, expand_out_name)
            model_ir.outputs = [
                str(expand_out_name) if str(v) == str(post_out_name) else str(v)
                for v in list(model_ir.outputs)
            ]

            for remove_idx in sorted({int(pre_idx), int(mid_idx), int(post_idx)}, reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_unary_transpose_reshape_expanddims_transpose_nhwc_chains": int(rewritten)
    }


def _optimize_transpose_squeeze_unary_expanddims_transpose_nhwc_fanout_bypass_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Bypass Conv1D-shim ExpandDims->Transpose branches under unary fanout.

    Target:
      x_nhwc --T(0,3,1,2)--> x_nchw --SQUEEZE(axis=k)--> s3 --UNARY--> u3
      u3 --EXPAND_DIMS(axis=k)--> e4 --T(0,2,3,1)--> y_nhwc --(...)
      u3 --(other consumers)--> ...

    Rewrite:
      x_nhwc --UNARY--> y_nhwc --T(0,3,1,2)--> x_nchw --SQUEEZE(axis=k)--> u3
      y_nhwc --(...)  # former post-transpose users
      u3 --(other consumers)--> ...

    This keeps the NCHW side branch intact while eliminating only the
    ExpandDims->Transpose wrapper branch.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "GELU",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "CAST",
        "FLOOR",
        "CEIL",
        "ROUND",
        "HARD_SWISH",
    }

    def _shape_list(name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or tensor.shape is None:
            return None
        return [int(v) for v in list(tensor.shape)]

    def _dims_compatible(a: int, b: int) -> bool:
        if int(a) < 0 or int(b) < 0:
            return True
        return int(a) == int(b)

    def _shape_compatible(a: List[int], b: List[int]) -> bool:
        if len(a) != len(b):
            return False
        return all(_dims_compatible(int(x), int(y)) for x, y in zip(a, b))

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue
            squeeze_idx = int(pre_users[0])
            squeeze_op = model_ir.operators[int(squeeze_idx)]
            if (
                str(squeeze_op.op_type) != "SQUEEZE"
                or len(squeeze_op.inputs) != 1
                or len(squeeze_op.outputs) != 1
                or str(squeeze_op.inputs[0]) != pre_output_name
            ):
                continue
            squeeze_out_name = str(squeeze_op.outputs[0])

            squeeze_users = [int(v) for v in consumers.get(squeeze_out_name, [])]
            if len(squeeze_users) != 1:
                continue
            unary_idx = int(squeeze_users[0])
            unary_op = model_ir.operators[int(unary_idx)]
            if (
                str(unary_op.op_type) not in unary_ops
                or len(unary_op.inputs) != 1
                or len(unary_op.outputs) != 1
                or str(unary_op.inputs[0]) != squeeze_out_name
            ):
                continue
            unary_out_name = str(unary_op.outputs[0])

            pre_input_shape = _shape_list(pre_input_name)
            pre_output_shape = _shape_list(pre_output_name)
            squeeze_out_shape = _shape_list(squeeze_out_name)
            unary_out_shape = _shape_list(unary_out_name)
            if (
                pre_input_shape is None
                or pre_output_shape is None
                or squeeze_out_shape is None
                or unary_out_shape is None
            ):
                continue
            if (
                len(pre_input_shape) != 4
                or len(pre_output_shape) != 4
                or len(squeeze_out_shape) != 3
                or len(unary_out_shape) != 3
                or not _shape_compatible(squeeze_out_shape, unary_out_shape)
            ):
                continue

            squeeze_axis: Optional[int] = None
            squeeze_options = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
            if "squeezeDims" in squeeze_options:
                raw_axes = np.asarray(squeeze_options.get("squeezeDims", []), dtype=np.int64).reshape(-1)
                normalized_axes = _normalize_squeeze_axes_for_rank(
                    [int(v) for v in raw_axes.tolist()],
                    4,
                )
                if normalized_axes is None or len(normalized_axes) != 1:
                    continue
                candidate_axis = int(normalized_axes[0])
                if int(pre_output_shape[candidate_axis]) != 1:
                    continue
                candidate_squeezed = [
                    int(pre_output_shape[idx])
                    for idx in range(4)
                    if int(idx) != int(candidate_axis)
                ]
                if not _shape_compatible(candidate_squeezed, squeeze_out_shape):
                    continue
                squeeze_axis = int(candidate_axis)
            else:
                candidate_axes: List[int] = []
                for axis in range(4):
                    if int(pre_output_shape[axis]) != 1:
                        continue
                    candidate_squeezed = [
                        int(pre_output_shape[idx])
                        for idx in range(4)
                        if int(idx) != int(axis)
                    ]
                    if _shape_compatible(candidate_squeezed, squeeze_out_shape):
                        candidate_axes.append(int(axis))
                if len(candidate_axes) != 1:
                    continue
                squeeze_axis = int(candidate_axes[0])

            unary_users = [int(v) for v in consumers.get(unary_out_name, [])]
            candidate_pairs: List[Tuple[int, int, str]] = []
            for unary_user_idx in unary_users:
                expand_idx = int(unary_user_idx)
                expand_op = model_ir.operators[int(expand_idx)]
                if (
                    str(expand_op.op_type) != "EXPAND_DIMS"
                    or len(expand_op.inputs) < 2
                    or len(expand_op.outputs) != 1
                    or str(expand_op.inputs[0]) != unary_out_name
                ):
                    continue
                expand_axis_values = _read_const_ints_from_tensor(
                    model_ir.tensors.get(str(expand_op.inputs[1]), None)
                )
                if expand_axis_values is None or len(expand_axis_values) != 1:
                    continue
                expand_axis = int(expand_axis_values[0])
                if expand_axis < 0:
                    expand_axis += 4
                if expand_axis < 0 or expand_axis >= 4 or int(expand_axis) != int(squeeze_axis):
                    continue
                expand_out_name = str(expand_op.outputs[0])
                expand_users = [int(v) for v in consumers.get(expand_out_name, [])]
                if len(expand_users) != 1:
                    continue
                post_idx = int(expand_users[0])
                post_op = model_ir.operators[int(post_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or str(post_op.inputs[0]) != expand_out_name
                    or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                ):
                    continue
                post_output_name = str(post_op.outputs[0])
                post_output_shape = _shape_list(post_output_name)
                expand_out_shape = _shape_list(expand_out_name)
                if (
                    post_output_shape is None
                    or expand_out_shape is None
                    or len(post_output_shape) != 4
                    or len(expand_out_shape) != 4
                    or not _shape_compatible(pre_input_shape, post_output_shape)
                    or not _shape_compatible(pre_output_shape, expand_out_shape)
                ):
                    continue
                candidate_pairs.append((int(expand_idx), int(post_idx), str(post_output_name)))

            if not candidate_pairs:
                continue

            # Pick first eligible branch and bypass it.
            expand_idx, post_idx, post_output_name = candidate_pairs[0]
            post_output_tensor = model_ir.tensors.get(post_output_name, None)
            old_unary_out_tensor = model_ir.tensors.get(unary_out_name, None)
            if post_output_tensor is not None and old_unary_out_tensor is not None:
                post_output_tensor.dtype = str(old_unary_out_tensor.dtype)
                post_output_tensor.quantization = _clone_quantization(old_unary_out_tensor.quantization)

            _set_operator_inputs(
                model_ir=model_ir,
                op=unary_op,
                new_inputs=[pre_input_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=unary_op,
                new_outputs=[post_output_name],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=pre_op,
                input_index=0,
                new_input_name=str(post_output_name),
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=squeeze_op,
                new_outputs=[unary_out_name],
            )

            for remove_idx in sorted({int(expand_idx), int(post_idx)}, reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_squeeze_unary_expanddims_transpose_nhwc_fanout_bypass_chains": int(rewritten)
    }


def _optimize_transpose_squeeze_instancenorm_unary_expanddims_transpose_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove NHWC<->NCHW wrapper transposes around:
      TRANSPOSE -> SQUEEZE -> RESHAPE -> InstanceNorm(flat) -> RESHAPE
      -> UNARY -> EXPAND_DIMS -> TRANSPOSE

    The middle subgraph operates on [N,1,K] and is permutation-equivariant
    over K in the matched pattern, so we can swap C/W interpretation at the
    two RESHAPE boundaries and drop both transposes.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "GELU",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "CAST",
        "FLOOR",
        "CEIL",
        "ROUND",
        "HARD_SWISH",
    }

    def _shape_list(name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or tensor.shape is None:
            return None
        return [int(v) for v in list(tensor.shape)]

    def _dims_compatible(a: int, b: int) -> bool:
        if int(a) < 0 or int(b) < 0:
            return True
        return int(a) == int(b)

    def _shape_compatible(a: List[int], b: List[int]) -> bool:
        if len(a) != len(b):
            return False
        return all(_dims_compatible(int(x), int(y)) for x, y in zip(a, b))

    def _single_consumer_idx(consumers: Dict[str, List[int]], tensor_name: str) -> Optional[int]:
        users = [int(v) for v in consumers.get(str(tensor_name), [])]
        if len(users) != 1:
            return None
        return int(users[0])

    def _normalize_axis_list_for_rank(raw_axes: Optional[List[int]], rank: int) -> Optional[List[int]]:
        if raw_axes is None:
            return None
        normalized: List[int] = []
        for axis in raw_axes:
            v = int(axis)
            if v < 0:
                v += int(rank)
            if v < 0 or v >= int(rank):
                return None
            normalized.append(int(v))
        return sorted(set(normalized))

    def _mean_axes_keepdims_ok(mean_op: OperatorIR) -> bool:
        if len(mean_op.inputs) < 2:
            return False
        axes = _read_const_ints_from_tensor(model_ir.tensors.get(str(mean_op.inputs[1]), None))
        axes = _normalize_axis_list_for_rank(axes, 3)
        if axes != [2]:
            return False
        opts = dict(mean_op.options) if isinstance(mean_op.options, dict) else {}
        keep_dims = bool(opts.get("keepDims", opts.get("keep_dims", False)))
        return bool(keep_dims)

    def _find_binary_consumer(
        *,
        consumers: Dict[str, List[int]],
        lhs_tensor: str,
        rhs_tensor: Optional[str],
        op_type: str,
    ) -> Optional[int]:
        for idx in [int(v) for v in consumers.get(str(lhs_tensor), [])]:
            op = model_ir.operators[int(idx)]
            if str(op.op_type) != str(op_type):
                continue
            op_inputs = [str(v) for v in list(op.inputs)]
            if str(lhs_tensor) not in op_inputs:
                continue
            if rhs_tensor is not None and str(rhs_tensor) not in op_inputs:
                continue
            if len(op.outputs) != 1:
                continue
            return int(idx)
        return None

    def _find_unary_consumer(
        *,
        consumers: Dict[str, List[int]],
        input_tensor: str,
        op_type: str,
    ) -> Optional[int]:
        for idx in [int(v) for v in consumers.get(str(input_tensor), [])]:
            op = model_ir.operators[int(idx)]
            if str(op.op_type) != str(op_type):
                continue
            if len(op.inputs) != 1 or len(op.outputs) != 1:
                continue
            if str(op.inputs[0]) != str(input_tensor):
                continue
            return int(idx)
        return None

    def _find_mean_consumer(
        *,
        consumers: Dict[str, List[int]],
        input_tensor: str,
    ) -> Optional[int]:
        for idx in [int(v) for v in consumers.get(str(input_tensor), [])]:
            op = model_ir.operators[int(idx)]
            if str(op.op_type) != "MEAN":
                continue
            if len(op.inputs) < 2 or len(op.outputs) != 1:
                continue
            if str(op.inputs[0]) != str(input_tensor):
                continue
            return int(idx)
        return None

    def _update_tensor_shape(name: str, shape: List[int]) -> None:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None:
            return
        tensor.shape = [int(v) for v in list(shape)]
        tensor.shape_signature = [int(v) for v in list(shape)]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            pre_input_shape = _shape_list(pre_input_name)
            pre_output_shape = _shape_list(pre_output_name)
            if (
                pre_input_shape is None
                or pre_output_shape is None
                or len(pre_input_shape) != 4
                or len(pre_output_shape) != 4
                or not _is_fully_known_positive_shape(pre_input_shape)
                or not _is_fully_known_positive_shape(pre_output_shape)
            ):
                continue

            squeeze_idx = _single_consumer_idx(consumers, pre_output_name)
            if squeeze_idx is None:
                continue
            squeeze_op = model_ir.operators[int(squeeze_idx)]
            if (
                str(squeeze_op.op_type) != "SQUEEZE"
                or len(squeeze_op.inputs) != 1
                or len(squeeze_op.outputs) != 1
                or str(squeeze_op.inputs[0]) != pre_output_name
            ):
                continue
            squeeze_out_name = str(squeeze_op.outputs[0])
            squeeze_out_shape = _shape_list(squeeze_out_name)
            if squeeze_out_shape is None or len(squeeze_out_shape) != 3:
                continue

            # Require squeeze axis==2 on pre_output shape [N,C,1,W].
            squeeze_axis: Optional[int] = None
            squeeze_options = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
            if "squeezeDims" in squeeze_options:
                raw_axes = np.asarray(squeeze_options.get("squeezeDims", []), dtype=np.int64).reshape(-1)
                normalized_axes = _normalize_squeeze_axes_for_rank(
                    [int(v) for v in raw_axes.tolist()],
                    4,
                )
                if normalized_axes is None or len(normalized_axes) != 1:
                    continue
                squeeze_axis = int(normalized_axes[0])
            else:
                candidate_axes: List[int] = []
                for axis in range(4):
                    if int(pre_output_shape[axis]) != 1:
                        continue
                    candidate_squeezed = [
                        int(pre_output_shape[idx])
                        for idx in range(4)
                        if int(idx) != int(axis)
                    ]
                    if _shape_compatible(candidate_squeezed, squeeze_out_shape):
                        candidate_axes.append(int(axis))
                if len(candidate_axes) != 1:
                    continue
                squeeze_axis = int(candidate_axes[0])
            if int(squeeze_axis) != 2:
                continue

            reshape1_idx = _single_consumer_idx(consumers, squeeze_out_name)
            if reshape1_idx is None:
                continue
            reshape1_op = model_ir.operators[int(reshape1_idx)]
            if (
                str(reshape1_op.op_type) != "RESHAPE"
                or len(reshape1_op.inputs) < 2
                or len(reshape1_op.outputs) != 1
                or str(reshape1_op.inputs[0]) != squeeze_out_name
            ):
                continue
            reshape1_out_name = str(reshape1_op.outputs[0])
            reshape1_out_shape = _shape_list(reshape1_out_name)
            if (
                reshape1_out_shape is None
                or len(reshape1_out_shape) != 3
                or not _is_fully_known_positive_shape(reshape1_out_shape)
                or int(reshape1_out_shape[1]) != 1
            ):
                continue

            # Match InstanceNorm(flat) pattern:
            # mean1(x), sub(x,mean1), mul(sub,sub), mean2, add, sqrt, div, mul, mul, add.
            mean1_idx = _find_mean_consumer(
                consumers=consumers,
                input_tensor=reshape1_out_name,
            )
            if mean1_idx is None:
                continue
            mean1_op = model_ir.operators[int(mean1_idx)]
            if not _mean_axes_keepdims_ok(mean1_op):
                continue
            mean1_out_name = str(mean1_op.outputs[0])

            sub_idx = _find_binary_consumer(
                consumers=consumers,
                lhs_tensor=reshape1_out_name,
                rhs_tensor=mean1_out_name,
                op_type="SUB",
            )
            if sub_idx is None:
                continue
            sub_op = model_ir.operators[int(sub_idx)]
            sub_out_name = str(sub_op.outputs[0])

            mul_sq_idx = _find_binary_consumer(
                consumers=consumers,
                lhs_tensor=sub_out_name,
                rhs_tensor=sub_out_name,
                op_type="MUL",
            )
            if mul_sq_idx is None:
                continue
            mul_sq_out_name = str(model_ir.operators[int(mul_sq_idx)].outputs[0])

            mean2_idx = _find_mean_consumer(
                consumers=consumers,
                input_tensor=mul_sq_out_name,
            )
            if mean2_idx is None:
                continue
            mean2_op = model_ir.operators[int(mean2_idx)]
            if not _mean_axes_keepdims_ok(mean2_op):
                continue
            mean2_out_name = str(mean2_op.outputs[0])

            add_eps_idx = _find_binary_consumer(
                consumers=consumers,
                lhs_tensor=mean2_out_name,
                rhs_tensor=None,
                op_type="ADD",
            )
            if add_eps_idx is None:
                continue
            add_eps_out_name = str(model_ir.operators[int(add_eps_idx)].outputs[0])

            sqrt_idx = _find_unary_consumer(
                consumers=consumers,
                input_tensor=add_eps_out_name,
                op_type="SQRT",
            )
            if sqrt_idx is None:
                continue
            sqrt_out_name = str(model_ir.operators[int(sqrt_idx)].outputs[0])

            div_idx = _find_binary_consumer(
                consumers=consumers,
                lhs_tensor=sqrt_out_name,
                rhs_tensor=None,
                op_type="DIV",
            )
            if div_idx is None:
                # DIV may have sqrt on input1
                for candidate_idx in [int(v) for v in consumers.get(str(sqrt_out_name), [])]:
                    op = model_ir.operators[int(candidate_idx)]
                    if str(op.op_type) != "DIV" or len(op.outputs) != 1:
                        continue
                    if str(sqrt_out_name) not in [str(v) for v in list(op.inputs)]:
                        continue
                    div_idx = int(candidate_idx)
                    break
            if div_idx is None:
                continue
            div_out_name = str(model_ir.operators[int(div_idx)].outputs[0])

            mul_norm_idx = _find_binary_consumer(
                consumers=consumers,
                lhs_tensor=sub_out_name,
                rhs_tensor=div_out_name,
                op_type="MUL",
            )
            if mul_norm_idx is None:
                continue
            mul_norm_out_name = str(model_ir.operators[int(mul_norm_idx)].outputs[0])

            mul_scale_idx = _find_binary_consumer(
                consumers=consumers,
                lhs_tensor=mul_norm_out_name,
                rhs_tensor=None,
                op_type="MUL",
            )
            if mul_scale_idx is None:
                continue
            mul_scale_out_name = str(model_ir.operators[int(mul_scale_idx)].outputs[0])

            add_bias_idx = _find_binary_consumer(
                consumers=consumers,
                lhs_tensor=mul_scale_out_name,
                rhs_tensor=None,
                op_type="ADD",
            )
            if add_bias_idx is None:
                continue
            add_bias_out_name = str(model_ir.operators[int(add_bias_idx)].outputs[0])

            reshape2_idx = _single_consumer_idx(consumers, add_bias_out_name)
            if reshape2_idx is None:
                continue
            reshape2_op = model_ir.operators[int(reshape2_idx)]
            if (
                str(reshape2_op.op_type) != "RESHAPE"
                or len(reshape2_op.inputs) < 2
                or len(reshape2_op.outputs) != 1
                or str(reshape2_op.inputs[0]) != add_bias_out_name
            ):
                continue
            reshape2_in_name = str(reshape2_op.inputs[0])
            reshape2_out_name = str(reshape2_op.outputs[0])
            reshape2_in_shape = _shape_list(reshape2_in_name)
            reshape2_out_shape = _shape_list(reshape2_out_name)
            if (
                reshape2_in_shape is None
                or reshape2_out_shape is None
                or len(reshape2_in_shape) != 3
                or len(reshape2_out_shape) != 3
                or not _shape_compatible(reshape2_in_shape, reshape1_out_shape)
                or not _shape_compatible(reshape2_out_shape, squeeze_out_shape)
                or not _is_fully_known_positive_shape(reshape2_out_shape)
            ):
                continue

            unary_idx = _single_consumer_idx(consumers, reshape2_out_name)
            if unary_idx is None:
                continue
            unary_op = model_ir.operators[int(unary_idx)]
            if (
                str(unary_op.op_type) not in unary_ops
                or len(unary_op.inputs) != 1
                or len(unary_op.outputs) != 1
                or str(unary_op.inputs[0]) != reshape2_out_name
            ):
                continue
            unary_out_name = str(unary_op.outputs[0])
            unary_out_shape = _shape_list(unary_out_name)
            if unary_out_shape is None or len(unary_out_shape) != 3 or not _shape_compatible(unary_out_shape, reshape2_out_shape):
                continue

            expand_idx = _single_consumer_idx(consumers, unary_out_name)
            if expand_idx is None:
                continue
            expand_op = model_ir.operators[int(expand_idx)]
            if (
                str(expand_op.op_type) != "EXPAND_DIMS"
                or len(expand_op.inputs) < 2
                or len(expand_op.outputs) != 1
                or str(expand_op.inputs[0]) != unary_out_name
            ):
                continue
            expand_out_name = str(expand_op.outputs[0])
            expand_axis_values = _read_const_ints_from_tensor(model_ir.tensors.get(str(expand_op.inputs[1]), None))
            if expand_axis_values is None or len(expand_axis_values) != 1:
                continue
            expand_axis = int(expand_axis_values[0])
            if expand_axis < 0:
                expand_axis += 4
            if int(expand_axis) != 2:
                continue

            post_idx = _single_consumer_idx(consumers, expand_out_name)
            if post_idx is None:
                continue
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != expand_out_name
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_out_name = str(post_op.outputs[0])
            post_out_shape = _shape_list(post_out_name)
            expand_out_shape = _shape_list(expand_out_name)
            if (
                post_out_shape is None
                or expand_out_shape is None
                or len(post_out_shape) != 4
                or len(expand_out_shape) != 4
                or not _shape_compatible(post_out_shape, pre_input_shape)
                or not _shape_compatible(expand_out_shape, pre_output_shape)
            ):
                continue

            n = int(pre_input_shape[0])
            w = int(pre_input_shape[2])
            c = int(pre_input_shape[3])
            new_rank3_shape = [n, w, c]
            new_rank4_shape = [n, 1, w, c]

            # Rewrite axes and reshape target.
            squeeze_opts = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
            squeeze_opts["squeezeDims"] = [1]
            squeeze_op.options = squeeze_opts
            _set_operator_inputs(
                model_ir=model_ir,
                op=squeeze_op,
                new_inputs=[pre_input_name],
            )
            _update_tensor_shape(squeeze_out_name, new_rank3_shape)

            reshape2_opts = dict(reshape2_op.options) if isinstance(reshape2_op.options, dict) else {}
            for key in ["newShape", "onnxRawNewShape"]:
                if key in reshape2_opts and isinstance(reshape2_opts[key], list):
                    reshape2_opts[key] = [int(v) for v in list(new_rank3_shape)]
            reshape2_op.options = reshape2_opts
            if len(reshape2_op.inputs) >= 2:
                _write_const_ints_to_tensor(
                    model_ir.tensors.get(str(reshape2_op.inputs[1]), None),
                    [int(v) for v in list(new_rank3_shape)],
                )
            _update_tensor_shape(reshape2_out_name, new_rank3_shape)
            _update_tensor_shape(unary_out_name, new_rank3_shape)

            if len(expand_op.inputs) >= 2:
                _write_const_ints_to_tensor(
                    model_ir.tensors.get(str(expand_op.inputs[1]), None),
                    [1],
                )
            _update_tensor_shape(expand_out_name, new_rank4_shape)

            _replace_tensor_inputs(model_ir, post_out_name, expand_out_name)
            model_ir.outputs = [
                str(expand_out_name) if str(v) == str(post_out_name) else str(v)
                for v in list(model_ir.outputs)
            ]

            for remove_idx in sorted({int(pre_idx), int(post_idx)}, reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_squeeze_instancenorm_unary_expanddims_transpose_nhwc_chains": int(rewritten)
    }


def _optimize_tencoder_add_expand_transpose_conv_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove Conv1D-shim post-transposes on dual tencoder branches before residual ADD.

    Target (NCHW-3D bridge):
      lhs4 --T(0,3,1,2)--> lhs4n --SQUEEZE(axis=2)--> lhs3 [N,C,W]
      rhs4 --T(0,3,1,2)--> rhs4n --SQUEEZE(axis=2)--> rhs3 [N,2C,W]
      rhs3 --RESHAPE/InstanceNorm/RESHAPE--> split_src [N,2C,W]
      split_src --SLICE--> a [N,C,W], b [N,C,W] --LOGISTIC/MUL/scale--> rhs_gate [N,C,W]
      lhs3 + rhs_gate -> add_out [N,C,W]
      add_out --EXPAND_DIMS(axis=2)--> add4 --T(0,2,3,1)--> add4_nhwc -> CONV_2D

    Rewrite (NHWC-3D bridge):
      lhs4 --SQUEEZE(axis=1)--> lhs3' [N,W,C]
      rhs4 --SQUEEZE(axis=1)--> rhs3' [N,W,2C]
      reshape/slice/scale constants adjusted to [N,W,*]
      lhs3' + rhs_gate' -> add_out' [N,W,C]
      add_out' --EXPAND_DIMS(axis=1)--> add4' [N,1,W,C] -> CONV_2D
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _shape_list(name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or tensor.shape is None:
            return None
        return [int(v) for v in list(tensor.shape)]

    def _update_tensor_shape(name: str, shape: List[int]) -> None:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None:
            return
        tensor.shape = [int(v) for v in list(shape)]
        tensor.shape_signature = [int(v) for v in list(shape)]

    def _resolve_single_squeeze_axis(
        squeeze_op: OperatorIR,
        input_shape: List[int],
        output_shape: List[int],
    ) -> Optional[int]:
        opts = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
        if "squeezeDims" in opts:
            raw_axes = np.asarray(opts.get("squeezeDims", []), dtype=np.int64).reshape(-1)
            normalized_axes = _normalize_squeeze_axes_for_rank(
                [int(v) for v in raw_axes.tolist()],
                int(len(input_shape)),
            )
            if normalized_axes is None or len(normalized_axes) != 1:
                return None
            axis = int(normalized_axes[0])
            if int(input_shape[axis]) != 1:
                return None
            candidate = [int(input_shape[idx]) for idx in range(len(input_shape)) if int(idx) != int(axis)]
            if candidate != [int(v) for v in list(output_shape)]:
                return None
            return int(axis)
        candidates: List[int] = []
        for axis in range(len(input_shape)):
            if int(input_shape[axis]) != 1:
                continue
            candidate = [int(input_shape[idx]) for idx in range(len(input_shape)) if int(idx) != int(axis)]
            if candidate == [int(v) for v in list(output_shape)]:
                candidates.append(int(axis))
        if len(candidates) != 1:
            return None
        return int(candidates[0])

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _clone_or_rewrite_scale_const(
        *,
        const_name: str,
        target_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        const_tensor = model_ir.tensors.get(str(const_name), None)
        if const_tensor is None or const_tensor.data is None:
            return None
        const_data = np.asarray(const_tensor.data)
        if const_data.ndim != 2:
            return None
        if int(const_data.shape[0]) >= 1 and int(const_data.shape[1]) == 1:
            new_data = np.asarray(const_data.T)
        elif int(const_data.shape[0]) == 1 and int(const_data.shape[1]) >= 1:
            new_data = np.asarray(const_data)
        else:
            return None
        users = [int(v) for v in consumers.get(str(const_name), [])]
        shared_outside_target = any(int(v) not in target_users for v in users)
        if shared_outside_target:
            new_name = _unique_tensor_name(f"{const_name}_nhwc")
            new_shape = [int(v) for v in list(new_data.shape)]
            model_ir.tensors[new_name] = TensorIR(
                name=new_name,
                dtype=str(const_tensor.dtype),
                shape=new_shape,
                shape_signature=new_shape,
                data=np.asarray(new_data),
                is_variable=False,
                quantization=_clone_quantization(const_tensor.quantization),
            )
            return str(new_name)
        const_tensor.data = np.asarray(new_data)
        const_tensor.shape = [int(v) for v in list(new_data.shape)]
        const_tensor.shape_signature = [int(v) for v in list(new_data.shape)]
        return str(const_name)

    def _find_upstream_squeeze_transpose(
        *,
        start_tensor: str,
        producers: Dict[str, int],
    ) -> Optional[Tuple[int, int, str, str]]:
        stack: List[str] = [str(start_tensor)]
        visited: set[str] = set()
        while stack:
            current = str(stack.pop())
            if current in visited:
                continue
            visited.add(current)
            producer_idx = producers.get(str(current), None)
            if producer_idx is None:
                continue
            producer_op = model_ir.operators[int(producer_idx)]
            if (
                str(producer_op.op_type) == "SQUEEZE"
                and len(producer_op.inputs) == 1
                and len(producer_op.outputs) == 1
            ):
                squeeze_in = str(producer_op.inputs[0])
                pre_idx = producers.get(str(squeeze_in), None)
                if pre_idx is not None:
                    pre_op = model_ir.operators[int(pre_idx)]
                    if (
                        str(pre_op.op_type) == "TRANSPOSE"
                        and len(pre_op.inputs) >= 2
                        and len(pre_op.outputs) == 1
                        and _read_transpose_perm(model_ir, pre_op) == perm_nhwc_to_nchw
                        and str(pre_op.outputs[0]) == str(squeeze_in)
                    ):
                        return (
                            int(pre_idx),
                            int(producer_idx),
                            str(pre_op.inputs[0]),
                            str(producer_op.outputs[0]),
                        )
            for in_name in [str(v) for v in list(producer_op.inputs)]:
                if producers.get(str(in_name), None) is not None:
                    stack.append(str(in_name))
        return None

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_in_name = str(post_op.inputs[0])
            post_out_name = str(post_op.outputs[0])

            expand_idx = producers.get(post_in_name, None)
            if expand_idx is None:
                continue
            expand_op = model_ir.operators[int(expand_idx)]
            if (
                str(expand_op.op_type) != "EXPAND_DIMS"
                or len(expand_op.inputs) < 2
                or len(expand_op.outputs) != 1
                or str(expand_op.outputs[0]) != post_in_name
            ):
                continue
            expand_axis_values = _read_const_ints_from_tensor(
                model_ir.tensors.get(str(expand_op.inputs[1]), None)
            )
            if expand_axis_values is None or len(expand_axis_values) != 1:
                continue
            expand_axis = int(expand_axis_values[0])
            if expand_axis < 0:
                expand_axis += 4
            if int(expand_axis) != 2:
                continue

            add_out_name = str(expand_op.inputs[0])
            if add_out_name in model_outputs:
                continue
            add_idx = producers.get(add_out_name, None)
            if add_idx is None:
                continue
            add_op = model_ir.operators[int(add_idx)]
            if (
                str(add_op.op_type) != "ADD"
                or len(add_op.inputs) != 2
                or len(add_op.outputs) != 1
                or str(add_op.outputs[0]) != add_out_name
            ):
                continue
            add_users = [int(v) for v in consumers.get(add_out_name, [])]
            if len(add_users) < 1:
                continue

            def _match_simple_branch(out_name: str) -> Optional[Dict[str, Any]]:
                sq_idx = producers.get(str(out_name), None)
                if sq_idx is None:
                    return None
                sq_op = model_ir.operators[int(sq_idx)]
                if (
                    str(sq_op.op_type) != "SQUEEZE"
                    or len(sq_op.inputs) != 1
                    or len(sq_op.outputs) != 1
                    or str(sq_op.outputs[0]) != str(out_name)
                ):
                    return None
                pre_name = str(sq_op.inputs[0])
                pre_idx = producers.get(pre_name, None)
                if pre_idx is None:
                    return None
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != pre_name
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                ):
                    return None
                src4_name = str(pre_op.inputs[0])
                src4_shape = _shape_list(src4_name)
                out_shape = _shape_list(str(out_name))
                if (
                    src4_shape is None
                    or out_shape is None
                    or len(src4_shape) != 4
                    or len(out_shape) != 3
                    or int(src4_shape[1]) != 1
                    or not _is_fully_known_positive_shape(src4_shape)
                    or not _is_fully_known_positive_shape(out_shape)
                ):
                    return None
                axis = _resolve_single_squeeze_axis(sq_op, _shape_list(pre_name) or [], out_shape)
                if axis != 2:
                    return None
                n, _, w, c = [int(v) for v in list(src4_shape)]
                if [n, c, w] != [int(v) for v in list(out_shape)]:
                    return None
                return {
                    "kind": "simple",
                    "pre_idx": int(pre_idx),
                    "sq_idx": int(sq_idx),
                    "src4_name": str(src4_name),
                    "out_name": str(out_name),
                    "n": int(n),
                    "c": int(c),
                    "w": int(w),
                }

            def _match_legacy_rank3_branch(out_name: str) -> Optional[Dict[str, Any]]:
                pre_idx = producers.get(str(out_name), None)
                if pre_idx is None:
                    return None
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != str(out_name)
                ):
                    return None
                if _read_transpose_perm(model_ir, pre_op) != [0, 2, 1]:
                    return None
                src3_name = str(pre_op.inputs[0])
                src3_shape = _shape_list(src3_name)
                out_shape = _shape_list(str(out_name))
                if (
                    src3_shape is None
                    or out_shape is None
                    or len(src3_shape) != 3
                    or len(out_shape) != 3
                    or not _is_fully_known_positive_shape(src3_shape)
                    or not _is_fully_known_positive_shape(out_shape)
                ):
                    return None
                n, w, c = [int(v) for v in list(src3_shape)]
                if [n, c, w] != [int(v) for v in list(out_shape)]:
                    return None
                return {
                    "kind": "legacy_rank3",
                    "pre_idx": int(pre_idx),
                    "src3_name": str(src3_name),
                    "out_name": str(out_name),
                    "n": int(n),
                    "c": int(c),
                    "w": int(w),
                }

            def _match_lhs_branch(out_name: str) -> Optional[Dict[str, Any]]:
                lhs_branch = _match_simple_branch(out_name)
                if lhs_branch is not None:
                    return lhs_branch
                return _match_legacy_rank3_branch(out_name)

            def _match_gate_branch(out_name: str) -> Optional[Dict[str, Any]]:
                scale_idx = producers.get(str(out_name), None)
                if scale_idx is None:
                    return None
                scale_op = model_ir.operators[int(scale_idx)]
                if (
                    str(scale_op.op_type) != "MUL"
                    or len(scale_op.inputs) != 2
                    or len(scale_op.outputs) != 1
                    or str(scale_op.outputs[0]) != str(out_name)
                ):
                    return None
                scale_inputs = [str(v) for v in list(scale_op.inputs)]
                const_name: Optional[str] = None
                gate_name: Optional[str] = None
                for cand in scale_inputs:
                    tensor = model_ir.tensors.get(str(cand), None)
                    if tensor is not None and tensor.data is not None and np.asarray(tensor.data).ndim == 2:
                        const_name = str(cand)
                    else:
                        gate_name = str(cand)
                if const_name is None or gate_name is None:
                    return None
                const_tensor = model_ir.tensors.get(str(const_name), None)
                if const_tensor is None or const_tensor.data is None:
                    return None
                const_shape = [int(v) for v in list(np.asarray(const_tensor.data).shape)]
                if len(const_shape) != 2 or int(min(const_shape)) != 1:
                    return None
                c = int(max(const_shape))

                gate_idx = producers.get(str(gate_name), None)
                if gate_idx is None:
                    return None
                gate_op = model_ir.operators[int(gate_idx)]
                if (
                    str(gate_op.op_type) != "MUL"
                    or len(gate_op.inputs) != 2
                    or len(gate_op.outputs) != 1
                    or str(gate_op.outputs[0]) != str(gate_name)
                ):
                    return None
                g0, g1 = [str(v) for v in list(gate_op.inputs)]
                g0_prod = producers.get(g0, None)
                g1_prod = producers.get(g1, None)
                logistic_name: Optional[str] = None
                slice0_name: Optional[str] = None
                if g0_prod is not None and str(model_ir.operators[int(g0_prod)].op_type) == "LOGISTIC":
                    logistic_name = str(g0)
                    slice0_name = str(g1)
                elif g1_prod is not None and str(model_ir.operators[int(g1_prod)].op_type) == "LOGISTIC":
                    logistic_name = str(g1)
                    slice0_name = str(g0)
                else:
                    return None
                logistic_idx = producers.get(str(logistic_name), None)
                slice0_idx = producers.get(str(slice0_name), None)
                if logistic_idx is None or slice0_idx is None:
                    return None
                logistic_op = model_ir.operators[int(logistic_idx)]
                slice0_op = model_ir.operators[int(slice0_idx)]
                if (
                    str(logistic_op.op_type) != "LOGISTIC"
                    or len(logistic_op.inputs) != 1
                    or str(slice0_op.op_type) != "SLICE"
                    or len(slice0_op.inputs) < 3
                    or len(slice0_op.outputs) != 1
                    or str(slice0_op.outputs[0]) != str(slice0_name)
                ):
                    return None
                slice1_name = str(logistic_op.inputs[0])
                slice1_idx = producers.get(str(slice1_name), None)
                if slice1_idx is None:
                    return None
                slice1_op = model_ir.operators[int(slice1_idx)]
                if (
                    str(slice1_op.op_type) != "SLICE"
                    or len(slice1_op.inputs) < 3
                    or len(slice1_op.outputs) != 1
                    or str(slice1_op.outputs[0]) != str(slice1_name)
                ):
                    return None
                split_src0 = str(slice0_op.inputs[0])
                split_src1 = str(slice1_op.inputs[0])
                if str(split_src0) != str(split_src1):
                    return None
                split_src = str(split_src0)

                split_src_shape = _shape_list(split_src)
                slice0_shape = _shape_list(slice0_name)
                slice1_shape = _shape_list(slice1_name)
                out_shape = _shape_list(str(out_name))
                if (
                    split_src_shape is None
                    or slice0_shape is None
                    or slice1_shape is None
                    or out_shape is None
                    or len(split_src_shape) != 3
                    or len(slice0_shape) != 3
                    or len(slice1_shape) != 3
                    or len(out_shape) != 3
                    or not _is_fully_known_positive_shape(split_src_shape)
                    or not _is_fully_known_positive_shape(slice0_shape)
                    or not _is_fully_known_positive_shape(out_shape)
                ):
                    return None
                n = int(split_src_shape[0])
                c2 = int(split_src_shape[1])
                w = int(split_src_shape[2])
                if int(c2) != int(c * 2):
                    return None
                if [n, c, w] != [int(v) for v in list(slice0_shape)]:
                    return None
                if [n, c, w] != [int(v) for v in list(slice1_shape)]:
                    return None
                if [n, c, w] != [int(v) for v in list(out_shape)]:
                    return None

                begin0 = _read_const_ints_from_tensor(model_ir.tensors.get(str(slice0_op.inputs[1]), None))
                size0 = _read_const_ints_from_tensor(model_ir.tensors.get(str(slice0_op.inputs[2]), None))
                begin1 = _read_const_ints_from_tensor(model_ir.tensors.get(str(slice1_op.inputs[1]), None))
                size1 = _read_const_ints_from_tensor(model_ir.tensors.get(str(slice1_op.inputs[2]), None))
                if (
                    begin0 is None
                    or size0 is None
                    or begin1 is None
                    or size1 is None
                    or len(begin0) != 3
                    or len(size0) != 3
                    or len(begin1) != 3
                    or len(size1) != 3
                ):
                    return None
                if [int(v) for v in begin0] != [0, 0, 0]:
                    return None
                if [int(v) for v in size0] != [n, c, w]:
                    return None
                if [int(v) for v in begin1] != [0, c, 0]:
                    return None
                if [int(v) for v in size1] != [n, c, w]:
                    return None

                reshape2_idx = producers.get(split_src, None)
                if reshape2_idx is None:
                    return None
                reshape2_op = model_ir.operators[int(reshape2_idx)]
                if (
                    str(reshape2_op.op_type) != "RESHAPE"
                    or len(reshape2_op.inputs) < 2
                    or len(reshape2_op.outputs) != 1
                    or str(reshape2_op.outputs[0]) != split_src
                ):
                    return None

                upstream = _find_upstream_squeeze_transpose(
                    start_tensor=str(reshape2_op.inputs[0]),
                    producers=producers,
                )
                if upstream is None:
                    return None
                pre_idx, sq_idx, src4_name, sq_out_name = upstream
                sq_out_shape = _shape_list(sq_out_name)
                src4_shape = _shape_list(src4_name)
                if (
                    sq_out_shape is None
                    or src4_shape is None
                    or len(sq_out_shape) != 3
                    or len(src4_shape) != 4
                    or int(src4_shape[1]) != 1
                    or [int(src4_shape[0]), int(src4_shape[3]), int(src4_shape[2])] != [n, c2, w]
                    or [int(v) for v in sq_out_shape] != [n, c2, w]
                ):
                    return None
                sq_op = model_ir.operators[int(sq_idx)]
                axis = _resolve_single_squeeze_axis(sq_op, _shape_list(str(sq_op.inputs[0])) or [], sq_out_shape)
                if axis != 2:
                    return None

                return {
                    "scale_idx": int(scale_idx),
                    "scale_const_name": str(const_name),
                    "gate_idx": int(gate_idx),
                    "logistic_idx": int(logistic_idx),
                    "slice0_idx": int(slice0_idx),
                    "slice1_idx": int(slice1_idx),
                    "slice0_name": str(slice0_name),
                    "slice1_name": str(slice1_name),
                    "split_src_name": str(split_src),
                    "reshape2_idx": int(reshape2_idx),
                    "rhs_pre_idx": int(pre_idx),
                    "rhs_sq_idx": int(sq_idx),
                    "rhs_src4_name": str(src4_name),
                    "rhs_sq_out_name": str(sq_out_name),
                    "n": int(n),
                    "c": int(c),
                    "w": int(w),
                    "c2": int(c2),
                    "scale_out_name": str(out_name),
                }

            add_input0 = str(add_op.inputs[0])
            add_input1 = str(add_op.inputs[1])
            lhs = _match_lhs_branch(add_input0)
            rhs = _match_gate_branch(add_input1)
            if lhs is None or rhs is None:
                lhs = _match_lhs_branch(add_input1)
                rhs = _match_gate_branch(add_input0)
            if lhs is None or rhs is None:
                continue

            n = int(lhs["n"])
            c = int(lhs["c"])
            w = int(lhs["w"])
            if int(rhs["n"]) != int(n) or int(rhs["c"]) != int(c) or int(rhs["w"]) != int(w):
                continue

            post_users = [int(v) for v in consumers.get(post_out_name, [])]
            if len(post_users) == 0:
                continue
            can_remove_post_transpose = (
                len(add_users) == 1
                and int(add_users[0]) == int(expand_idx)
                and post_out_name not in model_outputs
            )

            # Rewrite left branch to NHWC-3D.
            if str(lhs.get("kind", "")) == "simple":
                lhs_sq_op = model_ir.operators[int(lhs["sq_idx"])]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=lhs_sq_op,
                    new_inputs=[str(lhs["src4_name"])],
                )
                lhs_sq_opts = dict(lhs_sq_op.options) if isinstance(lhs_sq_op.options, dict) else {}
                lhs_sq_opts["squeezeDims"] = [1]
                lhs_sq_op.options = lhs_sq_opts
                _update_tensor_shape(str(lhs["out_name"]), [n, w, c])
            elif str(lhs.get("kind", "")) == "legacy_rank3":
                lhs_src_name = str(lhs["src3_name"])
                _update_tensor_shape(lhs_src_name, [n, w, c])
                for input_idx, input_name in enumerate(list(add_op.inputs)):
                    if str(input_name) == str(lhs["out_name"]):
                        _replace_operator_input_at(
                            model_ir=model_ir,
                            op=add_op,
                            input_index=int(input_idx),
                            new_input_name=lhs_src_name,
                        )
            else:
                continue

            # Rewrite right branch squeeze + reshape/slice/scale to NHWC-3D.
            rhs_sq_op = model_ir.operators[int(rhs["rhs_sq_idx"])]
            _set_operator_inputs(
                model_ir=model_ir,
                op=rhs_sq_op,
                new_inputs=[str(rhs["rhs_src4_name"])],
            )
            rhs_sq_opts = dict(rhs_sq_op.options) if isinstance(rhs_sq_op.options, dict) else {}
            rhs_sq_opts["squeezeDims"] = [1]
            rhs_sq_op.options = rhs_sq_opts
            _update_tensor_shape(str(rhs["rhs_sq_out_name"]), [n, w, int(rhs["c2"])])

            reshape2_op = model_ir.operators[int(rhs["reshape2_idx"])]
            reshape2_opts = dict(reshape2_op.options) if isinstance(reshape2_op.options, dict) else {}
            for key in ["newShape", "onnxRawNewShape"]:
                if key in reshape2_opts and isinstance(reshape2_opts[key], list):
                    reshape2_opts[key] = [int(v) for v in [n, w, int(rhs["c2"])]]
            reshape2_op.options = reshape2_opts
            if len(reshape2_op.inputs) >= 2:
                _write_const_ints_to_tensor(
                    model_ir.tensors.get(str(reshape2_op.inputs[1]), None),
                    [int(v) for v in [n, w, int(rhs["c2"])]],
                )
            _update_tensor_shape(str(rhs["split_src_name"]), [n, w, int(rhs["c2"])])

            slice0_op = model_ir.operators[int(rhs["slice0_idx"])]
            slice1_op = model_ir.operators[int(rhs["slice1_idx"])]
            _write_const_ints_to_tensor(
                model_ir.tensors.get(str(slice0_op.inputs[1]), None),
                [int(v) for v in [0, 0, 0]],
            )
            _write_const_ints_to_tensor(
                model_ir.tensors.get(str(slice0_op.inputs[2]), None),
                [int(v) for v in [n, w, c]],
            )
            _write_const_ints_to_tensor(
                model_ir.tensors.get(str(slice1_op.inputs[1]), None),
                [int(v) for v in [0, 0, c]],
            )
            _write_const_ints_to_tensor(
                model_ir.tensors.get(str(slice1_op.inputs[2]), None),
                [int(v) for v in [n, w, c]],
            )
            _update_tensor_shape(str(rhs["slice0_name"]), [n, w, c])
            _update_tensor_shape(str(rhs["slice1_name"]), [n, w, c])

            scale_users = {int(rhs["scale_idx"])}
            new_scale_const_name = _clone_or_rewrite_scale_const(
                const_name=str(rhs["scale_const_name"]),
                target_users=scale_users,
                consumers=consumers,
            )
            if new_scale_const_name is None:
                continue
            scale_op = model_ir.operators[int(rhs["scale_idx"])]
            if str(scale_op.inputs[0]) == str(rhs["scale_const_name"]):
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=scale_op,
                    input_index=0,
                    new_input_name=str(new_scale_const_name),
                )
            else:
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=scale_op,
                    input_index=1,
                    new_input_name=str(new_scale_const_name),
                )
            _update_tensor_shape(str(rhs["scale_out_name"]), [n, w, c])

            _update_tensor_shape(add_out_name, [n, w, c])

            remove_indices_set = {int(lhs["pre_idx"]), int(rhs["rhs_pre_idx"])}
            if can_remove_post_transpose:
                # Single-consumer form: replace post transpose with direct EXPAND_DIMS output.
                if len(expand_op.inputs) >= 2:
                    _write_const_ints_to_tensor(
                        model_ir.tensors.get(str(expand_op.inputs[1]), None),
                        [1],
                    )
                _update_tensor_shape(post_in_name, [n, 1, w, c])
                _replace_tensor_inputs(model_ir, post_out_name, post_in_name)
                model_ir.outputs = [
                    str(post_in_name) if str(v) == str(post_out_name) else str(v)
                    for v in list(model_ir.outputs)
                ]
                remove_indices_set.add(int(post_idx))
            else:
                # Multi-consumer form:
                # - Keep Conv branch on NHWC-friendly path (drop post-transpose).
                # - Provide legacy [N,C,W] view only for non-Conv users via 3D bridge.
                non_conv_add_users = [int(v) for v in add_users if int(v) != int(expand_idx)]
                if len(non_conv_add_users) == 0:
                    continue
                bridge_out_name = _unique_tensor_name(f"{add_out_name}_legacy_ncw")
                bridge_perm_name = _unique_tensor_name(f"{add_out_name}_legacy_ncw_perm")
                model_ir.tensors[bridge_perm_name] = TensorIR(
                    name=bridge_perm_name,
                    dtype="INT32",
                    shape=[3],
                    shape_signature=[3],
                    data=np.asarray([0, 2, 1], dtype=np.int32),
                    is_variable=False,
                )
                model_ir.tensors[bridge_out_name] = TensorIR(
                    name=bridge_out_name,
                    dtype=str(model_ir.tensors.get(add_out_name).dtype if model_ir.tensors.get(add_out_name) is not None else "FLOAT32"),
                    shape=[n, c, w],
                    shape_signature=[n, c, w],
                )
                for user_idx in non_conv_add_users:
                    user_op = model_ir.operators[int(user_idx)]
                    for input_idx, input_name in enumerate(list(user_op.inputs)):
                        if str(input_name) == str(add_out_name):
                            _replace_operator_input_at(
                                model_ir=model_ir,
                                op=user_op,
                                input_index=int(input_idx),
                                new_input_name=str(bridge_out_name),
                            )
                model_ir.operators.append(
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(add_out_name), str(bridge_perm_name)],
                        outputs=[str(bridge_out_name)],
                        options={},
                    )
                )

                if len(expand_op.inputs) >= 2:
                    _write_const_ints_to_tensor(
                        model_ir.tensors.get(str(expand_op.inputs[1]), None),
                        [1],
                    )
                _update_tensor_shape(post_in_name, [n, 1, w, c])
                _replace_tensor_inputs(model_ir, post_out_name, post_in_name)
                model_ir.outputs = [
                    str(post_in_name) if str(v) == str(post_out_name) else str(v)
                    for v in list(model_ir.outputs)
                ]
                remove_indices_set.add(int(post_idx))

            remove_indices = sorted(list(remove_indices_set), reverse=True)
            for remove_idx in remove_indices:
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_tencoder_add_expand_transpose_conv_nhwc_chains": int(rewritten)}


def _optimize_transpose_squeeze_unary_batchmatmul_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove NHWC->NCHW transpose before SQUEEZE->UNARY->BATCH_MATMUL tails.

    Target:
      x_nhwc --T(0,3,1,2)--> x_nchw --SQUEEZE(axis=s)--> s3 --(UNARY)*--> u3
      u3 --BATCH_MATMUL(adjX=old_adj_x, adjY=*)--> y

    Rewrite:
      x_nhwc --SQUEEZE(axis=perm[s])--> s3' --(UNARY)*--> u3'
      u3' --BATCH_MATMUL(adjX=new_adj_x, adjY=*)--> y

    where `new_adj_x` is chosen so matmul semantics are preserved.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    unary_passthrough_ops = {
        "RELU",
        "RELU6",
        "RELU_0_TO_1",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "CAST",
        "FLOOR",
        "CEIL",
        "ROUND",
        "HARD_SWISH",
    }

    def _shape_list(name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or tensor.shape is None:
            return None
        return [int(v) for v in list(tensor.shape)]

    def _dims_compatible(a: int, b: int) -> bool:
        if int(a) < 0 or int(b) < 0:
            return True
        return int(a) == int(b)

    def _shape_compatible(a: List[int], b: List[int]) -> bool:
        if len(a) != len(b):
            return False
        return all(_dims_compatible(int(x), int(y)) for x, y in zip(a, b))

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue
            squeeze_idx = int(pre_users[0])
            squeeze_op = model_ir.operators[int(squeeze_idx)]
            if (
                str(squeeze_op.op_type) != "SQUEEZE"
                or len(squeeze_op.inputs) != 1
                or len(squeeze_op.outputs) != 1
                or str(squeeze_op.inputs[0]) != pre_output_name
            ):
                continue

            squeeze_out_name = str(squeeze_op.outputs[0])
            if squeeze_out_name in model_outputs:
                continue

            # Collect optional strict unary chain.
            chain_indices: List[int] = []
            chain_output_names: List[str] = []
            current_name = str(squeeze_out_name)
            while True:
                current_users = [int(v) for v in consumers.get(current_name, [])]
                if len(current_users) != 1:
                    break
                unary_idx = int(current_users[0])
                unary_op = model_ir.operators[int(unary_idx)]
                if (
                    str(unary_op.op_type) not in unary_passthrough_ops
                    or len(unary_op.inputs) != 1
                    or len(unary_op.outputs) != 1
                    or str(unary_op.inputs[0]) != current_name
                ):
                    break
                unary_out_name = str(unary_op.outputs[0])
                if unary_out_name in model_outputs:
                    break
                chain_indices.append(int(unary_idx))
                chain_output_names.append(str(unary_out_name))
                current_name = str(unary_out_name)

            tail_users = [int(v) for v in consumers.get(current_name, [])]
            if len(tail_users) != 1:
                continue
            matmul_idx = int(tail_users[0])
            matmul_op = model_ir.operators[int(matmul_idx)]
            if (
                str(matmul_op.op_type) != "BATCH_MATMUL"
                or len(matmul_op.inputs) != 2
                or len(matmul_op.outputs) != 1
            ):
                continue
            matmul_inputs = [str(v) for v in list(matmul_op.inputs)]
            if current_name == matmul_inputs[0]:
                matmul_data_input_index = 0
            elif current_name == matmul_inputs[1]:
                matmul_data_input_index = 1
            else:
                continue
            # Keep this rewrite strict to avoid changing rhs transpose semantics.
            if int(matmul_data_input_index) != 0:
                continue

            pre_input_shape = _shape_list(pre_input_name)
            pre_output_shape = _shape_list(pre_output_name)
            squeeze_shape = _shape_list(squeeze_out_name)
            if (
                pre_input_shape is None
                or pre_output_shape is None
                or squeeze_shape is None
                or len(pre_input_shape) != 4
                or len(pre_output_shape) != 4
                or len(squeeze_shape) != 3
            ):
                continue

            # Determine squeeze axis in transposed domain.
            squeeze_options = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
            squeeze_axis: Optional[int] = None
            if "squeezeDims" in squeeze_options:
                raw_axes = np.asarray(squeeze_options.get("squeezeDims", []), dtype=np.int64).reshape(-1)
                normalized_axes = _normalize_squeeze_axes_for_rank(
                    [int(v) for v in raw_axes.tolist()],
                    4,
                )
                if normalized_axes is None or len(normalized_axes) != 1:
                    continue
                squeeze_axis = int(normalized_axes[0])
            else:
                continue

            # Old order (after transpose+squeeze): [in[perm[j]] for j != squeeze_axis]
            old_dim_indices = [
                int(perm_nhwc_to_nchw[j])
                for j in range(4)
                if int(j) != int(squeeze_axis)
            ]
            src_axis = int(perm_nhwc_to_nchw[int(squeeze_axis)])
            new_dim_indices = [int(i) for i in range(4) if int(i) != int(src_axis)]

            # Only support identity or last-two swap; BATCH_MATMUL adjX can express this.
            old_adj_x = bool(dict(matmul_op.options).get("adjX", False)) if isinstance(matmul_op.options, dict) else False
            if old_dim_indices == new_dim_indices:
                perm_rank3: Optional[List[int]] = None
                new_adj_x = bool(old_adj_x)
            elif old_dim_indices == [int(new_dim_indices[0]), int(new_dim_indices[2]), int(new_dim_indices[1])]:
                perm_rank3 = [0, 2, 1]
                new_adj_x = bool(not old_adj_x)
            else:
                continue

            expected_old_squeeze_shape = [int(pre_input_shape[idx]) for idx in old_dim_indices]
            if not _shape_compatible(squeeze_shape, expected_old_squeeze_shape):
                continue
            if int(pre_input_shape[src_axis]) >= 0 and int(pre_input_shape[src_axis]) != 1:
                continue

            # Rewire squeeze to consume NHWC tensor and remove pre-transpose.
            _set_operator_inputs(
                model_ir=model_ir,
                op=squeeze_op,
                new_inputs=[pre_input_name],
            )
            squeeze_options["squeezeDims"] = [int(src_axis)]
            squeeze_op.options = squeeze_options

            # Adjust unary metadata to the new rank-3 axis order.
            if perm_rank3 is not None:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(squeeze_out_name, None),
                    perm_rank3,
                )
                for chain_out_name in chain_output_names:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(chain_out_name, None),
                        perm_rank3,
                    )

            # Update BATCH_MATMUL adjX to preserve semantics.
            matmul_options = dict(matmul_op.options) if isinstance(matmul_op.options, dict) else {}
            matmul_options["adjX"] = bool(new_adj_x)
            matmul_op.options = matmul_options

            del model_ir.operators[int(pre_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_squeeze_unary_batchmatmul_nhwc_chains": int(rewritten)}


def _optimize_decoder_batchmatmul_add_expand_transpose_to_nhwc_deconv_input(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove decoder-side EXPAND_DIMS->TRANSPOSE adapters before TRANSPOSE_CONV
    by transposing the preceding BATCH_MATMUL/ADD layout instead.

    Target:
      mm = BATCH_MATMUL(X, W)                  # [N, C, L]
      a  = ADD(mm, b[L])
      e  = EXPAND_DIMS(a, axis=2)              # [N, C, 1, L]
      t  = TRANSPOSE(e, [0,2,3,1])             # [N, 1, L, C]
      y  = TRANSPOSE_CONV(..., t)

    Rewrite (equivalent):
      mm_t = BATCH_MATMUL(W, X, adjX=not old_adjY, adjY=not old_adjX)  # [N, L, C]
      a_t  = ADD(mm_t, b.reshape([1,L,1]))
      e_t  = EXPAND_DIMS(a_t, axis=1)                                   # [N,1,L,C]
      y    = TRANSPOSE_CONV(..., e_t)
    """
    rewritten = 0
    perm_expand_to_deconv = [0, 2, 3, 1]
    rank3_swap = [0, 2, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for transpose_idx, transpose_op in enumerate(model_ir.operators):
            if str(transpose_op.op_type) != "TRANSPOSE" or len(transpose_op.inputs) < 2 or len(transpose_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, transpose_op) != perm_expand_to_deconv:
                continue

            expand_out_name = str(transpose_op.inputs[0])
            transpose_out_name = str(transpose_op.outputs[0])
            if transpose_out_name in model_outputs:
                continue

            transpose_users = [int(v) for v in consumers.get(transpose_out_name, [])]
            if len(transpose_users) != 1:
                continue
            deconv_idx = int(transpose_users[0])
            deconv_op = model_ir.operators[int(deconv_idx)]
            if (
                str(deconv_op.op_type) != "TRANSPOSE_CONV"
                or len(deconv_op.inputs) < 3
                or str(deconv_op.inputs[2]) != transpose_out_name
            ):
                continue

            expand_idx = producers.get(expand_out_name, None)
            if expand_idx is None:
                continue
            expand_op = model_ir.operators[int(expand_idx)]
            if (
                str(expand_op.op_type) != "EXPAND_DIMS"
                or len(expand_op.inputs) < 2
                or len(expand_op.outputs) != 1
                or str(expand_op.outputs[0]) != expand_out_name
            ):
                continue

            expand_in_name = str(expand_op.inputs[0])
            add_idx = producers.get(expand_in_name, None)
            if add_idx is None:
                continue
            add_op = model_ir.operators[int(add_idx)]
            if (
                str(add_op.op_type) != "ADD"
                or len(add_op.inputs) != 2
                or len(add_op.outputs) != 1
                or str(add_op.outputs[0]) != expand_in_name
            ):
                continue

            add_users = [int(v) for v in consumers.get(expand_in_name, [])]
            if len(add_users) != 1 or int(add_users[0]) != int(expand_idx):
                continue

            add_input0 = str(add_op.inputs[0])
            add_input1 = str(add_op.inputs[1])
            mm_idx = producers.get(add_input0, None)
            bias_name = add_input1
            if mm_idx is None or str(model_ir.operators[int(mm_idx)].op_type) != "BATCH_MATMUL":
                mm_idx = producers.get(add_input1, None)
                bias_name = add_input0
            if mm_idx is None:
                continue
            mm_op = model_ir.operators[int(mm_idx)]
            if (
                str(mm_op.op_type) != "BATCH_MATMUL"
                or len(mm_op.inputs) != 2
                or len(mm_op.outputs) != 1
                or str(mm_op.outputs[0]) not in {add_input0, add_input1}
            ):
                continue

            mm_out_name = str(mm_op.outputs[0])
            mm_users = [int(v) for v in consumers.get(mm_out_name, [])]
            if len(mm_users) != 1 or int(mm_users[0]) != int(add_idx):
                continue

            mm_out_tensor = model_ir.tensors.get(mm_out_name, None)
            add_out_tensor = model_ir.tensors.get(expand_in_name, None)
            expand_out_tensor = model_ir.tensors.get(expand_out_name, None)
            transpose_out_tensor = model_ir.tensors.get(transpose_out_name, None)
            bias_tensor = model_ir.tensors.get(bias_name, None)
            if (
                mm_out_tensor is None
                or add_out_tensor is None
                or expand_out_tensor is None
                or transpose_out_tensor is None
                or bias_tensor is None
                or bias_tensor.data is None
            ):
                continue
            if len(list(mm_out_tensor.shape)) != 3 or len(list(add_out_tensor.shape)) != 3:
                continue
            if len(list(expand_out_tensor.shape)) != 4 or len(list(transpose_out_tensor.shape)) != 4:
                continue

            old_mm_shape = [int(v) for v in list(mm_out_tensor.shape)]
            if len(old_mm_shape) != 3:
                continue
            length_dim = int(old_mm_shape[2])
            if length_dim <= 0:
                continue

            bias_values = np.asarray(bias_tensor.data)
            if int(bias_values.size) != int(length_dim):
                continue

            # Update BATCH_MATMUL to emit transposed rank-3 layout directly.
            mm_options = dict(mm_op.options) if isinstance(mm_op.options, dict) else {}
            old_adj_x = bool(mm_options.get("adjX", False))
            old_adj_y = bool(mm_options.get("adjY", False))
            old_mm_inputs = [str(v) for v in list(mm_op.inputs)]
            _set_operator_inputs(
                model_ir=model_ir,
                op=mm_op,
                new_inputs=[old_mm_inputs[1], old_mm_inputs[0]],
            )
            mm_options["adjX"] = bool(not old_adj_y)
            mm_options["adjY"] = bool(not old_adj_x)
            mm_op.options = mm_options
            _permute_tensor_metadata_if_rank_matches(mm_out_tensor, rank3_swap)
            _permute_tensor_metadata_if_rank_matches(add_out_tensor, rank3_swap)

            # Bias was [L], but after rank-3 transpose it must broadcast on axis=1.
            reshaped_bias = np.asarray(bias_values).reshape(1, int(length_dim), 1)
            bias_tensor.data = reshaped_bias.astype(bias_values.dtype, copy=False)
            bias_tensor.shape = [1, int(length_dim), 1]
            bias_tensor.shape_signature = [1, int(length_dim), 1]

            # EXPAND_DIMS axis: 2 -> 1 for [N,L,C] -> [N,1,L,C].
            expand_axis_tensor = model_ir.tensors.get(str(expand_op.inputs[1]), None)
            if expand_axis_tensor is None:
                continue
            if not _write_const_ints_to_tensor(expand_axis_tensor, [1]):
                continue

            expand_out_tensor.shape = [int(v) for v in list(transpose_out_tensor.shape)]
            expand_out_tensor.shape_signature = (
                [int(v) for v in list(transpose_out_tensor.shape_signature)]
                if transpose_out_tensor.shape_signature is not None
                else [int(v) for v in list(transpose_out_tensor.shape)]
            )

            # Bypass transpose into deconv input.
            _replace_operator_input_at(
                model_ir=model_ir,
                op=deconv_op,
                input_index=2,
                new_input_name=expand_out_name,
            )

            del model_ir.operators[int(transpose_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {
        "optimized_decoder_batchmatmul_add_expand_transpose_to_nhwc_deconv_input": int(rewritten)
    }


def _optimize_transpose_squeeze_mean_squeeze_terminal_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove terminal NHWC->NCHW transpose in:
      x --T(0,3,1,2)--> t --SQUEEZE(axis=2)--> s --MEAN(axis=1,keepDims)--> m --SQUEEZE(axis=1)--> y

    Equivalent NHWC rewrite:
      x --SQUEEZE(axis=1)--> s' --MEAN(axis=2,keepDims)--> m' --SQUEEZE(axis=2)--> y
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    rank3_swap = [0, 2, 1]

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for transpose_idx, transpose_op in enumerate(model_ir.operators):
            if str(transpose_op.op_type) != "TRANSPOSE" or len(transpose_op.inputs) < 2 or len(transpose_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, transpose_op) != perm_nhwc_to_nchw:
                continue

            x_name = str(transpose_op.inputs[0])
            t_name = str(transpose_op.outputs[0])
            if t_name in model_outputs:
                continue

            t_users = [int(v) for v in consumers.get(t_name, [])]
            if len(t_users) != 1:
                continue
            squeeze1_idx = int(t_users[0])
            squeeze1_op = model_ir.operators[int(squeeze1_idx)]
            if (
                str(squeeze1_op.op_type) != "SQUEEZE"
                or len(squeeze1_op.inputs) != 1
                or len(squeeze1_op.outputs) != 1
                or str(squeeze1_op.inputs[0]) != t_name
            ):
                continue

            squeeze1_opts = dict(squeeze1_op.options) if isinstance(squeeze1_op.options, dict) else {}
            squeeze1_axes = _normalize_squeeze_axes_for_rank(
                _parse_axes_option(squeeze1_opts.get("squeezeDims", [])),
                4,
            )
            if squeeze1_axes is None or [int(v) for v in squeeze1_axes] != [2]:
                continue
            s_name = str(squeeze1_op.outputs[0])
            if s_name in model_outputs:
                continue

            s_users = [int(v) for v in consumers.get(s_name, [])]
            if len(s_users) != 1:
                continue
            mean_idx = int(s_users[0])
            mean_op = model_ir.operators[int(mean_idx)]
            if (
                str(mean_op.op_type) != "MEAN"
                or len(mean_op.inputs) < 2
                or len(mean_op.outputs) != 1
                or str(mean_op.inputs[0]) != s_name
                or not bool(mean_op.options.get("keepDims", False))
            ):
                continue

            mean_axes_name = str(mean_op.inputs[1])
            mean_axes_tensor = model_ir.tensors.get(mean_axes_name, None)
            mean_axes_vals = _read_const_ints_from_tensor(mean_axes_tensor)
            if mean_axes_vals is None:
                continue
            mean_axes_norm = _normalize_squeeze_axes_for_rank(
                [int(v) for v in mean_axes_vals],
                3,
            )
            if mean_axes_norm is None or [int(v) for v in mean_axes_norm] != [1]:
                continue

            m_name = str(mean_op.outputs[0])
            if m_name in model_outputs:
                continue
            m_users = [int(v) for v in consumers.get(m_name, [])]
            if len(m_users) != 1:
                continue
            squeeze2_idx = int(m_users[0])
            squeeze2_op = model_ir.operators[int(squeeze2_idx)]
            if (
                str(squeeze2_op.op_type) != "SQUEEZE"
                or len(squeeze2_op.inputs) != 1
                or len(squeeze2_op.outputs) != 1
                or str(squeeze2_op.inputs[0]) != m_name
            ):
                continue

            squeeze2_opts = dict(squeeze2_op.options) if isinstance(squeeze2_op.options, dict) else {}
            squeeze2_axes = _normalize_squeeze_axes_for_rank(
                _parse_axes_option(squeeze2_opts.get("squeezeDims", [])),
                3,
            )
            if squeeze2_axes is None or [int(v) for v in squeeze2_axes] != [1]:
                continue

            x_tensor = model_ir.tensors.get(x_name, None)
            t_tensor = model_ir.tensors.get(t_name, None)
            s_tensor = model_ir.tensors.get(s_name, None)
            m_tensor = model_ir.tensors.get(m_name, None)
            if (
                x_tensor is None
                or t_tensor is None
                or s_tensor is None
                or m_tensor is None
                or len(list(x_tensor.shape)) != 4
                or len(list(t_tensor.shape)) != 4
                or len(list(s_tensor.shape)) != 3
                or len(list(m_tensor.shape)) != 3
            ):
                continue

            # Rewire chain onto NHWC source and remap axes.
            _set_operator_inputs(
                model_ir=model_ir,
                op=squeeze1_op,
                new_inputs=[x_name],
            )
            squeeze1_opts["squeezeDims"] = [1]
            squeeze1_op.options = squeeze1_opts

            if mean_axes_tensor is None or not _write_const_ints_to_tensor(mean_axes_tensor, [2]):
                continue

            squeeze2_opts["squeezeDims"] = [2]
            squeeze2_op.options = squeeze2_opts

            # rank-3 tensors between squeeze1 and mean are [N,C,W] -> [N,W,C]
            _permute_tensor_metadata_if_rank_matches(s_tensor, rank3_swap)
            _permute_tensor_metadata_if_rank_matches(m_tensor, rank3_swap)

            del model_ir.operators[int(transpose_idx)]
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_squeeze_mean_squeeze_terminal_nhwc_chains": int(rewritten)
    }


def _optimize_squeeze_unary_reshape_passthrough_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_squeeze_unary_reshape_passthrough_chains_pass(model_ir)
def _optimize_squeeze_reshape_identity_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_squeeze_reshape_identity_chains_pass(model_ir)


def _optimize_transpose_instancenorm_prepost_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NHWC<->NCHW transpose bridges around decomposed InstanceNormalization blocks.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --SQUEEZE(axis=0)--> s0 --RESHAPE--> r0
      r0 --(InstanceNormalization decomposition in NCHW)--> y_nchw
      y_nchw --SQUEEZE(axis=0)--> s1 --UNARY--> u1 --RESHAPE--> r1
      r1 --TRANSPOSE(0,2,3,1)--> z_nhwc

    Rewrite:
      x_nhwc --SQUEEZE(axis=0)--> s0_hwc --RESHAPE(NHWC)--> r0_nhwc
      r0_nhwc --(same decomposition rewritten to NHWC axes/broadcast)--> y_nhwc
      y_nhwc --SQUEEZE(axis=0)--> s1_hwc --UNARY--> u1_hwc --RESHAPE(NHWC)--> z_nhwc
    """
    rewritten = 0
    # Keep this pass conservative for now: broad propagation can degrade
    # intermediate tensor correspondence quality in --report_op_coverage flows.
    max_total_rewrites = 32
    channel_last_hint_names = {
        str(v)
        for v in model_ir.metadata.get("assume_channel_last_layout_tensor_names", [])
        if str(v) != ""
    }
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_3d_chw_to_hwc = [1, 2, 0]
    unary_ops = {
        "RELU",
        "RELU6",
        "LEAKY_RELU",
        "LOGISTIC",
        "TANH",
        "ABS",
        "NEG",
        "SQRT",
        "EXP",
        "CAST",
        "FLOOR",
        "CEIL",
        "ROUND",
    }
    tail_nhwc_to_nchw_perm_name = "__instancenorm_tail_nhwc_to_nchw_perm_rank4__"
    tail_hwc_to_chw_perm_name = "__instancenorm_tail_hwc_to_chw_perm_rank3__"

    def _single_consumer_index(consumers: Dict[str, List[int]], tensor_name: str) -> Optional[int]:
        users = [int(v) for v in consumers.get(str(tensor_name), [])]
        if len(users) != 1:
            return None
        return int(users[0])

    def _single_producer_index(producers: Dict[str, int], tensor_name: str) -> Optional[int]:
        idx = producers.get(str(tensor_name), None)
        if idx is None:
            return None
        return int(idx)

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _const_ints(name: str) -> Optional[List[int]]:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or tensor.data is None:
            return None
        arr = np.asarray(tensor.data).reshape(-1)
        if arr.size == 0:
            return []
        return [int(v) for v in arr.tolist()]

    def _is_squeeze_axis0(
        *,
        squeeze_op: OperatorIR,
        input_name: str,
        output_name: str,
    ) -> bool:
        in_tensor = model_ir.tensors.get(str(input_name), None)
        out_tensor = model_ir.tensors.get(str(output_name), None)
        if in_tensor is None or out_tensor is None:
            return False
        in_shape = [int(v) for v in list(in_tensor.shape)]
        out_shape = [int(v) for v in list(out_tensor.shape)]
        if len(in_shape) != 4 or len(out_shape) != 3:
            return False
        if int(in_shape[0]) != 1:
            return False
        if out_shape != [int(in_shape[1]), int(in_shape[2]), int(in_shape[3])]:
            return False
        options = dict(squeeze_op.options) if isinstance(squeeze_op.options, dict) else {}
        if "squeezeDims" in options:
            dims = [int(v) for v in np.asarray(options.get("squeezeDims", [])).reshape(-1).tolist()]
            if dims != [0]:
                return False
        return True

    def _rewrite_reshape_shape_const(
        *,
        reshape_op: OperatorIR,
        reshape_idx: int,
        target_shape: List[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        if len(reshape_op.inputs) < 2:
            return False
        shape_name = str(reshape_op.inputs[1])
        shape_users = set(int(v) for v in consumers.get(shape_name, []))
        if shape_users != {int(reshape_idx)}:
            return False
        shape_tensor = model_ir.tensors.get(shape_name, None)
        if shape_tensor is None or shape_tensor.data is None:
            return False
        dtype = np.asarray(shape_tensor.data).dtype
        if dtype.kind not in {"i", "u"}:
            return False
        new_data = np.asarray([int(v) for v in list(target_shape)], dtype=dtype)
        shape_tensor.data = new_data
        shape_tensor.shape = [int(v) for v in list(new_data.shape)]
        shape_tensor.shape_signature = [int(v) for v in list(new_data.shape)]
        options = dict(reshape_op.options) if isinstance(reshape_op.options, dict) else {}
        options["newShape"] = [int(v) for v in list(target_shape)]
        reshape_op.options = options
        return True

    def _rewrite_reduce_axes_to_nhwc(
        *,
        axes_name: str,
        expected_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        axes_users = set(int(v) for v in consumers.get(str(axes_name), []))
        if axes_users != expected_users:
            return False
        axes_tensor = model_ir.tensors.get(str(axes_name), None)
        if axes_tensor is None or axes_tensor.data is None:
            return False
        dtype = np.asarray(axes_tensor.data).dtype
        if dtype.kind not in {"i", "u"}:
            return False
        axes_tensor.data = np.asarray([1, 2], dtype=dtype)
        axes_tensor.shape = [2]
        axes_tensor.shape_signature = [2]
        return True

    def _rewrite_nchw_coeff_to_nhwc(coeff_name: str) -> bool:
        coeff_tensor = model_ir.tensors.get(str(coeff_name), None)
        if coeff_tensor is None or coeff_tensor.data is None:
            return False
        coeff = np.asarray(coeff_tensor.data)
        if coeff.ndim != 4:
            return False
        if int(coeff.shape[0]) != 1 or int(coeff.shape[2]) != 1 or int(coeff.shape[3]) != 1:
            return False
        coeff_tensor.data = np.transpose(coeff, (0, 2, 3, 1))
        coeff_tensor.shape = [int(v) for v in list(coeff_tensor.data.shape)]
        coeff_tensor.shape_signature = [int(v) for v in list(coeff_tensor.data.shape)]
        return True

    while rewritten < max_total_rewrites:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            if pre_in_name in model_outputs or pre_out_name in model_outputs:
                continue

            squeeze1_idx = _single_consumer_index(consumers, pre_out_name)
            if squeeze1_idx is None:
                continue
            squeeze1_op = model_ir.operators[int(squeeze1_idx)]
            if str(squeeze1_op.op_type) != "SQUEEZE" or len(squeeze1_op.inputs) != 1 or len(squeeze1_op.outputs) != 1:
                continue
            squeeze1_out_name = str(squeeze1_op.outputs[0])
            if not _is_squeeze_axis0(
                squeeze_op=squeeze1_op,
                input_name=pre_out_name,
                output_name=squeeze1_out_name,
            ):
                continue

            reshape1_idx = _single_consumer_index(consumers, squeeze1_out_name)
            if reshape1_idx is None:
                continue
            reshape1_op = model_ir.operators[int(reshape1_idx)]
            if str(reshape1_op.op_type) != "RESHAPE" or len(reshape1_op.inputs) < 2 or len(reshape1_op.outputs) != 1:
                continue
            x_name = str(reshape1_op.outputs[0])
            x_users = set(int(v) for v in consumers.get(x_name, []))
            if len(x_users) != 2:
                continue

            mean1_idx = None
            sub_idx = None
            for idx in sorted(list(x_users)):
                op = model_ir.operators[int(idx)]
                if str(op.op_type) == "MEAN" and len(op.inputs) == 2 and str(op.inputs[0]) == x_name:
                    mean1_idx = int(idx)
                elif str(op.op_type) == "SUB" and len(op.inputs) == 2 and x_name in set(str(v) for v in op.inputs):
                    sub_idx = int(idx)
            if mean1_idx is None or sub_idx is None:
                continue
            mean1_op = model_ir.operators[int(mean1_idx)]
            sub_op = model_ir.operators[int(sub_idx)]
            mean1_out_name = str(mean1_op.outputs[0]) if len(mean1_op.outputs) == 1 else ""
            if mean1_out_name == "":
                continue
            if mean1_out_name not in set(str(v) for v in sub_op.inputs):
                continue
            if str(sub_op.outputs[0]) in model_outputs:
                continue
            centered_name = str(sub_op.outputs[0])

            centered_users = set(int(v) for v in consumers.get(centered_name, []))
            if len(centered_users) != 2:
                continue
            mul_square_idx = None
            mul_norm_idx = None
            for idx in sorted(list(centered_users)):
                op = model_ir.operators[int(idx)]
                if str(op.op_type) != "MUL" or len(op.inputs) != 2 or len(op.outputs) != 1:
                    continue
                in0 = str(op.inputs[0])
                in1 = str(op.inputs[1])
                if in0 == centered_name and in1 == centered_name:
                    mul_square_idx = int(idx)
                elif centered_name in {in0, in1}:
                    mul_norm_idx = int(idx)
            if mul_square_idx is None or mul_norm_idx is None:
                continue

            mul_square_op = model_ir.operators[int(mul_square_idx)]
            squared_name = str(mul_square_op.outputs[0])
            mean2_idx = _single_consumer_index(consumers, squared_name)
            if mean2_idx is None:
                continue
            mean2_op = model_ir.operators[int(mean2_idx)]
            if str(mean2_op.op_type) != "MEAN" or len(mean2_op.inputs) != 2 or len(mean2_op.outputs) != 1:
                continue
            if str(mean2_op.inputs[0]) != squared_name:
                continue
            mean2_out_name = str(mean2_op.outputs[0])

            add_eps_idx = _single_consumer_index(consumers, mean2_out_name)
            if add_eps_idx is None:
                continue
            add_eps_op = model_ir.operators[int(add_eps_idx)]
            if str(add_eps_op.op_type) != "ADD" or len(add_eps_op.inputs) != 2 or len(add_eps_op.outputs) != 1:
                continue
            if mean2_out_name not in set(str(v) for v in add_eps_op.inputs):
                continue
            add_eps_out_name = str(add_eps_op.outputs[0])

            sqrt_idx = _single_consumer_index(consumers, add_eps_out_name)
            if sqrt_idx is None:
                continue
            sqrt_op = model_ir.operators[int(sqrt_idx)]
            if str(sqrt_op.op_type) != "SQRT" or len(sqrt_op.inputs) != 1 or len(sqrt_op.outputs) != 1:
                continue
            if str(sqrt_op.inputs[0]) != add_eps_out_name:
                continue
            sqrt_out_name = str(sqrt_op.outputs[0])

            div_idx = _single_consumer_index(consumers, sqrt_out_name)
            if div_idx is None:
                continue
            div_op = model_ir.operators[int(div_idx)]
            if str(div_op.op_type) != "DIV" or len(div_op.inputs) != 2 or len(div_op.outputs) != 1:
                continue
            if str(div_op.inputs[1]) != sqrt_out_name:
                continue
            div_out_name = str(div_op.outputs[0])

            mul_norm_op = model_ir.operators[int(mul_norm_idx)]
            if div_out_name not in set(str(v) for v in mul_norm_op.inputs):
                continue
            normalized_name = str(mul_norm_op.outputs[0])

            mul_scale_idx = _single_consumer_index(consumers, normalized_name)
            if mul_scale_idx is None:
                continue
            mul_scale_op = model_ir.operators[int(mul_scale_idx)]
            if str(mul_scale_op.op_type) != "MUL" or len(mul_scale_op.inputs) != 2 or len(mul_scale_op.outputs) != 1:
                continue
            if normalized_name not in set(str(v) for v in mul_scale_op.inputs):
                continue
            scale_const_name = str(mul_scale_op.inputs[0]) if str(mul_scale_op.inputs[1]) == normalized_name else str(mul_scale_op.inputs[1])
            scaled_name = str(mul_scale_op.outputs[0])

            add_bias_idx = _single_consumer_index(consumers, scaled_name)
            if add_bias_idx is None:
                continue
            add_bias_op = model_ir.operators[int(add_bias_idx)]
            if str(add_bias_op.op_type) != "ADD" or len(add_bias_op.inputs) != 2 or len(add_bias_op.outputs) != 1:
                continue
            if scaled_name not in set(str(v) for v in add_bias_op.inputs):
                continue
            bias_const_name = str(add_bias_op.inputs[0]) if str(add_bias_op.inputs[1]) == scaled_name else str(add_bias_op.inputs[1])
            inst_out_name = str(add_bias_op.outputs[0])

            tail_mode = "direct_post_transpose"
            side_squeeze_idx: Optional[int] = None
            squeeze2_out_name: Optional[str] = None
            unary_out_name: Optional[str] = None
            tail_add_out_name: Optional[str] = None
            tail_add_residual_input_name: Optional[str] = None
            tail_add_legacy_slots: List[Tuple[int, int]] = []
            tail_add_legacy_meta: Optional[Tuple[str, Optional[Any], List[int], List[int]]] = None
            reshape2_idx: Optional[int] = None
            reshape2_op: Optional[OperatorIR] = None
            reshape2_out_name = str(inst_out_name)
            extra_remove_indices: set[int] = set()

            post_idx = _single_consumer_index(consumers, inst_out_name)
            if post_idx is not None:
                post_op = model_ir.operators[int(post_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                    or str(post_op.inputs[0]) != inst_out_name
                ):
                    post_idx = None
            if post_idx is None:
                # Variant:
                #   inst_out_nchw -> {post_transpose_nchw_to_nhwc, squeeze(axis=0) side branch}
                # Keep side branch in NCHW via a local adapter transpose and still
                # eliminate the pre/post bridge pair around InstanceNormalization.
                inst_out_users = [int(v) for v in consumers.get(inst_out_name, [])]
                candidate_post_indices: List[int] = []
                for user_idx in inst_out_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == inst_out_name
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    ):
                        candidate_post_indices.append(int(user_idx))
                if len(candidate_post_indices) == 1 and len(inst_out_users) == 2:
                    candidate_post_idx = int(candidate_post_indices[0])
                    candidate_side_idx = (
                        int(inst_out_users[1])
                        if int(inst_out_users[0]) == candidate_post_idx
                        else int(inst_out_users[0])
                    )
                    candidate_side_op = model_ir.operators[int(candidate_side_idx)]
                    candidate_side_out_name = (
                        str(candidate_side_op.outputs[0]) if len(candidate_side_op.outputs) == 1 else ""
                    )
                    if (
                        str(candidate_side_op.op_type) == "SQUEEZE"
                        and len(candidate_side_op.inputs) == 1
                        and len(candidate_side_op.outputs) == 1
                        and _is_squeeze_axis0(
                            squeeze_op=candidate_side_op,
                            input_name=inst_out_name,
                            output_name=candidate_side_out_name,
                        )
                    ):
                        post_idx = int(candidate_post_idx)
                        side_squeeze_idx = int(candidate_side_idx)
                        tail_mode = "direct_post_transpose_side_squeeze"
            if post_idx is None:
                squeeze2_idx = _single_consumer_index(consumers, inst_out_name)
                if squeeze2_idx is not None:
                    candidate_squeeze_op = model_ir.operators[int(squeeze2_idx)]
                    if (
                        str(candidate_squeeze_op.op_type) == "SQUEEZE"
                        and len(candidate_squeeze_op.inputs) == 1
                        and len(candidate_squeeze_op.outputs) == 1
                    ):
                        candidate_squeeze2_out_name = str(candidate_squeeze_op.outputs[0])
                        if _is_squeeze_axis0(
                            squeeze_op=candidate_squeeze_op,
                            input_name=inst_out_name,
                            output_name=candidate_squeeze2_out_name,
                        ):
                            candidate_unary_idx = _single_consumer_index(consumers, candidate_squeeze2_out_name)
                            if candidate_unary_idx is not None:
                                candidate_unary_op = model_ir.operators[int(candidate_unary_idx)]
                                if (
                                    str(candidate_unary_op.op_type) in unary_ops
                                    and len(candidate_unary_op.inputs) == 1
                                    and len(candidate_unary_op.outputs) == 1
                                    and str(candidate_unary_op.inputs[0]) == candidate_squeeze2_out_name
                                ):
                                    candidate_unary_out_name = str(candidate_unary_op.outputs[0])
                                    candidate_reshape2_idx = _single_consumer_index(consumers, candidate_unary_out_name)
                                    if candidate_reshape2_idx is not None:
                                        candidate_reshape2_op = model_ir.operators[int(candidate_reshape2_idx)]
                                        if (
                                            str(candidate_reshape2_op.op_type) == "RESHAPE"
                                            and len(candidate_reshape2_op.inputs) >= 2
                                            and len(candidate_reshape2_op.outputs) == 1
                                        ):
                                            candidate_reshape2_out_name = str(candidate_reshape2_op.outputs[0])
                                            candidate_post_idx = _single_consumer_index(
                                                consumers,
                                                candidate_reshape2_out_name,
                                            )
                                            if candidate_post_idx is not None:
                                                candidate_post_op = model_ir.operators[int(candidate_post_idx)]
                                                if (
                                                    str(candidate_post_op.op_type) == "TRANSPOSE"
                                                    and len(candidate_post_op.inputs) >= 2
                                                    and len(candidate_post_op.outputs) == 1
                                                    and _read_transpose_perm(model_ir, candidate_post_op)
                                                    == perm_nchw_to_nhwc
                                                    and str(candidate_post_op.inputs[0]) == candidate_reshape2_out_name
                                                ):
                                                    tail_mode = "squeeze_unary_reshape"
                                                    squeeze2_out_name = str(candidate_squeeze2_out_name)
                                                    unary_out_name = str(candidate_unary_out_name)
                                                    reshape2_idx = int(candidate_reshape2_idx)
                                                    reshape2_op = candidate_reshape2_op
                                                    reshape2_out_name = str(candidate_reshape2_out_name)
                                                    post_idx = int(candidate_post_idx)

            if post_idx is None:
                # Variant:
                #   inst_out --SQUEEZE(axis=0)--> s
                #   s --ADD(residual_3d)--> a
                #   a --RESHAPE--> r
                #   r --TRANSPOSE(0,2,3,1)--> post_out
                tail_mode = "squeeze_add_reshape"
                squeeze2_idx = _single_consumer_index(consumers, inst_out_name)
                if squeeze2_idx is None:
                    continue
                squeeze2_op = model_ir.operators[int(squeeze2_idx)]
                if str(squeeze2_op.op_type) != "SQUEEZE" or len(squeeze2_op.inputs) != 1 or len(squeeze2_op.outputs) != 1:
                    continue
                squeeze2_out_name = str(squeeze2_op.outputs[0])
                if not _is_squeeze_axis0(
                    squeeze_op=squeeze2_op,
                    input_name=inst_out_name,
                    output_name=squeeze2_out_name,
                ):
                    continue

                add_tail_idx = _single_consumer_index(consumers, squeeze2_out_name)
                if add_tail_idx is None:
                    continue
                add_tail_op = model_ir.operators[int(add_tail_idx)]
                if str(add_tail_op.op_type) != "ADD" or len(add_tail_op.inputs) != 2 or len(add_tail_op.outputs) != 1:
                    continue
                if squeeze2_out_name not in set(str(v) for v in add_tail_op.inputs):
                    continue
                tail_add_residual_input_name = (
                    str(add_tail_op.inputs[0])
                    if str(add_tail_op.inputs[1]) == squeeze2_out_name
                    else str(add_tail_op.inputs[1])
                )
                tail_add_out_name = str(add_tail_op.outputs[0])

                tail_add_users = [int(v) for v in consumers.get(tail_add_out_name, [])]
                reshape2_candidates: List[int] = []
                for user_idx in tail_add_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "RESHAPE"
                        and len(user_op.inputs) >= 1
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == tail_add_out_name
                    ):
                        reshape2_candidates.append(int(user_idx))
                if len(reshape2_candidates) != 1:
                    continue
                reshape2_idx = int(reshape2_candidates[0])
                reshape2_op = model_ir.operators[int(reshape2_idx)]
                if str(reshape2_op.op_type) != "RESHAPE" or len(reshape2_op.inputs) < 2 or len(reshape2_op.outputs) != 1:
                    continue
                if str(reshape2_op.inputs[0]) != tail_add_out_name:
                    continue
                reshape2_out_name = str(reshape2_op.outputs[0])

                tail_add_legacy_slots = []
                for user_idx in tail_add_users:
                    if int(user_idx) == int(reshape2_idx):
                        continue
                    user_op = model_ir.operators[int(user_idx)]
                    input_indices = [
                        int(input_idx)
                        for input_idx, input_name in enumerate(list(user_op.inputs))
                        if str(input_name) == tail_add_out_name
                    ]
                    if len(input_indices) == 0:
                        continue
                    for input_idx in input_indices:
                        tail_add_legacy_slots.append((int(id(user_op)), int(input_idx)))
                if len(tail_add_legacy_slots) > 0:
                    tail_add_tensor = model_ir.tensors.get(tail_add_out_name, None)
                    if tail_add_tensor is None or len(list(tail_add_tensor.shape)) != 3:
                        continue
                    tail_add_legacy_meta = (
                        str(tail_add_tensor.dtype),
                        _clone_quantization(tail_add_tensor.quantization),
                        [int(v) for v in list(tail_add_tensor.shape)],
                        (
                            [int(v) for v in list(tail_add_tensor.shape_signature)]
                            if tail_add_tensor.shape_signature is not None
                            else [int(v) for v in list(tail_add_tensor.shape)]
                        ),
                    )

                post_idx = _single_consumer_index(consumers, reshape2_out_name)
                if post_idx is None:
                    continue
                post_op = model_ir.operators[int(post_idx)]
                if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                    continue
                if _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc:
                    continue
                if str(post_op.inputs[0]) != reshape2_out_name:
                    continue

                # If residual side still uses CHW via NHWC->NCHW transpose, lift it to HWC.
                # This removes one extra transpose in residual shortcuts.
                if tail_add_residual_input_name is not None and tail_add_residual_input_name != "":
                    residual_input_name = str(tail_add_residual_input_name)
                    residual_layout_rewritten = False
                    if set(int(v) for v in consumers.get(residual_input_name, [])) != {int(add_tail_idx)}:
                        continue
                    residual_producer_idx = _single_producer_index(producers, residual_input_name)
                    if residual_producer_idx is not None:
                        residual_producer_op = model_ir.operators[int(residual_producer_idx)]
                        if (
                            str(residual_producer_op.op_type) == "TRANSPOSE"
                            and len(residual_producer_op.inputs) >= 2
                            and len(residual_producer_op.outputs) == 1
                            and str(residual_producer_op.outputs[0]) == residual_input_name
                            and _read_transpose_perm(model_ir, residual_producer_op) == [2, 0, 1]
                        ):
                            residual_src_name = str(residual_producer_op.inputs[0])
                            if residual_src_name in model_outputs:
                                continue
                            for input_idx, input_name in enumerate(list(add_tail_op.inputs)):
                                if str(input_name) == residual_input_name:
                                    _replace_operator_input_at(
                                        model_ir=model_ir,
                                        op=add_tail_op,
                                        input_index=int(input_idx),
                                        new_input_name=residual_src_name,
                                    )
                            tail_add_residual_input_name = str(residual_src_name)
                            residual_layout_rewritten = True
                            extra_remove_indices.add(int(residual_producer_idx))
                        else:
                            residual_squeeze_op: Optional[OperatorIR] = None
                            residual_squeeze_idx: Optional[int] = None
                            residual_squeeze_out_name: Optional[str] = None
                            residual_pre_transpose_idx: Optional[int] = None
                            residual_unary_out_name: Optional[str] = None

                            if str(residual_producer_op.op_type) in unary_ops and len(residual_producer_op.inputs) == 1:
                                candidate_squeeze_out = str(residual_producer_op.inputs[0])
                                candidate_squeeze_idx = _single_producer_index(producers, candidate_squeeze_out)
                                if candidate_squeeze_idx is not None:
                                    candidate_squeeze_op = model_ir.operators[int(candidate_squeeze_idx)]
                                    if (
                                        str(candidate_squeeze_op.op_type) == "SQUEEZE"
                                        and len(candidate_squeeze_op.inputs) == 1
                                        and len(candidate_squeeze_op.outputs) == 1
                                        and str(candidate_squeeze_op.outputs[0]) == candidate_squeeze_out
                                    ):
                                        residual_squeeze_op = candidate_squeeze_op
                                        residual_squeeze_idx = int(candidate_squeeze_idx)
                                        residual_squeeze_out_name = str(candidate_squeeze_out)
                                        residual_unary_out_name = str(residual_input_name)
                            elif str(residual_producer_op.op_type) == "SQUEEZE" and len(residual_producer_op.inputs) == 1:
                                residual_squeeze_op = residual_producer_op
                                residual_squeeze_idx = int(residual_producer_idx)
                                residual_squeeze_out_name = str(residual_input_name)

                            if (
                                residual_squeeze_op is not None
                                and residual_squeeze_idx is not None
                                and residual_squeeze_out_name is not None
                            ):
                                residual_squeeze_in_name = str(residual_squeeze_op.inputs[0])
                                if _is_squeeze_axis0(
                                    squeeze_op=residual_squeeze_op,
                                    input_name=residual_squeeze_in_name,
                                    output_name=residual_squeeze_out_name,
                                ):
                                    candidate_pre_idx = _single_producer_index(producers, residual_squeeze_in_name)
                                    if candidate_pre_idx is not None:
                                        candidate_pre_op = model_ir.operators[int(candidate_pre_idx)]
                                        if (
                                            str(candidate_pre_op.op_type) == "TRANSPOSE"
                                            and len(candidate_pre_op.inputs) >= 2
                                            and len(candidate_pre_op.outputs) == 1
                                            and str(candidate_pre_op.outputs[0]) == residual_squeeze_in_name
                                            and _read_transpose_perm(model_ir, candidate_pre_op) == perm_nhwc_to_nchw
                                        ):
                                            pre_out_users = set(int(v) for v in consumers.get(residual_squeeze_in_name, []))
                                            if (
                                                pre_out_users == {int(residual_squeeze_idx)}
                                                and residual_squeeze_in_name not in model_outputs
                                            ):
                                                residual_pre_transpose_idx = int(candidate_pre_idx)
                                                _set_operator_inputs(
                                                    model_ir=model_ir,
                                                    op=residual_squeeze_op,
                                                    new_inputs=[str(candidate_pre_op.inputs[0])],
                                                )
                                                _permute_tensor_metadata_if_rank_matches(
                                                    model_ir.tensors.get(residual_squeeze_out_name, None),
                                                    perm_3d_chw_to_hwc,
                                                )
                                                channel_last_hint_names.add(str(residual_squeeze_out_name))
                                                if residual_unary_out_name is not None:
                                                    _permute_tensor_metadata_if_rank_matches(
                                                        model_ir.tensors.get(str(residual_unary_out_name), None),
                                                        perm_3d_chw_to_hwc,
                                                    )
                                                    channel_last_hint_names.add(str(residual_unary_out_name))
                                                residual_layout_rewritten = True
                            if residual_pre_transpose_idx is not None:
                                extra_remove_indices.add(int(residual_pre_transpose_idx))
                    if not residual_layout_rewritten:
                        continue

            post_op = model_ir.operators[int(post_idx)]
            post_out_name = str(post_op.outputs[0])
            if post_out_name in model_outputs:
                continue

            if not _rewrite_reduce_axes_to_nhwc(
                axes_name=str(mean1_op.inputs[1]),
                expected_users={int(mean1_idx), int(mean2_idx)},
                consumers=consumers,
            ):
                continue
            if str(mean2_op.inputs[1]) != str(mean1_op.inputs[1]):
                if not _rewrite_reduce_axes_to_nhwc(
                    axes_name=str(mean2_op.inputs[1]),
                    expected_users={int(mean2_idx)},
                    consumers=consumers,
                ):
                    continue

            if not _rewrite_nchw_coeff_to_nhwc(scale_const_name):
                continue
            if not _rewrite_nchw_coeff_to_nhwc(bias_const_name):
                continue

            pre_in_tensor = model_ir.tensors.get(pre_in_name, None)
            reshape1_tensor = model_ir.tensors.get(x_name, None)
            if pre_in_tensor is None or reshape1_tensor is None:
                continue
            target_shape1 = [int(v) for v in list(pre_in_tensor.shape)]
            if len(target_shape1) != 4:
                continue
            if not _rewrite_reshape_shape_const(
                reshape_op=reshape1_op,
                reshape_idx=int(reshape1_idx),
                target_shape=target_shape1,
                consumers=consumers,
            ):
                continue

            if tail_mode in {"squeeze_unary_reshape", "squeeze_add_reshape"}:
                if reshape2_op is None or reshape2_idx is None:
                    continue
                reshape2_out_tensor = model_ir.tensors.get(reshape2_out_name, None)
                target_shape2 = None
                if reshape2_out_tensor is not None:
                    target_shape2 = _permute_shape(
                        [int(v) for v in list(reshape2_out_tensor.shape)],
                        perm_nchw_to_nhwc,
                    )
                if target_shape2 is None:
                    post_out_tensor = model_ir.tensors.get(post_out_name, None)
                    if post_out_tensor is not None:
                        target_shape2 = [int(v) for v in list(post_out_tensor.shape)]
                if target_shape2 is None or len(target_shape2) != 4:
                    continue
                if not _rewrite_reshape_shape_const(
                    reshape_op=reshape2_op,
                    reshape_idx=int(reshape2_idx),
                    target_shape=[int(v) for v in list(target_shape2)],
                    consumers=consumers,
                ):
                    continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mean1_op,
                input_index=0,
                new_input_name=pre_in_name,
            )
            _set_operator_inputs(
                model_ir=model_ir,
                op=squeeze1_op,
                new_inputs=[pre_in_name],
            )
            for input_idx, input_name in enumerate(list(sub_op.inputs)):
                if str(input_name) == x_name:
                    _replace_operator_input_at(
                        model_ir=model_ir,
                        op=sub_op,
                        input_index=int(input_idx),
                        new_input_name=pre_in_name,
                    )

            rank4_names = [
                x_name,
                mean1_out_name,
                centered_name,
                squared_name,
                mean2_out_name,
                add_eps_out_name,
                sqrt_out_name,
                div_out_name,
                normalized_name,
                scaled_name,
            ]
            if tail_mode != "direct_post_transpose_side_squeeze":
                rank4_names.append(str(inst_out_name))
            if tail_mode in {"squeeze_unary_reshape", "squeeze_add_reshape"} and str(reshape2_out_name) != str(inst_out_name):
                rank4_names.append(str(reshape2_out_name))
            for rank4_name in rank4_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(rank4_name, None),
                    perm_nchw_to_nhwc,
                )
                channel_last_hint_names.add(str(rank4_name))
            rank3_names = [str(squeeze1_out_name)]
            if squeeze2_out_name is not None:
                rank3_names.append(str(squeeze2_out_name))
            if unary_out_name is not None:
                rank3_names.append(str(unary_out_name))
            if tail_mode == "squeeze_add_reshape" and tail_add_out_name is not None:
                rank3_names.append(str(tail_add_out_name))
            for rank3_name in rank3_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(rank3_name, None),
                    perm_3d_chw_to_hwc,
                )
                channel_last_hint_names.add(str(rank3_name))

            channel_last_hint_names.add(str(post_out_name))
            model_ir.metadata["assume_channel_last_layout_tensor_names"] = sorted(
                channel_last_hint_names
            )

            if tail_mode in {"squeeze_unary_reshape", "squeeze_add_reshape"}:
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=reshape2_op,
                    new_outputs=[post_out_name],
                )
            else:
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=add_bias_op,
                    new_outputs=[post_out_name],
                )

            remove_indices_local: set[int] = {int(pre_idx), int(post_idx)} | set(int(v) for v in extra_remove_indices)
            for remove_idx in sorted(list(remove_indices_local), reverse=True):
                del model_ir.operators[int(remove_idx)]

            if (
                tail_mode == "squeeze_add_reshape"
                and tail_add_out_name is not None
                and len(tail_add_legacy_slots) > 0
                and tail_add_legacy_meta is not None
            ):
                if tail_hwc_to_chw_perm_name not in model_ir.tensors:
                    model_ir.tensors[tail_hwc_to_chw_perm_name] = TensorIR(
                        name=tail_hwc_to_chw_perm_name,
                        dtype="INT32",
                        shape=[3],
                        shape_signature=[3],
                        data=np.asarray([2, 0, 1], dtype=np.int32),
                        is_variable=False,
                        quantization=None,
                    )
                op_index_by_id = {int(id(op)): int(op_idx) for op_idx, op in enumerate(model_ir.operators)}
                slot_targets: List[Tuple[int, int]] = []
                for consumer_op_id, input_index in tail_add_legacy_slots:
                    consumer_index = op_index_by_id.get(int(consumer_op_id), None)
                    if consumer_index is None:
                        continue
                    if int(consumer_index) < 0 or int(consumer_index) >= len(model_ir.operators):
                        continue
                    consumer_op = model_ir.operators[int(consumer_index)]
                    if int(input_index) < 0 or int(input_index) >= len(consumer_op.inputs):
                        continue
                    if str(consumer_op.inputs[int(input_index)]) != str(tail_add_out_name):
                        continue
                    slot_targets.append((int(consumer_index), int(input_index)))
                if len(slot_targets) > 0:
                    adapter_name = _unique_tensor_name(f"{tail_add_out_name}_chw_adapter")
                    adapter_dtype, adapter_quant, adapter_shape, adapter_shape_signature = tail_add_legacy_meta
                    model_ir.tensors[adapter_name] = TensorIR(
                        name=adapter_name,
                        dtype=str(adapter_dtype),
                        shape=[int(v) for v in list(adapter_shape)],
                        shape_signature=[int(v) for v in list(adapter_shape_signature)],
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(adapter_quant),
                    )
                    adapter_op = OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(tail_add_out_name), tail_hwc_to_chw_perm_name],
                        outputs=[adapter_name],
                    )
                    for consumer_index, input_index in slot_targets:
                        consumer_op = model_ir.operators[int(consumer_index)]
                        new_inputs = [str(v) for v in list(consumer_op.inputs)]
                        new_inputs[int(input_index)] = str(adapter_name)
                        _set_operator_inputs(
                            model_ir=model_ir,
                            op=consumer_op,
                            new_inputs=new_inputs,
                        )
                    insert_index = min(int(v[0]) for v in slot_targets)
                    model_ir.operators.insert(int(insert_index), adapter_op)

            if tail_mode == "direct_post_transpose_side_squeeze" and side_squeeze_idx is not None:
                if tail_nhwc_to_nchw_perm_name not in model_ir.tensors:
                    model_ir.tensors[tail_nhwc_to_nchw_perm_name] = TensorIR(
                        name=tail_nhwc_to_nchw_perm_name,
                        dtype="INT32",
                        shape=[4],
                        shape_signature=[4],
                        data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                        is_variable=False,
                        quantization=None,
                    )
                adapter_insert_idx = int(side_squeeze_idx)
                for removed_idx in sorted(list(remove_indices_local)):
                    if removed_idx < int(side_squeeze_idx):
                        adapter_insert_idx -= 1
                adapter_insert_idx = int(max(0, min(adapter_insert_idx, len(model_ir.operators))))
                model_ir.operators.insert(
                    int(adapter_insert_idx),
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(post_out_name), tail_nhwc_to_nchw_perm_name],
                        outputs=[str(inst_out_name)],
                    ),
                )

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_instancenorm_prepost_nhwc_chains": int(rewritten)}


def _optimize_transpose_instancenorm_posttranspose_bias_add_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Eliminate strict NHWC<->NCHW transpose bridges around decomposed
    InstanceNormalization where channelwise bias ADD is already on NHWC side.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --(InstanceNormalization decomposition in NCHW, up to MUL(scale))--> s_nchw
      s_nchw --TRANSPOSE(0,2,3,1)--> s_nhwc
      ADD(s_nhwc, bias_nhwc) -> y_nhwc

    Rewrite:
      x_nhwc --(same decomposition rewritten to NHWC axes/broadcast)--> s_nhwc
      ADD(s_nhwc, bias_nhwc) -> y_nhwc
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    channel_last_hint_names = {
        str(v)
        for v in model_ir.metadata.get("assume_channel_last_layout_tensor_names", [])
        if str(v) != ""
    }

    def _single_consumer_index(consumers: Dict[str, List[int]], tensor_name: str) -> Optional[int]:
        users = [int(v) for v in consumers.get(str(tensor_name), [])]
        if len(users) != 1:
            return None
        return int(users[0])

    def _rewrite_axes_to_nhwc(
        *,
        axes_name: str,
        expected_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        axes_users = set(int(v) for v in consumers.get(str(axes_name), []))
        if axes_users != expected_users:
            return False
        axes_tensor = model_ir.tensors.get(str(axes_name), None)
        if axes_tensor is None or axes_tensor.data is None:
            return False
        axes_values = _read_const_ints_from_tensor(axes_tensor)
        if axes_values is None:
            return False
        normalized_axes: List[int] = []
        for axis in axes_values:
            axis_value = int(axis)
            if axis_value < 0:
                axis_value += 4
            if axis_value < 0 or axis_value >= 4:
                return False
            normalized_axes.append(int(axis_value))
        if sorted(list(set(normalized_axes))) != [2, 3]:
            return False
        _write_const_ints_to_tensor(axes_tensor, [1, 2])
        return True

    def _rewrite_coeff_to_nhwc(
        *,
        coeff_name: str,
        expected_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        coeff_users = set(int(v) for v in consumers.get(str(coeff_name), []))
        if coeff_users != expected_users:
            return False
        coeff_tensor = model_ir.tensors.get(str(coeff_name), None)
        if coeff_tensor is None or coeff_tensor.data is None:
            return False
        coeff = np.asarray(coeff_tensor.data)
        if int(coeff.size) == 1:
            return True
        if coeff.ndim != 4:
            return False
        shape = [int(v) for v in list(coeff.shape)]
        # Already NHWC broadcast [1,1,1,C].
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
        ):
            return True
        # NCHW broadcast [1,C,1,1] -> NHWC [1,1,1,C].
        if (
            int(shape[0]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            coeff_nhwc = np.transpose(coeff, perm_nchw_to_nhwc).astype(coeff.dtype, copy=False)
            coeff_tensor.data = np.asarray(coeff_nhwc)
            coeff_tensor.shape = [int(v) for v in list(coeff_nhwc.shape)]
            coeff_tensor.shape_signature = [int(v) for v in list(coeff_nhwc.shape)]
            return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            if pre_out_name in model_outputs:
                continue

            pre_users = set(int(v) for v in consumers.get(pre_out_name, []))
            if len(pre_users) != 2:
                continue

            mean1_idx: Optional[int] = None
            sub_idx: Optional[int] = None
            for user_idx in sorted(list(pre_users)):
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "MEAN"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == pre_out_name
                ):
                    mean1_idx = int(user_idx)
                elif (
                    str(user_op.op_type) == "SUB"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and pre_out_name in {str(user_op.inputs[0]), str(user_op.inputs[1])}
                ):
                    sub_idx = int(user_idx)
            if mean1_idx is None or sub_idx is None:
                continue

            mean1_op = model_ir.operators[int(mean1_idx)]
            sub_op = model_ir.operators[int(sub_idx)]
            mean1_out_name = str(mean1_op.outputs[0])
            if mean1_out_name in model_outputs:
                continue
            if mean1_out_name not in {str(sub_op.inputs[0]), str(sub_op.inputs[1])}:
                continue
            if set(int(v) for v in consumers.get(mean1_out_name, [])) != {int(sub_idx)}:
                continue

            centered_name = str(sub_op.outputs[0])
            centered_users = set(int(v) for v in consumers.get(centered_name, []))
            if len(centered_users) != 2:
                continue

            mul_square_idx: Optional[int] = None
            mul_norm_idx: Optional[int] = None
            for user_idx in sorted(list(centered_users)):
                user_op = model_ir.operators[int(user_idx)]
                if str(user_op.op_type) != "MUL" or len(user_op.inputs) != 2 or len(user_op.outputs) != 1:
                    continue
                in0 = str(user_op.inputs[0])
                in1 = str(user_op.inputs[1])
                if in0 == centered_name and in1 == centered_name:
                    mul_square_idx = int(user_idx)
                elif centered_name in {in0, in1}:
                    mul_norm_idx = int(user_idx)
            if mul_square_idx is None or mul_norm_idx is None:
                continue

            mul_square_op = model_ir.operators[int(mul_square_idx)]
            squared_name = str(mul_square_op.outputs[0])
            mean2_idx = _single_consumer_index(consumers, squared_name)
            if mean2_idx is None:
                continue
            mean2_op = model_ir.operators[int(mean2_idx)]
            if (
                str(mean2_op.op_type) != "MEAN"
                or len(mean2_op.inputs) != 2
                or len(mean2_op.outputs) != 1
                or str(mean2_op.inputs[0]) != squared_name
            ):
                continue
            mean2_out_name = str(mean2_op.outputs[0])

            add_eps_idx = _single_consumer_index(consumers, mean2_out_name)
            if add_eps_idx is None:
                continue
            add_eps_op = model_ir.operators[int(add_eps_idx)]
            if (
                str(add_eps_op.op_type) != "ADD"
                or len(add_eps_op.inputs) != 2
                or len(add_eps_op.outputs) != 1
                or mean2_out_name not in {str(add_eps_op.inputs[0]), str(add_eps_op.inputs[1])}
            ):
                continue
            add_eps_out_name = str(add_eps_op.outputs[0])

            sqrt_idx = _single_consumer_index(consumers, add_eps_out_name)
            if sqrt_idx is None:
                continue
            sqrt_op = model_ir.operators[int(sqrt_idx)]
            if (
                str(sqrt_op.op_type) != "SQRT"
                or len(sqrt_op.inputs) != 1
                or len(sqrt_op.outputs) != 1
                or str(sqrt_op.inputs[0]) != add_eps_out_name
            ):
                continue
            sqrt_out_name = str(sqrt_op.outputs[0])

            div_idx = _single_consumer_index(consumers, sqrt_out_name)
            if div_idx is None:
                continue
            div_op = model_ir.operators[int(div_idx)]
            if (
                str(div_op.op_type) != "DIV"
                or len(div_op.inputs) != 2
                or len(div_op.outputs) != 1
                or str(div_op.inputs[1]) != sqrt_out_name
            ):
                continue
            div_out_name = str(div_op.outputs[0])

            mul_norm_op = model_ir.operators[int(mul_norm_idx)]
            if div_out_name not in {str(mul_norm_op.inputs[0]), str(mul_norm_op.inputs[1])}:
                continue
            normalized_name = str(mul_norm_op.outputs[0])

            mul_scale_idx = _single_consumer_index(consumers, normalized_name)
            if mul_scale_idx is None:
                continue
            mul_scale_op = model_ir.operators[int(mul_scale_idx)]
            if (
                str(mul_scale_op.op_type) != "MUL"
                or len(mul_scale_op.inputs) != 2
                or len(mul_scale_op.outputs) != 1
                or normalized_name not in {str(mul_scale_op.inputs[0]), str(mul_scale_op.inputs[1])}
            ):
                continue
            scale_const_name = (
                str(mul_scale_op.inputs[0])
                if str(mul_scale_op.inputs[1]) == normalized_name
                else str(mul_scale_op.inputs[1])
            )
            scaled_name = str(mul_scale_op.outputs[0])

            post_idx = _single_consumer_index(consumers, scaled_name)
            if post_idx is None:
                continue
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or str(post_op.inputs[0]) != scaled_name
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_out_name = str(post_op.outputs[0])
            if post_out_name in model_outputs:
                continue

            add_bias_idx = _single_consumer_index(consumers, post_out_name)
            if add_bias_idx is None:
                continue
            add_bias_op = model_ir.operators[int(add_bias_idx)]
            if (
                str(add_bias_op.op_type) != "ADD"
                or len(add_bias_op.inputs) != 2
                or len(add_bias_op.outputs) != 1
                or post_out_name not in {str(add_bias_op.inputs[0]), str(add_bias_op.inputs[1])}
            ):
                continue
            bias_const_name = (
                str(add_bias_op.inputs[0])
                if str(add_bias_op.inputs[1]) == post_out_name
                else str(add_bias_op.inputs[1])
            )

            mean1_axes_name = str(mean1_op.inputs[1])
            mean2_axes_name = str(mean2_op.inputs[1])
            if mean1_axes_name == mean2_axes_name:
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean1_axes_name,
                    expected_users={int(mean1_idx), int(mean2_idx)},
                    consumers=consumers,
                ):
                    continue
            else:
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean1_axes_name,
                    expected_users={int(mean1_idx)},
                    consumers=consumers,
                ):
                    continue
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean2_axes_name,
                    expected_users={int(mean2_idx)},
                    consumers=consumers,
                ):
                    continue

            if not _rewrite_coeff_to_nhwc(
                coeff_name=scale_const_name,
                expected_users={int(mul_scale_idx)},
                consumers=consumers,
            ):
                continue
            if not _rewrite_coeff_to_nhwc(
                coeff_name=bias_const_name,
                expected_users={int(add_bias_idx)},
                consumers=consumers,
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mean1_op,
                input_index=0,
                new_input_name=pre_in_name,
            )
            sub_inputs = [str(v) for v in list(sub_op.inputs)]
            if sub_inputs[0] == pre_out_name:
                sub_inputs[0] = pre_in_name
            if sub_inputs[1] == pre_out_name:
                sub_inputs[1] = pre_in_name
            _set_operator_inputs(
                model_ir=model_ir,
                op=sub_op,
                new_inputs=sub_inputs,
            )
            add_bias_inputs = [str(v) for v in list(add_bias_op.inputs)]
            if add_bias_inputs[0] == post_out_name:
                add_bias_inputs[0] = scaled_name
            if add_bias_inputs[1] == post_out_name:
                add_bias_inputs[1] = scaled_name
            _set_operator_inputs(
                model_ir=model_ir,
                op=add_bias_op,
                new_inputs=add_bias_inputs,
            )

            rank4_names = [
                pre_out_name,
                mean1_out_name,
                centered_name,
                squared_name,
                mean2_out_name,
                add_eps_out_name,
                sqrt_out_name,
                div_out_name,
                normalized_name,
                scaled_name,
                post_out_name,
            ]
            for rank4_name in rank4_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(rank4_name), None),
                    perm_nchw_to_nhwc,
                )
                channel_last_hint_names.add(str(rank4_name))
            channel_last_hint_names.add(str(pre_in_name))
            model_ir.metadata["assume_channel_last_layout_tensor_names"] = sorted(
                channel_last_hint_names
            )

            for remove_idx in sorted([int(pre_idx), int(post_idx)], reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {
        "optimized_transpose_instancenorm_posttranspose_bias_add_nhwc_chains": int(rewritten)
    }


def _optimize_transpose_instancenorm_pad_prepost_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_instancenorm_pad_prepost_nhwc_chains_pass(model_ir)


def _optimize_transpose_flatten_globalnorm_pad_prepost_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_flatten_globalnorm_pad_prepost_nhwc_chains_pass(model_ir)


def _optimize_transpose_instancenorm_residual_add_to_single_post_adapter_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Collapse dual NHWC->NCHW bridges around decomposed InstanceNormalization + residual ADD.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --(InstanceNormalization decomposition in NCHW)--> y_nchw
      r_nhwc --TRANSPOSE(0,3,1,2)--> r_nchw
      ADD(y_nchw, r_nchw) -> a_nchw

    Rewrite:
      x_nhwc --(same decomposition rewritten to NHWC axes/broadcast)--> y_nhwc
      ADD(y_nhwc, r_nhwc) -> a_nhwc
      a_nhwc --TRANSPOSE(0,3,1,2)--> a_nchw

    Safety:
    - Both pre-transpose outputs are consumed only by the rewritten branch.
    - Strict decomposed InstanceNormalization topology.
    - Preserve downstream NCHW users through one post-ADD adapter.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    adapter_perm_name = "__instancenorm_residual_add_nhwc_to_nchw_perm_rank4__"

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _normalize_rank4_axes(axes: Optional[List[int]]) -> Optional[List[int]]:
        if axes is None or len(axes) == 0:
            return None
        normalized: List[int] = []
        for axis in axes:
            axis_value = int(axis)
            if axis_value < 0:
                axis_value += 4
            if axis_value < 0 or axis_value >= 4:
                return None
            normalized.append(int(axis_value))
        return sorted(list(set(normalized)))

    def _rewrite_axes_to_nhwc(
        *,
        axes_name: str,
        expected_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        axes_users = set(int(v) for v in consumers.get(str(axes_name), []))
        if axes_users != expected_users:
            return False
        axes_tensor = model_ir.tensors.get(str(axes_name), None)
        if axes_tensor is None:
            return False
        axes_values = _read_const_ints_from_tensor(axes_tensor)
        if _normalize_rank4_axes(axes_values) != [2, 3]:
            return False
        _write_const_ints_to_tensor(axes_tensor, [1, 2])
        return True

    def _rewrite_nchw_coeff_to_nhwc(
        *,
        coeff_name: str,
        expected_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        coeff_users = set(int(v) for v in consumers.get(str(coeff_name), []))
        if coeff_users != expected_users:
            return False
        coeff_tensor = model_ir.tensors.get(str(coeff_name), None)
        if coeff_tensor is None or coeff_tensor.data is None:
            return False
        coeff = np.asarray(coeff_tensor.data)
        if int(coeff.size) == 1:
            return True
        if coeff.ndim != 4:
            return False
        shape = [int(v) for v in list(coeff.shape)]
        if (
            len(shape) == 4
            and int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
        ):
            return True
        if (
            len(shape) == 4
            and int(shape[0]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            coeff_nhwc = np.transpose(coeff, perm_nchw_to_nhwc).astype(coeff.dtype, copy=False)
            coeff_tensor.data = np.asarray(coeff_nhwc)
            coeff_tensor.shape = [int(v) for v in list(coeff_nhwc.shape)]
            coeff_tensor.shape_signature = [int(v) for v in list(coeff_nhwc.shape)]
            return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            if pre_in_name in model_outputs or pre_out_name in model_outputs:
                continue

            pre_users = set(int(v) for v in consumers.get(pre_out_name, []))
            if len(pre_users) != 2:
                continue

            mean1_idx: Optional[int] = None
            sub_idx: Optional[int] = None
            for user_idx in sorted(list(pre_users)):
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "MEAN"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == pre_out_name
                ):
                    mean1_idx = int(user_idx)
                elif (
                    str(user_op.op_type) == "SUB"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and pre_out_name in {str(user_op.inputs[0]), str(user_op.inputs[1])}
                ):
                    sub_idx = int(user_idx)
            if mean1_idx is None or sub_idx is None:
                continue

            mean1_op = model_ir.operators[int(mean1_idx)]
            sub_op = model_ir.operators[int(sub_idx)]
            mean1_out_name = str(mean1_op.outputs[0])
            if mean1_out_name in model_outputs:
                continue
            if mean1_out_name not in {str(sub_op.inputs[0]), str(sub_op.inputs[1])}:
                continue
            if set(int(v) for v in consumers.get(mean1_out_name, [])) != {int(sub_idx)}:
                continue

            centered_name = str(sub_op.outputs[0])
            if centered_name in model_outputs:
                continue
            centered_users = set(int(v) for v in consumers.get(centered_name, []))
            if len(centered_users) != 2:
                continue

            mul_square_idx: Optional[int] = None
            mul_norm_idx: Optional[int] = None
            for user_idx in sorted(list(centered_users)):
                user_op = model_ir.operators[int(user_idx)]
                if str(user_op.op_type) != "MUL" or len(user_op.inputs) != 2 or len(user_op.outputs) != 1:
                    continue
                in0 = str(user_op.inputs[0])
                in1 = str(user_op.inputs[1])
                if in0 == centered_name and in1 == centered_name:
                    mul_square_idx = int(user_idx)
                elif centered_name in {in0, in1}:
                    mul_norm_idx = int(user_idx)
            if mul_square_idx is None or mul_norm_idx is None:
                continue

            mul_square_op = model_ir.operators[int(mul_square_idx)]
            squared_name = str(mul_square_op.outputs[0])
            mean2_users = set(int(v) for v in consumers.get(squared_name, []))
            if len(mean2_users) != 1:
                continue
            mean2_idx = int(list(mean2_users)[0])
            mean2_op = model_ir.operators[int(mean2_idx)]
            if (
                str(mean2_op.op_type) != "MEAN"
                or len(mean2_op.inputs) != 2
                or len(mean2_op.outputs) != 1
                or str(mean2_op.inputs[0]) != squared_name
            ):
                continue
            mean2_out_name = str(mean2_op.outputs[0])

            add_eps_users = set(int(v) for v in consumers.get(mean2_out_name, []))
            if len(add_eps_users) != 1:
                continue
            add_eps_idx = int(list(add_eps_users)[0])
            add_eps_op = model_ir.operators[int(add_eps_idx)]
            if (
                str(add_eps_op.op_type) != "ADD"
                or len(add_eps_op.inputs) != 2
                or len(add_eps_op.outputs) != 1
                or mean2_out_name not in {str(add_eps_op.inputs[0]), str(add_eps_op.inputs[1])}
            ):
                continue
            add_eps_out_name = str(add_eps_op.outputs[0])

            sqrt_users = set(int(v) for v in consumers.get(add_eps_out_name, []))
            if len(sqrt_users) != 1:
                continue
            sqrt_idx = int(list(sqrt_users)[0])
            sqrt_op = model_ir.operators[int(sqrt_idx)]
            if (
                str(sqrt_op.op_type) != "SQRT"
                or len(sqrt_op.inputs) != 1
                or len(sqrt_op.outputs) != 1
                or str(sqrt_op.inputs[0]) != add_eps_out_name
            ):
                continue
            sqrt_out_name = str(sqrt_op.outputs[0])

            div_users = set(int(v) for v in consumers.get(sqrt_out_name, []))
            if len(div_users) != 1:
                continue
            div_idx = int(list(div_users)[0])
            div_op = model_ir.operators[int(div_idx)]
            if (
                str(div_op.op_type) != "DIV"
                or len(div_op.inputs) != 2
                or len(div_op.outputs) != 1
                or str(div_op.inputs[1]) != sqrt_out_name
            ):
                continue
            div_out_name = str(div_op.outputs[0])

            mul_norm_op = model_ir.operators[int(mul_norm_idx)]
            if div_out_name not in {str(mul_norm_op.inputs[0]), str(mul_norm_op.inputs[1])}:
                continue
            normalized_name = str(mul_norm_op.outputs[0])

            mul_scale_users = set(int(v) for v in consumers.get(normalized_name, []))
            if len(mul_scale_users) != 1:
                continue
            mul_scale_idx = int(list(mul_scale_users)[0])
            mul_scale_op = model_ir.operators[int(mul_scale_idx)]
            if (
                str(mul_scale_op.op_type) != "MUL"
                or len(mul_scale_op.inputs) != 2
                or len(mul_scale_op.outputs) != 1
                or normalized_name not in {str(mul_scale_op.inputs[0]), str(mul_scale_op.inputs[1])}
            ):
                continue
            scale_const_name = (
                str(mul_scale_op.inputs[0])
                if str(mul_scale_op.inputs[1]) == normalized_name
                else str(mul_scale_op.inputs[1])
            )
            scaled_name = str(mul_scale_op.outputs[0])

            add_bias_users = set(int(v) for v in consumers.get(scaled_name, []))
            if len(add_bias_users) != 1:
                continue
            add_bias_idx = int(list(add_bias_users)[0])
            add_bias_op = model_ir.operators[int(add_bias_idx)]
            if (
                str(add_bias_op.op_type) != "ADD"
                or len(add_bias_op.inputs) != 2
                or len(add_bias_op.outputs) != 1
                or scaled_name not in {str(add_bias_op.inputs[0]), str(add_bias_op.inputs[1])}
            ):
                continue
            bias_const_name = (
                str(add_bias_op.inputs[0])
                if str(add_bias_op.inputs[1]) == scaled_name
                else str(add_bias_op.inputs[1])
            )
            inst_out_name = str(add_bias_op.outputs[0])
            if inst_out_name in model_outputs:
                continue

            inst_out_users = set(int(v) for v in consumers.get(inst_out_name, []))
            if len(inst_out_users) != 1:
                continue
            tail_add_idx = int(list(inst_out_users)[0])
            tail_add_op = model_ir.operators[int(tail_add_idx)]
            if (
                str(tail_add_op.op_type) != "ADD"
                or len(tail_add_op.inputs) != 2
                or len(tail_add_op.outputs) != 1
                or inst_out_name not in {str(tail_add_op.inputs[0]), str(tail_add_op.inputs[1])}
            ):
                continue
            add_out_name = str(tail_add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            residual_input_name = (
                str(tail_add_op.inputs[0])
                if str(tail_add_op.inputs[1]) == inst_out_name
                else str(tail_add_op.inputs[1])
            )
            residual_pre_idx = producers.get(residual_input_name, None)
            if residual_pre_idx is None:
                continue
            residual_pre_op = model_ir.operators[int(residual_pre_idx)]
            if (
                str(residual_pre_op.op_type) != "TRANSPOSE"
                or len(residual_pre_op.inputs) < 2
                or len(residual_pre_op.outputs) != 1
                or str(residual_pre_op.outputs[0]) != residual_input_name
                or _read_transpose_perm(model_ir, residual_pre_op) != perm_nhwc_to_nchw
            ):
                continue
            if set(int(v) for v in consumers.get(residual_input_name, [])) != {int(tail_add_idx)}:
                continue
            residual_src_name = str(residual_pre_op.inputs[0])
            if residual_src_name in model_outputs:
                continue

            add_out_users = [int(v) for v in consumers.get(add_out_name, [])]
            if len(add_out_users) == 0:
                continue

            mean1_axes_name = str(mean1_op.inputs[1])
            mean2_axes_name = str(mean2_op.inputs[1])
            if mean1_axes_name == mean2_axes_name:
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean1_axes_name,
                    expected_users={int(mean1_idx), int(mean2_idx)},
                    consumers=consumers,
                ):
                    continue
            else:
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean1_axes_name,
                    expected_users={int(mean1_idx)},
                    consumers=consumers,
                ):
                    continue
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean2_axes_name,
                    expected_users={int(mean2_idx)},
                    consumers=consumers,
                ):
                    continue

            if not _rewrite_nchw_coeff_to_nhwc(
                coeff_name=scale_const_name,
                expected_users={int(mul_scale_idx)},
                consumers=consumers,
            ):
                continue
            if not _rewrite_nchw_coeff_to_nhwc(
                coeff_name=bias_const_name,
                expected_users={int(add_bias_idx)},
                consumers=consumers,
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mean1_op,
                input_index=0,
                new_input_name=pre_in_name,
            )
            sub_inputs = [str(v) for v in list(sub_op.inputs)]
            if sub_inputs[0] == pre_out_name:
                sub_inputs[0] = pre_in_name
            if sub_inputs[1] == pre_out_name:
                sub_inputs[1] = pre_in_name
            _set_operator_inputs(
                model_ir=model_ir,
                op=sub_op,
                new_inputs=sub_inputs,
            )

            tail_add_inputs = [str(v) for v in list(tail_add_op.inputs)]
            for input_idx, input_name in enumerate(list(tail_add_inputs)):
                if str(input_name) == residual_input_name:
                    tail_add_inputs[int(input_idx)] = str(residual_src_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=tail_add_op,
                new_inputs=tail_add_inputs,
            )

            add_out_nhwc_name = _unique_tensor_name(f"{add_out_name}_nhwc")
            old_add_out_tensor = model_ir.tensors.get(str(add_out_name), None)
            add_out_nhwc_shape: Optional[List[int]] = None
            add_out_nhwc_signature: Optional[List[int]] = None
            add_out_dtype = "FLOAT32"
            add_out_quant = None
            if old_add_out_tensor is not None:
                add_out_dtype = str(old_add_out_tensor.dtype)
                add_out_quant = _clone_quantization(old_add_out_tensor.quantization)
                shape_src = [int(v) for v in list(old_add_out_tensor.shape)]
                signature_src = (
                    [int(v) for v in list(old_add_out_tensor.shape_signature)]
                    if old_add_out_tensor.shape_signature is not None
                    else [int(v) for v in list(old_add_out_tensor.shape)]
                )
                add_out_nhwc_shape = _permute_shape(shape_src, perm_nchw_to_nhwc)
                add_out_nhwc_signature = _permute_shape(signature_src, perm_nchw_to_nhwc)

            if add_out_nhwc_shape is None or add_out_nhwc_signature is None:
                continue

            model_ir.tensors[add_out_nhwc_name] = TensorIR(
                name=add_out_nhwc_name,
                dtype=add_out_dtype,
                shape=[int(v) for v in list(add_out_nhwc_shape)],
                shape_signature=[int(v) for v in list(add_out_nhwc_signature)],
                data=None,
                is_variable=False,
                quantization=_clone_quantization(add_out_quant),
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=tail_add_op,
                new_outputs=[add_out_nhwc_name],
            )

            rank4_names = [
                pre_out_name,
                mean1_out_name,
                centered_name,
                squared_name,
                mean2_out_name,
                add_eps_out_name,
                sqrt_out_name,
                div_out_name,
                normalized_name,
                scaled_name,
                inst_out_name,
            ]
            for tensor_name in rank4_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(tensor_name), None),
                    perm_nchw_to_nhwc,
                )

            if adapter_perm_name not in model_ir.tensors:
                model_ir.tensors[adapter_perm_name] = TensorIR(
                    name=adapter_perm_name,
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
            insert_index = min(int(v) for v in list(add_out_users))
            model_ir.operators.insert(
                int(insert_index),
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(add_out_nhwc_name), str(adapter_perm_name)],
                    outputs=[str(add_out_name)],
                ),
            )

            remove_indices = {int(pre_idx), int(residual_pre_idx)}
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_instancenorm_residual_add_to_single_post_adapter_nhwc_chains": int(rewritten)}


def _optimize_transpose_instancenorm_residual_mul_concat_conv_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around decomposed InstanceNorm residual tails.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --(InstanceNorm decomposition in NCHW)--> y_nchw
      y_nchw --TRANSPOSE(0,2,3,1)--> y_nhwc
      ADD(y_nhwc, r_nhwc) -> a_nhwc
      MUL(a_nhwc, c0_nchw[1,C,1,1]) -> m0_nchw
      MUL(a_nhwc, c1_nchw[1,C,1,1]) -> m1_nchw
      CONCAT(axis=1, [m0_nchw, m1_nchw]) -> cat_nchw
      cat_nchw --TRANSPOSE(0,2,3,1)--> cat_nhwc
      CONV_2D(cat_nhwc, ...)

    Rewrite:
      - Rewrite InstanceNorm decomposition to NHWC.
      - Rewrite channelwise constants to NHWC broadcasting.
      - CONCAT axis becomes 3 and directly produces `cat_nhwc`.
      - Remove three transposes (pre/post/tail post).
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _normalize_rank4_axes(axes: Optional[List[int]]) -> Optional[List[int]]:
        if axes is None or len(axes) == 0:
            return None
        normalized: List[int] = []
        for axis in axes:
            axis_value = int(axis)
            if axis_value < 0:
                axis_value += 4
            if axis_value < 0 or axis_value >= 4:
                return None
            normalized.append(int(axis_value))
        return sorted(list(set(normalized)))

    def _rewrite_axes_to_nhwc(
        *,
        axes_name: str,
        expected_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        axes_users = set(int(v) for v in consumers.get(str(axes_name), []))
        if axes_users != expected_users:
            return False
        axes_tensor = model_ir.tensors.get(str(axes_name), None)
        if axes_tensor is None:
            return False
        axes_values = _read_const_ints_from_tensor(axes_tensor)
        if _normalize_rank4_axes(axes_values) != [2, 3]:
            return False
        _write_const_ints_to_tensor(axes_tensor, [1, 2])
        return True

    def _rewrite_nchw_coeff_to_nhwc(
        *,
        coeff_name: str,
        expected_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        coeff_users = set(int(v) for v in consumers.get(str(coeff_name), []))
        if coeff_users != expected_users:
            return False
        coeff_tensor = model_ir.tensors.get(str(coeff_name), None)
        if coeff_tensor is None or coeff_tensor.data is None:
            return False
        coeff = np.asarray(coeff_tensor.data)
        if int(coeff.size) == 1:
            return True
        if coeff.ndim != 4:
            return False
        shape = [int(v) for v in list(coeff.shape)]
        # Already NHWC channelwise.
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
        ):
            return True
        # NCHW channelwise -> NHWC channelwise.
        if (
            int(shape[0]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            coeff_nhwc = np.transpose(coeff, perm_nchw_to_nhwc).astype(coeff.dtype, copy=False)
            coeff_tensor.data = np.asarray(coeff_nhwc)
            coeff_tensor.shape = [int(v) for v in list(coeff_nhwc.shape)]
            coeff_tensor.shape_signature = [int(v) for v in list(coeff_nhwc.shape)]
            return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            if pre_in_name in model_outputs or pre_out_name in model_outputs:
                continue

            pre_users = set(int(v) for v in consumers.get(pre_out_name, []))
            if len(pre_users) != 2:
                continue

            mean1_idx: Optional[int] = None
            sub_idx: Optional[int] = None
            for user_idx in sorted(list(pre_users)):
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "MEAN"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == pre_out_name
                ):
                    mean1_idx = int(user_idx)
                elif (
                    str(user_op.op_type) == "SUB"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and pre_out_name in {str(user_op.inputs[0]), str(user_op.inputs[1])}
                ):
                    sub_idx = int(user_idx)
            if mean1_idx is None or sub_idx is None:
                continue

            mean1_op = model_ir.operators[int(mean1_idx)]
            sub_op = model_ir.operators[int(sub_idx)]
            mean1_out_name = str(mean1_op.outputs[0])
            if mean1_out_name in model_outputs:
                continue
            if mean1_out_name not in {str(sub_op.inputs[0]), str(sub_op.inputs[1])}:
                continue
            if set(int(v) for v in consumers.get(mean1_out_name, [])) != {int(sub_idx)}:
                continue

            centered_name = str(sub_op.outputs[0])
            if centered_name in model_outputs:
                continue
            centered_users = set(int(v) for v in consumers.get(centered_name, []))
            if len(centered_users) != 2:
                continue

            mul_square_idx: Optional[int] = None
            mul_norm_idx: Optional[int] = None
            for user_idx in sorted(list(centered_users)):
                user_op = model_ir.operators[int(user_idx)]
                if str(user_op.op_type) != "MUL" or len(user_op.inputs) != 2 or len(user_op.outputs) != 1:
                    continue
                in0 = str(user_op.inputs[0])
                in1 = str(user_op.inputs[1])
                if in0 == centered_name and in1 == centered_name:
                    mul_square_idx = int(user_idx)
                elif centered_name in {in0, in1}:
                    mul_norm_idx = int(user_idx)
            if mul_square_idx is None or mul_norm_idx is None:
                continue

            mul_square_op = model_ir.operators[int(mul_square_idx)]
            squared_name = str(mul_square_op.outputs[0])
            mean2_users = set(int(v) for v in consumers.get(squared_name, []))
            if len(mean2_users) != 1:
                continue
            mean2_idx = int(list(mean2_users)[0])
            mean2_op = model_ir.operators[int(mean2_idx)]
            if (
                str(mean2_op.op_type) != "MEAN"
                or len(mean2_op.inputs) != 2
                or len(mean2_op.outputs) != 1
                or str(mean2_op.inputs[0]) != squared_name
            ):
                continue
            mean2_out_name = str(mean2_op.outputs[0])

            add_eps_users = set(int(v) for v in consumers.get(mean2_out_name, []))
            if len(add_eps_users) != 1:
                continue
            add_eps_idx = int(list(add_eps_users)[0])
            add_eps_op = model_ir.operators[int(add_eps_idx)]
            if (
                str(add_eps_op.op_type) != "ADD"
                or len(add_eps_op.inputs) != 2
                or len(add_eps_op.outputs) != 1
                or mean2_out_name not in {str(add_eps_op.inputs[0]), str(add_eps_op.inputs[1])}
            ):
                continue
            add_eps_out_name = str(add_eps_op.outputs[0])

            sqrt_users = set(int(v) for v in consumers.get(add_eps_out_name, []))
            if len(sqrt_users) != 1:
                continue
            sqrt_idx = int(list(sqrt_users)[0])
            sqrt_op = model_ir.operators[int(sqrt_idx)]
            if (
                str(sqrt_op.op_type) != "SQRT"
                or len(sqrt_op.inputs) != 1
                or len(sqrt_op.outputs) != 1
                or str(sqrt_op.inputs[0]) != add_eps_out_name
            ):
                continue
            sqrt_out_name = str(sqrt_op.outputs[0])

            div_users = set(int(v) for v in consumers.get(sqrt_out_name, []))
            if len(div_users) != 1:
                continue
            div_idx = int(list(div_users)[0])
            div_op = model_ir.operators[int(div_idx)]
            if (
                str(div_op.op_type) != "DIV"
                or len(div_op.inputs) != 2
                or len(div_op.outputs) != 1
                or str(div_op.inputs[1]) != sqrt_out_name
            ):
                continue
            div_out_name = str(div_op.outputs[0])

            mul_norm_op = model_ir.operators[int(mul_norm_idx)]
            if div_out_name not in {str(mul_norm_op.inputs[0]), str(mul_norm_op.inputs[1])}:
                continue
            normalized_name = str(mul_norm_op.outputs[0])

            mul_scale_users = set(int(v) for v in consumers.get(normalized_name, []))
            if len(mul_scale_users) != 1:
                continue
            mul_scale_idx = int(list(mul_scale_users)[0])
            mul_scale_op = model_ir.operators[int(mul_scale_idx)]
            if (
                str(mul_scale_op.op_type) != "MUL"
                or len(mul_scale_op.inputs) != 2
                or len(mul_scale_op.outputs) != 1
                or normalized_name not in {str(mul_scale_op.inputs[0]), str(mul_scale_op.inputs[1])}
            ):
                continue
            scale_const_name = (
                str(mul_scale_op.inputs[0])
                if str(mul_scale_op.inputs[1]) == normalized_name
                else str(mul_scale_op.inputs[1])
            )
            scaled_name = str(mul_scale_op.outputs[0])

            add_bias_users = set(int(v) for v in consumers.get(scaled_name, []))
            if len(add_bias_users) != 1:
                continue
            add_bias_idx = int(list(add_bias_users)[0])
            add_bias_op = model_ir.operators[int(add_bias_idx)]
            if (
                str(add_bias_op.op_type) != "ADD"
                or len(add_bias_op.inputs) != 2
                or len(add_bias_op.outputs) != 1
                or scaled_name not in {str(add_bias_op.inputs[0]), str(add_bias_op.inputs[1])}
            ):
                continue
            bias_const_name = (
                str(add_bias_op.inputs[0])
                if str(add_bias_op.inputs[1]) == scaled_name
                else str(add_bias_op.inputs[1])
            )
            inst_out_name = str(add_bias_op.outputs[0])
            if inst_out_name in model_outputs:
                continue

            inst_out_users = set(int(v) for v in consumers.get(inst_out_name, []))
            if len(inst_out_users) != 1:
                continue
            post_idx = int(list(inst_out_users)[0])
            post_op = model_ir.operators[int(post_idx)]
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                or str(post_op.inputs[0]) != inst_out_name
            ):
                continue
            post_out_name = str(post_op.outputs[0])
            if post_out_name in model_outputs:
                continue

            post_users = set(int(v) for v in consumers.get(post_out_name, []))
            if len(post_users) != 1:
                continue
            tail_add_idx = int(list(post_users)[0])
            tail_add_op = model_ir.operators[int(tail_add_idx)]
            if (
                str(tail_add_op.op_type) != "ADD"
                or len(tail_add_op.inputs) != 2
                or len(tail_add_op.outputs) != 1
                or post_out_name not in {str(tail_add_op.inputs[0]), str(tail_add_op.inputs[1])}
            ):
                continue
            add_out_name = str(tail_add_op.outputs[0])
            if add_out_name in model_outputs:
                continue

            add_out_users = [int(v) for v in consumers.get(add_out_name, [])]
            if len(add_out_users) != 2:
                continue

            tail_mul_indices: List[int] = []
            tail_mul_out_names: List[str] = []
            tail_mul_const_names: List[str] = []
            concat_idx: Optional[int] = None
            valid_tail = True
            for user_idx in sorted(add_out_users):
                user_op = model_ir.operators[int(user_idx)]
                if str(user_op.op_type) != "MUL" or len(user_op.inputs) != 2 or len(user_op.outputs) != 1:
                    valid_tail = False
                    break
                if add_out_name not in {str(user_op.inputs[0]), str(user_op.inputs[1])}:
                    valid_tail = False
                    break
                const_name = (
                    str(user_op.inputs[0])
                    if str(user_op.inputs[1]) == add_out_name
                    else str(user_op.inputs[1])
                )
                mul_out_name = str(user_op.outputs[0])
                if mul_out_name in model_outputs:
                    valid_tail = False
                    break
                mul_out_users = set(int(v) for v in consumers.get(mul_out_name, []))
                if len(mul_out_users) != 1:
                    valid_tail = False
                    break
                current_concat_idx = int(list(mul_out_users)[0])
                current_concat_op = model_ir.operators[int(current_concat_idx)]
                if str(current_concat_op.op_type) != "CONCATENATION" or len(current_concat_op.outputs) != 1:
                    valid_tail = False
                    break
                if concat_idx is None:
                    concat_idx = int(current_concat_idx)
                elif int(concat_idx) != int(current_concat_idx):
                    valid_tail = False
                    break
                tail_mul_indices.append(int(user_idx))
                tail_mul_out_names.append(str(mul_out_name))
                tail_mul_const_names.append(str(const_name))
            if not valid_tail or concat_idx is None:
                continue

            concat_op = model_ir.operators[int(concat_idx)]
            concat_axis = int(concat_op.options.get("axis", 1)) if isinstance(concat_op.options, dict) else 1
            if concat_axis < 0:
                concat_axis += 4
            if concat_axis != 1:
                continue
            concat_inputs = [str(v) for v in list(concat_op.inputs)]
            if set(concat_inputs) != set(tail_mul_out_names):
                continue
            concat_out_name = str(concat_op.outputs[0])
            if concat_out_name in model_outputs:
                continue

            concat_users = set(int(v) for v in consumers.get(concat_out_name, []))
            if len(concat_users) != 1:
                continue
            tail_post_idx = int(list(concat_users)[0])
            tail_post_op = model_ir.operators[int(tail_post_idx)]
            if (
                str(tail_post_op.op_type) != "TRANSPOSE"
                or len(tail_post_op.inputs) < 2
                or len(tail_post_op.outputs) != 1
                or _read_transpose_perm(model_ir, tail_post_op) != perm_nchw_to_nhwc
                or str(tail_post_op.inputs[0]) != concat_out_name
            ):
                continue
            tail_post_out_name = str(tail_post_op.outputs[0])

            mean1_axes_name = str(mean1_op.inputs[1])
            mean2_axes_name = str(mean2_op.inputs[1])
            if mean1_axes_name == mean2_axes_name:
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean1_axes_name,
                    expected_users={int(mean1_idx), int(mean2_idx)},
                    consumers=consumers,
                ):
                    continue
            else:
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean1_axes_name,
                    expected_users={int(mean1_idx)},
                    consumers=consumers,
                ):
                    continue
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean2_axes_name,
                    expected_users={int(mean2_idx)},
                    consumers=consumers,
                ):
                    continue

            if not _rewrite_nchw_coeff_to_nhwc(
                coeff_name=scale_const_name,
                expected_users={int(mul_scale_idx)},
                consumers=consumers,
            ):
                continue
            if not _rewrite_nchw_coeff_to_nhwc(
                coeff_name=bias_const_name,
                expected_users={int(add_bias_idx)},
                consumers=consumers,
            ):
                continue
            if not _rewrite_nchw_coeff_to_nhwc(
                coeff_name=tail_mul_const_names[0],
                expected_users={int(tail_mul_indices[0])},
                consumers=consumers,
            ):
                continue
            if not _rewrite_nchw_coeff_to_nhwc(
                coeff_name=tail_mul_const_names[1],
                expected_users={int(tail_mul_indices[1])},
                consumers=consumers,
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mean1_op,
                input_index=0,
                new_input_name=pre_in_name,
            )
            sub_inputs = [str(v) for v in list(sub_op.inputs)]
            if sub_inputs[0] == pre_out_name:
                sub_inputs[0] = pre_in_name
            if sub_inputs[1] == pre_out_name:
                sub_inputs[1] = pre_in_name
            _set_operator_inputs(
                model_ir=model_ir,
                op=sub_op,
                new_inputs=sub_inputs,
            )

            tail_add_inputs = [str(v) for v in list(tail_add_op.inputs)]
            for input_idx, input_name in enumerate(list(tail_add_inputs)):
                if str(input_name) == post_out_name:
                    tail_add_inputs[int(input_idx)] = str(inst_out_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=tail_add_op,
                new_inputs=tail_add_inputs,
            )

            rank4_names = [
                pre_out_name,
                mean1_out_name,
                centered_name,
                squared_name,
                mean2_out_name,
                add_eps_out_name,
                sqrt_out_name,
                div_out_name,
                normalized_name,
                scaled_name,
                inst_out_name,
                tail_mul_out_names[0],
                tail_mul_out_names[1],
                concat_out_name,
            ]
            for tensor_name in rank4_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(tensor_name), None),
                    perm_nchw_to_nhwc,
                )

            concat_opts = dict(concat_op.options) if isinstance(concat_op.options, dict) else {}
            concat_opts["axis"] = 3
            concat_op.options = concat_opts
            _set_operator_outputs(
                model_ir=model_ir,
                op=concat_op,
                new_outputs=[str(tail_post_out_name)],
            )

            for remove_idx in sorted(
                [int(pre_idx), int(post_idx), int(tail_post_idx)],
                reverse=True,
            ):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_instancenorm_residual_mul_concat_conv_nhwc_chains": int(rewritten)}


def _optimize_transpose_instancenorm_dualstats_residual_add_resize_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around dual-stat InstanceNorm-like residual blocks.

    Target (strict topology):
      x_nhwc --T(0,3,1,2)--> x_nchw
      x_nchw --(dual mean/sub/square/mean/sqrt/div branches)--> b0_nchw, b1_nchw
      ADD(b0_nchw, b1_nchw) -> m_nchw
      MUL(m_nchw, gamma_11c11_or_reshape) -> g_nchw
      ADD(g_nchw, beta_11c11_or_reshape) -> y_nchw
      r_nhwc --T(0,3,1,2)--> r_nchw
      ADD(y_nchw, r_nchw) -> a_nchw
      a_nchw --T(0,2,3,1)--> a_nhwc

    Rewrite:
      - Rewrite dual-stat branch tensors to NHWC (axes [2,3] -> [1,2]).
      - Rewrite channelwise coefficients to NHWC broadcast.
      - Bypass channelwise reshapes for gamma/beta when possible.
      - Remove the three transpose bridges.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _normalize_rank4_axes(axes: Optional[List[int]]) -> Optional[List[int]]:
        if axes is None or len(axes) == 0:
            return None
        normalized: List[int] = []
        for axis in axes:
            axis_value = int(axis)
            if axis_value < 0:
                axis_value += 4
            if axis_value < 0 or axis_value >= 4:
                return None
            normalized.append(int(axis_value))
        return sorted(list(set(normalized)))

    def _rewrite_axes_to_nhwc(
        *,
        axes_name: str,
        expected_users: set[int],
        target_axes: List[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        axes_users = set(int(v) for v in consumers.get(str(axes_name), []))
        if axes_users != expected_users:
            return False
        axes_tensor = model_ir.tensors.get(str(axes_name), None)
        if axes_tensor is None:
            return False
        _write_const_ints_to_tensor(axes_tensor, [int(v) for v in list(target_axes)])
        return True

    def _axes_match(
        *,
        axes_name: str,
        expected_axes: List[int],
    ) -> bool:
        axes_tensor = model_ir.tensors.get(str(axes_name), None)
        if axes_tensor is None:
            return False
        axes_values = _read_const_ints_from_tensor(axes_tensor)
        return _normalize_rank4_axes(axes_values) == sorted([int(v) for v in list(expected_axes)])

    def _rewrite_nchw_coeff_to_nhwc(
        *,
        coeff_name: str,
        expected_users: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        coeff_users = set(int(v) for v in consumers.get(str(coeff_name), []))
        if coeff_users != expected_users:
            return False
        coeff_tensor = model_ir.tensors.get(str(coeff_name), None)
        if coeff_tensor is None or coeff_tensor.data is None:
            return False
        coeff = np.asarray(coeff_tensor.data)
        if int(coeff.size) == 1:
            return True
        if coeff.ndim != 4:
            return False
        shape = [int(v) for v in list(coeff.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
        ):
            return True
        if (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            coeff_nhwc = np.transpose(coeff, perm_nchw_to_nhwc).astype(coeff.dtype, copy=False)
            coeff_tensor.data = np.asarray(coeff_nhwc)
            coeff_tensor.shape = [int(v) for v in list(coeff_nhwc.shape)]
            coeff_tensor.shape_signature = [int(v) for v in list(coeff_nhwc.shape)]
            return True
        return False

    def _bypass_channelwise_reshape_to_vector(
        *,
        coeff_name: str,
        expected_user: int,
        consumers: Dict[str, List[int]],
        producers: Dict[str, int],
    ) -> Optional[str]:
        coeff_users = set(int(v) for v in consumers.get(str(coeff_name), []))
        if coeff_users != {int(expected_user)}:
            return None
        coeff_prod_idx = producers.get(str(coeff_name), None)
        if coeff_prod_idx is None:
            return None
        coeff_prod_op = model_ir.operators[int(coeff_prod_idx)]
        if (
            str(coeff_prod_op.op_type) != "RESHAPE"
            or len(coeff_prod_op.inputs) != 2
            or len(coeff_prod_op.outputs) != 1
            or str(coeff_prod_op.outputs[0]) != str(coeff_name)
        ):
            return None
        source_name = str(coeff_prod_op.inputs[0])
        coeff_tensor = model_ir.tensors.get(str(coeff_name), None)
        source_tensor = model_ir.tensors.get(str(source_name), None)
        if coeff_tensor is None or source_tensor is None:
            return None
        coeff_shape = [int(v) for v in list(coeff_tensor.shape)]
        source_shape = [int(v) for v in list(source_tensor.shape)]
        if len(coeff_shape) != 4:
            return None
        if not (
            int(coeff_shape[0]) == 1
            and int(coeff_shape[1]) > 0
            and int(coeff_shape[2]) == 1
            and int(coeff_shape[3]) == 1
        ):
            return None
        if len(source_shape) == 2 and int(source_shape[0]) == 1 and int(source_shape[1]) == int(coeff_shape[1]):
            return str(source_name)
        if len(source_shape) == 1 and int(source_shape[0]) == int(coeff_shape[1]):
            return str(source_name)
        return None

    def _match_dual_norm_path(
        *,
        sub_idx: int,
        expected_axes: List[int],
        consumers: Dict[str, List[int]],
        model_outputs: set[str],
    ) -> Optional[Dict[str, Any]]:
        sub_op = model_ir.operators[int(sub_idx)]
        sub_out_name = str(sub_op.outputs[0])
        if sub_out_name in model_outputs:
            return None
        sub_users = set(int(v) for v in consumers.get(sub_out_name, []))
        if len(sub_users) != 2:
            return None

        square_idx: Optional[int] = None
        div_idx: Optional[int] = None
        for user_idx in sorted(list(sub_users)):
            user_op = model_ir.operators[int(user_idx)]
            if (
                str(user_op.op_type) == "MUL"
                and len(user_op.inputs) == 2
                and len(user_op.outputs) == 1
                and str(user_op.inputs[0]) == sub_out_name
                and str(user_op.inputs[1]) == sub_out_name
            ):
                square_idx = int(user_idx)
            elif (
                str(user_op.op_type) == "DIV"
                and len(user_op.inputs) == 2
                and len(user_op.outputs) == 1
                and str(user_op.inputs[0]) == sub_out_name
            ):
                div_idx = int(user_idx)
        if square_idx is None or div_idx is None:
            return None

        square_op = model_ir.operators[int(square_idx)]
        square_out_name = str(square_op.outputs[0])
        square_users = set(int(v) for v in consumers.get(square_out_name, []))
        if len(square_users) != 1:
            return None
        mean2_idx = int(list(square_users)[0])
        mean2_op = model_ir.operators[int(mean2_idx)]
        if (
            str(mean2_op.op_type) != "MEAN"
            or len(mean2_op.inputs) != 2
            or len(mean2_op.outputs) != 1
            or str(mean2_op.inputs[0]) != square_out_name
        ):
            return None
        mean2_axes_name = str(mean2_op.inputs[1])
        if not _axes_match(axes_name=mean2_axes_name, expected_axes=expected_axes):
            return None
        mean2_out_name = str(mean2_op.outputs[0])

        mul_factor_users = set(int(v) for v in consumers.get(mean2_out_name, []))
        if len(mul_factor_users) != 1:
            return None
        mul_factor_idx = int(list(mul_factor_users)[0])
        mul_factor_op = model_ir.operators[int(mul_factor_idx)]
        if (
            str(mul_factor_op.op_type) != "MUL"
            or len(mul_factor_op.inputs) != 2
            or len(mul_factor_op.outputs) != 1
            or mean2_out_name not in {str(mul_factor_op.inputs[0]), str(mul_factor_op.inputs[1])}
        ):
            return None
        mul_factor_out_name = str(mul_factor_op.outputs[0])

        add_eps_users = set(int(v) for v in consumers.get(mul_factor_out_name, []))
        if len(add_eps_users) != 1:
            return None
        add_eps_idx = int(list(add_eps_users)[0])
        add_eps_op = model_ir.operators[int(add_eps_idx)]
        if (
            str(add_eps_op.op_type) != "ADD"
            or len(add_eps_op.inputs) != 2
            or len(add_eps_op.outputs) != 1
            or mul_factor_out_name not in {str(add_eps_op.inputs[0]), str(add_eps_op.inputs[1])}
        ):
            return None
        add_eps_out_name = str(add_eps_op.outputs[0])

        sqrt_users = set(int(v) for v in consumers.get(add_eps_out_name, []))
        if len(sqrt_users) != 1:
            return None
        sqrt_idx = int(list(sqrt_users)[0])
        sqrt_op = model_ir.operators[int(sqrt_idx)]
        if (
            str(sqrt_op.op_type) != "SQRT"
            or len(sqrt_op.inputs) != 1
            or len(sqrt_op.outputs) != 1
            or str(sqrt_op.inputs[0]) != add_eps_out_name
        ):
            return None
        sqrt_out_name = str(sqrt_op.outputs[0])

        div_op = model_ir.operators[int(div_idx)]
        if str(div_op.inputs[1]) != sqrt_out_name:
            return None
        div_out_name = str(div_op.outputs[0])
        div_out_users = set(int(v) for v in consumers.get(div_out_name, []))
        if len(div_out_users) != 1:
            return None
        scale_idx = int(list(div_out_users)[0])
        scale_op = model_ir.operators[int(scale_idx)]
        if (
            str(scale_op.op_type) != "MUL"
            or len(scale_op.inputs) != 2
            or len(scale_op.outputs) != 1
            or div_out_name not in {str(scale_op.inputs[0]), str(scale_op.inputs[1])}
        ):
            return None
        scale_const_name = (
            str(scale_op.inputs[0])
            if str(scale_op.inputs[1]) == div_out_name
            else str(scale_op.inputs[1])
        )
        scaled_out_name = str(scale_op.outputs[0])
        if scaled_out_name in model_outputs:
            return None

        return {
            "sub_idx": int(sub_idx),
            "sub_out_name": str(sub_out_name),
            "square_idx": int(square_idx),
            "square_out_name": str(square_out_name),
            "mean2_idx": int(mean2_idx),
            "mean2_axes_name": str(mean2_axes_name),
            "mean2_out_name": str(mean2_out_name),
            "mul_factor_idx": int(mul_factor_idx),
            "mul_factor_out_name": str(mul_factor_out_name),
            "add_eps_idx": int(add_eps_idx),
            "add_eps_out_name": str(add_eps_out_name),
            "sqrt_idx": int(sqrt_idx),
            "sqrt_out_name": str(sqrt_out_name),
            "div_idx": int(div_idx),
            "div_out_name": str(div_out_name),
            "scale_idx": int(scale_idx),
            "scale_const_name": str(scale_const_name),
            "scaled_out_name": str(scaled_out_name),
        }

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue
            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            if pre_in_name in model_outputs or pre_out_name in model_outputs:
                continue

            pre_users = sorted(set(int(v) for v in consumers.get(pre_out_name, [])))
            if len(pre_users) != 4:
                continue

            mean_spatial_idx: Optional[int] = None
            mean_global_idx: Optional[int] = None
            mean_spatial_axes_name: Optional[str] = None
            mean_global_axes_name: Optional[str] = None
            sub_candidates: List[int] = []
            for user_idx in pre_users:
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "MEAN"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == pre_out_name
                ):
                    axes_name = str(user_op.inputs[1])
                    if _axes_match(axes_name=axes_name, expected_axes=[2, 3]):
                        mean_spatial_idx = int(user_idx)
                        mean_spatial_axes_name = str(axes_name)
                    elif _axes_match(axes_name=axes_name, expected_axes=[1, 2, 3]):
                        mean_global_idx = int(user_idx)
                        mean_global_axes_name = str(axes_name)
                elif (
                    str(user_op.op_type) == "SUB"
                    and len(user_op.inputs) == 2
                    and len(user_op.outputs) == 1
                    and pre_out_name in {str(user_op.inputs[0]), str(user_op.inputs[1])}
                ):
                    sub_candidates.append(int(user_idx))
            if (
                mean_spatial_idx is None
                or mean_global_idx is None
                or len(sub_candidates) != 2
                or mean_spatial_axes_name is None
                or mean_global_axes_name is None
            ):
                continue

            mean_spatial_out_name = str(model_ir.operators[int(mean_spatial_idx)].outputs[0])
            mean_global_out_name = str(model_ir.operators[int(mean_global_idx)].outputs[0])
            if (
                mean_spatial_out_name in model_outputs
                or mean_global_out_name in model_outputs
                or set(int(v) for v in consumers.get(mean_spatial_out_name, [])) == set()
                or set(int(v) for v in consumers.get(mean_global_out_name, [])) == set()
            ):
                continue

            sub_spatial_idx: Optional[int] = None
            sub_global_idx: Optional[int] = None
            for sub_idx in sub_candidates:
                sub_op = model_ir.operators[int(sub_idx)]
                sub_inputs = set(str(v) for v in list(sub_op.inputs))
                if mean_spatial_out_name in sub_inputs:
                    sub_spatial_idx = int(sub_idx)
                elif mean_global_out_name in sub_inputs:
                    sub_global_idx = int(sub_idx)
            if sub_spatial_idx is None or sub_global_idx is None:
                continue
            if set(int(v) for v in consumers.get(mean_spatial_out_name, [])) != {int(sub_spatial_idx)}:
                continue
            if set(int(v) for v in consumers.get(mean_global_out_name, [])) != {int(sub_global_idx)}:
                continue

            path_spatial = _match_dual_norm_path(
                sub_idx=int(sub_spatial_idx),
                expected_axes=[2, 3],
                consumers=consumers,
                model_outputs=model_outputs,
            )
            if path_spatial is None:
                continue
            path_global = _match_dual_norm_path(
                sub_idx=int(sub_global_idx),
                expected_axes=[1, 2, 3],
                consumers=consumers,
                model_outputs=model_outputs,
            )
            if path_global is None:
                continue

            scaled0_name = str(path_spatial["scaled_out_name"])
            scaled1_name = str(path_global["scaled_out_name"])
            scaled0_users = set(int(v) for v in consumers.get(scaled0_name, []))
            scaled1_users = set(int(v) for v in consumers.get(scaled1_name, []))
            if len(scaled0_users) != 1 or len(scaled1_users) != 1 or scaled0_users != scaled1_users:
                continue
            blend_add_idx = int(list(scaled0_users)[0])
            blend_add_op = model_ir.operators[int(blend_add_idx)]
            if (
                str(blend_add_op.op_type) != "ADD"
                or len(blend_add_op.inputs) != 2
                or len(blend_add_op.outputs) != 1
            ):
                continue
            blend_inputs = set(str(v) for v in list(blend_add_op.inputs))
            if blend_inputs != {scaled0_name, scaled1_name}:
                continue
            blend_add_out_name = str(blend_add_op.outputs[0])
            if blend_add_out_name in model_outputs:
                continue

            blend_mul_users = set(int(v) for v in consumers.get(blend_add_out_name, []))
            if len(blend_mul_users) != 1:
                continue
            blend_mul_idx = int(list(blend_mul_users)[0])
            blend_mul_op = model_ir.operators[int(blend_mul_idx)]
            if (
                str(blend_mul_op.op_type) != "MUL"
                or len(blend_mul_op.inputs) != 2
                or len(blend_mul_op.outputs) != 1
                or blend_add_out_name not in {str(blend_mul_op.inputs[0]), str(blend_mul_op.inputs[1])}
            ):
                continue
            gamma_input_index = 0 if str(blend_mul_op.inputs[1]) == blend_add_out_name else 1
            gamma_name = str(blend_mul_op.inputs[int(gamma_input_index)])
            blend_mul_out_name = str(blend_mul_op.outputs[0])
            if blend_mul_out_name in model_outputs:
                continue

            blend_bias_users = set(int(v) for v in consumers.get(blend_mul_out_name, []))
            if len(blend_bias_users) != 1:
                continue
            blend_bias_idx = int(list(blend_bias_users)[0])
            blend_bias_op = model_ir.operators[int(blend_bias_idx)]
            if (
                str(blend_bias_op.op_type) != "ADD"
                or len(blend_bias_op.inputs) != 2
                or len(blend_bias_op.outputs) != 1
                or blend_mul_out_name not in {str(blend_bias_op.inputs[0]), str(blend_bias_op.inputs[1])}
            ):
                continue
            beta_input_index = 0 if str(blend_bias_op.inputs[1]) == blend_mul_out_name else 1
            beta_name = str(blend_bias_op.inputs[int(beta_input_index)])
            inst_out_name = str(blend_bias_op.outputs[0])
            if inst_out_name in model_outputs:
                continue

            inst_out_users = set(int(v) for v in consumers.get(inst_out_name, []))
            if len(inst_out_users) != 1:
                continue
            inst_out_user_idx = int(list(inst_out_users)[0])
            inst_out_user_op = model_ir.operators[int(inst_out_user_idx)]

            use_residual_tail = False
            tail_add_idx: Optional[int] = None
            tail_add_op: Optional[OperatorIR] = None
            post_idx: Optional[int] = None
            post_out_name: Optional[str] = None
            residual_pre_idx: Optional[int] = None
            residual_src_name: Optional[str] = None

            if (
                str(inst_out_user_op.op_type) == "TRANSPOSE"
                and len(inst_out_user_op.inputs) >= 2
                and len(inst_out_user_op.outputs) == 1
                and str(inst_out_user_op.inputs[0]) == inst_out_name
                and _read_transpose_perm(model_ir, inst_out_user_op) == perm_nchw_to_nhwc
            ):
                post_idx = int(inst_out_user_idx)
                post_out_name = str(inst_out_user_op.outputs[0])
            elif (
                str(inst_out_user_op.op_type) == "ADD"
                and len(inst_out_user_op.inputs) == 2
                and len(inst_out_user_op.outputs) == 1
                and inst_out_name in {str(inst_out_user_op.inputs[0]), str(inst_out_user_op.inputs[1])}
            ):
                tail_add_idx = int(inst_out_user_idx)
                tail_add_op = inst_out_user_op
                tail_add_out_name = str(tail_add_op.outputs[0])
                if tail_add_out_name in model_outputs:
                    continue
                tail_add_users2 = set(int(v) for v in consumers.get(tail_add_out_name, []))
                if len(tail_add_users2) != 1:
                    continue
                post_idx = int(list(tail_add_users2)[0])
                post_op = model_ir.operators[int(post_idx)]
                if (
                    str(post_op.op_type) != "TRANSPOSE"
                    or len(post_op.inputs) < 2
                    or len(post_op.outputs) != 1
                    or str(post_op.inputs[0]) != tail_add_out_name
                    or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
                ):
                    continue
                post_out_name = str(post_op.outputs[0])
                residual_input_name = (
                    str(tail_add_op.inputs[0])
                    if str(tail_add_op.inputs[1]) == inst_out_name
                    else str(tail_add_op.inputs[1])
                )
                residual_pre_idx = producers.get(str(residual_input_name), None)
                if residual_pre_idx is None:
                    continue
                residual_pre_op = model_ir.operators[int(residual_pre_idx)]
                if (
                    str(residual_pre_op.op_type) != "TRANSPOSE"
                    or len(residual_pre_op.inputs) < 2
                    or len(residual_pre_op.outputs) != 1
                    or str(residual_pre_op.outputs[0]) != residual_input_name
                    or _read_transpose_perm(model_ir, residual_pre_op) != perm_nhwc_to_nchw
                ):
                    continue
                if set(int(v) for v in consumers.get(residual_input_name, [])) != {int(tail_add_idx)}:
                    continue
                residual_src_name = str(residual_pre_op.inputs[0])
                if residual_src_name in model_outputs:
                    continue
                use_residual_tail = True
            else:
                continue

            if post_idx is None or post_out_name is None:
                continue
            if post_out_name in model_outputs:
                continue

            mean2_spatial_axes_name = str(path_spatial["mean2_axes_name"])
            if mean_spatial_axes_name == mean2_spatial_axes_name:
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean_spatial_axes_name,
                    expected_users={int(mean_spatial_idx), int(path_spatial["mean2_idx"])},
                    target_axes=[1, 2],
                    consumers=consumers,
                ):
                    continue
            else:
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean_spatial_axes_name,
                    expected_users={int(mean_spatial_idx)},
                    target_axes=[1, 2],
                    consumers=consumers,
                ):
                    continue
                if not _rewrite_axes_to_nhwc(
                    axes_name=mean2_spatial_axes_name,
                    expected_users={int(path_spatial["mean2_idx"])},
                    target_axes=[1, 2],
                    consumers=consumers,
                ):
                    continue

            if not _axes_match(axes_name=mean_global_axes_name, expected_axes=[1, 2, 3]):
                continue
            if not _axes_match(axes_name=str(path_global["mean2_axes_name"]), expected_axes=[1, 2, 3]):
                continue

            if not _rewrite_nchw_coeff_to_nhwc(
                coeff_name=str(path_spatial["scale_const_name"]),
                expected_users={int(path_spatial["scale_idx"])},
                consumers=consumers,
            ):
                continue
            if not _rewrite_nchw_coeff_to_nhwc(
                coeff_name=str(path_global["scale_const_name"]),
                expected_users={int(path_global["scale_idx"])},
                consumers=consumers,
            ):
                continue

            gamma_bypass_name = _bypass_channelwise_reshape_to_vector(
                coeff_name=str(gamma_name),
                expected_user=int(blend_mul_idx),
                consumers=consumers,
                producers=producers,
            )
            if gamma_bypass_name is not None:
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=blend_mul_op,
                    input_index=int(gamma_input_index),
                    new_input_name=str(gamma_bypass_name),
                )
            else:
                if not _rewrite_nchw_coeff_to_nhwc(
                    coeff_name=str(gamma_name),
                    expected_users={int(blend_mul_idx)},
                    consumers=consumers,
                ):
                    continue

            beta_bypass_name = _bypass_channelwise_reshape_to_vector(
                coeff_name=str(beta_name),
                expected_user=int(blend_bias_idx),
                consumers=consumers,
                producers=producers,
            )
            if beta_bypass_name is not None:
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=blend_bias_op,
                    input_index=int(beta_input_index),
                    new_input_name=str(beta_bypass_name),
                )
            else:
                if not _rewrite_nchw_coeff_to_nhwc(
                    coeff_name=str(beta_name),
                    expected_users={int(blend_bias_idx)},
                    consumers=consumers,
                ):
                    continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=model_ir.operators[int(mean_spatial_idx)],
                input_index=0,
                new_input_name=str(pre_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=model_ir.operators[int(mean_global_idx)],
                input_index=0,
                new_input_name=str(pre_in_name),
            )
            for sub_idx in [int(sub_spatial_idx), int(sub_global_idx)]:
                sub_op = model_ir.operators[int(sub_idx)]
                sub_inputs = [str(v) for v in list(sub_op.inputs)]
                if sub_inputs[0] == pre_out_name:
                    sub_inputs[0] = pre_in_name
                if sub_inputs[1] == pre_out_name:
                    sub_inputs[1] = pre_in_name
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=sub_op,
                    new_inputs=sub_inputs,
                )

            if use_residual_tail:
                if tail_add_op is None or residual_src_name is None:
                    continue
                tail_add_inputs = [str(v) for v in list(tail_add_op.inputs)]
                for input_idx, input_name in enumerate(list(tail_add_inputs)):
                    if str(input_name) != inst_out_name:
                        tail_add_inputs[int(input_idx)] = str(residual_src_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=tail_add_op,
                    new_inputs=tail_add_inputs,
                )

            rank4_names = [
                pre_out_name,
                mean_spatial_out_name,
                mean_global_out_name,
                str(path_spatial["sub_out_name"]),
                str(path_global["sub_out_name"]),
                str(path_spatial["square_out_name"]),
                str(path_global["square_out_name"]),
                str(path_spatial["mean2_out_name"]),
                str(path_global["mean2_out_name"]),
                str(path_spatial["mul_factor_out_name"]),
                str(path_global["mul_factor_out_name"]),
                str(path_spatial["add_eps_out_name"]),
                str(path_global["add_eps_out_name"]),
                str(path_spatial["sqrt_out_name"]),
                str(path_global["sqrt_out_name"]),
                str(path_spatial["div_out_name"]),
                str(path_global["div_out_name"]),
                str(path_spatial["scaled_out_name"]),
                str(path_global["scaled_out_name"]),
                blend_add_out_name,
                blend_mul_out_name,
                inst_out_name,
            ]
            for tensor_name in rank4_names:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(tensor_name), None),
                    perm_nchw_to_nhwc,
                )

            if use_residual_tail:
                if tail_add_op is None:
                    continue
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=tail_add_op,
                    new_outputs=[str(post_out_name)],
                )
            else:
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=blend_bias_op,
                    new_outputs=[str(post_out_name)],
                )

            remove_indices = {int(pre_idx), int(post_idx)}
            if use_residual_tail and residual_pre_idx is not None:
                remove_indices.add(int(residual_pre_idx))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_instancenorm_dualstats_residual_add_resize_nhwc_chains": int(rewritten)}


def _optimize_fold_mul_add_mul_affine_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Fold strict affine tails:
      x -> MUL(c1) -> ADD(c2) -> MUL(c3)
    into:
      x -> MUL(c1*c3) -> ADD(c2*c3)

    This pass is intentionally conservative:
    - all side inputs must be constants,
    - intermediate tensors must be single-use along the chain.
    """
    optimized = 0

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _extract_data_const(
        *,
        op: OperatorIR,
        data_producer_type: Optional[str],
        producers: Dict[str, int],
    ) -> Optional[Tuple[int, str, int, str]]:
        if len(op.inputs) != 2:
            return None
        in0 = str(op.inputs[0])
        in1 = str(op.inputs[1])
        t0 = model_ir.tensors.get(in0, None)
        t1 = model_ir.tensors.get(in1, None)
        c0 = t0 is not None and t0.data is not None
        c1 = t1 is not None and t1.data is not None
        if c0 == c1:
            return None
        if c0:
            const_idx, const_name = 0, in0
            data_idx, data_name = 1, in1
        else:
            const_idx, const_name = 1, in1
            data_idx, data_name = 0, in0
        if data_producer_type is not None:
            pidx = producers.get(str(data_name), None)
            if pidx is None:
                return None
            pop = model_ir.operators[int(pidx)]
            if str(pop.op_type) != str(data_producer_type):
                return None
            if len(pop.outputs) != 1 or str(pop.outputs[0]) != str(data_name):
                return None
        return int(data_idx), str(data_name), int(const_idx), str(const_name)

    def _assign_const_array(
        *,
        target_name: str,
        new_array: np.ndarray,
        chain_indices: set[int],
        consumers: Dict[str, List[int]],
    ) -> str:
        tensor = model_ir.tensors[str(target_name)]
        users = [int(v) for v in consumers.get(str(target_name), [])]
        shared_outside = any(int(v) not in chain_indices for v in users)
        if not shared_outside:
            tensor.data = np.asarray(new_array)
            tensor.shape = [int(v) for v in list(new_array.shape)]
            tensor.shape_signature = [int(v) for v in list(new_array.shape)]
            return str(target_name)

        cloned_name = _unique_tensor_name(f"{target_name}_folded")
        model_ir.tensors[cloned_name] = TensorIR(
            name=cloned_name,
            dtype=str(tensor.dtype),
            shape=[int(v) for v in list(new_array.shape)],
            shape_signature=[int(v) for v in list(new_array.shape)],
            data=np.asarray(new_array),
            is_variable=False,
            quantization=_clone_quantization(tensor.quantization),
        )
        return str(cloned_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for mul2_idx, mul2_op in enumerate(model_ir.operators):
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_out_name = str(mul2_op.outputs[0])

            parsed_mul2 = _extract_data_const(
                op=mul2_op,
                data_producer_type="ADD",
                producers=producers,
            )
            if parsed_mul2 is None:
                continue
            _, add_out_name, mul2_const_idx, mul2_const_name = parsed_mul2
            add_idx = producers.get(str(add_out_name), None)
            if add_idx is None:
                continue
            add_op = model_ir.operators[int(add_idx)]
            if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                continue
            if set(int(v) for v in consumers.get(str(add_out_name), [])) != {int(mul2_idx)}:
                continue

            parsed_add = _extract_data_const(
                op=add_op,
                data_producer_type="MUL",
                producers=producers,
            )
            if parsed_add is None:
                continue
            _, mul1_out_name, add_const_idx, add_const_name = parsed_add
            mul1_idx = producers.get(str(mul1_out_name), None)
            if mul1_idx is None:
                continue
            mul1_op = model_ir.operators[int(mul1_idx)]
            if str(mul1_op.op_type) != "MUL" or len(mul1_op.inputs) != 2 or len(mul1_op.outputs) != 1:
                continue
            if set(int(v) for v in consumers.get(str(mul1_out_name), [])) != {int(add_idx)}:
                continue

            mul1_inputs = [str(v) for v in list(mul1_op.inputs)]
            t0 = model_ir.tensors.get(str(mul1_inputs[0]), None)
            t1 = model_ir.tensors.get(str(mul1_inputs[1]), None)
            c0 = t0 is not None and t0.data is not None
            c1 = t1 is not None and t1.data is not None
            if c0 == c1:
                continue
            mul1_const_idx = 0 if c0 else 1
            mul1_const_name = str(mul1_inputs[int(mul1_const_idx)])

            mul1_const_tensor = model_ir.tensors.get(str(mul1_const_name), None)
            add_const_tensor = model_ir.tensors.get(str(add_const_name), None)
            mul2_const_tensor = model_ir.tensors.get(str(mul2_const_name), None)
            if (
                mul1_const_tensor is None
                or add_const_tensor is None
                or mul2_const_tensor is None
                or mul1_const_tensor.data is None
                or add_const_tensor.data is None
                or mul2_const_tensor.data is None
            ):
                continue

            try:
                c1_arr = np.asarray(mul1_const_tensor.data)
                c2_arr = np.asarray(add_const_tensor.data)
                c3_arr = np.asarray(mul2_const_tensor.data)
                c1_new = np.asarray(c1_arr * c3_arr, dtype=c1_arr.dtype)
                c2_new = np.asarray(c2_arr * c3_arr, dtype=c2_arr.dtype)
            except Exception:
                continue

            chain_indices = {int(mul1_idx), int(add_idx), int(mul2_idx)}

            c1_target_name = _assign_const_array(
                target_name=str(mul1_const_name),
                new_array=np.asarray(c1_new),
                chain_indices=chain_indices,
                consumers=consumers,
            )
            c2_target_name = _assign_const_array(
                target_name=str(add_const_name),
                new_array=np.asarray(c2_new),
                chain_indices=chain_indices,
                consumers=consumers,
            )

            if c1_target_name != str(mul1_const_name):
                mul1_new_inputs = [str(v) for v in list(mul1_op.inputs)]
                mul1_new_inputs[int(mul1_const_idx)] = str(c1_target_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul1_op,
                    new_inputs=mul1_new_inputs,
                )
            if c2_target_name != str(add_const_name):
                add_new_inputs = [str(v) for v in list(add_op.inputs)]
                add_new_inputs[int(add_const_idx)] = str(c2_target_name)
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=add_op,
                    new_inputs=add_new_inputs,
                )

            add_out_tensor = model_ir.tensors.get(str(add_out_name), None)
            mul2_out_tensor = model_ir.tensors.get(str(mul2_out_name), None)
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_op,
                new_outputs=[str(mul2_out_name)],
            )
            if add_out_tensor is not None and mul2_out_tensor is not None:
                mul2_out_tensor.dtype = str(add_out_tensor.dtype)
                mul2_out_tensor.quantization = _clone_quantization(add_out_tensor.quantization)
                mul2_out_tensor.shape = [int(v) for v in list(add_out_tensor.shape)]
                mul2_out_tensor.shape_signature = (
                    [int(v) for v in list(add_out_tensor.shape_signature)]
                    if add_out_tensor.shape_signature is not None
                    else [int(v) for v in list(add_out_tensor.shape)]
                )

            del model_ir.operators[int(mul2_idx)]
            optimized += 1
            changed = True
            break

        if not changed:
            break

    if optimized > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_fold_mul_add_mul_affine_chains": int(optimized)}


def _optimize_transpose_mul_add_const_prepost_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around linear TRANSPOSE->MUL(const)->ADD(const)->TRANSPOSE chains.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --MUL(const)--> m_nchw --ADD(const)--> y_nchw
      y_nchw --TRANSPOSE(0,2,3,1)--> y_nhwc

    Rewrite:
      x_nhwc --MUL(const_nhwc)--> m_nhwc --ADD(const_nhwc)--> y_nhwc
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_binary_const_to_nhwc(
        *,
        op_idx: int,
        side_input_index: int,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False

        nhwc_data: Optional[np.ndarray] = None
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is not None:
            side_shape = [int(v) for v in list(side_data.shape)]
            is_nchw_channelwise = (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 0
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            )
            if is_nchw_channelwise:
                rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is None:
                    return False
                nhwc_data = np.asarray(rotated)
                if np.array_equal(nhwc_data, side_data):
                    return True
            elif _broadcast_static_shapes(target_shape, side_shape) is not None:
                # Already NHWC-compatible. Keep idempotent across repeated sweeps.
                return True
            else:
                rotated = np.asarray(side_data)
                for _ in range(3):
                    rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                    rotated_shape = [int(v) for v in list(rotated.shape)]
                    if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                        nhwc_data = np.asarray(rotated)
                        break
                if nhwc_data is None:
                    return False
        else:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 1
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                nhwc_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            else:
                return True

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)

        target_name = str(side_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{side_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
        else:
            side_tensor.data = np.asarray(nhwc_data)
            side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        _replace_operator_input_at(
            model_ir=model_ir,
            op=model_ir.operators[int(op_idx)],
            input_index=int(side_input_index),
            new_input_name=str(target_name),
        )
        return True

    def _can_rewrite_binary_const_to_nhwc(
        *,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is None:
            return True
        side_shape = [int(v) for v in list(side_data.shape)]
        is_nchw_channelwise = (
            len(side_shape) == 4
            and int(side_shape[0]) == 1
            and int(side_shape[1]) > 0
            and int(side_shape[2]) == 1
            and int(side_shape[3]) == 1
        )
        if is_nchw_channelwise:
            rotated = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            return _broadcast_static_shapes(target_shape, rotated_shape) is not None
        if _broadcast_static_shapes(target_shape, side_shape) is not None:
            return True
        rotated = np.asarray(side_data)
        for _ in range(3):
            rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue
            for mul_idx in pre_users:
                mul_op = model_ir.operators[int(mul_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    continue
                mul_in0 = str(mul_op.inputs[0])
                mul_in1 = str(mul_op.inputs[1])
                if mul_in0 == pre_output_name:
                    mul_side_input_index = 1
                    mul_side_name = mul_in1
                elif mul_in1 == pre_output_name:
                    mul_side_input_index = 0
                    mul_side_name = mul_in0
                else:
                    continue

                add_input_name = str(mul_op.outputs[0])
                if add_input_name in model_outputs:
                    continue
                add_users = [int(v) for v in consumers.get(add_input_name, [])]
                if len(add_users) != 1:
                    continue
                add_idx = int(add_users[0])
                add_op = model_ir.operators[add_idx]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    continue
                add_in0 = str(add_op.inputs[0])
                add_in1 = str(add_op.inputs[1])
                if add_in0 == add_input_name:
                    add_side_input_index = 1
                    add_side_name = add_in1
                elif add_in1 == add_input_name:
                    add_side_input_index = 0
                    add_side_name = add_in0
                else:
                    continue

                add_output_name = str(add_op.outputs[0])
                if add_output_name in model_outputs:
                    continue

                bridge_output_name = str(add_output_name)
                bridge_output_producer_idx = int(add_idx)
                bridge_output_producer_op = add_op
                prelu_idx: Optional[int] = None
                prelu_side_input_index: Optional[int] = None
                prelu_side_name: Optional[str] = None

                add_output_users = [int(v) for v in consumers.get(add_output_name, []) if int(v) != int(add_idx)]
                if len(add_output_users) == 0:
                    continue
                if False and len(add_output_users) == 1:
                    candidate_idx = int(add_output_users[0])
                    candidate_op = model_ir.operators[int(candidate_idx)]
                    if (
                        str(candidate_op.op_type) == "PRELU"
                        and len(candidate_op.inputs) == 2
                        and len(candidate_op.outputs) == 1
                        and str(candidate_op.inputs[0]) == add_output_name
                    ):
                        candidate_out_name = str(candidate_op.outputs[0])
                        if candidate_out_name in model_outputs:
                            continue
                        prelu_idx = int(candidate_idx)
                        prelu_side_input_index = 1
                        prelu_side_name = str(candidate_op.inputs[1])
                        bridge_output_name = str(candidate_out_name)
                        bridge_output_producer_idx = int(candidate_idx)
                        bridge_output_producer_op = candidate_op

                bridge_output_users = [
                    int(v)
                    for v in consumers.get(bridge_output_name, [])
                    if int(v) != int(bridge_output_producer_idx)
                ]
                if len(bridge_output_users) == 0:
                    continue

                post_indices: List[int] = []
                post_output_names: List[str] = []
                legacy_users: List[int] = []
                valid_posts = True
                for user_idx in bridge_output_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == bridge_output_name
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        post_indices.append(int(user_idx))
                        post_output_names.append(str(user_op.outputs[0]))
                    else:
                        legacy_users.append(int(user_idx))
                if not valid_posts or len(post_indices) == 0:
                    continue
                if len(legacy_users) > 0:
                    continue

                chain_index_set = {int(mul_idx), int(add_idx)}
                if prelu_idx is not None:
                    chain_index_set.add(int(prelu_idx))
                target_nhwc_shape = (
                    list(model_ir.tensors[pre_input_name].shape)
                    if pre_input_name in model_ir.tensors
                    else None
                )
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(mul_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    continue
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(add_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    continue
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(mul_idx),
                    side_input_index=int(mul_side_input_index),
                    side_input_name=str(mul_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    continue
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(add_idx),
                    side_input_index=int(add_side_input_index),
                    side_input_name=str(add_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    continue
                if prelu_idx is not None:
                    if prelu_side_input_index is None or prelu_side_name is None:
                        continue
                    if not _can_rewrite_binary_const_to_nhwc(
                        side_input_name=str(prelu_side_name),
                        target_broadcast_shape=target_nhwc_shape,
                    ):
                        continue
                    if not _rewrite_binary_const_to_nhwc(
                        op_idx=int(prelu_idx),
                        side_input_index=int(prelu_side_input_index),
                        side_input_name=str(prelu_side_name),
                        target_broadcast_shape=target_nhwc_shape,
                        chain_index_set=chain_index_set,
                        consumers=consumers,
                    ):
                        continue

                # Bypass only this branch input from pre_output to pre_input.
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                if mul_inputs[0] == pre_output_name:
                    mul_inputs[0] = pre_input_name
                elif mul_inputs[1] == pre_output_name:
                    mul_inputs[1] = pre_input_name
                else:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )

                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(add_input_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(add_output_name, None),
                    perm_nchw_to_nhwc,
                )
                if prelu_idx is not None:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(bridge_output_name, None),
                        perm_nchw_to_nhwc,
                    )

                canonical_post_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=bridge_output_producer_op,
                    new_outputs=[canonical_post_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

                old_add_out_tensor = model_ir.tensors.get(bridge_output_name, None)
                canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
                if old_add_out_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_add_out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_add_out_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_add_out_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_add_out_tensor.shape_signature)]
                        if old_add_out_tensor.shape_signature is not None
                        else [int(v) for v in list(old_add_out_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )

                post_remove_indices = [int(v) for v in post_indices]

                remove_indices = set(int(v) for v in post_remove_indices)
                # Drop pre transpose only when this rewrite consumed its last user.
                pre_remaining_users = [int(v) for v in pre_users if int(v) != int(mul_idx)]
                if len(pre_remaining_users) == 0:
                    remove_indices.add(int(pre_idx))
                for remove_idx in sorted(remove_indices, reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_mul_add_const_prepost_nhwc_chains": int(rewritten)}


def _optimize_transpose_pad_mul_posttranspose_add_nhwc_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    return _optimize_transpose_pad_mul_posttranspose_add_nhwc_chains_pass(model_ir)


def _optimize_transpose_mul_posttranspose_add_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate strict NHWC<->NCHW round-trips around:
      TRANSPOSE(NHWC->NCHW) -> MUL(const) -> TRANSPOSE(NCHW->NHWC) -> ADD(const)

    Rewrite:
      MUL(const_nhwc) -> ADD(const)
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_mul_const_to_nhwc_if_needed(
        *,
        mul_op: OperatorIR,
        const_input_index: int,
        const_input_name: str,
        target_nhwc_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        const_tensor = model_ir.tensors.get(str(const_input_name), None)
        if const_tensor is None or const_tensor.data is None:
            return False
        const_data = np.asarray(const_tensor.data)
        if int(const_data.size) == 1:
            return True

        target_shape = (
            [int(v) for v in list(target_nhwc_shape)]
            if _is_fully_known_positive_shape(target_nhwc_shape)
            else None
        )

        rotated_data: Optional[np.ndarray] = None
        if int(const_data.ndim) == 4:
            as_is_shape = [int(v) for v in list(const_data.shape)]
            is_nchw_channelwise = (
                len(as_is_shape) == 4
                and int(as_is_shape[0]) == 1
                and int(as_is_shape[1]) > 0
                and int(as_is_shape[2]) == 1
                and int(as_is_shape[3]) == 1
            )
            if target_shape is not None and _broadcast_static_shapes(target_shape, as_is_shape) is not None:
                return True
            rotated_candidate = np.transpose(const_data, perm_nchw_to_nhwc).astype(const_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated_candidate.shape)]
            if target_shape is not None:
                if _broadcast_static_shapes(target_shape, rotated_shape) is None:
                    return False
            elif not is_nchw_channelwise:
                return False
            rotated_data = np.asarray(rotated_candidate)
        else:
            if target_shape is None:
                return False
            side_shape = [int(v) for v in list(const_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                return True
            return False

        if rotated_data is None:
            return False

        const_users = [int(v) for v in consumers.get(str(const_input_name), [])]
        shared_outside_chain = any(int(v) not in chain_index_set for v in const_users)
        target_name = str(const_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{const_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(const_tensor.dtype),
                shape=[int(v) for v in list(rotated_data.shape)],
                shape_signature=[int(v) for v in list(rotated_data.shape)],
                data=np.asarray(rotated_data),
                is_variable=False,
                quantization=_clone_quantization(const_tensor.quantization),
            )
        else:
            const_tensor.data = np.asarray(rotated_data)
            const_tensor.shape = [int(v) for v in list(rotated_data.shape)]
            const_tensor.shape_signature = [int(v) for v in list(rotated_data.shape)]

        if target_name != str(const_input_name):
            mul_inputs = [str(v) for v in list(mul_op.inputs)]
            mul_inputs[int(const_input_index)] = str(target_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=mul_op,
                new_inputs=mul_inputs,
            )
        return True

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc:
                continue

            mul_output_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if mul_output_name in model_outputs or post_output_name in model_outputs:
                continue

            mul_idx = producers.get(str(mul_output_name), None)
            if mul_idx is None:
                continue
            mul_op = model_ir.operators[int(mul_idx)]
            if (
                str(mul_op.op_type) != "MUL"
                or len(mul_op.inputs) != 2
                or len(mul_op.outputs) != 1
                or str(mul_op.outputs[0]) != str(mul_output_name)
            ):
                continue
            if set(int(v) for v in consumers.get(str(mul_output_name), [])) != {int(post_idx)}:
                continue

            mul_inputs = [str(v) for v in list(mul_op.inputs)]
            pre_input_index: Optional[int] = None
            pre_idx: Optional[int] = None
            pre_op: Optional[OperatorIR] = None
            mul_const_input_index: Optional[int] = None
            mul_const_name: Optional[str] = None
            for i, input_name in enumerate(mul_inputs):
                producer_idx = producers.get(str(input_name), None)
                if producer_idx is not None:
                    producer_op = model_ir.operators[int(producer_idx)]
                    if (
                        str(producer_op.op_type) == "TRANSPOSE"
                        and len(producer_op.inputs) >= 2
                        and len(producer_op.outputs) == 1
                        and str(producer_op.outputs[0]) == str(input_name)
                        and _read_transpose_perm(model_ir, producer_op) == perm_nhwc_to_nchw
                    ):
                        if pre_idx is not None:
                            pre_idx = None
                            break
                        pre_input_index = int(i)
                        pre_idx = int(producer_idx)
                        pre_op = producer_op
                        continue
                const_tensor = model_ir.tensors.get(str(input_name), None)
                if const_tensor is not None and const_tensor.data is not None:
                    mul_const_input_index = int(i)
                    mul_const_name = str(input_name)

            if (
                pre_idx is None
                or pre_op is None
                or pre_input_index is None
                or mul_const_input_index is None
                or mul_const_name is None
            ):
                continue

            pre_output_name = str(pre_op.outputs[0])
            pre_input_name = str(pre_op.inputs[0])
            if pre_output_name in model_outputs:
                continue

            add_users = [int(v) for v in consumers.get(str(post_output_name), [])]
            if len(add_users) == 0:
                continue

            valid_add_tail = True
            for add_idx in add_users:
                add_op = model_ir.operators[int(add_idx)]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    valid_add_tail = False
                    break
                add_inputs = [str(v) for v in list(add_op.inputs)]
                if str(post_output_name) == add_inputs[0]:
                    side_name = str(add_inputs[1])
                elif str(post_output_name) == add_inputs[1]:
                    side_name = str(add_inputs[0])
                else:
                    valid_add_tail = False
                    break
                side_tensor = model_ir.tensors.get(side_name, None)
                if side_tensor is None or side_tensor.data is None:
                    valid_add_tail = False
                    break
                side_data = np.asarray(side_tensor.data)
                if int(side_data.size) != 1:
                    side_shape = [int(v) for v in list(side_data.shape)]
                    if len(side_shape) != 4:
                        valid_add_tail = False
                        break
                    if not (
                        int(side_shape[0]) == 1
                        and int(side_shape[1]) == 1
                        and int(side_shape[2]) == 1
                        and int(side_shape[3]) > 0
                    ):
                        valid_add_tail = False
                        break
            if not valid_add_tail:
                continue

            target_nhwc_shape: Optional[List[int]] = None
            pre_input_tensor = model_ir.tensors.get(str(pre_input_name), None)
            if pre_input_tensor is not None and len(list(pre_input_tensor.shape)) == 4:
                target_nhwc_shape = [int(v) for v in list(pre_input_tensor.shape)]

            chain_index_set = {int(mul_idx), int(post_idx), int(pre_idx)}
            chain_index_set.update(int(v) for v in add_users)
            if not _rewrite_mul_const_to_nhwc_if_needed(
                mul_op=mul_op,
                const_input_index=int(mul_const_input_index),
                const_input_name=str(mul_const_name),
                target_nhwc_shape=target_nhwc_shape,
                chain_index_set=chain_index_set,
                consumers=consumers,
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(pre_input_index),
                new_input_name=str(pre_input_name),
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(mul_output_name), None),
                perm_nchw_to_nhwc,
            )

            for add_idx in add_users:
                add_op = model_ir.operators[int(add_idx)]
                add_inputs = [str(v) for v in list(add_op.inputs)]
                if str(post_output_name) == add_inputs[0]:
                    _replace_operator_input_at(
                        model_ir=model_ir,
                        op=add_op,
                        input_index=0,
                        new_input_name=str(mul_output_name),
                    )
                elif str(post_output_name) == add_inputs[1]:
                    _replace_operator_input_at(
                        model_ir=model_ir,
                        op=add_op,
                        input_index=1,
                        new_input_name=str(mul_output_name),
                    )

            remove_indices = {int(post_idx)}
            pre_remaining_users = [int(v) for v in consumers.get(str(pre_output_name), []) if int(v) != int(mul_idx)]
            if len(pre_remaining_users) == 0:
                remove_indices.add(int(pre_idx))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_mul_posttranspose_add_nhwc_chains": int(rewritten)}


def _optimize_sinet_shuffle_residual_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize a strict ShuffleNet-like residual pattern observed in SiNet blocks:

      T13: a_nhwc -> a_nchw
      T26/T36: x_nhwc,y_nhwc -> x_nchw,y_nchw
      ADD -> MUL(const) -> ADD(const) -> PRELU -> T42 (to NHWC conv branch)
      CONCAT(a_nchw, prelu_nchw) -> MUL(const) -> ADD(const) -> PRELU -> T49

    Rewrite to NHWC core and drop redundant adapters:
      - remove T26/T36 and run first residual chain in NHWC
      - remove T42 by exposing first PRELU output as NHWC directly
      - rewrite CONCAT to NHWC (axis=3), consume a_nhwc directly (drop T13)
      - run second residual chain in NHWC and remove T49
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post2_idx, post2_op in enumerate(model_ir.operators):
            if (
                str(post2_op.op_type) != "TRANSPOSE"
                or len(post2_op.inputs) < 2
                or len(post2_op.outputs) != 1
                or _read_transpose_perm(model_ir, post2_op) != perm_nchw_to_nhwc
            ):
                continue
            post2_input_name = str(post2_op.inputs[0])
            post2_output_name = str(post2_op.outputs[0])
            if post2_output_name in model_outputs:
                continue

            prelu2_idx = producers.get(post2_input_name, None)
            if prelu2_idx is None:
                continue
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.outputs[0]) != post2_input_name
            ):
                continue

            add2_idx = producers.get(str(prelu2_op.inputs[0]), None)
            if add2_idx is None:
                continue
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if str(prelu2_op.inputs[0]) != add2_out_name:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])

            mul2_idx = producers.get(add2_in0, None)
            if mul2_idx is None:
                mul2_idx = producers.get(add2_in1, None)
            if mul2_idx is None:
                continue
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name == add2_in0:
                add2_side_input_index = 1
                add2_side_name = add2_in1
            elif mul2_out_name == add2_in1:
                add2_side_input_index = 0
                add2_side_name = add2_in0
            else:
                continue

            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if str(mul2_out_name) != str(prelu2_op.inputs[0]) and str(mul2_out_name) != str(add2_in0) and str(mul2_out_name) != str(add2_in1):
                continue
            if str(mul2_out_name) in model_outputs:
                continue

            if mul2_in0 == str(mul2_in1):
                continue
            if mul2_in0 in model_outputs or mul2_in1 in model_outputs:
                continue

            if mul2_in0 in producers and str(model_ir.operators[int(producers[mul2_in0])].op_type) == "CONCATENATION":
                concat2_data_name = str(mul2_in0)
                mul2_side_input_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 in producers and str(model_ir.operators[int(producers[mul2_in1])].op_type) == "CONCATENATION":
                concat2_data_name = str(mul2_in1)
                mul2_side_input_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue

            concat2_idx = producers.get(concat2_data_name, None)
            if concat2_idx is None:
                continue
            concat2_op = model_ir.operators[int(concat2_idx)]
            if (
                str(concat2_op.op_type) != "CONCATENATION"
                or len(concat2_op.inputs) != 2
                or len(concat2_op.outputs) != 1
                or int(concat2_op.options.get("axis", 1)) != 1
                or str(concat2_op.outputs[0]) != concat2_data_name
            ):
                continue

            concat2_inputs = [str(v) for v in list(concat2_op.inputs)]
            pre13_idx: Optional[int] = None
            pre13_input_name: Optional[str] = None
            prelu1_out_name: Optional[str] = None
            for input_name in concat2_inputs:
                input_prod_idx = producers.get(str(input_name), None)
                if input_prod_idx is None:
                    continue
                input_prod_op = model_ir.operators[int(input_prod_idx)]
                if (
                    str(input_prod_op.op_type) == "TRANSPOSE"
                    and len(input_prod_op.inputs) >= 2
                    and len(input_prod_op.outputs) == 1
                    and str(input_prod_op.outputs[0]) == str(input_name)
                    and _read_transpose_perm(model_ir, input_prod_op) == perm_nhwc_to_nchw
                ):
                    pre13_idx = int(input_prod_idx)
                    pre13_input_name = str(input_prod_op.inputs[0])
                elif str(input_prod_op.op_type) == "PRELU":
                    prelu1_out_name = str(input_name)
            if pre13_idx is None or pre13_input_name is None or prelu1_out_name is None:
                continue

            prelu1_idx = producers.get(str(prelu1_out_name), None)
            if prelu1_idx is None:
                continue
            prelu1_op = model_ir.operators[int(prelu1_idx)]
            if (
                str(prelu1_op.op_type) != "PRELU"
                or len(prelu1_op.inputs) != 2
                or len(prelu1_op.outputs) != 1
                or str(prelu1_op.outputs[0]) != str(prelu1_out_name)
            ):
                continue
            if str(prelu1_out_name) in model_outputs:
                continue

            prelu1_users = [int(v) for v in consumers.get(str(prelu1_out_name), []) if int(v) != int(prelu1_idx)]
            if len(prelu1_users) != 2 or int(concat2_idx) not in prelu1_users:
                continue
            post1_idx = None
            for u in prelu1_users:
                if int(u) == int(concat2_idx):
                    continue
                u_op = model_ir.operators[int(u)]
                if (
                    str(u_op.op_type) == "TRANSPOSE"
                    and len(u_op.inputs) >= 2
                    and len(u_op.outputs) == 1
                    and str(u_op.inputs[0]) == str(prelu1_out_name)
                    and _read_transpose_perm(model_ir, u_op) == perm_nchw_to_nhwc
                    and str(u_op.outputs[0]) not in model_outputs
                ):
                    post1_idx = int(u)
            if post1_idx is None:
                continue
            post1_op = model_ir.operators[int(post1_idx)]
            post1_output_name = str(post1_op.outputs[0])

            add1_idx = producers.get(str(prelu1_op.inputs[0]), None)
            if add1_idx is None:
                continue
            add1_op = model_ir.operators[int(add1_idx)]
            if str(add1_op.op_type) != "ADD" or len(add1_op.inputs) != 2 or len(add1_op.outputs) != 1:
                continue
            add1_in0 = str(add1_op.inputs[0])
            add1_in1 = str(add1_op.inputs[1])

            mul1_idx = producers.get(add1_in0, None)
            if mul1_idx is None:
                mul1_idx = producers.get(add1_in1, None)
            if mul1_idx is None:
                continue
            mul1_op = model_ir.operators[int(mul1_idx)]
            if str(mul1_op.op_type) != "MUL" or len(mul1_op.inputs) != 2 or len(mul1_op.outputs) != 1:
                continue
            mul1_out_name = str(mul1_op.outputs[0])
            if mul1_out_name == add1_in0:
                add1_side_input_index = 1
                add1_side_name = add1_in1
            elif mul1_out_name == add1_in1:
                add1_side_input_index = 0
                add1_side_name = add1_in0
            else:
                continue

            mul1_in0 = str(mul1_op.inputs[0])
            mul1_in1 = str(mul1_op.inputs[1])
            add0_out_name: Optional[str] = None
            mul1_side_input_index: Optional[int] = None
            mul1_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mul1_op.inputs[int(data_idx)])
                cand_side = str(mul1_op.inputs[int(side_idx)])
                cand_prod_idx = producers.get(cand_data, None)
                if cand_prod_idx is not None:
                    cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                    if str(cand_prod_op.op_type) == "ADD":
                        add0_out_name = str(cand_data)
                        mul1_side_input_index = int(side_idx)
                        mul1_side_name = str(cand_side)
                        break
            if add0_out_name is None or mul1_side_input_index is None or mul1_side_name is None:
                continue

            add0_idx = producers.get(str(add0_out_name), None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue
            if str(add0_op.outputs[0]) != str(add0_out_name):
                continue

            pre_add_indices: List[int] = []
            pre_add_inputs_nhwc: List[str] = []
            pre_add_out_names = [str(v) for v in list(add0_op.inputs)]
            valid_pre_add = True
            for pre_add_out in pre_add_out_names:
                pre_add_idx = producers.get(str(pre_add_out), None)
                if pre_add_idx is None:
                    valid_pre_add = False
                    break
                pre_add_op = model_ir.operators[int(pre_add_idx)]
                if (
                    str(pre_add_op.op_type) != "TRANSPOSE"
                    or len(pre_add_op.inputs) < 2
                    or len(pre_add_op.outputs) != 1
                    or str(pre_add_op.outputs[0]) != str(pre_add_out)
                    or _read_transpose_perm(model_ir, pre_add_op) != perm_nhwc_to_nchw
                ):
                    valid_pre_add = False
                    break
                if set(int(v) for v in consumers.get(str(pre_add_out), [])) != {int(add0_idx)}:
                    valid_pre_add = False
                    break
                pre_add_indices.append(int(pre_add_idx))
                pre_add_inputs_nhwc.append(str(pre_add_op.inputs[0]))
            if not valid_pre_add or len(pre_add_indices) != 2:
                continue

            if set(int(v) for v in consumers.get(str(concat2_inputs[0]), [])) != {int(concat2_idx)} and set(
                int(v) for v in consumers.get(str(concat2_inputs[1]), [])
            ) != {int(concat2_idx)}:
                continue
            if set(int(v) for v in consumers.get(str(pre13_input_name if pre13_input_name else ""), [])):
                pass
            if set(int(v) for v in consumers.get(str(model_ir.operators[int(pre13_idx)].outputs[0]), [])) != {int(concat2_idx)}:
                continue

            chain_index_set = {
                int(add0_idx),
                int(mul1_idx),
                int(add1_idx),
                int(prelu1_idx),
                int(concat2_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                int(pre13_idx),
                int(post1_idx),
                int(post2_idx),
                int(pre_add_indices[0]),
                int(pre_add_indices[1]),
            }
            mul1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu1_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(
                v is None
                for v in [
                    mul1_side_for_op,
                    add1_side_for_op,
                    prelu1_side_for_op,
                    mul2_side_for_op,
                    add2_side_for_op,
                    prelu2_side_for_op,
                ]
            ):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(pre_add_inputs_nhwc[0]), str(pre_add_inputs_nhwc[1])],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul1_op,
                input_index=int(mul1_side_input_index),
                new_input_name=str(mul1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add1_op,
                input_index=int(add1_side_input_index),
                new_input_name=str(add1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu1_op,
                input_index=1,
                new_input_name=str(prelu1_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu1_op,
                new_outputs=[str(post1_output_name)],
            )

            new_concat_inputs = []
            for inp in concat2_inputs:
                if str(inp) == str(model_ir.operators[int(pre13_idx)].outputs[0]):
                    new_concat_inputs.append(str(pre13_input_name))
                elif str(inp) == str(prelu1_out_name):
                    new_concat_inputs.append(str(post1_output_name))
                else:
                    new_concat_inputs.append(str(inp))
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat2_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat2_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_input_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_input_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post2_output_name)],
            )

            for t_name in [add0_out_name, mul1_out_name, str(add1_op.outputs[0]), str(post1_output_name)]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(concat2_data_name), None),
                perm_nchw_to_nhwc,
            )
            for t_name in [mul2_out_name, add2_out_name, str(post2_output_name)]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            remove_indices = set([int(post1_idx), int(post2_idx), int(pre13_idx)])
            remove_indices.update(set(int(v) for v in pre_add_indices))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_shuffle_residual_transpose_chains": int(optimized)}


def _optimize_sinet_shuffle_residual_mul_posttranspose_tail_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize a SiNet residual variant where the second residual block is already
    partially restored to NHWC:

      T13: a_nhwc -> a_nchw
      T26/T36: x_nhwc,y_nhwc -> x_nchw,y_nchw
      ADD -> MUL(const) -> ADD(const) -> PRELU -> T42 (to NHWC side branch)
      CONCAT(a_nchw, prelu_nchw) -> MUL(const) -> T49 -> ADD(const) -> PRELU

    Rewrite to NHWC core and drop the transpose adapters:
      - remove T26/T36 and run the first residual chain in NHWC
      - remove T42 by exposing the first PRELU output as NHWC directly
      - rewrite CONCAT to NHWC (axis=3), consume a_nhwc directly (drop T13)
      - remove T49 by letting the second MUL emit NHWC directly
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post2_idx, post2_op in enumerate(model_ir.operators):
            if (
                str(post2_op.op_type) != "TRANSPOSE"
                or len(post2_op.inputs) < 2
                or len(post2_op.outputs) != 1
                or _read_transpose_perm(model_ir, post2_op) != perm_nchw_to_nhwc
            ):
                continue
            post2_input_name = str(post2_op.inputs[0])
            post2_output_name = str(post2_op.outputs[0])
            if post2_output_name in model_outputs:
                continue

            mul2_idx = producers.get(post2_input_name, None)
            if mul2_idx is None:
                continue
            mul2_op = model_ir.operators[int(mul2_idx)]
            if (
                str(mul2_op.op_type) != "MUL"
                or len(mul2_op.inputs) != 2
                or len(mul2_op.outputs) != 1
                or str(mul2_op.outputs[0]) != post2_input_name
            ):
                continue

            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            concat2_data_name: Optional[str] = None
            mul2_side_name: Optional[str] = None
            mul2_side_input_index: Optional[int] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mul2_op.inputs[int(data_idx)])
                cand_side = str(mul2_op.inputs[int(side_idx)])
                cand_prod_idx = producers.get(cand_data, None)
                if cand_prod_idx is None:
                    continue
                cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                if str(cand_prod_op.op_type) != "CONCATENATION":
                    continue
                concat2_data_name = str(cand_data)
                mul2_side_name = str(cand_side)
                mul2_side_input_index = int(side_idx)
                break
            if concat2_data_name is None or mul2_side_name is None or mul2_side_input_index is None:
                continue

            concat2_idx = producers.get(concat2_data_name, None)
            if concat2_idx is None:
                continue
            concat2_op = model_ir.operators[int(concat2_idx)]
            if (
                str(concat2_op.op_type) != "CONCATENATION"
                or len(concat2_op.inputs) != 2
                or len(concat2_op.outputs) != 1
                or int(concat2_op.options.get("axis", 1)) != 1
                or str(concat2_op.outputs[0]) != concat2_data_name
            ):
                continue

            post2_users = [int(v) for v in consumers.get(post2_output_name, [])]
            if len(post2_users) != 1:
                continue
            add2_idx = int(post2_users[0])
            add2_op = model_ir.operators[int(add2_idx)]
            if (
                str(add2_op.op_type) != "ADD"
                or len(add2_op.inputs) != 2
                or len(add2_op.outputs) != 1
            ):
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == post2_output_name:
                add2_side_input_index = 1
                add2_side_name = add2_in1
            elif add2_in1 == post2_output_name:
                add2_side_input_index = 0
                add2_side_name = add2_in0
            else:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if add2_out_name in model_outputs:
                continue

            add2_users = [int(v) for v in consumers.get(add2_out_name, [])]
            if len(add2_users) != 1:
                continue
            prelu2_idx = int(add2_users[0])
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.inputs[0]) != add2_out_name
            ):
                continue

            concat2_inputs = [str(v) for v in list(concat2_op.inputs)]
            pre13_idx: Optional[int] = None
            pre13_input_name: Optional[str] = None
            prelu1_out_name: Optional[str] = None
            for input_name in concat2_inputs:
                input_prod_idx = producers.get(str(input_name), None)
                if input_prod_idx is None:
                    continue
                input_prod_op = model_ir.operators[int(input_prod_idx)]
                if (
                    str(input_prod_op.op_type) == "TRANSPOSE"
                    and len(input_prod_op.inputs) >= 2
                    and len(input_prod_op.outputs) == 1
                    and str(input_prod_op.outputs[0]) == str(input_name)
                    and _read_transpose_perm(model_ir, input_prod_op) == perm_nhwc_to_nchw
                ):
                    pre13_idx = int(input_prod_idx)
                    pre13_input_name = str(input_prod_op.inputs[0])
                elif str(input_prod_op.op_type) == "PRELU":
                    prelu1_out_name = str(input_name)
            if pre13_idx is None or pre13_input_name is None or prelu1_out_name is None:
                continue
            if set(int(v) for v in consumers.get(str(model_ir.operators[int(pre13_idx)].outputs[0]), [])) != {int(concat2_idx)}:
                continue

            prelu1_idx = producers.get(str(prelu1_out_name), None)
            if prelu1_idx is None:
                continue
            prelu1_op = model_ir.operators[int(prelu1_idx)]
            if (
                str(prelu1_op.op_type) != "PRELU"
                or len(prelu1_op.inputs) != 2
                or len(prelu1_op.outputs) != 1
                or str(prelu1_op.outputs[0]) != str(prelu1_out_name)
                or str(prelu1_out_name) in model_outputs
            ):
                continue

            prelu1_users = [int(v) for v in consumers.get(str(prelu1_out_name), []) if int(v) != int(prelu1_idx)]
            if len(prelu1_users) != 2 or int(concat2_idx) not in prelu1_users:
                continue
            post1_idx: Optional[int] = None
            for u in prelu1_users:
                if int(u) == int(concat2_idx):
                    continue
                u_op = model_ir.operators[int(u)]
                if (
                    str(u_op.op_type) == "TRANSPOSE"
                    and len(u_op.inputs) >= 2
                    and len(u_op.outputs) == 1
                    and str(u_op.inputs[0]) == str(prelu1_out_name)
                    and _read_transpose_perm(model_ir, u_op) == perm_nchw_to_nhwc
                    and str(u_op.outputs[0]) not in model_outputs
                ):
                    post1_idx = int(u)
            if post1_idx is None:
                continue
            post1_op = model_ir.operators[int(post1_idx)]
            post1_output_name = str(post1_op.outputs[0])

            add1_idx = producers.get(str(prelu1_op.inputs[0]), None)
            if add1_idx is None:
                continue
            add1_op = model_ir.operators[int(add1_idx)]
            if str(add1_op.op_type) != "ADD" or len(add1_op.inputs) != 2 or len(add1_op.outputs) != 1:
                continue
            add1_in0 = str(add1_op.inputs[0])
            add1_in1 = str(add1_op.inputs[1])

            mul1_idx = producers.get(add1_in0, None)
            if mul1_idx is None:
                mul1_idx = producers.get(add1_in1, None)
            if mul1_idx is None:
                continue
            mul1_op = model_ir.operators[int(mul1_idx)]
            if str(mul1_op.op_type) != "MUL" or len(mul1_op.inputs) != 2 or len(mul1_op.outputs) != 1:
                continue
            mul1_out_name = str(mul1_op.outputs[0])
            if mul1_out_name == add1_in0:
                add1_side_input_index = 1
                add1_side_name = add1_in1
            elif mul1_out_name == add1_in1:
                add1_side_input_index = 0
                add1_side_name = add1_in0
            else:
                continue

            add0_out_name: Optional[str] = None
            mul1_side_input_index: Optional[int] = None
            mul1_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mul1_op.inputs[int(data_idx)])
                cand_side = str(mul1_op.inputs[int(side_idx)])
                cand_prod_idx = producers.get(cand_data, None)
                if cand_prod_idx is not None:
                    cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                    if str(cand_prod_op.op_type) == "ADD":
                        add0_out_name = str(cand_data)
                        mul1_side_input_index = int(side_idx)
                        mul1_side_name = str(cand_side)
                        break
            if add0_out_name is None or mul1_side_input_index is None or mul1_side_name is None:
                continue

            add0_idx = producers.get(str(add0_out_name), None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue

            pre_add_indices: List[int] = []
            pre_add_inputs_nhwc: List[str] = []
            valid_pre_add = True
            for pre_add_out in [str(v) for v in list(add0_op.inputs)]:
                pre_add_idx = producers.get(str(pre_add_out), None)
                if pre_add_idx is None:
                    valid_pre_add = False
                    break
                pre_add_op = model_ir.operators[int(pre_add_idx)]
                if (
                    str(pre_add_op.op_type) != "TRANSPOSE"
                    or len(pre_add_op.inputs) < 2
                    or len(pre_add_op.outputs) != 1
                    or str(pre_add_op.outputs[0]) != str(pre_add_out)
                    or _read_transpose_perm(model_ir, pre_add_op) != perm_nhwc_to_nchw
                ):
                    valid_pre_add = False
                    break
                if set(int(v) for v in consumers.get(str(pre_add_out), [])) != {int(add0_idx)}:
                    valid_pre_add = False
                    break
                pre_add_indices.append(int(pre_add_idx))
                pre_add_inputs_nhwc.append(str(pre_add_op.inputs[0]))
            if not valid_pre_add or len(pre_add_indices) != 2:
                continue

            chain_index_set = {
                int(pre13_idx),
                int(pre_add_indices[0]),
                int(pre_add_indices[1]),
                int(add0_idx),
                int(mul1_idx),
                int(add1_idx),
                int(prelu1_idx),
                int(post1_idx),
                int(concat2_idx),
                int(mul2_idx),
                int(post2_idx),
                int(add2_idx),
                int(prelu2_idx),
            }
            mul1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu1_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(
                v is None
                for v in [
                    mul1_side_for_op,
                    add1_side_for_op,
                    prelu1_side_for_op,
                    mul2_side_for_op,
                    add2_side_for_op,
                    prelu2_side_for_op,
                ]
            ):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(pre_add_inputs_nhwc[0]), str(pre_add_inputs_nhwc[1])],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul1_op,
                input_index=int(mul1_side_input_index),
                new_input_name=str(mul1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add1_op,
                input_index=int(add1_side_input_index),
                new_input_name=str(add1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu1_op,
                input_index=1,
                new_input_name=str(prelu1_side_for_op),
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu1_op,
                new_outputs=[str(post1_output_name)],
            )

            new_concat_inputs = []
            for inp in concat2_inputs:
                if str(inp) == str(model_ir.operators[int(pre13_idx)].outputs[0]):
                    new_concat_inputs.append(str(pre13_input_name))
                elif str(inp) == str(prelu1_out_name):
                    new_concat_inputs.append(str(post1_output_name))
                else:
                    new_concat_inputs.append(str(inp))
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat2_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat2_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_input_index),
                new_input_name=str(mul2_side_for_op),
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=mul2_op,
                new_outputs=[str(post2_output_name)],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_input_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )

            for t_name in [add0_out_name, mul1_out_name, str(add1_op.outputs[0]), str(post1_output_name)]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(concat2_data_name), None),
                perm_nchw_to_nhwc,
            )

            remove_indices = set([int(pre13_idx), int(post1_idx), int(post2_idx)])
            remove_indices.update(set(int(v) for v in pre_add_indices))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_shuffle_residual_mul_posttranspose_tail_chains": int(optimized)}


def _optimize_sinet_late_residual_pre_add_mul_add_prelu_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize the late SiNet residual variant:

      x_nhwc --T(0,3,1,2)--> x_nchw
      y_nhwc --T(0,3,1,2)--> y_nchw   (y_nhwc is CONCAT(axis=3))
      ADD -> MUL(const) -> ADD(const) -> PRELU -> T(0,2,3,1) -> conv_nhwc

    The PRELU output also keeps a legacy CONCAT(axis=1) consumer. Preserve
    that legacy branch with one transpose while exposing the conv branch in NHWC.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_input_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if post_output_name in model_outputs:
                continue

            post_users = [int(v) for v in consumers.get(post_output_name, [])]
            if len(post_users) != 1:
                continue
            post_user_idx = int(post_users[0])
            post_user_op = model_ir.operators[int(post_user_idx)]
            if str(post_user_op.op_type) not in {"CONV_2D", "DEPTHWISE_CONV_2D"}:
                continue
            if str(post_user_op.inputs[0]) != post_output_name:
                continue

            prelu_idx = producers.get(post_input_name, None)
            if prelu_idx is None:
                continue
            prelu_op = model_ir.operators[int(prelu_idx)]
            if (
                str(prelu_op.op_type) != "PRELU"
                or len(prelu_op.inputs) != 2
                or len(prelu_op.outputs) != 1
                or str(prelu_op.outputs[0]) != post_input_name
            ):
                continue

            prelu_out_tensor = model_ir.tensors.get(post_input_name, None)
            prelu_out_shape = (
                [int(v) for v in list(prelu_out_tensor.shape)]
                if prelu_out_tensor is not None and prelu_out_tensor.shape is not None
                else None
            )
            if (
                not _is_fully_known_positive_shape(prelu_out_shape)
                or len(prelu_out_shape) != 4
                or int(prelu_out_shape[2]) != 40
                or int(prelu_out_shape[3]) != 40
            ):
                continue

            legacy_users = [int(v) for v in consumers.get(post_input_name, []) if int(v) != int(post_idx)]
            if len(legacy_users) == 0:
                continue

            add2_idx = producers.get(str(prelu_op.inputs[0]), None)
            if add2_idx is None:
                continue
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])

            mul_idx = producers.get(add2_in0, None)
            if mul_idx is None:
                mul_idx = producers.get(add2_in1, None)
            if mul_idx is None:
                continue
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name == add2_in0:
                add2_side_input_index = 1
                add2_side_name = add2_in1
            elif mul_out_name == add2_in1:
                add2_side_input_index = 0
                add2_side_name = add2_in0
            else:
                continue

            add0_name: Optional[str] = None
            mul_side_input_index: Optional[int] = None
            mul_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                candidate_data = str(mul_op.inputs[int(data_idx)])
                candidate_prod_idx = producers.get(candidate_data, None)
                if candidate_prod_idx is None:
                    continue
                candidate_prod_op = model_ir.operators[int(candidate_prod_idx)]
                if str(candidate_prod_op.op_type) != "ADD":
                    continue
                add0_name = candidate_data
                mul_side_input_index = int(side_idx)
                mul_side_name = str(mul_op.inputs[int(side_idx)])
                break
            if add0_name is None or mul_side_input_index is None or mul_side_name is None:
                continue

            add0_idx = producers.get(add0_name, None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue

            input_plans: List[Dict[str, Any]] = []
            concat_backed_inputs = 0
            for add_input_name in [str(v) for v in list(add0_op.inputs)]:
                pre_idx = producers.get(str(add_input_name), None)
                if pre_idx is None:
                    input_plans = []
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != str(add_input_name)
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                    or str(add_input_name) in model_outputs
                ):
                    input_plans = []
                    break
                users = [int(v) for v in consumers.get(str(add_input_name), [])]
                if set(users) != {int(add0_idx)}:
                    input_plans = []
                    break
                nhwc_input_name = str(pre_op.inputs[0])
                nhwc_input_prod_idx = producers.get(nhwc_input_name, None)
                if nhwc_input_prod_idx is not None:
                    nhwc_input_prod = model_ir.operators[int(nhwc_input_prod_idx)]
                    if (
                        str(nhwc_input_prod.op_type) == "CONCATENATION"
                        and int(nhwc_input_prod.options.get("axis", -1)) == 3
                    ):
                        concat_backed_inputs += 1
                input_plans.append(
                    {
                        "pre_idx": int(pre_idx),
                        "nhwc_input_name": nhwc_input_name,
                    }
                )
            if len(input_plans) != 2 or concat_backed_inputs != 1:
                continue

            chain_index_set = {
                int(add0_idx),
                int(mul_idx),
                int(add2_idx),
                int(prelu_idx),
                int(post_idx),
                int(post_user_idx),
            }
            chain_index_set.update(int(plan["pre_idx"]) for plan in input_plans)
            mul_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(v is None for v in [mul_side_for_op, add2_side_for_op, prelu_side_for_op]):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(plan["nhwc_input_name"]) for plan in input_plans],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(mul_side_input_index),
                new_input_name=str(mul_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_input_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu_op,
                input_index=1,
                new_input_name=str(prelu_side_for_op),
            )

            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(add0_name, None), perm_nchw_to_nhwc)
            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(mul_out_name, None), perm_nchw_to_nhwc)
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(add2_op.outputs[0]), None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(post_input_name, None), perm_nchw_to_nhwc)

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[str(post_output_name)],
            )

            old_prelu_tensor = model_ir.tensors.get(post_input_name, None)
            new_prelu_tensor = model_ir.tensors.get(post_output_name, None)
            if old_prelu_tensor is not None and new_prelu_tensor is not None:
                new_prelu_tensor.dtype = str(old_prelu_tensor.dtype)
                new_prelu_tensor.quantization = _clone_quantization(old_prelu_tensor.quantization)
                new_prelu_tensor.shape = [int(v) for v in list(old_prelu_tensor.shape)]
                new_prelu_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu_tensor.shape_signature)]
                    if old_prelu_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(new_prelu_tensor, perm_nchw_to_nhwc)

            keep_perm_name = str(post_op.inputs[1])
            keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
            if keep_perm_tensor is not None:
                keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
            _set_operator_inputs(
                model_ir=model_ir,
                op=post_op,
                new_inputs=[str(post_output_name), keep_perm_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=post_op,
                new_outputs=[str(post_input_name)],
            )

            for remove_idx in sorted([int(plan["pre_idx"]) for plan in input_plans], reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_late_residual_pre_add_mul_add_prelu_chains": int(optimized)}


def _optimize_sinet_deep_skip_concat_resize_affine_tail_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize a late SiNet 40x40 residual variant with a deep skip branch:

      skip_nhwc --T(0,3,1,2)--> skip_nchw
      pre_nchw --T(0,2,3,1)--> pre_nhwc --conv/gather/resize tail-->
      b0_nhwc --T(0,3,1,2)--> b0_nchw
      rz_nhwc --T(0,3,1,2)--> rz_nchw --MUL(const)--ADD(const)--> b1_nchw
      CONCAT(axis=1,[b0_nchw,b1_nchw]) -> c1_nchw
      ADD(pre_nchw,c1_nchw)->MUL(const)->ADD(const)->PRELU -> p1_nchw
      CONCAT(axis=1,[skip_nchw,p1_nchw]) -> c2_nchw
      c2_nchw -> MUL(const) -> T(0,2,3,1) -> ADD -> PRELU

    Rewrite the branch-local residual back to NHWC while preserving the deep
    skip semantics and leaving the upstream NCHW residual source untouched.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_input_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if post_output_name in model_outputs:
                continue

            post_users = [int(v) for v in consumers.get(post_output_name, [])]
            if len(post_users) != 1:
                continue
            add2_idx = int(post_users[0])
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            if str(add2_op.outputs[0]) in model_outputs:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == add2_in1:
                continue
            if add2_in0 == post_output_name:
                add2_side_index = 1
                add2_side_name = str(add2_in1)
            elif add2_in1 == post_output_name:
                add2_side_index = 0
                add2_side_name = str(add2_in0)
            else:
                continue

            add2_users = [int(v) for v in consumers.get(str(add2_op.outputs[0]), [])]
            if len(add2_users) != 1:
                continue
            prelu2_idx = int(add2_users[0])
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.inputs[0]) != str(add2_op.outputs[0])
            ):
                continue

            mul2_idx = producers.get(post_input_name, None)
            if mul2_idx is None:
                continue
            mul2_op = model_ir.operators[int(mul2_idx)]
            if (
                str(mul2_op.op_type) != "MUL"
                or len(mul2_op.inputs) != 2
                or len(mul2_op.outputs) != 1
                or str(mul2_op.outputs[0]) != str(post_input_name)
                or str(post_input_name) in model_outputs
            ):
                continue
            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if mul2_in0 == mul2_in1:
                continue
            if mul2_in0 in producers and str(model_ir.operators[int(producers[mul2_in0])].op_type) == "CONCATENATION":
                concat2_name = str(mul2_in0)
                mul2_side_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 in producers and str(model_ir.operators[int(producers[mul2_in1])].op_type) == "CONCATENATION":
                concat2_name = str(mul2_in1)
                mul2_side_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue

            concat2_idx = producers.get(concat2_name, None)
            if concat2_idx is None:
                continue
            concat2_op = model_ir.operators[int(concat2_idx)]
            if (
                str(concat2_op.op_type) != "CONCATENATION"
                or len(concat2_op.inputs) != 2
                or len(concat2_op.outputs) != 1
                or str(concat2_op.outputs[0]) != str(concat2_name)
                or int(concat2_op.options.get("axis", 1)) != 1
                or set(int(v) for v in consumers.get(str(concat2_name), [])) != {int(mul2_idx)}
            ):
                continue

            skip_transpose_idx: Optional[int] = None
            skip_nhwc_name: Optional[str] = None
            skip_nchw_name: Optional[str] = None
            prelu1_idx: Optional[int] = None
            prelu1_out_name: Optional[str] = None
            for concat_input in [str(v) for v in list(concat2_op.inputs)]:
                prod_idx = producers.get(str(concat_input), None)
                if prod_idx is None:
                    continue
                prod_op = model_ir.operators[int(prod_idx)]
                if (
                    str(prod_op.op_type) == "TRANSPOSE"
                    and len(prod_op.inputs) >= 2
                    and len(prod_op.outputs) == 1
                    and str(prod_op.outputs[0]) == str(concat_input)
                    and _read_transpose_perm(model_ir, prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(concat_input), [])) == {int(concat2_idx)}
                    and str(concat_input) not in model_outputs
                ):
                    skip_transpose_idx = int(prod_idx)
                    skip_nhwc_name = str(prod_op.inputs[0])
                    skip_nchw_name = str(concat_input)
                elif str(prod_op.op_type) == "PRELU":
                    prelu1_idx = int(prod_idx)
                    prelu1_out_name = str(concat_input)
            if (
                skip_transpose_idx is None
                or skip_nhwc_name is None
                or skip_nchw_name is None
                or prelu1_idx is None
                or prelu1_out_name is None
            ):
                continue

            prelu1_op = model_ir.operators[int(prelu1_idx)]
            if (
                str(prelu1_op.op_type) != "PRELU"
                or len(prelu1_op.inputs) != 2
                or len(prelu1_op.outputs) != 1
                or str(prelu1_op.outputs[0]) != str(prelu1_out_name)
                or str(prelu1_out_name) in model_outputs
                or set(int(v) for v in consumers.get(str(prelu1_out_name), [])) != {int(concat2_idx)}
            ):
                continue

            add1_idx = producers.get(str(prelu1_op.inputs[0]), None)
            if add1_idx is None:
                continue
            add1_op = model_ir.operators[int(add1_idx)]
            if str(add1_op.op_type) != "ADD" or len(add1_op.inputs) != 2 or len(add1_op.outputs) != 1:
                continue
            add1_in0 = str(add1_op.inputs[0])
            add1_in1 = str(add1_op.inputs[1])
            if add1_in0 == add1_in1:
                continue

            mul1_idx = producers.get(add1_in0, None)
            if mul1_idx is None:
                mul1_idx = producers.get(add1_in1, None)
            if mul1_idx is None:
                continue
            mul1_op = model_ir.operators[int(mul1_idx)]
            if str(mul1_op.op_type) != "MUL" or len(mul1_op.inputs) != 2 or len(mul1_op.outputs) != 1:
                continue
            mul1_out_name = str(mul1_op.outputs[0])
            if mul1_out_name == add1_in0:
                add1_side_index = 1
                add1_side_name = str(add1_in1)
            elif mul1_out_name == add1_in1:
                add1_side_index = 0
                add1_side_name = str(add1_in0)
            else:
                continue

            add0_name: Optional[str] = None
            mul1_side_index: Optional[int] = None
            mul1_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mul1_op.inputs[int(data_idx)])
                cand_side = str(mul1_op.inputs[int(side_idx)])
                cand_prod_idx = producers.get(cand_data, None)
                if cand_prod_idx is None:
                    continue
                cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                if str(cand_prod_op.op_type) == "ADD":
                    add0_name = str(cand_data)
                    mul1_side_index = int(side_idx)
                    mul1_side_name = str(cand_side)
                    break
            if add0_name is None or mul1_side_index is None or mul1_side_name is None:
                continue

            add0_idx = producers.get(str(add0_name), None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if (
                str(add0_op.op_type) != "ADD"
                or len(add0_op.inputs) != 2
                or len(add0_op.outputs) != 1
                or str(add0_op.outputs[0]) != str(add0_name)
                or str(add0_name) in model_outputs
            ):
                continue

            pre_nchw_name: Optional[str] = None
            pre_to_nhwc_idx: Optional[int] = None
            pre_nhwc_name: Optional[str] = None
            concat1_idx: Optional[int] = None
            concat1_name: Optional[str] = None
            for add0_input in [str(v) for v in list(add0_op.inputs)]:
                add0_prod_idx = producers.get(str(add0_input), None)
                if add0_prod_idx is None:
                    continue
                add0_prod_op = model_ir.operators[int(add0_prod_idx)]
                if (
                    str(add0_prod_op.op_type) == "CONCATENATION"
                    and len(add0_prod_op.inputs) == 2
                    and len(add0_prod_op.outputs) == 1
                    and str(add0_prod_op.outputs[0]) == str(add0_input)
                    and int(add0_prod_op.options.get("axis", 1)) == 1
                    and set(int(v) for v in consumers.get(str(add0_input), [])) == {int(add0_idx)}
                    and str(add0_input) not in model_outputs
                ):
                    concat1_idx = int(add0_prod_idx)
                    concat1_name = str(add0_input)
                else:
                    pre_nchw_name = str(add0_input)
            if pre_nchw_name is None or concat1_idx is None or concat1_name is None:
                continue
            pre_input_tensor = model_ir.tensors.get(str(pre_nchw_name), None)
            if (
                pre_input_tensor is not None
                and _is_fully_known_positive_shape(pre_input_tensor.shape)
                and len(pre_input_tensor.shape) == 4
                and int(pre_input_tensor.shape[1]) == 40
                and int(pre_input_tensor.shape[2]) == 40
            ):
                pre_nhwc_name = str(pre_nchw_name)
            else:
                pre_nchw_users = set(int(v) for v in consumers.get(str(pre_nchw_name), []))
                if int(add0_idx) not in pre_nchw_users or len(pre_nchw_users) != 2:
                    continue
                for pre_nchw_user_idx in sorted(list(pre_nchw_users)):
                    if int(pre_nchw_user_idx) == int(add0_idx):
                        continue
                    candidate_op = model_ir.operators[int(pre_nchw_user_idx)]
                    if (
                        str(candidate_op.op_type) == "TRANSPOSE"
                        and len(candidate_op.inputs) >= 2
                        and len(candidate_op.outputs) == 1
                        and str(candidate_op.inputs[0]) == str(pre_nchw_name)
                        and _read_transpose_perm(model_ir, candidate_op) == perm_nchw_to_nhwc
                        and str(candidate_op.outputs[0]) not in model_outputs
                    ):
                        pre_to_nhwc_idx = int(pre_nchw_user_idx)
                        pre_nhwc_name = str(candidate_op.outputs[0])
                        break
                if pre_to_nhwc_idx is None and pre_nhwc_name is None:
                    continue

            concat1_op = model_ir.operators[int(concat1_idx)]
            trans_a_idx: Optional[int] = None
            trans_a_in_name: Optional[str] = None
            addb_idx: Optional[int] = None
            addb_out_name: Optional[str] = None
            for concat1_input in [str(v) for v in list(concat1_op.inputs)]:
                concat1_prod_idx = producers.get(str(concat1_input), None)
                if concat1_prod_idx is None:
                    continue
                concat1_prod_op = model_ir.operators[int(concat1_prod_idx)]
                if (
                    str(concat1_prod_op.op_type) == "TRANSPOSE"
                    and len(concat1_prod_op.inputs) >= 2
                    and len(concat1_prod_op.outputs) == 1
                    and str(concat1_prod_op.outputs[0]) == str(concat1_input)
                    and _read_transpose_perm(model_ir, concat1_prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(concat1_input), [])) == {int(concat1_idx)}
                    and str(concat1_input) not in model_outputs
                ):
                    trans_a_idx = int(concat1_prod_idx)
                    trans_a_in_name = str(concat1_prod_op.inputs[0])
                elif (
                    str(concat1_prod_op.op_type) == "ADD"
                    and len(concat1_prod_op.inputs) == 2
                    and len(concat1_prod_op.outputs) == 1
                    and str(concat1_prod_op.outputs[0]) == str(concat1_input)
                    and set(int(v) for v in consumers.get(str(concat1_input), [])) == {int(concat1_idx)}
                    and str(concat1_input) not in model_outputs
                ):
                    addb_idx = int(concat1_prod_idx)
                    addb_out_name = str(concat1_input)
            if trans_a_idx is None or trans_a_in_name is None or addb_idx is None or addb_out_name is None:
                continue

            addb_op = model_ir.operators[int(addb_idx)]
            addb_in0 = str(addb_op.inputs[0])
            addb_in1 = str(addb_op.inputs[1])
            mulb_idx = producers.get(addb_in0, None)
            if mulb_idx is None:
                mulb_idx = producers.get(addb_in1, None)
            if mulb_idx is None:
                continue
            mulb_op = model_ir.operators[int(mulb_idx)]
            if str(mulb_op.op_type) != "MUL" or len(mulb_op.inputs) != 2 or len(mulb_op.outputs) != 1:
                continue
            mulb_out_name = str(mulb_op.outputs[0])
            if mulb_out_name == addb_in0:
                addb_side_index = 1
                addb_side_name = str(addb_in1)
            elif mulb_out_name == addb_in1:
                addb_side_index = 0
                addb_side_name = str(addb_in0)
            else:
                continue

            trans_b_idx: Optional[int] = None
            trans_b_in_name: Optional[str] = None
            mulb_side_index: Optional[int] = None
            mulb_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mulb_op.inputs[int(data_idx)])
                cand_side = str(mulb_op.inputs[int(side_idx)])
                cand_prod_idx = producers.get(str(cand_data), None)
                if cand_prod_idx is None:
                    continue
                cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                if (
                    str(cand_prod_op.op_type) != "TRANSPOSE"
                    or len(cand_prod_op.inputs) < 2
                    or len(cand_prod_op.outputs) != 1
                    or str(cand_prod_op.outputs[0]) != str(cand_data)
                    or _read_transpose_perm(model_ir, cand_prod_op) != perm_nhwc_to_nchw
                    or set(int(v) for v in consumers.get(str(cand_data), [])) != {int(mulb_idx)}
                    or str(cand_data) in model_outputs
                ):
                    continue
                resize_name = str(cand_prod_op.inputs[0])
                resize_idx = producers.get(resize_name, None)
                if resize_idx is None:
                    continue
                resize_op = model_ir.operators[int(resize_idx)]
                if (
                    str(resize_op.op_type) not in {"RESIZE_BILINEAR", "RESIZE_NEAREST_NEIGHBOR"}
                    or len(resize_op.outputs) != 1
                    or str(resize_op.outputs[0]) != str(resize_name)
                ):
                    continue
                trans_b_idx = int(cand_prod_idx)
                trans_b_in_name = str(resize_name)
                mulb_side_index = int(side_idx)
                mulb_side_name = str(cand_side)
                break
            if (
                trans_b_idx is None
                or trans_b_in_name is None
                or mulb_side_index is None
                or mulb_side_name is None
            ):
                continue

            shape_candidates = [
                model_ir.tensors.get(str(skip_nhwc_name), None),
                model_ir.tensors.get(str(trans_a_in_name), None),
                model_ir.tensors.get(str(trans_b_in_name), None),
                model_ir.tensors.get(str(pre_nhwc_name), None),
                model_ir.tensors.get(str(post_output_name), None),
            ]
            if any(
                t is None
                or not _is_fully_known_positive_shape(t.shape)
                or len(t.shape) != 4
                or int(t.shape[1]) != 40
                or int(t.shape[2]) != 40
                for t in shape_candidates
            ):
                continue

            chain_index_set = {
                int(skip_transpose_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                int(addb_idx),
                int(mulb_idx),
                int(concat1_idx),
                int(add0_idx),
                int(mul1_idx),
                int(add1_idx),
                int(prelu1_idx),
                int(concat2_idx),
                int(mul2_idx),
                int(post_idx),
                int(add2_idx),
                int(prelu2_idx),
            }
            if pre_to_nhwc_idx is not None:
                chain_index_set.add(int(pre_to_nhwc_idx))
            mulb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mulb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            addb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(addb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu1_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(
                v is None
                for v in [
                    mulb_side_for_op,
                    addb_side_for_op,
                    mul1_side_for_op,
                    add1_side_for_op,
                    prelu1_side_for_op,
                    mul2_side_for_op,
                    add2_side_for_op,
                ]
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(1 - int(mulb_side_index)),
                new_input_name=str(trans_b_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(mulb_side_index),
                new_input_name=str(mulb_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=addb_op,
                input_index=int(addb_side_index),
                new_input_name=str(addb_side_for_op),
            )

            trans_a_out_name = str(model_ir.operators[int(trans_a_idx)].outputs[0])
            new_concat1_inputs = [
                str(trans_a_in_name) if str(v) == str(trans_a_out_name) else str(v)
                for v in list(concat1_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat1_op,
                new_inputs=[str(v) for v in new_concat1_inputs],
            )
            concat1_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=add0_op,
                input_index=0 if str(add0_op.inputs[0]) == str(pre_nchw_name) else 1,
                new_input_name=str(pre_nhwc_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul1_op,
                input_index=int(mul1_side_index),
                new_input_name=str(mul1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add1_op,
                input_index=int(add1_side_index),
                new_input_name=str(add1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu1_op,
                input_index=1,
                new_input_name=str(prelu1_side_for_op),
            )

            new_concat2_inputs = [
                str(skip_nhwc_name) if str(v) == str(skip_nchw_name) else str(v)
                for v in list(concat2_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat2_op,
                new_inputs=[str(v) for v in new_concat2_inputs],
            )
            concat2_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=0 if str(add2_op.inputs[0]) == str(post_output_name) else 1,
                new_input_name=str(post_input_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_index),
                new_input_name=str(add2_side_for_op),
            )

            for tensor_name in [
                str(mulb_out_name),
                str(addb_out_name),
                str(concat1_name),
                str(add0_name),
                str(mul1_out_name),
                str(add1_op.outputs[0]),
                str(prelu1_out_name),
                str(concat2_name),
                str(post_input_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(tensor_name), None),
                    perm_nchw_to_nhwc,
                )

            remove_indices = {
                int(skip_transpose_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                int(post_idx),
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_deep_skip_concat_resize_affine_tail_chains": int(optimized)}


def _optimize_sinet_deep_skip_pre_add_concat_prelu_fanout_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize a SiNet deep-skip fanout variant:

      pre_nchw --T(0,2,3,1)--> pre_nhwc --conv-->
      concat_nhwc --T(0,3,1,2)--> concat_nchw
      ADD(pre_nchw, concat_nchw) -> MUL(const) -> ADD(const) -> PRELU -> p_nchw
      p_nchw --T(0,2,3,1)--> p_nhwc --conv-->

    The PRELU output also feeds a deep residual branch in NCHW. Rewrite the
    conv path to NHWC and keep one reverse adapter only for the residual path.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_input_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if post_output_name in model_outputs:
                continue

            post_users = [int(v) for v in consumers.get(post_output_name, [])]
            if len(post_users) != 1:
                continue
            post_user_op = model_ir.operators[int(post_users[0])]
            if str(post_user_op.op_type) not in {"CONV_2D", "DEPTHWISE_CONV_2D"}:
                continue
            if str(post_user_op.inputs[0]) != str(post_output_name):
                continue

            prelu_idx = producers.get(post_input_name, None)
            if prelu_idx is None:
                continue
            prelu_op = model_ir.operators[int(prelu_idx)]
            if (
                str(prelu_op.op_type) != "PRELU"
                or len(prelu_op.inputs) != 2
                or len(prelu_op.outputs) != 1
                or str(prelu_op.outputs[0]) != str(post_input_name)
            ):
                continue

            prelu_out_tensor = model_ir.tensors.get(post_input_name, None)
            prelu_out_shape = (
                [int(v) for v in list(prelu_out_tensor.shape)]
                if prelu_out_tensor is not None and prelu_out_tensor.shape is not None
                else None
            )
            if (
                not _is_fully_known_positive_shape(prelu_out_shape)
                or len(prelu_out_shape) != 4
                or int(prelu_out_shape[2]) != 40
                or int(prelu_out_shape[3]) != 40
            ):
                continue

            legacy_users = [int(v) for v in consumers.get(post_input_name, []) if int(v) != int(post_idx)]
            if len(legacy_users) == 0:
                continue

            add2_idx = producers.get(str(prelu_op.inputs[0]), None)
            if add2_idx is None:
                continue
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])

            mul_idx = producers.get(add2_in0, None)
            if mul_idx is None:
                mul_idx = producers.get(add2_in1, None)
            if mul_idx is None:
                continue
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name == add2_in0:
                add2_side_input_index = 1
                add2_side_name = add2_in1
            elif mul_out_name == add2_in1:
                add2_side_input_index = 0
                add2_side_name = add2_in0
            else:
                continue

            add0_name: Optional[str] = None
            mul_side_input_index: Optional[int] = None
            mul_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                candidate_data = str(mul_op.inputs[int(data_idx)])
                candidate_prod_idx = producers.get(candidate_data, None)
                if candidate_prod_idx is None:
                    continue
                candidate_prod_op = model_ir.operators[int(candidate_prod_idx)]
                if str(candidate_prod_op.op_type) != "ADD":
                    continue
                add0_name = candidate_data
                mul_side_input_index = int(side_idx)
                mul_side_name = str(mul_op.inputs[int(side_idx)])
                break
            if add0_name is None or mul_side_input_index is None or mul_side_name is None:
                continue

            add0_idx = producers.get(add0_name, None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue

            concat_plan: Optional[Dict[str, Any]] = None
            direct_pre_plan: Optional[Dict[str, Any]] = None
            ordered_inputs: List[str] = []
            for add_input_name in [str(v) for v in list(add0_op.inputs)]:
                ordered_inputs.append(str(add_input_name))
                pre_idx = producers.get(str(add_input_name), None)
                if pre_idx is not None:
                    pre_op = model_ir.operators[int(pre_idx)]
                    if (
                        str(pre_op.op_type) == "TRANSPOSE"
                        and len(pre_op.inputs) >= 2
                        and len(pre_op.outputs) == 1
                        and str(pre_op.outputs[0]) == str(add_input_name)
                        and _read_transpose_perm(model_ir, pre_op) == perm_nhwc_to_nchw
                        and set(int(v) for v in consumers.get(str(add_input_name), [])) == {int(add0_idx)}
                        and str(add_input_name) not in model_outputs
                    ):
                        nhwc_input_name = str(pre_op.inputs[0])
                        nhwc_input_prod_idx = producers.get(nhwc_input_name, None)
                        if nhwc_input_prod_idx is None:
                            continue
                        nhwc_input_prod = model_ir.operators[int(nhwc_input_prod_idx)]
                        if (
                            str(nhwc_input_prod.op_type) == "CONCATENATION"
                            and int(nhwc_input_prod.options.get("axis", -1)) == 3
                        ):
                            concat_plan = {
                                "input_name": str(add_input_name),
                                "pre_idx": int(pre_idx),
                                "nhwc_input_name": str(nhwc_input_name),
                            }
                        continue

                direct_users = set(int(v) for v in consumers.get(str(add_input_name), []))
                if int(add0_idx) not in direct_users or len(direct_users) != 2:
                    continue
                sibling_transpose_idx: Optional[int] = None
                sibling_nhwc_name: Optional[str] = None
                for user_idx in sorted(list(direct_users)):
                    if int(user_idx) == int(add0_idx):
                        continue
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == str(add_input_name)
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        sibling_transpose_idx = int(user_idx)
                        sibling_nhwc_name = str(user_op.outputs[0])
                        break
                if sibling_transpose_idx is not None and sibling_nhwc_name is not None:
                    direct_pre_plan = {
                        "input_name": str(add_input_name),
                        "transpose_idx": int(sibling_transpose_idx),
                        "nhwc_input_name": str(sibling_nhwc_name),
                    }

            if concat_plan is None or direct_pre_plan is None:
                continue

            chain_index_set = {
                int(concat_plan["pre_idx"]),
                int(add0_idx),
                int(mul_idx),
                int(add2_idx),
                int(prelu_idx),
                int(post_idx),
            }
            mul_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(v is None for v in [mul_side_for_op, add2_side_for_op, prelu_side_for_op]):
                continue

            new_add0_inputs: List[str] = []
            for add_input_name in ordered_inputs:
                if str(add_input_name) == str(concat_plan["input_name"]):
                    new_add0_inputs.append(str(concat_plan["nhwc_input_name"]))
                elif str(add_input_name) == str(direct_pre_plan["input_name"]):
                    new_add0_inputs.append(str(direct_pre_plan["nhwc_input_name"]))
                else:
                    new_add0_inputs.append(str(add_input_name))
            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(v) for v in new_add0_inputs],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(mul_side_input_index),
                new_input_name=str(mul_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_input_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu_op,
                input_index=1,
                new_input_name=str(prelu_side_for_op),
            )

            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(add0_name, None), perm_nchw_to_nhwc)
            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(mul_out_name, None), perm_nchw_to_nhwc)
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(add2_op.outputs[0]), None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(post_input_name, None), perm_nchw_to_nhwc)

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[str(post_output_name)],
            )

            old_prelu_tensor = model_ir.tensors.get(post_input_name, None)
            new_prelu_tensor = model_ir.tensors.get(post_output_name, None)
            if old_prelu_tensor is not None and new_prelu_tensor is not None:
                new_prelu_tensor.dtype = str(old_prelu_tensor.dtype)
                new_prelu_tensor.quantization = _clone_quantization(old_prelu_tensor.quantization)
                new_prelu_tensor.shape = [int(v) for v in list(old_prelu_tensor.shape)]
                new_prelu_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu_tensor.shape_signature)]
                    if old_prelu_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(new_prelu_tensor, perm_nchw_to_nhwc)

            keep_perm_name = str(post_op.inputs[1])
            keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
            if keep_perm_tensor is not None:
                keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
            _set_operator_inputs(
                model_ir=model_ir,
                op=post_op,
                new_inputs=[str(post_output_name), keep_perm_name],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=post_op,
                new_outputs=[str(post_input_name)],
            )

            del model_ir.operators[int(concat_plan["pre_idx"])]
            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_deep_skip_pre_add_concat_prelu_fanout_chains": int(optimized)}


def _optimize_sinet_deep_skip_dual_resize_affine_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize a SiNet deep-skip dual-resize tail:

      pre_nchw --T(0,2,3,1)--> pre_nhwc
      b0_nhwc --Resize--> T(0,3,1,2)--> MUL(const)->ADD(const)
      b1_nhwc --Resize--> T(0,3,1,2)--> MUL(const)->ADD(const)
      CONCAT(axis=1) -> ADD(pre_nchw, ...) -> MUL(const)->ADD(const)->PRELU -> T(0,2,3,1)

    Rewrite only the local residual core to NHWC and keep the upstream deep
    skip adapter untouched.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_input_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if post_output_name in model_outputs:
                continue

            post_users = [int(v) for v in consumers.get(post_output_name, [])]
            if len(post_users) == 0:
                continue

            prelu2_idx = producers.get(post_input_name, None)
            if prelu2_idx is None:
                continue
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.outputs[0]) != str(post_input_name)
            ):
                continue

            add2_idx = producers.get(str(prelu2_op.inputs[0]), None)
            if add2_idx is None:
                continue
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == add2_in1:
                continue

            mul2_idx = producers.get(add2_in0, None)
            if mul2_idx is None:
                mul2_idx = producers.get(add2_in1, None)
            if mul2_idx is None:
                continue
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name == add2_in0:
                add2_side_index = 1
                add2_side_name = str(add2_in1)
            elif mul2_out_name == add2_in1:
                add2_side_index = 0
                add2_side_name = str(add2_in0)
            else:
                continue

            add0_name: Optional[str] = None
            mul2_side_index: Optional[int] = None
            mul2_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mul2_op.inputs[int(data_idx)])
                cand_side = str(mul2_op.inputs[int(side_idx)])
                if str(cand_data) == str(mul2_out_name):
                    continue
                cand_prod_idx = producers.get(cand_data, None)
                if cand_prod_idx is None:
                    continue
                cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                if str(cand_prod_op.op_type) == "ADD":
                    add0_name = str(cand_data)
                    mul2_side_index = int(side_idx)
                    mul2_side_name = str(cand_side)
                    break
            if add0_name is None or mul2_side_index is None or mul2_side_name is None:
                continue

            add0_idx = producers.get(str(add0_name), None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if (
                str(add0_op.op_type) != "ADD"
                or len(add0_op.inputs) != 2
                or len(add0_op.outputs) != 1
                or str(add0_op.outputs[0]) != str(add0_name)
                or str(add0_name) in model_outputs
            ):
                continue

            pre_nchw_name: Optional[str] = None
            pre_nhwc_name: Optional[str] = None
            pre_adapter_idx: Optional[int] = None
            concat_idx: Optional[int] = None
            concat_name: Optional[str] = None
            for add0_input in [str(v) for v in list(add0_op.inputs)]:
                prod_idx = producers.get(str(add0_input), None)
                if prod_idx is not None:
                    prod_op = model_ir.operators[int(prod_idx)]
                    if (
                        str(prod_op.op_type) == "CONCATENATION"
                        and len(prod_op.inputs) == 2
                        and len(prod_op.outputs) == 1
                        and str(prod_op.outputs[0]) == str(add0_input)
                        and int(prod_op.options.get("axis", 1)) == 1
                        and set(int(v) for v in consumers.get(str(add0_input), [])) == {int(add0_idx)}
                        and str(add0_input) not in model_outputs
                    ):
                        concat_idx = int(prod_idx)
                        concat_name = str(add0_input)
                        continue
                pre_nchw_name = str(add0_input)

            if pre_nchw_name is None or concat_idx is None or concat_name is None:
                continue

            pre_users = set(int(v) for v in consumers.get(str(pre_nchw_name), []))
            if int(add0_idx) not in pre_users:
                continue
            for user_idx in sorted(list(pre_users)):
                if int(user_idx) == int(add0_idx):
                    continue
                user_op = model_ir.operators[int(user_idx)]
                if (
                    str(user_op.op_type) == "TRANSPOSE"
                    and len(user_op.inputs) >= 2
                    and len(user_op.outputs) == 1
                    and str(user_op.inputs[0]) == str(pre_nchw_name)
                    and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                    and str(user_op.outputs[0]) not in model_outputs
                ):
                    pre_adapter_idx = int(user_idx)
                    pre_nhwc_name = str(user_op.outputs[0])
                    break
            if pre_adapter_idx is None or pre_nhwc_name is None:
                continue

            concat_op = model_ir.operators[int(concat_idx)]
            branch_plans: List[Dict[str, Any]] = []

            def _match_resize_affine_branch(add_out_name: str) -> Optional[Dict[str, Any]]:
                add_idx = producers.get(str(add_out_name), None)
                if add_idx is None:
                    return None
                add_op = model_ir.operators[int(add_idx)]
                if (
                    str(add_op.op_type) != "ADD"
                    or len(add_op.inputs) != 2
                    or len(add_op.outputs) != 1
                    or str(add_op.outputs[0]) != str(add_out_name)
                    or set(int(v) for v in consumers.get(str(add_out_name), [])) != {int(concat_idx)}
                ):
                    return None

                add_in0 = str(add_op.inputs[0])
                add_in1 = str(add_op.inputs[1])
                mul_idx = producers.get(add_in0, None)
                if mul_idx is None:
                    mul_idx = producers.get(add_in1, None)
                if mul_idx is None:
                    return None
                mul_op = model_ir.operators[int(mul_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    return None
                mul_out_name = str(mul_op.outputs[0])
                if mul_out_name == add_in0:
                    add_side_index = 1
                    add_side_name = str(add_in1)
                elif mul_out_name == add_in1:
                    add_side_index = 0
                    add_side_name = str(add_in0)
                else:
                    return None

                trans_idx: Optional[int] = None
                trans_in_name: Optional[str] = None
                mul_data_index: Optional[int] = None
                mul_side_name: Optional[str] = None
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                for data_idx, side_idx in [(0, 1), (1, 0)]:
                    cand_data = str(mul_inputs[int(data_idx)])
                    cand_side = str(mul_inputs[int(side_idx)])
                    cand_trans_idx = producers.get(str(cand_data), None)
                    if cand_trans_idx is None:
                        continue
                    cand_trans_op = model_ir.operators[int(cand_trans_idx)]
                    if (
                        str(cand_trans_op.op_type) != "TRANSPOSE"
                        or len(cand_trans_op.inputs) < 2
                        or len(cand_trans_op.outputs) != 1
                        or str(cand_trans_op.outputs[0]) != str(cand_data)
                        or _read_transpose_perm(model_ir, cand_trans_op) != perm_nhwc_to_nchw
                        or set(int(v) for v in consumers.get(str(cand_data), [])) != {int(mul_idx)}
                        or str(cand_data) in model_outputs
                    ):
                        continue
                    resize_name = str(cand_trans_op.inputs[0])
                    resize_idx = producers.get(resize_name, None)
                    if resize_idx is None:
                        continue
                    resize_op = model_ir.operators[int(resize_idx)]
                    if (
                        str(resize_op.op_type) not in {"RESIZE_BILINEAR", "RESIZE_NEAREST_NEIGHBOR"}
                        or len(resize_op.outputs) != 1
                        or str(resize_op.outputs[0]) != str(resize_name)
                    ):
                        continue
                    trans_idx = int(cand_trans_idx)
                    trans_in_name = str(resize_name)
                    mul_data_index = int(data_idx)
                    mul_side_name = str(cand_side)
                    break

                if trans_idx is None or trans_in_name is None or mul_data_index is None or mul_side_name is None:
                    return None

                return {
                    "add_idx": int(add_idx),
                    "add_op": add_op,
                    "add_out_name": str(add_out_name),
                    "add_side_index": int(add_side_index),
                    "add_side_name": str(add_side_name),
                    "mul_idx": int(mul_idx),
                    "mul_op": mul_op,
                    "mul_out_name": str(mul_out_name),
                    "mul_data_index": int(mul_data_index),
                    "mul_side_name": str(mul_side_name),
                    "trans_idx": int(trans_idx),
                    "trans_in_name": str(trans_in_name),
                }

            valid_branches = True
            for concat_input_name in [str(v) for v in list(concat_op.inputs)]:
                plan = _match_resize_affine_branch(str(concat_input_name))
                if plan is None:
                    valid_branches = False
                    break
                branch_plans.append(plan)
            if not valid_branches or len(branch_plans) != 2:
                continue

            shape_candidates = [
                model_ir.tensors.get(str(pre_nhwc_name), None),
                model_ir.tensors.get(str(post_output_name), None),
            ]
            if any(
                t is None
                or not _is_fully_known_positive_shape(t.shape)
                or len(t.shape) != 4
                or int(t.shape[1]) != 40
                or int(t.shape[2]) != 40
                for t in shape_candidates
            ):
                continue

            chain_index_set = {
                int(concat_idx),
                int(add0_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                int(post_idx),
            }
            for plan in branch_plans:
                chain_index_set.add(int(plan["trans_idx"]))
                chain_index_set.add(int(plan["mul_idx"]))
                chain_index_set.add(int(plan["add_idx"]))

            branch_mul_side_names: List[str] = []
            branch_add_side_names: List[str] = []
            for plan in branch_plans:
                branch_mul_side = _ensure_channel_last_const(
                    tensor_name=str(plan["mul_side_name"]),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                branch_add_side = _ensure_channel_last_const(
                    tensor_name=str(plan["add_side_name"]),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if branch_mul_side is None or branch_add_side is None:
                    branch_mul_side_names = []
                    branch_add_side_names = []
                    break
                branch_mul_side_names.append(str(branch_mul_side))
                branch_add_side_names.append(str(branch_add_side))
            if len(branch_mul_side_names) != 2 or len(branch_add_side_names) != 2:
                continue

            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(v is None for v in [mul2_side_for_op, add2_side_for_op, prelu2_side_for_op]):
                continue

            for plan, branch_mul_side, branch_add_side in zip(
                branch_plans,
                branch_mul_side_names,
                branch_add_side_names,
            ):
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["mul_op"],
                    input_index=int(plan["mul_data_index"]),
                    new_input_name=str(plan["trans_in_name"]),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["mul_op"],
                    input_index=int(1 - int(plan["mul_data_index"])),
                    new_input_name=str(branch_mul_side),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["add_op"],
                    input_index=int(plan["add_side_index"]),
                    new_input_name=str(branch_add_side),
                )

            concat_op.options["axis"] = 3
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add0_op,
                input_index=0 if str(add0_op.inputs[0]) == str(pre_nchw_name) else 1,
                new_input_name=str(pre_nhwc_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post_output_name)],
            )
            for consumer_idx in [int(v) for v in consumers.get(str(post_input_name), [])]:
                if int(consumer_idx) == int(post_idx):
                    continue
                consumer_op = model_ir.operators[int(consumer_idx)]
                for input_index, input_name in enumerate(list(consumer_op.inputs)):
                    if str(input_name) == str(post_input_name):
                        _replace_operator_input_at(
                            model_ir=model_ir,
                            op=consumer_op,
                            input_index=int(input_index),
                            new_input_name=str(post_output_name),
                        )

            for plan in branch_plans:
                for t_name in [str(plan["mul_out_name"]), str(plan["add_out_name"])]:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(t_name), None),
                        perm_nchw_to_nhwc,
                    )
            for t_name in [
                str(concat_name),
                str(add0_name),
                str(mul2_out_name),
                str(add2_op.outputs[0]),
                str(post_output_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            old_prelu2_tensor = model_ir.tensors.get(str(post_input_name), None)
            post_tensor = model_ir.tensors.get(str(post_output_name), None)
            if old_prelu2_tensor is not None and post_tensor is not None:
                post_tensor.dtype = str(old_prelu2_tensor.dtype)
                post_tensor.quantization = _clone_quantization(old_prelu2_tensor.quantization)
                post_tensor.shape = [int(v) for v in list(old_prelu2_tensor.shape)]
                post_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu2_tensor.shape_signature)]
                    if old_prelu2_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu2_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(post_tensor, perm_nchw_to_nhwc)

            remove_indices = {int(post_idx), *[int(plan["trans_idx"]) for plan in branch_plans]}
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_deep_skip_dual_resize_affine_transpose_chains": int(optimized)}


def _optimize_sinet_shared_post_prelu_transpose_fanout_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize strict SiNet fanout tails where:
      pre0_nhwc --T(0,3,1,2)--> pre0_nchw
      pre1_nhwc --T(0,3,1,2)--> pre1_nchw   (exactly one is CONCAT(axis=3)-backed)
      ADD -> MUL(const) -> ADD(const) -> PRELU -> T(0,2,3,1)

    The transpose output is shared by NHWC consumers, so rewrite the whole
    block to NHWC and remove all three transpose adapters.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue
            post_input_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if post_output_name in model_outputs:
                continue

            prelu_idx = producers.get(post_input_name, None)
            if prelu_idx is None:
                continue
            prelu_op = model_ir.operators[int(prelu_idx)]
            if (
                str(prelu_op.op_type) != "PRELU"
                or len(prelu_op.inputs) != 2
                or len(prelu_op.outputs) != 1
                or str(prelu_op.outputs[0]) != str(post_input_name)
            ):
                continue

            prelu_users = [int(v) for v in consumers.get(str(post_input_name), [])]
            if set(prelu_users) != {int(post_idx)}:
                continue

            prelu_shape = model_ir.tensors.get(str(post_input_name), None)
            if (
                prelu_shape is None
                or not _is_fully_known_positive_shape(prelu_shape.shape)
                or len(prelu_shape.shape) != 4
                or int(prelu_shape.shape[2]) != 40
                or int(prelu_shape.shape[3]) != 40
            ):
                continue

            post_users = [int(v) for v in consumers.get(str(post_output_name), [])]
            if len(post_users) < 2:
                continue
            saw_conv = False
            saw_add = False
            valid_users = True
            for user_idx in post_users:
                user_op = model_ir.operators[int(user_idx)]
                user_type = str(user_op.op_type)
                if user_type in {"CONV_2D", "DEPTHWISE_CONV_2D"}:
                    if str(user_op.inputs[0]) != str(post_output_name):
                        valid_users = False
                        break
                    saw_conv = True
                elif user_type == "ADD":
                    saw_add = True
                else:
                    valid_users = False
                    break
            if not valid_users or not saw_conv or not saw_add:
                continue

            add2_idx = producers.get(str(prelu_op.inputs[0]), None)
            if add2_idx is None:
                continue
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])

            mul_idx = producers.get(add2_in0, None)
            if mul_idx is None:
                mul_idx = producers.get(add2_in1, None)
            if mul_idx is None:
                continue
            mul_op = model_ir.operators[int(mul_idx)]
            if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                continue
            mul_out_name = str(mul_op.outputs[0])
            if mul_out_name == add2_in0:
                add2_side_input_index = 1
                add2_side_name = add2_in1
            elif mul_out_name == add2_in1:
                add2_side_input_index = 0
                add2_side_name = add2_in0
            else:
                continue

            add0_name: Optional[str] = None
            mul_side_input_index: Optional[int] = None
            mul_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                candidate_data = str(mul_op.inputs[int(data_idx)])
                candidate_prod_idx = producers.get(candidate_data, None)
                if candidate_prod_idx is None:
                    continue
                candidate_prod_op = model_ir.operators[int(candidate_prod_idx)]
                if str(candidate_prod_op.op_type) != "ADD":
                    continue
                add0_name = candidate_data
                mul_side_input_index = int(side_idx)
                mul_side_name = str(mul_op.inputs[int(side_idx)])
                break
            if add0_name is None or mul_side_input_index is None or mul_side_name is None:
                continue

            add0_idx = producers.get(add0_name, None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue

            input_plans: List[Dict[str, Any]] = []
            concat_backed_inputs = 0
            for add_input_name in [str(v) for v in list(add0_op.inputs)]:
                pre_idx = producers.get(str(add_input_name), None)
                if pre_idx is None:
                    input_plans = []
                    break
                pre_op = model_ir.operators[int(pre_idx)]
                if (
                    str(pre_op.op_type) != "TRANSPOSE"
                    or len(pre_op.inputs) < 2
                    or len(pre_op.outputs) != 1
                    or str(pre_op.outputs[0]) != str(add_input_name)
                    or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
                    or str(add_input_name) in model_outputs
                ):
                    input_plans = []
                    break
                users = [int(v) for v in consumers.get(str(add_input_name), [])]
                if set(users) != {int(add0_idx)}:
                    input_plans = []
                    break
                nhwc_input_name = str(pre_op.inputs[0])
                nhwc_input_prod_idx = producers.get(nhwc_input_name, None)
                if nhwc_input_prod_idx is not None:
                    nhwc_input_prod = model_ir.operators[int(nhwc_input_prod_idx)]
                    if (
                        str(nhwc_input_prod.op_type) == "CONCATENATION"
                        and int(nhwc_input_prod.options.get("axis", -1)) == 3
                    ):
                        concat_backed_inputs += 1
                input_plans.append(
                    {
                        "pre_idx": int(pre_idx),
                        "nhwc_input_name": nhwc_input_name,
                    }
                )
            if len(input_plans) != 2 or concat_backed_inputs != 1:
                continue

            chain_index_set = {
                int(add0_idx),
                int(mul_idx),
                int(add2_idx),
                int(prelu_idx),
                int(post_idx),
            }
            chain_index_set.update(int(plan["pre_idx"]) for plan in input_plans)
            mul_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(v is None for v in [mul_side_for_op, add2_side_for_op, prelu_side_for_op]):
                continue

            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(plan["nhwc_input_name"]) for plan in input_plans],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul_op,
                input_index=int(mul_side_input_index),
                new_input_name=str(mul_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_input_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu_op,
                input_index=1,
                new_input_name=str(prelu_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu_op,
                new_outputs=[str(post_output_name)],
            )
            post_tensor = model_ir.tensors.get(str(post_output_name), None)
            if post_tensor is not None:
                post_tensor.dtype = str(prelu_shape.dtype)
                post_tensor.quantization = _clone_quantization(prelu_shape.quantization)
                post_tensor.shape = [int(v) for v in list(prelu_shape.shape)]
                post_tensor.shape_signature = (
                    [int(v) for v in list(prelu_shape.shape_signature)]
                    if prelu_shape.shape_signature is not None
                    else [int(v) for v in list(prelu_shape.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(post_tensor, perm_nchw_to_nhwc)

            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(add0_name), None), perm_nchw_to_nhwc)
            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(mul_out_name), None), perm_nchw_to_nhwc)
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(add2_op.outputs[0]), None),
                perm_nchw_to_nhwc,
            )

            remove_indices = {int(post_idx)}
            remove_indices.update(int(plan["pre_idx"]) for plan in input_plans)
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_shared_post_prelu_transpose_fanout_chains": int(optimized)}


def _optimize_sinet_concat_resize_affine_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize strict SiNet branch merge blocks with three NHWC->NCHW adapters:

      pre_nhwc --T(0,3,1,2)--> pre_nchw
      branch0_nhwc --T(0,3,1,2)--> b0_nchw
      resize_nhwc --T(0,3,1,2)--> rz_nchw --MUL(const)--ADD(const)--> b1_nchw
      CONCAT(axis=1, [b0_nchw, b1_nchw]) -> c_nchw
      ADD(pre_nchw, c_nchw) -> a_nchw --MUL(const)--ADD(const)--PRELU--> p_nchw
      p_nchw --T(0,2,3,1)--> p_nhwc

    Rewrite to NHWC core and remove the four transpose adapters.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue
            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue

            add0_idx = int(pre_users[0])
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue
            add0_inputs = [str(v) for v in list(add0_op.inputs)]
            if add0_inputs[0] == pre_output_name:
                concat_name = str(add0_inputs[1])
            elif add0_inputs[1] == pre_output_name:
                concat_name = str(add0_inputs[0])
            else:
                continue
            add0_out_name = str(add0_op.outputs[0])
            if add0_out_name in model_outputs:
                continue

            concat_idx = producers.get(concat_name, None)
            if concat_idx is None:
                continue
            concat_op = model_ir.operators[int(concat_idx)]
            if (
                str(concat_op.op_type) != "CONCATENATION"
                or len(concat_op.inputs) != 2
                or len(concat_op.outputs) != 1
                or str(concat_op.outputs[0]) != concat_name
                or int(concat_op.options.get("axis", 1)) != 1
            ):
                continue
            if set(int(v) for v in consumers.get(concat_name, [])) != {int(add0_idx)}:
                continue

            trans_a_idx: Optional[int] = None
            trans_a_in_name: Optional[str] = None
            trans_a_out_name: Optional[str] = None
            addb_idx: Optional[int] = None
            addb_out_name: Optional[str] = None
            for c_in in [str(v) for v in list(concat_op.inputs)]:
                c_prod_idx = producers.get(str(c_in), None)
                if c_prod_idx is None:
                    continue
                c_prod_op = model_ir.operators[int(c_prod_idx)]
                if (
                    str(c_prod_op.op_type) == "TRANSPOSE"
                    and len(c_prod_op.inputs) >= 2
                    and len(c_prod_op.outputs) == 1
                    and str(c_prod_op.outputs[0]) == str(c_in)
                    and _read_transpose_perm(model_ir, c_prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(c_in), [])) == {int(concat_idx)}
                    and str(c_in) not in model_outputs
                ):
                    trans_a_idx = int(c_prod_idx)
                    trans_a_in_name = str(c_prod_op.inputs[0])
                    trans_a_out_name = str(c_in)
                elif (
                    str(c_prod_op.op_type) == "ADD"
                    and len(c_prod_op.inputs) == 2
                    and len(c_prod_op.outputs) == 1
                    and str(c_prod_op.outputs[0]) == str(c_in)
                    and set(int(v) for v in consumers.get(str(c_in), [])) == {int(concat_idx)}
                    and str(c_in) not in model_outputs
                ):
                    addb_idx = int(c_prod_idx)
                    addb_out_name = str(c_in)
            if (
                trans_a_idx is None
                or trans_a_in_name is None
                or trans_a_out_name is None
                or addb_idx is None
                or addb_out_name is None
            ):
                continue

            addb_op = model_ir.operators[int(addb_idx)]
            addb_in0 = str(addb_op.inputs[0])
            addb_in1 = str(addb_op.inputs[1])
            mulb_idx = producers.get(addb_in0, None)
            if mulb_idx is None:
                mulb_idx = producers.get(addb_in1, None)
            if mulb_idx is None:
                continue
            mulb_op = model_ir.operators[int(mulb_idx)]
            if str(mulb_op.op_type) != "MUL" or len(mulb_op.inputs) != 2 or len(mulb_op.outputs) != 1:
                continue
            mulb_out_name = str(mulb_op.outputs[0])
            if mulb_out_name == addb_in0:
                addb_side_index = 1
                addb_side_name = str(addb_in1)
            elif mulb_out_name == addb_in1:
                addb_side_index = 0
                addb_side_name = str(addb_in0)
            else:
                continue

            mulb_inputs = [str(v) for v in list(mulb_op.inputs)]
            if mulb_inputs[0] == mulb_inputs[1]:
                continue
            trans_b_idx: Optional[int] = None
            trans_b_in_name: Optional[str] = None
            mulb_data_index: Optional[int] = None
            mulb_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                trans_idx = producers.get(str(mulb_inputs[int(data_idx)]), None)
                if trans_idx is None:
                    continue
                trans_op = model_ir.operators[int(trans_idx)]
                if (
                    str(trans_op.op_type) != "TRANSPOSE"
                    or len(trans_op.inputs) < 2
                    or len(trans_op.outputs) != 1
                    or str(trans_op.outputs[0]) != str(mulb_inputs[int(data_idx)])
                    or _read_transpose_perm(model_ir, trans_op) != perm_nhwc_to_nchw
                    or set(int(v) for v in consumers.get(str(mulb_inputs[int(data_idx)]), [])) != {int(mulb_idx)}
                    or str(mulb_inputs[int(data_idx)]) in model_outputs
                ):
                    continue
                trans_b_idx = int(trans_idx)
                trans_b_in_name = str(trans_op.inputs[0])
                mulb_data_index = int(data_idx)
                mulb_side_name = str(mulb_inputs[int(side_idx)])
                break
            if trans_b_idx is None or trans_b_in_name is None or mulb_data_index is None or mulb_side_name is None:
                continue

            add0_users = [int(v) for v in consumers.get(str(add0_out_name), [])]
            if len(add0_users) != 1:
                continue
            mul2_idx = int(add0_users[0])
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if mul2_in0 == add0_out_name:
                mul2_side_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 == add0_out_name:
                mul2_side_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name in model_outputs:
                continue

            mul2_users = [int(v) for v in consumers.get(str(mul2_out_name), [])]
            if len(mul2_users) != 1:
                continue
            add2_idx = int(mul2_users[0])
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == mul2_out_name:
                add2_side_index = 1
                add2_side_name = str(add2_in1)
            elif add2_in1 == mul2_out_name:
                add2_side_index = 0
                add2_side_name = str(add2_in0)
            else:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if add2_out_name in model_outputs:
                continue

            add2_users = [int(v) for v in consumers.get(str(add2_out_name), [])]
            if len(add2_users) != 1:
                continue
            prelu2_idx = int(add2_users[0])
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.inputs[0]) != str(add2_out_name)
            ):
                continue
            prelu2_out_name = str(prelu2_op.outputs[0])
            if prelu2_out_name in model_outputs:
                continue

            prelu2_users = [int(v) for v in consumers.get(str(prelu2_out_name), [])]
            if len(prelu2_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            for u_idx in prelu2_users:
                u_op = model_ir.operators[int(u_idx)]
                if (
                    str(u_op.op_type) == "TRANSPOSE"
                    and len(u_op.inputs) >= 2
                    and len(u_op.outputs) == 1
                    and str(u_op.inputs[0]) == str(prelu2_out_name)
                    and _read_transpose_perm(model_ir, u_op) == perm_nchw_to_nhwc
                    and str(u_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(u_idx))
                    post_output_names.append(str(u_op.outputs[0]))
                else:
                    legacy_users.append(int(u_idx))
            if len(post_indices) == 0:
                continue
            post_out_name = str(post_output_names[0])

            chain_index_set = {
                int(pre_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                int(addb_idx),
                int(mulb_idx),
                int(concat_idx),
                int(add0_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                *[int(v) for v in list(post_indices)],
            }
            mulb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mulb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            addb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(addb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(
                v is None
                for v in [
                    mulb_side_for_op,
                    addb_side_for_op,
                    mul2_side_for_op,
                    add2_side_for_op,
                    prelu2_side_for_op,
                ]
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(mulb_data_index),
                new_input_name=str(trans_b_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(1 - int(mulb_data_index)),
                new_input_name=str(mulb_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=addb_op,
                input_index=int(addb_side_index),
                new_input_name=str(addb_side_for_op),
            )

            new_concat_inputs = [
                str(trans_a_in_name) if str(v) == str(trans_a_out_name) else str(v)
                for v in list(concat_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat_op,
                new_inputs=[str(v) for v in new_concat_inputs],
            )
            concat_op.options["axis"] = 3

            new_add0_inputs = [str(v) for v in add0_inputs]
            if new_add0_inputs[0] == str(pre_output_name):
                new_add0_inputs[0] = str(pre_input_name)
            elif new_add0_inputs[1] == str(pre_output_name):
                new_add0_inputs[1] = str(pre_input_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(v) for v in new_add0_inputs],
            )

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post_out_name)],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, str(alias_name), str(post_out_name))

            for t_name in [
                str(mulb_out_name),
                str(addb_out_name),
                str(concat_name),
                str(add0_out_name),
                str(mul2_out_name),
                str(add2_out_name),
                str(post_out_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            old_prelu2_tensor = model_ir.tensors.get(str(prelu2_out_name), None)
            post_tensor = model_ir.tensors.get(str(post_out_name), None)
            if old_prelu2_tensor is not None and post_tensor is not None:
                post_tensor.dtype = str(old_prelu2_tensor.dtype)
                post_tensor.quantization = _clone_quantization(old_prelu2_tensor.quantization)
                post_tensor.shape = [int(v) for v in list(old_prelu2_tensor.shape)]
                post_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu2_tensor.shape_signature)]
                    if old_prelu2_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu2_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post_tensor,
                    perm_nchw_to_nhwc,
                )

            if len(legacy_users) > 0:
                # Preserve NCHW legacy fan-out from the rewritten NHWC output.
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(post_out_name), str(pre_op.inputs[1])],
                    outputs=[str(prelu2_out_name)],
                    options={},
                )
                op_index_by_id = {int(id(op)): int(op_idx) for op_idx, op in enumerate(model_ir.operators)}
                live_legacy_indices = [
                    int(op_index_by_id[int(id(model_ir.operators[int(v)]))])
                    for v in legacy_users
                    if int(v) < len(model_ir.operators)
                ]
                insert_index = int(min(live_legacy_indices)) if len(live_legacy_indices) > 0 else int(len(model_ir.operators))
                model_ir.operators.insert(int(insert_index), adapter_op)

            remove_indices = {
                int(pre_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                *[int(v) for v in list(post_indices)],
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_concat_resize_affine_transpose_chains": int(optimized)}


def _optimize_sinet_dual_resize_affine_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize strict SiNet branch-merge blocks where BOTH concat branches are:
      RESIZE -> TRANSPOSE(NHWC->NCHW) -> MUL(const) -> ADD(const)

    Target:
      pre_nhwc --T(0,3,1,2)--> pre_nchw
      b0_nhwc --Resize--> r0_nhwc --T(0,3,1,2)--> r0_nchw --MUL(c0)--ADD(c1)--> b0_nchw
      b1_nhwc --Resize--> r1_nhwc --T(0,3,1,2)--> r1_nchw --MUL(c2)--ADD(c3)--> b1_nchw
      CONCAT(axis=1, [b0_nchw, b1_nchw]) -> c_nchw
      ADD(pre_nchw, c_nchw) -> a_nchw --MUL(const)--ADD(const)--PRELU--> p_nchw
      p_nchw --T(0,2,3,1)--> p_nhwc

    Rewrite to NHWC core and remove the four transpose adapters.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if (
                str(pre_op.op_type) != "TRANSPOSE"
                or len(pre_op.inputs) < 2
                or len(pre_op.outputs) != 1
                or _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw
            ):
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue
            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) != 1:
                continue

            add0_idx = int(pre_users[0])
            add0_op = model_ir.operators[int(add0_idx)]
            if str(add0_op.op_type) != "ADD" or len(add0_op.inputs) != 2 or len(add0_op.outputs) != 1:
                continue
            add0_inputs = [str(v) for v in list(add0_op.inputs)]
            if add0_inputs[0] == pre_output_name:
                concat_name = str(add0_inputs[1])
            elif add0_inputs[1] == pre_output_name:
                concat_name = str(add0_inputs[0])
            else:
                continue
            add0_out_name = str(add0_op.outputs[0])
            if add0_out_name in model_outputs:
                continue

            concat_idx = producers.get(concat_name, None)
            if concat_idx is None:
                continue
            concat_op = model_ir.operators[int(concat_idx)]
            if (
                str(concat_op.op_type) != "CONCATENATION"
                or len(concat_op.inputs) != 2
                or len(concat_op.outputs) != 1
                or str(concat_op.outputs[0]) != concat_name
                or int(concat_op.options.get("axis", 1)) != 1
            ):
                continue
            if set(int(v) for v in consumers.get(concat_name, [])) != {int(add0_idx)}:
                continue

            branch_plans: List[Dict[str, Any]] = []

            def _match_resize_affine_branch(add_out_name: str) -> Optional[Dict[str, Any]]:
                add_idx = producers.get(str(add_out_name), None)
                if add_idx is None:
                    return None
                add_op = model_ir.operators[int(add_idx)]
                if (
                    str(add_op.op_type) != "ADD"
                    or len(add_op.inputs) != 2
                    or len(add_op.outputs) != 1
                    or str(add_op.outputs[0]) != str(add_out_name)
                ):
                    return None
                if set(int(v) for v in consumers.get(str(add_out_name), [])) != {int(concat_idx)}:
                    return None

                add_in0 = str(add_op.inputs[0])
                add_in1 = str(add_op.inputs[1])
                mul_idx = producers.get(add_in0, None)
                if mul_idx is None:
                    mul_idx = producers.get(add_in1, None)
                if mul_idx is None:
                    return None
                mul_op = model_ir.operators[int(mul_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    return None

                mul_out_name = str(mul_op.outputs[0])
                if mul_out_name == add_in0:
                    add_side_index = 1
                    add_side_name = str(add_in1)
                elif mul_out_name == add_in1:
                    add_side_index = 0
                    add_side_name = str(add_in0)
                else:
                    return None

                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                if mul_inputs[0] == mul_inputs[1]:
                    return None

                trans_idx: Optional[int] = None
                trans_in_name: Optional[str] = None
                mul_data_index: Optional[int] = None
                mul_side_name: Optional[str] = None

                for data_idx, side_idx in [(0, 1), (1, 0)]:
                    candidate_trans_idx = producers.get(str(mul_inputs[int(data_idx)]), None)
                    if candidate_trans_idx is None:
                        continue
                    candidate_trans_op = model_ir.operators[int(candidate_trans_idx)]
                    if (
                        str(candidate_trans_op.op_type) != "TRANSPOSE"
                        or len(candidate_trans_op.inputs) < 2
                        or len(candidate_trans_op.outputs) != 1
                        or str(candidate_trans_op.outputs[0]) != str(mul_inputs[int(data_idx)])
                        or _read_transpose_perm(model_ir, candidate_trans_op) != perm_nhwc_to_nchw
                        or set(int(v) for v in consumers.get(str(mul_inputs[int(data_idx)]), []))
                        != {int(mul_idx)}
                        or str(mul_inputs[int(data_idx)]) in model_outputs
                    ):
                        continue
                    candidate_resize_out_name = str(candidate_trans_op.inputs[0])
                    resize_idx = producers.get(candidate_resize_out_name, None)
                    if resize_idx is None:
                        continue
                    resize_op = model_ir.operators[int(resize_idx)]
                    if str(resize_op.op_type) not in {"RESIZE_BILINEAR", "RESIZE_NEAREST_NEIGHBOR"}:
                        continue
                    if len(resize_op.outputs) != 1 or str(resize_op.outputs[0]) != candidate_resize_out_name:
                        continue
                    trans_idx = int(candidate_trans_idx)
                    trans_in_name = candidate_resize_out_name
                    mul_data_index = int(data_idx)
                    mul_side_name = str(mul_inputs[int(side_idx)])
                    break

                if trans_idx is None or trans_in_name is None or mul_data_index is None or mul_side_name is None:
                    return None

                return {
                    "add_idx": int(add_idx),
                    "add_op": add_op,
                    "add_out_name": str(add_out_name),
                    "add_side_index": int(add_side_index),
                    "add_side_name": str(add_side_name),
                    "mul_idx": int(mul_idx),
                    "mul_op": mul_op,
                    "mul_out_name": str(mul_out_name),
                    "mul_data_index": int(mul_data_index),
                    "mul_side_name": str(mul_side_name),
                    "trans_idx": int(trans_idx),
                    "trans_in_name": str(trans_in_name),
                }

            valid_branches = True
            for concat_input_name in [str(v) for v in list(concat_op.inputs)]:
                plan = _match_resize_affine_branch(str(concat_input_name))
                if plan is None:
                    valid_branches = False
                    break
                branch_plans.append(plan)
            if not valid_branches or len(branch_plans) != 2:
                continue

            add0_users = [int(v) for v in consumers.get(str(add0_out_name), [])]
            if len(add0_users) != 1:
                continue
            mul2_idx = int(add0_users[0])
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if mul2_in0 == add0_out_name:
                mul2_side_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 == add0_out_name:
                mul2_side_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name in model_outputs:
                continue

            mul2_users = [int(v) for v in consumers.get(str(mul2_out_name), [])]
            if len(mul2_users) != 1:
                continue
            add2_idx = int(mul2_users[0])
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == mul2_out_name:
                add2_side_index = 1
                add2_side_name = str(add2_in1)
            elif add2_in1 == mul2_out_name:
                add2_side_index = 0
                add2_side_name = str(add2_in0)
            else:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if add2_out_name in model_outputs:
                continue

            add2_users = [int(v) for v in consumers.get(str(add2_out_name), [])]
            if len(add2_users) != 1:
                continue
            prelu2_idx = int(add2_users[0])
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.inputs[0]) != str(add2_out_name)
            ):
                continue
            prelu2_out_name = str(prelu2_op.outputs[0])
            if prelu2_out_name in model_outputs:
                continue

            prelu2_users = [int(v) for v in consumers.get(str(prelu2_out_name), [])]
            if len(prelu2_users) == 0:
                continue
            post_indices: List[int] = []
            post_output_names: List[str] = []
            legacy_users: List[int] = []
            for u_idx in prelu2_users:
                u_op = model_ir.operators[int(u_idx)]
                if (
                    str(u_op.op_type) == "TRANSPOSE"
                    and len(u_op.inputs) >= 2
                    and len(u_op.outputs) == 1
                    and str(u_op.inputs[0]) == str(prelu2_out_name)
                    and _read_transpose_perm(model_ir, u_op) == perm_nchw_to_nhwc
                    and str(u_op.outputs[0]) not in model_outputs
                ):
                    post_indices.append(int(u_idx))
                    post_output_names.append(str(u_op.outputs[0]))
                else:
                    legacy_users.append(int(u_idx))
            if len(post_indices) == 0:
                continue
            post_out_name = str(post_output_names[0])

            chain_index_set = {
                int(pre_idx),
                int(concat_idx),
                int(add0_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                *[int(v) for v in list(post_indices)],
            }
            for plan in branch_plans:
                chain_index_set.add(int(plan["trans_idx"]))
                chain_index_set.add(int(plan["mul_idx"]))
                chain_index_set.add(int(plan["add_idx"]))

            branch_mul_side_names: List[str] = []
            branch_add_side_names: List[str] = []
            for plan in branch_plans:
                branch_mul_side = _ensure_channel_last_const(
                    tensor_name=str(plan["mul_side_name"]),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                branch_add_side = _ensure_channel_last_const(
                    tensor_name=str(plan["add_side_name"]),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if branch_mul_side is None or branch_add_side is None:
                    branch_mul_side_names = []
                    branch_add_side_names = []
                    break
                branch_mul_side_names.append(str(branch_mul_side))
                branch_add_side_names.append(str(branch_add_side))
            if len(branch_mul_side_names) != 2 or len(branch_add_side_names) != 2:
                continue

            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(v is None for v in [mul2_side_for_op, add2_side_for_op, prelu2_side_for_op]):
                continue

            for plan, branch_mul_side, branch_add_side in zip(
                branch_plans,
                branch_mul_side_names,
                branch_add_side_names,
            ):
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["mul_op"],
                    input_index=int(plan["mul_data_index"]),
                    new_input_name=str(plan["trans_in_name"]),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["mul_op"],
                    input_index=int(1 - int(plan["mul_data_index"])),
                    new_input_name=str(branch_mul_side),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=plan["add_op"],
                    input_index=int(plan["add_side_index"]),
                    new_input_name=str(branch_add_side),
                )

            concat_op.options["axis"] = 3

            new_add0_inputs = [str(v) for v in add0_inputs]
            if new_add0_inputs[0] == str(pre_output_name):
                new_add0_inputs[0] = str(pre_input_name)
            elif new_add0_inputs[1] == str(pre_output_name):
                new_add0_inputs[1] = str(pre_input_name)
            _set_operator_inputs(
                model_ir=model_ir,
                op=add0_op,
                new_inputs=[str(v) for v in new_add0_inputs],
            )

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post_out_name)],
            )
            for alias_name in post_output_names[1:]:
                _replace_tensor_inputs(model_ir, str(alias_name), str(post_out_name))

            for plan in branch_plans:
                for t_name in [str(plan["mul_out_name"]), str(plan["add_out_name"])]:
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(t_name), None),
                        perm_nchw_to_nhwc,
                    )
            for t_name in [
                str(concat_name),
                str(add0_out_name),
                str(mul2_out_name),
                str(add2_out_name),
                str(post_out_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            old_prelu2_tensor = model_ir.tensors.get(str(prelu2_out_name), None)
            post_tensor = model_ir.tensors.get(str(post_out_name), None)
            if old_prelu2_tensor is not None and post_tensor is not None:
                post_tensor.dtype = str(old_prelu2_tensor.dtype)
                post_tensor.quantization = _clone_quantization(old_prelu2_tensor.quantization)
                post_tensor.shape = [int(v) for v in list(old_prelu2_tensor.shape)]
                post_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu2_tensor.shape_signature)]
                    if old_prelu2_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu2_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post_tensor,
                    perm_nchw_to_nhwc,
                )

            if len(legacy_users) > 0:
                adapter_op = OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[str(post_out_name), str(pre_op.inputs[1])],
                    outputs=[str(prelu2_out_name)],
                    options={},
                )
                op_index_by_id = {int(id(op)): int(op_idx) for op_idx, op in enumerate(model_ir.operators)}
                live_legacy_indices = [
                    int(op_index_by_id[int(id(model_ir.operators[int(v)]))])
                    for v in legacy_users
                    if int(v) < len(model_ir.operators)
                ]
                insert_index = int(min(live_legacy_indices)) if len(live_legacy_indices) > 0 else int(len(model_ir.operators))
                model_ir.operators.insert(int(insert_index), adapter_op)

            remove_indices = {
                int(pre_idx),
                *[int(v) for v in list(post_indices)],
                *[int(plan["trans_idx"]) for plan in branch_plans],
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_dual_resize_affine_transpose_chains": int(optimized)}


def _optimize_sinet_concat_resize_affine_tail_concat_transpose_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize a late SiNet residual variant:

      skip_nhwc --T(0,3,1,2)--> skip_nchw
      pre_nhwc --T(0,3,1,2)--> pre_nchw
      b0_nhwc --T(0,3,1,2)--> b0_nchw
      rz_nhwc --T(0,3,1,2)--> rz_nchw --MUL(const)--ADD(const)--> b1_nchw
      CONCAT(axis=1,[b0_nchw,b1_nchw]) -> c1_nchw
      ADD(pre_nchw,c1_nchw)->MUL(const)->ADD(const)->PRELU -> p1_nchw
      CONCAT(axis=1,[skip_nchw,p1_nchw]) -> c2_nchw
      c2_nchw -> MUL(const) -> ADD(const) -> PRELU -> T(0,2,3,1)

    Rewrite the whole block to NHWC and remove redundant transpose bridges.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_channel_last_const(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post2_idx, post2_op in enumerate(model_ir.operators):
            if (
                str(post2_op.op_type) != "TRANSPOSE"
                or len(post2_op.inputs) < 2
                or len(post2_op.outputs) != 1
                or _read_transpose_perm(model_ir, post2_op) != perm_nchw_to_nhwc
            ):
                continue
            post2_input_name = str(post2_op.inputs[0])
            post2_output_name = str(post2_op.outputs[0])
            if post2_output_name in model_outputs:
                continue

            prelu2_idx = producers.get(post2_input_name, None)
            if prelu2_idx is None:
                continue
            prelu2_op = model_ir.operators[int(prelu2_idx)]
            if (
                str(prelu2_op.op_type) != "PRELU"
                or len(prelu2_op.inputs) != 2
                or len(prelu2_op.outputs) != 1
                or str(prelu2_op.outputs[0]) != str(post2_input_name)
            ):
                continue

            add2_idx = producers.get(str(prelu2_op.inputs[0]), None)
            if add2_idx is None:
                continue
            add2_op = model_ir.operators[int(add2_idx)]
            if str(add2_op.op_type) != "ADD" or len(add2_op.inputs) != 2 or len(add2_op.outputs) != 1:
                continue
            add2_out_name = str(add2_op.outputs[0])
            if str(prelu2_op.inputs[0]) != str(add2_out_name):
                continue

            add2_in0 = str(add2_op.inputs[0])
            add2_in1 = str(add2_op.inputs[1])
            if add2_in0 == add2_in1:
                continue
            if add2_out_name in model_outputs:
                continue

            mul2_idx = producers.get(add2_in0, None)
            if mul2_idx is None:
                mul2_idx = producers.get(add2_in1, None)
            if mul2_idx is None:
                continue
            mul2_op = model_ir.operators[int(mul2_idx)]
            if str(mul2_op.op_type) != "MUL" or len(mul2_op.inputs) != 2 or len(mul2_op.outputs) != 1:
                continue
            mul2_out_name = str(mul2_op.outputs[0])
            if mul2_out_name == add2_in0:
                add2_side_index = 1
                add2_side_name = str(add2_in1)
            elif mul2_out_name == add2_in1:
                add2_side_index = 0
                add2_side_name = str(add2_in0)
            else:
                continue

            mul2_in0 = str(mul2_op.inputs[0])
            mul2_in1 = str(mul2_op.inputs[1])
            if mul2_in0 == mul2_in1:
                continue
            if mul2_out_name in model_outputs:
                continue

            if mul2_in0 in producers and str(model_ir.operators[int(producers[mul2_in0])].op_type) == "CONCATENATION":
                concat2_name = str(mul2_in0)
                mul2_side_index = 1
                mul2_side_name = str(mul2_in1)
            elif mul2_in1 in producers and str(model_ir.operators[int(producers[mul2_in1])].op_type) == "CONCATENATION":
                concat2_name = str(mul2_in1)
                mul2_side_index = 0
                mul2_side_name = str(mul2_in0)
            else:
                continue

            concat2_idx = producers.get(concat2_name, None)
            if concat2_idx is None:
                continue
            concat2_op = model_ir.operators[int(concat2_idx)]
            if (
                str(concat2_op.op_type) != "CONCATENATION"
                or len(concat2_op.inputs) != 2
                or len(concat2_op.outputs) != 1
                or str(concat2_op.outputs[0]) != str(concat2_name)
                or int(concat2_op.options.get("axis", 1)) != 1
            ):
                continue
            if set(int(v) for v in consumers.get(str(concat2_name), [])) != {int(mul2_idx)}:
                continue

            pre13_idx: Optional[int] = None
            pre13_in_name: Optional[str] = None
            pre13_out_name: Optional[str] = None
            prelu1_idx: Optional[int] = None
            prelu1_out_name: Optional[str] = None
            for c_in in [str(v) for v in list(concat2_op.inputs)]:
                prod_idx = producers.get(str(c_in), None)
                if prod_idx is None:
                    continue
                prod_op = model_ir.operators[int(prod_idx)]
                if (
                    str(prod_op.op_type) == "TRANSPOSE"
                    and len(prod_op.inputs) >= 2
                    and len(prod_op.outputs) == 1
                    and str(prod_op.outputs[0]) == str(c_in)
                    and _read_transpose_perm(model_ir, prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(c_in), [])) == {int(concat2_idx)}
                    and str(c_in) not in model_outputs
                ):
                    pre13_idx = int(prod_idx)
                    pre13_in_name = str(prod_op.inputs[0])
                    pre13_out_name = str(c_in)
                elif str(prod_op.op_type) == "PRELU":
                    prelu1_idx = int(prod_idx)
                    prelu1_out_name = str(c_in)
            if (
                pre13_idx is None
                or pre13_in_name is None
                or pre13_out_name is None
                or prelu1_idx is None
                or prelu1_out_name is None
            ):
                continue

            prelu1_op = model_ir.operators[int(prelu1_idx)]
            if (
                str(prelu1_op.op_type) != "PRELU"
                or len(prelu1_op.inputs) != 2
                or len(prelu1_op.outputs) != 1
                or str(prelu1_op.outputs[0]) != str(prelu1_out_name)
                or str(prelu1_out_name) in model_outputs
            ):
                continue
            # strict variant: prelu1 only feeds concat2
            if set(int(v) for v in consumers.get(str(prelu1_out_name), [])) != {int(concat2_idx)}:
                continue

            add1_idx = producers.get(str(prelu1_op.inputs[0]), None)
            if add1_idx is None:
                continue
            add1_op = model_ir.operators[int(add1_idx)]
            if str(add1_op.op_type) != "ADD" or len(add1_op.inputs) != 2 or len(add1_op.outputs) != 1:
                continue
            add1_out_name = str(add1_op.outputs[0])
            if str(prelu1_op.inputs[0]) != str(add1_out_name):
                continue
            add1_in0 = str(add1_op.inputs[0])
            add1_in1 = str(add1_op.inputs[1])

            mul1_idx = producers.get(add1_in0, None)
            if mul1_idx is None:
                mul1_idx = producers.get(add1_in1, None)
            if mul1_idx is None:
                continue
            mul1_op = model_ir.operators[int(mul1_idx)]
            if str(mul1_op.op_type) != "MUL" or len(mul1_op.inputs) != 2 or len(mul1_op.outputs) != 1:
                continue
            mul1_out_name = str(mul1_op.outputs[0])
            if mul1_out_name == add1_in0:
                add1_side_index = 1
                add1_side_name = str(add1_in1)
            elif mul1_out_name == add1_in1:
                add1_side_index = 0
                add1_side_name = str(add1_in0)
            else:
                continue

            add0_name: Optional[str] = None
            mul1_side_index: Optional[int] = None
            mul1_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mul1_op.inputs[int(data_idx)])
                cand_side = str(mul1_op.inputs[int(side_idx)])
                cand_prod_idx = producers.get(cand_data, None)
                if cand_prod_idx is None:
                    continue
                cand_prod_op = model_ir.operators[int(cand_prod_idx)]
                if str(cand_prod_op.op_type) == "ADD":
                    add0_name = str(cand_data)
                    mul1_side_index = int(side_idx)
                    mul1_side_name = str(cand_side)
                    break
            if add0_name is None or mul1_side_index is None or mul1_side_name is None:
                continue

            add0_idx = producers.get(str(add0_name), None)
            if add0_idx is None:
                continue
            add0_op = model_ir.operators[int(add0_idx)]
            if (
                str(add0_op.op_type) != "ADD"
                or len(add0_op.inputs) != 2
                or len(add0_op.outputs) != 1
                or str(add0_op.outputs[0]) != str(add0_name)
                or str(add0_name) in model_outputs
            ):
                continue

            # add0 inputs: pre transpose + concat(axis=1)
            pre_idx: Optional[int] = None
            pre_in_name: Optional[str] = None
            pre_out_name: Optional[str] = None
            concat1_idx: Optional[int] = None
            concat1_name: Optional[str] = None
            for a_in in [str(v) for v in list(add0_op.inputs)]:
                a_prod_idx = producers.get(str(a_in), None)
                if a_prod_idx is None:
                    continue
                a_prod_op = model_ir.operators[int(a_prod_idx)]
                if (
                    str(a_prod_op.op_type) == "TRANSPOSE"
                    and len(a_prod_op.inputs) >= 2
                    and len(a_prod_op.outputs) == 1
                    and str(a_prod_op.outputs[0]) == str(a_in)
                    and _read_transpose_perm(model_ir, a_prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(a_in), [])) == {int(add0_idx)}
                    and str(a_in) not in model_outputs
                ):
                    pre_idx = int(a_prod_idx)
                    pre_in_name = str(a_prod_op.inputs[0])
                    pre_out_name = str(a_in)
                elif (
                    str(a_prod_op.op_type) == "CONCATENATION"
                    and len(a_prod_op.inputs) == 2
                    and len(a_prod_op.outputs) == 1
                    and str(a_prod_op.outputs[0]) == str(a_in)
                    and int(a_prod_op.options.get("axis", 1)) == 1
                    and set(int(v) for v in consumers.get(str(a_in), [])) == {int(add0_idx)}
                    and str(a_in) not in model_outputs
                ):
                    concat1_idx = int(a_prod_idx)
                    concat1_name = str(a_in)
            if (
                pre_idx is None
                or pre_in_name is None
                or pre_out_name is None
                or concat1_idx is None
                or concat1_name is None
            ):
                continue

            concat1_op = model_ir.operators[int(concat1_idx)]
            trans_a_idx: Optional[int] = None
            trans_a_in_name: Optional[str] = None
            trans_a_out_name: Optional[str] = None
            addb_idx: Optional[int] = None
            addb_out_name: Optional[str] = None
            for c1_in in [str(v) for v in list(concat1_op.inputs)]:
                c1_prod_idx = producers.get(str(c1_in), None)
                if c1_prod_idx is None:
                    continue
                c1_prod_op = model_ir.operators[int(c1_prod_idx)]
                if (
                    str(c1_prod_op.op_type) == "TRANSPOSE"
                    and len(c1_prod_op.inputs) >= 2
                    and len(c1_prod_op.outputs) == 1
                    and str(c1_prod_op.outputs[0]) == str(c1_in)
                    and _read_transpose_perm(model_ir, c1_prod_op) == perm_nhwc_to_nchw
                    and set(int(v) for v in consumers.get(str(c1_in), [])) == {int(concat1_idx)}
                    and str(c1_in) not in model_outputs
                ):
                    trans_a_idx = int(c1_prod_idx)
                    trans_a_in_name = str(c1_prod_op.inputs[0])
                    trans_a_out_name = str(c1_in)
                elif (
                    str(c1_prod_op.op_type) == "ADD"
                    and len(c1_prod_op.inputs) == 2
                    and len(c1_prod_op.outputs) == 1
                    and str(c1_prod_op.outputs[0]) == str(c1_in)
                    and set(int(v) for v in consumers.get(str(c1_in), [])) == {int(concat1_idx)}
                    and str(c1_in) not in model_outputs
                ):
                    addb_idx = int(c1_prod_idx)
                    addb_out_name = str(c1_in)
            if (
                trans_a_idx is None
                or trans_a_in_name is None
                or trans_a_out_name is None
                or addb_idx is None
                or addb_out_name is None
            ):
                continue

            addb_op = model_ir.operators[int(addb_idx)]
            addb_in0 = str(addb_op.inputs[0])
            addb_in1 = str(addb_op.inputs[1])
            mulb_idx = producers.get(addb_in0, None)
            if mulb_idx is None:
                mulb_idx = producers.get(addb_in1, None)
            if mulb_idx is None:
                continue
            mulb_op = model_ir.operators[int(mulb_idx)]
            if str(mulb_op.op_type) != "MUL" or len(mulb_op.inputs) != 2 or len(mulb_op.outputs) != 1:
                continue
            mulb_out_name = str(mulb_op.outputs[0])
            if mulb_out_name == addb_in0:
                addb_side_index = 1
                addb_side_name = str(addb_in1)
            elif mulb_out_name == addb_in1:
                addb_side_index = 0
                addb_side_name = str(addb_in0)
            else:
                continue

            trans_b_idx: Optional[int] = None
            trans_b_in_name: Optional[str] = None
            trans_b_out_name: Optional[str] = None
            mulb_side_index: Optional[int] = None
            mulb_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(mulb_op.inputs[int(data_idx)])
                cand_side = str(mulb_op.inputs[int(side_idx)])
                t_idx = producers.get(str(cand_data), None)
                if t_idx is None:
                    continue
                t_op = model_ir.operators[int(t_idx)]
                if (
                    str(t_op.op_type) != "TRANSPOSE"
                    or len(t_op.inputs) < 2
                    or len(t_op.outputs) != 1
                    or str(t_op.outputs[0]) != str(cand_data)
                    or _read_transpose_perm(model_ir, t_op) != perm_nhwc_to_nchw
                    or set(int(v) for v in consumers.get(str(cand_data), [])) != {int(mulb_idx)}
                    or str(cand_data) in model_outputs
                ):
                    continue
                rz_name = str(t_op.inputs[0])
                rz_idx = producers.get(rz_name, None)
                if rz_idx is None:
                    continue
                rz_op = model_ir.operators[int(rz_idx)]
                if str(rz_op.op_type) not in {"RESIZE_BILINEAR", "RESIZE_NEAREST_NEIGHBOR"}:
                    continue
                if len(rz_op.outputs) != 1 or str(rz_op.outputs[0]) != rz_name:
                    continue
                trans_b_idx = int(t_idx)
                trans_b_in_name = str(rz_name)
                trans_b_out_name = str(cand_data)
                mulb_side_index = int(side_idx)
                mulb_side_name = str(cand_side)
                break
            if (
                trans_b_idx is None
                or trans_b_in_name is None
                or trans_b_out_name is None
                or mulb_side_index is None
                or mulb_side_name is None
            ):
                continue

            chain_index_set = {
                int(pre13_idx),
                int(pre_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                int(concat1_idx),
                int(addb_idx),
                int(mulb_idx),
                int(add0_idx),
                int(mul1_idx),
                int(add1_idx),
                int(prelu1_idx),
                int(concat2_idx),
                int(mul2_idx),
                int(add2_idx),
                int(prelu2_idx),
                int(post2_idx),
            }
            mulb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mulb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            addb_side_for_op = _ensure_channel_last_const(
                tensor_name=str(addb_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add1_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu1_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu1_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            mul2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(mul2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            add2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(add2_side_name),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            prelu2_side_for_op = _ensure_channel_last_const(
                tensor_name=str(prelu2_op.inputs[1]),
                chain_index_set=chain_index_set,
                consumers=consumers,
            )
            if any(
                v is None
                for v in [
                    mulb_side_for_op,
                    addb_side_for_op,
                    mul1_side_for_op,
                    add1_side_for_op,
                    prelu1_side_for_op,
                    mul2_side_for_op,
                    add2_side_for_op,
                    prelu2_side_for_op,
                ]
            ):
                continue

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(1 - int(mulb_side_index)),
                new_input_name=str(trans_b_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mulb_op,
                input_index=int(mulb_side_index),
                new_input_name=str(mulb_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=addb_op,
                input_index=int(addb_side_index),
                new_input_name=str(addb_side_for_op),
            )

            new_concat1_inputs = [
                str(trans_a_in_name) if str(v) == str(trans_a_out_name) else str(v)
                for v in list(concat1_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat1_op,
                new_inputs=[str(v) for v in new_concat1_inputs],
            )
            concat1_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=add0_op,
                input_index=0 if str(add0_op.inputs[0]) == str(pre_out_name) else 1,
                new_input_name=str(pre_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul1_op,
                input_index=int(mul1_side_index),
                new_input_name=str(mul1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add1_op,
                input_index=int(add1_side_index),
                new_input_name=str(add1_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu1_op,
                input_index=1,
                new_input_name=str(prelu1_side_for_op),
            )

            new_concat2_inputs = [
                str(pre13_in_name) if str(v) == str(pre13_out_name) else str(v)
                for v in list(concat2_op.inputs)
            ]
            _set_operator_inputs(
                model_ir=model_ir,
                op=concat2_op,
                new_inputs=[str(v) for v in new_concat2_inputs],
            )
            concat2_op.options["axis"] = 3

            _replace_operator_input_at(
                model_ir=model_ir,
                op=mul2_op,
                input_index=int(mul2_side_index),
                new_input_name=str(mul2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=add2_op,
                input_index=int(add2_side_index),
                new_input_name=str(add2_side_for_op),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=prelu2_op,
                input_index=1,
                new_input_name=str(prelu2_side_for_op),
            )

            for t_name in [
                str(mulb_out_name),
                str(addb_out_name),
                str(concat1_name),
                str(add0_name),
                str(mul1_out_name),
                str(add1_out_name),
                str(prelu1_out_name),
                str(concat2_name),
                str(mul2_out_name),
                str(add2_out_name),
                str(post2_output_name),
            ]:
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(str(t_name), None),
                    perm_nchw_to_nhwc,
                )

            _set_operator_outputs(
                model_ir=model_ir,
                op=prelu2_op,
                new_outputs=[str(post2_output_name)],
            )
            old_prelu2_tensor = model_ir.tensors.get(str(post2_input_name), None)
            post2_tensor = model_ir.tensors.get(str(post2_output_name), None)
            if old_prelu2_tensor is not None and post2_tensor is not None:
                post2_tensor.dtype = str(old_prelu2_tensor.dtype)
                post2_tensor.quantization = _clone_quantization(old_prelu2_tensor.quantization)
                post2_tensor.shape = [int(v) for v in list(old_prelu2_tensor.shape)]
                post2_tensor.shape_signature = (
                    [int(v) for v in list(old_prelu2_tensor.shape_signature)]
                    if old_prelu2_tensor.shape_signature is not None
                    else [int(v) for v in list(old_prelu2_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    post2_tensor,
                    perm_nchw_to_nhwc,
                )

            remove_indices = {
                int(pre13_idx),
                int(pre_idx),
                int(trans_a_idx),
                int(trans_b_idx),
                int(post2_idx),
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_concat_resize_affine_tail_concat_transpose_chains": int(optimized)}


def _optimize_sinet_softmax_mask_residual_nhwc_tail_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Optimize late SiNet tail blocks where NCHW adapters remain around
    Softmax+mask residual composition.

    Target sketch:
      side_nhwc --T(0,3,1,2)--> side_nchw --PRELU--> side_prelu_nchw
      main_nhwc --T(0,3,1,2)--> main_nchw --MUL(const)--ADD(const)--> bn_nchw
      bn_nchw --T(0,3,2,1)--> s_in --SOFTMAX--> s_out --T(0,3,2,1)--> soft_nchw
      REDUCE_MAX(axis=1)->SUB->RESHAPE([N,1,H,W])->MUL(ones)
      MUL(side_prelu_nchw, mask_nchw) + bn_nchw -> sum_nchw --T(0,2,3,1)--> sum_nhwc

    Rewrite:
      - keep side/main branches in NHWC
      - remove the three NCHW bridge transposes plus terminal pre-resize transpose
      - run SOFTMAX directly on NHWC tensor and remap reduce axis/reshape/consts
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nchw_to_nwhc = [0, 3, 2, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _set_const_int_data(
        *,
        tensor_name: str,
        new_values: List[int],
        target_consumer_idx: int,
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        users = [int(v) for v in consumers.get(str(tensor_name), [])]
        new_data = np.asarray([int(v) for v in list(new_values)], dtype=np.int32)
        if len(users) == 1 and int(users[0]) == int(target_consumer_idx):
            tensor.data = new_data
            tensor.dtype = "INT32"
            tensor.shape = [int(len(new_values))]
            tensor.shape_signature = [int(len(new_values))]
            return str(tensor_name)

        cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
        model_ir.tensors[cloned_name] = TensorIR(
            name=cloned_name,
            dtype="INT32",
            shape=[int(len(new_values))],
            shape_signature=[int(len(new_values))],
            data=new_data,
            is_variable=False,
            quantization=None,
        )
        return str(cloned_name)

    def _ensure_const_matches_target_nhwc(
        *,
        tensor_name: str,
        target_shape: Optional[List[int]],
        target_consumer_idx: int,
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None

        shape = [int(v) for v in list(data.shape)]
        nhwc_data: Optional[np.ndarray] = None
        if _is_fully_known_positive_shape(target_shape):
            target = [int(v) for v in list(target_shape)]
            if _broadcast_static_shapes(target, shape) is not None:
                nhwc_data = np.asarray(data)
            else:
                rotated = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target, rotated_shape) is None:
                    return None
                nhwc_data = np.asarray(rotated)
        else:
            # Unknown target: preserve idempotence and only rotate strict NCHW-per-channel constants.
            if (
                int(shape[0]) == 1
                and int(shape[1]) > 0
                and int(shape[2]) == 1
                and int(shape[3]) == 1
            ):
                nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
            elif (
                int(shape[0]) == 1
                and int(shape[1]) == 1
                and int(shape[2]) == 1
                and int(shape[3]) > 0
            ):
                nhwc_data = np.asarray(data)
            else:
                return None

        users = [int(v) for v in consumers.get(str(tensor_name), [])]
        if len(users) == 1 and int(users[0]) == int(target_consumer_idx):
            tensor.data = np.asarray(nhwc_data)
            tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
            return str(tensor_name)

        cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
        model_ir.tensors[cloned_name] = TensorIR(
            name=cloned_name,
            dtype=str(tensor.dtype),
            shape=[int(v) for v in list(nhwc_data.shape)],
            shape_signature=[int(v) for v in list(nhwc_data.shape)],
            data=np.asarray(nhwc_data),
            is_variable=False,
            quantization=_clone_quantization(tensor.quantization),
        )
        return str(cloned_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if (
                str(post_op.op_type) != "TRANSPOSE"
                or len(post_op.inputs) < 2
                or len(post_op.outputs) != 1
                or _read_transpose_perm(model_ir, post_op) != perm_nchw_to_nhwc
            ):
                continue

            post_in = str(post_op.inputs[0])
            post_out = str(post_op.outputs[0])
            if post_out in model_outputs:
                continue

            add_res_idx = producers.get(str(post_in), None)
            if add_res_idx is None:
                continue
            add_res_op = model_ir.operators[int(add_res_idx)]
            if (
                str(add_res_op.op_type) != "ADD"
                or len(add_res_op.inputs) != 2
                or len(add_res_op.outputs) != 1
                or str(add_res_op.outputs[0]) != str(post_in)
            ):
                continue

            # Parse add_res inputs:
            #   - main_nchw (ADD from BN affine)
            #   - side_mask_nchw (MUL from side-prelu and mask)
            add_res_inputs = [str(v) for v in list(add_res_op.inputs)]
            main_name: Optional[str] = None
            side_mask_name: Optional[str] = None
            main_add_idx: Optional[int] = None
            side_mask_idx: Optional[int] = None
            for inp in add_res_inputs:
                inp_prod_idx = producers.get(str(inp), None)
                if inp_prod_idx is None:
                    continue
                inp_prod_op = model_ir.operators[int(inp_prod_idx)]
                if str(inp_prod_op.op_type) == "ADD":
                    # Candidate: BN affine result
                    a_in0 = str(inp_prod_op.inputs[0])
                    a_in1 = str(inp_prod_op.inputs[1])
                    m_idx = producers.get(a_in0, None)
                    if m_idx is None:
                        m_idx = producers.get(a_in1, None)
                    if m_idx is None:
                        continue
                    m_op = model_ir.operators[int(m_idx)]
                    if str(m_op.op_type) != "MUL" or len(m_op.inputs) != 2:
                        continue
                    if str(m_op.outputs[0]) not in {a_in0, a_in1}:
                        continue
                    main_name = str(inp)
                    main_add_idx = int(inp_prod_idx)
                elif str(inp_prod_op.op_type) == "MUL":
                    side_mask_name = str(inp)
                    side_mask_idx = int(inp_prod_idx)
            if (
                main_name is None
                or side_mask_name is None
                or main_add_idx is None
                or side_mask_idx is None
            ):
                continue

            main_add_op = model_ir.operators[int(main_add_idx)]
            main_add_in0 = str(main_add_op.inputs[0])
            main_add_in1 = str(main_add_op.inputs[1])
            main_mul_idx = producers.get(main_add_in0, None)
            if main_mul_idx is None:
                main_mul_idx = producers.get(main_add_in1, None)
            if main_mul_idx is None:
                continue
            main_mul_op = model_ir.operators[int(main_mul_idx)]
            if str(main_mul_op.op_type) != "MUL" or len(main_mul_op.inputs) != 2:
                continue
            if str(main_mul_op.outputs[0]) == str(main_add_in0):
                main_add_side_idx = 1
                main_add_side_name = str(main_add_in1)
            elif str(main_mul_op.outputs[0]) == str(main_add_in1):
                main_add_side_idx = 0
                main_add_side_name = str(main_add_in0)
            else:
                continue

            main_pre_idx: Optional[int] = None
            main_pre_in_name: Optional[str] = None
            main_pre_out_name: Optional[str] = None
            main_mul_side_idx: Optional[int] = None
            main_mul_side_name: Optional[str] = None
            for data_idx, side_idx in [(0, 1), (1, 0)]:
                cand_data = str(main_mul_op.inputs[int(data_idx)])
                cand_side = str(main_mul_op.inputs[int(side_idx)])
                cand_pre_idx = producers.get(str(cand_data), None)
                if cand_pre_idx is None:
                    continue
                cand_pre_op = model_ir.operators[int(cand_pre_idx)]
                if (
                    str(cand_pre_op.op_type) != "TRANSPOSE"
                    or len(cand_pre_op.inputs) < 2
                    or len(cand_pre_op.outputs) != 1
                    or str(cand_pre_op.outputs[0]) != str(cand_data)
                    or _read_transpose_perm(model_ir, cand_pre_op) != perm_nhwc_to_nchw
                    or set(int(v) for v in consumers.get(str(cand_data), [])) != {int(main_mul_idx)}
                    or str(cand_data) in model_outputs
                ):
                    continue
                main_pre_idx = int(cand_pre_idx)
                main_pre_in_name = str(cand_pre_op.inputs[0])
                main_pre_out_name = str(cand_data)
                main_mul_side_idx = int(side_idx)
                main_mul_side_name = str(cand_side)
                break
            if (
                main_pre_idx is None
                or main_pre_in_name is None
                or main_pre_out_name is None
                or main_mul_side_idx is None
                or main_mul_side_name is None
            ):
                continue

            # Softmax chain on main_name.
            main_users = set(int(v) for v in consumers.get(str(main_name), []))
            if int(add_res_idx) not in main_users or len(main_users) != 2:
                continue
            soft_pre_idx = next((int(v) for v in main_users if int(v) != int(add_res_idx)), None)
            if soft_pre_idx is None:
                continue
            soft_pre_op = model_ir.operators[int(soft_pre_idx)]
            if (
                str(soft_pre_op.op_type) != "TRANSPOSE"
                or len(soft_pre_op.inputs) < 2
                or len(soft_pre_op.outputs) != 1
                or str(soft_pre_op.inputs[0]) != str(main_name)
                or _read_transpose_perm(model_ir, soft_pre_op) != perm_nchw_to_nwhc
            ):
                continue
            soft_pre_out = str(soft_pre_op.outputs[0])
            softmax_idx = consumers.get(str(soft_pre_out), [])
            if len(softmax_idx) != 1:
                continue
            softmax_idx = int(softmax_idx[0])
            softmax_op = model_ir.operators[int(softmax_idx)]
            if (
                str(softmax_op.op_type) != "SOFTMAX"
                or len(softmax_op.inputs) != 1
                or len(softmax_op.outputs) != 1
                or str(softmax_op.inputs[0]) != str(soft_pre_out)
            ):
                continue
            softmax_out = str(softmax_op.outputs[0])
            soft_post_users = [int(v) for v in consumers.get(str(softmax_out), [])]
            if len(soft_post_users) != 1:
                continue
            soft_post_idx = int(soft_post_users[0])
            soft_post_op = model_ir.operators[int(soft_post_idx)]
            if (
                str(soft_post_op.op_type) != "TRANSPOSE"
                or len(soft_post_op.inputs) < 2
                or len(soft_post_op.outputs) != 1
                or str(soft_post_op.inputs[0]) != str(softmax_out)
                or _read_transpose_perm(model_ir, soft_post_op) != perm_nchw_to_nwhc
            ):
                continue
            soft_back_name = str(soft_post_op.outputs[0])

            reduce_users = [int(v) for v in consumers.get(str(soft_back_name), [])]
            if len(reduce_users) != 1:
                continue
            reduce_idx = int(reduce_users[0])
            reduce_op = model_ir.operators[int(reduce_idx)]
            if (
                str(reduce_op.op_type) != "REDUCE_MAX"
                or len(reduce_op.inputs) < 2
                or len(reduce_op.outputs) != 1
                or str(reduce_op.inputs[0]) != str(soft_back_name)
                or bool(reduce_op.options.get("keepDims", False))
            ):
                continue
            reduce_axis_name = str(reduce_op.inputs[1])
            reduce_axis_tensor = model_ir.tensors.get(str(reduce_axis_name), None)
            reduce_axis_vals = _read_const_ints_from_tensor(reduce_axis_tensor)
            if reduce_axis_vals is None or list(reduce_axis_vals) != [1]:
                continue
            reduce_out = str(reduce_op.outputs[0])

            sub_users = [int(v) for v in consumers.get(str(reduce_out), [])]
            if len(sub_users) != 1:
                continue
            sub_idx = int(sub_users[0])
            sub_op = model_ir.operators[int(sub_idx)]
            if str(sub_op.op_type) != "SUB" or len(sub_op.inputs) != 2 or len(sub_op.outputs) != 1:
                continue
            sub_in0 = str(sub_op.inputs[0])
            sub_in1 = str(sub_op.inputs[1])
            if sub_in1 == str(reduce_out):
                if not _is_singleton_constant_tensor(model_ir, sub_in0):
                    continue
            elif sub_in0 == str(reduce_out):
                if not _is_singleton_constant_tensor(model_ir, sub_in1):
                    continue
            else:
                continue
            sub_out = str(sub_op.outputs[0])

            reshape_users = [int(v) for v in consumers.get(str(sub_out), [])]
            if len(reshape_users) != 1:
                continue
            reshape_idx = int(reshape_users[0])
            reshape_op = model_ir.operators[int(reshape_idx)]
            if (
                str(reshape_op.op_type) != "RESHAPE"
                or len(reshape_op.inputs) < 2
                or len(reshape_op.outputs) != 1
                or str(reshape_op.inputs[0]) != str(sub_out)
            ):
                continue
            reshape_shape_name = str(reshape_op.inputs[1])
            reshape_shape_tensor = model_ir.tensors.get(str(reshape_shape_name), None)
            reshape_vals = _read_const_ints_from_tensor(reshape_shape_tensor)
            if reshape_vals is None or len(reshape_vals) != 4:
                continue
            if int(reshape_vals[0]) != 1 or int(reshape_vals[1]) != 1:
                continue
            reshape_out = str(reshape_op.outputs[0])

            expand_users = [int(v) for v in consumers.get(str(reshape_out), [])]
            if len(expand_users) != 1:
                continue
            expand_idx = int(expand_users[0])
            expand_op = model_ir.operators[int(expand_idx)]
            if str(expand_op.op_type) != "MUL" or len(expand_op.inputs) != 2 or len(expand_op.outputs) != 1:
                continue
            expand_in0 = str(expand_op.inputs[0])
            expand_in1 = str(expand_op.inputs[1])
            if expand_in0 == str(reshape_out):
                expand_const_idx = 1
                expand_const_name = str(expand_in1)
            elif expand_in1 == str(reshape_out):
                expand_const_idx = 0
                expand_const_name = str(expand_in0)
            else:
                continue
            expand_const_tensor = model_ir.tensors.get(str(expand_const_name), None)
            if expand_const_tensor is None or expand_const_tensor.data is None:
                continue
            expand_out = str(expand_op.outputs[0])

            side_mask_op = model_ir.operators[int(side_mask_idx)]
            side_mask_in0 = str(side_mask_op.inputs[0])
            side_mask_in1 = str(side_mask_op.inputs[1])
            if side_mask_in0 == str(expand_out):
                side_tensor_name = str(side_mask_in1)
            elif side_mask_in1 == str(expand_out):
                side_tensor_name = str(side_mask_in0)
            else:
                continue

            side_prelu_idx = producers.get(str(side_tensor_name), None)
            if side_prelu_idx is None:
                continue
            side_prelu_op = model_ir.operators[int(side_prelu_idx)]
            if (
                str(side_prelu_op.op_type) != "PRELU"
                or len(side_prelu_op.inputs) != 2
                or len(side_prelu_op.outputs) != 1
                or str(side_prelu_op.outputs[0]) != str(side_tensor_name)
            ):
                continue
            side_pre_in = str(side_prelu_op.inputs[0])
            side_pre_idx = producers.get(str(side_pre_in), None)
            if side_pre_idx is None:
                continue
            side_pre_op = model_ir.operators[int(side_pre_idx)]
            if (
                str(side_pre_op.op_type) != "TRANSPOSE"
                or len(side_pre_op.inputs) < 2
                or len(side_pre_op.outputs) != 1
                or str(side_pre_op.outputs[0]) != str(side_pre_in)
                or _read_transpose_perm(model_ir, side_pre_op) != perm_nhwc_to_nchw
                or set(int(v) for v in consumers.get(str(side_pre_in), [])) != {int(side_prelu_idx)}
                or str(side_pre_in) in model_outputs
            ):
                continue
            side_pre_in_name = str(side_pre_op.inputs[0])

            # Locality and output guards.
            if any(
                name in model_outputs
                for name in [
                    str(main_name),
                    str(side_tensor_name),
                    str(soft_pre_out),
                    str(softmax_out),
                    str(soft_back_name),
                    str(post_in),
                ]
            ):
                continue

            main_nhwc_shape = (
                list(model_ir.tensors[str(main_pre_in_name)].shape)
                if str(main_pre_in_name) in model_ir.tensors
                else None
            )
            side_nhwc_shape = (
                list(model_ir.tensors[str(side_pre_in_name)].shape)
                if str(side_pre_in_name) in model_ir.tensors
                else None
            )

            main_mul_const = _ensure_const_matches_target_nhwc(
                tensor_name=str(main_mul_side_name),
                target_shape=main_nhwc_shape,
                target_consumer_idx=int(main_mul_idx),
                consumers=consumers,
            )
            main_add_const = _ensure_const_matches_target_nhwc(
                tensor_name=str(main_add_side_name),
                target_shape=main_nhwc_shape,
                target_consumer_idx=int(main_add_idx),
                consumers=consumers,
            )
            side_prelu_const = _ensure_const_matches_target_nhwc(
                tensor_name=str(side_prelu_op.inputs[1]),
                target_shape=side_nhwc_shape,
                target_consumer_idx=int(side_prelu_idx),
                consumers=consumers,
            )
            expand_const_nhwc = _ensure_const_matches_target_nhwc(
                tensor_name=str(expand_const_name),
                target_shape=side_nhwc_shape,
                target_consumer_idx=int(expand_idx),
                consumers=consumers,
            )
            if any(v is None for v in [main_mul_const, main_add_const, side_prelu_const, expand_const_nhwc]):
                continue

            new_reduce_axis_name = _set_const_int_data(
                tensor_name=str(reduce_axis_name),
                new_values=[3],
                target_consumer_idx=int(reduce_idx),
                consumers=consumers,
            )
            if new_reduce_axis_name is None:
                continue
            new_reshape_shape_name = _set_const_int_data(
                tensor_name=str(reshape_shape_name),
                new_values=[int(reshape_vals[0]), int(reshape_vals[2]), int(reshape_vals[3]), int(reshape_vals[1])],
                target_consumer_idx=int(reshape_idx),
                consumers=consumers,
            )
            if new_reshape_shape_name is None:
                continue

            # Rewrite side branch to NHWC.
            _set_operator_inputs(
                model_ir=model_ir,
                op=side_prelu_op,
                new_inputs=[str(side_pre_in_name), str(side_prelu_const)],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(side_tensor_name), None),
                perm_nchw_to_nhwc,
            )

            # Rewrite main branch to NHWC.
            _replace_operator_input_at(
                model_ir=model_ir,
                op=main_mul_op,
                input_index=int(1 - int(main_mul_side_idx)),
                new_input_name=str(main_pre_in_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=main_mul_op,
                input_index=int(main_mul_side_idx),
                new_input_name=str(main_mul_const),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=main_add_op,
                input_index=int(main_add_side_idx),
                new_input_name=str(main_add_const),
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(main_mul_op.outputs[0]), None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(main_name), None),
                perm_nchw_to_nhwc,
            )

            # Remove softmax wrapper transposes.
            _set_operator_inputs(
                model_ir=model_ir,
                op=softmax_op,
                new_inputs=[str(main_name)],
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=softmax_op,
                new_outputs=[str(soft_back_name)],
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=reduce_op,
                input_index=1,
                new_input_name=str(new_reduce_axis_name),
            )
            _replace_operator_input_at(
                model_ir=model_ir,
                op=reshape_op,
                input_index=1,
                new_input_name=str(new_reshape_shape_name),
            )
            reshape_opts = dict(reshape_op.options) if isinstance(reshape_op.options, dict) else {}
            for shape_key in ["newShape", "onnxRawNewShape"]:
                shape_val = reshape_opts.get(shape_key, None)
                if isinstance(shape_val, list) and len(shape_val) == 4:
                    reshape_opts[shape_key] = [
                        int(shape_val[0]),
                        int(shape_val[2]),
                        int(shape_val[3]),
                        int(shape_val[1]),
                    ]
            reshape_op.options = reshape_opts
            _replace_operator_input_at(
                model_ir=model_ir,
                op=expand_op,
                input_index=int(expand_const_idx),
                new_input_name=str(expand_const_nhwc),
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(soft_back_name), None),
                perm_nchw_to_nhwc,
            )

            # Keep mask/residual in NHWC and bypass terminal transpose.
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(expand_out), None),
                perm_nchw_to_nhwc,
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(side_mask_name), None),
                perm_nchw_to_nhwc,
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=add_res_op,
                new_outputs=[str(post_out)],
            )
            _permute_tensor_metadata_if_rank_matches(
                model_ir.tensors.get(str(post_out), None),
                perm_nchw_to_nhwc,
            )

            remove_indices = {
                int(side_pre_idx),
                int(main_pre_idx),
                int(soft_pre_idx),
                int(soft_post_idx),
                int(post_idx),
            }
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            optimized += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_sinet_softmax_mask_residual_nhwc_tail_chains": int(optimized)}


def _optimize_transpose_mul_add_const_prelu_prepost_nhwc_terminal_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Terminal rewrite for:
      TRANSPOSE(NHWC->NCHW) -> MUL(const) -> ADD(const) -> PRELU(const) -> TRANSPOSE(NCHW->NHWC)

    This pass is intentionally strict and runs only in the terminal stage to avoid
    interacting with earlier graph-wide transpose optimizers.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _ensure_const_nhwc_channel_last(
        *,
        tensor_name: str,
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> Optional[str]:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return None
        data = np.asarray(tensor.data)
        if int(data.size) == 1:
            return str(tensor_name)
        if data.ndim != 4:
            return None
        shape = [int(v) for v in list(data.shape)]
        nhwc_data: Optional[np.ndarray] = None
        if (
            int(shape[0]) == 1
            and int(shape[1]) == 1
            and int(shape[2]) == 1
            and int(shape[3]) > 0
        ):
            nhwc_data = np.asarray(data)
        elif (
            int(shape[0]) == 1
            and int(shape[1]) > 0
            and int(shape[2]) == 1
            and int(shape[3]) == 1
        ):
            nhwc_data = np.transpose(data, perm_nchw_to_nhwc).astype(data.dtype, copy=False)
        else:
            return None

        side_users = [int(v) for v in consumers.get(str(tensor_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)
        if shared_outside_chain:
            cloned_name = _unique_tensor_name(f"{tensor_name}_nhwc")
            model_ir.tensors[cloned_name] = TensorIR(
                name=cloned_name,
                dtype=str(tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(tensor.quantization),
            )
            return str(cloned_name)

        tensor.data = np.asarray(nhwc_data)
        tensor.shape = [int(v) for v in list(nhwc_data.shape)]
        tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]
        return str(tensor_name)

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue
            for mul_idx in pre_users:
                mul_op = model_ir.operators[int(mul_idx)]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    continue
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                if mul_inputs[0] == pre_output_name:
                    mul_side_input_index = 1
                    mul_side_name = str(mul_inputs[1])
                elif mul_inputs[1] == pre_output_name:
                    mul_side_input_index = 0
                    mul_side_name = str(mul_inputs[0])
                else:
                    continue

                mul_out_name = str(mul_op.outputs[0])
                if mul_out_name in model_outputs:
                    continue
                mul_out_users = [int(v) for v in consumers.get(mul_out_name, []) if int(v) != int(mul_idx)]
                if len(mul_out_users) != 1:
                    continue
                add_idx = int(mul_out_users[0])
                add_op = model_ir.operators[int(add_idx)]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    continue
                add_inputs = [str(v) for v in list(add_op.inputs)]
                if add_inputs[0] == mul_out_name:
                    add_side_input_index = 1
                    add_side_name = str(add_inputs[1])
                elif add_inputs[1] == mul_out_name:
                    add_side_input_index = 0
                    add_side_name = str(add_inputs[0])
                else:
                    continue

                add_out_name = str(add_op.outputs[0])
                if add_out_name in model_outputs:
                    continue
                add_out_users = [int(v) for v in consumers.get(add_out_name, []) if int(v) != int(add_idx)]
                if len(add_out_users) != 1:
                    continue
                prelu_idx = int(add_out_users[0])
                prelu_op = model_ir.operators[int(prelu_idx)]
                if (
                    str(prelu_op.op_type) != "PRELU"
                    or len(prelu_op.inputs) != 2
                    or len(prelu_op.outputs) != 1
                    or str(prelu_op.inputs[0]) != add_out_name
                ):
                    continue
                prelu_side_name = str(prelu_op.inputs[1])
                prelu_out_name = str(prelu_op.outputs[0])
                if prelu_out_name in model_outputs:
                    continue

                prelu_users = [int(v) for v in consumers.get(prelu_out_name, []) if int(v) != int(prelu_idx)]
                if len(prelu_users) == 0:
                    continue
                post_indices: List[int] = []
                post_output_names: List[str] = []
                legacy_users: List[int] = []
                for user_idx in prelu_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == prelu_out_name
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        post_indices.append(int(user_idx))
                        post_output_names.append(str(user_op.outputs[0]))
                    else:
                        legacy_users.append(int(user_idx))
                if len(post_indices) == 0:
                    continue

                chain_index_set = {int(mul_idx), int(add_idx), int(prelu_idx)}
                mul_side_for_op = _ensure_const_nhwc_channel_last(
                    tensor_name=str(mul_side_name),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if mul_side_for_op is None:
                    continue
                add_side_for_op = _ensure_const_nhwc_channel_last(
                    tensor_name=str(add_side_name),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if add_side_for_op is None:
                    continue
                prelu_side_for_op = _ensure_const_nhwc_channel_last(
                    tensor_name=str(prelu_side_name),
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                )
                if prelu_side_for_op is None:
                    continue

                mul_inputs[int(mul_side_input_index)] = str(mul_side_for_op)
                if mul_inputs[0] == pre_output_name:
                    mul_inputs[0] = str(pre_input_name)
                elif mul_inputs[1] == pre_output_name:
                    mul_inputs[1] = str(pre_input_name)
                else:
                    continue
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mul_op,
                    new_inputs=mul_inputs,
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=add_op,
                    input_index=int(add_side_input_index),
                    new_input_name=str(add_side_for_op),
                )
                _replace_operator_input_at(
                    model_ir=model_ir,
                    op=prelu_op,
                    input_index=1,
                    new_input_name=str(prelu_side_for_op),
                )

                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(mul_out_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(add_out_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(prelu_out_name, None),
                    perm_nchw_to_nhwc,
                )

                canonical_post_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=prelu_op,
                    new_outputs=[canonical_post_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

                old_prelu_tensor = model_ir.tensors.get(prelu_out_name, None)
                canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
                if old_prelu_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_prelu_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_prelu_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_prelu_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_prelu_tensor.shape_signature)]
                        if old_prelu_tensor.shape_signature is not None
                        else [int(v) for v in list(old_prelu_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )

                if len(legacy_users) > 0:
                    keep_post_idx = int(post_indices[0])
                    keep_post_op = model_ir.operators[int(keep_post_idx)]
                    keep_perm_name = str(keep_post_op.inputs[1])
                    keep_perm_tensor = model_ir.tensors.get(keep_perm_name, None)
                    if keep_perm_tensor is not None:
                        keep_perm_tensor.data = np.asarray(perm_nhwc_to_nchw, dtype=np.int32)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=keep_post_op,
                        new_inputs=[canonical_post_output_name, keep_perm_name],
                    )
                    _set_operator_outputs(
                        model_ir=model_ir,
                        op=keep_post_op,
                        new_outputs=[prelu_out_name],
                    )
                    post_remove_indices = [int(v) for v in post_indices[1:]]
                else:
                    post_remove_indices = [int(v) for v in post_indices]

                remove_indices = set(int(v) for v in post_remove_indices)
                pre_remaining_users = [int(v) for v in pre_users if int(v) != int(mul_idx)]
                if len(pre_remaining_users) == 0:
                    remove_indices.add(int(pre_idx))
                for remove_idx in sorted(list(remove_indices), reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_mul_add_const_prelu_prepost_nhwc_terminal_chains": int(rewritten)}


def _optimize_transpose_mean_mul_add_const_prepost_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Eliminate NCHW round-trips around TRANSPOSE->MEAN->MUL(const)->ADD(const)->TRANSPOSE chains.

    Target:
      x_nhwc --TRANSPOSE(0,3,1,2)--> x_nchw
      x_nchw --MEAN(axes_nchw, keepDims=True)--> m_nchw
      m_nchw --MUL(const)--> u_nchw --ADD(const)--> y_nchw
      y_nchw --TRANSPOSE(0,2,3,1)--> y_nhwc

    Rewrite:
      x_nhwc --MEAN(axes_nhwc, keepDims=True)--> m_nhwc
      m_nhwc --MUL(const_nhwc)--> u_nhwc --ADD(const_nhwc)--> y_nhwc
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _rewrite_binary_const_to_nhwc(
        *,
        op_idx: int,
        side_input_index: int,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
        chain_index_set: set[int],
        consumers: Dict[str, List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False

        nhwc_data: Optional[np.ndarray] = None
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is not None:
            side_shape = [int(v) for v in list(side_data.shape)]
            if _broadcast_static_shapes(target_shape, side_shape) is not None:
                # Already NHWC-compatible. Keep idempotent across repeated sweeps.
                return True
            rotated = np.asarray(side_data)
            for _ in range(3):
                rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
                rotated_shape = [int(v) for v in list(rotated.shape)]
                if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                    nhwc_data = np.asarray(rotated)
                    break
            if nhwc_data is None:
                return False
        else:
            side_shape = [int(v) for v in list(side_data.shape)]
            if (
                len(side_shape) == 4
                and int(side_shape[0]) == 1
                and int(side_shape[1]) > 1
                and int(side_shape[2]) == 1
                and int(side_shape[3]) == 1
            ):
                nhwc_data = np.transpose(side_data, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            else:
                return True

        side_users = [int(v) for v in consumers.get(str(side_input_name), [])]
        shared_outside_chain = any(int(u) not in chain_index_set for u in side_users)

        target_name = str(side_input_name)
        if shared_outside_chain:
            target_name = _unique_tensor_name(f"{side_input_name}_nhwc")
            model_ir.tensors[target_name] = TensorIR(
                name=target_name,
                dtype=str(side_tensor.dtype),
                shape=[int(v) for v in list(nhwc_data.shape)],
                shape_signature=[int(v) for v in list(nhwc_data.shape)],
                data=np.asarray(nhwc_data),
                is_variable=False,
                quantization=_clone_quantization(side_tensor.quantization),
            )
        else:
            side_tensor.data = np.asarray(nhwc_data)
            side_tensor.shape = [int(v) for v in list(nhwc_data.shape)]
            side_tensor.shape_signature = [int(v) for v in list(nhwc_data.shape)]

        _replace_operator_input_at(
            model_ir=model_ir,
            op=model_ir.operators[int(op_idx)],
            input_index=int(side_input_index),
            new_input_name=str(target_name),
        )
        return True

    def _can_rewrite_binary_const_to_nhwc(
        *,
        side_input_name: str,
        target_broadcast_shape: Optional[List[int]],
    ) -> bool:
        side_tensor = model_ir.tensors.get(str(side_input_name), None)
        if side_tensor is None or side_tensor.data is None:
            return False
        side_data = np.asarray(side_tensor.data)
        if int(side_data.size) == 1:
            return True
        if side_data.ndim != 4:
            return False
        target_shape = (
            [int(v) for v in list(target_broadcast_shape)]
            if _is_fully_known_positive_shape(target_broadcast_shape)
            else None
        )
        if target_shape is None:
            return True
        side_shape = [int(v) for v in list(side_data.shape)]
        if _broadcast_static_shapes(target_shape, side_shape) is not None:
            return True
        rotated = np.asarray(side_data)
        for _ in range(3):
            rotated = np.transpose(rotated, perm_nchw_to_nhwc).astype(side_data.dtype, copy=False)
            rotated_shape = [int(v) for v in list(rotated.shape)]
            if _broadcast_static_shapes(target_shape, rotated_shape) is not None:
                return True
        return False

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_input_name in model_outputs or pre_output_name in model_outputs:
                continue

            pre_users = [int(v) for v in consumers.get(pre_output_name, [])]
            if len(pre_users) == 0:
                continue

            for mean_idx in pre_users:
                mean_op = model_ir.operators[int(mean_idx)]
                if str(mean_op.op_type) != "MEAN" or len(mean_op.inputs) < 2 or len(mean_op.outputs) != 1:
                    continue
                if str(mean_op.inputs[0]) != pre_output_name:
                    continue
                if not bool(mean_op.options.get("keepDims", False)):
                    continue

                mean_axes_name = str(mean_op.inputs[1])
                mean_axes_tensor = model_ir.tensors.get(mean_axes_name, None)
                mean_axes = _read_const_ints_from_tensor(mean_axes_tensor)
                if mean_axes is None or len(mean_axes) == 0:
                    continue

                mean_output_name = str(mean_op.outputs[0])
                if mean_output_name in model_outputs:
                    continue
                mul_users = [int(v) for v in consumers.get(mean_output_name, [])]
                if len(mul_users) != 1:
                    continue
                mul_idx = int(mul_users[0])
                mul_op = model_ir.operators[mul_idx]
                if str(mul_op.op_type) != "MUL" or len(mul_op.inputs) != 2 or len(mul_op.outputs) != 1:
                    continue

                mul_in0 = str(mul_op.inputs[0])
                mul_in1 = str(mul_op.inputs[1])
                if mul_in0 == mean_output_name:
                    mul_side_input_index = 1
                    mul_side_name = mul_in1
                elif mul_in1 == mean_output_name:
                    mul_side_input_index = 0
                    mul_side_name = mul_in0
                else:
                    continue

                add_input_name = str(mul_op.outputs[0])
                if add_input_name in model_outputs:
                    continue
                add_users = [int(v) for v in consumers.get(add_input_name, [])]
                if len(add_users) != 1:
                    continue
                add_idx = int(add_users[0])
                add_op = model_ir.operators[add_idx]
                if str(add_op.op_type) != "ADD" or len(add_op.inputs) != 2 or len(add_op.outputs) != 1:
                    continue

                add_in0 = str(add_op.inputs[0])
                add_in1 = str(add_op.inputs[1])
                if add_in0 == add_input_name:
                    add_side_input_index = 1
                    add_side_name = add_in1
                elif add_in1 == add_input_name:
                    add_side_input_index = 0
                    add_side_name = add_in0
                else:
                    continue

                add_output_name = str(add_op.outputs[0])
                if add_output_name in model_outputs:
                    continue
                add_output_users = [int(v) for v in consumers.get(add_output_name, [])]
                if len(add_output_users) == 0:
                    continue

                post_indices: List[int] = []
                post_output_names: List[str] = []
                valid_posts = True
                for user_idx in add_output_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) == "TRANSPOSE"
                        and len(user_op.inputs) >= 2
                        and len(user_op.outputs) == 1
                        and str(user_op.inputs[0]) == add_output_name
                        and _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        post_indices.append(int(user_idx))
                        post_output_names.append(str(user_op.outputs[0]))
                    else:
                        valid_posts = False
                        break
                if not valid_posts or len(post_indices) == 0:
                    continue

                # Normalize NCHW-side axes and map them to NHWC-side axes.
                mapped_axes: List[int] = []
                valid_axes = True
                for axis in mean_axes:
                    a = int(axis)
                    if a < 0:
                        a += 4
                    if a < 0 or a >= 4:
                        valid_axes = False
                        break
                    # `perm_nchw_to_nhwc` lists old axes in new-axis order.
                    # Reduction axes need the inverse mapping (old axis -> new
                    # axis), which is the NHWC->NCHW permutation here.
                    mapped_axes.append(int(perm_nhwc_to_nchw[int(a)]))
                if not valid_axes or len(mapped_axes) == 0:
                    continue

                chain_index_set = {int(mean_idx), int(mul_idx), int(add_idx)}
                target_nhwc_shape = (
                    list(model_ir.tensors[pre_input_name].shape)
                    if pre_input_name in model_ir.tensors
                    else None
                )
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(mul_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    continue
                if not _can_rewrite_binary_const_to_nhwc(
                    side_input_name=str(add_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                ):
                    continue
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(mul_idx),
                    side_input_index=int(mul_side_input_index),
                    side_input_name=str(mul_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    continue
                if not _rewrite_binary_const_to_nhwc(
                    op_idx=int(add_idx),
                    side_input_index=int(add_side_input_index),
                    side_input_name=str(add_side_name),
                    target_broadcast_shape=target_nhwc_shape,
                    chain_index_set=chain_index_set,
                    consumers=consumers,
                ):
                    continue

                if not _write_const_ints_to_tensor(mean_axes_tensor, [int(v) for v in mapped_axes]):
                    # Keep going even when unchanged; rewrite still valid.
                    pass

                mean_inputs = [str(v) for v in list(mean_op.inputs)]
                mean_inputs[0] = pre_input_name
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=mean_op,
                    new_inputs=mean_inputs,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(mean_output_name, None),
                    perm_nchw_to_nhwc,
                )
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(add_input_name, None),
                    perm_nchw_to_nhwc,
                )

                canonical_post_output_name = str(post_output_names[0])
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=add_op,
                    new_outputs=[canonical_post_output_name],
                )
                for alias_name in post_output_names[1:]:
                    _replace_tensor_inputs(model_ir, str(alias_name), canonical_post_output_name)

                old_add_out_tensor = model_ir.tensors.get(add_output_name, None)
                canonical_tensor = model_ir.tensors.get(canonical_post_output_name, None)
                if old_add_out_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_add_out_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_add_out_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_add_out_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_add_out_tensor.shape_signature)]
                        if old_add_out_tensor.shape_signature is not None
                        else [int(v) for v in list(old_add_out_tensor.shape)]
                    )
                    _permute_tensor_metadata_if_rank_matches(
                        canonical_tensor,
                        perm_nchw_to_nhwc,
                    )

                remove_indices = set(int(v) for v in post_indices)
                # Drop pre transpose only when this rewrite consumed its last user.
                pre_remaining_users = [int(v) for v in pre_users if int(v) != int(mean_idx)]
                if len(pre_remaining_users) == 0:
                    remove_indices.add(int(pre_idx))
                for remove_idx in sorted(remove_indices, reverse=True):
                    del model_ir.operators[int(remove_idx)]

                rewritten += 1
                changed = True
                break

            if changed:
                break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_mean_mul_add_const_prepost_nhwc_chains": int(rewritten)}


