def _optimize_singleton_gate_conv_concat_nhwc_bridge_blocks(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove singleton-channel NCHW adapters around a localized gate->conv->concat block.

    Target:
      split_nchw --RESHAPE--> split_nhwc
      clip_nhwc --RESHAPE--> clip_nchw
      clip_nchw * split_nchw -> mul_gate
      scalar - clip_nchw -> sub_gate
      (optional) input_nhwc --TRANSPOSE--> input_nchw
      clip_nchw * input_nchw -> mul_rgb
      conv_out_nhwc --RESHAPE--> conv_out_nchw --LOGISTIC--> sig_nchw
      sub_gate * sig_nchw -> gated
      mul_gate + gated -> fused --UNARY--> clip3_nchw
      clip3_nchw --RESHAPE--> clip3_nhwc
      CONCAT(axis=3, [..., split_nhwc, ..., clip3_nhwc]) -> y_nhwc

    Rewrite:
      - Keep the whole gate path in NHWC.
      - Remove singleton layout RESHAPEs and optional input TRANSPOSE.
      - Rewire CONCAT to consume the NHWC tensors directly.
    """
    rewritten = 0
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    unary_ops = {"RELU", "RELU6", "RELU_0_TO_1", "LOGISTIC", "HARD_SWISH", "LEAKY_RELU", "TANH"}

    def _is_singleton_layout_reshape(op: OperatorIR) -> bool:
        if str(op.op_type) != "RESHAPE" or len(op.inputs) < 1 or len(op.outputs) != 1:
            return False
        in_tensor = model_ir.tensors.get(str(op.inputs[0]), None)
        out_tensor = model_ir.tensors.get(str(op.outputs[0]), None)
        if (
            in_tensor is None
            or out_tensor is None
            or not _is_fully_known_positive_shape(in_tensor.shape)
            or not _is_fully_known_positive_shape(out_tensor.shape)
        ):
            return False
        in_shape = [int(v) for v in list(in_tensor.shape)]
        out_shape = [int(v) for v in list(out_tensor.shape)]
        if len(in_shape) != 4 or len(out_shape) != 4:
            return False
        return _permute_shape(in_shape, perm_nchw_to_nhwc) == out_shape or _permute_shape(in_shape, perm_nhwc_to_nchw) == out_shape

    while True:
        changed = False
        producers = _build_tensor_producer_map(model_ir)
        consumers = _build_tensor_consumer_map(model_ir)

        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or int(concat_op.options.get("axis", 3)) != 3:
                continue
            concat_inputs = [str(v) for v in list(concat_op.inputs)]
            clip3_adapter_idx = None
            clip3_adapter_op = None
            clip3_nchw_name = ""
            clip3_nhwc_name = ""
            clip3_unary_idx = None
            for name in concat_inputs:
                prod_idx = producers.get(name, None)
                if prod_idx is None or not _is_singleton_layout_reshape(model_ir.operators[int(prod_idx)]):
                    continue
                candidate_op = model_ir.operators[int(prod_idx)]
                candidate_source_name = str(candidate_op.inputs[0])
                candidate_unary_idx = producers.get(candidate_source_name, None)
                if candidate_unary_idx is None or str(model_ir.operators[int(candidate_unary_idx)].op_type) not in unary_ops:
                    continue
                add_candidate_idx = producers.get(str(model_ir.operators[int(candidate_unary_idx)].inputs[0]), None)
                if add_candidate_idx is None or str(model_ir.operators[int(add_candidate_idx)].op_type) != "ADD":
                    continue
                clip3_adapter_idx = int(prod_idx)
                clip3_adapter_op = candidate_op
                clip3_nchw_name = str(candidate_source_name)
                clip3_nhwc_name = str(candidate_op.outputs[0])
                clip3_unary_idx = int(candidate_unary_idx)
                break
            if clip3_adapter_idx is None or clip3_adapter_op is None or clip3_unary_idx is None:
                continue
            add_idx = producers.get(str(model_ir.operators[int(clip3_unary_idx)].inputs[0]), None)
            if add_idx is None or str(model_ir.operators[int(add_idx)].op_type) != "ADD":
                continue
            add_inputs = [str(v) for v in list(model_ir.operators[int(add_idx)].inputs)]
            mul_indices = [producers.get(name, None) for name in add_inputs]
            if any(idx is None or str(model_ir.operators[int(idx)].op_type) != "MUL" for idx in mul_indices):
                continue

            clip_adapter_idx = None
            clip_nhwc_name = ""
            split_nchw_name = ""
            sig_idx = None
            aux_adapter_idx = None
            aux_nhwc_name = ""
            sub_idx = None
            gate_mul_idx = None
            sig_mul_idx = None
            for mul_idx in [int(v) for v in mul_indices if v is not None]:
                mul_op = model_ir.operators[int(mul_idx)]
                mul_inputs = [str(v) for v in list(mul_op.inputs)]
                found_gated_branch = False
                for maybe_aux_name in mul_inputs:
                    maybe_aux_idx = producers.get(maybe_aux_name, None)
                    if maybe_aux_idx is None:
                        continue
                    maybe_aux_op = model_ir.operators[int(maybe_aux_idx)]
                    if not (
                        str(maybe_aux_op.op_type) == "LOGISTIC"
                        or _is_singleton_layout_reshape(maybe_aux_op)
                    ):
                        continue
                    other_name = next(name for name in mul_inputs if name != str(maybe_aux_op.outputs[0]))
                    cand_sub_idx = producers.get(other_name, None)
                    if cand_sub_idx is None or str(model_ir.operators[int(cand_sub_idx)].op_type) != "SUB":
                        continue
                    clip_adapter_out = str(model_ir.operators[int(cand_sub_idx)].inputs[1])
                    cand_clip_adapter_idx = producers.get(clip_adapter_out, None)
                    if cand_clip_adapter_idx is None or not _is_singleton_layout_reshape(model_ir.operators[int(cand_clip_adapter_idx)]):
                        continue
                    sub_idx = int(cand_sub_idx)
                    clip_adapter_idx = int(cand_clip_adapter_idx)
                    clip_nhwc_name = str(model_ir.operators[int(clip_adapter_idx)].inputs[0])
                    if str(maybe_aux_op.op_type) == "LOGISTIC":
                        sig_idx = int(maybe_aux_idx)
                        aux_input_name = str(maybe_aux_op.inputs[0])
                        aux_adapter_idx = producers.get(aux_input_name, None)
                        if aux_adapter_idx is None or not _is_singleton_layout_reshape(model_ir.operators[int(aux_adapter_idx)]):
                            sig_idx = None
                            sub_idx = None
                            clip_adapter_idx = None
                            clip_nhwc_name = ""
                            continue
                        aux_nhwc_name = str(model_ir.operators[int(aux_adapter_idx)].inputs[0])
                    else:
                        sig_idx = None
                        aux_adapter_idx = int(maybe_aux_idx)
                        aux_nhwc_name = str(maybe_aux_op.inputs[0])
                    sig_mul_idx = int(mul_idx)
                    found_gated_branch = True
                    break
                if not found_gated_branch:
                    clip_side = next((name for name in mul_inputs if producers.get(name, None) is not None and _is_singleton_layout_reshape(model_ir.operators[int(producers.get(name))])), None)
                    if clip_side is None:
                        continue
                    clip_adapter_idx = int(producers.get(clip_side))
                    clip_nhwc_name = str(model_ir.operators[int(clip_adapter_idx)].inputs[0])
                    split_nchw_name = next(name for name in mul_inputs if name != clip_side)
                    gate_mul_idx = int(mul_idx)
            if None in {clip_adapter_idx, aux_adapter_idx, sub_idx, gate_mul_idx, sig_mul_idx}:
                continue

            split_reshape_idx = producers.get(next((name for name in concat_inputs if name != clip3_nhwc_name and producers.get(name, None) is not None and _is_singleton_layout_reshape(model_ir.operators[int(producers.get(name))]) and str(model_ir.operators[int(producers.get(name))].inputs[0]) == split_nchw_name), ""), None)

            gate_clip_out = str(model_ir.operators[int(clip_adapter_idx)].outputs[0])
            gate_mul_op = model_ir.operators[int(gate_mul_idx)]
            sub_op = model_ir.operators[int(sub_idx)]
            sig_mul_op = model_ir.operators[int(sig_mul_idx)]

            _set_operator_inputs(model_ir=model_ir, op=gate_mul_op, new_inputs=[clip_nhwc_name if str(v) == gate_clip_out else str(v) for v in list(gate_mul_op.inputs)])
            _set_operator_inputs(model_ir=model_ir, op=sub_op, new_inputs=[clip_nhwc_name if str(v) == gate_clip_out else str(v) for v in list(sub_op.inputs)])
            if sig_idx is not None:
                sig_op = model_ir.operators[int(sig_idx)]
                _set_operator_inputs(model_ir=model_ir, op=sig_op, new_inputs=[aux_nhwc_name])
            _set_operator_inputs(
                model_ir=model_ir,
                op=sig_mul_op,
                new_inputs=[
                    aux_nhwc_name if str(v) == str(model_ir.operators[int(aux_adapter_idx)].outputs[0]) else str(v)
                    for v in list(sig_mul_op.inputs)
                ],
            )

            rgb_mul_idx = next((int(user_idx) for user_idx in consumers.get(gate_clip_out, []) if int(user_idx) not in {int(gate_mul_idx), int(sub_idx)} and str(model_ir.operators[int(user_idx)].op_type) == "MUL"), None)
            input_transpose_idx = None
            if rgb_mul_idx is not None:
                rgb_mul_op = model_ir.operators[int(rgb_mul_idx)]
                other_name = next(name for name in list(rgb_mul_op.inputs) if name != gate_clip_out)
                input_transpose_idx = producers.get(other_name, None)
                if input_transpose_idx is not None and str(model_ir.operators[int(input_transpose_idx)].op_type) == "TRANSPOSE" and _read_transpose_perm(model_ir, model_ir.operators[int(input_transpose_idx)]) == perm_nhwc_to_nchw:
                    _set_operator_inputs(model_ir=model_ir, op=rgb_mul_op, new_inputs=[str(model_ir.operators[int(input_transpose_idx)].inputs[0]) if str(v) == other_name else clip_nhwc_name if str(v) == gate_clip_out else str(v) for v in list(rgb_mul_op.inputs)])
                    _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(rgb_mul_op.outputs[0]), None), perm_nchw_to_nhwc)
                else:
                    input_transpose_idx = None
                    _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(other_name, None), perm_nchw_to_nhwc)
                    _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(rgb_mul_op.outputs[0]), None), perm_nchw_to_nhwc)
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=rgb_mul_op,
                        new_inputs=[
                            clip_nhwc_name if str(v) == gate_clip_out else str(v)
                            for v in list(rgb_mul_op.inputs)
                        ],
                    )

            for tensor_name in [
                str(model_ir.tensors[split_nchw_name].name),
                str(gate_mul_op.outputs[0]),
                str(sub_op.outputs[0]),
                str(sig_mul_op.outputs[0]),
                str(model_ir.operators[int(add_idx)].outputs[0]),
                str(model_ir.operators[int(clip3_unary_idx)].outputs[0]),
            ]:
                _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(tensor_name, None), perm_nchw_to_nhwc)
            if sig_idx is not None:
                _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(model_ir.operators[int(sig_idx)].outputs[0]), None), perm_nchw_to_nhwc)

            if split_reshape_idx is not None:
                split_reshape_out = str(model_ir.operators[int(split_reshape_idx)].outputs[0])
                for user_idx in consumers.get(split_reshape_out, []):
                    user_op = model_ir.operators[int(user_idx)]
                    _set_operator_inputs(model_ir=model_ir, op=user_op, new_inputs=[split_nchw_name if str(v) == split_reshape_out else str(v) for v in list(user_op.inputs)])

            for user_idx in consumers.get(str(clip3_nhwc_name), []):
                user_op = model_ir.operators[int(user_idx)]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=user_op,
                    new_inputs=[clip3_nchw_name if str(v) == clip3_nhwc_name else str(v) for v in list(user_op.inputs)],
                )

            remove_indices = {int(clip_adapter_idx), int(aux_adapter_idx), int(clip3_adapter_idx)}
            if split_reshape_idx is not None:
                remove_indices.add(int(split_reshape_idx))
            if input_transpose_idx is not None:
                remove_indices.add(int(input_transpose_idx))
            for remove_idx in sorted(remove_indices, reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_singleton_gate_conv_concat_nhwc_bridge_blocks": int(rewritten)}


def _repair_mixed_singleton_nchw_inputs_for_nhwc_concat(model_ir: ModelIR) -> Dict[str, int]:
    """
    Repair remaining NHWC CONCAT(axis=3) ops that still consume singleton-channel
    NCHW tensors directly.

    Pattern:
      CONCAT(axis=3, [..., x_nchw=[N,1,H,W], ... y_nhwc=[N,H,W,1] ...])

    Rewrite:
      Insert a local RESHAPE adapter for each direct singleton NCHW input:
        x_nchw -> x_nhwc_adapter=[N,H,W,1]
      and rewire CONCAT to consume the adapter.
    """
    repaired = 0
    perm_nchw_to_nhwc = [0, 2, 3, 1]

    def _unique_tensor_name(base: str) -> str:
        existing = set(model_ir.tensors.keys())
        existing.update(str(v) for op in list(model_ir.operators) for v in list(op.outputs))
        if str(base) not in existing:
            return str(base)
        suffix = 1
        while f"{base}_{suffix}" in existing:
            suffix += 1
        return f"{base}_{suffix}"

    while True:
        changed = False
        producers = _build_tensor_producer_map(model_ir)
        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or int(concat_op.options.get("axis", 3)) != 3:
                continue
            concat_out_name = str(concat_op.outputs[0]) if len(concat_op.outputs) == 1 else ""
            concat_out_tensor = model_ir.tensors.get(concat_out_name, None)
            if (
                concat_out_tensor is None
                or not _is_fully_known_positive_shape(concat_out_tensor.shape)
                or len(list(concat_out_tensor.shape)) != 4
            ):
                continue
            target_shape = [int(v) for v in list(concat_out_tensor.shape)]
            if int(target_shape[3]) <= 0:
                continue

            new_inputs: List[str] = []
            adapters_to_insert: List[Tuple[str, str, str, List[int]]] = []
            valid = True
            needs_repair = False

            for input_name in [str(v) for v in list(concat_op.inputs)]:
                input_tensor = model_ir.tensors.get(str(input_name), None)
                if (
                    input_tensor is None
                    or not _is_fully_known_positive_shape(input_tensor.shape)
                    or len(list(input_tensor.shape)) != 4
                ):
                    valid = False
                    break
                input_shape = [int(v) for v in list(input_tensor.shape)]
                if input_shape == target_shape[:-1] + [1]:
                    new_inputs.append(str(input_name))
                    continue
                nhwc_shape = _permute_shape(input_shape, perm_nchw_to_nhwc)
                if (
                    nhwc_shape is not None
                    and [int(v) for v in list(nhwc_shape)] == target_shape[:-1] + [1]
                    and int(input_shape[1]) == 1
                ):
                    adapter_name = _unique_tensor_name(f"{input_name}_nhwc_concat_adapter")
                    shape_name = _unique_tensor_name(f"{adapter_name}_reshape_shape")
                    adapters_to_insert.append(
                        (
                            str(input_name),
                            str(adapter_name),
                            str(shape_name),
                            [int(v) for v in list(nhwc_shape)],
                        )
                    )
                    new_inputs.append(str(adapter_name))
                    needs_repair = True
                    continue
                valid = False
                break

            if not valid or not needs_repair:
                continue

            insert_pos = int(concat_idx)
            for source_name, adapter_name, shape_name, nhwc_shape in adapters_to_insert:
                source_tensor = model_ir.tensors.get(source_name, None)
                source_dtype = str(source_tensor.dtype) if source_tensor is not None else "FLOAT32"
                source_quant = _clone_quantization(source_tensor.quantization) if source_tensor is not None else None
                model_ir.tensors[shape_name] = TensorIR(
                    name=str(shape_name),
                    dtype="INT32",
                    shape=[len(nhwc_shape)],
                    shape_signature=[len(nhwc_shape)],
                    data=np.asarray(nhwc_shape, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
                model_ir.tensors[adapter_name] = TensorIR(
                    name=str(adapter_name),
                    dtype=str(source_dtype),
                    shape=[int(v) for v in list(nhwc_shape)],
                    shape_signature=[int(v) for v in list(nhwc_shape)],
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(source_quant),
                )
                model_ir.operators.insert(
                    int(insert_pos),
                    OperatorIR(
                        op_type="RESHAPE",
                        inputs=[str(source_name), str(shape_name)],
                        outputs=[str(adapter_name)],
                        options={"newShape": [int(v) for v in list(nhwc_shape)]},
                    ),
                )
                insert_pos += 1

            concat_op = next((op for op in model_ir.operators if op is concat_op), None)
            if concat_op is None:
                continue
            _set_operator_inputs(model_ir=model_ir, op=concat_op, new_inputs=[str(v) for v in list(new_inputs)])
            repaired += 1
            changed = True
            break

        if not changed:
            break

    if repaired > 0:
        _prune_unused_tensors(model_ir)
    return {"repaired_mixed_singleton_nchw_inputs_for_nhwc_concat": int(repaired)}


def _optimize_transpose_unary_split_concat_single_post_nchw(model_ir: ModelIR) -> Dict[str, int]:
    """
    Rewrite TRANSPOSE->UNARY->SPLIT->(optional UNARY)->CONCAT blocks to NHWC
    while preserving a single post-CONCAT NCHW contract.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {"RELU", "RELU6", "RELU_0_TO_1", "LOGISTIC", "HARD_SWISH", "LEAKY_RELU", "TANH"}

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _is_singleton_layout_reshape(op: OperatorIR) -> bool:
        if str(op.op_type) != "RESHAPE" or len(op.inputs) < 1 or len(op.outputs) != 1:
            return False
        in_tensor = model_ir.tensors.get(str(op.inputs[0]), None)
        out_tensor = model_ir.tensors.get(str(op.outputs[0]), None)
        if (
            in_tensor is None
            or out_tensor is None
            or not _is_fully_known_positive_shape(in_tensor.shape)
            or not _is_fully_known_positive_shape(out_tensor.shape)
        ):
            return False
        in_shape = [int(v) for v in list(in_tensor.shape)]
        out_shape = [int(v) for v in list(out_tensor.shape)]
        if len(in_shape) != 4 or len(out_shape) != 4:
            return False
        return _permute_shape(in_shape, perm_nchw_to_nhwc) == out_shape or _permute_shape(in_shape, perm_nhwc_to_nchw) == out_shape

    while True:
        changed = False
        producers = _build_tensor_producer_map(model_ir)
        consumers = _build_tensor_consumer_map(model_ir)
        for concat_idx, concat_op in enumerate(model_ir.operators):
            if str(concat_op.op_type) != "CONCATENATION" or int(concat_op.options.get("axis", 1)) != 1 or len(concat_op.outputs) != 1:
                continue
            concat_output_name = str(concat_op.outputs[0])

            concat_inputs = [str(v) for v in list(concat_op.inputs)]
            branch_sources: List[str] = []
            branch_outputs: List[str] = []
            branch_unary_indices: List[int] = []
            split_idx: Optional[int] = None
            pre_unary_idx: Optional[int] = None
            pre_t_idx: Optional[int] = None
            ext_input_name = ""

            for input_name in concat_inputs:
                prod_idx = producers.get(input_name, None)
                source_name = str(input_name)
                branch_unary_idx = -1
                if prod_idx is not None and str(model_ir.operators[int(prod_idx)].op_type) in unary_ops:
                    branch_unary_idx = int(prod_idx)
                    source_name = str(model_ir.operators[int(prod_idx)].inputs[0])
                source_prod_idx = producers.get(source_name, None)
                if source_prod_idx is None or str(model_ir.operators[int(source_prod_idx)].op_type) != "SPLIT":
                    continue
                candidate_split_idx = int(source_prod_idx)
                candidate_split_op = model_ir.operators[int(candidate_split_idx)]
                axis_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(candidate_split_op.inputs[0]), None))
                if axis_vals is None or len(axis_vals) != 1 or int(axis_vals[0]) != 1:
                    continue
                candidate_pre_unary_idx = producers.get(str(candidate_split_op.inputs[1]), None)
                if candidate_pre_unary_idx is None or str(model_ir.operators[int(candidate_pre_unary_idx)].op_type) not in unary_ops:
                    continue
                candidate_pre_t_idx = producers.get(str(model_ir.operators[int(candidate_pre_unary_idx)].inputs[0]), None)
                if candidate_pre_t_idx is None:
                    continue
                candidate_pre_t_op = model_ir.operators[int(candidate_pre_t_idx)]
                if str(candidate_pre_t_op.op_type) != "TRANSPOSE" or _read_transpose_perm(model_ir, candidate_pre_t_op) != perm_nhwc_to_nchw:
                    continue
                if split_idx is None:
                    split_idx = int(candidate_split_idx)
                    pre_unary_idx = int(candidate_pre_unary_idx)
                    pre_t_idx = int(candidate_pre_t_idx)
                elif int(split_idx) != int(candidate_split_idx):
                    continue
                branch_sources.append(str(source_name))
                branch_outputs.append(str(input_name))
                branch_unary_indices.append(int(branch_unary_idx))

            if split_idx is None or pre_unary_idx is None or pre_t_idx is None:
                continue
            split_op = model_ir.operators[int(split_idx)]
            if len(branch_sources) != len(list(split_op.outputs)):
                continue
            ext_input_name = next((name for name in concat_inputs if name not in branch_outputs), "")
            if ext_input_name == "":
                continue
            ext_prod_idx = producers.get(ext_input_name, None)
            if ext_prod_idx is not None and _is_singleton_layout_reshape(model_ir.operators[int(ext_prod_idx)]):
                ext_input_name = str(model_ir.operators[int(ext_prod_idx)].inputs[0])

            pre_t_op = model_ir.operators[int(pre_t_idx)]
            source_nhwc_name = str(pre_t_op.inputs[0])
            split_axis_tensor = model_ir.tensors.get(str(split_op.inputs[0]), None)
            if split_axis_tensor is None:
                continue
            if set(int(v) for v in consumers.get(str(split_op.inputs[0]), [])) == {int(split_idx)}:
                _write_const_ints_to_tensor(split_axis_tensor, [3])
            else:
                axis_name = _unique_tensor_name(f"{str(split_op.inputs[0])}_nhwc")
                model_ir.tensors[axis_name] = TensorIR(name=axis_name, dtype=str(split_axis_tensor.dtype), shape=[1], shape_signature=[1], data=np.asarray([3], dtype=np.int32), is_variable=False, quantization=_clone_quantization(split_axis_tensor.quantization))
                _set_operator_inputs(model_ir=model_ir, op=split_op, new_inputs=[axis_name, str(split_op.inputs[1])])

            pre_unary_op = model_ir.operators[int(pre_unary_idx)]
            _set_operator_inputs(model_ir=model_ir, op=pre_unary_op, new_inputs=[source_nhwc_name])
            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(pre_unary_op.outputs[0]), None), perm_nchw_to_nhwc)
            for split_output_name in list(split_op.outputs):
                _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(split_output_name), None), perm_nchw_to_nhwc)
            for unary_idx in branch_unary_indices:
                if unary_idx >= 0:
                    _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(model_ir.operators[int(unary_idx)].outputs[0]), None), perm_nchw_to_nhwc)

            new_concat_inputs: List[str] = []
            for input_name in concat_inputs:
                if input_name == ext_input_name or (ext_prod_idx is not None and producers.get(input_name, None) == ext_prod_idx):
                    new_concat_inputs.append(ext_input_name)
                else:
                    new_concat_inputs.append(input_name)
            concat_op.options["axis"] = 3
            _set_operator_inputs(model_ir=model_ir, op=concat_op, new_inputs=new_concat_inputs)

            concat_tensor = model_ir.tensors.get(concat_output_name, None)
            if concat_tensor is None or not _is_fully_known_positive_shape(concat_tensor.shape):
                continue
            nhwc_shape = _permute_shape([int(v) for v in list(concat_tensor.shape)], perm_nchw_to_nhwc)
            nhwc_sig = _permute_shape([int(v) for v in list(concat_tensor.shape_signature)] if concat_tensor.shape_signature is not None else [int(v) for v in list(concat_tensor.shape)], perm_nchw_to_nhwc)
            if nhwc_shape is None or nhwc_sig is None:
                continue
            concat_nhwc_name = _unique_tensor_name(f"{concat_output_name}_nhwc")
            model_ir.tensors[concat_nhwc_name] = TensorIR(name=concat_nhwc_name, dtype=str(concat_tensor.dtype), shape=[int(v) for v in list(nhwc_shape)], shape_signature=[int(v) for v in list(nhwc_sig)], data=None, is_variable=False, quantization=_clone_quantization(concat_tensor.quantization))
            _set_operator_outputs(model_ir=model_ir, op=concat_op, new_outputs=[concat_nhwc_name])
            perm_name = _unique_tensor_name(f"{concat_output_name}_perm")
            model_ir.tensors[perm_name] = TensorIR(name=perm_name, dtype="INT32", shape=[4], shape_signature=[4], data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32), is_variable=False)
            model_ir.operators.insert(int(concat_idx) + 1, OperatorIR(op_type="TRANSPOSE", inputs=[concat_nhwc_name, perm_name], outputs=[concat_output_name], options={}))
            del model_ir.operators[int(pre_t_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    if rewritten > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_unary_split_concat_single_post_nchw": int(rewritten)}


def _optimize_transpose_split_channelwise_tail_to_single_post_nchw(model_ir: ModelIR) -> Dict[str, int]:
    """
    Propagate NHWC through a local channelwise tail that currently starts with
    a NHWC->NCHW transpose feeding a channel SPLIT.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {"RELU", "RELU6", "RELU_0_TO_1", "LOGISTIC", "HARD_SWISH", "LEAKY_RELU", "TANH", "NEG", "EXP"}
    binary_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM"}

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _is_probably_nhwc_tensor(name: str) -> bool:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or not _is_fully_known_positive_shape(tensor.shape):
            return False
        shape = [int(v) for v in list(tensor.shape)]
        if len(shape) != 4:
            return False
        if int(shape[1]) <= 4 and int(shape[2]) > 4 and int(shape[3]) > 4:
            return False
        return True

    def _rewrite_channel_slice_axis1_to_axis3(op: OperatorIR) -> bool:
        if str(op.op_type) != "SLICE" or len(op.inputs) < 3:
            return False
        begin_tensor = model_ir.tensors.get(str(op.inputs[1]), None)
        size_tensor = model_ir.tensors.get(str(op.inputs[2]), None)
        begin_vals = _read_const_ints_from_tensor(begin_tensor)
        size_vals = _read_const_ints_from_tensor(size_tensor)
        if begin_vals is None or size_vals is None or len(begin_vals) != 4 or len(size_vals) != 4:
            return False
        new_begin = [int(begin_vals[0]), int(begin_vals[2]), int(begin_vals[3]), int(begin_vals[1])]
        new_size = [int(size_vals[0]), int(size_vals[2]), int(size_vals[3]), int(size_vals[1])]
        _write_const_ints_to_tensor(begin_tensor, new_begin)
        _write_const_ints_to_tensor(size_tensor, new_size)
        return True

    while True:
        changed = False
        producers = _build_tensor_producer_map(model_ir)
        consumers = _build_tensor_consumer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            split_users = [int(v) for v in consumers.get(pre_out_name, [])]
            if len(split_users) != 1:
                continue
            split_idx = int(split_users[0])
            split_op = model_ir.operators[int(split_idx)]
            if str(split_op.op_type) != "SPLIT" or len(split_op.inputs) < 2:
                continue
            axis_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(split_op.inputs[0]), None))
            if axis_vals is None or len(axis_vals) != 1 or int(axis_vals[0]) != 1:
                continue

            _replace_operator_input_at(model_ir=model_ir, op=split_op, input_index=1, new_input_name=pre_in_name)
            axis_tensor = model_ir.tensors.get(str(split_op.inputs[0]), None)
            if axis_tensor is not None:
                if set(int(v) for v in consumers.get(str(split_op.inputs[0]), [])) == {int(split_idx)}:
                    _write_const_ints_to_tensor(axis_tensor, [3])

            nhwc_tensors = {str(pre_in_name)}
            for out_name in list(split_op.outputs):
                _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(out_name), None), perm_nchw_to_nhwc)
                nhwc_tensors.add(str(out_name))

            propagated = True
            while propagated:
                propagated = False
                for op in model_ir.operators:
                    if len(op.outputs) != 1:
                        continue
                    out_name = str(op.outputs[0])
                    if out_name in nhwc_tensors:
                        continue
                    op_type = str(op.op_type)
                    if op_type in unary_ops and len(op.inputs) == 1 and str(op.inputs[0]) in nhwc_tensors:
                        _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(out_name, None), perm_nchw_to_nhwc)
                        nhwc_tensors.add(out_name)
                        propagated = True
                        continue
                    if op_type in binary_ops and len(op.inputs) == 2:
                        tensor_inputs = [str(v) for v in list(op.inputs) if model_ir.tensors.get(str(v), None) is not None and model_ir.tensors[str(v)].data is None]
                        if len(tensor_inputs) == 0:
                            continue
                        if all(name in nhwc_tensors or _is_probably_nhwc_tensor(name) for name in tensor_inputs):
                            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(out_name, None), perm_nchw_to_nhwc)
                            nhwc_tensors.add(out_name)
                            propagated = True
                        continue
                    if op_type == "CONCATENATION" and len(op.inputs) > 0 and all(str(v) in nhwc_tensors for v in list(op.inputs)):
                        axis = int(op.options.get("axis", -1))
                        if axis in {1, -3}:
                            op.options["axis"] = 3
                        _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(out_name, None), perm_nchw_to_nhwc)
                        nhwc_tensors.add(out_name)
                        propagated = True
                        continue
                    if op_type == "SPLIT" and len(op.inputs) >= 2 and str(op.inputs[1]) in nhwc_tensors:
                        axis_tensor_local = model_ir.tensors.get(str(op.inputs[0]), None)
                        axis_vals_local = _read_const_ints_from_tensor(axis_tensor_local)
                        if axis_vals_local is None or len(axis_vals_local) != 1 or int(axis_vals_local[0]) not in {1, 3}:
                            continue
                        if int(axis_vals_local[0]) == 1:
                            axis_users = [int(v) for v in consumers.get(str(op.inputs[0]), [])]
                            if set(axis_users) == {int(next(idx for idx, candidate in enumerate(model_ir.operators) if candidate is op))}:
                                _write_const_ints_to_tensor(axis_tensor_local, [3])
                            else:
                                axis_name = _unique_tensor_name(f"{str(op.inputs[0])}_nhwc")
                                model_ir.tensors[axis_name] = TensorIR(
                                    name=axis_name,
                                    dtype=str(axis_tensor_local.dtype),
                                    shape=[1],
                                    shape_signature=[1],
                                    data=np.asarray([3], dtype=np.int32),
                                    is_variable=False,
                                    quantization=_clone_quantization(axis_tensor_local.quantization),
                                )
                                _set_operator_inputs(
                                    model_ir=model_ir,
                                    op=op,
                                    new_inputs=[axis_name, str(op.inputs[1])],
                                )
                        for split_out_name in list(op.outputs):
                            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(split_out_name), None), perm_nchw_to_nhwc)
                            nhwc_tensors.add(str(split_out_name))
                        propagated = True
                        continue
                    if op_type == "SLICE" and len(op.inputs) >= 3 and str(op.inputs[0]) in nhwc_tensors:
                        if _rewrite_channel_slice_axis1_to_axis3(op):
                            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(out_name, None), perm_nchw_to_nhwc)
                            nhwc_tensors.add(out_name)
                            propagated = True

            output_name = str(model_ir.outputs[0]) if len(model_ir.outputs) == 1 else ""
            if output_name != "" and output_name in nhwc_tensors:
                prod_idx = producers.get(output_name, None)
                if prod_idx is not None:
                    prod_op = model_ir.operators[int(prod_idx)]
                    output_nhwc_name = _unique_tensor_name(f"{output_name}_nhwc")
                    out_tensor = model_ir.tensors.get(output_name, None)
                    if out_tensor is not None and _is_fully_known_positive_shape(out_tensor.shape):
                        nhwc_shape = [int(v) for v in list(out_tensor.shape)]
                        nhwc_sig = [int(v) for v in list(out_tensor.shape_signature)] if out_tensor.shape_signature is not None else list(nhwc_shape)
                        model_ir.tensors[output_nhwc_name] = TensorIR(name=output_nhwc_name, dtype=str(out_tensor.dtype), shape=list(nhwc_shape), shape_signature=list(nhwc_sig), data=None, is_variable=False, quantization=_clone_quantization(out_tensor.quantization))
                        _set_operator_outputs(model_ir=model_ir, op=prod_op, new_outputs=[output_nhwc_name])
                        perm_name = _unique_tensor_name(f"{output_name}_perm")
                        model_ir.tensors[perm_name] = TensorIR(name=perm_name, dtype="INT32", shape=[4], shape_signature=[4], data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32), is_variable=False)
                        model_ir.operators.insert(int(prod_idx) + 1, OperatorIR(op_type="TRANSPOSE", inputs=[output_nhwc_name, perm_name], outputs=[output_name], options={}))

            del model_ir.operators[int(pre_idx)]
            optimized += 1
            changed = True
            break

        if not changed:
            break

    if optimized > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_split_channelwise_tail_to_single_post_nchw": int(optimized)}


def _optimize_transpose_binary_split_channelwise_tail_to_single_post_nchw(model_ir: ModelIR) -> Dict[str, int]:
    """
    Propagate NHWC through a local channelwise tail that currently starts with
    NHWC->NCHW TRANSPOSE -> BINARY -> BINARY -> SPLIT.
    """
    optimized = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    unary_ops = {"RELU", "RELU6", "RELU_0_TO_1", "LOGISTIC", "HARD_SWISH", "LEAKY_RELU", "TANH", "NEG", "EXP"}
    binary_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM"}

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _is_probably_nhwc_tensor(name: str) -> bool:
        tensor = model_ir.tensors.get(str(name), None)
        if tensor is None or not _is_fully_known_positive_shape(tensor.shape):
            return False
        shape = [int(v) for v in list(tensor.shape)]
        if len(shape) != 4:
            return False
        if int(shape[1]) <= 4 and int(shape[2]) > 4 and int(shape[3]) > 4:
            return False
        return True

    while True:
        changed = False
        producers = _build_tensor_producer_map(model_ir)
        consumers = _build_tensor_consumer_map(model_ir)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_in_name = str(pre_op.inputs[0])
            pre_out_name = str(pre_op.outputs[0])
            pre_users = [int(v) for v in consumers.get(pre_out_name, [])]
            if len(pre_users) != 1:
                continue
            first_idx = int(pre_users[0])
            first_op = model_ir.operators[int(first_idx)]
            if str(first_op.op_type) not in binary_ops or len(first_op.outputs) != 1:
                continue
            first_out_name = str(first_op.outputs[0])
            second_users = [int(v) for v in consumers.get(first_out_name, [])]
            if len(second_users) != 1:
                continue
            second_idx = int(second_users[0])
            second_op = model_ir.operators[int(second_idx)]
            if str(second_op.op_type) not in binary_ops or len(second_op.outputs) != 1:
                continue
            second_out_name = str(second_op.outputs[0])
            split_users = [int(v) for v in consumers.get(second_out_name, [])]
            if len(split_users) != 1:
                continue
            split_idx = int(split_users[0])
            split_op = model_ir.operators[int(split_idx)]
            if str(split_op.op_type) != "SPLIT" or len(split_op.inputs) < 2:
                continue
            axis_tensor = model_ir.tensors.get(str(split_op.inputs[0]), None)
            axis_vals = _read_const_ints_from_tensor(axis_tensor)
            if axis_vals is None or len(axis_vals) != 1 or int(axis_vals[0]) != 1:
                continue

            ext_tensor_inputs = []
            for candidate_op in [first_op, second_op]:
                for input_name in [str(v) for v in list(candidate_op.inputs)]:
                    if input_name in {pre_out_name, first_out_name, second_out_name}:
                        continue
                    tensor = model_ir.tensors.get(input_name, None)
                    if tensor is None or tensor.data is not None:
                        continue
                    ext_tensor_inputs.append(str(input_name))
            if any(not _is_probably_nhwc_tensor(name) for name in ext_tensor_inputs):
                continue

            _replace_tensor_inputs(model_ir, pre_out_name, pre_in_name)
            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(first_out_name, None), perm_nchw_to_nhwc)
            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(second_out_name, None), perm_nchw_to_nhwc)

            if axis_tensor is not None:
                axis_users = [int(v) for v in consumers.get(str(split_op.inputs[0]), [])]
                if set(axis_users) == {int(split_idx)}:
                    _write_const_ints_to_tensor(axis_tensor, [3])
                else:
                    axis_name = _unique_tensor_name(f"{str(split_op.inputs[0])}_nhwc")
                    model_ir.tensors[axis_name] = TensorIR(
                        name=axis_name,
                        dtype=str(axis_tensor.dtype),
                        shape=[1],
                        shape_signature=[1],
                        data=np.asarray([3], dtype=np.int32),
                        is_variable=False,
                        quantization=_clone_quantization(axis_tensor.quantization),
                    )
                    _set_operator_inputs(model_ir=model_ir, op=split_op, new_inputs=[axis_name, str(split_op.inputs[1])])

            nhwc_tensors = {str(pre_in_name), str(first_out_name), str(second_out_name)}
            for out_name in list(split_op.outputs):
                _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(out_name), None), perm_nchw_to_nhwc)
                nhwc_tensors.add(str(out_name))

            propagated = True
            while propagated:
                propagated = False
                for op in model_ir.operators:
                    if len(op.outputs) != 1:
                        continue
                    out_name = str(op.outputs[0])
                    if out_name in nhwc_tensors:
                        continue
                    op_type = str(op.op_type)
                    if op_type in unary_ops and len(op.inputs) == 1 and str(op.inputs[0]) in nhwc_tensors:
                        _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(out_name, None), perm_nchw_to_nhwc)
                        nhwc_tensors.add(out_name)
                        propagated = True
                        continue
                    if op_type in binary_ops and len(op.inputs) == 2:
                        tensor_inputs = [
                            str(v)
                            for v in list(op.inputs)
                            if model_ir.tensors.get(str(v), None) is not None and model_ir.tensors[str(v)].data is None
                        ]
                        if len(tensor_inputs) == 0:
                            continue
                        if all(name in nhwc_tensors or _is_probably_nhwc_tensor(name) for name in tensor_inputs):
                            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(out_name, None), perm_nchw_to_nhwc)
                            nhwc_tensors.add(out_name)
                            propagated = True
                        continue
                    if op_type == "CONCATENATION" and len(op.inputs) > 0 and all(str(v) in nhwc_tensors for v in list(op.inputs)):
                        axis = int(op.options.get("axis", -1))
                        if axis in {1, -3}:
                            op.options["axis"] = 3
                        _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(out_name, None), perm_nchw_to_nhwc)
                        nhwc_tensors.add(out_name)
                        propagated = True
                        continue
                    if op_type == "SPLIT" and len(op.inputs) >= 2 and str(op.inputs[1]) in nhwc_tensors:
                        axis_tensor_local = model_ir.tensors.get(str(op.inputs[0]), None)
                        axis_vals_local = _read_const_ints_from_tensor(axis_tensor_local)
                        if axis_vals_local is None or len(axis_vals_local) != 1 or int(axis_vals_local[0]) not in {1, 3}:
                            continue
                        if int(axis_vals_local[0]) == 1:
                            axis_users = [int(v) for v in consumers.get(str(op.inputs[0]), [])]
                            op_idx = next((idx for idx, candidate in enumerate(model_ir.operators) if candidate is op), None)
                            if op_idx is None:
                                continue
                            if set(axis_users) == {int(op_idx)}:
                                _write_const_ints_to_tensor(axis_tensor_local, [3])
                            else:
                                axis_name = _unique_tensor_name(f"{str(op.inputs[0])}_nhwc")
                                model_ir.tensors[axis_name] = TensorIR(
                                    name=axis_name,
                                    dtype=str(axis_tensor_local.dtype),
                                    shape=[1],
                                    shape_signature=[1],
                                    data=np.asarray([3], dtype=np.int32),
                                    is_variable=False,
                                    quantization=_clone_quantization(axis_tensor_local.quantization),
                                )
                                _set_operator_inputs(model_ir=model_ir, op=op, new_inputs=[axis_name, str(op.inputs[1])])
                        for split_out_name in list(op.outputs):
                            _permute_tensor_metadata_if_rank_matches(model_ir.tensors.get(str(split_out_name), None), perm_nchw_to_nhwc)
                            nhwc_tensors.add(str(split_out_name))
                        propagated = True

            output_name = str(model_ir.outputs[0]) if len(model_ir.outputs) == 1 else ""
            if output_name != "" and output_name in nhwc_tensors:
                prod_idx = producers.get(output_name, None)
                if prod_idx is not None:
                    prod_op = model_ir.operators[int(prod_idx)]
                    output_nhwc_name = _unique_tensor_name(f"{output_name}_nhwc")
                    out_tensor = model_ir.tensors.get(output_name, None)
                    if out_tensor is not None and _is_fully_known_positive_shape(out_tensor.shape):
                        nhwc_shape = [int(v) for v in list(out_tensor.shape)]
                        nhwc_sig = [int(v) for v in list(out_tensor.shape_signature)] if out_tensor.shape_signature is not None else list(nhwc_shape)
                        model_ir.tensors[output_nhwc_name] = TensorIR(
                            name=output_nhwc_name,
                            dtype=str(out_tensor.dtype),
                            shape=list(nhwc_shape),
                            shape_signature=list(nhwc_sig),
                            data=None,
                            is_variable=False,
                            quantization=_clone_quantization(out_tensor.quantization),
                        )
                        _set_operator_outputs(model_ir=model_ir, op=prod_op, new_outputs=[output_nhwc_name])
                        perm_name = _unique_tensor_name(f"{output_name}_perm")
                        model_ir.tensors[perm_name] = TensorIR(
                            name=perm_name,
                            dtype="INT32",
                            shape=[4],
                            shape_signature=[4],
                            data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                            is_variable=False,
                        )
                        model_ir.operators.insert(
                            int(prod_idx) + 1,
                            OperatorIR(op_type="TRANSPOSE", inputs=[output_nhwc_name, perm_name], outputs=[output_name], options={}),
                        )

            del model_ir.operators[int(pre_idx)]
            optimized += 1
            changed = True
            break

        if not changed:
            break

    if optimized > 0:
        _prune_unused_tensors(model_ir)
    return {"optimized_transpose_binary_split_channelwise_tail_to_single_post_nchw": int(optimized)}


def _sanitize_probable_nhwc_axis_sensitive_ops(model_ir: ModelIR) -> Dict[str, int]:
    """
    Repair late axis-sensitive metadata when tensors are clearly NHWC but still
    carry NCHW-era axis constants or derived shapes.
    """
    rewritten = 0
    inserted_terminal_transposes = 0
    public_layout_map = model_ir.metadata.get("onnx_public_layout_map", {})
    if not isinstance(public_layout_map, dict):
        public_layout_map = {}

    def _unique_tensor_name(base: str) -> str:
        name = str(base)
        suffix = 1
        while name in model_ir.tensors:
            name = f"{base}_{suffix}"
            suffix += 1
        return name

    def _is_probable_nhwc_shape(shape: Optional[List[int]]) -> bool:
        if shape is None or len(shape) != 4:
            return False
        values = [int(v) for v in list(shape)]
        return (
            all(int(v) > 0 for v in values)
            and int(values[1]) > 4
            and int(values[2]) > 4
            and 0 < int(values[3]) <= 8
        )

    def _set_axis_input(op: OperatorIR, op_idx: int, new_axis: int, consumers: Dict[str, List[int]]) -> None:
        axis_name = str(op.inputs[0])
        axis_tensor = model_ir.tensors.get(axis_name, None)
        if axis_tensor is None:
            return
        axis_users = [int(v) for v in consumers.get(axis_name, [])]
        if set(axis_users) == {int(op_idx)}:
            _write_const_ints_to_tensor(axis_tensor, [int(new_axis)])
            return
        clone_name = _unique_tensor_name(f"{axis_name}_nhwc")
        model_ir.tensors[clone_name] = TensorIR(
            name=clone_name,
            dtype=str(axis_tensor.dtype),
            shape=[1],
            shape_signature=[1],
            data=np.asarray([int(new_axis)], dtype=np.int32),
            is_variable=False,
            quantization=_clone_quantization(axis_tensor.quantization),
        )
        _set_operator_inputs(
            model_ir=model_ir,
            op=op,
            new_inputs=[clone_name] + [str(v) for v in list(op.inputs[1:])],
        )

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)

        for op_idx, op in enumerate(model_ir.operators):
            op_type = str(op.op_type)

            if op_type == "SPLIT" and len(op.inputs) >= 2:
                input_name = str(op.inputs[1])
                input_tensor = model_ir.tensors.get(input_name, None)
                axis_vals = _read_const_ints_from_tensor(model_ir.tensors.get(str(op.inputs[0]), None))
                if (
                    input_tensor is not None
                    and _is_probable_nhwc_shape(input_tensor.shape)
                    and axis_vals is not None
                    and len(axis_vals) == 1
                    and int(axis_vals[0]) == 1
                ):
                    input_shape = [int(v) for v in list(input_tensor.shape)]
                    num_splits = int(op.options.get("numSplits", len(list(op.outputs))))
                    if num_splits > 0 and int(input_shape[3]) % int(num_splits) == 0:
                        _set_axis_input(op, int(op_idx), 3, consumers)
                        c_each = int(input_shape[3]) // int(num_splits)
                        for output_name in list(op.outputs):
                            output_tensor = model_ir.tensors.get(str(output_name), None)
                            if output_tensor is not None:
                                output_tensor.shape = [input_shape[0], input_shape[1], input_shape[2], c_each]
                                output_tensor.shape_signature = [input_shape[0], input_shape[1], input_shape[2], c_each]
                        rewritten += 1
                        changed = True
                continue

            if op_type == "CONCATENATION" and len(op.inputs) > 0:
                axis = int(op.options.get("axis", -1))
                input_tensors = [model_ir.tensors.get(str(name), None) for name in list(op.inputs)]
                output_name = str(op.outputs[0]) if len(op.outputs) == 1 else ""
                has_explicit_nchw_input = False
                for input_name in op.inputs:
                    producer_idx = producers.get(str(input_name), None)
                    if producer_idx is None:
                        continue
                    producer_op = model_ir.operators[int(producer_idx)]
                    if (
                        str(producer_op.op_type) == "TRANSPOSE"
                        and _read_transpose_perm(model_ir, producer_op) == [0, 3, 1, 2]
                    ):
                        has_explicit_nchw_input = True
                        break
                if (
                    axis == 1
                    and str(public_layout_map.get(output_name, "")).upper() != "NCHW"
                    and not has_explicit_nchw_input
                    and all(t is not None and _is_probable_nhwc_shape(t.shape) for t in input_tensors)
                ):
                    base = [int(v) for v in list(input_tensors[0].shape)]
                    if all(
                        [int(v) for v in list(t.shape)][:3] == base[:3]
                        for t in input_tensors[1:]
                    ):
                        total_c = sum(int(list(t.shape)[3]) for t in input_tensors if t is not None)
                        op.options["axis"] = 3
                        out_tensor = model_ir.tensors.get(str(op.outputs[0]), None)
                        if out_tensor is not None:
                            out_tensor.shape = [base[0], base[1], base[2], total_c]
                            out_tensor.shape_signature = [base[0], base[1], base[2], total_c]
                        rewritten += 1
                        changed = True
                continue

            if op_type == "SLICE" and len(op.inputs) >= 3:
                input_name = str(op.inputs[0])
                input_tensor = model_ir.tensors.get(input_name, None)
                begin_tensor = model_ir.tensors.get(str(op.inputs[1]), None)
                size_tensor = model_ir.tensors.get(str(op.inputs[2]), None)
                begin_vals = _read_const_ints_from_tensor(begin_tensor)
                size_vals = _read_const_ints_from_tensor(size_tensor)
                if (
                    input_tensor is not None
                    and _is_probable_nhwc_shape(input_tensor.shape)
                    and begin_vals is not None
                    and size_vals is not None
                    and len(begin_vals) == 4
                    and len(size_vals) == 4
                    and int(size_vals[1]) == 1
                    and int(begin_vals[2]) == 0
                    and int(begin_vals[3]) == 0
                ):
                    new_begin = [int(begin_vals[0]), int(begin_vals[2]), int(begin_vals[3]), int(begin_vals[1])]
                    new_size = [int(size_vals[0]), int(size_vals[2]), int(size_vals[3]), int(size_vals[1])]
                    _write_const_ints_to_tensor(begin_tensor, new_begin)
                    _write_const_ints_to_tensor(size_tensor, new_size)
                    input_shape = [int(v) for v in list(input_tensor.shape)]
                    out_tensor = model_ir.tensors.get(str(op.outputs[0]), None)
                    if out_tensor is not None:
                        out_tensor.shape = [input_shape[0], input_shape[1], input_shape[2], int(new_size[3])]
                        out_tensor.shape_signature = [input_shape[0], input_shape[1], input_shape[2], int(new_size[3])]
                    rewritten += 1
                    changed = True
                continue

            if op_type in {"RELU", "RELU6", "RELU_0_TO_1", "LOGISTIC", "HARD_SWISH", "LEAKY_RELU", "TANH", "NEG", "EXP"} and len(op.inputs) == 1:
                input_tensor = model_ir.tensors.get(str(op.inputs[0]), None)
                out_tensor = model_ir.tensors.get(str(op.outputs[0]), None) if len(op.outputs) == 1 else None
                if input_tensor is not None and out_tensor is not None and _is_probable_nhwc_shape(input_tensor.shape):
                    out_tensor.shape = [int(v) for v in list(input_tensor.shape)]
                    out_tensor.shape_signature = [int(v) for v in list(input_tensor.shape_signature)] if input_tensor.shape_signature is not None else [int(v) for v in list(input_tensor.shape)]
                continue

            if op_type in {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM"} and len(op.inputs) == 2 and len(op.outputs) == 1:
                a_tensor = model_ir.tensors.get(str(op.inputs[0]), None)
                b_tensor = model_ir.tensors.get(str(op.inputs[1]), None)
                out_tensor = model_ir.tensors.get(str(op.outputs[0]), None)
                if out_tensor is None:
                    continue
                shapes = []
                for tensor in [a_tensor, b_tensor]:
                    if tensor is not None and tensor.data is None and tensor.shape is not None:
                        shapes.append([int(v) for v in list(tensor.shape)])
                if len(shapes) == 0:
                    continue
                if all(_is_probable_nhwc_shape(shape) or shape in ([1], []) for shape in shapes):
                    inferred = shapes[0]
                    for shape in shapes[1:]:
                        candidate = _broadcast_static_shapes(inferred, shape)
                        if candidate is not None:
                            inferred = [int(v) for v in list(candidate)]
                    if len(inferred) == 4:
                        out_tensor.shape = list(inferred)
                        out_tensor.shape_signature = list(inferred)
                continue

        if not changed:
            break

    if rewritten > 0:
        producers = _build_tensor_producer_map(model_ir)
        for output_name in list(model_ir.outputs):
            output_name = str(output_name)
            output_tensor = model_ir.tensors.get(output_name, None)
            if output_tensor is None or not _is_probable_nhwc_shape(output_tensor.shape):
                continue
            prod_idx = producers.get(output_name, None)
            if prod_idx is None:
                continue
            output_nhwc_name = _unique_tensor_name(f"{output_name}_nhwc")
            nhwc_shape = [int(v) for v in list(output_tensor.shape)]
            nhwc_sig = [int(v) for v in list(output_tensor.shape_signature)] if output_tensor.shape_signature is not None else list(nhwc_shape)
            nchw_shape = [nhwc_shape[0], nhwc_shape[3], nhwc_shape[1], nhwc_shape[2]]
            nchw_sig = [nhwc_sig[0], nhwc_sig[3], nhwc_sig[1], nhwc_sig[2]]
            model_ir.tensors[output_nhwc_name] = TensorIR(
                name=output_nhwc_name,
                dtype=str(output_tensor.dtype),
                shape=list(nhwc_shape),
                shape_signature=list(nhwc_sig),
                data=None,
                is_variable=False,
                quantization=_clone_quantization(output_tensor.quantization),
            )
            _set_operator_outputs(
                model_ir=model_ir,
                op=model_ir.operators[int(prod_idx)],
                new_outputs=[output_nhwc_name],
            )
            perm_name = _unique_tensor_name(f"{output_name}_perm")
            model_ir.tensors[perm_name] = TensorIR(
                name=perm_name,
                dtype="INT32",
                shape=[4],
                shape_signature=[4],
                data=np.asarray([0, 3, 1, 2], dtype=np.int32),
                is_variable=False,
            )
            output_tensor.shape = list(nchw_shape)
            output_tensor.shape_signature = list(nchw_sig)
            model_ir.operators.insert(
                int(prod_idx) + 1,
                OperatorIR(
                    op_type="TRANSPOSE",
                    inputs=[output_nhwc_name, perm_name],
                    outputs=[output_name],
                    options={},
                ),
            )
            inserted_terminal_transposes += 1

    return {
        "sanitized_probable_nhwc_axis_sensitive_ops": int(rewritten),
        "inserted_probable_nhwc_terminal_transposes": int(inserted_terminal_transposes),
    }


def _optimize_transpose_unary_passthrough_chains(model_ir: ModelIR) -> Dict[str, int]:
    return _optimize_transpose_unary_passthrough_chains_pass(model_ir)


def _optimize_transpose_elementwise_roundtrip_nchw_nhwc_chains(model_ir: ModelIR) -> Dict[str, int]:
    """
    Remove NCHW->NHWC->NCHW bridge pairs around a layout-agnostic elementwise subgraph.

    Pattern:
      (one or more) pre_transpose_i:  T(0,2,3,1)(x_i_nchw) -> x_i_nhwc
      elementwise-only subgraph in NHWC
      root_nhwc --T(0,3,1,2)--> root_nchw

    Rewrite:
      - Bypass each pre-transpose into the NHWC elementwise subgraph.
      - Keep the subgraph in NCHW.
      - Remove pre-transposes and the trailing inverse post-transpose.
    """
    rewritten = 0
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    # Restrict to ops whose semantics are independent of channel axis placement.
    allowed_elementwise_ops = {
        "ABS",
        "ADD",
        "DIV",
        "EXP",
        "FLOOR",
        "LOG",
        "MAXIMUM",
        "MINIMUM",
        "MUL",
        "NEG",
        "POW",
        "RSQRT",
        "SIGN",
        "SQRT",
        "SUB",
    }

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for post_idx, post_op in enumerate(model_ir.operators):
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, post_op) != perm_nhwc_to_nchw:
                continue

            root_nhwc_name = str(post_op.inputs[0])
            post_output_name = str(post_op.outputs[0])
            if root_nhwc_name in model_outputs or post_output_name in model_outputs:
                continue

            root_idx = producers.get(root_nhwc_name, None)
            if root_idx is None:
                continue

            # Backward traverse from root producer to collect an elementwise-only subgraph.
            subgraph_indices: set[int] = set()
            pre_transpose_output_to_index: Dict[str, int] = {}
            stack: List[int] = [int(root_idx)]
            valid = True

            while len(stack) > 0 and valid:
                op_idx = int(stack.pop())
                if op_idx in subgraph_indices:
                    continue
                op = model_ir.operators[int(op_idx)]
                if str(op.op_type) not in allowed_elementwise_ops:
                    valid = False
                    break

                subgraph_indices.add(int(op_idx))
                for input_name_raw in list(op.inputs):
                    input_name = str(input_name_raw)
                    prod_idx = producers.get(input_name, None)
                    if prod_idx is None:
                        input_tensor = model_ir.tensors.get(input_name, None)
                        # Allow embedded constants only.
                        if input_tensor is not None and input_tensor.data is not None:
                            continue
                        valid = False
                        break

                    prod_op = model_ir.operators[int(prod_idx)]
                    if (
                        str(prod_op.op_type) == "TRANSPOSE"
                        and len(prod_op.inputs) >= 2
                        and len(prod_op.outputs) == 1
                        and str(prod_op.outputs[0]) == input_name
                        and _read_transpose_perm(model_ir, prod_op) == perm_nchw_to_nhwc
                        and input_name not in model_outputs
                        and str(prod_op.inputs[0]) not in model_outputs
                    ):
                        pre_transpose_output_to_index[str(input_name)] = int(prod_idx)
                        continue

                    if str(prod_op.op_type) in allowed_elementwise_ops:
                        stack.append(int(prod_idx))
                        continue

                    valid = False
                    break

            if not valid or len(pre_transpose_output_to_index) == 0:
                continue

            # Root output must be consumed only by the matched post-transpose.
            if set(int(v) for v in consumers.get(root_nhwc_name, [])) != {int(post_idx)}:
                continue

            # Subgraph outputs must not leak outside subgraph except root->post.
            valid_outputs = True
            for op_idx in list(subgraph_indices):
                op = model_ir.operators[int(op_idx)]
                for output_name_raw in list(op.outputs):
                    output_name = str(output_name_raw)
                    users = set(int(v) for v in consumers.get(output_name, []))
                    if output_name == root_nhwc_name:
                        if users != {int(post_idx)}:
                            valid_outputs = False
                            break
                    else:
                        if not users.issubset(set(int(v) for v in list(subgraph_indices))):
                            valid_outputs = False
                            break
                if not valid_outputs:
                    break
            if not valid_outputs:
                continue

            # Each pre-transpose output must be local to this subgraph.
            valid_pre_consumers = True
            for pre_output_name, _ in pre_transpose_output_to_index.items():
                users = set(int(v) for v in consumers.get(str(pre_output_name), []))
                if len(users) == 0:
                    valid_pre_consumers = False
                    break
                if not users.issubset(set(int(v) for v in list(subgraph_indices))):
                    valid_pre_consumers = False
                    break
            if not valid_pre_consumers:
                continue

            pre_input_map: Dict[str, str] = {}
            for pre_output_name, pre_op_idx in pre_transpose_output_to_index.items():
                pre_op = model_ir.operators[int(pre_op_idx)]
                pre_input_map[str(pre_output_name)] = str(pre_op.inputs[0])

            # Rewire all subgraph inputs from transpose outputs to original NCHW tensors.
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[int(op_idx)]
                new_inputs = [pre_input_map.get(str(v), str(v)) for v in list(op.inputs)]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=op,
                    new_inputs=new_inputs,
                )

            # Subgraph tensors were NHWC; convert metadata to NCHW.
            for op_idx in list(subgraph_indices):
                op = model_ir.operators[int(op_idx)]
                for output_name_raw in list(op.outputs):
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(str(output_name_raw), None),
                        perm_nhwc_to_nchw,
                    )

            # Replace root NHWC output with canonical post-transpose output.
            root_op = model_ir.operators[int(root_idx)]
            _set_operator_outputs(
                model_ir=model_ir,
                op=root_op,
                new_outputs=[post_output_name],
            )
            _replace_tensor_inputs(model_ir, root_nhwc_name, post_output_name)

            old_root_tensor = model_ir.tensors.get(root_nhwc_name, None)
            canonical_tensor = model_ir.tensors.get(post_output_name, None)
            if old_root_tensor is not None and canonical_tensor is not None:
                canonical_tensor.dtype = str(old_root_tensor.dtype)
                canonical_tensor.quantization = _clone_quantization(old_root_tensor.quantization)
                canonical_tensor.shape = [int(v) for v in list(old_root_tensor.shape)]
                canonical_tensor.shape_signature = (
                    [int(v) for v in list(old_root_tensor.shape_signature)]
                    if old_root_tensor.shape_signature is not None
                    else [int(v) for v in list(old_root_tensor.shape)]
                )
                _permute_tensor_metadata_if_rank_matches(
                    canonical_tensor,
                    perm_nhwc_to_nchw,
                )

            remove_indices = set([int(post_idx)])
            remove_indices.update(int(v) for v in list(pre_transpose_output_to_index.values()))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_elementwise_roundtrip_nchw_nhwc_chains": int(rewritten)}


def _optimize_transpose_elementwise_roundtrip_nhwc_nchw_fanout_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove NHWC->NCHW and inverse NCHW->NHWC transpose bridges around an
    elementwise-only fanout subgraph.

    Pattern:
      x_nhwc --T(0,3,1,2)--> x_nchw
      x_nchw --(elementwise DAG; const side inputs allowed)--> y*_nchw
      y*_nchw --T(0,2,3,1)--> y*_nhwc

    Rewrite:
      - Keep the full elementwise DAG in NHWC by bypassing the leading transpose.
      - Remove all trailing inverse transposes at subgraph boundaries.

    Safety:
      - Subgraph ops are limited to layout-agnostic elementwise ops.
      - Per-channel rank-4 constants are remapped only when they are local to the subgraph.
      - Legacy NCHW users are preserved via local adapter TRANSPOSE ops.
    """
    rewritten = 0
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    allowed_elementwise_ops = {
        "ABS",
        "ADD",
        "DIV",
        "ERF",
        "EXP",
        "FLOOR",
        "LOG",
        "MAXIMUM",
        "MINIMUM",
        "MUL",
        "NEG",
        "POW",
        "RSQRT",
        "SIGN",
        "SQRT",
        "SUB",
    }

    def _unique_tensor_name(base_name: str) -> str:
        candidate = str(base_name)
        serial = 0
        while candidate in model_ir.tensors:
            serial += 1
            candidate = f"{base_name}_{serial}"
        return candidate

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue

            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            # Forward-collect elementwise-only reachable ops.
            subgraph_indices: set[int] = set()
            frontier_tensors: List[str] = [pre_output_name]
            seen_tensors: set[str] = {pre_output_name}
            while len(frontier_tensors) > 0:
                current_tensor = str(frontier_tensors.pop())
                for user_idx_raw in consumers.get(current_tensor, []):
                    user_idx = int(user_idx_raw)
                    user_op = model_ir.operators[user_idx]
                    if str(user_op.op_type) not in allowed_elementwise_ops:
                        continue
                    if user_idx in subgraph_indices:
                        continue
                    subgraph_indices.add(user_idx)
                    for out_name_raw in list(user_op.outputs):
                        out_name = str(out_name_raw)
                        if out_name not in seen_tensors:
                            seen_tensors.add(out_name)
                            frontier_tensors.append(out_name)

            if len(subgraph_indices) == 0:
                continue

            # Validate local shape and collect runtime inputs coming from outside
            # the local elementwise region. Those external NCHW tensors are
            # adapted locally into NHWC.
            valid = True
            external_runtime_inputs: set[str] = set()
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[op_idx]
                if len(op.outputs) != 1:
                    valid = False
                    break
                for input_name_raw in list(op.inputs):
                    input_name = str(input_name_raw)
                    input_tensor = model_ir.tensors.get(input_name, None)
                    if input_tensor is not None and input_tensor.data is not None:
                        continue

                    if input_name == pre_output_name:
                        continue

                    prod_idx = producers.get(input_name, None)
                    if prod_idx is None or int(prod_idx) not in subgraph_indices:
                        external_runtime_inputs.add(str(input_name))
                if not valid:
                    break
            if not valid:
                continue

            # Ensure pre-transpose output is consumed only by this local subgraph.
            pre_users = set(int(v) for v in consumers.get(pre_output_name, []))
            if len(pre_users) == 0 or not pre_users.issubset(subgraph_indices):
                continue

            # Detect subgraph boundaries and classify external users:
            # - inverse post-transpose consumers (remove)
            # - legacy users (preserve via NHWC->NCHW adapter)
            boundary_posts: Dict[str, List[int]] = {}
            boundary_legacy_users: Dict[str, List[int]] = {}
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[op_idx]
                out_name = str(op.outputs[0])
                if out_name in model_outputs:
                    valid = False
                    break

                users = set(int(v) for v in consumers.get(out_name, []))
                external_users = sorted(list(users - subgraph_indices))
                if len(external_users) == 0:
                    continue

                for user_idx in external_users:
                    user_op = model_ir.operators[int(user_idx)]
                    if (
                        str(user_op.op_type) != "TRANSPOSE"
                        or len(user_op.inputs) < 2
                        or len(user_op.outputs) != 1
                        or str(user_op.inputs[0]) != out_name
                    ):
                        boundary_legacy_users.setdefault(out_name, []).append(int(user_idx))
                        continue
                    if (
                        _read_transpose_perm(model_ir, user_op) == perm_nchw_to_nhwc
                        and str(user_op.outputs[0]) not in model_outputs
                    ):
                        boundary_posts.setdefault(out_name, []).append(int(user_idx))
                    else:
                        boundary_legacy_users.setdefault(out_name, []).append(int(user_idx))
                if not valid:
                    break
            if not valid:
                continue
            if sum(len(v) for v in boundary_posts.values()) <= 0:
                continue
            # Conservative guard:
            # Rewriting mixed fanout islands that require external runtime
            # NCHW->NHWC adapter insertion has produced dangling `__to_nhwc`
            # tensors in some large graphs (e.g. network.7 branches).
            # Skip this candidate and leave it to other safer transpose passes.
            if len(external_runtime_inputs) > 0:
                continue

            # Safety guard:
            # This pass can be very aggressive on wide fanout graphs. Snapshot one
            # candidate rewrite and roll back if it introduces new unbound runtime
            # inputs (which later appears as "Input tensor N lacks data").
            candidate_snapshot = copy.deepcopy(model_ir)
            unbound_before_count = int(len(_find_unbound_nonconstant_operator_inputs(model_ir)))
            def _rollback_candidate() -> None:
                model_ir.tensors = candidate_snapshot.tensors
                model_ir.operators = candidate_snapshot.operators
                model_ir.inputs = candidate_snapshot.inputs
                model_ir.outputs = candidate_snapshot.outputs
                model_ir.subgraphs = candidate_snapshot.subgraphs
                model_ir.metadata = candidate_snapshot.metadata

            # Remap per-channel rank-4 constants from NCHW->NHWC where required.
            remapped_const_names: set[str] = set()
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[op_idx]
                runtime_input_names = []
                const_input_names = []
                for input_name_raw in list(op.inputs):
                    input_name = str(input_name_raw)
                    input_tensor = model_ir.tensors.get(input_name, None)
                    if input_tensor is not None and input_tensor.data is not None:
                        const_input_names.append(input_name)
                    else:
                        runtime_input_names.append(input_name)
                if len(runtime_input_names) == 0:
                    continue

                ref_name = next((name for name in runtime_input_names if name == pre_output_name), runtime_input_names[0])
                ref_tensor = model_ir.tensors.get(str(ref_name), None)
                if ref_tensor is None or ref_tensor.shape is None or len(list(ref_tensor.shape)) != 4:
                    continue
                ref_shape_nchw = [int(v) for v in list(ref_tensor.shape)]
                if any(int(v) <= 0 for v in ref_shape_nchw):
                    continue
                ref_shape_nhwc = _permute_shape(ref_shape_nchw, perm_nchw_to_nhwc)
                if ref_shape_nhwc is None:
                    continue

                for const_name in const_input_names:
                    if const_name in remapped_const_names:
                        continue
                    const_tensor = model_ir.tensors.get(str(const_name), None)
                    if const_tensor is None or const_tensor.data is None:
                        continue
                    const_data = np.asarray(const_tensor.data)
                    if int(const_data.ndim) != 4:
                        continue
                    const_shape = [int(v) for v in list(const_data.shape)]
                    # Strictly target NCHW per-channel broadcast constants [1,C,1,1].
                    if not (
                        const_shape[0] == 1
                        and const_shape[1] == ref_shape_nchw[1]
                        and const_shape[2] == 1
                        and const_shape[3] == 1
                    ):
                        continue
                    # Shared constants cannot be remapped safely because non-local
                    # users still expect NCHW semantics.
                    const_users = set(int(v) for v in consumers.get(str(const_name), []))
                    rotated_data = np.transpose(const_data, axes=perm_nchw_to_nhwc)
                    rotated_shape = [int(v) for v in list(rotated_data.shape)]
                    if _broadcast_static_shapes(ref_shape_nhwc, rotated_shape) is None:
                        valid = False
                        break
                    if const_users.issubset(subgraph_indices):
                        const_tensor.data = rotated_data.astype(const_data.dtype, copy=False)
                        const_tensor.shape = [int(v) for v in list(rotated_shape)]
                        const_tensor.shape_signature = (
                            [int(v) for v in list(rotated_shape)]
                            if const_tensor.shape_signature is None
                            else [int(v) for v in list(rotated_shape)]
                        )
                        remapped_const_names.add(str(const_name))
                    else:
                        # Shared constants are cloned for this rewritten branch.
                        clone_name = _unique_tensor_name(f"{const_name}__nhwc")
                        model_ir.tensors[str(clone_name)] = TensorIR(
                            name=str(clone_name),
                            dtype=str(const_tensor.dtype),
                            shape=[int(v) for v in list(rotated_shape)],
                            shape_signature=[int(v) for v in list(rotated_shape)],
                            data=rotated_data.astype(const_data.dtype, copy=False),
                            is_variable=False,
                            quantization=_clone_quantization(const_tensor.quantization),
                        )
                        op_inputs = [str(v) for v in list(op.inputs)]
                        op_inputs = [str(clone_name) if str(v) == str(const_name) else str(v) for v in op_inputs]
                        _set_operator_inputs(
                            model_ir=model_ir,
                            op=op,
                            new_inputs=op_inputs,
                        )
                        remapped_const_names.add(str(clone_name))
                if not valid:
                    break
            if not valid:
                _rollback_candidate()
                continue

            # Rewire all subgraph inputs from pre-transpose output to NHWC source.
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[int(op_idx)]
                new_inputs = [
                    pre_input_name if str(v) == pre_output_name else str(v)
                    for v in list(op.inputs)
                ]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=op,
                    new_inputs=new_inputs,
                )

            # Bridge external NCHW runtime inputs into NHWC for rewritten ops.
            if len(external_runtime_inputs) > 0:
                for external_input_name in sorted(list(external_runtime_inputs)):
                    external_tensor = model_ir.tensors.get(str(external_input_name), None)
                    if (
                        external_tensor is None
                        or external_tensor.shape is None
                        or len(list(external_tensor.shape)) != 4
                    ):
                        valid = False
                        break
                    source_shape = [int(v) for v in list(external_tensor.shape)]
                    target_shape = _permute_shape(source_shape, perm_nchw_to_nhwc)
                    if target_shape is None:
                        valid = False
                        break
                    adapter_perm_name = _unique_tensor_name(
                        f"{external_input_name}__to_nhwc_perm",
                    )
                    adapter_output_name = _unique_tensor_name(
                        f"{external_input_name}__to_nhwc",
                    )
                    model_ir.tensors[str(adapter_perm_name)] = TensorIR(
                        name=str(adapter_perm_name),
                        dtype="INT32",
                        shape=[4],
                        shape_signature=[4],
                        data=np.asarray(perm_nchw_to_nhwc, dtype=np.int32),
                        is_variable=False,
                        quantization=None,
                    )
                    model_ir.tensors[str(adapter_output_name)] = TensorIR(
                        name=str(adapter_output_name),
                        dtype=str(external_tensor.dtype),
                        shape=[int(v) for v in list(target_shape)],
                        shape_signature=[int(v) for v in list(target_shape)],
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(external_tensor.quantization),
                    )
                    model_ir.operators.append(
                        OperatorIR(
                            op_type="TRANSPOSE",
                            inputs=[str(external_input_name), str(adapter_perm_name)],
                            outputs=[str(adapter_output_name)],
                        )
                    )
                    for op_idx in sorted(list(subgraph_indices)):
                        op = model_ir.operators[int(op_idx)]
                        new_inputs = [
                            str(adapter_output_name) if str(v) == str(external_input_name) else str(v)
                            for v in list(op.inputs)
                        ]
                        _set_operator_inputs(
                            model_ir=model_ir,
                            op=op,
                            new_inputs=new_inputs,
                        )
            if not valid:
                _rollback_candidate()
                continue

            # Subgraph tensors were NCHW; convert metadata to NHWC.
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[int(op_idx)]
                out_name = str(op.outputs[0])
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(out_name, None),
                    perm_nchw_to_nhwc,
                )

            # Final broadcast-safety guard:
            # if an elementwise op now consumes NHWC data with a legacy
            # [1,C,1,1] constant, rotate (or clone+rotate) that constant.
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[int(op_idx)]
                if str(op.op_type) not in {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM", "POW"}:
                    continue
                input_names = [str(v) for v in list(op.inputs)]
                for const_input_name in list(input_names):
                    const_tensor = model_ir.tensors.get(str(const_input_name), None)
                    if const_tensor is None or const_tensor.data is None:
                        continue
                    const_data = np.asarray(const_tensor.data)
                    if int(const_data.ndim) != 4:
                        continue
                    data_input_name = next((name for name in input_names if str(name) != str(const_input_name)), None)
                    if data_input_name is None:
                        continue
                    data_tensor = model_ir.tensors.get(str(data_input_name), None)
                    if data_tensor is None or data_tensor.shape is None or len(list(data_tensor.shape)) != 4:
                        continue
                    data_shape = [int(v) for v in list(data_tensor.shape)]
                    if any(int(v) <= 0 for v in data_shape):
                        continue
                    const_shape = [int(v) for v in list(const_data.shape)]
                    if _broadcast_static_shapes(data_shape, const_shape) is not None:
                        continue
                    rotated_data = np.transpose(const_data, axes=perm_nchw_to_nhwc)
                    rotated_shape = [int(v) for v in list(rotated_data.shape)]
                    if _broadcast_static_shapes(data_shape, rotated_shape) is None:
                        continue
                    const_users = set(int(v) for v in consumers.get(str(const_input_name), []))
                    if const_users.issubset(subgraph_indices):
                        const_tensor.data = rotated_data.astype(const_data.dtype, copy=False)
                        const_tensor.shape = [int(v) for v in list(rotated_shape)]
                        const_tensor.shape_signature = [int(v) for v in list(rotated_shape)]
                    else:
                        clone_name = _unique_tensor_name(f"{const_input_name}__nhwc")
                        model_ir.tensors[str(clone_name)] = TensorIR(
                            name=str(clone_name),
                            dtype=str(const_tensor.dtype),
                            shape=[int(v) for v in list(rotated_shape)],
                            shape_signature=[int(v) for v in list(rotated_shape)],
                            data=rotated_data.astype(const_data.dtype, copy=False),
                            is_variable=False,
                            quantization=_clone_quantization(const_tensor.quantization),
                        )
                        _set_operator_inputs(
                            model_ir=model_ir,
                            op=op,
                            new_inputs=[
                                str(clone_name) if str(v) == str(const_input_name) else str(v)
                                for v in list(op.inputs)
                            ],
                        )

            # Replace each boundary with one canonical post-transpose output.
            post_indices_to_remove: set[int] = set()
            boundary_output_names = sorted(
                set(list(boundary_posts.keys()) + list(boundary_legacy_users.keys()))
            )
            for boundary_name in boundary_output_names:
                post_indices = [int(v) for v in list(boundary_posts.get(boundary_name, []))]
                legacy_users = [int(v) for v in list(boundary_legacy_users.get(boundary_name, []))]
                producer_idx = producers.get(str(boundary_name), None)
                if producer_idx is None or int(producer_idx) not in subgraph_indices:
                    valid = False
                    break
                producer_op = model_ir.operators[int(producer_idx)]
                if len(producer_op.outputs) != 1 or str(producer_op.outputs[0]) != str(boundary_name):
                    valid = False
                    break

                if len(post_indices) > 0:
                    canonical_post_idx = int(sorted(set(int(v) for v in post_indices))[0])
                    canonical_post_op = model_ir.operators[canonical_post_idx]
                    canonical_output_name = str(canonical_post_op.outputs[0])
                else:
                    canonical_post_idx = None
                    canonical_output_name = _unique_tensor_name(f"{boundary_name}__nhwc")
                    old_boundary_tensor = model_ir.tensors.get(str(boundary_name), None)
                    if old_boundary_tensor is not None:
                        model_ir.tensors[str(canonical_output_name)] = TensorIR(
                            name=str(canonical_output_name),
                            dtype=str(old_boundary_tensor.dtype),
                            shape=[int(v) for v in list(old_boundary_tensor.shape)],
                            shape_signature=(
                                [int(v) for v in list(old_boundary_tensor.shape_signature)]
                                if old_boundary_tensor.shape_signature is not None
                                else [int(v) for v in list(old_boundary_tensor.shape)]
                            ),
                            data=None,
                            is_variable=False,
                            quantization=_clone_quantization(old_boundary_tensor.quantization),
                        )

                _set_operator_outputs(
                    model_ir=model_ir,
                    op=producer_op,
                    new_outputs=[canonical_output_name],
                )
                _replace_tensor_inputs(model_ir, str(boundary_name), canonical_output_name)

                old_boundary_tensor = model_ir.tensors.get(str(boundary_name), None)
                canonical_tensor = model_ir.tensors.get(canonical_output_name, None)
                if old_boundary_tensor is not None and canonical_tensor is not None:
                    canonical_tensor.dtype = str(old_boundary_tensor.dtype)
                    canonical_tensor.quantization = _clone_quantization(old_boundary_tensor.quantization)
                    canonical_tensor.shape = [int(v) for v in list(old_boundary_tensor.shape)]
                    canonical_tensor.shape_signature = (
                        [int(v) for v in list(old_boundary_tensor.shape_signature)]
                        if old_boundary_tensor.shape_signature is not None
                        else [int(v) for v in list(old_boundary_tensor.shape)]
                    )

                for post_idx in sorted(set(int(v) for v in list(post_indices))):
                    post_indices_to_remove.add(int(post_idx))
                    if canonical_post_idx is not None and int(post_idx) == int(canonical_post_idx):
                        continue
                    post_output_name = str(model_ir.operators[int(post_idx)].outputs[0])
                    _replace_tensor_inputs(model_ir, post_output_name, canonical_output_name)

                # Preserve external NCHW users by appending a local NHWC->NCHW adapter.
                if len(legacy_users) > 0:
                    adapter_perm_name = _unique_tensor_name(
                        f"{boundary_name}__to_nchw_perm",
                    )
                    adapter_output_name = str(boundary_name)
                    canonical_tensor = model_ir.tensors.get(str(canonical_output_name), None)
                    if canonical_tensor is None or canonical_tensor.shape is None:
                        valid = False
                        break
                    canonical_shape = [int(v) for v in list(canonical_tensor.shape)]
                    legacy_shape = _permute_shape(canonical_shape, perm_nhwc_to_nchw)
                    if legacy_shape is None:
                        valid = False
                        break
                    model_ir.tensors[str(adapter_perm_name)] = TensorIR(
                        name=str(adapter_perm_name),
                        dtype="INT32",
                        shape=[4],
                        shape_signature=[4],
                        data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                        is_variable=False,
                        quantization=None,
                    )
                    model_ir.tensors[str(adapter_output_name)] = TensorIR(
                        name=str(adapter_output_name),
                        dtype=str(canonical_tensor.dtype),
                        shape=[int(v) for v in list(legacy_shape)],
                        shape_signature=[int(v) for v in list(legacy_shape)],
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(canonical_tensor.quantization),
                    )
                    model_ir.operators.append(
                        OperatorIR(
                            op_type="TRANSPOSE",
                            inputs=[str(canonical_output_name), str(adapter_perm_name)],
                            outputs=[str(adapter_output_name)],
                        )
                    )
                    # Restore legacy users to NCHW tensor name.
                    for legacy_idx in list(legacy_users):
                        legacy_op = model_ir.operators[int(legacy_idx)]
                        new_inputs = [
                            str(adapter_output_name) if str(v) == str(canonical_output_name) else str(v)
                            for v in list(legacy_op.inputs)
                        ]
                        _set_operator_inputs(
                            model_ir=model_ir,
                            op=legacy_op,
                            new_inputs=new_inputs,
                        )

            if not valid:
                _rollback_candidate()
                continue

            remove_indices = set([int(pre_idx)])
            remove_indices.update(int(v) for v in list(post_indices_to_remove))
            for remove_idx in sorted(list(remove_indices), reverse=True):
                del model_ir.operators[int(remove_idx)]

            unbound_after_count = int(len(_find_unbound_nonconstant_operator_inputs(model_ir)))
            if unbound_after_count > unbound_before_count:
                _rollback_candidate()
                continue

            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_transpose_elementwise_roundtrip_nhwc_nchw_fanout_chains": int(rewritten)}


def _repair_rank4_channelwise_broadcast_constants_to_runtime_layout(
    model_ir: ModelIR,
    *,
    graph_index: Optional[ModelIRGraphIndex] = None,
) -> Dict[str, int]:
    """
    Repair channelwise constants that became layout-misaligned after
    transpose/layout rewrites.

    If a binary op consumes rank-4 runtime data tensor `X` and a rank-3/4
    channelwise constant `C` where:
      - as-is broadcast does not preserve `X` shape
      - NHWC-rotated broadcast preserves `X` shape
    then rotate `C` to NHWC layout. Shared constants are cloned.
    """
    repaired = 0
    binary_ops = {"ADD", "SUB", "MUL", "DIV", "MAXIMUM", "MINIMUM", "POW"}
    graph_index = (
        graph_index
        if graph_index is not None and graph_index.model_ir is model_ir
        else ModelIRGraphIndex(model_ir)
    )
    consumer_indices_snapshot = {
        str(tensor_name): tuple(int(index) for index in indices)
        for tensor_name, indices in graph_index.consumers.items()
    }

    def _unique_tensor_name(base_name: str) -> str:
        candidate = str(base_name)
        serial = 0
        while candidate in model_ir.tensors:
            serial += 1
            candidate = f"{base_name}_{serial}"
        return candidate

    def _prefer_runtime_layout_for_rank4_data_tensor(data_tensor_name: str) -> Optional[str]:
        name = str(data_tensor_name)
        data_tensor = model_ir.tensors.get(name, None)
        if data_tensor is not None:
            logical_layout = str(getattr(data_tensor, "logical_layout", "") or "").upper()
            if logical_layout in {"NHWC", "NCHW"}:
                return logical_layout
        lower_name = name.lower()
        if lower_name.endswith("_nhwc"):
            return "NHWC"
        if lower_name.endswith("_nchw"):
            return "NCHW"
        producer_op = graph_index.producer(name)
        if producer_op is None:
            return None
        producer_op_type = str(producer_op.op_type)
        if producer_op_type in {
            "CONV_2D",
            "DEPTHWISE_CONV_2D",
            "TRANSPOSE_CONV",
            "AVERAGE_POOL_2D",
            "MAX_POOL_2D",
            "RESIZE_BILINEAR",
            "RESIZE_NEAREST_NEIGHBOR",
        }:
            return "NHWC"
        return None

    for operator_index in graph_index.operator_indices_for_types(binary_ops):
        op = model_ir.operators[int(operator_index)]
        if len(op.inputs) != 2:
            continue
        input_names = [str(v) for v in list(op.inputs)]

        for const_input_name in list(input_names):
            const_tensor = model_ir.tensors.get(str(const_input_name), None)
            if const_tensor is None or const_tensor.data is None:
                continue
            const_data = np.asarray(const_tensor.data)
            if int(const_data.ndim) not in {3, 4}:
                continue

            data_input_name = next((name for name in input_names if str(name) != str(const_input_name)), None)
            if data_input_name is None:
                continue
            data_tensor = model_ir.tensors.get(str(data_input_name), None)
            if data_tensor is None or data_tensor.shape is None or len(list(data_tensor.shape)) != 4:
                continue
            data_shape = [int(v) for v in list(data_tensor.shape)]
            if any(int(v) <= 0 for v in data_shape):
                continue

            const_shape = [int(v) for v in list(const_data.shape)]
            as_is_broadcast = _broadcast_static_shapes(data_shape, const_shape)

            rotated_data: Optional[np.ndarray] = None
            if int(const_data.ndim) == 4:
                rotated_data = np.transpose(const_data, axes=[0, 2, 3, 1])
            elif (
                int(const_data.ndim) == 3
                and int(const_shape[0]) > 0
                and int(const_shape[1]) == 1
                and int(const_shape[2]) == 1
            ):
                rotated_data = np.transpose(const_data, axes=[1, 2, 0])
            else:
                continue

            rotated_shape = [int(v) for v in list(rotated_data.shape)]
            rotated_broadcast = _broadcast_static_shapes(data_shape, rotated_shape)
            if (
                (rotated_broadcast is None or rotated_broadcast != data_shape)
                and int(const_data.ndim) == 4
            ):
                # A previous NHWC rewrite can become stale after later shape
                # reconciliation.  Try the exact inverse standard layout
                # permutation and accept it only when it restores the runtime
                # broadcast equation.
                inverse_rotated_data = np.transpose(
                    const_data,
                    axes=[0, 3, 1, 2],
                )
                inverse_rotated_shape = [
                    int(v) for v in list(inverse_rotated_data.shape)
                ]
                inverse_broadcast = _broadcast_static_shapes(
                    data_shape,
                    inverse_rotated_shape,
                )
                if inverse_broadcast == data_shape:
                    rotated_data = inverse_rotated_data
                    rotated_shape = inverse_rotated_shape
                    rotated_broadcast = inverse_broadcast
            if rotated_broadcast is None or rotated_broadcast != data_shape:
                continue
            force_rotate_even_if_ambiguous = False
            if as_is_broadcast == data_shape and int(const_data.ndim) in {3, 4}:
                # Ambiguous case:
                # [1,C,1,1] can broadcast to NHWC [N,H,W,C] when H==C, but this
                # semantically applies scale over height, not channel.
                # If runtime data layout is NHWC, prefer [1,1,1,C].
                preferred_layout = _prefer_runtime_layout_for_rank4_data_tensor(
                    data_input_name
                )
                if (
                    preferred_layout == "NHWC"
                    and int(const_data.ndim) == 4
                    and int(const_shape[0]) == 1
                    and int(const_shape[1]) > 1
                    and int(const_shape[2]) == 1
                    and int(const_shape[3]) == 1
                    and int(rotated_shape[0]) == 1
                    and int(rotated_shape[1]) == 1
                    and int(rotated_shape[2]) == 1
                    and int(rotated_shape[3]) > 1
                ):
                    force_rotate_even_if_ambiguous = True
                elif (
                    preferred_layout == "NHWC"
                    and int(const_data.ndim) == 3
                    and int(const_shape[0]) > 1
                    and int(const_shape[1]) == 1
                    and int(const_shape[2]) == 1
                    and int(rotated_shape[0]) == 1
                    and int(rotated_shape[1]) == 1
                    and int(rotated_shape[2]) == int(const_shape[0])
                    and int(data_shape[3]) == int(const_shape[0])
                ):
                    force_rotate_even_if_ambiguous = True
            if as_is_broadcast == data_shape and not force_rotate_even_if_ambiguous:
                continue

            const_users = set(
                consumer_indices_snapshot.get(str(const_input_name), ())
            )
            if len(const_users) <= 1:
                const_tensor.data = rotated_data.astype(const_data.dtype, copy=False)
                const_tensor.shape = [int(v) for v in list(rotated_shape)]
                const_tensor.shape_signature = [int(v) for v in list(rotated_shape)]
            else:
                clone_name = _unique_tensor_name(f"{const_input_name}__nhwc")
                model_ir.tensors[str(clone_name)] = TensorIR(
                    name=str(clone_name),
                    dtype=str(const_tensor.dtype),
                    shape=[int(v) for v in list(rotated_shape)],
                    shape_signature=[int(v) for v in list(rotated_shape)],
                    data=rotated_data.astype(const_data.dtype, copy=False),
                    is_variable=False,
                    quantization=_clone_quantization(const_tensor.quantization),
                )
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=op,
                    new_inputs=[
                        str(clone_name) if str(v) == str(const_input_name) else str(v)
                        for v in list(op.inputs)
                    ],
                    graph_index=graph_index,
                )

            repaired += 1
            break

    return {"repaired_rank4_channelwise_broadcast_constants": int(repaired)}


def _repair_decomposed_instance_normalization_layouts(
    model_ir: ModelIR,
) -> Dict[str, int]:
    repaired = 0
    consumers = _build_tensor_consumer_map(model_ir)

    def _single_consumer_index(tensor_name: str) -> Optional[int]:
        users = [int(v) for v in consumers.get(str(tensor_name), [])]
        if len(users) != 1:
            return None
        return int(users[0])

    def _set_shape_metadata(tensor_name: str, shape: List[int]) -> bool:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None:
            return False
        changed = False
        normalized_shape = [int(v) for v in list(shape)]
        if [int(v) for v in list(tensor.shape)] != normalized_shape:
            tensor.shape = list(normalized_shape)
            changed = True
        if tensor.shape_signature is not None:
            if [int(v) for v in list(tensor.shape_signature)] != normalized_shape:
                tensor.shape_signature = list(normalized_shape)
                changed = True
        return changed

    def _reshape_channelwise_const(tensor_name: str, broadcast_shape: List[int]) -> bool:
        tensor = model_ir.tensors.get(str(tensor_name), None)
        if tensor is None or tensor.data is None:
            return False
        data = np.asarray(tensor.data)
        if int(data.size) <= 1:
            return False
        if int(np.prod(np.asarray(broadcast_shape), dtype=np.int64)) != int(data.size):
            return False
        reshaped = np.asarray(data.reshape(broadcast_shape), dtype=data.dtype)
        changed = False
        if list(data.shape) != list(reshaped.shape) or not np.array_equal(data, reshaped):
            tensor.data = reshaped
            changed = True
        if [int(v) for v in list(tensor.shape)] != [int(v) for v in list(reshaped.shape)]:
            tensor.shape = [int(v) for v in list(reshaped.shape)]
            changed = True
        reshaped_shape = [int(v) for v in list(reshaped.shape)]
        if tensor.shape_signature is not None:
            if [int(v) for v in list(tensor.shape_signature)] != reshaped_shape:
                tensor.shape_signature = list(reshaped_shape)
                changed = True
        return changed

    for mean1_idx, mean1_op in enumerate(list(model_ir.operators)):
        if str(mean1_op.op_type) != "MEAN" or len(mean1_op.inputs) != 2 or len(mean1_op.outputs) != 1:
            continue
        if str(getattr(mean1_op, "onnx_op_type", "")) != "InstanceNormalization":
            continue
        x_name = str(mean1_op.inputs[0])
        x_tensor = model_ir.tensors.get(x_name, None)
        if x_tensor is None:
            continue
        x_shape = [int(v) for v in list(x_tensor.shape)]
        rank = len(x_shape)
        if rank not in {3, 4, 5}:
            continue
        x_layout = normalize_logical_layout(getattr(x_tensor, "logical_layout", None))
        if is_channel_first_logical_layout(x_layout):
            channel_axis = 1
        elif is_channel_last_logical_layout(x_layout):
            channel_axis = rank - 1
        else:
            continue
        desired_axes = [int(axis) for axis in range(1, rank) if int(axis) != int(channel_axis)]
        axes_name = str(mean1_op.inputs[1])
        axes_values = _read_const_ints_from_tensor(model_ir.tensors.get(axes_name, None))
        if axes_values is None:
            continue

        mean1_out_name = str(mean1_op.outputs[0])
        sub_idx = None
        for user_idx in consumers.get(x_name, []):
            user_op = model_ir.operators[int(user_idx)]
            if (
                str(user_op.op_type) == "SUB"
                and len(user_op.inputs) == 2
                and len(user_op.outputs) == 1
                and x_name in {str(user_op.inputs[0]), str(user_op.inputs[1])}
                and mean1_out_name in {str(user_op.inputs[0]), str(user_op.inputs[1])}
            ):
                sub_idx = int(user_idx)
                break
        if sub_idx is None:
            continue
        centered_name = str(model_ir.operators[int(sub_idx)].outputs[0])

        mul_square_idx = None
        mul_norm_idx = None
        for user_idx in consumers.get(centered_name, []):
            user_op = model_ir.operators[int(user_idx)]
            if str(user_op.op_type) != "MUL" or len(user_op.inputs) != 2 or len(user_op.outputs) != 1:
                continue
            in0 = str(user_op.inputs[0])
            in1 = str(user_op.inputs[1])
            if in0 == centered_name and in1 == centered_name:
                mul_square_idx = int(user_idx)
            elif centered_name in {in0, in1}:
                mul_norm_idx = int(user_idx)
        if mul_square_idx is None or mul_norm_idx is None:
            continue

        squared_name = str(model_ir.operators[int(mul_square_idx)].outputs[0])
        mean2_idx = _single_consumer_index(squared_name)
        if mean2_idx is None:
            continue
        mean2_op = model_ir.operators[int(mean2_idx)]
        if str(mean2_op.op_type) != "MEAN" or len(mean2_op.inputs) != 2 or len(mean2_op.outputs) != 1:
            continue
        mean2_axes_name = str(mean2_op.inputs[1])
        mean2_axes_values = _read_const_ints_from_tensor(model_ir.tensors.get(mean2_axes_name, None))
        if mean2_axes_values is None:
            continue

        mean2_out_name = str(mean2_op.outputs[0])
        add_eps_idx = _single_consumer_index(mean2_out_name)
        if add_eps_idx is None:
            continue
        add_eps_out_name = str(model_ir.operators[int(add_eps_idx)].outputs[0])
        sqrt_idx = _single_consumer_index(add_eps_out_name)
        if sqrt_idx is None:
            continue
        sqrt_out_name = str(model_ir.operators[int(sqrt_idx)].outputs[0])
        div_idx = _single_consumer_index(sqrt_out_name)
        if div_idx is None:
            continue
        div_out_name = str(model_ir.operators[int(div_idx)].outputs[0])
        mul_norm_op = model_ir.operators[int(mul_norm_idx)]
        if div_out_name not in {str(v) for v in list(mul_norm_op.inputs)}:
            continue
        normalized_name = str(mul_norm_op.outputs[0])

        mul_scale_idx = _single_consumer_index(normalized_name)
        if mul_scale_idx is None:
            continue
        mul_scale_op = model_ir.operators[int(mul_scale_idx)]
        if str(mul_scale_op.op_type) != "MUL" or len(mul_scale_op.inputs) != 2 or len(mul_scale_op.outputs) != 1:
            continue
        if normalized_name not in {str(v) for v in list(mul_scale_op.inputs)}:
            continue
        scale_const_name = (
            str(mul_scale_op.inputs[0])
            if str(mul_scale_op.inputs[1]) == normalized_name
            else str(mul_scale_op.inputs[1])
        )
        scaled_name = str(mul_scale_op.outputs[0])
        desired_reduced_shape = list(x_shape)
        for axis in desired_axes:
            desired_reduced_shape[int(axis)] = 1
        desired_broadcast_shape = [1 for _ in range(rank)]
        desired_broadcast_shape[int(channel_axis)] = int(x_shape[int(channel_axis)])

        bias_const_name = None
        bias_broadcast_shape = None
        post_scaled_name = scaled_name
        add_bias_idx = _single_consumer_index(scaled_name)
        if add_bias_idx is not None:
            add_bias_op = model_ir.operators[int(add_bias_idx)]
            if (
                str(add_bias_op.op_type) == "ADD"
                and len(add_bias_op.inputs) == 2
                and len(add_bias_op.outputs) == 1
                and scaled_name in {str(v) for v in list(add_bias_op.inputs)}
            ):
                bias_const_name = (
                    str(add_bias_op.inputs[0])
                    if str(add_bias_op.inputs[1]) == scaled_name
                    else str(add_bias_op.inputs[1])
                )
                bias_broadcast_shape = list(desired_broadcast_shape)
            else:
                add_bias_idx = None
        if add_bias_idx is None:
            post_idx = _single_consumer_index(scaled_name)
            if post_idx is None:
                continue
            post_op = model_ir.operators[int(post_idx)]
            if str(post_op.op_type) != "TRANSPOSE" or len(post_op.inputs) < 2 or len(post_op.outputs) != 1:
                continue
            post_perm = _read_transpose_perm(model_ir, post_op)
            if post_perm is None or len(post_perm) != rank:
                continue
            post_scaled_name = str(post_op.outputs[0])
            add_bias_idx = _single_consumer_index(post_scaled_name)
            if add_bias_idx is None:
                continue
            add_bias_op = model_ir.operators[int(add_bias_idx)]
            if (
                str(add_bias_op.op_type) != "ADD"
                or len(add_bias_op.inputs) != 2
                or len(add_bias_op.outputs) != 1
                or post_scaled_name not in {str(v) for v in list(add_bias_op.inputs)}
            ):
                continue
            bias_const_name = (
                str(add_bias_op.inputs[0])
                if str(add_bias_op.inputs[1]) == post_scaled_name
                else str(add_bias_op.inputs[1])
            )
            bias_broadcast_shape = [1 for _ in range(rank)]
            inverse_post_perm = [0 for _ in range(rank)]
            for new_axis, old_axis in enumerate(post_perm):
                inverse_post_perm[int(old_axis)] = int(new_axis)
            post_channel_axis = int(inverse_post_perm[int(channel_axis)])
            bias_broadcast_shape[int(post_channel_axis)] = int(x_shape[int(channel_axis)])
        if bias_const_name is None or bias_broadcast_shape is None:
            continue

        changed = False
        if [int(v) for v in list(axes_values)] != desired_axes:
            changed = _write_const_ints_to_tensor(model_ir.tensors.get(axes_name, None), desired_axes) or changed
        if [int(v) for v in list(mean2_axes_values)] != desired_axes:
            changed = _write_const_ints_to_tensor(model_ir.tensors.get(mean2_axes_name, None), desired_axes) or changed

        for reduced_name in [mean1_out_name, mean2_out_name, add_eps_out_name, sqrt_out_name, div_out_name]:
            changed = _set_shape_metadata(reduced_name, desired_reduced_shape) or changed
        for full_name in [centered_name, squared_name, normalized_name, scaled_name]:
            changed = _set_shape_metadata(full_name, x_shape) or changed
        changed = _reshape_channelwise_const(scale_const_name, desired_broadcast_shape) or changed
        changed = _reshape_channelwise_const(bias_const_name, bias_broadcast_shape) or changed
        if post_scaled_name != scaled_name:
            post_scaled_tensor = model_ir.tensors.get(post_scaled_name, None)
            if post_scaled_tensor is not None:
                post_shape = [int(v) for v in list(post_scaled_tensor.shape)]
                if len(post_shape) == rank:
                    changed = _set_shape_metadata(post_scaled_name, post_shape) or changed

        if changed:
            repaired += 1

    return {"repaired_decomposed_instance_normalization_layouts": int(repaired)}


def _optimize_convpool_output_transpose_nhwc_passthrough_chains(
    model_ir: ModelIR,
) -> Dict[str, int]:
    """
    Remove NHWC->NCHW TRANSPOSE directly after Conv/Pool-family outputs and
    keep downstream layout contracts via local adapters only when required.

    Pattern:
      conv_or_pool_out_nhwc --T(0,3,1,2)--> x_nchw
      x_nchw -> elementwise-only subgraph

    Rewrite:
      - bypass leading transpose (subgraph runs in NHWC)
      - keep legacy external NCHW users through local NHWC->NCHW adapters
    """
    rewritten = 0
    channel_last_hint_names = {
        str(v)
        for v in model_ir.metadata.get(
            "assume_channel_last_layout_tensor_names",
            [],
        )
        if str(v) != ""
    }
    perm_nhwc_to_nchw = [0, 3, 1, 2]
    perm_nchw_to_nhwc = [0, 2, 3, 1]
    mean_axes_remapped_marker = "__convpool_output_nhwc_axes_remapped__"
    remapped_axes_tensor_names = {
        str(v)
        for v in model_ir.metadata.get(
            "convpool_output_nhwc_remapped_axes_tensor_names",
            [],
        )
        if str(v) != ""
    }
    convpool_ops = {
        "CONV_2D",
        "DEPTHWISE_CONV_2D",
        "TRANSPOSE_CONV",
        "AVERAGE_POOL_2D",
        "MAX_POOL_2D",
    }
    elementwise_ops = {
        "ABS",
        "ADD",
        "DIV",
        "ERF",
        "EXP",
        "FLOOR",
        "LOG",
        "MAXIMUM",
        "MINIMUM",
        "MUL",
        "NEG",
        "POW",
        "RSQRT",
        "SIGN",
        "SQRT",
        "SUB",
    }

    def _unique_tensor_name(base_name: str) -> str:
        candidate = str(base_name)
        serial = 0
        while candidate in model_ir.tensors:
            serial += 1
            candidate = f"{base_name}_{serial}"
        return candidate

    while True:
        changed = False
        consumers = _build_tensor_consumer_map(model_ir)
        producers = _build_tensor_producer_map(model_ir)
        model_outputs = set(str(v) for v in model_ir.outputs)

        for pre_idx, pre_op in enumerate(model_ir.operators):
            if str(pre_op.op_type) != "TRANSPOSE" or len(pre_op.inputs) < 2 or len(pre_op.outputs) != 1:
                continue
            if _read_transpose_perm(model_ir, pre_op) != perm_nhwc_to_nchw:
                continue
            pre_input_name = str(pre_op.inputs[0])
            pre_output_name = str(pre_op.outputs[0])
            if pre_output_name in model_outputs:
                continue

            pre_input_producer_idx = producers.get(pre_input_name, None)
            if pre_input_producer_idx is None:
                continue
            if str(model_ir.operators[int(pre_input_producer_idx)].op_type) not in convpool_ops:
                continue

            # Collect forward elementwise-only region from pre_output.
            subgraph_indices: set[int] = set()
            frontier: List[str] = [pre_output_name]
            seen_tensors: set[str] = {pre_output_name}
            while len(frontier) > 0:
                cur = str(frontier.pop())
                for user_idx_raw in consumers.get(cur, []):
                    user_idx = int(user_idx_raw)
                    user_op = model_ir.operators[int(user_idx)]
                    if str(user_op.op_type) not in elementwise_ops:
                        continue
                    if int(user_idx) in subgraph_indices:
                        continue
                    subgraph_indices.add(int(user_idx))
                    for out_name_raw in list(user_op.outputs):
                        out_name = str(out_name_raw)
                        if out_name not in seen_tensors:
                            seen_tensors.add(out_name)
                            frontier.append(out_name)
            if len(subgraph_indices) == 0:
                continue

            # Validate runtime inputs and gather external runtime dependencies.
            valid = True
            external_runtime_inputs: set[str] = set()
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[int(op_idx)]
                if len(op.outputs) != 1:
                    valid = False
                    break
                for input_name_raw in list(op.inputs):
                    input_name = str(input_name_raw)
                    input_tensor = model_ir.tensors.get(input_name, None)
                    if input_tensor is not None and input_tensor.data is not None:
                        continue
                    if input_name == pre_output_name:
                        continue
                    prod_idx = producers.get(input_name, None)
                    if prod_idx is None or int(prod_idx) not in subgraph_indices:
                        external_runtime_inputs.add(str(input_name))
            if not valid:
                continue

            # pre_output must be used only by local elementwise subgraph.
            pre_users = set(int(v) for v in consumers.get(pre_output_name, []))
            if len(pre_users) == 0 or not pre_users.issubset(subgraph_indices):
                continue

            # classify boundary users outside subgraph
            boundary_legacy_users: Dict[str, List[int]] = {}
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[int(op_idx)]
                out_name = str(op.outputs[0])
                if out_name in model_outputs:
                    valid = False
                    break
                users = set(int(v) for v in consumers.get(out_name, []))
                external_users = sorted(list(users - subgraph_indices))
                if len(external_users) == 0:
                    continue
                boundary_legacy_users[out_name] = [int(v) for v in list(external_users)]
            if not valid:
                continue

            channel_last_hint_names.add(str(pre_input_name))
            boundary_name_set = set(str(v) for v in boundary_legacy_users)
            for op_idx in sorted(list(subgraph_indices)):
                out_name = str(model_ir.operators[int(op_idx)].outputs[0])
                if out_name not in boundary_name_set:
                    channel_last_hint_names.add(out_name)

            # Rewire subgraph from pre_output -> pre_input.
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[int(op_idx)]
                _set_operator_inputs(
                    model_ir=model_ir,
                    op=op,
                    new_inputs=[
                        pre_input_name if str(v) == pre_output_name else str(v)
                        for v in list(op.inputs)
                    ],
                )

            # Adapt external runtime NCHW inputs used by subgraph.
            for external_input_name in sorted(list(external_runtime_inputs)):
                ext_tensor = model_ir.tensors.get(str(external_input_name), None)
                if ext_tensor is None or ext_tensor.shape is None or len(list(ext_tensor.shape)) != 4:
                    valid = False
                    break
                ext_shape = [int(v) for v in list(ext_tensor.shape)]
                ext_nhwc_shape = _permute_shape(ext_shape, perm_nchw_to_nhwc)
                if ext_nhwc_shape is None:
                    valid = False
                    break
                adapter_perm_name = _unique_tensor_name(f"{external_input_name}__to_nhwc_perm")
                adapter_output_name = _unique_tensor_name(f"{external_input_name}__to_nhwc")
                model_ir.tensors[str(adapter_perm_name)] = TensorIR(
                    name=str(adapter_perm_name),
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nchw_to_nhwc, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
                model_ir.tensors[str(adapter_output_name)] = TensorIR(
                    name=str(adapter_output_name),
                    dtype=str(ext_tensor.dtype),
                    shape=[int(v) for v in list(ext_nhwc_shape)],
                    shape_signature=[int(v) for v in list(ext_nhwc_shape)],
                    data=None,
                    is_variable=False,
                    quantization=_clone_quantization(ext_tensor.quantization),
                )
                model_ir.operators.append(
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(external_input_name), str(adapter_perm_name)],
                        outputs=[str(adapter_output_name)],
                    )
                )
                channel_last_hint_names.add(str(adapter_output_name))
                for op_idx in sorted(list(subgraph_indices)):
                    op = model_ir.operators[int(op_idx)]
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=op,
                        new_inputs=[
                            str(adapter_output_name) if str(v) == str(external_input_name) else str(v)
                            for v in list(op.inputs)
                        ],
                    )
            if not valid:
                continue

            # Metadata update: subgraph tensors are now NHWC.
            for op_idx in sorted(list(subgraph_indices)):
                op = model_ir.operators[int(op_idx)]
                out_name = str(op.outputs[0])
                _permute_tensor_metadata_if_rank_matches(
                    model_ir.tensors.get(out_name, None),
                    perm_nchw_to_nhwc,
                )

            # Keep external users with local NHWC->NCHW adapters at boundaries.
            for boundary_name, legacy_users in boundary_legacy_users.items():
                producer_idx = producers.get(str(boundary_name), None)
                if producer_idx is None or int(producer_idx) not in subgraph_indices:
                    valid = False
                    break
                boundary_nhwc_name = _unique_tensor_name(f"{boundary_name}__to_nhwc")
                channel_last_hint_names.add(str(boundary_nhwc_name))
                producer_op = model_ir.operators[int(producer_idx)]
                _set_operator_outputs(
                    model_ir=model_ir,
                    op=producer_op,
                    new_outputs=[str(boundary_nhwc_name)],
                )
                _replace_tensor_inputs(model_ir, str(boundary_name), str(boundary_nhwc_name))

                boundary_tensor = model_ir.tensors.get(str(boundary_name), None)
                boundary_nhwc_tensor = model_ir.tensors.get(str(boundary_nhwc_name), None)
                if boundary_tensor is not None and boundary_nhwc_tensor is None:
                    boundary_nhwc_tensor = TensorIR(
                        name=str(boundary_nhwc_name),
                        dtype=str(boundary_tensor.dtype),
                        shape=[int(v) for v in list(boundary_tensor.shape)],
                        shape_signature=(
                            [int(v) for v in list(boundary_tensor.shape_signature)]
                            if boundary_tensor.shape_signature is not None
                            else [int(v) for v in list(boundary_tensor.shape)]
                        ),
                        data=None,
                        is_variable=False,
                        quantization=_clone_quantization(boundary_tensor.quantization),
                    )
                    model_ir.tensors[str(boundary_nhwc_name)] = boundary_nhwc_tensor

                # First, try to absorb NCHW-only MEAN consumers by remapping axes
                # and keeping them on NHWC input directly.
                remapped_legacy_users: set[int] = set()
                for legacy_idx in list(legacy_users):
                    legacy_op = model_ir.operators[int(legacy_idx)]
                    if (
                        str(legacy_op.op_type) != "MEAN"
                        or len(legacy_op.inputs) < 2
                        or len(legacy_op.outputs) != 1
                        or str(legacy_op.inputs[0]) != str(boundary_nhwc_name)
                        or not bool(legacy_op.options.get("keepDims", False))
                    ):
                        continue
                    legacy_options = (
                        dict(legacy_op.options)
                        if isinstance(legacy_op.options, dict)
                        else {}
                    )
                    mean_was_remapped = bool(
                        legacy_options.get(mean_axes_remapped_marker, False)
                    )
                    if (
                        boundary_nhwc_tensor is None
                        or boundary_nhwc_tensor.shape is None
                        or len(list(boundary_nhwc_tensor.shape)) != 4
                    ):
                        continue

                    mean_axes_name = str(legacy_op.inputs[1])
                    mean_axes_tensor = model_ir.tensors.get(mean_axes_name, None)
                    mean_axes_vals = _read_const_ints_from_tensor(mean_axes_tensor)
                    if mean_axes_vals is None or len(mean_axes_vals) == 0:
                        continue

                    normalized_axes: List[int] = []
                    valid_axes = True
                    for axis in mean_axes_vals:
                        a = int(axis)
                        if a < 0:
                            a += 4
                        if a < 0 or a >= 4:
                            valid_axes = False
                            break
                        normalized_axes.append(int(a))
                    if not valid_axes:
                        continue
                    axes_were_remapped = (
                        mean_was_remapped
                        or mean_axes_name in remapped_axes_tensor_names
                    )
                    mapped_axes = (
                        [int(v) for v in normalized_axes]
                        if axes_were_remapped
                        else [
                            int(perm_nhwc_to_nchw[int(axis)])
                            for axis in normalized_axes
                        ]
                    )

                    if not axes_were_remapped:
                        _write_const_ints_to_tensor(
                            mean_axes_tensor,
                            [int(v) for v in mapped_axes],
                        )
                        remapped_axes_tensor_names.add(mean_axes_name)
                        model_ir.metadata[
                            "convpool_output_nhwc_remapped_axes_tensor_names"
                        ] = sorted(remapped_axes_tensor_names)
                    if isinstance(legacy_op.options, dict):
                        mean_options = dict(legacy_op.options)
                        for key in ["axis", "axes", "onnxRawAxes"]:
                            value = mean_options.get(key, None)
                            if isinstance(value, list) and len(value) == len(mapped_axes):
                                mean_options[key] = [int(v) for v in mapped_axes]
                        mean_options[mean_axes_remapped_marker] = True
                        legacy_op.options = mean_options

                    mean_out_name = str(legacy_op.outputs[0])
                    _permute_tensor_metadata_if_rank_matches(
                        model_ir.tensors.get(mean_out_name, None),
                        perm_nchw_to_nhwc,
                    )

                    for mean_user_idx in consumers.get(mean_out_name, []):
                        mean_user_op = model_ir.operators[int(mean_user_idx)]
                        mean_user_options = (
                            dict(mean_user_op.options)
                            if isinstance(mean_user_op.options, dict)
                            else {}
                        )
                        if (
                            str(mean_user_op.op_type) == "RESHAPE"
                            and len(mean_user_op.inputs) >= 2
                            and len(mean_user_op.outputs) == 1
                            and str(mean_user_op.inputs[0]) == mean_out_name
                            and bool(
                                mean_user_options.get(
                                    "layoutTransposeAsReshape",
                                    False,
                                )
                            )
                            and [
                                int(v)
                                for v in mean_user_options.get(
                                    "layoutTransposePerm",
                                    [],
                                )
                            ]
                            == perm_nchw_to_nhwc
                        ):
                            mean_out_tensor = model_ir.tensors.get(
                                mean_out_name,
                                None,
                            )
                            adapter_out_tensor = model_ir.tensors.get(
                                str(mean_user_op.outputs[0]),
                                None,
                            )
                            if mean_out_tensor is not None:
                                identity_shape = [
                                    int(v) for v in mean_out_tensor.shape
                                ]
                                _write_const_ints_to_tensor(
                                    model_ir.tensors.get(
                                        str(mean_user_op.inputs[1]),
                                        None,
                                    ),
                                    identity_shape,
                                )
                                mean_user_options["newShape"] = list(
                                    identity_shape
                                )
                                mean_user_op.options = mean_user_options
                                if adapter_out_tensor is not None:
                                    adapter_out_tensor.shape = list(
                                        identity_shape
                                    )
                                    adapter_out_tensor.shape_signature = (
                                        list(mean_out_tensor.shape_signature)
                                        if mean_out_tensor.shape_signature
                                        is not None
                                        else list(identity_shape)
                                    )
                            continue
                        if (
                            str(mean_user_op.op_type) == "TRANSPOSE"
                            and len(mean_user_op.inputs) >= 2
                            and len(mean_user_op.outputs) == 1
                            and str(mean_user_op.inputs[0]) == mean_out_name
                            and _read_transpose_perm(model_ir, mean_user_op)
                            == perm_nchw_to_nhwc
                        ):
                            # MEAN now already produces NHWC. Keep the boundary
                            # tensor name but turn its former NCHW->NHWC adapter
                            # into identity so the generic transpose cleanup can
                            # remove it without a second layout permutation.
                            perm_tensor = model_ir.tensors.get(
                                str(mean_user_op.inputs[1]),
                                None,
                            )
                            _write_const_ints_to_tensor(
                                perm_tensor,
                                [0, 1, 2, 3],
                            )
                            mean_out_tensor = model_ir.tensors.get(
                                mean_out_name,
                                None,
                            )
                            adapter_out_tensor = model_ir.tensors.get(
                                str(mean_user_op.outputs[0]),
                                None,
                            )
                            if (
                                mean_out_tensor is not None
                                and adapter_out_tensor is not None
                            ):
                                adapter_out_tensor.shape = list(
                                    mean_out_tensor.shape
                                )
                                adapter_out_tensor.shape_signature = (
                                    list(mean_out_tensor.shape_signature)
                                    if mean_out_tensor.shape_signature is not None
                                    else list(mean_out_tensor.shape)
                                )
                            continue
                        if mean_was_remapped:
                            continue
                        if (
                            str(mean_user_op.op_type) != "SQUEEZE"
                            or len(mean_user_op.inputs) != 1
                            or len(mean_user_op.outputs) != 1
                            or str(mean_user_op.inputs[0]) != mean_out_name
                            or not isinstance(mean_user_op.options, dict)
                            or "squeezeDims" not in mean_user_op.options
                        ):
                            continue
                        raw_axes = list(mean_user_op.options.get("squeezeDims", []))
                        remapped_squeeze_axes: List[int] = []
                        valid_squeeze_axes = True
                        for axis in raw_axes:
                            a = int(axis)
                            if a < 0:
                                a += 4
                            if a < 0 or a >= 4:
                                valid_squeeze_axes = False
                                break
                            remapped_squeeze_axes.append(int(perm_nhwc_to_nchw[int(a)]))
                        if not valid_squeeze_axes:
                            continue
                        squeeze_options = dict(mean_user_op.options)
                        squeeze_options["squeezeDims"] = sorted([int(v) for v in remapped_squeeze_axes])
                        mean_user_op.options = squeeze_options

                    remapped_legacy_users.add(int(legacy_idx))

                pending_legacy_users = [
                    int(v) for v in list(legacy_users)
                    if int(v) not in remapped_legacy_users
                ]
                if len(pending_legacy_users) <= 0:
                    continue

                perm_name = _unique_tensor_name(f"{boundary_name}__to_nchw_perm")
                model_ir.tensors[str(perm_name)] = TensorIR(
                    name=str(perm_name),
                    dtype="INT32",
                    shape=[4],
                    shape_signature=[4],
                    data=np.asarray(perm_nhwc_to_nchw, dtype=np.int32),
                    is_variable=False,
                    quantization=None,
                )
                model_ir.operators.append(
                    OperatorIR(
                        op_type="TRANSPOSE",
                        inputs=[str(boundary_nhwc_name), str(perm_name)],
                        outputs=[str(boundary_name)],
                    )
                )
                for legacy_idx in list(pending_legacy_users):
                    legacy_op = model_ir.operators[int(legacy_idx)]
                    _set_operator_inputs(
                        model_ir=model_ir,
                        op=legacy_op,
                        new_inputs=[
                            str(boundary_name) if str(v) == str(boundary_nhwc_name) else str(v)
                            for v in list(legacy_op.inputs)
                        ],
                    )
            if not valid:
                continue

            # Remove leading transpose.
            del model_ir.operators[int(pre_idx)]
            model_ir.metadata["assume_channel_last_layout_tensor_names"] = sorted(
                channel_last_hint_names
            )
            rewritten += 1
            changed = True
            break

        if not changed:
            break

    _prune_unused_tensors(model_ir)
    return {"optimized_convpool_output_transpose_nhwc_passthrough_chains": int(rewritten)}


def _optimize_transpose_unary_fanout_inverse_post_bridges(model_ir: ModelIR) -> Dict[str, int]:
    return _optimize_transpose_unary_fanout_inverse_post_bridges_pass(model_ir)


