    def _run_singleton_reshape_layout_pass_cluster(
        *,
        include_layout_transpose: bool = False,
        include_duplicate_fanout: bool = False,
        include_multi_branch_gate: bool = False,
        include_spatial_concat_post_transpose: bool = True,
    ) -> None:
        state_scope = ModelIRPassStateScope(
            model_ir,
            layout_state=session.layout_state,
        )
        if include_layout_transpose:
            run_layout_transpose_cleanup(
                model_ir,
                layout_state=session.layout_state,
                diagnostics=session.diagnostics,
                state_scope=state_scope,
            )
        run_singleton_channel_transpose_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        if include_duplicate_fanout:
            run_duplicate_fanout_cleanup(
                model_ir,
                include_transpose=False,
                layout_state=session.layout_state,
                diagnostics=session.diagnostics,
                state_scope=state_scope,
            )
        run_singleton_reshape_layout_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        run_singleton_maxpool_layout_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        run_flatten_concat_reshape_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        run_consecutive_reshape_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        run_squeeze_reshape_identity_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        run_singleton_spatial_reshape_cleanup(
            model_ir,
            include_concat_post_transpose=include_spatial_concat_post_transpose,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        if include_multi_branch_gate:
            run_multi_branch_gate_layout_cleanup(
                model_ir,
                layout_state=session.layout_state,
                diagnostics=session.diagnostics,
                state_scope=state_scope,
            )

    def _run_singleton_consecutive_reshape_pass_cluster(
        target_model_ir: ModelIR,
        target_layout_state: LayoutState | None,
    ) -> None:
        state_scope = ModelIRPassStateScope(
            target_model_ir,
            layout_state=target_layout_state,
        )
        run_singleton_channel_transpose_cleanup(
            target_model_ir,
            layout_state=target_layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        run_duplicate_fanout_cleanup(
            target_model_ir,
            include_transpose=False,
            layout_state=target_layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )
        run_consecutive_reshape_cleanup(
            target_model_ir,
            layout_state=target_layout_state,
            diagnostics=session.diagnostics,
            state_scope=state_scope,
        )

    def _run_layout_recovery_prefix_pass_sequence() -> None:
        _optimize_transpose_quant_dequant_bridges(model_ir)
        _run_boundary_batchmatmul_unary_layout_pass_cluster()
        _optimize_transpose_elementwise_roundtrip_nchw_nhwc_chains(model_ir)
        _optimize_transpose_elementwise_roundtrip_nhwc_nchw_fanout_chains(model_ir)
        run_hard_activation_passthrough_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        _optimize_swish_transpose_passthrough_chains(model_ir)
        _optimize_gelu_tanh_transpose_passthrough_chains(model_ir)
        _optimize_center_size_offset_terminal_transpose_chains(model_ir)
        _optimize_leakyrelu_transpose_passthrough_chains(model_ir)
        _optimize_prelu_transpose_passthrough_chains(model_ir)
        _optimize_transpose_elementwise_concat_conv_nhwc_groups(model_ir)
        run_spp_layout_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        _optimize_transpose_pre_concat_nhwc_chains(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        run_ndhwc_concat_layout_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        _optimize_transpose_stridedslice_pre_concat_nhwc_chains(model_ir)
        _optimize_transpose_split_mixed_pre_concat_to_single_post_adapter_nhwc_chains(model_ir)
        _optimize_transpose_input_chains_pre_concat_to_single_post_adapter(model_ir)
        _optimize_transpose_slice_logistic_concat_reshape_tail_nhwc_chains(model_ir)
        _run_channel_shuffle_gather_layout_pass_cluster()

    def _run_layout_reshape_attention_recovery_prefix() -> None:
        _run_layout_recovery_prefix_pass_sequence()
        _optimize_transpose_pre_add_nhwc_chains(model_ir)
        _optimize_transpose_pre_add_mulconst_reshape_transpose_suffix_nhwc_chains(model_ir)
        _optimize_transpose_pre_add_reshape_transpose_suffix_nhwc_chains(model_ir)
        _optimize_transpose_pre_unary_reshape_transpose_suffix_nhwc_chains(model_ir)
        _optimize_transpose_reshape_transpose_to_expanddims_nhwc_chains(model_ir)
        _optimize_transpose_reshape_transpose_to_flatten_hw_nhwc_chains(model_ir)
        _optimize_reshape_transpose_reshape_transpose_to_nhwc_reshape_chains(model_ir)
        _optimize_attention_qkv_reshape_transpose_reshape_to_reshape_transpose_chains(model_ir)
        _optimize_attention_gather_transpose_reshape_cleanup_chains(model_ir)
        _optimize_gather_axis0_singleton_to_reshape_input_chains(
            model_ir,
            layout_state=session.layout_state,
        )
        _optimize_attention_preproj_reshape_to_batchmatmul_ranklift_chains(model_ir)
        _optimize_window_partition_reshape_transpose_to_space_to_depth_chains(model_ir)
        _optimize_window_reverse_reshape_transpose_to_depth_to_space_chains(model_ir)
        _optimize_transpose_pre_unary_squeeze_transpose_suffix_nhwc_chains(model_ir)
        run_squeeze_reshape_identity_cleanup(
            model_ir,
            include_unary_passthrough=True,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )

    def _run_preadd_mean_attention_recovery_sequence() -> None:
        _optimize_transpose_pre_add_nhwc_chains(model_ir)
        _optimize_transpose_pre_add_mul_add_prelu_nhwc_chains(model_ir)
        _optimize_transpose_pre_add_mul_add_transpose_fanout_nhwc_chains(model_ir)
        _optimize_transpose_mul_add_const_prepost_nhwc_chains(model_ir)
        _optimize_transpose_pre_unary_mul_add_transpose_fanout_nhwc_chains(model_ir)
        _optimize_transpose_mean_mul_add_const_prepost_nhwc_chains(model_ir)
        _run_mean_attention_layout_pass_cluster()

    def _run_attention_gate_qdq_recovery_sequence() -> None:
        _optimize_transpose_sa_pa_mirrorpad_nhwc_propagation_chains(model_ir)
        _optimize_sinet_mix_attention_double_logistic_nhwc_chains(model_ir)
        _run_gate_layout_pass_cluster()
        _optimize_transposeconv_output_nhwc_passthrough_chains(model_ir)
        _optimize_transposeconv_output_channel1_terminal_transpose_chains(model_ir)
        _run_transpose_unary_fanout_layout_pass_cluster()
        _optimize_transpose_dequant_relu_quantize_bridges(model_ir)
        _optimize_transpose_dequant_hardsigmoid_quantize_bridges(model_ir)
        run_trailing_output_transpose_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        _optimize_transpose_dequant_mul_add_prelu_quantize_bridges(model_ir)

    def _run_safe_binary_bridge_recovery_sequence() -> None:
        _optimize_transpose_binary_symmetric_legacy_only_bridges_safe(model_ir)
        _optimize_transpose_binary_single_post_bridges_safe(model_ir)
        _optimize_transpose_binary_mixed_fanout_bridges_safe(model_ir)
        _optimize_transpose_binary_asymmetric_fanout_bridges(model_ir)
        _optimize_transpose_binary_full_post_fanout_bridges(model_ir)

    def _run_quantized_activation_binary_bridge_recovery_sequence() -> None:
        _optimize_dequant_hardsigmoid_quantize_chains(model_ir)
        _optimize_dequant_maxpool_quantize_chains(
            model_ir,
            layout_state=session.layout_state,
        )
        _optimize_dequant_softmax_quantize_chains(model_ir)
        _optimize_dequant_logistic_quantize_chains(
            model_ir,
            layout_state=session.layout_state,
        )
        _canonicalize_softmax_transpose_chains(model_ir)
        _run_safe_binary_bridge_recovery_sequence()

    def _run_qlinear_mean_concat_recovery_sequence() -> None:
        _optimize_transpose_mean_hardsigmoid_muladd_chains(model_ir)
        _optimize_nhwc_prefix_qlinear_silu_chains(model_ir)
        _optimize_nhwc_propagation_qlinear_concat_conv(model_ir)
        _optimize_concat_pre_quantize_dequantize(model_ir)
        _optimize_transpose_mean_maxpool_concat_conv_chains(model_ir)

    def _run_layout_attention_quantized_recovery_suffix(
        *,
        include_duplicate_transpose: bool,
    ) -> None:
        _optimize_transpose_mul_add_const_prepost_nhwc_chains(model_ir)
        _optimize_transpose_pre_unary_mul_add_transpose_fanout_nhwc_chains(model_ir)
        _optimize_transpose_mean_mul_add_const_prepost_nhwc_chains(model_ir)
        _run_mean_attention_layout_pass_cluster()
        _run_attention_gate_qdq_recovery_sequence()
        _run_duplicate_quantized_prelu_pass_cluster(
            include_transpose=include_duplicate_transpose,
        )
        _optimize_dequant_transposeconv_quantize_chains(model_ir)
        run_quantized_reshape_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        _optimize_dequant_hardsigmoid_quantize_chains(model_ir)
        _optimize_dequant_maxpool_quantize_chains(
            model_ir,
            layout_state=session.layout_state,
        )
        _optimize_dequant_softmax_quantize_chains(model_ir)
        _optimize_dequant_logistic_quantize_chains(
            model_ir,
            layout_state=session.layout_state,
        )
        _canonicalize_softmax_transpose_chains(model_ir)

    def _run_terminal_slice_concat_layout_recovery_sequence() -> None:
        _run_channel_slice_pad_mul_layout_pass_cluster()
        _optimize_transpose_mul_posttranspose_add_nhwc_chains(model_ir)
        _optimize_concat_mul_add_transpose_nhwc_bridge_chains(model_ir)
        _optimize_concat_mul_add_transpose_add_nhwc_bridge_chains(model_ir)
        _optimize_concat_mul_add_add_mean_reshape_tail_nhwc_bridge_chains(model_ir)
        _optimize_concat_tree_mul_add_transpose_nhwc_bridge_chains(model_ir)
        _optimize_singleton_gate_conv_concat_nhwc_bridge_blocks(model_ir)
        _optimize_transpose_unary_split_concat_single_post_nchw(model_ir)
        _optimize_transpose_split_channelwise_tail_to_single_post_nchw(model_ir)
        _optimize_transpose_binary_split_channelwise_tail_to_single_post_nchw(model_ir)
        _sanitize_probable_nhwc_axis_sensitive_ops(model_ir)
        _optimize_transpose_stridedslice_pad_concat_mul_add_posttranspose_nhwc_chains(model_ir)
        _optimize_transpose_pre_add_nhwc_chains(model_ir)
        run_layout_transpose_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )

    def _run_terminal_affine_concat_split_recovery_sequence() -> None:
        _optimize_fold_mul_add_mul_affine_chains(model_ir)
        _optimize_transpose_mul_add_const_prepost_nhwc_chains(model_ir)
        _optimize_concat_mul_add_transpose_nhwc_bridge_chains(model_ir)
        _optimize_concat_mul_add_transpose_add_nhwc_bridge_chains(model_ir)
        _optimize_concat_mul_add_add_mean_reshape_tail_nhwc_bridge_chains(model_ir)
        _optimize_concat_tree_mul_add_transpose_nhwc_bridge_chains(model_ir)
        _optimize_singleton_gate_conv_concat_nhwc_bridge_blocks(model_ir)
        _optimize_transpose_unary_split_concat_single_post_nchw(model_ir)
        _optimize_transpose_split_channelwise_tail_to_single_post_nchw(model_ir)
        _optimize_transpose_binary_split_channelwise_tail_to_single_post_nchw(model_ir)
        _sanitize_probable_nhwc_axis_sensitive_ops(model_ir)

    def _run_sinet_preadd_resize_recovery_sequence() -> None:
        _optimize_transpose_pre_add_mul_add_prelu_nhwc_chains(model_ir)
        _optimize_transpose_pre_add_mul_add_transpose_fanout_nhwc_chains(model_ir)
        # Generic rewrites can recreate SiNet concat+resize transpose adapters.
        _optimize_sinet_concat_resize_affine_transpose_chains(model_ir)
        _optimize_sinet_dual_resize_affine_transpose_chains(model_ir)
        _optimize_sinet_concat_resize_affine_tail_concat_transpose_chains(model_ir)
        _optimize_sinet_softmax_mask_residual_nhwc_tail_chains(model_ir)

    def _run_sinet_terminal_layout_recovery_sequence() -> None:
        _optimize_sinet_shuffle_residual_transpose_chains(model_ir)
        _run_sinet_preadd_resize_recovery_sequence()
        _optimize_transpose_mul_add_const_prelu_prepost_nhwc_terminal_chains(model_ir)

    _set_post_progress_desc("outputs")

    # Outputs
    for graph_output in onnx_graph.graph.output:
        ctx.ensure_tensor(graph_output.name)
        _append_model_outputs_preserving_order(
            model_ir,
            [str(graph_output.name)],
        )
    protected_boundary_outputs = [
        str(name)
        for name in _get_protected_boundary_tensor_names(model_ir)
        if str(name) in model_ir.tensors
    ]
    _append_model_outputs_preserving_order(
        model_ir,
        protected_boundary_outputs,
    )
    dynamic_boundary_signature_map: Dict[str, List[int]] = {}
    onnx_boundary_signature_map = model_ir.metadata.get(
        "onnx_boundary_shape_signature_map",
        {},
    )
    if not isinstance(onnx_boundary_signature_map, dict):
        onnx_boundary_signature_map = {}
    dynamic_boundary_name_set = set(
        list(model_ir.metadata.get("onnx_dynamic_input_tensor_names", []))
        + list(model_ir.metadata.get("onnx_dynamic_output_tensor_names", []))
    )
    for boundary_name in list(model_ir.inputs) + list(model_ir.outputs):
        if str(boundary_name) not in dynamic_boundary_name_set:
            continue
        boundary_tensor = model_ir.tensors.get(str(boundary_name), None)
        if boundary_tensor is None or boundary_tensor.shape_signature is None:
            continue
        snapshot_signature = [int(v) for v in list(boundary_tensor.shape_signature)]
        hinted_signature = onnx_boundary_signature_map.get(str(boundary_name), None)
        hinted_signature_aligned = _align_boundary_signature_to_current_shape(
            boundary_signature=(
                [int(v) for v in list(hinted_signature)]
                if isinstance(hinted_signature, list)
                else None
            ),
            current_shape=[int(v) for v in list(boundary_tensor.shape)],
        )
        if hinted_signature_aligned is not None:
            if len(hinted_signature_aligned) == len(snapshot_signature):
                for axis in range(len(snapshot_signature)):
                    if int(hinted_signature_aligned[axis]) > 0:
                        snapshot_signature[axis] = int(hinted_signature_aligned[axis])
        if any(int(v) < 0 for v in snapshot_signature):
            dynamic_boundary_signature_map[str(boundary_name)] = snapshot_signature
    model_ir.metadata["dynamic_boundary_shape_signature_map"] = (
        dynamic_boundary_signature_map
    )
    _advance_post_progress()

    if optimize_layout_transpose_chains:
        _set_post_progress_desc("layout optimize pass-set 1")
        has_qdq_ops = any(
            str(op.op_type) in {"QUANTIZE", "DEQUANTIZE"}
            for op in model_ir.operators
        )
        # NOTE:
        # Binary/fanout transpose rewrites can invalidate tensor shape/layout
        # assumptions in multi-branch int8 graphs. Keep them enabled on
        # non-QDQ graphs where the pass is effective and stable.
        enable_transpose_binary_bridge_optimizations = not has_qdq_ops
        # Duplicate transpose fanout dedup is safe on pure float graphs and
        # removes redundant NHWC/NCHW adapters in multi-branch heads.
        enable_duplicate_transpose_fanout_optimizations = not has_qdq_ops

        run_layout_transpose_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        _run_layout_reshape_attention_recovery_prefix()
        _optimize_fold_mul_add_mul_affine_chains(model_ir)
        _optimize_transpose_mul_add_const_prepost_nhwc_chains(model_ir)
        _optimize_transpose_pre_unary_mul_add_transpose_fanout_nhwc_chains(model_ir)
        _optimize_transpose_mean_mul_add_const_prepost_nhwc_chains(model_ir)
        _run_mean_attention_layout_pass_cluster(include_layernorm=True)
        _run_attention_gate_qdq_recovery_sequence()
        run_quantized_prelu_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        _optimize_dequant_transposeconv_quantize_chains(model_ir)
        run_quantized_reshape_cleanup(
            model_ir,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        _run_quantized_activation_binary_bridge_recovery_sequence()
        if enable_transpose_binary_bridge_optimizations:
            _optimize_transpose_binary_bridges(model_ir)
        run_duplicate_fanout_cleanup(
            model_ir,
            include_transpose=enable_duplicate_transpose_fanout_optimizations,
            layout_state=session.layout_state,
            diagnostics=session.diagnostics,
        )
        # Binary bridge rewrites can introduce new transpose-(q|dq)-transpose patterns.
